      SUBROUTINE H15(X,N,C,NCUT,AH15,XSC,WS,WS2,MAXNXT,ISUBRO,IBUGA3)
!
!     THIS SUBROUTINE IS ADAPTED FROM:
!
!         ANALYTICAL METHODS COMMITTEE, "ROBUST STATISTICS--HOW
!         NOT TO REJECT OUTLIERS: PART 1. BASIC CONCEPTS",
!         ANALYST, DECEMBER 1989, VOL. 1.
!
!         THE BASIC CODE IS FROM THIS ARTICLE AND WAS WRITTEN
!         BY B. D. RIPLEY.  IT WAS MODIFED SOMEWHAT FOR ADAPTION
!         INTO DATAPLOT BY ALAN HECKERT JULY 2009.
!
!     IT COMPUTES THE H15 ROBUST ESTIMATES OF LOCATION AND SCALE.
!     NOTE THAT BY PASSING VALUES OF C OTHER THAN 1.5, IT CAN
!     ALSO BE USED TO COMPUTE H10 (C = 1), H12 (C = 1.2),
!     H17 (C = 1.7), AND H20 (C = 2.0).
!
      REAL    X(*)
      REAL    WS(*)
      REAL    WS2(*)
      REAL    XSC
      REAL    A
      REAL    BETA
      REAL    C
      REAL    C1
      REAL    XS
      REAL    XS0
      REAL    XC
      REAL    AN
      DOUBLE PRECISION    SUM
      DOUBLE PRECISION    SUM2
!
      INTEGER N
      INTEGER MAXNXT
      INTEGER I
!
      CHARACTER*4 IERROR
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IWRITE
!
      INCLUDE 'DPCOP2.INC'
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'H15 ')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF H15--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,C,N
   52   FORMAT('IBUGA3,C = ',A4,2X,G15.7,2X,I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I)
   56     FORMAT('I,X(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
      IF(C.EQ.1.0)THEN
        BETA=0.516
      ELSEIF(C.EQ.1.1)THEN
        BETA=0.578
      ELSEIF(C.EQ.1.2)THEN
        BETA=0.635
      ELSEIF(C.EQ.1.3)THEN
        BETA=0.688
      ELSEIF(C.EQ.1.4)THEN
        BETA=0.736
      ELSEIF(C.EQ.1.5)THEN
        BETA=0.778
      ELSEIF(C.EQ.1.6)THEN
        BETA=0.816
      ELSEIF(C.EQ.1.7)THEN
        BETA=0.849
      ELSEIF(C.EQ.1.8)THEN
        BETA=0.877
      ELSEIF(C.EQ.1.9)THEN
        BETA=0.900
      ELSEIF(C.EQ.2.0)THEN
        BETA=0.921
      ELSE
        BETA=0.778
      ENDIF
!
      C1 = C
      AN=REAL(N)
      IF(NCUT.GT.0 .AND. N.LE.NCUT)THEN
        C1 = C * SQRT(1.0 - 1.0/AN)
      ENDIF
!
      IWRITE='OFF'
      IERROR='NO'
      CALL MEDIAN(X,N,IWRITE,WS,MAXNXT,XM,IBUGA3,IERROR)
      CALL MAD(X,N,IWRITE,WS,WS2,MAXNXT,XS,IBUGA3,IERROR)
      XS=XS/0.6745
!
      ITER = 0
   10 CONTINUE
      ITER = ITER + 1
!
      IF(ITER.GT.100)THEN
        WRITE(ICOUT,11)
   11   FORMAT('***** WARNING FROM H15--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,13)
   13   FORMAT('      100 ITERATIONS WITHOUT CONVERGENCE.')
        CALL DPWRST('XXX','BUG ')
        GO TO 900
      ENDIF
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'H15 ')THEN
        WRITE(ICOUT,112)ITER,XM,XS
  112   FORMAT('FROM H15: ITER,XM,XS = ',I8,2G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      XM0 = XM
      XS0 = XS
      SUM = 0.0D0
      SUM2 = 0.0D0
      XC = C1*XS
!
      DO 200  I = 1, N
        A = MIN(XM+XC, MAX(XM-XC, X(I)))
        SUM = SUM + DBLE(A)
        SUM2 = SUM2 + DBLE((A-XM)*(A-XM))
!
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'H15 ')THEN
          WRITE(ICOUT,205)I,X(I),A,SUM,SUM2
  205     FORMAT('I,X(I),A,SUM,SUM2 = ',I8,4G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
  200 CONTINUE
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'H15 ')THEN
        WRITE(ICOUT,212)SUM,SUM2
  212   FORMAT('FROM H15: SUM,SUM2 = ',2G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      XM = REAL(SUM/DBLE(N))
      XS = REAL(SQRT(SUM2/DBLE(BETA*(AN-1.0))))
      IF ((ABS(XM-XM0) .GT. 1.0E-4*XS0)  .OR.   &
          ABS(XS/XS0 - 1.0) .GT. 1.0E-4)  GO TO  10
!
  900 CONTINUE
      AH15 = XM
      XSC = XS
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'H15 ')THEN
        WRITE(ICOUT,9010)
 9010   FORMAT('AT THE END OF H15')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)XM,XM0,XS,XS0,AH15,XSC
 9012   FORMAT('XM,XM0,XS,XS0,AH15,XSC=',6G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE H15
      SUBROUTINE HAMDIS(X,Y,N,IWRITE,STATVA,IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE HAMMING DISTANCE BETWEEN THE
!              TWO SETS OF DATA IN THE INPUT VECTORS X AND Y.  THE
!              SAMPLE HAMMING DISTANCE IS THE NUMBER OF ELEMENTS THAT
!              ARE NOT THE SAME IN X AND Y.
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED) OBSERVATIONS WHICH
!                                CONSTITUTE THE FIRST SET OF DATA.
!                     --Y      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED) OBSERVATIONS WHICH
!                                CONSTITUTE THE SECOND SET OF DATA.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTORS X AND Y.
!     OUTPUT ARGUMENTS--STATVA = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SAMPLE HAMMING DISTANCE
!                                BETWEEN THE TWO SETS OF DATA IN THE
!                                INPUT VECTORS X AND Y.  THIS SINGLE
!                                PRECISION VALUE WILL BE BETWEEN 0.0
!                                AND 1.0 (INCLUSIVELY).
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE HANNING DISTANCE BETWEEN THE 2 SETS
!             OF DATA IN THE INPUT VECTORS X AND Y.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--ABS.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--XXX
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGYS
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGYS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2018/08
!     ORIGINAL VERSION--AUGUST    2018.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION Y(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='HAMD'
      ISUBN2='IS  '
      IERROR='NO'
      STATVA=CPUMIN
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'SDIS')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF MANDIS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N
   52   FORMAT('IBUGA3,ISUBRO,N = ',2(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I),Y(I)
   56     FORMAT('I,X(I),Y(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN HAMMING DISTANCE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE RESPONSE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)
  113   FORMAT('      VARIABLES IS LESS THAN 1.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE NUMBER OF OBSERVATIONS HERE = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ************************************************
!               **  STEP 2--                                  **
!               **  COMPUTE THE MANHATTAN DISTANCE.           **
!               ************************************************
!
      STATVA=0.0
      DO 200 I=1,N
        IF(X(I).NE.Y(I))STATVA=STATVA+1
  200 CONTINUE
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,811)N,INT(STATVA+0.1)
  811   FORMAT('THE HAMMING DISTANCE OF THE ',I8,   &
                 ' OBSERVATIONS = ',I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MDIS')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF HAMDIS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IERROR,STATVA
 9012   FORMAT('IERROR,STATVA = ',A4,2X,G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE HAMDIS
      SUBROUTINE HARMEA(X,N,IWRITE,XHARM,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE
!              SAMPLE HARMONIC MEAN, XHARM,
!              OF THE DATA IN THE INPUT VECTOR X.
!              THE SAMPLE XHARM = SUM(N/(1/X))
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--XHARM  = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SAMPLE HARMONIC MEAN.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE HARMONIC MEAN
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--99.3
!     ORIGINAL VERSION--MARCH     1999.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DX
      DOUBLE PRECISION DSUM
!
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='GEOM'
      ISUBN2='EA  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'OFF')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF HARMEA--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IBUGA3
   52 FORMAT('IBUGA3 = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)N
   53 FORMAT('N = ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 55 I=1,N
      WRITE(ICOUT,56)I,X(I)
   56 FORMAT('I,X(I) = ',I8,E15.7)
      CALL DPWRST('XXX','BUG ')
   55 CONTINUE
   90 CONTINUE
!
!               ******************************
!               **  COMPUTE HARMONIC MEAN  **
!               ******************************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.GE.1)GO TO 119
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,111)
  111 FORMAT('***** ERROR IN HARMEA--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,112)
  112 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,113)
  113 FORMAT('      IN THE VARIABLE FOR WHICH')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,114)
  114 FORMAT('      THE HARMEA IS TO BE COMPUTED')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,115)
  115 FORMAT('      MUST BE 1 OR LARGER.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,116)
  116 FORMAT('      SUCH WAS NOT THE CASE HERE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,117)N
  117 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS HERE = ',I8,   &
      '.')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
  119 CONTINUE
!
      IF(N.EQ.1)GO TO 120
      GO TO 129
  120 CONTINUE
      XHARM=X(1)
      GO TO 9000
  129 CONTINUE
!
!               ***********************************
!               **  STEP 2--                     **
!               **  COMPUTE THE HARMONIC MEAN.   **
!               ***********************************
!
      DN=N
      DSUM=0.0D0
      DO 200 I=1,N
        DX=DBLE(X(I))
        IF(DX.NE.0.0D0)DSUM=DSUM+1.0D0/DX
  200 CONTINUE
      DSUM=DN/DSUM
      XHARM=REAL(DSUM)
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'OFF')GO TO 890
      IF(IWRITE.EQ.'OFF')GO TO 890
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,811)N,XHARM
  811 FORMAT('THE HARMONIC MEAN OF THE ',I8,' OBSERVATIONS = ',E15.7)
      CALL DPWRST('XXX','BUG ')
  890 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF HARMEA--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGA3,IERROR
 9012 FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)N
 9013 FORMAT('N = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9015)XHARM
 9015 FORMAT('XHARM = ',E15.7)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE HARMEA
      SUBROUTINE HAZARD(X,TAG,NX,IWRITE,Y,XTEMP,MAXNXT,IBUGA3,IERROR)
!
!     PURPOSE--COMPUTE HAZARD OF AN ARRAY
!              THE TAG VARIABLE IDENTIFIES CENSORED DATA
!              (1 = FAILURE TIME, 0 = CENSORED)
!     NOTE--IT IS PERMISSIBLE TO HAVE THE OUTPUT VECTOR Y(.)
!           BEING IDENTICAL TO THE INPUT VECTOR X(.).
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--98/5
!     ORIGINAL VERSION--MAY       1998.
!     UPDATED         --JANUARY   2007.  CALL LIST TO RANK
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION Y(*)
      DIMENSION TAG(*)
      DIMENSION XTEMP(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='HAZA'
      ISUBN2='RD  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF HAZARD--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,NX
   52   FORMAT('IBUGA3,NX = ',A4,2X,I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,NX
          WRITE(ICOUT,56)I,X(I),TAG(I)
   56     FORMAT('I,X(I), TAG(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               **************************************
!               **  COMPUTE CUMULATIVE HAZARD       **
!               **************************************
!
      CALL SORTC(X,TAG,NX,Y,TAG)
      CALL RANK(Y,NX,IWRITE,Y,XTEMP,MAXNXT,IBUGA3,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
      AFACT=REAL(NX+1)
      DO 100 I=1,NX
        IF(ABS(TAG(I)).GE.0.5)THEN
          Y(I)=100.0/(AFACT - Y(I))
        ELSE
          Y(I)=0.0
        ENDIF
  100 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF HAZARD--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IERROR
 9012   FORMAT('IERROR = ',A4)
        CALL DPWRST('XXX','BUG ')
        DO 9015 I=1,NX
          WRITE(ICOUT,9016)I,X(I),Y(I)
 9016     FORMAT('I,X(I),Y(I) = ',I8,2E15.7)
          CALL DPWRST('XXX','BUG ')
 9015   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE HAZARD
      SUBROUTINE HBOCDF(X,ALPHA,XI,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE HYPERBOLIC
!              DISTRIBUTION WITH SHAPE PARAMETERS ALPHA AND XI.
!              THE CUMULATIVE DISTRIBUTION IS COMPUTED BY
!              NUMERICALLY INTEGRATING THE PDF FUNCTION.
!     INPUT  ARGUMENTS--X       = THE DOUBLE PRECISION VALUE AT
!                                 WHICH THE CUMULATIVE DISTRIBUTION
!                                 FUNCTION IS TO BE EVALUATED.
!                     --ALPHA   = THE FIRST SHAPE PARAMETER
!                     --XI      = THE SECOND SHAPE PARAMETER
!     OUTPUT ARGUMENTS--CDF     = THE DOUBLE PRECISION CUMULATIVE
!                                 DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE FOR THE HYPERBOLIC
!             DISTRIBUTION WITH SHAPE PARAMETERS ALPHA AND XI.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--DQAGI.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 WILEY, 1994, PP. 60.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.9
!     ORIGINAL VERSION--SEPTEMBER 2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      INTEGER LIMIT
      INTEGER LENW
      PARAMETER(LIMIT=100)
      PARAMETER(LENW=4*LIMIT)
      INTEGER INF
      INTEGER NEVAL
      INTEGER IER
      INTEGER LAST
      INTEGER IWORK(LIMIT)
      DOUBLE PRECISION ALPHA
      DOUBLE PRECISION XI
      DOUBLE PRECISION EPSABS
      DOUBLE PRECISION EPSREL
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION CDF
      DOUBLE PRECISION X
      DOUBLE PRECISION DX
      DOUBLE PRECISION ABSERR
      DOUBLE PRECISION WORK(LENW)
!
      DOUBLE PRECISION HBOFUN
      EXTERNAL HBOFUN
!
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DXI
      COMMON/HBOCOM/DALPHA,DXI
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(ALPHA.LE.0.0D0)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,48)ALPHA
        CALL DPWRST('XXX','WRIT')
        CDF=0.0D0
        GO TO 9000
      ENDIF
    5 FORMAT('***** ERROR: VALUE OF FIRST SHAPE PARAMETER (ALPHA)',   &
             ' IN HBOCDF ROUTINE IS NON-POSITIVE.')
      IF(XI.LE.0.0D0)THEN
        WRITE(ICOUT,8)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,48)XI
        CALL DPWRST('XXX','WRIT')
        CDF=0.0D0
        GO TO 9000
      ENDIF
    8 FORMAT('***** ERROR: VALUE OF SECOND SHAPE PARAMETER (XI)',   &
             ' IN HBOCDF ROUTINE IS NON-POSITIVE.')
   48 FORMAT('      VALUE OF ARGUMENT IS: ',G15.7)
!
!               ************************************
!               **  STEP 1--                      **
!               **  COMPUTE THE DENSITY FUNCTION  **
!               ************************************
!
      DX=X
      INF=-1
      EPSABS=0.0D0
      EPSREL=1.0D-7
      IER=0
      DCDF=0.0D0
      IFLAG=0
      IF(DX.LT.0.0D0)THEN
        IFLAG=1
        INF=1
      ENDIF
!
      DATEMP=0.0D0
      DXI=XI
!
      CALL DQAGI(HBOFUN,DX,INF,EPSABS,EPSREL,DCDF,ABSERR,NEVAL,   &
                IER,LIMIT,LENW,LAST,IWORK,WORK)
!
      IF(IFLAG.EQ.1)THEN
        CDF=1.0D0 - DCDF
      ELSE
        CDF=DCDF
      ENDIF
!
      IF(IER.EQ.1)THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR FROM HBOCDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)
  113   FORMAT('      MAXIMUM NUMBER OF SUBDIVISIONS EXCEEDED.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,121)
  121   FORMAT('***** ERROR FROM HBOCDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,123)
  123   FORMAT('      ROUNDOFF ERROR PREVENTS REQUESTED TOLERANCE ',   &
               'FROM BEING ACHIEVED.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.3)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,131)
  131   FORMAT('***** ERROR FROM HBOCDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,133)
  133   FORMAT('      BAD INTEGRAND BEHAVIOUR DETECTED.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.4)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,141)
  141   FORMAT('***** ERROR FROM HBOCDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,143)
  143   FORMAT('      INTEGRATION DID NOT CONVERGE.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.5)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,151)
  151   FORMAT('***** ERROR FROM HBOCDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,153)
  153   FORMAT('      THE INTEGRATION IS PROBABLY DIVERGENT.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.6)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,161)
  161   FORMAT('***** ERROR FROM HBOCDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,163)
  163   FORMAT('      INVALID INPUT TO THE INTEGRATION ROUTINE.')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE HBOCDF
      DOUBLE PRECISION FUNCTION HBOFUN(DX)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE HYPERBOLIC
!              DISTRIBUTION WITH SHAPE PARAMETERS ALPHA AND XI.
!              THIS DISTRIBUTION IS DEFINED FOR ALL REAL X
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!
!                 f(X;ALPHA,XI) = (1/{2*SQRT(1+ALPHA**2)*K(1)(XI)})*
!                     EXP{-XI*[SQRT(1+ALPHA**2)*SQRT(1+X**2)-ALPHA*X]}
!                     XI > 0
!              WHERE
!                 K(N,X) IS THE MODIFIED BESSEL FUNCTION OF THE
!                        SECOND KIND AND ORDER N.
!
!              THE HBOPDF ROUTINE IS CALLED TO COMPUTE THE
!              PROBABILITY DENSITY.  DEFINE AS FUNCTION TO BE USED FOR
!              INTEGRATION CODE CALLED BY HBOCDF.  THIS ROUTINE USES
!              DOUBLE PRECISION ARITHMETIC.
!     INPUT  ARGUMENTS--DX      = THE DOUBLE PRECISION VALUE AT
!                                 WHICH THE PROBABILITY DENSITY
!                                 FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--HBOFUN  = THE DOUBLE PRECISION PROBABILITY
!                                 DENSITY FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE HYPERBOLIC
!             DISTRIBUTION WITH SHAPE PARAMETERS ALPHA AND XI.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--HBOPDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 WILEY, 1994, PP. 60.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.9
!     ORIGINAL VERSION--SEPTEMBER 2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DTERM
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DXI
      COMMON/HBOCOM/DALPHA,DXI
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!               ************************************
!               **  STEP 1--                      **
!               **  COMPUTE THE DENSITY FUNCTION  **
!               ************************************
!
      CALL HBOPDF(DX,DALPHA,DXI,DTERM)
      HBOFUN=DTERM
!
      RETURN
      END FUNCTION HBOFUN
      SUBROUTINE HBOPDF(X,ALPHA,XI,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE HYPERBOLIC DISTRIBUTION WITH
!              SHAPE PARAMETERS ALPHA AND XI.  THIS DISTRIBUTION IS
!              DEFINED FOR ALL REAL X AND HAS THE PROBABILITY DENSITY
!              FUNCTION
!
!                 f(X;ALPHA,XI) = (1/{2*SQRT(1+ALPHA**2)*K(1)(XI)})*
!                     EXP{-XI*[SQRT(1+ALPHA**2)*SQRT(1+X**2)-ALPHA*X]}
!                     XI > 0
!              WHERE
!                 K(N,X) IS THE MODIFIED BESSEL FUNCTION OF THE
!                        SECOND KIND AND ORDER N.
!
!     NOTE--ARGUMENTS TO THIS ROUTINE ARE IN DOUBLE PRECISION.
!     INPUT  ARGUMENTS--X       = THE DOUBLE PRECISION VALUE AT
!                                 WHICH THE PROBABILITY DENSITY
!                                 FUNCTION IS TO BE EVALUATED.
!                     --ALPHA   = THE FIRST SHAPE PARAMETER
!                     --XI      = THE SECOND SHAPE PARAMETER,
!                                 XI SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--PDF     = THE DOUBLE PRECISION PROBABILITY
!                                 DENSITY FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY DENSITY FUNCTION
!             VALUE PDF FOR THE HYPERBOLIC DISTRIBUTION
!             WITH SHAPE PARAMETERS ALPHA AND XI.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--DBESK.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DEXP, DLOG.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 WILEY, 1994, PP. 60.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.9
!     ORIGINAL VERSION--SEPTEMBER 2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION X
      DOUBLE PRECISION ALPHA
      DOUBLE PRECISION XI
      DOUBLE PRECISION PDF
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DBESK1
      EXTERNAL DBESK1
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(ALPHA.LE.0.0D0)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,48)ALPHA
        CALL DPWRST('XXX','WRIT')
        PDF=0.0D0
        GO TO 9000
      ENDIF
    5 FORMAT('***** ERROR: VALUE OF FIRST SHAPE PARAMETER (ALPHA)',   &
             ' IN HBOPDF ROUTINE IS NON-POSITIVE.')
      IF(XI.LE.0.0D0)THEN
        WRITE(ICOUT,8)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,48)XI
        CALL DPWRST('XXX','WRIT')
        PDF=0.0D0
        GO TO 9000
      ENDIF
    8 FORMAT('***** ERROR: VALUE OF SECOND SHAPE PARAMETER (XI)',   &
             ' IN HBOPDF ROUTINE IS NON-POSITIVE.')
   48 FORMAT('      VALUE OF ARGUMENT IS: ',G15.7)
!
!               *****************************************
!               **  STEP 2--                           **
!               **  COMPUTE THE DENSITY FUNCTION.  FOR **
!               **  BETTER NUMERICAL STABILITY,        **
!               **  COMPUTE LOGARIGHMS.                **
!               *****************************************
!
!
      DTERM1=DLOG(2.0D0) + 0.5D0*DLOG(1.0D0+ALPHA**2) +   &
             DLOG(DBESK1(XI))
      DTERM2=-XI*(DSQRT((1.0D0+ALPHA**2)*(1.0D0+X**2)) - ALPHA*X)
      DTERM3=-DTERM1 + DTERM2
      PDF=DEXP(DTERM3)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE HBOPDF
      SUBROUTINE HCONS(Y,X,XIDTEM,TEMP,TEMP2,N,IWRITE,YOUT,NUMSET,   &
                       XBARIV,SDI,DXBARI,CELLWT,NCELL,   &
                       ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE H CONSISTENCY STATISTIC
!              OF THE DATA IN THE INPUT VECTOR Y WITH LAB ID
!              VECTOR X.  THE H CONSISTENCY STATISTIC IS DEFINED AS:
!
!                 H(i) = D(i)/s(xbar(i))
!
!              WITH
!
!                 xbar(i)     = MEAN OF GROUP I
!                 s(xbar(i))  = STANDARD DEVIATION OF THE GROUP
!                               MEANS
!                 D(i)        = xbar(i) - xbar
!                 xbar        = OVERALL MEAN
!
!     INPUT  ARGUMENTS--Y      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --X      = THE SINGLE PRECISION VECTOR OF
!                                GROUP ID's.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR Y.
!     OUTPUT ARGUMENTS--YOUT   = THE SINGLE PRECISION VECTOR OF THE
!                                COMPUTED SAMPLE H CONSISTENCY
!                                STATISTIC.
!                     --NUMSET = THE INTEGER VALUE CONTAINING THE
!                                NUMBER OF GROUPS.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VECTOR OF THE
!             SAMPLE H CONSISTENCY STATISTIC.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--SORT, DISTIN, SD.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--SQRT.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--"Standard Practice for Conducting an
!                 Interlaboratory Study to Determine the Precision
!                 of a Test Method", ASTM International,
!                 100 Barr Harbor Drive, PO BOX C700,
!                 West Conshohoceken, PA 19428-2959, USA.
!                 This document is in support of
!                 ASTM Standard E 691 - 23.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2005.2
!     ORIGINAL VERSION--FEBRUARY  2005.
!     UPDATED         --APRIL     2024. UPDATED FOR UNBALANCED DATA
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 IBAL
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION X(*)
      DIMENSION YOUT(*)
      DIMENSION XIDTEM(*)
      DIMENSION TEMP(*)
      DIMENSION TEMP2(*)
      DIMENSION XBARIV(*)
      DIMENSION SDI(*)
      DIMENSION DXBARI(*)
      DIMENSION CELLWT(*)
!
      INTEGER   NCELL(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='HCON'
      ISUBN2='S   '
      IERROR='NO'
      IBAL='YES'
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CONS')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF HCONS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N
   52   FORMAT('IBUGA3,ISUBRO,N = ',A4,1X,A4,1X,I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,Y(I),X(I)
   56     FORMAT('I,Y(I),X(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      N=N
!
      IF(N.LE.1)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN COMPUTING H CONSISTENCY STATISTIC--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS IN THE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,114)
  114   FORMAT('      VARIABLES FOR WHICH THE H CONSISTENCY ',   &
               'STATISTIC')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,115)
  115   FORMAT('      IS TO BE COMPUTED MUST BE 2 OR LARGER.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,116)
  116   FORMAT('      SUCH WAS NOT THE CASE HERE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ****************************************************
!               **  STEP 2--                                      **
!               **  COMPUTE THE H CONSISTENCY STATISTIC           **
!               ****************************************************
!
      IWRITE='OFF'
      CALL DISTIN(X,N,IWRITE,XIDTEM,NUMSET,IBUGA3,IERROR)
      CALL SORT(XIDTEM,NUMSET,XIDTEM)
      CALL MEAN(Y,N,IWRITE,XBAR,IBUGA3,IERROR)
!
      IF(NUMSET.LT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,192)
  192   FORMAT('      NUMBER OF LABS    NUMSET < 1')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      AN=N
      ANUMSE=NUMSET
!
      J=0
      NOUT=0
      NHOLD=0
      NTEMP=0
      DO 1110 ISET1=1,NUMSET
        K=0
        DO 1130 I=1,N
          IF(XIDTEM(ISET1).EQ.X(I))THEN
            K=K+1
            TEMP(K)=Y(I)
          ENDIF
 1130   CONTINUE
        NTEMP=K
!
!     2024/04: CHECK FOR BALANCED DATA
!
        IF(ISET1.EQ.1)THEN
          NHOLD=NTEMP
        ELSEIF(NTEMP.NE.NHOLD)THEN
           IBAL='NO'
           GO TO 2000
        ENDIF
!
        CALL MEAN(TEMP,NTEMP,IWRITE,XBARI,IBUGA3,IERROR)
        TEMP2(ISET1)=XBARI
        YOUT(ISET1)=XBARI - XBAR
!
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CONS')THEN
          WRITE(ICOUT,1131)ISET1,XBARI
 1131     FORMAT('ISET1,XBARI = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
 1110 CONTINUE
!
      CALL SD(TEMP2,NUMSET,IWRITE,SDBARI,IBUGA3,IERROR)
      DO 1150 I=1,NUMSET
        YOUT(I)=YOUT(I)/SDBARI
 1150 CONTINUE
      GO TO 9000
!
 2000 CONTINUE
!
      J=0
      NTEMP=0
      CALL MEAN(Y,N,IWRITE,XGRAND,IBUGA3,IERROR)
!
      DSUM=0.0D0
      DO 2110 ISET1=1,NUMSET
        K=0
        DO 2130 I=1,N
          IF(XIDTEM(ISET1).EQ.X(I))THEN
            K=K+1
            TEMP(K)=Y(I)
          ENDIF
 2130   CONTINUE
        NTEMP=K
        NCELL(ISET1)=NTEMP
        NOUT=ISET1
!
!       COMPUTE CELL MEAN, CELL SD, DIFFERENCE BETWEEN CELL
!       MEAN AND OVERALL MEAN
!
        CALL MEAN(TEMP,NTEMP,IWRITE,XMEAN,IBUGA3,IERROR)
        IF(NTEMP.EQ.1)THEN
          XSD=0.0
        ELSE
          CALL SD(TEMP,NTEMP,IWRITE,XSD,IBUGA3,IERROR)
        ENDIF
        DSUM=DSUM + DBLE(XSD)**2
        XBARIV(ISET1)=XMEAN
        SDI(ISET1)=XSD
        DXBARI(ISET1)=XBARIV(ISET1) - XGRAND
!
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'EIN2')THEN
          WRITE(ICOUT,2119)ISET1,NOUT,XGRAND,XBARIV(NOUT),   &
                           SDI(NOUT),DXBARI(NOUT)
 2119     FORMAT('ISET1,NOUT,XGRAND,XBARIV(NOUT)SDI(NOUT),',   &
                 'DXBARI(NOUT) = ',2I8,4G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
 2110 CONTINUE
!
!     2024/03: FOR UNBALANCED DATA, COMPUTE OPERATIONAL NUMBER OF
!              REPLICATES (A2.6)
!
      SUM=0.0
      SUM2=0.0
      SUM3=0.0
      DO 2160 ISET1=1,NUMSET
        AVAL=REAL(NCELL(ISET1))
        IINDX=ISET1
        SUM=SUM + (AVAL**2/REAL(N))
        SUM2=SUM2 + AVAL*DXBARI(ISET1)**2
        SUM3=SUM3 + (AVAL-1.0)*SDI(ISET1)**2
!
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CONS')THEN
          WRITE(ICOUT,2163)ISET1,AVAL,DXBARI(ISET1),SDI(ISET1)
 2163     FORMAT('ISET1,AVAL,DXBARI(ISET1),SDI(ISET1) = ',I6,3G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
 2160 CONTINUE
!
      ANSTAR=(AN - SUM)/REAL(NUMSET-1)
      DENOM=ANSTAR*REAL(NUMSET-1)
      SDXBRI=SQRT(SUM2/DENOM)
      SRPT=SQRT(SUM3/REAL(N-NUMSET))
      AVAL=SDXBRI**2 - (SRPT**2/ANSTAR)
      SL=0.0
      IF(AVAL.GT.0.0)SL=SQRT(AVAL)
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CONS')THEN
        WRITE(ICOUT,2168)SUM,SUM2,SUM3,DENOM,ANSTAR,SDXBRI
 2168   FORMAT('SUM,SUM2,SUM3,DENOM,ANSTAR,SDXBRI = ',6G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      SUM1=0.0
      SUM2=0.0
      AVAL1=SRPT**2
      DO 2170 ISET1=1,NUMSET
        AVAL2=REAL(NCELL(ISET1))
        CELLWT(ISET1)=1.0/(SL**2 + (AVAL1/AVAL2))
        SUM1=SUM1 + CELLWT(ISET1)*XBARIV(ISET1)
        SUM2=SUM2 + CELLWT(ISET1)
!
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'EIN2')THEN
          WRITE(ICOUT,2171)ISET1,CELLWT(ISET1),XBARIV(ISET1)
 2171     FORMAT('ISET1,CELLWT(ISET1),XBARIV(ISET1) = ',I6,2G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
 2170 CONTINUE
      XHAT=SUM1/SUM2
!
      SSDBAR=0.0
      DO 2172 ISET1=1,NUMSET
        DBAR=XBARIV(ISET1) - XHAT
        SSDBAR=SSDBAR + CELLWT(ISET1)*DBAR**2
 2172 CONTINUE
!
      AVAL2=SSDBAR*REAL(NUMSET)
      DO 2175 ISET1=1,NUMSET
        DBAR=XBARIV(ISET1) - XHAT
        ANUM=DBAR*REAL(NUMSET-1)
        AVAL1=(1.0/CELLWT(ISET1)) - (1.0/SUM2)
        DENOM=SQRT(AVAL1*AVAL2)
        YOUT(ISET1)=ANUM/DENOM
 2175 CONTINUE
!
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CONS')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF HCONS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGA3,ISUBRO,IERROR
 9012   FORMAT('IBUGA3,ISUBRO,IERROR = ',A4,2X,A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)N,NUMSET,XBAR
 9013   FORMAT('N,NUMSET,XBAR = ',I8,1X,I8,1X,G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)SDBARI
 9015   FORMAT('SDBARI = ',E15.7)
        CALL DPWRST('XXX','BUG ')
        DO 9018 I=1,NUMSET
          WRITE(ICOUT,9019)I,TEMP2(I),YOUT(I)
 9019     FORMAT('I,TEMP2(I),YOUT(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
 9018   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE HCONS
      SUBROUTINE HCONS2(Y,X1,X2,XIDTEM,XIDTE2,TEMP,TEMP2,N,IWRITE,   &
                        YOUT,TAG,TAG2,NOUT,   &
                        TEMP3,TEMP4,TEMP5,TEMP6,TEMP7,TEMP8,TEMP9,   &
                        ITEMP1,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE H CONSISTENCY STATISTIC
!              OF THE DATA IN THE INPUT VECTOR Y WITH LAB ID
!              VECTOR X.  THE H CONSISTENCY STATISTIC IS DEFINED AS:
!
!                 H(i) = D(i)/s(xbar(i))
!
!              WITH
!
!                 xbar(i)     = MEAN OF GROUP I
!                 s(xbar(i))  = STANDARD DEVIATION OF THE GROUP
!                               MEANS
!                 D(i)        = xbar(i) - xbar
!                 xbar        = OVERALL MEAN
!
!              THE DISTINCTION BETWEEN HCONS AND HCONS2 IS THAT
!              HCONS IS USED TO COMPUTE THE H CONSISTENCY STATISTIC
!              FOR A SINGLE MATERIAL WHILE HCONS2 COMPUTES THE
!              H CONSISTENCY STATISTIC FOR MULTIPLE MATERIALS.
!
!     INPUT  ARGUMENTS--Y      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --X1     = THE SINGLE PRECISION VECTOR OF
!                                GROUP ID's.
!                     --X2     = THE SINGLE PRECISION VECTOR OF
!                                MATERIAL ID's.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR Y.
!     OUTPUT ARGUMENTS--YOUT   = THE SINGLE PRECISION VECTOR OF THE
!                                COMPUTED SAMPLE H CONSISTENCY
!                                STATISTIC.
!                     --TAG    = THE SINGLE PRECISION VECTOR OF THE
!                                MATERIAL ID's.
!                     --TAG2   = THE SINGLE PRECISION VECTOR OF THE
!                                LAB ID's.
!                     --NOUT   = THE INTEGER VALUE CONTAINING THE
!                                NUMBER OF VALUES IN YOUT
!     OUTPUT--THE COMPUTED SINGLE PRECISION VECTOR OF THE
!             SAMPLE H CONSISTENCY STATISTIC WITH THE CORRESPONDING
!             MATERIAL ID.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--SORT, DISTIN, SD.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--SQRT.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--"Standard Practice for Conducting an
!                 Interlaboratory Study to Determine the Precision
!                 of a Test Method", ASTM International,
!                 100 Barr Harbor Drive, PO BOX C700,
!                 West Conshohoceken, PA 19428-2959, USA.
!                 This document is in support of
!                 ASTM Standard E 691 - 23.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2005.2
!     ORIGINAL VERSION--FEBRUARY  2005.
!     UPDATED         --MAY       2024. SUPPORT FOR UNBALANCE DATA
!                                       (REWRITE TO USE HCONS)
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION X1(*)
      DIMENSION X2(*)
      DIMENSION YOUT(*)
      DIMENSION TAG(*)
      DIMENSION TAG2(*)
      DIMENSION XIDTEM(*)
      DIMENSION XIDTE2(*)
      DIMENSION TEMP(*)
      DIMENSION TEMP2(*)
      DIMENSION TEMP3(*)
      DIMENSION TEMP4(*)
      DIMENSION TEMP5(*)
      DIMENSION TEMP6(*)
      DIMENSION TEMP7(*)
      DIMENSION TEMP8(*)
      DIMENSION TEMP9(*)
!
      INTEGER   ITEMP1(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='HCON'
      ISUBN2='S2  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'ONS2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF HCONS2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N
   52   FORMAT('IBUGA3,ISUBRO,N = ',A4,1X,A4,1X,I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,Y(I),X1(I),X2(I)
   56     FORMAT('I,Y(I),X1(I),X2(I) = ',I8,3G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.LE.1)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN COMPUTING H CONSISTENCY STATISTIC--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS IN THE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,114)
  114   FORMAT('      VARIABLES FOR WHICH THE H CONSISTENCY ',   &
               'STATISTIC')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,115)
  115   FORMAT('      IS TO BE COMPUTED MUST BE 2 OR LARGER.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,116)
  116   FORMAT('      SUCH WAS NOT THE CASE HERE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ****************************************************
!               **  STEP 2--                                      **
!               **  COMPUTE THE H CONSISTENCY STATISTIC           **
!               ****************************************************
!
      IWRITE='OFF'
      CALL DISTIN(X2,N,IWRITE,XIDTE2,NUMSE2,IBUGA3,IERROR)
      CALL SORT(XIDTE2,NUMSE2,XIDTE2)
!
      IF(NUMSE2.LT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,194)
  194   FORMAT('      NUMBER OF MATERIALS    NUMSE2 < 1')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      J=0
      NOUT=0
      DO 1110 ISET2=1,NUMSE2
!
!  STEP 1: EXTRACT DATA FOR A SINGLE MATERIAL AND CALL HCONS
!          TO COMPUTE H-CONSISTENCY STATISTIC
!
        K=0
        DO 1140 I=1,N
          IF(XIDTE2(ISET2).EQ.X2(I))THEN
            K=K+1
            TEMP(K)=Y(I)
            TEMP2(K)=X1(I)
          ENDIF
 1140   CONTINUE
        NTEMP=K
!
        IERROR='NO'
        CALL HCONS(TEMP,TEMP2,XIDTEM,TEMP3,TEMP4,NTEMP,   &
                   IWRITE,TEMP5,NUMSET,   &
                   TEMP6,TEMP7,TEMP8,TEMP9,ITEMP1,   &
                   ISUBRO,IBUGA3,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
!
        DO 1160 I=1,NUMSET
          NOUT=NOUT+1
          YOUT(NOUT)=TEMP5(I)
          TAG(NOUT)=XIDTE2(ISET2)
          TAG2(NOUT)=XIDTEM(I)
 1160   CONTINUE
!
!
 1110 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'ONS2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF HCONS2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)IERROR,NUMSE2,NUMSE2
 9013   FORMAT('IERROR,NUMSET,NUMSE2 = ',A4,2X,2I8)
        CALL DPWRST('XXX','BUG ')
        DO 9018 I=1,NOUT
          WRITE(ICOUT,9019)I,TAG(I),TAG2(I),YOUT(I)
 9019     FORMAT('I,TAG(I),TAG2(I),YOUT(I) = ',I8,3G15.7)
          CALL DPWRST('XXX','BUG ')
 9018   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE HCONS2
      SUBROUTINE HEADS(Y,X,TAG,N,DIST,DTAG,TAGMAX,TAGMIN,DEL,   &
                       HEADS2,NTRIAL,AVEDEL,SDAVED,   &
                       IBUGG3,ISUBRO,IERROR)
!
!     PURPOSE--DETERMINE NUMBER OF "HEADS" IN BLOCK PLOT
!     WRITTEN BY--JAMES J. FILLIBEN
!                 NATIONAL INSTITUTE OF STANDARDS & TECHNOLOGY
!                 GAITHERSBURG, MARYLAND 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     ORIGINAL VERSION--MAY     1992.
!     UPDATED         --AUGUST  2010. PASS IN TEMPORARY ARRAYS
!                                     INSTEAD OF CREATING THEM HERE
!                                     TO AVOID CONFLICTS WITH ARRAY
!                                     CREATION IN DPBLOC
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IBUGG3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION X(*)
      DIMENSION TAG(*)
      DIMENSION DIST(*)
      DIMENSION DTAG(*)
      DIMENSION TAGMAX(*)
      DIMENSION TAGMIN(*)
      DIMENSION DEL(*)
!
!CCCC DIMENSION TAGMAX(1000)
!CCCC DIMENSION TAGMIN(1000)
!CCCC DIMENSION DEL(1000)
!
!CCCC INCLUDE 'DPCOPA.INC'
!CCCC INCLUDE 'DPCOZZ.INC'
!CCCC EQUIVALENCE (GARBAG(IGARB7),TAGMAX(1))
!CCCC EQUIVALENCE (GARBAG(IGARB8),TAGMIN(1))
!CCCC EQUIVALENCE (GARBAG(IGARB9),DEL(1))
!
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IERROR='NO'
!
      IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'EADS')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,70)
   70   FORMAT('AT THE BEGINNING OF HEADS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,71)N
   71   FORMAT('N = ',I8)
        CALL DPWRST('XXX','BUG ')
        DO 75 I=1,N
          WRITE(ICOUT,76)I,Y(I),X(I),TAG(I)
   76     FORMAT('I,Y(I),X(I),TAG(I) = ',I8,3F15.7)
          CALL DPWRST('XXX','BUG ')
   75   CONTINUE
      ENDIF
!
!               **************************************************
!               **  STEP 1--                                    **
!               **  FORM A VECTOR (TAXMAX(.))                   **
!               **  WHICH WILL CONTAIN THE TAGS                 **
!               **  OF THE LARGEST ITEM IN EACH BLOCK.          **
!               **  THE NUMBER OF ITEMS IN TAGMAX(.)            **
!               **  WILL EQUAL THE NUMBER OF DISTINCT X VALUES. **
!               **************************************************
!
      CALL DISTIN(X,N,'OFF ',DIST,NTRIAL,IBUGG3,IERROR)
!
      DO 1100 ID=1,NTRIAL
!
         YIMAX=CPUMIN
         DO 1200 I=1,N
            IF(X(I).EQ.DIST(ID))THEN
               IF(Y(I).GT.YIMAX)THEN
                  YIMAX=Y(I)
                  TAGMAX(ID)=TAG(I)
               ENDIF
            ENDIF
 1200    CONTINUE
!
         YIMIN=CPUMAX
         DO 1300 I=1,N
            IF(X(I).EQ.DIST(ID))THEN
               IF(Y(I).LT.YIMIN)THEN
                  YIMIN=Y(I)
                  TAGMIN(ID)=TAG(I)
               ENDIF
            ENDIF
 1300    CONTINUE
!
      IF(TAGMAX(ID).EQ.TAGMAX(1))DEL(ID)=YIMAX-YIMIN
      IF(TAGMAX(ID).NE.TAGMAX(1))DEL(ID)=(-(YIMAX-YIMIN))
!
 1100 CONTINUE
!
!               **************************************************
!               **  STEP 2--                                    **
!               **  SCAN THE TAGMAX(.) VECTOR.                  **
!               **  DETERMINE THE MOST FREQUENT TAG IN TAXMAX(.). **
!               **  OUTPUT THAT MAX FREQUENCY (IN HEADS2).      **
!               **************************************************
!
      CALL DISTIN(TAGMAX,NTRIAL,'OFF ',DTAG,NDTAG,IBUGG3,IERROR)
!
      JMAX=(-999)
      DO 2100 IDTAG=1,NDTAG
         J=0
         DO 2200 I=1,NTRIAL
            IF(TAGMAX(I).EQ.DTAG(IDTAG))J=J+1
 2200    CONTINUE
         IF(J.GT.JMAX)JMAX=J
 2100 CONTINUE
      HEADS2=JMAX
!
!               *****************************************************
!               **  STEP 3--                                       **
!               **  COMPUTE THE AVERAGE DIFFERENCE (= EST. EFFECT) **
!               **  IN THE RESPONSE                                **
!               **  BETWEEN THE MAX AND THE MIN                    **
!               *****************************************************
!
      IWRITE='OFF'
      CALL MEAN(DEL,NTRIAL,IWRITE,AVEDEL,IBUGG3,IERROR)
      CALL SDMEAN(DEL,NTRIAL,IWRITE,SDAVED,IBUGG3,IERROR)
!
!               ******************
!               **   STEP 90--  **
!               **   EXIT       **
!               ******************
!
      IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'EADS')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('AT THE END       OF HEADS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9031)HEADS2,AVEDEL,SDAVED,NTRIAL
 9031   FORMAT('HEADS2,AVEDEL,SDAVED,NTRIAL= ',3F15.5,I8)
        CALL DPWRST('XXX','BUG ')
        DO 9033 I=1,NTRIAL
          WRITE(ICOUT,9034)I,DIST(I),TAGMAX(I)
 9034     FORMAT('I,DIST(I),TAGMAX(I) = ',I8,2F15.7)
          CALL DPWRST('XXX','BUG ')
 9033   CONTINUE
        WRITE(ICOUT,9041)NDTAG
 9041   FORMAT('NDTAG = ',I8)
        CALL DPWRST('XXX','BUG ')
        DO 9042 I=1,NDTAG
          WRITE(ICOUT,9043)I,DTAG(I)
 9043     FORMAT('I,DTAG(I) = ',I8,F15.7)
          CALL DPWRST('XXX','BUG ')
 9042   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE HEADS
      SUBROUTINE HEDGEG(Y1,Y2,N1,N2,IWRITE,STATVA,STATBC,STATSE,   &
                        ALPHA,ALCL,AUCL,   &
                        YMEAN1,YSD1,YMEAN2,YSD2,SPOOL,   &
                        ICASE,ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE HEDGE'S G STATISTIC.
!
!              GIVEN TWO SAMPLES, THE HEDGE'S G STATISTIC IS
!
!                 g = (YBAR1 - YBAR2)/S(POOLED)
!
!              WHERE
!
!                 YBAR1  = MEAN OF SAMPLE 1
!                 YBAR2  = MEAN OF SAMPEL 2
!                 S(POOLED) = THE POOLED STANDARD DEVIATION OF THE
!                             TWO SAMPLES:
!
!                             SQRT{((N1-1)*s1**2 + (N2-1)*s2**2)/
!                                  ((N1-1) + (N2-1))}
!
!                             S1 = STANDARD DEVIAITON SAMPLE ONE
!                             N1 = NUMBER OF OBSERVATIONS FOR SAMPLE ONE
!                             S2 = STANDARD DEVIAITON SAMPLE TWO
!                             N2 = NUMBER OF OBSERVATIONS FOR SAMPLE TWO
!
!              THERE IS A SMALL SAMPLE BIAS CORRECTION TERM (N=N1+N2):
!
!                 ((N-3)/(N-2.25))*SQRT((N-2)/N)
!
!              2018/08: HEDGE'S ORIGINAL APPROXIMATION WAS
!
!                           1 - 3/(4*N - 9)
!
!                        NOTE THAT THESE ARE ACTUALLY APPROXIMATING
!
!                           J(N1+N2-2)
!
!                        WHERE
!
!                           J(X) = GAMMA(X/2)/{SQRT(X/2)*GAMMA((X-1)/2)}
!
!                        RUNNING A COMPARISON FOR VALUES OF N1 AND N2
!                        FROM 2 TO 20 INDICATES THAT HEDGE'S ORIGINAL
!                        APPROXIMATION IS MORE ACCURATE.  WE WILL USE
!                        THE GAMMA FUNCTIONS FOR N1 AND N2 < 20.
!
!              THIS STATISTIC IS A MEASURE OF EFFECT SIZE IN STANDARD
!              DEVIATION UNITS.  A RULE OF THUMB IS
!
!                  0.2  => SMALL EFFECT
!                  0.5  => MODERATE EFFECT
!                  0.8  => LARGE EFFECT
!
!              THIS ROUTINE COMPUTES TWO VARIANTS OF THIS STATISTIC.
!
!                  1) COHEN'S D USES THE FOLLOWING ESTIMATE FOR
!                     THE POOLED STANDARD DEVAITION
!
!                       S(pooled) = SQRT((s1**2 + s2**2)/2)
!
!                     THAT IS, THE POOLED STANDARD DEVIATION IS NOT
!                     WEIGHTED BY SAMPLE SIZE.
!
!                     GENERALLY SPEAKING, HEDGE'S G IS PREFERRED TO
!                     COHEN'S D.
!
!                  2) GLASS'S ESTIMATE USES THE CONTROL GROUP STANDARD
!                     DEVIATION RATHER THAN THE POOLED STANDARD
!                     DEVIATION.  THIS VERSION IS SOMETIMES PREFERRED
!                     WHEN THE DIFFERENCE IN THE SAMPLE STANDARD
!                     DEVIATIONS IS LARGE.
!
!                     DATAPLOT ASSUMES THE CONTROL DATA IS IN SAMPLE
!                     TWO.
!
!     INPUT  ARGUMENTS--Y1     = THE SINGLE PRECISION VECTOR FOR SAMPLE ONE
!                     --Y2     = THE SINGLE PRECISION VECTOR FOR SAMPLE TWO
!                     --N1     = THE INTEGER NUMBER OF OBSERVATIONS FOR Y1
!                     --N2     = THE INTEGER NUMBER OF OBSERVATIONS FOR Y2
!                     --ICASE  = 'BIAS' => NO BIAS CORRECTION
!                              = 'BC  ' => BIAS CORRECTED
!                              = 'COHE' => COHEN'S D
!                              = 'GLAS' => GLASS STATISTIC
!     OUTPUT ARGUMENTS--STATVA = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED HEDGE'S G
!                     --STATBC = THE SINGLE PRECISION VALUE OF THE
!                                BIAS CORRECTED HEDGE'S G
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE HEDGE'S G.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2017/07
!     ORIGINAL VERSION--JULY      2017.
!     UPDATED         --AUGUST    2018. UPDATED BIAS CORRECTION TERM
!                                       FOR HEDGE'S G
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ICASE
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DN1
      DOUBLE PRECISION DN2
      DOUBLE PRECISION DN
      DOUBLE PRECISION DY
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DPOOL
      DOUBLE PRECISION DX
      DOUBLE PRECISION DX2
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DCORR
!
      DIMENSION Y1(*)
      DIMENSION Y2(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='HEDG'
      ISUBN2='EG  '
      IERROR='NO'
      STATVA=CPUMIN
      STATBC=CPUMIN
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'DGEG')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF HEDGEG--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,ICASE,N1,N2,ALPHA
   52   FORMAT('IBUGA3,ISUBRO,ICASE,N1,N2,ALPHA = ',3(A4,2X),2I8,G15.7)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N1
          WRITE(ICOUT,56)I,Y1(I)
   56     FORMAT('I,Y1(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
        DO 65 I=1,N2
          WRITE(ICOUT,66)I,Y2(I)
   66     FORMAT('I,Y2(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   65   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
!
      IF(N1.LT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN HEDGES G--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE NUMBER OF OBSERVATIONS FOR VARIABLE ONE IS ',   &
               'LESS THAN ONE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N1
  117   FORMAT('      THE NUMBER OF OBSERVATIONS = ',I8)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ELSEIF(N2.LT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,122)
  122   FORMAT('      THE NUMBER OF OBSERVATIONS FOR VARIABLE TWO IS ',   &
               'LESS THAN ONE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N2
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ************************************************
!               **  STEP 2--                                  **
!               **  COMPUTE THE HEDGE'S G STATISTIC.          **
!               ************************************************
!
!     COMPUTE THE MEANS AND STANDARD DEVIATIONS
!
      DN1=DBLE(N1)
      DSUM1=0.0D0
      DO 210 I=1,N1
        DSUM1=DSUM1+DBLE(Y1(I))
  210 CONTINUE
      DMEAN1=DSUM1/DN1
      DSUM1=0.0D0
      DO 220 I=1,N1
        DY=DBLE(Y1(I))
        DSUM1=DSUM1+(DY-DMEAN1)**2
  220 CONTINUE
      DSD1=0.0D0
      IF(DN1.GT.1.5D0)DSD1=DSQRT(DSUM1/(DN1-1.0D0))
!
      DN2=DBLE(N2)
      DSUM1=0.0D0
      DO 230 I=1,N2
        DSUM1=DSUM1+DBLE(Y2(I))
  230 CONTINUE
      DMEAN2=DSUM1/DN2
      DSUM1=0.0D0
      DO 240 I=1,N2
        DY=DBLE(Y2(I))
        DSUM1=DSUM1+(DY-DMEAN2)**2
  240 CONTINUE
      DSD2=0.0D0
      IF(DN2.GT.1.5D0)DSD2=DSQRT(DSUM1/(DN2-1.0D0))
      YMEAN1=REAL(DMEAN1)
      YMEAN2=REAL(DMEAN2)
      YSD1=REAL(DSD1)
      YSD2=REAL(DSD2)
!
      DNUM=DMEAN1-DMEAN2
      IF(ICASE.EQ.'COHD')THEN
        DPOOL=(DSD1**2 + DSD2**2)/2.0D0
        DPOOL=DSQRT(DPOOL)
      ELSEIF(ICASE.EQ.'GLAS')THEN
        DPOOL=DSD2
        IF(DSD2.LE.0.0D0)DSD1=0.0D0
      ELSE
        DPOOL=((DN1-1.0D0)*DSD1**2 + (DN2-1.0D0)*DSD2**2)/   &
              (DN1+DN2-2.0D0)
        DPOOL=DSQRT(DPOOL)
      ENDIF
      SPOOL=REAL(DPOOL)
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'DGEG')THEN
        WRITE(ICOUT,241)DMEAN1,DSD1,DMEAN2,DSD2
  241   FORMAT('DMEAN1,DSD1,DMEAN2,DSD2 = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,243)DNUM,DPOOL
  243   FORMAT('DNUM,DPOOL = ',2G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF(DSD1.LE.0.0D0 .AND. DSD2.LE.0.0D0)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,251)
  251   FORMAT('      THE STANDARD DEVIATIONS FOR BOTH SAMPLES ARE ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      STATVA=REAL(DNUM/DPOOL)
!
!     COMPUTE BIAS CORRECTION FACTOR
!
      N=N1+N2
      AN=REAL(N)
!CCCC CORR=((AN-3.0)/(AN-2.25))*SQRT((AN-2.0)/AN)
      IF(N.LE.40)THEN
        DN=DBLE(AN)
        DX=DN/2.0D0
        DTERM1=DGAMMA(DX)
        DTERM2=DSQRT(DX)
        DX2=(DN-1.0D0)/2.0D0
        DTERM3=DGAMMA(DX2)
        DCORR=DTERM1/(DTERM2*DTERM3)
        CORR=REAL(DCORR)
      ELSE
        CORR=1.0 - 3.0/(4.0*AN - 9.0)
      ENDIF
      STATBC=STATVA*CORR
!
!     COMPUTE STANDARD ERROR AND LOWER AND UPPER CONFIDENCE LIMITS
!
      TERM1=AN/(REAL(N1)*REAL(N2))
      TERM2=STATVA**2/(2.0*AN)
      STATSE=SQRT(TERM1 + TERM2)
      ALPHA2=ALPHA
      IF(ALPHA2.GE.1.0 .AND. ALPHA2.LE.100.0)ALPHA2=ALPHA2/100.0
      IF(ALPHA2.LE.0.0 .OR. ALPHA2.GE.1.0)THEN
        ALPHA2=0.975
      ELSEIF(ALPHA2.LT.0.5)THEN
        ALPHA2= 1.0 - (ALPHA2/2.0)
      ELSE
        ALPHA2=1.0 - ALPHA2
        ALPHA2=1.0 - (ALPHA2/2.0)
      ENDIF
      CALL NORPPF(ALPHA2,PPF)
      ALCL=STATVA - PPF*STATSE
      AUCL=STATVA + PPF*STATSE
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IF(ICASE.EQ.'HEDG')THEN
           WRITE(ICOUT,301)STATVA
  301      FORMAT('THE HEDGES G STATISTIC (NO BIAS CORRECTION) IS ',   &
                  G15.7)
          CALL DPWRST('XXX','BUG ')
        ELSEIF(ICASE.EQ.'BCHG')THEN
           WRITE(ICOUT,303)STATBC
  303      FORMAT('THE BIAS CORRECTED HEDGES G STATISTIC  IS ',G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'DGEG')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF HEDGEG--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)IERROR,STATVA,STATBC,CORR
 9014   FORMAT('IERROR,STATVA,STATBC,CORR = ',A4,2X,3G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9016)STATSE,ALPHA2,ALCL,AUCL
 9016   FORMAT('STATSE,ALPHA2,ALCL,AUCL = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE HEDGEG
      SUBROUTINE HERMIT(X,AN,HN)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE HERMITE POLYNOMIAL OF
!              ORDER N.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION INPUT ARGUMENT
!                       AN     = THE SINGLE PRECISION VALUE FOR THE
!                                ORDER OF THE FUNCTION (SHOULD BE
!                                NON-NEGATIVE ORDER)
!     OUTPUT ARGUMENTS--HN     = THE SINGLE PRECISION VALUE OF THE
!                                HERMITE POLYNOMIAL.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE
!     MODE OF INTERNAL OPERATIONS--SOME DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--"HANDBOOK OF MATHEMATICAL FUNCTIONS, AMS 55",
!                 ABRAMOWITZ AND STEGUM.
!                 USE FOLLOWING RECURRENCE FORMULA:
!                    H(N+1) = 2.0*X*H(N)-2.0*N*H(N-1)
!                 FIRST FEW TERMS ARE FROM TABLE 22.12 OF ABRAMOWITZ
!                 AND STEGUM.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--JULY       1995.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DN, DN2
      DOUBLE PRECISION DHN, DHN1, DHN2
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      N=INT(AN+0.5)
      IF(N.LT.0)THEN
        WRITE(ICOUT,6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
    6 FORMAT('***** NON-FATAL DIAGNOSTIC--THE 2ND INPUT ARGUMENT ',   &
      'TO THE HERMIT SUBROUTINE IS NEGATIVE *****')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,' *****')
!
      DX=DBLE(X)
      DN=DBLE(N)
!
      IF(N.LE.0)THEN
        HN=1.0
      ELSEIF(N.EQ.1)THEN
        HN=2.0*X
      ELSEIF(N.EQ.2)THEN
        HN=4.0*X**2 - 2.0
      ELSEIF(N.EQ.3)THEN
        DHN=8.0D0*DX**3 - 12.0D0*DX
        HN=REAL(DHN)
      ELSEIF(N.EQ.4)THEN
        DHN=16.0D0*DX**4 - 48.0D0*X**2 + 12.0D0
        HN=REAL(DHN)
      ELSEIF(N.EQ.5)THEN
        DHN=32.0D0*DX**5 - 160.0D0*DX**3 + 120.0D0*DX
        HN=REAL(DHN)
      ELSE
        DHN1=32.0D0*DX**5 - 160.0D0*DX**3 + 120.0D0*DX
        DHN2=16.0D0*DX**4 - 48.0D0*X**2 + 12.0D0
        DO 1000 I=6,N
          DN2=DBLE(I)-1.0D0
          DHN=2.0D0*DX*DHN1 - 2.0D0*DN2*DHN2
          DHN2=DHN1
          DHN1=DHN
 1000   CONTINUE
        HN=REAL(DHN)
      ENDIF
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE HERMIT
      SUBROUTINE HERCDF(X,ALPHA,BETA,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE AT THE SINGLE PRECISION VALUE X
!              FOR THE HERMITE DISTRIBUTION
!              WITH SINGLE PRECISION PARAMETERS ALPHA AND BETA.
!              THIS DISTRIBUTION IS DEFINED FOR ALL
!              NON-NEGATIVE INTEGERS.
!              THIS DISTRIBUTION HAS THE PROBABILITY FUNCTION
!                 F(X) = (ALPHA**X*H(BETA)/X!)*PR(X=0)
!              WITH H(X) DENOTING THE MODIFIED HERMITE POLYNOMIAL:
!                 H(BETA) = SUM[j=0 to INT(N/2)]
!                           [N!*X**(N-2*j)/((N-2(j)!j!2**j)]
!              THE FIRST FEW TERMS ARE:
!                 PR(X=0) = EXP[-ALPHA*BETA - ALPHA**2/2]
!                 PR(X=1) = ALPHA*BETA*PR(X=0)
!                 PR(X=2) = (ALPHA**2*(BETA**2+1)/2!)*PR(X=0)
!                 PR(X=3) = (ALPHA**3*(BETA**3+3*BETA)/3!)*PR(X=0)
!                 PR(X=4) = (ALPHA**4*(BETA**4+6*BETA**2+3)/4!)*PR(X=0)
!                 PR(X=5) = (ALPHA**5*(BETA**5+10*BETA**3+15*BETA)/5!)
!                           *PR(X=0)
!
!                 PR(X=X+1) = (1/(X+1))*ALPHA*BETA*PR(X=x) +
!                             ALPHA**2*PR(X=x-1)
!
!              FOR X <= 20, THE ABOVE RECURRENCE RELATION WILL
!              BE USED.  FOR X > 20, AN AYMPTOTIC FORMULA DUE
!              TO Y. C. PATEL WILL BE USED.  NOTE THAT THE
!              PATEL ARTICLE USES:
!
!                 A = ALPHA*BETA
!                 B = ALPHA**2/2
!
!              IF YOU WANT TO OBTAIN APPROPRIATE VALUES OF
!              ALPHA AND BETA GIVEN A AND B, THEN
!
!                 ALPHA = SQRT(2*B)
!                 BETA  = A/SQRT(2*B)
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE INTEGRAL-VALUED,
!                                AND BETWEEN 0.0 (INCLUSIVELY)
!                                AND N (INCLUSIVELY).
!                     --ALPHA  = THE SINGLE PRECISION VALUE
!                                OF THE FIRST SHAPE PARAMETER.
!                     --BETA   = THE SINGLE PRECISION VALUE
!                                OF THE SECOND SHAPE PARAMETER.
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE HERMITE DISTRIBUTION
!             WITH SHAPE PARAMETERS ALPHA AND BETA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE INTEGRAL-VALUED AND NON-NEGATIVE
!                 --ALPHA AND BETA SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--DLNGAM, DGAMMA.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DLOG, DEXP, DSQRT, DCOSH,
!                                         DSINH, DLOG10.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND KEMP, "UNIVARIATE DISCRETE
!                 DISTRIBUTIONS", SECOND EDITION, WILEY, 1992,
!                 PP. 357-364.
!               --Y. C. PATEL, "AN ASYMPTOTIC EXPRESSION FOR
!                 CUMULATIVE SUM OF PROBABILITIES OF THE HERMITE
!                 DISTRIBUTION", COMMUNICATIOS IN STATISTICS-
!                 THEORY AND METHODS, 14, PP. 2233-2241.
!               --KEMP AND KEMP, "SOME PROPERTIES OF THE HERMITE
!                 DISTRIBUTION", BIOMETRIKA, 1965, 52, 3 AND 4,
!                 P. 381
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--2004/4
!     ORIGINAL VERSION--APRIL     2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DBETA
      DOUBLE PRECISION DA
      DOUBLE PRECISION DB
      DOUBLE PRECISION DTERM1, DTERM2, DTERM3, DTERM4, DTERM5
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DCDF0
      DOUBLE PRECISION DS
      DOUBLE PRECISION DMU
      DOUBLE PRECISION DMUS
      DOUBLE PRECISION S0
      DOUBLE PRECISION K
      DOUBLE PRECISION ZS
      DOUBLE PRECISION DNUM
      DOUBLE PRECISION DDENOM
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      CDF=0.0
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(ALPHA.LE.0.0)THEN
        WRITE(ICOUT,11)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9999
      ENDIF
      IF(BETA.LE.0.0)THEN
        WRITE(ICOUT,12)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)BETA
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9999
      ENDIF
      INTX=INT(X+0.0001)
      FINTX=INTX
      DEL=X-FINTX
      IF(DEL.LT.0.0)DEL=-DEL
      IF(DEL.GT.0.001)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,6)INT(FINTX)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
      ENDIF
      IF(FINTX.LT.0.0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
!
    4 FORMAT('***** ERROR--THE FIRST ARGUMENT TO HERCDF IS NEGATIVE.')
    5 FORMAT('***** WARNING--THE FIRST ARGUMENT TO HERCDF IS ',   &
             'NON-INTEGRAL.')
    6 FORMAT('      IT HAS BEEN SET TO ',I8)
   11 FORMAT('***** ERROR--THE SECOND ARGUMENT TO HERCDF IS ',   &
             'NON-POSITIVE.')
   12 FORMAT('***** ERROR--THE THIRD ARGUMENT TO HERCDF IS ',   &
             'NON-POSITIVE.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
!
      DALPHA=DBLE(ALPHA)
      DBETA=DBLE(BETA)
      DB=DALPHA**2/2.0D0
      DA=DALPHA*DBETA
!
!  USE EXACT FORMULAS
!
      IF(INTX.LE.25)THEN
        DCDF0=DEXP(-DALPHA*DBETA - DALPHA**2/2.0D0)
        DCDF=DCDF0
        IF(INTX.EQ.0)GO TO 9010
!
        DCDF=DCDF + DALPHA*DBETA*DCDF0
        IF(INTX.EQ.1)GO TO 9010
!
        DTERM1=DALPHA**2*(DBETA*DBETA + 1.0D0)
        DCDF=DCDF + (DTERM1/2.0D0)*DCDF0
        IF(INTX.EQ.2)GO TO 9010
!
        DTERM1=DALPHA**3*(DBETA**3 + 3.0D0*DBETA)
        DCDF=DCDF + (DTERM1/6.0D0)*DCDF0
        IF(INTX.EQ.3)GO TO 9010
!
        DTERM1=DALPHA**4*(DBETA**4 + 6.0D0*DBETA**2 + 3.0D0)
        DCDF=DCDF + (DTERM1/24.0D0)*DCDF0
        IF(INTX.EQ.4)GO TO 9010
!
        DTERM1=DALPHA**5*(DBETA**5 + 10.0D0*DBETA**3 + 15.0D0*DBETA)
        DCDF=DCDF + (DTERM1/120.0D0)*DCDF0
        IF(INTX.EQ.5)GO TO 9010
!
        DTERM1=DALPHA**4*(DBETA**4 + 6.0D0*DBETA**2 + 3.0D0)
        DTERM1=(DTERM1/24.0D0)*DCDF0
        DTERM2=DALPHA**5*(DBETA**5 + 10.0D0*DBETA**3 + 15.0D0*DBETA)
        DTERM2=(DTERM2/120.0D0)*DCDF0
!
        DO 110 I=6,INTX
          DPDF=(DALPHA*DBETA*DTERM2 + DALPHA*DALPHA*DTERM1)/DBLE(I)
          DCDF=DCDF + DPDF
          DTERM1=DTERM2
          DTERM2=DPDF
  110   CONTINUE
        GO TO 9010
      ELSE
!
!  USE ASYMPTOTIC APPROXIMATION
!
        DS=DBLE(INTX)
        DMU=DA + 2.0D0*DB
        CALL HERPDF(0.0,ALPHA,BETA,PDF)
        S0=1.0D0 + 1.0D0/(12.0D0*DS) + 1.0D0/(288.0D0*DS*DS)
        DMUS=(DMU-DS)/DSQRT(DS+2.0D0*DB)
        C=DSQRT(2.0D0*DB/DS)
        K=DSQRT(1.0D0 + 2.0D0*DB/DS)
        CALL NODPDF(DMUS,ZS)
        CALL NODCDF(DMUS,DTERM1)
!
        DTERM1=1.0D0-DTERM1
        DTERM1=DTERM1*(1.0D0 + 1.0D0/(12.0D0*DS))
!
        DNUM=(DMUS**2 + (6.0D0*DB/DS) + 2.0D0)*DS
        DDENOM=3.0D0*(DS+2.0D0*DB)**(3.0D0/2.0D0)
        DTERM2=(DNUM/DDENOM)*ZS
!
        DNUM=DMUS*(DS**2 + 6.0D0*DB*DS + 48.0D0*DB*DB)
        DDENOM=12.0D0*(DS+2.0D0*DB)**3
        DTERM3=(DNUM/DDENOM)*ZS
!
        DNUM=DMUS**3*(DS + 42.0D0*DB)*DS
        DDENOM=36.0D0*(DS+2.0D0*DB)**3
        DTERM4=(DNUM/DDENOM)*ZS
!
        DNUM=DMUS**5*DS*DS
        DDENOM=18.0D0*(DS+2.0D0*DB)**3
        DTERM5=(DNUM/DDENOM)*ZS
!
        DCDF=DTERM5 + DTERM4 + DTERM3 + DTERM2 + DTERM1
        DCDF=(1.0D0/S0)*DCDF
        GO TO 9010
      ENDIF
!
 9010 CONTINUE
      CDF=REAL(DCDF)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE HERCDF
      SUBROUTINE HERPDF(X,ALPHA,BETA,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE AT THE SINGLE PRECISION VALUE X
!              FOR THE HERMITE DISTRIBUTION
!              WITH SINGLE PRECISION PARAMETERS ALPHA AND BETA.
!              THIS DISTRIBUTION IS DEFINED FOR ALL
!              NON-NEGATIVE INTEGERS.
!              THIS DISTRIBUTION HAS THE PROBABILITY FUNCTION
!                 F(X) = (ALPHA**X*H(BETA)/X!)*PR(X=0)
!              WITH H(X) DENOTING THE MODIFIED HERMITE POLYNOMIAL:
!                 H(BETA) = SUM[j=0 to INT(N/2)]
!                           [N!*X**(N-2*j)/((N-2(j)!j!2**j)]
!              THE FIRST FEW TERMS ARE:
!                 PR(X=0) = EXP[-ALPHA*BETA - ALPHA**2/2]
!                 PR(X=1) = ALPHA*BETA*PR(X=0)
!                 PR(X=2) = (ALPHA**2*(BETA**2+1)/2!)*PR(X=0)
!                 PR(X=3) = (ALPHA**3*(BETA**3+3*BETA)/3!)*PR(X=0)
!                 PR(X=4) = (ALPHA**4*(BETA**4+6*BETA**2+3)/4!)*PR(X=0)
!                 PR(X=5) = (ALPHA**5*(BETA**5+10*BETA**3+15*BETA)/5!)
!                           *PR(X=0)
!
!                 PR(X=X+1) = (1/(X+1))*ALPHA*BETA*PR(X=x) +
!                             ALPHA**2*PR(X=x-1)
!
!              FOR X <= 10, THE ABOVE RECURRENCE RELATION WILL
!              BE USED.  FOR X > 10, AN AYMPTOTIC FORMULA DUE
!              TO Y. C. PATEL WILL BE USED.  NOTE THAT THE
!              PATEL ARTICLE USES:
!
!                 A = ALPHA*BETA
!                 B = ALPHA**2/2
!
!              IF YOU WANT TO OBTAIN APPROPRIATE VALUES OF
!              ALPHA AND BETA GIVEN A AND B, THEN
!
!                 ALPHA = SQRT(2*B)
!                 BETA  = A/SQRT(2*B)
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE INTEGRAL-VALUED,
!                                AND BETWEEN 0.0 (INCLUSIVELY)
!                                AND N (INCLUSIVELY).
!                     --ALPHA  = THE SINGLE PRECISION VALUE
!                                OF THE FIRST SHAPE PARAMETER.
!                     --BETA   = THE SINGLE PRECISION VALUE
!                                OF THE SECOND SHAPE PARAMETER.
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE HERMITE DISTRIBUTION
!             WITH SHAPE PARAMETERS ALPHA AND BETA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE INTEGRAL-VALUED AND NON-NEGATIVE
!                 --ALPHA AND BETA SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--DLNGAM, DGAMMA.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DLOG, DEXP, DSQRT, DCOSH,
!                                         DSINH, DLOG10.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND KEMP, "UNIVARIATE DISCRETE
!                 DISTRIBUTIONS", SECOND EDITION, WILEY, 1992,
!                 PP. 357-364.
!               --Y. C. PATEL, "AN ASYMPTOTIC EXPRESSION FOR
!                 CUMULATIVE SUM OF PROBABILITIES OF THE HERMITE
!                 DISTRIBUTION", COMMUNICATIOS IN STATISTICS-
!                 THEORY AND METHODS, 14, PP. 2233-2241.
!               --KEMP AND KEMP, "SOME PROPERTIES OF THE HERMITE
!                 DISTRIBUTION", BIOMETRIKA, 1965, 52, 3 AND 4,
!                 P. 381
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--2004/4
!     ORIGINAL VERSION--APRIL     2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DBETA
      DOUBLE PRECISION DA
      DOUBLE PRECISION DB
      DOUBLE PRECISION DTERM1, DTERM2, DTERM3, DTERM4
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DPDF0
      DOUBLE PRECISION DTHETA
      DOUBLE PRECISION DLNGAM
      DOUBLE PRECISION DIS
      DOUBLE PRECISION DAA
      DOUBLE PRECISION BS
      DOUBLE PRECISION CS
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      PDF=0.0
      DPDF=0.0D0
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(ALPHA.LE.0.0)THEN
        WRITE(ICOUT,11)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ENDIF
      IF(BETA.LE.0.0)THEN
        WRITE(ICOUT,12)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)BETA
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ENDIF
      INTX=INT(X+0.0001)
      FINTX=INTX
      DEL=X-FINTX
      IF(DEL.LT.0.0)DEL=-DEL
      IF(DEL.GT.0.001)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,6)INT(FINTX)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
      ENDIF
      IF(FINTX.LT.0.0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
!
    4 FORMAT('***** FATAL ERROR--THE FIRST INPUT ',   &
      'ARGUMENT TO THE HERPDF SUBROUTINE IS NEGATIVE.')
    5 FORMAT('***** NON-FATAL DIAGNOSTIC--THE FIRST INPUT ',   &
      'ARGUMENT TO THE HERPDF SUBROUTINE IS NON-INTEGRAL *****')
    6 FORMAT('      IT HAS BEEN SET TO ',I8)
   11 FORMAT('***** FATAL ERROR--THE SECOND INPUT ARGUMENT TO THE ',   &
      ' HERPDF SUBROUTINE IS NON-POSITIVE')
   12 FORMAT('***** FATAL ERROR--THE THIRD INPUT ARGUMENT TO THE ',   &
      ' HERPDF SUBROUTINE IS NON-POSITIVE')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
!
      DALPHA=DBLE(ALPHA)
      DBETA=DBLE(BETA)
      DB=DALPHA**2/2.0D0
      DA=DALPHA*DBETA
!
!  USE EXACT FORMULAS
!
!CCCC IF(INTX.LE.20)THEN
      IF(INTX.LE.10)THEN
        DPDF0=DEXP(-DALPHA*DBETA - DALPHA**2/2.0D0)
        IF(INTX.EQ.0)THEN
          DPDF=DPDF0
        ELSEIF(INTX.EQ.1)THEN
          DPDF=DALPHA*DBETA*DPDF0
        ELSEIF(INTX.EQ.2)THEN
          DTERM1=DALPHA**2*(DBETA*DBETA + 1.0D0)
          DPDF=(DTERM1/2.0D0)*DPDF0
        ELSEIF(INTX.EQ.3)THEN
          DTERM1=DALPHA**3*(DBETA**3 + 3.0D0*DBETA)
          DPDF=(DTERM1/6.0D0)*DPDF0
        ELSEIF(INTX.EQ.4)THEN
          DTERM1=DALPHA**4*(DBETA**4 + 6.0D0*DBETA**2 + 3.0D0)
          DPDF=(DTERM1/24.0D0)*DPDF0
        ELSEIF(INTX.EQ.5)THEN
          DTERM1=DALPHA**5*(DBETA**5 + 10.0D0*DBETA**3 + 15.0D0*DBETA)
          DPDF=(DTERM1/120.0D0)*DPDF0
        ELSEIF(INTX.GE.6)THEN
          DTERM1=DALPHA**4*(DBETA**4 + 6.0D0*DBETA**2 + 3.0D0)
          DTERM1=(DTERM1/24.0D0)*DPDF0
          DTERM2=DALPHA**5*(DBETA**5 + 10.0D0*DBETA**3 + 15.0D0*DBETA)
          DTERM2=(DTERM2/120.0D0)*DPDF0
          DO 110 I=6,INTX
            DPDF=(DALPHA*DBETA*DTERM2 + DALPHA*DALPHA*DTERM1)/DBLE(I)
            DTERM1=DTERM2
            DTERM2=DPDF
  110     CONTINUE
        ENDIF
        PDF=REAL(DPDF)
      ELSE
        IF(MOD(INTX,2).EQ.0)THEN
          IS=INTX/2
          DIS=DBLE(IS)
          DAA=DA*DA/(8.0D0*DB)
          BS=(4.0D0*DIS+1.0D0)
          DTERM1=DSQRT(DAA)*DSQRT(DAA+BS)
          DTERM2=BS*DLOG10(DSQRT(1.0D0+DAA/BS)+DSQRT(DAA/BS))
          DTHETA=DCOSH(DTERM1 + DTERM2)
          DTERM1=-(DA+DB+DAA)
          DTERM2=DIS*DLOG(DB) - DLNGAM(DBLE(IS+1))
          DTERM3=-0.25D0*DLOG(1.0D0 + DAA/BS)
          DTERM4=DLOG(DTHETA)
          DPDF=DTERM1 + DTERM2 + DTERM3 + DTERM4
          DPDF=DEXP(DPDF)
          PDF=REAL(DPDF)
        ELSE
          IS=(INTX-1)/2
          DIS=DBLE(IS)
          DAA=DA*DA/(8.0D0*DB)
          CS=(4.0D0*DIS+3.0D0)/2.0D0
          DTERM1=DSQRT(DAA)*DSQRT(DAA+CS)
          DTERM2=CS*DLOG(DSQRT(1.0D0+DAA/CS)+DSQRT(DAA/CS))
          DTHETA=DSINH(DTERM1 + DTERM2)
          DTERM1=-(DA+DB+DAA)
          DTERM2=DIS*DLOG(DB) + 0.5D0*DLOG(2.0D0*DB) -   &
                 0.5D0*DLOG(CS) - DLNGAM(DBLE(IS+1))
          DTERM3=0.25D0*DLOG(1.0D0 + DAA/CS)
          DTERM4=DLOG(DTHETA)
          DPDF=DTERM1 + DTERM2 + DTERM3 + DTERM4
          DPDF=DEXP(DPDF)
          PDF=REAL(DPDF)
        ENDIF
!
!  USE ASYMPTOTIC APPROXIMATION
!
      ENDIF
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE HERPDF
      SUBROUTINE HERPPF(P,ALPHA,BETA,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE AT THE SINGLE PRECISION VALUE P
!              FOR THE HERMITE DISTRIBUTION
!              WITH SINGLE PRECISION PARAMETERS ALPHA AND BETA.
!              THE FIRST 25 TERMS OF THE HERMITE CUMULATIVE
!              DISTRIBUTION WILL BE COMPUTED.  IF THE PERCENT
!              POINT IS NOT FOUND WITHIN THESE FIRST 25 TERMS,
!              A BISECTION METHOD WILL BE ATTEMPTED.
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE
!                                (BETWEEN 0.0 (INCLUSIVELY)
!                                AND 1.0 (INCLUSIVELY))
!                                AT WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --ALPHA  = THE SINGLE PRECISION VALUE
!                                OF THE FIRST SHAPE PARAMETER.
!                     --BETA   = THE SINGLE PRECISION VALUE
!                                OF THE SECOND SHAPE PARAMETER.
!                                N SHOULD BE A POSITIVE INTEGER.
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION PERCENT
!                                POINT FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT  .
!             FUNCTION VALUE PPF
!             FOR THE HERMITE DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--ALPHA AND BETA SHOULD BE POSITIVE.
!                 --P SHOULD BE BETWEEN 0.0 (INCLUSIVELY)
!                   AND 1.0 (INCLUSIVELY).
!     OTHER DATAPAC   SUBROUTINES NEEDED--HERCDF
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION AND DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND KEMP, "UNIVARIATE DISCRETE
!                 DISTRIBUTIONS", SECOND EDITION, WILEY, 1992,
!                 PP. 357-364.
!               --Y. C. PATEL, "AN ASYMPTOTIC EXPRESSION FOR
!                 CUMULATIVE SUM OF PROBABILITIES OF THE HERMITE
!                 DISTRIBUTION", COMMUNICATIOS IN STATISTICS-
!                 THEORY AND METHODS, 14, PP. 2233-2241.
!               --KEMP AND KEMP, "SOME PROPERTIES OF THE HERMITE
!                 DISTRIBUTION", BIOMETRIKA, 1965, 52, 3 AND 4,
!                 P. 381
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--2004/4
!     ORIGINAL VERSION--APRIL     2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DBETA
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DCDF0
      DOUBLE PRECISION DP
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(P.LT.0.0.OR.P.GE.1.0)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9999
      ENDIF
      IF(ALPHA.LE.0.0)THEN
        WRITE(ICOUT,11)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9999
      ENDIF
      IF(BETA.LE.0.0)THEN
        WRITE(ICOUT,12)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)BETA
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9999
      ENDIF
    1 FORMAT('***** ERROR--THE FIRST ARGUMENT TO ',   &
      ' HERPPF IS OUTSIDE THE ALLOWABLE (0,1] INTERVAL')
   11 FORMAT('***** ERROR--THE SECOND ARGUMENT TO ',   &
      ' HERPPF IS NON-POSITIVE')
   12 FORMAT('***** ERROR--THE THIRD ARGUMENT TO ',   &
      ' HERPPF IS NON-POSITIVE')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
!
      PPF=0.0
!
!     TREAT CERTAIN SPECIAL CASES IMMEDIATELY--
!     1) P = 0.0
!
      IF(P.EQ.0.0)THEN
        PPF=0.0
        GO TO 9999
      ENDIF
!
!     COMPUTE THE HERCDF, TERMINATE WHEN CDF IS GREATER THAN OR
!     EQUAL TO P.
!
      DP=DBLE(P)
      DALPHA=DBLE(ALPHA)
      DBETA=DBLE(BETA)
!
      DCDF0=DEXP(-DALPHA*DBETA - DALPHA**2/2.0D0)
      DCDF=DCDF0
      IF(DCDF.GE.DP)THEN
        PPF=0.0
        GO TO 9999
      ENDIF
!
      DCDF=DCDF + DALPHA*DBETA*DCDF0
      IF(DCDF.GE.DP)THEN
        PPF=1.0
        GO TO 9999
      ENDIF
!
      DTERM1=DALPHA**2*(DBETA*DBETA + 1.0D0)
      DCDF=DCDF + (DTERM1/2.0D0)*DCDF0
      IF(DCDF.GE.DP)THEN
        PPF=2.0
        GO TO 9999
      ENDIF
!
      DTERM1=DALPHA**3*(DBETA**3 + 3.0D0*DBETA)
      DCDF=DCDF + (DTERM1/6.0D0)*DCDF0
      IF(DCDF.GE.DP)THEN
        PPF=3.0
        GO TO 9999
      ENDIF
!
      DTERM1=DALPHA**4*(DBETA**4 + 6.0D0*DBETA**2 + 3.0D0)
      DCDF=DCDF + (DTERM1/24.0D0)*DCDF0
      IF(DCDF.GE.DP)THEN
        PPF=4.0
        GO TO 9999
      ENDIF
!
      DTERM1=DALPHA**5*(DBETA**5 + 10.0D0*DBETA**3 + 15.0D0*DBETA)
      DCDF=DCDF + (DTERM1/120.0D0)*DCDF0
      IF(DCDF.GE.DP)THEN
        PPF=5.0
        GO TO 9999
      ENDIF
!
      DTERM1=DALPHA**4*(DBETA**4 + 6.0D0*DBETA**2 + 3.0D0)
      DTERM1=(DTERM1/24.0D0)*DCDF0
      DTERM2=DALPHA**5*(DBETA**5 + 10.0D0*DBETA**3 + 15.0D0*DBETA)
      DTERM2=(DTERM2/120.0D0)*DCDF0
!
      DO 110 I=6,25
        DPDF=(DALPHA*DBETA*DTERM2 + DALPHA*DALPHA*DTERM1)/DBLE(I)
        DCDF=DCDF + DPDF
        IF(DCDF.GE.DP)THEN
          PPF=REAL(I)
          GO TO 9999
        ENDIF
        DTERM1=DTERM2
        DTERM2=DPDF
  110 CONTINUE
      P0=REAL(DCDF)
!
!     IF PPF NOT FOUND IN FIRST 25 TERMS, SWITCH TO BISECTION METHOD.
!
      X0=25.0
      AMEAN=ALPHA*(ALPHA+BETA)
      ASD=SQRT(ALPHA*(2*ALPHA+BETA))
      ISD=INT(ASD)+1
!
!     DETERMINE AN UPPER BOUND BY ITERATING IN STEPS OF ONE SD.
!
      MAXIT=1000
      ICOUNT=0
  200 CONTINUE
        ICOUNT=ICOUNT+1
        IF(ICOUNT.GT.MAXIT)THEN
          WRITE(ICOUT,210)
  210     FORMAT('***** ERROR: UNABLE TO FIND UPPER BOUND IN ',   &
                 'HERPPF.')
          CALL DPWRST('XXX','BUG ')
          PPF=0.0
          GO TO 9999
        ENDIF
        X1=X0 + REAL(ISD)
        CALL HERCDF(X1,ALPHA,BETA,P1)
        IF(P1.LT.P)THEN
          X0=X1
          GO TO 200
        ENDIF
!
!     THE STOPPING CRITERION IS THAT THE LOWER BOUND
!     AND UPPER BOUND ARE EXACTLY 1 UNIT APART.
!     CHECK TO SEE IF IX1 = IX0 + 1;
!     IF SO, THE ITERATIONS ARE COMPLETE;
!     IF NOT, THEN BISECT, COMPUTE PROBABILIIES,
!     CHECK PROBABILITIES, AND CONTINUE ITERATING
!     UNTIL IX1 = IX0 + 1.
      IX0=INT(X0+ 0.01)
      IX1=INT(X1+ 0.01)
!
  300 CONTINUE
      IXOP1=IX0+1
      IF(IX1.EQ.IXOP1)THEN
        PPF=REAL(IX1)
        IF(P0.EQ.P)PPF=REAL(IX0)
        GO TO 9999
      ENDIF
      IX2=(IX0+IX1)/2
      IF(IX2.EQ.IX0 .OR. IX2.EQ.IX0)THEN
        WRITE(ICOUT,311)
  311   FORMAT('***** INTERNAL ERROR IN HERPPF  SUBROUTINE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,313)
  313   FORMAT('      BISECTION VALUE (X2) = LOWER BOUND (X0) OR ',   &
               'UPPER BOUND (X1)')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,315)X0,P0
  315   FORMAT('      X0  = ',F14.7,10X,'P0 = ',F14.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,317)X1,P1
  317   FORMAT('      X1  = ',F14.7,10X,'P1 = ',F14.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,319)X2,P2
  319   FORMAT('      X2  = ',F14.7,10X,'P2 = ',F14.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,321)P
  321   FORMAT('      P    = ',F14.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,323)ALPHA,BETA
  323   FORMAT('      ALPHA, BETA = ',F14.7,F14.7)
        CALL DPWRST('XXX','BUG ')
      ELSE
        X2=REAL(IX2)
        CALL HERCDF(X2,ALPHA,BETA,P2)
        IF(P0.LT.P2 .AND. P2.LT.P1)THEN
          IF(P2.LE.P)THEN
            IX0=IX2
            X0=REAL(IX0)
            P0=P2
          ELSE
            IX1=IX2
            X1=REAL(IX1)
            P1=P2
          ENDIF
          GO TO 300
        ELSEIF(P2.LE.P0 .OR. P2.GE.P1)THEN
          WRITE(ICOUT,311)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,313)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,315)X0,P0
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,317)X1,P1
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,319)X2,P2
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,321)P
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,323)ALPHA,BETA
          CALL DPWRST('XXX','BUG ')
        ELSE
          WRITE(ICOUT,311)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,313)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,315)X0,P0
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,317)X1,P1
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,319)X2,P2
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,321)P
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,323)ALPHA,BETA
          CALL DPWRST('XXX','BUG ')
        ENDIF
      ENDIF
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE HERPPF
      SUBROUTINE HERRAN(ALPHA,BETA,N,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE HERMITE DISTRIBUTION
!              WITH SHAPE PARAMETERS ALPHA AND BETA.
!              THIS DISTRIBUTION IS DEFINED FOR ALL
!              NON-NEGATIVE X.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --ALPHA  = THE SINGLE PRECISION VALUE
!                                OF THE FIRST SHAPE PARAMETER OF THE
!                                HERMITE DISTRIBUTION.
!                                ALPHA > 0.
!                     --BETA   = THE SINGLE PRECISION VALUE
!                                OF THE SECOND SHAPE PARAMETER OF THE
!                                HERMITE DISTRIBUTION.
!                                BETA > 0.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE HERMITE DISTRIBUTION.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --ALPHA, BETA > 0
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN, GEORAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND KEMP, "UNIVARIATE DISCRETE
!                 DISTRIBUTIONS", SECOND EDITION, WILEY, 1992,
!                 PP. 357-364.
!               --Y. C. PATEL, "AN ASYMPTOTIC EXPRESSION FOR
!                 CUMULATIVE SUM OF PROBABILITIES OF THE HERMITE
!                 DISTRIBUTION", COMMUNICATIOS IN STATISTICS-
!                 THEORY AND METHODS, 14, PP. 2233-2241.
!               --KEMP AND KEMP, "SOME PROPERTIES OF THE HERMITE
!                 DISTRIBUTION", BIOMETRIKA, 1965, 52, 3 AND 4,
!                 P. 381
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--2004/4
!     ORIGINAL VERSION--APRIL     2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION G(2)
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
      IF(ALPHA.LE.0.0)THEN
        WRITE(ICOUT,11)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
      IF(BETA.LE.0.0)THEN
        WRITE(ICOUT,12)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    5 FORMAT('***** FATAL ERROR--NUMBER OF HERMITE RANDOM ',   &
      'NUMBERS REQUESTED < 1')
   11 FORMAT('***** FATAL ERROR--THE ALPHA SHAPE PARAMETER ARGUMENT',   &
      ' TO THE HERRAN SUBROUTINE IS <= 0')
   12 FORMAT('***** FATAL ERROR--THE BETA SHAPE PARAMETER ARGUMENT',   &
      ' TO THE HERRAN SUBROUTINE IS <= 0')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,' *****')
!
!     ALGORITHM BASED ON FACT THAT HERMITE DISTRIBUTION IS
!
!          X1 + 2*X2
!
!     WHERE X1 AND X2 ARE INDPENDENT POISSON RANDOM VARIABLES
!     WITH SHAPE PARAMETERS ALPHA*BETA AND ALPHA**2/2, RESPECTIVELY.
!
      A1=ALPHA*BETA
      A2=ALPHA*ALPHA/2.0
      NTEMP=1
!
      DO 100 I=1,N
        CALL POIRAN(NTEMP,A1,ISEED,G(1))
        CALL POIRAN(NTEMP,A2,ISEED,G(2))
        X(I)=G(1) + 2.0*G(2)
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
!
      END SUBROUTINE HERRAN
      SUBROUTINE HESS(PNRFUN,X,N,SCL,STPSZ,FNBR,H,TIMEL,TIMEU,RLENGT)
!
! *   AUTHORS: Necip Doganaksoy and Wayne Nelson
! *   PURPOSE: Maximum likelihood fitting of the power-normal and
! *            -lognormal models to censored life or strength data
! *            from specimens of various sizes
! *   DOCUMENTATION: Wayne Nelson and Necip Doganaksoy, "A Computer
! *                  Program POWNOR for Fitting the Power-Normal and
! *                  -Lognormal Models to Life or Strength Data from
! *                  Specimens of Various Sizes", NISTIR 4760, 3/1992.
! *   PROJECT: 1990-91 ASA/NIST/NSF Fellowship
!
!     Declarations
!
                                                                                                                                  
      IMPLICIT DOUBLE PRECISION (a-h,o-z)
!
      DOUBLE PRECISION X(N),SCL(N),STPSZ(N),FNBR(N),H(N,N)
      DOUBLE PRECISION MACHEP
!
      DOUBLE PRECISION TIMEL(*)
      DOUBLE PRECISION TIMEU(*)
      DOUBLE PRECISION RLENGT(*)
!
      REAL R1MACH
      INCLUDE 'DPCOMC.INC'
!
      EXTERNAL PNRFUN
!
!     End declarations
!
      MACHEP = D1MACH(4)
      FC = PNRFUN(X,N,TIMEL,TIMEU,RLENGT)
      C = MACHEP**(1.0D0/3.0D0)
!
!     Calculate stepsize and updated function value
!
      DO 10 i = 1,n
          stpsz(i) = dmax1(dabs(x(i)),1.0d0/scl(i))
          stpsz(i) = stpsz(i)*c*dsign(1.0d0,x(i))
          tempi = x(i)
          x(i) = x(i) + stpsz(i)
          stpsz(i) = x(i) - tempi
          FNBR(I) = PNRFUN(X,N,TIMEL,TIMEU,RLENGT)
          x(i) = tempi
   10 CONTINUE
      DO 30 i = 1,n
!
!     Calculate Hessian
!
!
!     Calculate Diagonal Elements
!
          tempi = x(i)
          x(i) = x(i) + 2.0d0*stpsz(i)
          fii=pnrfun(x,n,timel,timeu,rlengt)
          h(i,i) = ((fc-fnbr(i))+ (fii-fnbr(i)))/ (stpsz(i)*stpsz(i))
          x(i) = tempi + stpsz(i)
          DO 20 j = i + 1,n
!
!     Calculate Off-Diagonal Elements
!
              tempj = x(j)
              x(j) = x(j) + stpsz(j)
              fij=pnrfun(x,n,timel,timeu,rlengt)
              h(i,j) = ((fc-fnbr(i))+ (fij-fnbr(j)))/   &
                       (stpsz(i)*stpsz(j))
              h(j,i) = h(i,j)
              x(j) = tempj
   20     CONTINUE
          x(i) = tempi
   30 CONTINUE
!
      RETURN
      END SUBROUTINE HESS
      SUBROUTINE HFCCDF(X,CDF)
