      SUBROUTINE HFCPPF(P,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE HALF-CAUCHY DISTRIBUTION
!              THIS DISTRIBUTION IS DEFINED FOR ALL NON-NEGATIVE X
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              F(X) = (2/PI)/(1+X**2)
!              THE HALF-CAUCHY DISTRIBUTION USED HEREIN
!              IS THE DISTRIBUTION OF THE VARIATE X = ABS(Z) WHERE
!              THE VARIATE Z IS CAUCHY DISTRIBUTED
!              NOTE THAT THE PERCENT POINT FUNCTION OF A DISTRIBUTION
!              IS IDENTICALLY THE SAME AS THE INVERSE CUMULATIVE
!              DISTRIBUTION FUNCTION OF THE DISTRIBUTION.
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE
!                                (BETWEEN 0.0 (INCLUSIVELY)
!                                AND 1.0 (EXCLUSIVELY))
!                                AT WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION PERCENT
!                                POINT FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT FUNCTION .
!             VALUE PPF FOR THE HALF-CAUCHY DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--P SHOULD BE BETWEEN 0.0 (INCLUSIVELY)
!                   AND 1.0 (EXCLUSIVELY).
!     OTHER DATAPAC   SUBROUTINES NEEDED--CAUPPF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1994, PAGE 328
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--95/10
!     ORIGINAL VERSION--OCTOBER   1995.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(P.LT.0.0.OR.P.GE.1.0)GO TO 50
      GO TO 90
   50 WRITE(ICOUT,1)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,46)P
      CALL DPWRST('XXX','BUG ')
      PPF=0.0
      RETURN
   90 CONTINUE
    1 FORMAT('***** FATAL ERROR--THE 1ST INPUT ARGUMENT TO THE ',   &
      'HFCPPF SUBROUTINE IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
!
      ARG=(1.0+P)/2.0
      CALL CAUPPF(ARG,PPF)
      IF(PPF.LE.0.0)PPF=0.0
!
      RETURN
      END SUBROUTINE HFCPPF
      SUBROUTINE HFCRAN(N,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE HALF-CAUCHY DISTRIBUTION
!              WITH MEDIAN = 0 AND 75% POINT = 1.
!              THIS DISTRIBUTION IS DEFINED FOR ALL X AND HAS
!              THE PROBABILITY DENSITY FUNCTION
!              F(X) = (2/PI)*(1/(1+X*X)).
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FUNCTION VALUE FOR THE HALF-CAUCHY DISTRIBUTION
!             WITH MEDIAN = 0 AND 75% POINT = 1.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--SIN, COS.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--TOCHER, THE ART OF SIMULATION,
!                 1963, PAGE 15.
!               --HAMMERSLEY AND HANDSCOMB, MONTE CARLO METHODS,
!                 1964, PAGE 36.
!               --FILLIBEN, SIMPLE AND ROBUST LINEAR ESTIMATION
!                 OF THE LOCATION PARAMETER OF A SYMMETRIC
!                 DISTRIBUTION (UNPUBLISHED PH.D. DISSERTATION,
!                 PRINCETON UNIVERSITY), 1969, PAGE 231.
!               --FILLIBEN, 'THE PERCENT POINT FUNCTION',
!                 (UNPUBLISHED MANUSCRIPT), 1970, PAGES 28-31.
!               --JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES 154-165.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--95/10
!     ORIGINAL VERSION--OCTOBER   1995.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
      DATA PI/3.14159265359/
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)GO TO 50
      GO TO 90
   50 WRITE(ICOUT, 5)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,47)N
      CALL DPWRST('XXX','BUG ')
      RETURN
   90 CONTINUE
    5 FORMAT('***** FATAL ERROR--THE 1ST INPUT ARGUMENT TO THE ',   &
      'HFCRAN SUBROUTINE IS NON-POSITIVE *****')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8   ,' *****')
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N CAUCHY RANDOM NUMBERS
!     USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD.
!
      DO 100 I=1,N
      ARG=PI*X(I)
      X(I)=-COS(ARG)/SIN(ARG)
  100 CONTINUE
!
!
!     GENERATE N HALF-CAUCHY RANDOM NUMBERS
!     USING THE DEFINITION THAT
!     A HALF-CAUCHY VARIATE
!     EQUALS THE ABSOLUTE VALUE OF A CAUCHY VARIATE.
!
      DO 400 I=1,N
      IF(X(I).LT.0.0)X(I)=-X(I)
  400 CONTINUE
!
      RETURN
      END SUBROUTINE HFCRAN
      SUBROUTINE HFLCDF(X,GAMMA,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE HALF-LOGISTIC DISTRIBUTION.
!              THIS DISTRIBUTION IS DEFINED FOR ALL NON-NEGATIVE X
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              F(X) = 2*EXP(-X)/(1+EXP(-X))**2    X>=0
!              THE HALF-LOGISTIC DISTRIBUTION USED HEREIN
!              IS THE DISTRIBUTION OF THE VARIATE X = ABS(Z) WHERE
!              THE VARIATE Z IS LOGISTICALLY DISTRIBUTED
!              IF GAMMA IS POSITIVE, THE GENERALIZED HALF-LOGISTIC
!              DISTRIBUTION IS COMPUTED.  THIS HAS THE PDF:
!              F(X) = 2*(1-K*X)**((1/K)-1)/(1+(1-K*X)**(1/K))**2
!                                                     0<=X<=1/K
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE NON-NEGATIVE.
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE CDF FOR THE HALF-LOGISTIC
!             DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--CAUCDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 1994, PAGES 150-151
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--OCTOBER   1995.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX, DG, DCDF
      DOUBLE PRECISION DTERM1, DTERM2, DTERM3
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(GAMMA.GT.10.0)THEN
          WRITE(ICOUT,24)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)GAMMA
          CALL DPWRST('XXX','BUG ')
          CDF=0.0
          GO TO 9999
      ENDIF
      IF(GAMMA.LE.0.0)THEN
        IF(X.LT.0.0)THEN
          WRITE(ICOUT,4)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)X
          CALL DPWRST('XXX','BUG ')
          CDF=0.0
          GO TO 9999
        ENDIF
      ELSE
        ARG1=1./GAMMA
        IF(X.LT.0.0.OR.X.GT.ARG1)THEN
          WRITE(ICOUT,14)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)X
          CALL DPWRST('XXX','BUG ')
          CDF=0.0
          GO TO 9999
        ENDIF
      ENDIF
    4 FORMAT('***** WARNING--THE FIRST ARGUMENT TO HFLCDF ',   &
             'IS NEGATIVE.')
   14 FORMAT('***** WARNING--THE FIRST  ARGUMENT TO HFLCDF IS ',   &
             'OUTSIDE THE (0,1/GAMMA) INTERVAL.')
   24 FORMAT('***** ERROR--THE SECOND ARGUMENT TO HFLCDF ',   &
             'IS GREATER THAN 10.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
!
!-----START POINT-----------------------------------------------------
!
      IF(X.EQ.0.)THEN
        CDF=0.0
        GO TO 9999
      ELSEIF(GAMMA.GT.0.0.AND.X.GE.1.0/GAMMA)THEN
        CDF=1.0
        GO TO 9999
      ENDIF
!
      DX=DBLE(X)
      DG=DBLE(GAMMA)
      IF(GAMMA.LE.0.0)THEN
        DTERM1=DLOG(1.D0-DEXP(-DX))
        DTERM2=DLOG(1.D0+DEXP(-DX))
        DTERM3=DTERM1-DTERM2
        IF(DTERM3.LE.-500.D0)THEN
          CDF=0.0
        ELSEIF(DTERM3.GE.500.D0)THEN
          CDF=1.0
        ELSE
          DCDF=DEXP(DTERM3)
          CDF=SNGL(DCDF)
        ENDIF
      ELSE
        DTERM1=DLOG(1.D0-(1.D0-DG*DX)**(1.D0/DG))
        DTERM2=DLOG(1.D0+(1.D0-DG*DX)**(1.D0/DG))
        DTERM3=DTERM1-DTERM2
        IF(DTERM3.LE.-500.D0)THEN
          CDF=0.0
        ELSEIF(DTERM3.GE.500.D0)THEN
          CDF=1.0
        ELSE
          DCDF=DEXP(DTERM3)
          CDF=SNGL(DCDF)
        ENDIF
      ENDIF
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE HFLCDF
      REAL FUNCTION HFLFUN(SIGHAT,X,N)
!
!     PURPOSE--THIS ROUTINE IS USED IN FINDING THE MAXIMUM LIKELIHOOD
!              ESTIMATE OF THE SCALE PARAMETER OF THE HALF-LOGISTIC
!              DISTRIBUTION.  THIS FUNCTION FINDS THE ROOT OF THE
!              EQUATION:
!
!                N*LOG(2) - N*LOG(SIGMA) + (N*YBAR/SIGMA) -
!                2*SUM[LOG(1 + EXP(Y(I)/SIGMA)]
!
!              CALLED BY FMIND2 ROUTINE FOR FINDING THE MINIMUM
!              OF A FUNCTION.  RETURN "NEGATIVE" OF THE FUNCTION
!              SINCE WE WANT THE MAXIMUM.
!     EXAMPLE--HALF LOGISTIC MAXIMUM LIKELIHOOD Y
!     REFERENCE--XXX
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2020/04
!     ORIGINAL VERSION--APRIL      2020.
!
!---------------------------------------------------------------------
!
      REAL SIGHAT
      DOUBLE PRECISION X(*)
!
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      COMMON/HFLCOM/DTERM1,DTERM2
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DX
      DOUBLE PRECISION DN
      DOUBLE PRECISION SG
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      SG=DBLE(SIGHAT)
      DN=DBLE(N)
      DSUM1=0.0D0
      DO 100 I=1,N
        DX=X(I)
        DTERM3=1.0D0 + DEXP(DX/SG)
        DSUM1=DSUM1 + DLOG(DTERM3)
  100 CONTINUE
!
!CCCC HFLFUN=-REAL(DTERM1 + DN*DLOG(SG) + (DTERM2/SG) - 2.0*DSUM1)
      HFLFUN=REAL(DTERM1 + DN*DLOG(SG) + (DTERM2/SG) - 2.0*DSUM1)
!CCCC write(18,*) 'sighat,hflfun = ',sighat,hflfun
!
      RETURN
      END FUNCTION HFLFUN
      SUBROUTINE HFLLI1(Y,N,ICASPL,   &
                        ALOC,SCALE,   &
                        ALIK,AIC,AICC,BIC,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE LIKELIHOOD FUNCTION FOR
!              THE HALF-LOGISTIC DISTRIBUTION.  THIS IS FOR THE RAW DATA
!              CASE (I.E., NO GROUPING AND NO CENSORING).
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!     REFERENCE--XXXX
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2020/04
!     ORIGINAL VERSION--APRIL     2020.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DNP
      DOUBLE PRECISION DLIK
      DOUBLE PRECISION DTERM3
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='HFLL'
      ISUBN2='I1  '
      IERROR='NO'
!
      ALIK=CPUMIN
      AIC=CPUMIN
      AICC=CPUMIN
      BIC=CPUMIN
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LLI1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF HFLLI1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO
   52   FORMAT('IBUGA3,ISUBRO = ',A4,2X,A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,55)N,ALOC,SCALE
   55   FORMAT('N,ALOC,SCALE = ',I8,2G15.7)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  COMPUTE LIKELIHOOD FUNCTION         **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LLI1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IERFLG=0
      IERROR='NO'
      IWRITE='OFF'
!
      NP=2
      IF(ICASPL.EQ.'1')THEN
        ALOC=0.0
        NP=1
      ENDIF
!
      ALIK=0.0
      GAMMA=CPUMIN
      DO 1000 I=1,N
        ARG1=(Y(I) - ALOC)/SCALE
        CALL HFLPDF(ARG1,GAMMA,RESULT)
        APDF=RESULT/SCALE
        IF(APDF.GT.0.0)THEN
          ALIK=ALIK + LOG(APDF)
        ENDIF
 1000 CONTINUE
!
      DN=DBLE(N)
      DLIK=DBLE(ALIK)
      DNP=DBLE(NP)
      AIC=REAL(-2.0D0*DLIK + 2.0D0*DNP)
      DTERM3=(2.0D0*DNP*(DNP+1.0D0))/(DN-DNP-1.0D0)
      AICC=REAL(-2.0D0*DLIK + 2.0D0*DNP + DTERM3)
      BIC=REAL(-2.0D0*DLIK + DNP*LOG(DN))
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LLI1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF HFLLI1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9014)ALIK,AIC,AICC,BIC
 9014   FORMAT('ALIK,AIC,AICC,BIC = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE HFLLI1
      SUBROUTINE HFLML1(Y,N,ICASPL,   &
                        TEMP1,DTEMP1,   &
                        XMEAN,XSD,XMIN,XMAX,   &
                        ALOCMO,SCALMO,ALOCML,SCALML,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE MOMENT AND MAXIMUM LIKELIHOOD
!              ESTIMATES FOR THE HALF-LOGISTIC DISTRIBUTION FOR THE RAW
!              DATA CASE (I.E., NO CENSORING AND NO GROUPING).
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!              PUT THIS IN A SEPARATE ROUTINE AS IT MAY BE CALLED
!              FROM MULTIPLE PLACES (DPMLHL WILL GENERATE THE OUTPUT
!              FOR THE HALF-LOGISTIC MLE COMMAND).
!
!              THE MOMENT ESTIMATORS ARE
!
!                  SCALEHAT = S/SQRT(1.368056)
!                  LOCHAT   = YBAR - SCALEHAT*LN(4)
!
!              THE MAXIMUM LIKELIHOOD ESTIMATORS ARE
!
!                  SCALEHAT = ...
!                  LOCHAT   = ...
!
!     REFERENCE--XXXX
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2020/06
!     ORIGINAL VERSION--JUNE      2020.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*40 IDIST
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      DIMENSION Y(*)
      DIMENSION TEMP1(*)
      DOUBLE PRECISION DTEMP1(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='HFNN'
      ISUBN2='L1  '
      IWRITE='OFF'
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LML1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF HFLML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N
   52   FORMAT('IBUGA3,ISUBRO,N = ',2(A4,2X),I8)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
        WRITE(ICOUT,59)TEMP1(1),DTEMP1(1)
   59   FORMAT('TEMP1(1),DTEMP1(1) = ',2G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CARRY OUT CALCULATIONS                **
!               **  FOR HALF-LOGISTIC MLE ESTIMATE        **
!               ********************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LML1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IDIST='HALF-LOGISTIC'
      IFLAG=0
      IF(ICASPL.EQ.'1')IFLAG=1
      CALL SUMRAW(Y,N,IDIST,IFLAG,   &
                  XMEAN,XVAR,XSD,XMIN,XMAX,   &
                  ISUBRO,IBUGA3,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      C=SQRT(1.368056)
      SCALMO=XSD/C
      IF(ICASPL.EQ.'1')THEN
        ALOCMO=0.0
      ELSE
        ALOCMO=XMEAN - SCALMO*LOG(4.0)
        IF(ALOCMO.GT.XMIN)ALOCMO=XMIN
      ENDIF
!
!     FOR NOW, SET ML ESTIMATES TO MOMENT ESTIMATES
!
      ALOCML=ALOCMO
      SCALML=SCALMO
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LML1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF HFLML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9055)N,XMEAN,XSD,XMIN,XMAX
 9055   FORMAT('N,XMEAN,XSD,XMIN,XMAX = ',I8,6G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9056)ALOCMO,SCALMO,ALOCML,SCALML
 9056   FORMAT('ALOCMO,SCALMO,ALOCML,SCALML = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE HFLML1
      SUBROUTINE HFLPDF(X,GAMMA,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE HALF-LOGISTIC DISTRIBUTION.
!              THIS DISTRIBUTION IS DEFINED FOR ALL NON-NEGATIVE X
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              F(X) = 2*EXP(-X)/(1+EXP(-X))**2    X>=0
!              THE HALF-LOGISTIC DISTRIBUTION USED HEREIN
!              IS THE DISTRIBUTION OF THE VARIATE X = ABS(Z) WHERE
!              THE VARIATE Z IS LOGISTIC DISTRIBUTED
!              IF GAMMA IS POSITIVE, THE GENERALIZED HALF-LOGISTIC
!              DISTRIBUTION IS COMPUTED.  THIS HAS THE PDF:
!              F(X) = 2*(1-K*X)**((1/K)-1)/(1+(1-K*X)**(1/K))**2
!                                                     0<=X<=1/K
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE NON-NEGATIVE.
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE HALF-LOGISTIC
!             DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--CAUPDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 1994, PAGES 150-151
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--OCTOBER   1995.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX, DG, DPDF
      DOUBLE PRECISION DTERM1, DTERM2, DTERM3, DTERM4
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PDF=0.0
      IF(GAMMA.GT.10.0)THEN
          WRITE(ICOUT,24)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)GAMMA
          CALL DPWRST('XXX','BUG ')
          GO TO 9999
      ELSEIF(GAMMA.LE.0.0)THEN
        IF(X.LT.0.0)THEN
          WRITE(ICOUT,4)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)X
          CALL DPWRST('XXX','BUG ')
          GO TO 9999
        ENDIF
      ELSE
        ARG1=1./GAMMA
        IF(X.LT.0.0.OR.X.GT.ARG1)THEN
          WRITE(ICOUT,14)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)X
          CALL DPWRST('XXX','BUG ')
          GO TO 9999
        ENDIF
      ENDIF
    4 FORMAT('***** WARNING--THE FIRST ARGUMENT TO HFLPDF IS NEGATIVE.')
   14 FORMAT('***** WARNING--THE FIRST ARGUMENT TO HFLPDF ',   &
             'IS OUTSIDE THE (0,1/GAMMA) INTERVAL.')
   24 FORMAT('***** ERROR--THE SECOND ARGUMENT TO HFLPDF ',   &
             'IS GREATER THAN 10.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
!
!-----START POINT-----------------------------------------------------
!
      IF(GAMMA.LE.0.0)THEN
        CALL LOGPDF(X,PDF)
        PDF=2.0*PDF
      ELSE
        DX=DBLE(X)
        IF(X.GE.1.0/GAMMA)THEN
          IF(GAMMA.LT.1.0)THEN
            PDF=0.0
            GO TO 9999
          ELSEIF(GAMMA.EQ.1.0)THEN
            PDF=2.0
            GO TO 9999
          ELSE
            DX=DX-0.000000001D0
          ENDIF
        ENDIF
        DG=DBLE(GAMMA)
        DTERM1=DLOG(2.0D0)
        DTERM2=((1.D0/DG)-1.D0)*DLOG(1.D0-DG*DX)
        DTERM3=2.D0*DLOG(1.D0+(1.D0-DG*DX)**(1.D0/DG))
        DTERM4=DTERM1+DTERM2-DTERM3
        IF(DABS(DTERM4).GE.40.D0)THEN
          PDF=0.0
        ELSE
          DPDF=DEXP(DTERM4)
          PDF=SNGL(DPDF)
        ENDIF
      ENDIF
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE HFLPDF
      SUBROUTINE HFLPPF(P,GAMMA,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE HALF-LOGISTIC DISTRIBUTION.
!              THIS DISTRIBUTION IS DEFINED FOR ALL NON-NEGATIVE X
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              F(X) = 2*EXP(-X)/(1+EXP(-X))**2    X>=0
!              THE HALF-LOGISTIC DISTRIBUTION USED HEREIN
!              IS THE DISTRIBUTION OF THE VARIATE X = ABS(Z) WHERE
!              THE VARIATE Z IS LOGISTIC DISTRIBUTED
!              IF GAMMA IS POSITIVE, THE GENERALIZED HALF-LOGISTIC
!              DISTRIBUTION IS COMPUTED.  THIS HAS THE PDF:
!              F(X) = 2*(1-K*X)**((1/K)-1)/(1+(1-K*X)**(1/K))**2
!                                                     0<=X<=1/K
!
!              FOR THE HALF-LOGISTIC, THE PPF FUNCTION IS:
!
!                 G(P) = -LOG((P-1)/(P+1))
!
!              FOR THE GENERALIZED HALF-LOGISTIC, THE PPF
!              FUNCTION IS:
!
!                 G(P,GAMMA) = (1 - ((1-P)/(1+P))**GAMMA)/GAMMA
!
!
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE
!                                (BETWEEN 0.0 (INCLUSIVELY)
!                                AND 1.0 (EXCLUSIVELY))
!                                AT WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION PERCENT
!                                POINT FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT FUNCTION .
!             VALUE PPF FOR THE HALF-LOGISTIC DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--P SHOULD BE BETWEEN 0.0 (INCLUSIVELY)
!                   AND 1.0 (EXCLUSIVELY).
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 1994, PAGES 150-151
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--95/10
!     ORIGINAL VERSION--OCTOBER   1995.
!     UPDATED         --JANUARY   2005. REPLACE NUMERICAL INVERSION
!                                       WITH EXPLICIT FORMULAS
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DP
      DOUBLE PRECISION DPPF
      DOUBLE PRECISION DG
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PPF=0.0
      IF(GAMMA.GT.10.0)THEN
          WRITE(ICOUT,24)
   24     FORMAT('***** ERROR--THE SECOND ARGUMENT TO HFLPPF ',   &
                 'IS GREATER THAN 10.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)GAMMA
          CALL DPWRST('XXX','BUG ')
          GO TO 9999
      ELSEIF(GAMMA.LE.0.0)THEN
        IF(P.LT.0.0.OR.P.GE.1.0)THEN
          WRITE(ICOUT,1)
    1     FORMAT('***** ERROR--THE FIRST ARGUMENT TO HFLPPF ',   &
                 'IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)P
          CALL DPWRST('XXX','BUG ')
          GO TO 9999
        ENDIF
      ELSE
        IF(P.LT.0.0.OR.P.GE.1.0)THEN
          WRITE(ICOUT,1)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)P
          CALL DPWRST('XXX','BUG ')
          GO TO 9999
        ENDIF
      ENDIF
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
!
!  STANDARD HALF-LOGISTIC CASE.  HAVE TO BOUND TO THE RIGHT.
!
      IF(P.EQ.0.0)THEN
        PPF=0.
        GO TO 9999
      ENDIF
!
      DP=DBLE(P)
      DG=DBLE(GAMMA)
!
      IF(GAMMA.LE.0.0)THEN
        DPPF=-DLOG((1.0D0-DP)/(1.0D0+DP))
      ELSE
        IF(P.EQ.1.0)THEN
          DPPF=1.0D0/DG
        ELSE
          DPPF=(1.0D0 - ((1.0D0-DP)/(1.0D0+DP))**DG)/DG
        ENDIF
      ENDIF
      PPF=REAL(DPPF)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE HFLPPF
      SUBROUTINE HFLRAN(N,GAMMA,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE HALF-LOGISTIC DISTRIBUTION
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE HALF-LOGISTIC DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--2001/10
!     ORIGINAL VERSION--OCTOBER   2001.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
    5   FORMAT('***** ERROR--THE FIRST ARGUMENT TO HFLRAN ',   &
               'IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
   47   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N HALF-LOGISTIC RANDOM NUMBERS
!     USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD
!     AND THE FACT THAT THE HALF-LOGISTIC RANDOM NUMBER IS DEFINED
!     TO BE THE ABSOLUTE VALUE OF LOGISTIC RANDOM NUMBER.
!
      DO 100 I=1,N
      CALL HFLPPF(X(I),GAMMA,XTEMP)
      X(I)=XTEMP
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE HFLRAN
      SUBROUTINE HFNCDF(X,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE HALFNORMAL
!              DISTRIBUTION.
!              THE HALFNORMAL DISTRIBUTION USED
!              HEREIN HAS MEAN = SQRT(2/PI) = 0.79788456
!              AND STANDARD DEVIATION = 1.
!              THIS DISTRIBUTION IS DEFINED FOR ALL NON-NEGATIVE X
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              F(X) = (2/SQRT(2*PI)) * EXP(-X*X/2).
!              THE HALFNORMAL DISTRIBUTION USED HEREIN
!              IS THE DISTRIBUTION OF THE VARIATE X = ABS(Z) WHERE
!              THE VARIATE Z IS NORMALLY DISTRIBUTED
!              WITH MEAN = 0 AND STANDARD DEVIATION = 1.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE NON-NEGATIVE.
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE HALFNORMAL
!             DISTRIBUTION WITH MEAN = SQRT(2/PI) = 0.79788456
!             AND STANDARD DEVIATION = 1.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NORCDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES 53, 59, 81, 83.
!               --DANIEL, 'USE OF HALF-NORMAL PLOTS IN
!                 INTERPRETING FACTORIAL TWO-LEVEL EXPERIMENTS',
!                 TECHNOMETRICS, 1959, PAGES 311-341.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-921-2315
!     ORIGINAL VERSION--APRIL     1994.
!     UPDATED         --APRIL     2021. TREAT X = 0 AS SPECIAL CASE.
!                                       USE HIGHER ACCURACY VERSION
!                                       OF NORCDF
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DCDF
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      CDF=0.0
      IF(X.LT.0.0)THEN
        WRITE(ICOUT,4)
    4   FORMAT('***** WARNING--THE FIRST ARGUMENT TO HFNCDF IS ',   &
               'NEGATIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(X.EQ.0.0)THEN
        CDF=0.0
      ELSE
!
!-------START POINT-----------------------------------------------------
!
        DX=DBLE(X)
        CALL NODCDF(X,DCDF)
        DCDF=2.0D0*DCDF-1.0D0
        CDF=REAL(DCDF)
      ENDIF
!
      RETURN
      END SUBROUTINE HFNCDF
      SUBROUTINE HFNLI1(Y,N,ICASPL,   &
                        ALOC,SCALE,   &
                        ALIK,AIC,AICC,BIC,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE LIKELIHOOD FUNCTION FOR
!              THE HALF-NORMAL DISTRIBUTION.  THIS IS FOR THE RAW DATA
!              CASE (I.E., NO GROUPING AND NO CENSORING).
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!     REFERENCE--XXXX
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2020/04
!     ORIGINAL VERSION--APRIL     2020.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DNP
      DOUBLE PRECISION DLIK
      DOUBLE PRECISION DTERM3
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='HFNL'
      ISUBN2='I1  '
      IERROR='NO'
!
      ALIK=CPUMIN
      AIC=CPUMIN
      AICC=CPUMIN
      BIC=CPUMIN
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'NLI1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF HFNLI1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO
   52   FORMAT('IBUGA3,ISUBRO = ',A4,2X,A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,55)N,ALOC,SCALE
   55   FORMAT('N,ALOC,SCALE = ',I8,2G15.7)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  COMPUTE LIKELIHOOD FUNCTION         **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'NLI1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IERFLG=0
      IERROR='NO'
      IWRITE='OFF'
!
      NP=2
      IF(ICASPL.EQ.'1')THEN
        ALOC=0.0
        NP=1
      ENDIF
!
      ALIK=0.0
      DO 1000 I=1,N
        ARG1=(Y(I) - ALOC)/SCALE
        CALL HFNPDF(ARG1,RESULT)
        APDF=RESULT/SCALE
        IF(APDF.GT.0.0)THEN
          ALIK=ALIK + LOG(APDF)
        ENDIF
 1000 CONTINUE
!
      DN=DBLE(N)
      DLIK=DBLE(ALIK)
      DNP=DBLE(NP)
      AIC=REAL(-2.0D0*DLIK + 2.0D0*DNP)
      DTERM3=(2.0D0*DNP*(DNP+1.0D0))/(DN-DNP-1.0D0)
      AICC=REAL(-2.0D0*DLIK + 2.0D0*DNP + DTERM3)
      BIC=REAL(-2.0D0*DLIK + DNP*LOG(DN))
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'NLI1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF HFNLI1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9014)ALIK,AIC,AICC,BIC
 9014   FORMAT('ALIK,AIC,AICC,BIC = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE HFNLI1
      SUBROUTINE HFNML1(Y,N,ICASPL,   &
                        XMEAN,XSD,XMIN,XMAX,   &
                        ALOCML,SCALML,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE MAXIMUM LIKELIHOOD ESTIMATES
!              FOR THE HALF-NORMAL DISTRIBUTION FOR THE RAW DATA CASE (I.E.,
!              NO CENSORING AND NO GROUPING).
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!              PUT THIS IN A SEPARATE ROUTINE AS IT MAY BE CALLED
!              FROM MULTIPLE PLACES (DPMLHN WILL GENERATE THE OUTPUT
!              FOR THE HALF-NORMAL MLE COMMAND).
!
!              THE CODE IS SET-UP TO HANDLE EITHER 1-PARAMETER OR
!              2-PARAMETER CASE.
!
!              THE ESTIMATE OF THE LOCATION PARAMETER IS THE
!              SAMPLE MINIMUM.  THE ESTIMATE OF THE SCALE PARAMETER IS
!
!                 SCALEHAT = SQRT(SUM[i=1 to N][(X(i) - YMIN)**2/N])
!
!     REFERENCE--XXXX
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2020/04
!     ORIGINAL VERSION--APRIL     2020.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*40 IDIST
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DLOC
      DOUBLE PRECISION DN
      DOUBLE PRECISION DX
!
      DIMENSION Y(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='HFNM'
      ISUBN2='L1  '
      IWRITE='OFF'
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'NML1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF HFNML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N
   52   FORMAT('IBUGA3,ISUBRO,N = ',2(A4,2X),I8)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CARRY OUT CALCULATIONS                **
!               **  FOR HALF-NORMAL MLE ESTIMATE          **
!               ********************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'NML1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IDIST='HALF-NORMAL'
      IFLAG=0
      IF(ICASPL.EQ.'1')IFLAG=1
      CALL SUMRAW(Y,N,IDIST,IFLAG,   &
                  XMEAN,XVAR,XSD,XMIN,XMAX,   &
                  ISUBRO,IBUGA3,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(ICASPL.EQ.'1')THEN
        ALOCML=0.0
      ELSE
        ALOCML=XMIN
      ENDIF
      SCALML=CPUMIN
!
      DSUM1=0.0D0
      DLOC=DBLE(ALOCML)
      DN=DBLE(N)
!
      DO 1010 I=1,N
        DX=DBLE(Y(I))
        DSUM1=DSUM1 + (DX - DLOC)**2
 1010 CONTINUE
      SCALML=REAL(DSQRT(DSUM1/DN))
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'NML1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF HFNML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9055)N,XMEAN,XSD,XMIN,XMAX
 9055   FORMAT('N,XMEAN,XSD,XMIN,XMAX = ',I8,6G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9056)DSUM1,ALOCML,SCALML
 9056   FORMAT('DSUM1,ALOCML,SCALML = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE HFNML1
      SUBROUTINE HFNPDF(X,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE HALFNORMAL DISTRIBUTION.
!              THE HALFNORMAL DISTRIBUTION USED
!              HEREIN HAS MEAN = SQRT(2/PI) = 0.79788456
!              AND STANDARD DEVIATION = 1.
!              THIS DISTRIBUTION IS DEFINED FOR ALL NON-NEGATIVE X
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              F(X) = (2/SQRT(2*PI)) * EXP(-X*X/2).
!              THE HALFNORMAL DISTRIBUTION USED HEREIN
!              IS THE DISTRIBUTION OF THE VARIATE X = ABS(Z) WHERE
!              THE VARIATE Z IS NORMALLY DISTRIBUTED
!              WITH MEAN = 0 AND STANDARD DEVIATION = 1.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE NON-NEGATIVE.
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE HALFNORMAL
!             DISTRIBUTION WITH MEAN = SQRT(2/PI) = 0.79788456
!             AND STANDARD DEVIATION = 1.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NORPDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES 53, 59, 81, 83.
!               --DANIEL, 'USE OF HALF-NORMAL PLOTS IN
!                 INTERPRETING FACTORIAL TWO-LEVEL EXPERIMENTS',
!                 TECHNOMETRICS, 1959, PAGES 311-341.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-921-2315
!     ORIGINAL VERSION--APRIL     1994.
!     UPDATED         --APRIL     2021. USE NODPDF INSTEAD OF NORPDF
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DPDF
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PDF=0.0
      IF(X.LT.0.0)THEN
        WRITE(ICOUT,4)
    4   FORMAT('***** WARNING--THE FIRST ARGUMENT TO HFNPDF IS ',   &
               'NEGATIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!-----START POINT-----------------------------------------------------
!
      DX=DBLE(X)
      CALL NODPDF(DX,DPDF)
      DPDF=2.0D0*DPDF
      PDF=REAL(DPDF)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE HFNPDF
      SUBROUTINE HFNPPF(P,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE HALFNORMAL
!              DISTRIBUTION.
!              THE HALFNORMAL DISTRIBUTION USED
!              HEREIN HAS MEAN = SQRT(2/PI) = 0.79788456
!              AND STANDARD DEVIATION = 1.
!              THIS DISTRIBUTION IS DEFINED FOR ALL NON-NEGATIVE X
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              F(X) = (2/SQRT(2*PI)) * EXP(-X*X/2).
!              THE HALFNORMAL DISTRIBUTION USED HEREIN
!              IS THE DISTRIBUTION OF THE VARIATE X = ABS(Z) WHERE
!              THE VARIATE Z IS NORMALLY DISTRIBUTED
!              WITH MEAN = 0 AND STANDARD DEVIATION = 1.
!              NOTE THAT THE PERCENT POINT FUNCTION OF A DISTRIBUTION
!              IS IDENTICALLY THE SAME AS THE INVERSE CUMULATIVE
!              DISTRIBUTION FUNCTION OF THE DISTRIBUTION.
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE
!                                (BETWEEN 0.0 (INCLUSIVELY)
!                                AND 1.0 (EXCLUSIVELY))
!                                AT WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION PERCENT
!                                POINT FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT FUNCTION .
!             VALUE PPF FOR THE HALFNORMAL DISTRIBUTION
!             WITH MEAN = SQRT(2/PI) = 0.79788456
!             AND STANDARD DEVIATION = 1.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--P SHOULD BE BETWEEN 0.0 (INCLUSIVELY)
!                   AND 1.0 (EXCLUSIVELY).
!     OTHER DATAPAC   SUBROUTINES NEEDED--NORPPF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES 53, 59, 81, 83.
!               --DANIEL, 'USE OF HALF-NORMAL PLOTS IN
!                 INTERPRETING FACTORIAL TWO-LEVEL EXPERIMENTS',
!                 TECHNOMETRICS, 1959, PAGES 311-341.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--NOVEMBER  1975.
!     UPDATED         --OCTOBER   1976.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(P.LT.0.0.OR.P.GE.1.0)GO TO 50
      GO TO 90
   50 WRITE(ICOUT,1)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,46)P
      CALL DPWRST('XXX','BUG ')
      PPF=0.0
      RETURN
   90 CONTINUE
    1 FORMAT('***** FATAL ERROR--THE 1ST INPUT ARGUMENT TO THE ',   &
      'HFNPPF SUBROUTINE IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
!
      ARG=(1.0+P)/2.0
      CALL NORPPF(ARG,PPF)
      IF(PPF.LE.0.0)PPF=0.0
!
      RETURN
      END SUBROUTINE HFNPPF
      SUBROUTINE HFNRAN(N,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE HALFNORMAL DISTRIBUTION.
!              THE PROTOTYPE HALFNORMAL DISTRIBUTION USED
!              HEREIN HAS MEAN = SQRT(2/PI) = 0.79788456
!              AND STANDARD DEVIATION = 1.
!              THIS DISTRIBUTION IS DEFINED FOR ALL NON-NEGATIVE X
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              F(X) = (2/SQRT(2*PI)) * EXP(-X*X/2).
!              THE PROTOTYPE HALFNORMAL DISTRIBUTION USED HEREIN
!              IS THE DISTRIBUTION OF THE VARIATE X = ABS(Z) WHERE
!              THE VARIATE Z IS NORMALLY DISTRIBUTED
!              WITH MEAN = 0 AND STANDARD DEVIATION = 1.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE HALFNORMAL DISTRIBUTION
!              WITH MEAN = SQRT(2/PI) = 0.79788456
!              AND STANDARD DEVIATION = 1.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG, SQRT, SIN, COS.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--TOCHER, THE ART OF SIMULATION,
!                 1963, PAGES 14-15.
!               --HAMMERSLEY AND HANDSCOMB, MONTE CARLO METHODS,
!                 1964, PAGE 36.
!               --JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES 53, 59, 81, 83.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--NOVEMBER  1975.
!     UPDATED         --JULY      1976.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION Y(2)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
      DATA PI/3.14159265359/
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)GO TO 50
      GO TO 90
   50 WRITE(ICOUT, 5)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,47)N
      CALL DPWRST('XXX','BUG ')
      RETURN
   90 CONTINUE
    5 FORMAT('***** FATAL ERROR--THE 1ST INPUT ARGUMENT TO THE ',   &
      'HFNRAN SUBROUTINE IS NON-POSITIVE *****')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,' *****')
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!     THEN GENERATE 2 ADDITIONAL UNIFORM (0,1) RANDOM NUMBERS
!     (TO BE USED BELOW IN FORMING THE N-TH NORMAL
!     RANDOM NUMBER WHEN THE DESIRED SAMPLE SIZE N
!     HAPPENS TO BE ODD).
!
      CALL UNIRAN(N,ISEED,X)
      CALL UNIRAN(2,ISEED,Y)
!
!     GENERATE N NORMAL RANDOM NUMBERS
!     USING THE BOX-MULLER METHOD.
!
      DO 200 I=1,N,2
      IP1=I+1
      U1=X(I)
      IF(I.EQ.N)GO TO 210
      U2=X(IP1)
      GO TO 220
  210 U2=Y(2)
  220 ARG1=-2.0*LOG(U1)
      ARG2=2.0*PI*U2
      SQRT1=SQRT(ARG1)
      Z1=SQRT1*COS(ARG2)
      Z2=SQRT1*SIN(ARG2)
      X(I)=Z1
      IF(I.EQ.N)GO TO 200
      X(IP1)=Z2
  200 CONTINUE
!
!     GENERATE N HALFNORMAL RANDOM NUMBERS
!     USING THE DEFINITION THAT
!     A HALFNORMAL VARIATE
!     EQUALS THE ABSOLUTE VALUE OF A NORMAL VARIATE.
!
      DO 400 I=1,N
      IF(X(I).LT.0.0)X(I)=-X(I)
  400 CONTINUE
!
      RETURN
      END SUBROUTINE HFNRAN
      SUBROUTINE HLQEST(X, N, XTEMP, LB, RB, Q, ISEED, RESULT)
!
!    SUBROUTINE HLQEST
!
!    PURPOSE       COMPUTES THE HODGES-LEHMANN LOCATION ESTIMATOR:
!                  MEDIAN OF ( X(I) + X(J) ) / 2   FOR 1 LE I LE J LE N
!
!    USAGE         CALL HLQEST(X,N,LB,RB,Q,RESULT)
!
!    ARGUMENTS  X   REAL ARRAY OF OBSERVATIONS  (INPUT)
!                 * VALUES OF X MUST BE IN NONDECREASING ORDER *
!
!               N   INTEGER NUMBER OF OBSERVATIONS  (INPUT)
!                 * N MUST NOT BE LESS THAN 1 *
!
!               LB  INTEGER ARRAY OF LENGTH N FOR WORKSPACE
!
!               RB  INTEGER ARRAY OF LENGTH N FOR WORKSPACE
!
!               Q   INTEGER ARRAY OF LENGTH N FOR WORKSPACE
!
!           ISEED   SEED FOR UNIFORM RANDOM NUMBER GENERATOR
!
!         NOTE ---  ONLY LB,RB, AND Q ARE CHANGED IN COMPUTATION
!
!   EXTERNAL ROUTINE
!              RAN  FUNCTION PROVIDING UNIFORM RANDOM VARIABLES
!                   IN THE INTERVAL (0,1)
!                   RAN REQUIRES A DUMMY INTEGER ARGUMENT
!
!   NOTES           HLQEST HAS AN EXPECTED TIME COMPLEXITY ON
!                   THE ORDER OF N * LG( N )
!
!
!                   FOR N <= 25, COMPUTE DIRECTLY
!
!  J F MONAHAN, APRIL 1982, DEPT OF STAT, N C S U, RALEIGH, N C 27650
!  FINAL VERSION  JUNE 1983
!
      REAL X(*), AMN, AMX, XRAN(1)
      REAL XTEMP(*)
      INTEGER LB(*), RB(*), Q(*), SM, SQ, I, J, K, K1, K2, L, N, NN,   &
       MDLL, MDLU, LBI, RBI, MDLROW, IQ
!
!  TAKE CARE OF SPECIAL CASES: N=1 AND N=2
!
      IF (N.LE.0) THEN
         RESULT=0.0
         RETURN
      ENDIF
!
      CALL SORT(X,N,X)
      IF (N.EQ.1) THEN
          RESULT = X(1)
          RETURN
      ELSEIF (N.EQ.2) THEN
          RESULT = (X(1)+X(2))/2.
          RETURN
      ELSEIF (N.LE.25) THEN
          NN = 0
          DO 1 I=1,N
            DO 2 J = I,N
              NN = NN + 1
              XTEMP(NN) = X(I) + X(J)
 2          CONTINUE
 1        CONTINUE
          CALL SORT(XTEMP,NN,XTEMP)
          K=(NN+1)/2
          IF(2*K.EQ.NN) XTEMP(K) = (XTEMP(K) + XTEMP(K+1))/2.
          RESULT=XTEMP(K)/2.
          RETURN
      ENDIF
!
!  FIND THE TOTAL NUMBER OF PAIRS (NN) AND THE MEDIAN(S) (K1,K2) NEEDED
!
      NN = (N*(N+1))/2
      K1 = (NN+1)/2
      K2 = (NN+2)/2
!
!  INITIALIZE LEFT AND RIGHT BOUNDS
!
      DO 20 I=1,N
        LB(I) = I
        RB(I) = N
   20 CONTINUE
!  SM = NUMBER IN SET S AT STEP M
      SM = NN
!  L = NUMBER OF PAIRS LESS THAN THOSE IN SET S AT STEP M
      L = 0
!
!
!  USE THE MEDIAN OF X(I)'S TO PARTITION ON THE FIRST STEP
!
      MDLL = (N+1)/2
      MDLU = (N+2)/2
      AM = X(MDLL) + X(MDLU)
      GO TO 80
!
!  USE THE MIDRANGE OF SET S AS PARTITION ELEMENT WHEN TIES ARE LIKELY
!   -- OR GET THE AVERAGE OF THE LAST 2 ELEMENTS
!
   30 CONTINUE
      AMX = X(1) + X(1)
      AMN = X(N) + X(N)
      DO 40 I=1,N
!   SKIP THIS ROW IF NO ELEMENT IN IT IS IN SET S ON THIS STEP
        IF (LB(I).GT.RB(I)) GO TO 40
        LBI = LB(I)
!                             GET THE SMALLEST IN THIS ROW
        AMN = AMIN1(AMN,X(LBI)+X(I))
        RBI = RB(I)
!                             GET THE LARGEST IN THIS ROW
        AMX = AMAX1(AMX,X(RBI)+X(I))
   40 CONTINUE
      AM = (AMX+AMN)/2.
!  BE CAREFUL TO CUT OFF SOMETHING -- ROUNDOFF CAN DO WIERD THINGS
      IF (AM.LE.AMN .OR. AM.GT.AMX) AM = AMX
!  UNLESS FINISHED, JUMP TO PARTITION STEP
      IF (AMN.NE.AMX .AND. SM.NE.2) GO TO 80
!  ALL DONE IF ALL OF S IS THE SAME -OR- IF ONLY 2 ELEMENTS ARE LEFT
      RESULT = AM/2.
      RETURN
!
!   *****   RESTART HERE UNLESS WORRIED ABOUT TIES   *****
!
   50 CONTINUE
!                        USE RANDOM ROW MEDIAN AS PARTITION ELEMENT
!CCCC FOR DATAPLOT: CALL UNIRAN
!CCCC K = IFIX(FLOAT(SM)*RAN(SM))
      NTEMP=1
      CALL UNIRAN(NTEMP, ISEED, XRAN)
      K = IFIX(FLOAT(SM)*XRAN(1))
!                        K IS A RANDOM INTEGER FROM O TO SM-1
      DO 60 I=1,N
        J = I
        IF (K.LE.RB(I)-LB(I)) GO TO 70
        K = K - RB(I) + LB(I) - 1
   60 CONTINUE
!                        J IS A RANDOM ROW --- NOW GET ITS MEDIAN
   70 MDLROW = (LB(J)+RB(J))/2
      AM = X(J) + X(MDLROW)
!
!       *****   PARTITION STEP   *****
!
!  USE AM TO PARTITION S0 INTO 2 GROUPS: THOSE .LT. AM, THOSE .GE. AM
!  Q(I)= HOW MANY PAIRS (X(I)+X(J)) IN ROW I LESS THAN AM
   80 CONTINUE
      J = N
!                              START IN UPPER RIGHT CORNER
      SQ = 0
!                              I COUNTS ROWS
      DO 110 I=1,N
        Q(I) = 0
!                              HAVE WE HIT THE DIAGONAL ?
   90   IF (J.LT.I) GO TO 110
!                              SHALL WE MOVE LEFT ?
        IF (X(I)+X(J).LT.AM) GO TO 100
        J = J - 1
        GO TO 90
!                              WE'RE DONE IN THIS ROW
  100   Q(I) = J - I + 1
!  SQ = TOTAL NUMBER OF PAIRS LESS THAN AM
        SQ = SQ + Q(I)
  110 CONTINUE
!
!  ***  FINISHED PARTITION --- START BRANCHING  ***
!
!  IF CONSECUTIVE PARTITIONS ARE THE SAME WE PROBABLY HAVE TIES
      IF (SQ.EQ.L) GO TO 30
!
!  ARE WE NEARLY DONE, WITH THE VALUES WE WANT ON THE BORDER?
!  IF(WE NEED  MAX OF THOSE .LT. AM -OR- MIN OF THOSE .GE. AM) GO TO 90
!
      IF (SQ.EQ.K2-1) GO TO 180
!
!  THE SET S IS SPLIT, WHICH PIECE DO WE KEEP?
!  70  =  CUT OFF BOTTOM,   90  =  NEARLY DONE,   60  =  CUT OFF TOP
!
!CCCC IF (SQ-K1) 140, 180, 120
      IF (SQ-K1.LT.0) THEN
         GO TO 140
      ELSEIF (SQ-K1.EQ.0) THEN
        GO TO 180
      ELSE
        GO TO 120
      ENDIF
!
!  NEW S = (OLD S) .INTERSECT. (THOSE .LT. AM)
  120 CONTINUE
      DO 130 I=1,N
!                            RESET RIGHT BOUNDS FOR EACH ROW
        RB(I) = I + Q(I) - 1
  130 CONTINUE
      GO TO 160
!  NEW S = (OLD S) .INTERSECT. (THOSE .GE. AM)
  140 CONTINUE
      DO 150 I=1,N
!                            RESET LEFT BOUNDS FOR EACH ROW
        LB(I) = I + Q(I)
  150 CONTINUE
!
!  COUNT   SM = NUMBER OF PAIRS STILL IN NEW SET S
!           L = NUMBER OF PAIRS LESS THAN THOSE IN NEW SET S
  160 L = 0
      SM = 0
      DO 170 I=1,N
        L = L + LB(I) - I
        SM = SM + RB(I) - LB(I) + 1
  170 CONTINUE
!
!        *****   NORMAL RESTART JUMP   *****
!
      IF (SM.GT.2) GO TO 50
!  CAN ONLY GET TO 2 LEFT IF K1.NE.K2  -- GO GET THEIR AVERAGE
      GO TO 30
!
!  FIND:   MAX OF THOSE .LT. AM
!          MIN OF THOSE .GE. AM
  180 CONTINUE
      AMN = X(N) + X(N)
      AMX = X(1) + X(1)
      DO 190 I=1,N
        IQ = Q(I)
        IPIQ = I + IQ
        IF (IQ.GT.0) AMX = AMAX1(AMX,X(I)+X(IPIQ-1))
        IPIQ = I + IQ
        IF (IQ.LT.N-I+1) AMN = AMIN1(AMN,X(I)+X(IPIQ))
  190 CONTINUE
      RESULT = (AMN+AMX)/4.
!  WE ARE DONE, BUT WHICH SITUATION ARE WE IN?
      IF (K1.LT.K2) RETURN
      IF (SQ.EQ.K1) RESULT = AMX/2.
      IF (SQ.EQ.K1-1) RESULT = AMN/2.
      RETURN
      END SUBROUTINE HLQEST
      SUBROUTINE HN(NX,DHN)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE HARMONIC NUMBER
!              FUNCTION FOR REAL ARGUMENTS GREATER THAN 1.
!
!              THE HARMONIC NUMBER IS:
!
!                 H(N)=SUM[K=1 to N][1/K]
!
!              THE HARMONIC NUMBER CAN BE COMPUTED IN EITHER
!              OF THE FOLLOWING TWO WAYS:
!
!              1) H(N) = PSI(N+1) + gamma
!                 WHERE gamma IS EULER'S CONSTANT
!
!              2) H(N) = gamma + LOG(N) + (1/2)*N**(-2) +
!                        (1/120)*N**(-4) + O(n**(-6))
!
!              IN THIS SUBROUTINE, WE WILL USE DIRECT SUMMATION
!              FOR N <= 30.  FOR N > 30, WE WILL USE THE PSI
!              FUNCTION.
!
!     INPUT  ARGUMENTS--NX     = THE INTEGR VALUE OF THE ORDER OF
!                                THE HARMONIC NUMBER
!     OUTPUT ARGUMENTS--DHN    = THE DOUBLE PRECISION HARMONIC
!                                NUMBER
!     OUTPUT--THE DOUBLE PRECISION HARMONIC NUMBER DHN.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--DPSI.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--XX
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBRUG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006.9
!     ORIGINAL VERSION--MAY       2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-----------------
!
!-------------------------------------------------------------------
!
      IMPLICIT DOUBLE PRECISION (A-H, O-Z)
      EXTERNAL DPSI
      DOUBLE PRECISION DPSI
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-----------------------------------------------
!
!CCCC DATA DEPS/1.0D-20/
!
!-----START POINT---------------------------------------------------
!
      IF(NX.LT.1)THEN
        WRITE(ICOUT,51)
   51   FORMAT('***** ERROR FROM HARMNUMB FUNCTION--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)
   53   FORMAT('      THE FIRST ARGUMENT (N) MUST BE A POSITIVE ',   &
               'INTEGER')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,55)NX
   55   FORMAT('      VALUE OF THE ARGUMENT IS ',I8)
        CALL DPWRST('XXX','BUG ')
        DHN=0.0D0
        GO TO 9000
      ENDIF
!
!     FOR N <= 30, JUST DO A DIRECT SUM.
!
      IF(NX.LE.30)THEN
        DSUM=0.0D0
        DO 100 I=NX,1,-1
          DSUM=DSUM + 1.0D0/DBLE(I)
  100   CONTINUE
        DHN=DSUM
!
!     OTHERWISE, USE DPSI FUNCTION
!
      ELSE
        DHN=DPSI(DBLE(NX+1)) + 0.5772156649
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE HN
      SUBROUTINE HNM(NX,DM,DHNM)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE GENERALIZED HARMONIC
!              NUMBER FUNCTION FOR REAL ARGUMENTS GREATER THAN 1.
!
!              THE GENERALIZED HARMONIC NUMBER IS:
!
!                 H(N,M)=SUM[K=1 to N][1/K**M]
!
!              THIS IS RELATED TO THE RIEMAN-ZETA SUM:
!
!                 ZETA(M)=SUM[K=1 to INFINITY][1/K**M]
!
!              THAT IS, THE ZETA SUM IS THE LIMIT OF THE
!              GENERALIZED HARMONIC NUMBER AS N GOES TO INFINITY.
!
!              WE ADAPT THE CODE FOR COMPUTING THE RIEMAN-ZETA SUM.
!              THIS CODE IS BASED ON EULER-MACMACLAURIN SUMMATION.
!
!              FOR BETTER COMPUTATIONAL ACCURACY, ACTUALLY
!              COMPUTE ZETA(X) - 1.
!     INPUT  ARGUMENTS--DNX    = THE DOUBLE PRECISION VALUE OF
!                                THE N ARGUMENT
!                     --DM     = THE DOUBLE PRECISION VALUE OF
!                                THE M ARGUMENT
!     OUTPUT ARGUMENTS--DHNM   = THE DOUBLE PRECISION GENERALIZED
!                                HARMONIC NUMBER
!     OUTPUT--THE DOUBLE PRECISION GENERALIZED HARMONIC NUMBER DHNM.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--NATIONAL BUREAU OF STANDARDS APPLIED MATHEMATICS
!                 SERIES 55, 1964.
!               --THOMPSON, "ATLAS FOR COMPUTING MATHEMATICAL
!                 FUNCTIONS", WILEY, 1997.  THIS ROUTINE IS A
!                 FORTRAN TRANSLATION OF THE C FUNCTION ON PAGE 146
!                 OF THIS BOOK.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBRUG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006.9
!     ORIGINAL VERSION--MAY       2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-----------------
!
!-------------------------------------------------------------------
!
      IMPLICIT DOUBLE PRECISION (A-H, O-Z)
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-----------------------------------------------
!
!CCCC DATA DEPS/1.0D-30/
!
!-----START POINT---------------------------------------------------
!
      IF(NX.LT.1)THEN
        WRITE(ICOUT,51)
   51   FORMAT('***** ERROR FROM GENEHARM FUNCTION--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)
   53   FORMAT('      THE FIRST ARGUMENT (N) MUST BE A POSITIVE ',   &
               'INTEGER')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,55)NX
   55   FORMAT('      VALUE OF THE ARGUMENT IS ',I8)
        CALL DPWRST('XXX','BUG ')
        DHNM=0.0D0
        GO TO 9000
      ELSEIF(DM.LE.1.0D0)THEN
        WRITE(ICOUT,51)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,63)
   63   FORMAT('      THE SECOND ARGUMENT (M) MUST BE > 1')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,65)DM
   65   FORMAT('      VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        DHNM=0.0D0
        GO TO 9000
      ENDIF
!
!CCCC DX=DM
!
!CCCC DSTERM=DX*(DX+1.0D0)*(DX+2.0D0)*
!CCCC1       (DX+3.0D0)*(DX+4.0D0)/30240.0D0
!CCCC DTERM1=DSTERM*(2.0D0**DX)/DEPS
!CCCC DTERM2=DTERM1**(1.0D0/(DX+5.0D0))
!CCCC IF(DTERM2.LE.10.01)THEN
!CCCC   N=10
!CCCC ELSE
!CCCC   N=INT(DTERM2)
!CCCC ENDIF
!
!CCCC DSUM2=0.0D0
!CCCC DO190I=1,MIN(N,NX)
!CCCC     DSUM2=DSUM2 + 1.0D0/DBLE(I)**DX
!C190 CONTINUE
!CCCC print *,'nx,n,dsum2=',nx,n,dsum2
!
!     FOR NOW, JUST COMPUTE BY DIRECT SUMMATION.  NEED TO
!     FIND A BETTER ALGORITHM FOR THIS FUNCTION.
!
      DX=DM
      N=NX
!CCCC IF(N.LE.30)THEN
        DSUM=0.0D0
        DO 200 I=N,1,-1
          DSUM=DSUM + 1.0D0/DBLE(I)**DX
  200   CONTINUE
        DHNM=DSUM
!
!     OTHERWISE, USE ZETA APPROXIMATION WHERE N MAY BE
!     TRUNCATED SOONER THAN FOR ZETA.
!
!CCCC ELSE
!CCCC   FN=DBLE(N)
!CCCC   DNEGX=-DX
!CCCC   DSUM=0.0D0
!CCCC   DO100K=2,N-1
!CCCC     DSUM=DSUM + DBLE(K)**DNEGX
!100    CONTINUE
!
!CCCC   DSUM = DSUM +
!CCCC1         (FN**DNEGX)*(0.5D0 + FN/(DX-1.0D0)
!CCCC1         + DX*(1.0D0 -
!CCCC1         (DX+1.0D0)*(DX+2.0D0)/(60.0D0*FN*FN))/(12.0D0*FN))
!CCCC1         + DSTERM/(FN**(DX+0.5D0))
!
!CCCC   DHNM=DSUM + 1.0D0
!CCCC ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE HNM
      SUBROUTINE HOOKDR(NR,N,X,F,G,A,UDIAG,P,XPLS,FPLS,   &
           SX,STEPMX,   &
           STEPTL,DLT,IRETCD,MXTAKE,AMU,DLTP,PHI,PHIP0,   &
           SC,XPLSP,WRK0,EPSM,ITNCNT,IPR)
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
! PURPOSE
! -------
! FIND A NEXT NEWTON ITERATE (XPLS) BY THE MORE-HEBDON METHOD
!
! PARAMETERS
! ----------
! NR           --> ROW DIMENSION OF MATRIX
! N            --> DIMENSION OF PROBLEM
! X(N)         --> OLD ITERATE X[K-1]
! F            --> FUNCTION VALUE AT OLD ITERATE, F(X)
! G(N)         --> GRADIENT AT OLD ITERATE, G(X), OR APPROXIMATE
! A(N,N)       --> CHOLESKY DECOMPOSITION OF HESSIAN IN LOWER
!                  TRIANGULAR PART AND DIAGONAL.
!                  HESSIAN IN UPPER TRIANGULAR PART AND UDIAG.
! UDIAG(N)     --> DIAGONAL OF HESSIAN IN A(.,.)
! P(N)         --> NEWTON STEP
! XPLS(N)     <--  NEW ITERATE X[K]
! FPLS        <--  FUNCTION VALUE AT NEW ITERATE, F(XPLS)
! OPTFCN       --> NAME OF SUBROUTINE TO EVALUATE FUNCTION
! SX(N)        --> DIAGONAL SCALING MATRIX FOR X
! STEPMX       --> MAXIMUM ALLOWABLE STEP SIZE
! STEPTL       --> RELATIVE STEP SIZE AT WHICH SUCCESSIVE ITERATES
!                  CONSIDERED CLOSE ENOUGH TO TERMINATE ALGORITHM
! DLT         <--> TRUST REGION RADIUS
! IRETCD      <--  RETURN CODE
!                    =0 SATISFACTORY XPLS FOUND
!                    =1 FAILED TO FIND SATISFACTORY XPLS SUFFICIENTLY
!                       DISTINCT FROM X
! MXTAKE      <--  BOOLEAN FLAG INDICATING STEP OF MAXIMUM LENGTH USED
! AMU         <--> [RETAIN VALUE BETWEEN SUCCESSIVE CALLS]
! DLTP        <--> [RETAIN VALUE BETWEEN SUCCESSIVE CALLS]
! PHI         <--> [RETAIN VALUE BETWEEN SUCCESSIVE CALLS]
! PHIP0       <--> [RETAIN VALUE BETWEEN SUCCESSIVE CALLS]
! SC(N)        --> WORKSPACE
! XPLSP(N)     --> WORKSPACE
! WRK0(N)      --> WORKSPACE
! EPSM         --> MACHINE EPSILON
! ITNCNT       --> ITERATION COUNT
! IPR          --> DEVICE TO WHICH TO SEND OUTPUT
!
      DIMENSION X(N),G(N),P(N),XPLS(N),SX(N)
      DIMENSION A(NR,1),UDIAG(N)
      DIMENSION SC(N),XPLSP(N),WRK0(N)
      LOGICAL MXTAKE,NWTAKE
      LOGICAL FSTIME
!DPLT EXTERNAL OPTFCN
!
      IRETCD=4
      FSTIME=.TRUE.
      TMP=0.
      DO 5 I=1,N
        TMP=TMP+SX(I)*SX(I)*P(I)*P(I)
    5 CONTINUE
      RNWTLN=SQRT(TMP)
!$    WRITE(IPR,954) RNWTLN
!
      IF(ITNCNT.GT.1) GO TO 100
!     IF(ITNCNT.EQ.1)
!     THEN
        AMU=0.
!
!       IF FIRST ITERATION AND TRUST REGION NOT PROVIDED BY USER,
!       COMPUTE INITIAL TRUST REGION.
!
        IF(DLT.NE. (-1.)) GO TO 100
!       IF(DLT.EQ. (-1.))
!       THEN
          ALPHA=0.
          DO 10 I=1,N
            ALPHA=ALPHA+(G(I)*G(I))/(SX(I)*SX(I))
   10     CONTINUE
          BETA=0.0
          DO 30 I=1,N
            TMP=0.
            DO 20 J=I,N
              TMP=TMP + (A(J,I)*G(J))/(SX(J)*SX(J))
   20       CONTINUE
            BETA=BETA+TMP*TMP
   30     CONTINUE
          DLT=ALPHA*SQRT(ALPHA)/BETA
          DLT = MIN(DLT, STEPMX)
!$        WRITE(IPR,950)
!$        WRITE(IPR,951) ALPHA,BETA,DLT
!       ENDIF
!     ENDIF
!
  100 CONTINUE
!
! FIND NEW STEP BY MORE-HEBDON ALGORITHM
      CALL HOOKST(NR,N,G,A,UDIAG,P,SX,RNWTLN,DLT,AMU,   &
           DLTP,PHI,PHIP0,FSTIME,SC,NWTAKE,WRK0,EPSM,IPR)
      DLTP=DLT
!
! CHECK NEW POINT AND UPDATE TRUST REGION
!DPLT CALL TREGUP(NR,N,X,F,G,A,OPTFCN,SC,SX,NWTAKE,STEPMX,STEPTL,
      CALL TREGUP(NR,N,X,F,G,A,SC,SX,NWTAKE,STEPMX,STEPTL,   &
               DLT,IRETCD,XPLSP,FPLSP,XPLS,FPLS,MXTAKE,IPR,3,UDIAG)
      IF(IRETCD.LE.1) RETURN
      GO TO 100
!
!C950 FORMAT(43H HOOKDR    INITIAL TRUST REGION NOT GIVEN. ,
!C   +       21H COMPUTE CAUCHY STEP.)
!C951 FORMAT(18H HOOKDR    ALPHA =,E20.13/
!C   +       18H HOOKDR    BETA  =,E20.13/
!C   +       18H HOOKDR    DLT   =,E20.13)
!C952 FORMAT(28H HOOKDR    CURRENT STEP (SC))
!C954 FORMAT(18H0HOOKDR    RNWTLN=,E20.13)
!C955 FORMAT(14H HOOKDR       ,5(E20.13,3X))
      END SUBROUTINE HOOKDR
      SUBROUTINE HOOKST(NR,N,G,A,UDIAG,P,SX,RNWTLN,DLT,AMU,   &
           DLTP,PHI,PHIP0,FSTIME,SC,NWTAKE,WRK0,EPSM,IPR)
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
! PURPOSE
! -------
! FIND NEW STEP BY MORE-HEBDON ALGORITHM
!
! PARAMETERS
! ----------
! NR           --> ROW DIMENSION OF MATRIX
! N            --> DIMENSION OF PROBLEM
! G(N)         --> GRADIENT AT CURRENT ITERATE, G(X)
! A(N,N)       --> CHOLESKY DECOMPOSITION OF HESSIAN IN
!                  LOWER TRIANGULAR PART AND DIAGONAL.
!                  HESSIAN OR APPROX IN UPPER TRIANGULAR PART
! UDIAG(N)     --> DIAGONAL OF HESSIAN IN A(.,.)
! P(N)         --> NEWTON STEP
! SX(N)        --> DIAGONAL SCALING MATRIX FOR N
! RNWTLN       --> NEWTON STEP LENGTH
! DLT         <--> TRUST REGION RADIUS
! AMU         <--> [RETAIN VALUE BETWEEN SUCCESSIVE CALLS]
! DLTP         --> TRUST REGION RADIUS AT LAST EXIT FROM THIS ROUTINE
! PHI         <--> [RETAIN VALUE BETWEEN SUCCESSIVE CALLS]
! PHIP0       <--> [RETAIN VALUE BETWEEN SUCCESSIVE CALLS]
! FSTIME      <--> BOOLEAN. =.TRUE. IF FIRST ENTRY TO THIS ROUTINE
!                  DURING K-TH ITERATION
! SC(N)       <--  CURRENT STEP
! NWTAKE      <--  BOOLEAN, =.TRUE. IF NEWTON STEP TAKEN
! WRK0         --> WORKSPACE
! EPSM         --> MACHINE EPSILON
! IPR          --> DEVICE TO WHICH TO SEND OUTPUT
!
      DIMENSION G(N),P(N),SX(N),SC(N),WRK0(N)
      DIMENSION A(NR,1),UDIAG(N)
      LOGICAL NWTAKE,DONE
      LOGICAL FSTIME
!
      PHIP=0.0
!
! HI AND ALO ARE CONSTANTS USED IN THIS ROUTINE.
! CHANGE HERE IF OTHER VALUES ARE TO BE SUBSTITUTED.
      IPR=IPR
      HI=1.5
      ALO=.75
! -----
      IF(RNWTLN.GT.HI*DLT) GO TO 15
!     IF(RNWTLN.LE.HI*DLT)
!     THEN
!
!       TAKE NEWTON STEP
!
        NWTAKE=.TRUE.
        DO 10 I=1,N
          SC(I)=P(I)
   10   CONTINUE
        DLT=MIN(DLT,RNWTLN)
        AMU=0.
!$      WRITE(IPR,951)
        RETURN
!     ELSE
!
!       NEWTON STEP NOT TAKEN
!
   15   CONTINUE
!$      WRITE(IPR,952)
        NWTAKE=.FALSE.
        IF(AMU.LE.0.) GO TO 20
!       IF(AMU.GT.0.)
!       THEN
          AMU=AMU- (PHI+DLTP) *((DLTP-DLT)+PHI)/(DLT*PHIP)
!$        WRITE(IPR,956) AMU
!       ENDIF
   20   CONTINUE
        PHI=RNWTLN-DLT
        IF(.NOT.FSTIME) GO TO 28
!       IF(FSTIME)
!       THEN
          DO 25 I=1,N
            WRK0(I)=SX(I)*SX(I)*P(I)
   25     CONTINUE
!
!         SOLVE L*Y = (SX**2)*P
!
          CALL FORSLV(NR,N,A,WRK0,WRK0)
          PHIP0=-DNRM2(N,WRK0,1)**2/RNWTLN
          FSTIME=.FALSE.
!       ENDIF
   28   PHIP=PHIP0
        AMULO=-PHI/PHIP
        AMUUP=0.0
        DO 30 I=1,N
          AMUUP=AMUUP+(G(I)*G(I))/(SX(I)*SX(I))
   30   CONTINUE
        AMUUP=SQRT(AMUUP)/DLT
        DONE=.FALSE.
!$      WRITE(IPR,956) AMU
!$      WRITE(IPR,959) PHI
!$      WRITE(IPR,960) PHIP
!$      WRITE(IPR,957) AMULO
!$      WRITE(IPR,958) AMUUP
!
!       TEST VALUE OF AMU; GENERATE NEXT AMU IF NECESSARY
!
  100   CONTINUE
        IF(DONE) RETURN
!$      WRITE(IPR,962)
        IF(AMU.GE.AMULO .AND. AMU.LE.AMUUP) GO TO 110
!       IF(AMU.LT.AMULO .OR.  AMU.GT.AMUUP)
!       THEN
          AMU=MAX(SQRT(AMULO*AMUUP),AMUUP*1.0E-3)
!$        WRITE(IPR,956) AMU
!       ENDIF
  110   CONTINUE
!
!       COPY (H,UDIAG) TO L
!       WHERE H <-- H+AMU*(SX**2) [DO NOT ACTUALLY CHANGE (H,UDIAG)]
        DO 130 J=1,N
          A(J,J)=UDIAG(J) + AMU*SX(J)*SX(J)
          IF(J.EQ.N) GO TO 130
          JP1=J+1
          DO 120 I=JP1,N
            A(I,J)=A(J,I)
  120     CONTINUE
  130   CONTINUE
!
!       FACTOR H=L(L+)
!
        CALL CHOLDC(NR,N,A,0.0D0,SQRT(EPSM),ADDMAX)
!
!       SOLVE H*P = L(L+)*SC = -G
!
        DO 140 I=1,N
          WRK0(I)=-G(I)
  140   CONTINUE
        CALL LLTSLV(NR,N,A,SC,WRK0)
!$      WRITE(IPR,955)
!$      WRITE(IPR,963) (SC(I),I=1,N)
!
!       RESET H.  NOTE SINCE UDIAG HAS NOT BEEN DESTROYED WE NEED DO
!       NOTHING HERE.  H IS IN THE UPPER PART AND IN UDIAG, STILL INTACT
!
        STEPLN=0.
        DO 150 I=1,N
          STEPLN=STEPLN + SX(I)*SX(I)*SC(I)*SC(I)
  150   CONTINUE
        STEPLN=SQRT(STEPLN)
        PHI=STEPLN-DLT
        DO 160 I=1,N
          WRK0(I)=SX(I)*SX(I)*SC(I)
  160   CONTINUE
        CALL FORSLV(NR,N,A,WRK0,WRK0)
        PHIP=-DNRM2(N,WRK0,1)**2/STEPLN
!$      WRITE(IPR,961) DLT,STEPLN
!$      WRITE(IPR,959) PHI
!$      WRITE(IPR,960) PHIP
        IF((ALO*DLT.GT.STEPLN .OR. STEPLN.GT.HI*DLT) .AND.   &
             (AMUUP-AMULO.GT.0.)) GO TO 170
!       IF((ALO*DLT.LE.STEPLN .AND. STEPLN.LE.HI*DLT) .OR.
!            (AMUUP-AMULO.LE.0.))
!       THEN
!
!         SC IS ACCEPTABLE HOOKSTEP
!
!$        WRITE(IPR,954)
          DONE=.TRUE.
          GO TO 100
!       ELSE
!
!         SC NOT ACCEPTABLE HOOKSTEP.  SELECT NEW AMU
!
  170     CONTINUE
!$        WRITE(IPR,953)
          AMULO=MAX(AMULO,AMU-(PHI/PHIP))
          IF(PHI.LT.0.) AMUUP=MIN(AMUUP,AMU)
          AMU=AMU-(STEPLN*PHI)/(DLT*PHIP)
!$        WRITE(IPR,956) AMU
!$        WRITE(IPR,957) AMULO
!$        WRITE(IPR,958) AMUUP
          GO TO 100
!       ENDIF
!     ENDIF
!
!C951 FORMAT(27H0HOOKST    TAKE NEWTON STEP)
!C952 FORMAT(32H0HOOKST    NEWTON STEP NOT TAKEN)
!C953 FORMAT(31H HOOKST    SC IS NOT ACCEPTABLE)
!C954 FORMAT(27H HOOKST    SC IS ACCEPTABLE)
!C955 FORMAT(28H HOOKST    CURRENT STEP (SC))
!C956 FORMAT(18H HOOKST    AMU   =,E20.13)
!C957 FORMAT(18H HOOKST    AMULO =,E20.13)
!C958 FORMAT(18H HOOKST    AMUUP =,E20.13)
!C959 FORMAT(18H HOOKST    PHI   =,E20.13)
!C960 FORMAT(18H HOOKST    PHIP  =,E20.13)
!C961 FORMAT(18H HOOKST    DLT   =,E20.13/
!CCCC+       18H HOOKST    STEPLN=,E20.13)
!C962 FORMAT(23H0HOOKST    FIND NEW AMU)
!C963 FORMAT(14H HOOKST       ,5(E20.13,3X))
      END SUBROUTINE HOOKST
      SUBROUTINE HORIND(X,XMIN,XMAX,I1,I2,I,IBUGU2,ISUBRO,IERROR)
!
!     PURPOSE--TRANSLATE A FLOATING POINT NUMBER
!              BETWEEN XMIN AND XMAX
!              INTO AN INTEGER INDEX BETWEEN I1 AND I2.
!              THIS IS USED IN REFERENCING ELEMENTS
!              IN HTE HORIZON TABLES USED IN
!              3-D HIDDEN LINE REMOVAL.
!
!---------------------------------------------------------------------
!
      CHARACTER*4 IBUGU2
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!               **************************************************
!               **  STEP 11--                                   **
!               **  COMPUTE THE INTEGER INDEX.                  **
!               **************************************************
!
      IERROR='NO'
!
      P=(X-XMIN)/(XMAX-XMIN)
      AI1=I1
      AI2=I2
      AI=AI1+P*(AI2-AI1)
      I=INT(AI+0.5)
!
!               **************************************************
!               **  STEP 90--                                   **
!               **  EXIT.                                       **
!               **************************************************
!
      IF(IBUGU2.EQ.'ON' .OR. ISUBRO.EQ.'NDEX')THEN
        WRITE(ICOUT,9014)X,XMIN,XMAX,I1,I2,I
 9014   FORMAT('FROM HORIND--X,XMIN,XMAX,I1,I2,I = ',3E15.7,3I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE HORIND
      SUBROUTINE HORW(XBAR,N,AHORW,RHORW)
!
!     DESCRIPTION--GIVEN A MEAN VALUE AND AN N (HERE, THE MEAN IS
!                  TYPICALLY THE MEAN OF N LABS), RETURN THE HORWITZ
!                  AND THE RETUNED HORWITZ ESTIMATES OF UNCERTAINTY.
!
!                  THE HORWITZ UNCERTAINTY IS
!
!                      UH(XBAR,N) = 2*(XBAR/SQRT(N))*(XBAR/100)**-0.15/100
!
!                  AND THE RETUNED HORWITZ UNCERTAINTY IS
!
!                      URH(XBAR,N) = 10**{-1.66989 + 0.47813*LOG10(XBAR) -
!                                          0.28125*LOG10(N)}
!     REFERENCE--SIEBER, EPSTEIN AND POSSOLO (2019), "NIST SP 260-198: A
!                RETUNED HORWITZ PROCEDURE FOR UPGRADING CERTIFICATES OF
!                OLDER STANDARD REFERENCE MATERIALS," NIST, DEPARTMENT OF
!                COMMERCE.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGYS
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGYS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2025/04
!     ORIGINAL VERSION--APRIL     2025.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!
      INCLUDE 'DPCOP2.INC'
!
      DATA PI/3.1415926535898E0/
!
!-----START POINT-----------------------------------------------------
!
      AHORW=CPUMIN
      RHORW=CPUMIN
      IF(XBAR.LE.0.0)THEN
        WRITE(ICOUT,301)
  301   FORMAT('***** ERROR--HORWITZ (OR RETUNED HORWITZ) FUNCTION')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,303)
  303   FORMAT('      THE MEAN IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,305)XBAR
  305   FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ELSEIF(N.LT.2)THEN
        WRITE(ICOUT,301)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,308)
  308   FORMAT('      THE NUMBER OF LABS IS LESS THAN 2.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,309)N
  309   FORMAT('      THE VALUE OF THE ARGUMENT IS ',I6)
        CALL DPWRST('XXX','BUG ')
      ELSE
        AN=REAL(N)
        AHORW=2.0*(XBAR/SQRT(AN))*(XBAR/100.)**(-0.15)/100.0
        RHORW=10.**(-1.66989 + 0.47813*LOG10(XBAR) - 0.28125*LOG10(AN))
      ENDIF
!
      RETURN
      END SUBROUTINE HORW
      SUBROUTINE HPSORT (HX, N, STRBEG, STREND, IPERM, KFLAG, WORK, IER)
!***BEGIN PROLOGUE  HPSORT
!***PURPOSE  Return the permutation vector generated by sorting a
!            substring within a character array and, optionally,
!            rearrange the elements of the array.  The array may be
!            sorted in forward or reverse lexicographical order.  A
!            slightly modified quicksort algorithm is used.
!***LIBRARY   SLATEC
!***CATEGORY  N6A1C, N6A2C
!***TYPE      CHARACTER (SPSORT-S, DPSORT-D, IPSORT-I, HPSORT-H)
!***KEYWORDS  PASSIVE SORTING, SINGLETON QUICKSORT, SORT, STRING SORTING
!***AUTHOR  Jones, R. E., (SNLA)
!           Rhoads, G. S., (NBS)
!           Sullivan, F. E., (NBS)
!           Wisniewski, J. A., (SNLA)
!***DESCRIPTION
!
!   HPSORT returns the permutation vector IPERM generated by sorting
!   the substrings beginning with the character STRBEG and ending with
!   the character STREND within the strings in array HX and, optionally,
!   rearranges the strings in HX.   HX may be sorted in increasing or
!   decreasing lexicographical order.  A slightly modified quicksort
!   algorithm is used.
!
!   IPERM is such that HX(IPERM(I)) is the Ith value in the
!   rearrangement of HX.  IPERM may be applied to another array by
!   calling IPPERM, SPPERM, DPPERM or HPPERM.
!
!   An active sort of numerical data is expected to execute somewhat
!   more quickly than a passive sort because there is no need to use
!   indirect references. But for the character data in HPSORT, integers
!   in the IPERM vector are manipulated rather than the strings in HX.
!   Moving integers may be enough faster than moving character strings
!   to more than offset the penalty of indirect referencing.
!
!   Description of Parameters
!      HX - input/output -- array of type character to be sorted.
!           For example, to sort a 80 element array of names,
!           each of length 6, declare HX as character HX(100)*6.
!           If ABS(KFLAG) = 2, then the values in HX will be
!           rearranged on output; otherwise, they are unchanged.
!      N  - input -- number of values in array HX to be sorted.
!      STRBEG - input -- the index of the initial character in
!               the string HX that is to be sorted.
!      STREND - input -- the index of the final character in
!               the string HX that is to be sorted.
!      IPERM - output -- permutation array such that IPERM(I) is the
!              index of the string in the original order of the
!              HX array that is in the Ith location in the sorted
!              order.
!      KFLAG - input -- control parameter:
!            =  2  means return the permutation vector resulting from
!                  sorting HX in lexicographical order and sort HX also.
!            =  1  means return the permutation vector resulting from
!                  sorting HX in lexicographical order and do not sort
!                  HX.
!            = -1  means return the permutation vector resulting from
!                  sorting HX in reverse lexicographical order and do
!                  not sort HX.
!            = -2  means return the permutation vector resulting from
!                  sorting HX in reverse lexicographical order and sort
!                  HX also.
!      WORK - character variable which must have a length specification
!             at least as great as that of HX.
!      IER - output -- error indicator:
!          =  0  if no error,
!          =  1  if N is zero or negative,
!          =  2  if KFLAG is not 2, 1, -1, or -2,
!          =  3  if work array is not long enough,
!          =  4  if string beginning is beyond its end,
!          =  5  if string beginning is out-of-range,
!          =  6  if string end is out-of-range.
!
!     E X A M P L E  O F  U S E
!
!      CHARACTER*2 HX, W
!      INTEGER STRBEG, STREND
!      DIMENSION HX(10), IPERM(10)
!      DATA (HX(I),I=1,10)/ '05','I ',' I','  ','Rs','9R','R9','89',
!     1     ',*','N"'/
!      DATA STRBEG, STREND / 1, 2 /
!      CALL HPSORT (HX,10,STRBEG,STREND,IPERM,1,W)
!      PRINT 100, (HX(IPERM(I)),I=1,10)
! 100 FORMAT (2X, A2)
!      STOP
!      END
!
!***REFERENCES  R. C. Singleton, Algorithm 347, An efficient algorithm
!                 for sorting with minimal storage, Communications of
!                 the ACM, 12, 3 (1969), pp. 185-187.
!***ROUTINES CALLED  XERMSG
!***REVISION HISTORY  (YYMMDD)
!   761101  DATE WRITTEN
!   761118  Modified by John A. Wisniewski to use the Singleton
!           quicksort algorithm.
!   811001  Modified by Francis Sullivan for string data.
!   850326  Documentation slightly modified by D. Kahaner.
!   870423  Modified by Gregory S. Rhoads for passive sorting with the
!           option for the rearrangement of the original data.
!   890620  Algorithm for rearranging the data vector corrected by R.
!           Boisvert.
!   890622  Prologue upgraded to Version 4.0 style by D. Lozier.
!   920507  Modified by M. McClain to revise prologue text.
!   920818  Declarations section rebuilt and code restructured to use
!           IF-THEN-ELSE-ENDIF.  (SMR, WRB)
!***END PROLOGUE  HPSORT
!     .. Scalar Arguments ..
      INTEGER IER, KFLAG, N, STRBEG, STREND
      CHARACTER * (*) WORK
!     .. Array Arguments ..
      INTEGER IPERM(*)
      CHARACTER * (*) HX(*)
!     .. Local Scalars ..
      REAL R
      INTEGER I, IJ, INDX, INDX0, IR, ISTRT, J, K, KK, L, LM, LMT, M,   &
              NN, NN2
!     .. Local Arrays ..
      INTEGER IL(21), IU(21)
!     .. External Subroutines ..
!CCCC EXTERNAL XERMSG
!     .. Intrinsic Functions ..
      INTRINSIC ABS, INT, LEN
!
      INCLUDE 'DPCOP2.INC'
!
!***FIRST EXECUTABLE STATEMENT  HPSORT
      IER = 0
      NN = N
      IF (NN .LT. 1) THEN
         IER = 1
         WRITE(ICOUT,999)
  999    FORMAT(1X)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,901)
  901    FORMAT('***** ERROR IN HPSORT (SORTING CHARACTER DATA--')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,903)
  903    FORMAT('      THE NUMBER OF VALUES TO BE SORTED IS ',   &
                'NON-POSITIVE')
         CALL DPWRST('XXX','BUG ')
         GO TO 9999
      ENDIF
      KK = ABS(KFLAG)
      IF (KK.NE.1 .AND. KK.NE.2) THEN
         IER = 2
         WRITE(ICOUT,999)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,901)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,921)
  921    FORMAT('      THE SORT CONTROL PARAMETER HAS AN INVALID ',   &
                'VALUE.')
         CALL DPWRST('XXX','BUG ')
         GO TO 9999
      ENDIF
!
      IF(LEN(WORK) .LT. LEN(HX(1))) THEN
         IER = 3
         WRITE(ICOUT,999)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,901)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,931)
  931    FORMAT('      THE LENGTH OF THE WORK VARIABLE IS TOO SHORT.')
         CALL DPWRST('XXX','BUG ')
         GO TO 9999
      ENDIF
      IF (STRBEG .GT. STREND) THEN
         IER = 4
         WRITE(ICOUT,999)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,901)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,941)STRBEG,STREND
  941    FORMAT('      THE STRING BEGINNING, ',I8,' IS BEYOND ITS ',   &
                'END, ',I8,' .')
         CALL DPWRST('XXX','BUG ')
         GO TO 9999
      ENDIF
      IF (STRBEG .LT. 1 .OR. STRBEG .GT. LEN(HX(1))) THEN
         IER = 5
         WRITE(ICOUT,999)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,901)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,951)STRBEG
  951    FORMAT('      THE STRING BEGINNING, ',I8,' IS OUT-OF-RANGE.')
         CALL DPWRST('XXX','BUG ')
         GO TO 9999
      ENDIF
      IF (STREND .LT. 1 .OR. STREND .GT. LEN(HX(1))) THEN
         IER = 6
         WRITE(ICOUT,999)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,901)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,961)STREND
  961    FORMAT('      THE STRING END, ',I8,' IS OUT-OF-RANGE.')
         CALL DPWRST('XXX','BUG ')
         GO TO 9999
      ENDIF
!
!     Initialize permutation vector
!
      DO 10 I=1,NN
         IPERM(I) = I
   10 CONTINUE
!
!     Return if only one value is to be sorted
!
      IF (NN .EQ. 1) RETURN
!
!     Sort HX only
!
      M = 1
      I = 1
      J = NN
      R = .375E0
!
   20 IF (I .EQ. J) GO TO 70
      IF (R .LE. 0.5898437E0) THEN
         R = R+3.90625E-2
      ELSE
         R = R-0.21875E0
      ENDIF
!
   30 K = I
!
!     Select a central element of the array and save it in location L
!
      IJ = I + INT((J-I)*R)
      LM = IPERM(IJ)
!
!     If first element of array is greater than LM, interchange with LM
!
      IF (HX(IPERM(I))(STRBEG:STREND) .GT. HX(LM)(STRBEG:STREND)) THEN
         IPERM(IJ) = IPERM(I)
         IPERM(I) = LM
         LM = IPERM(IJ)
      ENDIF
      L = J
!
!     If last element of array is less than LM, interchange with LM
!
      IF (HX(IPERM(J))(STRBEG:STREND) .LT. HX(LM)(STRBEG:STREND)) THEN
         IPERM(IJ) = IPERM(J)
         IPERM(J) = LM
         LM = IPERM(IJ)
!
!        If first element of array is greater than LM, interchange
!        with LM
!
         IF (HX(IPERM(I))(STRBEG:STREND) .GT. HX(LM)(STRBEG:STREND))   &
            THEN
               IPERM(IJ) = IPERM(I)
               IPERM(I) = LM
               LM = IPERM(IJ)
         ENDIF
      ENDIF
      GO TO 50
   40 LMT = IPERM(L)
      IPERM(L) = IPERM(K)
      IPERM(K) = LMT
!
!     Find an element in the second half of the array which is smaller
!     than LM
!
   50 L = L-1
      IF (HX(IPERM(L))(STRBEG:STREND) .GT. HX(LM)(STRBEG:STREND))   &
          GO TO 50
!
!     Find an element in the first half of the array which is greater
!     than LM
!
   60 K = K+1
      IF (HX(IPERM(K))(STRBEG:STREND) .LT. HX(LM)(STRBEG:STREND))   &
         GO TO 60
!
!     Interchange these elements
!
      IF (K .LE. L) GO TO 40
!
!     Save upper and lower subscripts of the array yet to be sorted
!
      IF (L-I .GT. J-K) THEN
         IL(M) = I
         IU(M) = L
         I = K
         M = M+1
      ELSE
         IL(M) = K
         IU(M) = J
         J = L
         M = M+1
      ENDIF
      GO TO 80
!
!     Begin again on another portion of the unsorted array
!
   70 M = M-1
      IF (M .EQ. 0) GO TO 110
      I = IL(M)
      J = IU(M)
!
   80 IF (J-I .GE. 1) GO TO 30
      IF (I .EQ. 1) GO TO 20
      I = I-1
!
   90 I = I+1
      IF (I .EQ. J) GO TO 70
      LM = IPERM(I+1)
      IF (HX(IPERM(I))(STRBEG:STREND) .LE. HX(LM)(STRBEG:STREND))   &
         GO TO 90
      K = I
!
  100 IPERM(K+1) = IPERM(K)
      K = K-1
!
      IF (HX(LM)(STRBEG:STREND) .LT. HX(IPERM(K))(STRBEG:STREND))   &
          GO TO 100
      IPERM(K+1) = LM
      GO TO 90
!
!     Clean up
!
  110 IF (KFLAG .LE. -1) THEN
!
!        Alter array to get reverse order, if necessary
!
         NN2 = NN/2
         DO 120 I=1,NN2
           IR = NN-I+1
           LM = IPERM(I)
           IPERM(I) = IPERM(IR)
           IPERM(IR) = LM
  120    CONTINUE
      ENDIF
!
!     Rearrange the values of HX if desired
!
      IF (KK .EQ. 2) THEN
!
!        Use the IPERM vector as a flag.
!        If IPERM(I) < 0, then the I-th value is in correct location
!
         DO 140 ISTRT=1,NN
            IF (IPERM(ISTRT) .GE. 0) THEN
               INDX = ISTRT
               INDX0 = INDX
               WORK = HX(ISTRT)
  130          IF (IPERM(INDX) .GT. 0) THEN
                  HX(INDX) = HX(IPERM(INDX))
                  INDX0 = INDX
                  IPERM(INDX) = -IPERM(INDX)
                  INDX = ABS(IPERM(INDX))
                  GO TO 130
               ENDIF
               HX(INDX0) = WORK
            ENDIF
  140    CONTINUE
!
!        Revert the signs of the IPERM values
!
         DO 150 I=1,NN
            IPERM(I) = -IPERM(I)
  150    CONTINUE
!
      ENDIF
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE HPSORT 
      SUBROUTINE HPTRPT(IXC,IYC,ICSTR,NCSTR,ISUBN0)
!
!     PURPOSE--TRANSLATE AN INTEGER PAIR OF COORDINATES
!              (HP MBP = MULTIPLE BYTE PAIR OF NUMBERS)
!              INTO A 5-BYTE PACKED CHARACTER REPRESENTATION
!              THAT WILL BE UNDERSTOOD BY A HEWLETT-PACKARD
!              GRAPHICS DEVICE.
!     NOTE--THE RESULTING PACKED WORDS
!           WILL BE PLACED IN SPECIFIC ELEMENTS
!           OF THE CHARACTER*130 VARIABLE ICSTR(.:.).
!           THE VALUE OF THE VARIABLE    NCSTR
!           REPRESENTS THE NUMBER OF ELEMENTS IN ICSTR(.:.)
!           THAT HAVE ALREADY BEEN FILLED.
!           THE RESULTING PACKED WORDS WILL GO INTO
!           THE NEXT AVAILABLE ELEMENTS OF ICSTR(.:.)
!           AND THE VALUE OF    NCSTR    WILL BE
!           UPDATED ACCORDINGLY.
!     NOTE--MORE COMPACT (1 TO 4-BYTE REPRESENTATIONS)
!           ARE POSSIBLE FOR HP DEVICES FOR SMALLER
!           RANGES (0 TO 3, 0 TO 31, 0 TO 255, AND
!           0 TO 2047, RESPECTIVELY) OF THE INPUT X AND Y
!           COORDINATES.
!           THIS SUBROUTINE IS GENERAL AND TREATS ALL
!           X AND Y VALUES FROM 0 TO 2**14-1 (= 16383).
!           THE OUTPUT WILL THUS ALWAYS BE A 5-BYTE
!           REPRESENTATION.
!     DANGER--NCSTR IS BOTH AN INPUT ARGUMENT
!             AND AN OUTPUT ARGUMENT OF THIS SUBROUTINE.
!     NOTE--ISUBN0 = NAME OF SUBROUTINE WHICH CALLED HPTRPT
!                    (AND THEREBY HAVE WALKBACK INFORMATION).
!     REFERENCE--HP 7221 C AND HP 7221T GRAPHICS PLOTTER
!                OPERATING AND PROGRAMMING MANUAL,
!                PAGES 71-72 AND 319.
!
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--83.6
!     ORIGINAL VERSION (AS A SEPARATE SUBROUTINE)--MARCH     1984.
!
!-----NON-COMMON VARIABLES (GRAPHICS)-------------------------------------------
!
      CHARACTER*4 ISUBN0
!
      CHARACTER*130 ICSTR
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOGR.INC'
      INCLUDE 'DPCOBE.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-----------------------------------------------
!
      DATA K2/4/
      DATA K4/16/
      DATA K6/64/
      DATA K10/1024/
      DATA K12/4096/
!
!-----START POINT-----------------------------------------------------
!
      IERRG4='NO'
!
      IF(IBUGG4.EQ.'OFF'.AND.ISUBG4.NE.'TRPT')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF HPTRPT--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)ISUBN0
   52 FORMAT('ISUBN0 (NAME OF THE CALLING SUBROUTINE) = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)IXC,IYC
   53 FORMAT('IXC,IYC = ',2I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,55)K2,K4,K6,K10,K12
   55 FORMAT('K2,K4,K6,K10,K12 = ',5I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,56)IGUNIT
   56 FORMAT('IGUNIT = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,63)NCSTR
   63 FORMAT('NCSTR = ',I8)
      CALL DPWRST('XXX','BUG ')
      IF(NCSTR.LE.0)GO TO 67
      DO 65 I=1,NCSTR
!CCCC IASCNE=ICHAR(ICSTR(I:I))
      CALL DPCOAN(ICSTR(I:I),IASCNE)
      WRITE(ICOUT,66)I,ICSTR(I:I),IASCNE
   66 FORMAT('I,ICSTR(I:I),IASCNE = ',I8,2X,A1,I8)
      CALL DPWRST('XXX','BUG ')
   65 CONTINUE
   67 CONTINUE
      WRITE(ICOUT,69)IBUGG4,ISUBG4,IERRG4
   69 FORMAT('IBUGG4,ISUBG4,IERRG4 = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
   90 CONTINUE
!
      IVX=IXC
      IVY=IYC
      IF(IVX.LT.0)IVX=0
      IF(IVY.LT.0)IVY=0
!
!               ******************************************************
!               **  STEP 1--                                        **
!               **  FORM THE HIGH-X 7-BIT BYTE--                    **
!               **  THE LEFT 3 BITS ARE 1 1 0;                      **
!               **  THE RIGHT 4 BITS = BITS 13 TO 10 OF X.          **
!               **  SHIFT THE X VALUE TO THE RIGHT 10 PLACES;       **
!               **  THEN KEEP ONLY THE RIGHT 4 PLACES;              **
!               **  THEN PLACE A 1 1 0 IN BITS 6, 5, AND 4          **
!               **  (WHERE BIT 6 = LEFT-MOST BIT IN A 7-BIT BYTE).  **
!               ******************************************************
!
      NCSTR=NCSTR+1
      IBYTE1=MOD(IVX/K10,K4)+96
!CCCC ICSTR(NCSTR:NCSTR)=CHAR(IBYTE1)
      CALL DPCONA(IBYTE1,ICSTR(NCSTR:NCSTR))
!
!               ***************************************************************
!               **  STEP 2--                                                 **
!               **  FORM THE MIDDLE-X 7-BIT BYTE--                           **
!               **  THE LEFT BIT IS THE COMPLEMENT OF THE NEXT-TO-LEFT BIT;  **
!               **  THE RIGHT 6 BITS = BITS 9 TO 4 OF X.                     **
!               **  SHIFT THE X VALUE TO THE RIGHT 4 PLACES;                 **
!               **  THEN KEEP ONLY THE RIGHT 6 PLACES;                       **
!               **  THEN IF NEW BIT 5 = 0, PLACE A 1 IN NEW BIT 6,           **
!               **  OR   IF NEW BIT 5 = 1, PLACE A 0 IN NEW BIT 6.           **
!               ***************************************************************
!
      NCSTR=NCSTR+1
      IBYTE2=MOD(IVX/K4,K6)
      IF(IBYTE2.LE.31)IBYTE2=IBYTE2+64
!CCCC ICSTR(NCSTR:NCSTR)=CHAR(IBYTE2)
      CALL DPCONA(IBYTE2,ICSTR(NCSTR:NCSTR))
!
!               ***************************************************************
!               **  STEP 3--                                                 **
!               **  FORM THE SHARED (LOW-X, HIGH Y) 7-BIT BYTE--             **
!               **  THE LEFT BIT IS THE COMPLEMENT OF THE NEXT-TO-LEFT BIT;  **
!               **  THE NEXT 4 BITS = BITS 3 TO 0 OF X;                      **
!               **  THE RIGHT 2 BITS = BITS 13 AND 12 OF Y.                  **
!               **  KEEP ONLY THE RIGHT 4 BITS OF X;                         **
!               **  SHIFT THESE 4 BITS TO THE LEFT 2 PLACES;                 **
!               **  SHIFT THE Y VALUE TO THE RIGHT 12 PLACES;                **
!               **  THEN KEEP ONLY THE RIGHT 2 BITS;                         **
!               **  THEN MERGE THE 4 X BITS AND THE 2 Y BITS;                **
!               **  FINALLY, IF NEW BIT 5 = 0, PLACE A 1 IN NEW BIT 6,       **
!               **  OR       IF NEW BIT 5 = 1, PLACE A 0 IN NEW BIT 6.       **
!               ***************************************************************
!
      NCSTR=NCSTR+1
      IBYTE3=MOD(IVX,K4)*K2+MOD(IVY/K12,K2)
      IF(IBYTE3.LE.31)IBYTE3=IBYTE3+64
!CCCC ICSTR(NCSTR:NCSTR)=CHAR(IBYTE3)
      CALL DPCONA(IBYTE3,ICSTR(NCSTR:NCSTR))
!
!               ***************************************************************
!               **  STEP 4--                                                 **
!               **  FORM THE MIDDLE-Y 7-BIT BYTE--                           **
!               **  THE LEFT BIT IS THE COMPLEMENT OF THE NEXT-TO-LEFT BIT;  **
!               **  THE RIGHT 6 BITS = BITS 11 TO 6 OF Y.                    **
!               **  SHIFT THE Y VALUE 6 PLACES TO THE RIGHT;                 **
!               **  THEN KEEP ONLY THE RIGHT 6 PLACES;                       **
!               **  THEN IF NEW BIT 5 = 0, PLACE A 1 IN NEW BIT 6,           **
!               **  OR   IF NEW BIT 5 = 1, PLACE A 0 IN NEW BIT 6.           **
!               ***************************************************************
!
      NCSTR=NCSTR+1
      IBYTE4=MOD(IVY/K6,K6)
      IF(IBYTE4.LE.31)IBYTE4=IBYTE4+64
!CCCC ICSTR(NCSTR:NCSTR)=CHAR(IBYTE4)
      CALL DPCONA(IBYTE4,ICSTR(NCSTR:NCSTR))
!
!               ***************************************************************
!               **  STEP 5--                                                 **
!               **  FORM THE LOW-Y 7-BIT BYTE--                              **
!               **  THE LEFT BIT IS THE COMPLEMENT OF THE NEXT-TO-LEFT BIT;  **
!               **  THE RIGHT 6 BITS = BITS 5 TO 0 OF Y.                     **
!               **  KEEP ONLY THE RIGHT 6 BITS OF Y;                         **
!               **  THEN IF NEW BIT 5 = 0, PLACE A 1 IN NEW BIT 6,           **
!               **  OR   IF NEW BIT 5 = 1, PLACE A 0 IN NEW BIT 6.           **
!               ***************************************************************
!
      NCSTR=NCSTR+1
      IBYTE5=MOD(IVY,K6)
      IF(IBYTE5.LE.31)IBYTE5=IBYTE5+64
!CCCC ICSTR(NCSTR:NCSTR)=CHAR(IBYTE5)
      CALL DPCONA(IBYTE5,ICSTR(NCSTR:NCSTR))
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
      IF(IBUGG4.EQ.'OFF'.AND.ISUBG4.NE.'TRPT')GO TO 9090
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF TKTRPT--')
      WRITE(ICOUT,9012)IXC,IYC
 9012 FORMAT('IXC,IYC = ',2I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)IVX,IVY
 9013 FORMAT('IVX,IVY = ',2I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9015)K2,K4,K6,K10,K12
 9015 FORMAT('K2,K4,K6,K10,K12 = ',5I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9016)IGUNIT
 9016 FORMAT('IGUNIT = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9017)IBYTE1,IBYTE2,IBYTE3,IBYTE4,IBYTE5
 9017 FORMAT('IBYTE1,IBYTE2,IBYTE3,IBYTE4,IBYTE5 = ',5I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9023)NCSTR
 9023 FORMAT('NCSTR = ',I8)
      CALL DPWRST('XXX','BUG ')
      IF(NCSTR.LE.0)GO TO 9027
      DO 9025 I=1,NCSTR
!CCCC IASCNE=ICHAR(ICSTR(I:I))
      CALL DPCOAN(ICSTR(I:I),IASCNE)
      WRITE(ICOUT,9026)I,ICSTR(I:I),IASCNE
 9026 FORMAT('I,ICSTR(I:I),IASCNE = ',I8,2X,A1,I8)
      CALL DPWRST('XXX','BUG ')
 9025 CONTINUE
 9027 CONTINUE
      WRITE(ICOUT,9029)IBUGG4,ISUBG4,IERRG4
 9029 FORMAT('IBUGG4,ISUBG4,IERRG4 = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE HPTRPT
      SUBROUTINE HQR(NM,N,LOW,IGH,H,WR,WI,IERR)
!***BEGIN PROLOGUE  HQR
!***DATE WRITTEN   760101   (YYMMDD)
!***REVISION DATE  830518   (YYMMDD)
!***CATEGORY NO.  D4C2B
!***KEYWORDS  EIGENVALUES,EIGENVECTORS,EISPACK
!***AUTHOR  SMITH, B. T., ET AL.
!***PURPOSE  Computes eigenvalues of a real upper Hessenberg matrix
!            using the QR method.
!***DESCRIPTION
!
!     This subroutine is a translation of the ALGOL procedure HQR,
!     NUM. MATH. 14, 219-231(1970) by Martin, Peters, and Wilkinson.
!     HANDBOOK FOR AUTO. COMP., VOL.II-LINEAR ALGEBRA, 359-371(1971).
!
!     This subroutine finds the eigenvalues of a REAL
!     UPPER Hessenberg matrix by the QR method.
!
!     On INPUT
!
!        NM must be set to the row dimension of two-dimensional
!          array parameters as declared in the calling program
!          dimension statement.
!
!        N is the order of the matrix.
!
!        LOW and IGH are integers determined by the balancing
!          subroutine  BALANC.  If  BALANC  has not been used,
!          set LOW=1, IGH=N.
!
!        H contains the upper Hessenberg matrix.  Information about
!          the transformations used in the reduction to Hessenberg
!          form by  ELMHES  or  ORTHES, if performed, is stored
!          in the remaining triangle under the Hessenberg matrix.
!
!     On OUTPUT
!
!        H has been destroyed.  Therefore, it must be saved
!          before calling  HQR  if subsequent calculation and
!          back transformation of eigenvectors is to be performed.
!
!        WR and WI contain the real and imaginary parts,
!          respectively, of the eigenvalues.  The eigenvalues
!          are unordered except that complex conjugate pairs
!          of values appear consecutively with the eigenvalue
!          having the positive imaginary part first.  If an
!          error exit is made, the eigenvalues should be correct
!          for indices IERR+1,...,N.
!
!        IERR is set to
!          Zero       for normal return,
!          J          if the J-th eigenvalue has not been
!                     determined after a total of 30*N iterations.
!
!     Questions and comments should be directed to B. S. Garbow,
!     APPLIED MATHEMATICS DIVISION, ARGONNE NATIONAL LABORATORY
!     ------------------------------------------------------------------
!***REFERENCES  B. T. SMITH, J. M. BOYLE, J. J. DONGARRA, B. S. GARBOW,
!                 Y. IKEBE, V. C. KLEMA, C. B. MOLER, *MATRIX EIGEN-
!                 SYSTEM ROUTINES - EISPACK GUIDE*, SPRINGER-VERLAG,
!                 1976.
!***ROUTINES CALLED  (NONE)
!***END PROLOGUE  HQR
!
      INTEGER I,J,K,L,M,N,EN,LL,MM,NA,NM,IGH,ITN,ITS,LOW,MP2,ENM2,IERR
      REAL H(NM,N),WR(N),WI(N)
      REAL P,Q,R,S,T,W,X,Y,ZZ,NORM,S1,S2
      LOGICAL NOTLAS
!
      R=0.0
      Q=0.0
      P=0.0
      M=0
      L=0
!
!***FIRST EXECUTABLE STATEMENT  HQR
      IERR = 0
      NORM = 0.0E0
      K = 1
!     .......... STORE ROOTS ISOLATED BY BALANC
!                AND COMPUTE MATRIX NORM ..........
      DO 50 I = 1, N
!
         DO 40 J = K, N
            NORM = NORM + ABS(H(I,J))
   40    CONTINUE
!
         K = I
         IF (I .GE. LOW .AND. I .LE. IGH) GO TO 50
         WR(I) = H(I,I)
         WI(I) = 0.0E0
   50 CONTINUE
!
      EN = IGH
      T = 0.0E0
      ITN = 30*N
!     .......... SEARCH FOR NEXT EIGENVALUES ..........
   60 IF (EN .LT. LOW) GO TO 1001
      ITS = 0
      NA = EN - 1
      ENM2 = NA - 1
!     .......... LOOK FOR SINGLE SMALL SUB-DIAGONAL ELEMENT
!                FOR L=EN STEP -1 UNTIL LOW DO -- ..........
   70 DO 80 LL = LOW, EN
         L = EN + LOW - LL
         IF (L .EQ. LOW) GO TO 100
         S = ABS(H(L-1,L-1)) + ABS(H(L,L))
         IF (S .EQ. 0.0E0) S = NORM
         S2 = S + ABS(H(L,L-1))
         IF (S2 .EQ. S) GO TO 100
   80 CONTINUE
!     .......... FORM SHIFT ..........
  100 X = H(EN,EN)
      IF (L .EQ. EN) GO TO 270
      Y = H(NA,NA)
      W = H(EN,NA) * H(NA,EN)
      IF (L .EQ. NA) GO TO 280
      IF (ITN .EQ. 0) GO TO 1000
      IF (ITS .NE. 10 .AND. ITS .NE. 20) GO TO 130
!     .......... FORM EXCEPTIONAL SHIFT ..........
      T = T + X
!
      DO 120 I = LOW, EN
         H(I,I) = H(I,I) - X
  120 CONTINUE
!
      S = ABS(H(EN,NA)) + ABS(H(NA,ENM2))
      X = 0.75E0 * S
      Y = X
      W = -0.4375E0 * S * S
  130 ITS = ITS + 1
      ITN = ITN - 1
!     .......... LOOK FOR TWO CONSECUTIVE SMALL
!                SUB-DIAGONAL ELEMENTS.
!                FOR M=EN-2 STEP -1 UNTIL L DO -- ..........
      DO 140 MM = L, ENM2
         M = ENM2 + L - MM
         ZZ = H(M,M)
         R = X - ZZ
         S = Y - ZZ
         P = (R * S - W) / H(M+1,M) + H(M,M+1)
         Q = H(M+1,M+1) - ZZ - R - S
         R = H(M+2,M+1)
         S = ABS(P) + ABS(Q) + ABS(R)
         P = P / S
         Q = Q / S
         R = R / S
         IF (M .EQ. L) GO TO 150
         S1 = ABS(P) * (ABS(H(M-1,M-1)) + ABS(ZZ) + ABS(H(M+1,M+1)))
         S2 = S1 + ABS(H(M,M-1)) * (ABS(Q) + ABS(R))
         IF (S2 .EQ. S1) GO TO 150
  140 CONTINUE
!
  150 MP2 = M + 2
!
      DO 160 I = MP2, EN
         H(I,I-2) = 0.0E0
         IF (I .EQ. MP2) GO TO 160
         H(I,I-3) = 0.0E0
  160 CONTINUE
!     .......... DOUBLE QR STEP INVOLVING ROWS L TO EN AND
!                COLUMNS M TO EN ..........
      DO 260 K = M, NA
         NOTLAS = K .NE. NA
         IF (K .EQ. M) GO TO 170
         P = H(K,K-1)
         Q = H(K+1,K-1)
         R = 0.0E0
         IF (NOTLAS) R = H(K+2,K-1)
         X = ABS(P) + ABS(Q) + ABS(R)
         IF (X .EQ. 0.0E0) GO TO 260
         P = P / X
         Q = Q / X
         R = R / X
  170    S = SIGN(SQRT(P*P+Q*Q+R*R),P)
         IF (K .EQ. M) GO TO 180
         H(K,K-1) = -S * X
         GO TO 190
  180    IF (L .NE. M) H(K,K-1) = -H(K,K-1)
  190    P = P + S
         X = P / S
         Y = Q / S
         ZZ = R / S
         Q = Q / P
         R = R / P
!     .......... ROW MODIFICATION ..........
         DO 210 J = K, EN
            P = H(K,J) + Q * H(K+1,J)
            IF (.NOT. NOTLAS) GO TO 200
            P = P + R * H(K+2,J)
            H(K+2,J) = H(K+2,J) - P * ZZ
  200       H(K+1,J) = H(K+1,J) - P * Y
            H(K,J) = H(K,J) - P * X
  210    CONTINUE
!
         J = MIN0(EN,K+3)
!     .......... COLUMN MODIFICATION ..........
         DO 230 I = L, J
            P = X * H(I,K) + Y * H(I,K+1)
            IF (.NOT. NOTLAS) GO TO 220
            P = P + ZZ * H(I,K+2)
            H(I,K+2) = H(I,K+2) - P * R
  220       H(I,K+1) = H(I,K+1) - P * Q
            H(I,K) = H(I,K) - P
  230    CONTINUE
!
  260 CONTINUE
!
      GO TO 70
!     .......... ONE ROOT FOUND ..........
  270 WR(EN) = X + T
      WI(EN) = 0.0E0
      EN = NA
      GO TO 60
!     .......... TWO ROOTS FOUND ..........
  280 P = (Y - X) / 2.0E0
      Q = P * P + W
      ZZ = SQRT(ABS(Q))
      X = X + T
      IF (Q .LT. 0.0E0) GO TO 320
!     .......... REAL PAIR ..........
      ZZ = P + SIGN(ZZ,P)
      WR(NA) = X + ZZ
      WR(EN) = WR(NA)
      IF (ZZ .NE. 0.0E0) WR(EN) = X - W / ZZ
      WI(NA) = 0.0E0
      WI(EN) = 0.0E0
      GO TO 330
!     .......... COMPLEX PAIR ..........
  320 WR(NA) = X + P
      WR(EN) = X + P
      WI(NA) = ZZ
      WI(EN) = -ZZ
  330 EN = ENM2
      GO TO 60
!     .......... SET ERROR -- NO CONVERGENCE TO AN
!                EIGENVALUE AFTER 30*N ITERATIONS ..........
 1000 IERR = EN
 1001 RETURN
      END SUBROUTINE HQR
      SUBROUTINE HQR2(NM,N,LOW,IGH,H,WR,WI,Z,IERR)
!***BEGIN PROLOGUE  HQR2
!***DATE WRITTEN   760101   (YYMMDD)
!***REVISION DATE  830518   (YYMMDD)
!***CATEGORY NO.  D4C2B
!***KEYWORDS  EIGENVALUES,EIGENVECTORS,EISPACK
!***AUTHOR  SMITH, B. T., ET AL.
!***PURPOSE  Computes eigenvalues and eigenvectors of real upper
!            Hessenberg matrix using QR method.
!***DESCRIPTION
!
!     This subroutine is a translation of the ALGOL procedure HQR2,
!     NUM. MATH. 16, 181-204(1970) by Peters and Wilkinson.
!     HANDBOOK FOR AUTO. COMP., VOL.II-LINEAR ALGEBRA, 372-395(1971).
!
!     This subroutine finds the eigenvalues and eigenvectors
!     of a REAL UPPER Hessenberg matrix by the QR method.  The
!     eigenvectors of a REAL GENERAL matrix can also be found
!     if  ELMHES  and  ELTRAN  or  ORTHES  and  ORTRAN  have
!     been used to reduce this general matrix to Hessenberg form
!     and to accumulate the similarity transformations.
!
!     On INPUT
!
!        NM must be set to the row dimension of two-dimensional
!          array parameters as declared in the calling program
!          dimension statement.
!
!        N is the order of the matrix.
!
!        LOW and IGH are integers determined by the balancing
!          subroutine  BALANC.  If  BALANC  has not been used,
!          set LOW=1, IGH=N.
!
!        H contains the upper Hessenberg matrix.
!
!        Z contains the transformation matrix produced by  ELTRAN
!          after the reduction by  ELMHES, or by  ORTRAN  after the
!          reduction by  ORTHES, if performed.  If the eigenvectors
!          of the Hessenberg matrix are desired, Z must contain the
!          identity matrix.
!
!     On OUTPUT
!
!        H has been destroyed.
!
!        WR and WI contain the real and imaginary parts,
!          respectively, of the eigenvalues.  The eigenvalues
!          are unordered except that complex conjugate pairs
!          of values appear consecutively with the eigenvalue
!          having the positive imaginary part first.  If an
!          error exit is made, the eigenvalues should be correct
!          for indices IERR+1,...,N.
!
!        Z contains the real and imaginary parts of the eigenvectors.
!          If the I-th eigenvalue is real, the I-th column of Z
!          contains its eigenvector.  If the I-th eigenvalue is complex
!          with positive imaginary part, the I-th and (I+1)-th
!          columns of Z contain the real and imaginary parts of its
!          eigenvector.  The eigenvectors are unnormalized.  If an
!          error exit is made, none of the eigenvectors has been found.
!
!        IERR is set to
!          Zero       for normal return,
!          J          if the J-th eigenvalue has not been
!                     determined after a total of 30*N iterations.
!
!     Calls CDIV for complex division.
!
!     Questions and comments should be directed to B. S. Garbow,
!     APPLIED MATHEMATICS DIVISION, ARGONNE NATIONAL LABORATORY
!     ------------------------------------------------------------------
!***REFERENCES  B. T. SMITH, J. M. BOYLE, J. J. DONGARRA, B. S. GARBOW,
!                 Y. IKEBE, V. C. KLEMA, C. B. MOLER, *MATRIX EIGEN-
!                 SYSTEM ROUTINES - EISPACK GUIDE*, SPRINGER-VERLAG,
!                 1976.
!***ROUTINES CALLED  CDIV
!***END PROLOGUE  HQR2
!
      INTEGER I,J,K,L,M,N,EN,II,JJ,LL,MM,NA,NM,NN
      INTEGER IGH,ITN,ITS,LOW,MP2,ENM2,IERR
      REAL H(NM,N),WR(N),WI(N),Z(NM,N)
      REAL P,Q,R,S,T,W,X,Y,RA,SA,VI,VR,ZZ,NORM,S1
      LOGICAL NOTLAS
!
      S=0.0
      R=0.0
      P=0.0
      M=0
      L=0
!
!***FIRST EXECUTABLE STATEMENT  HQR2
      IERR = 0
      NORM = 0.0E0
      K = 1
!     .......... STORE ROOTS ISOLATED BY BALANC
!                AND COMPUTE MATRIX NORM ..........
      DO 50 I = 1, N
!
         DO 40 J = K, N
            NORM = NORM + ABS(H(I,J))
   40    CONTINUE
!
         K = I
         IF (I .GE. LOW .AND. I .LE. IGH) GO TO 50
         WR(I) = H(I,I)
         WI(I) = 0.0E0
   50 CONTINUE
!
      EN = IGH
      T = 0.0E0
      ITN = 30*N
!     .......... SEARCH FOR NEXT EIGENVALUES ..........
   60 IF (EN .LT. LOW) GO TO 340
      ITS = 0
      NA = EN - 1
      ENM2 = NA - 1
!     .......... LOOK FOR SINGLE SMALL SUB-DIAGONAL ELEMENT
!                FOR L=EN STEP -1 UNTIL LOW DO -- ..........
   70 DO 80 LL = LOW, EN
         L = EN + LOW - LL
         IF (L .EQ. LOW) GO TO 100
         S = ABS(H(L-1,L-1)) + ABS(H(L,L))
         IF (S .EQ. 0.0E0) S = NORM
         S2 = S + ABS(H(L,L-1))
         IF (S2 .EQ. S) GO TO 100
   80 CONTINUE
!     .......... FORM SHIFT ..........
  100 X = H(EN,EN)
      IF (L .EQ. EN) GO TO 270
      Y = H(NA,NA)
      W = H(EN,NA) * H(NA,EN)
      IF (L .EQ. NA) GO TO 280
      IF (ITN .EQ. 0) GO TO 1000
      IF (ITS .NE. 10 .AND. ITS .NE. 20) GO TO 130
!     .......... FORM EXCEPTIONAL SHIFT ..........
      T = T + X
!
      DO 120 I = LOW, EN
         H(I,I) = H(I,I) - X
  120 CONTINUE
!
      S = ABS(H(EN,NA)) + ABS(H(NA,ENM2))
      X = 0.75E0 * S
      Y = X
      W = -0.4375E0 * S * S
  130 ITS = ITS + 1
      ITN = ITN - 1
!     .......... LOOK FOR TWO CONSECUTIVE SMALL
!                SUB-DIAGONAL ELEMENTS.
!                FOR M=EN-2 STEP -1 UNTIL L DO -- ..........
      DO 140 MM = L, ENM2
         M = ENM2 + L - MM
         ZZ = H(M,M)
         R = X - ZZ
         S = Y - ZZ
         P = (R * S - W) / H(M+1,M) + H(M,M+1)
         Q = H(M+1,M+1) - ZZ - R - S
         R = H(M+2,M+1)
         S = ABS(P) + ABS(Q) + ABS(R)
         P = P / S
         Q = Q / S
         R = R / S
         IF (M .EQ. L) GO TO 150
         S1 = ABS(P) * (ABS(H(M-1,M-1)) + ABS(ZZ) + ABS(H(M+1,M+1)))
         S2 = S1 + ABS(H(M,M-1)) * (ABS(Q) + ABS(R))
         IF (S2 .EQ. S1) GO TO 150
  140 CONTINUE
!
  150 MP2 = M + 2
!
      DO 160 I = MP2, EN
         H(I,I-2) = 0.0E0
         IF (I .EQ. MP2) GO TO 160
         H(I,I-3) = 0.0E0
  160 CONTINUE
!     .......... DOUBLE QR STEP INVOLVING ROWS L TO EN AND
!                COLUMNS M TO EN ..........
      DO 260 K = M, NA
         NOTLAS = K .NE. NA
         IF (K .EQ. M) GO TO 170
         P = H(K,K-1)
         Q = H(K+1,K-1)
         R = 0.0E0
         IF (NOTLAS) R = H(K+2,K-1)
         X = ABS(P) + ABS(Q) + ABS(R)
         IF (X .EQ. 0.0E0) GO TO 260
         P = P / X
         Q = Q / X
         R = R / X
  170    S = SIGN(SQRT(P*P+Q*Q+R*R),P)
         IF (K .EQ. M) GO TO 180
         H(K,K-1) = -S * X
         GO TO 190
  180    IF (L .NE. M) H(K,K-1) = -H(K,K-1)
  190    P = P + S
         X = P / S
         Y = Q / S
         ZZ = R / S
         Q = Q / P
         R = R / P
!     .......... ROW MODIFICATION ..........
         DO 210 J = K, N
            P = H(K,J) + Q * H(K+1,J)
            IF (.NOT. NOTLAS) GO TO 200
            P = P + R * H(K+2,J)
            H(K+2,J) = H(K+2,J) - P * ZZ
  200       H(K+1,J) = H(K+1,J) - P * Y
            H(K,J) = H(K,J) - P * X
  210    CONTINUE
!
         J = MIN0(EN,K+3)
!     .......... COLUMN MODIFICATION ..........
         DO 230 I = 1, J
            P = X * H(I,K) + Y * H(I,K+1)
            IF (.NOT. NOTLAS) GO TO 220
            P = P + ZZ * H(I,K+2)
            H(I,K+2) = H(I,K+2) - P * R
  220       H(I,K+1) = H(I,K+1) - P * Q
            H(I,K) = H(I,K) - P
  230    CONTINUE
!     .......... ACCUMULATE TRANSFORMATIONS ..........
         DO 250 I = LOW, IGH
            P = X * Z(I,K) + Y * Z(I,K+1)
            IF (.NOT. NOTLAS) GO TO 240
            P = P + ZZ * Z(I,K+2)
            Z(I,K+2) = Z(I,K+2) - P * R
  240       Z(I,K+1) = Z(I,K+1) - P * Q
            Z(I,K) = Z(I,K) - P
  250    CONTINUE
!
  260 CONTINUE
!
      GO TO 70
!     .......... ONE ROOT FOUND ..........
  270 H(EN,EN) = X + T
      WR(EN) = H(EN,EN)
      WI(EN) = 0.0E0
      EN = NA
      GO TO 60
!     .......... TWO ROOTS FOUND ..........
  280 P = (Y - X) / 2.0E0
      Q = P * P + W
      ZZ = SQRT(ABS(Q))
      H(EN,EN) = X + T
      X = H(EN,EN)
      H(NA,NA) = Y + T
      IF (Q .LT. 0.0E0) GO TO 320
!     .......... REAL PAIR ..........
      ZZ = P + SIGN(ZZ,P)
      WR(NA) = X + ZZ
      WR(EN) = WR(NA)
      IF (ZZ .NE. 0.0E0) WR(EN) = X - W / ZZ
      WI(NA) = 0.0E0
      WI(EN) = 0.0E0
      X = H(EN,NA)
      S = ABS(X) + ABS(ZZ)
      P = X / S
      Q = ZZ / S
      R = SQRT(P*P+Q*Q)
      P = P / R
      Q = Q / R
!     .......... ROW MODIFICATION ..........
      DO 290 J = NA, N
         ZZ = H(NA,J)
         H(NA,J) = Q * ZZ + P * H(EN,J)
         H(EN,J) = Q * H(EN,J) - P * ZZ
  290 CONTINUE
!     .......... COLUMN MODIFICATION ..........
      DO 300 I = 1, EN
         ZZ = H(I,NA)
         H(I,NA) = Q * ZZ + P * H(I,EN)
         H(I,EN) = Q * H(I,EN) - P * ZZ
  300 CONTINUE
!     .......... ACCUMULATE TRANSFORMATIONS ..........
      DO 310 I = LOW, IGH
         ZZ = Z(I,NA)
         Z(I,NA) = Q * ZZ + P * Z(I,EN)
         Z(I,EN) = Q * Z(I,EN) - P * ZZ
  310 CONTINUE
!
      GO TO 330
!     .......... COMPLEX PAIR ..........
  320 WR(NA) = X + P
      WR(EN) = X + P
      WI(NA) = ZZ
      WI(EN) = -ZZ
  330 EN = ENM2
      GO TO 60
!     .......... ALL ROOTS FOUND.  BACKSUBSTITUTE TO FIND
!                VECTORS OF UPPER TRIANGULAR FORM ..........
  340 IF (NORM .EQ. 0.0E0) GO TO 1001
!     .......... FOR EN=N STEP -1 UNTIL 1 DO -- ..........
      DO 800 NN = 1, N
         EN = N + 1 - NN
         P = WR(EN)
         Q = WI(EN)
         NA = EN - 1
!CCCC    IF (Q) 710, 600, 800
         IF (Q.LT.0.) THEN
            GO TO 710
         ELSEIF (Q.EQ.0.) THEN
            GO TO 600
         ELSE
            GO TO 800
         ENDIF
!     .......... REAL VECTOR ..........
  600    M = EN
         H(EN,EN) = 1.0E0
         IF (NA .EQ. 0) GO TO 800
!     .......... FOR I=EN-1 STEP -1 UNTIL 1 DO -- ..........
         DO 700 II = 1, NA
            I = EN - II
            W = H(I,I) - P
            R = H(I,EN)
            IF (M .GT. NA) GO TO 620
!
            DO 610 J = M, NA
               R = R + H(I,J) * H(J,EN)
  610       CONTINUE
!
  620       IF (WI(I) .GE. 0.0E0) GO TO 630
            ZZ = W
            S = R
            GO TO 700
  630       M = I
            IF (WI(I) .NE. 0.0E0) GO TO 640
            T = W
            IF (T .NE. 0.0E0) GO TO 635
            T = NORM
  632       T = 0.5E0*T
            IF (NORM + T .GT. NORM) GO TO 632
            T = 2.0E0*T
  635       H(I,EN) = -R / T
            GO TO 700
!     .......... SOLVE REAL EQUATIONS ..........
  640       X = H(I,I+1)
            Y = H(I+1,I)
            Q = (WR(I) - P) * (WR(I) - P) + WI(I) * WI(I)
            T = (X * S - ZZ * R) / Q
            H(I,EN) = T
            IF (ABS(X) .LE. ABS(ZZ)) GO TO 650
            H(I+1,EN) = (-R - W * T) / X
            GO TO 700
  650       H(I+1,EN) = (-S - Y * T) / ZZ
  700    CONTINUE
!     .......... END REAL VECTOR ..........
         GO TO 800
!     .......... COMPLEX VECTOR ..........
  710    M = NA
!     .......... LAST VECTOR COMPONENT CHOSEN IMAGINARY SO THAT
!                EIGENVECTOR MATRIX IS TRIANGULAR ..........
         IF (ABS(H(EN,NA)) .LE. ABS(H(NA,EN))) GO TO 720
         H(NA,NA) = Q / H(EN,NA)
         H(NA,EN) = -(H(EN,EN) - P) / H(EN,NA)
         GO TO 730
  720    CALL CDIV(0.0E0,-H(NA,EN),H(NA,NA)-P,Q,H(NA,NA),H(NA,EN))
  730    H(EN,NA) = 0.0E0
         H(EN,EN) = 1.0E0
         ENM2 = NA - 1
         IF (ENM2 .EQ. 0) GO TO 800
!     .......... FOR I=EN-2 STEP -1 UNTIL 1 DO -- ..........
         DO 790 II = 1, ENM2
            I = NA - II
            W = H(I,I) - P
            RA = 0.0E0
            SA = H(I,EN)
!
            DO 760 J = M, NA
               RA = RA + H(I,J) * H(J,NA)
               SA = SA + H(I,J) * H(J,EN)
  760       CONTINUE
!
            IF (WI(I) .GE. 0.0E0) GO TO 770
            ZZ = W
            R = RA
            S = SA
            GO TO 790
  770       M = I
            IF (WI(I) .NE. 0.0E0) GO TO 780
            CALL CDIV(-RA,-SA,W,Q,H(I,NA),H(I,EN))
            GO TO 790
!     .......... SOLVE COMPLEX EQUATIONS ..........
  780       X = H(I,I+1)
            Y = H(I+1,I)
            VR = (WR(I) - P) * (WR(I) - P) + WI(I) * WI(I) - Q * Q
            VI = (WR(I) - P) * 2.0E0 * Q
            IF (VR .NE. 0.0E0 .OR. VI .NE. 0.0E0) GO TO 783
            S1 = NORM * (ABS(W)+ABS(Q)+ABS(X)+ABS(Y)+ABS(ZZ))
            VR = S1
  782       VR = 0.5E0*VR
            IF (S1 + VR .GT. S1) GO TO 782
            VR = 2.0E0*VR
  783       CALL CDIV(X*R-ZZ*RA+Q*SA,X*S-ZZ*SA-Q*RA,VR,VI,   &
                      H(I,NA),H(I,EN))
            IF (ABS(X) .LE. ABS(ZZ) + ABS(Q)) GO TO 785
            H(I+1,NA) = (-RA - W * H(I,NA) + Q * H(I,EN)) / X
            H(I+1,EN) = (-SA - W * H(I,EN) - Q * H(I,NA)) / X
            GO TO 790
  785       CALL CDIV(-R-Y*H(I,NA),-S-Y*H(I,EN),ZZ,Q,   &
                      H(I+1,NA),H(I+1,EN))
  790    CONTINUE
!     .......... END COMPLEX VECTOR ..........
  800 CONTINUE
!     .......... END BACK SUBSTITUTION.
!                VECTORS OF ISOLATED ROOTS ..........
      DO 840 I = 1, N
         IF (I .GE. LOW .AND. I .LE. IGH) GO TO 840
!
         DO 820 J = I, N
            Z(I,J) = H(I,J)
  820    CONTINUE
!
  840 CONTINUE
!     .......... MULTIPLY BY TRANSFORMATION MATRIX TO GIVE
!                VECTORS OF ORIGINAL FULL MATRIX.
!                FOR J=N STEP -1 UNTIL LOW DO -- ..........
      DO 880 JJ = LOW, N
         J = N + LOW - JJ
         M = MIN0(J,IGH)
!
         DO 885 I = LOW, IGH
            ZZ = 0.0E0
!
            DO 860 K = LOW, M
               ZZ = ZZ + Z(I,K) * H(K,J)
  860       CONTINUE
!
            Z(I,J) = ZZ
  885    CONTINUE
  880 CONTINUE
!
      GO TO 1001
!     .......... SET ERROR -- NO CONVERGENCE TO AN
!                EIGENVALUE AFTER 30*N ITERATIONS ..........
 1000 IERR = EN
 1001 RETURN
      END SUBROUTINE HQR2
      SUBROUTINE HSECDF(X,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE HYPERBOLIC SECANT DISTRIBUTION
!              WITH MEAN = 0 AND STANDARD DEVIATION = PI/SQRT(3).
!              THIS DISTRIBUTION IS DEFINED FOR ALL X AND HAS
!              THE PROBABILITY DENSITY FUNCTION
!              F(X) = EXP(X)/(1+EXP(X)).
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 1994, PAGE 147
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--OCTOBER   1995.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!----COMMON-----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      DATA PI / 3.1415926535/
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS.
!     NO INPUT ARGUMENT ERRORS POSSIBLE
!     FOR THIS DISTRIBUTION.
!
!-----START POINT-----------------------------------------------------
!
      IF(X.GT.80.0)THEN
        CDF=1.0
        GO TO 9999
      ELSEIF(X.LT.-80.0)THEN
        CDF=0.0
        GO TO 9999
      ELSE
        ARG=X/2.0
        TERM1=(EXP(ARG)-EXP(-ARG))/(EXP(ARG)+EXP(-ARG))
        CDF=0.5 + (2.0/PI)*ATAN(TERM1)
      ENDIF
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE HSECDF
      SUBROUTINE HSEPDF(X,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE HYPERBOLIC SECANT DISTRIBUTION
!              THIS DISTRIBUTION IS DEFINED FOR ALL X AND HAS
!              THE PROBABILITY DENSITY FUNCTION
!              F(X) = SECH(X)/PI
!                   = (1/PI)*(2/(EXP(X) + EXP(-X))
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 1994, PAGE 147
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2899
!     ORIGINAL VERSION--OCTOBER   1995.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX, DPDF, DPI
!
      INCLUDE 'DPCOP2.INC'
!
      DATA DPI / 3.141592653589793238462643383279503D0 /
!
!---------------------------------------------------------------------
!
      DX=DBLE(X)
      IF(DABS(DX).GT.500.0D0)THEN
        PDF=0.0
      ELSE
        DPDF=2.0D0/(DEXP(DX) + DEXP(-DX))
        PDF=SNGL(DPDF/DPI)
      ENDIF
!
      RETURN
      END SUBROUTINE HSEPDF
      SUBROUTINE HSEPPF(P,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE HYPERBOLIC SECANT DISTRIBUTION
!              THE PROBABILITY DENSITY FUNCTION IS
!              F(X) = SECH(X)/PI
!                   = (1/PI)*(2/(EXP(X) + EXP(-X))
!              NOTE THAT THE PERCENT POINT FUNCTION OF A DISTRIBUTION
!              IS IDENTICALLY THE SAME AS THE INVERSE CUMULATIVE
!              DISTRIBUTION FUNCTION OF THE DISTRIBUTION.
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE
!                                (BETWEEN 0.0 AND 1.0)
!                                AT WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION PERCENT
!                                POINT FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT
!             FUNCTION VALUE PPF.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--P SHOULD BE BETWEEN 0.0 AND 1.0, EXCLUSIVELY.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!               --JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 1994, PAGE 147
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--95.10
!     ORIGINAL VERSION--OCTOBER   1995.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DARG
      DOUBLE PRECISION DPI
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DPPF
!
      INCLUDE 'DPCOP2.INC'
!
      DATA DPI / 3.141592653589793238462643383279503D0 /
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(P.LE.0.0.OR.P.GE.1.0)GO TO 50
      GO TO 90
   50 WRITE(ICOUT,1)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,46)P
      CALL DPWRST('XXX','BUG ')
      RETURN
   90 CONTINUE
    1 FORMAT('***** FATAL ERROR--THE 1ST INPUT ARGUMENT TO THE ',   &
      'HSEPPF SUBROUTINE IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
!
      DARG=DPI*(DBLE(P)-0.5D0)/2.0D0
      DTERM1=DTAN(DARG)
      DPPF=DLOG((1.0+DTERM1)/(1.0D0-DTERM1))
      PPF=SNGL(DPPF)
!
      RETURN
      END SUBROUTINE HSEPPF
      SUBROUTINE HSERAN(N,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE HYPERBOLIC SECANT DISTRIBUTION
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE HYPERBOLIC SECANT DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--2001/10
!     ORIGINAL VERSION--OCTOBER   2001.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)GO TO 50
      GO TO 90
   50 WRITE(ICOUT, 5)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,47)N
      CALL DPWRST('XXX','BUG ')
      RETURN
   90 CONTINUE
    5 FORMAT('***** FATAL ERROR--THE 1ST INPUT ARGUMENT TO THE ',   &
      'HSERAN SUBROUTINE IS NON-POSITIVE *****')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,' *****')
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N HYPERBOLIC SECANT RANDOM NUMBERS
!     USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD.
!
      DO 100 I=1,N
      CALL HSEPPF(X(I),XTEMP)
      X(I)=XTEMP
  100 CONTINUE
!
      RETURN
      END SUBROUTINE HSERAN
      SUBROUTINE HSNINT(NR,N,A,SX,METHOD)
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
! PURPOSE
! -------
! PROVIDE INITIAL HESSIAN WHEN USING SECANT UPDATES
!
! PARAMETERS
! ----------
! NR           --> ROW DIMENSION OF MATRIX
! N            --> DIMENSION OF PROBLEM
! A(N,N)      <--  INITIAL HESSIAN (LOWER TRIANGULAR MATRIX)
! SX(N)        --> DIAGONAL SCALING MATRIX FOR X
! METHOD       --> ALGORITHM TO USE TO SOLVE MINIMIZATION PROBLEM
!                    =1,2 FACTORED SECANT METHOD USED
!                    =3   UNFACTORED SECANT METHOD USED
!
      DIMENSION A(NR,1),SX(N)
!
      DO 100 J=1,N
        IF(METHOD.EQ.3) A(J,J)=SX(J)*SX(J)
        IF(METHOD.NE.3) A(J,J)=SX(J)
        IF(J.EQ.N) GO TO 100
        JP1=J+1
        DO 90 I=JP1,N
          A(I,J)=0.D0
   90   CONTINUE
  100 CONTINUE
      RETURN
      END SUBROUTINE HSNINT
      SUBROUTINE HTTSQ1(AMAT1,AMAT2,MAXROM,MAXCOM,NR1,NC1,   &
                        TSTAT,ASIG90,ASIG95,ASIG99,ASG995,   &
                        DMEAN,Y1,Y2,Y3,INDEX,   &
                        IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE
!              1-SAMPLE HOTELLING T-SQUARE STATISTIC.
!              HO: U = U0
!              T2=N*(XBAR-U0)'*SINV*(XBAR-U0)
!     INPUT  ARGUMENTS--AMAT1  = THE ORIGINAL SINGLE PRECISION MATRIX
!                     --MAXROM = THE INTEGER ROW DIMENSION OF AMAT1
!                     --MAXCOM = THE INTEGER COUMN DIMENSION OF AMAT1
!                     --NR1    = THE INTEGER NUMBER OF ROWS OF AMAT1
!                     --NC1    = THE INTEGER NUMBER OF COLUMNS OF AMAT1
!                     --Y1     = VECTOR CONTAINING HYPOTHESIZED MEANS
!                     --Y2     = DUMMY VECTOR CONTAINING SAMPLE MEANS
!     OUTPUT ARGUMENTS--AMAT2  = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED INVERTED VARIANCE-COVARIANCE
!                                MATRIX
!                     --TSTAT  = VALUE OF HOTELLING T-SQUARE
!                     --ASIG90 = CRITICAL VALUE FOR ALPHA = .90
!                     --ASIG95 = CRITICAL VALUE FOR ALPHA = .95
!                     --ASIG99 = CRITICAL VALUE FOR ALPHA = .99
!                     --ASG995= CRITICAL VALUE FOR ALPHA = .995
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             HOTELLING T-SQUARE VALUE
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--98.7
!     ORIGINAL VERSION--JULY      1998.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASE
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
!
      DIMENSION AMAT1(MAXROM,MAXCOM)
      DIMENSION AMAT2(MAXROM,MAXCOM)
      DIMENSION Y1(*)
      DIMENSION Y2(*)
      DIMENSION Y3(*)
      DIMENSION INDEX(*)
      DOUBLE PRECISION DMEAN(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='HOTT'
      ISUBN2='SQ  '
!
      IWRITE='OFF'
      IERROR='NO'
!
      IF(IBUGA3.EQ.'OFF')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF HTTSQ1--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IBUGA3
   52 FORMAT('IBUGA3 = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)NR1,NC1
   53 FORMAT('NR1, NC1 = ',2I8)
      CALL DPWRST('XXX','BUG ')
      DO 55 I=1,NC1
      WRITE(ICOUT,56)I,Y1(I)
   56 FORMAT('I,Y(I) = ',I8,E15.7)
      CALL DPWRST('XXX','BUG ')
   55 CONTINUE
   90 CONTINUE
!
!               **********************************
!               **  COMPUTE HOTELLING T-SQUARE  **
!               **********************************
!
      ICASE='COLU'
      CALL VARCOV(AMAT1,AMAT2,MAXROM,MAXCOM,NR1,NC1,DMEAN,   &
                  ICASE,IBUGA3,IERROR)
      CALL SGECO(AMAT2,MAXROM,NC1,INDEX,RCOND,Y2)
!
      IF(1.0+RCOND.EQ.1.0)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5171)
        CALL DPWRST('XXX','ERRO ')
        WRITE(ICOUT,5172)
        CALL DPWRST('XXX','ERRO ')
        WRITE(ICOUT,5173)
        CALL DPWRST('XXX','ERRO ')
        IERROR='YES'
        GO TO 9000
      ENDIF
 5171 FORMAT('*** ERROR FROM HTTSQ1: UNABLE TO COMPUTE THE INVERSE OF ',   &
             'THE COVARIANCE MATRIX.')
 5172 FORMAT('    PROBLEM: SOME COLUMNS ARE LINEARLY DEPDENDENT ON ',   &
             ' OTHER COLUMNS.')
 5173 FORMAT('    SUGGESTED SOLUTION: WORK WITH A SUBSET OF THE ',   &
             'ORIGINAL COLUMNS.')
!
      IJOB=1
      CALL SGEDI(AMAT2,MAXROM,NC1,INDEX,Y2,Y3,IJOB)
!
      DO 6000 I=1,NC1
        DO 6110 J=1,NR1
          Y2(J)=AMAT1(J,I)
 6110   CONTINUE
        CALL MEAN(Y2,NR1,IWRITE,XMEAN,IBUGA3,IERROR)
        Y3(I)=XMEAN-Y1(I)
 6000 CONTINUE
      CALL QUAFRM(AMAT2,MAXROM,MAXCOM,NC1,NC1,Y3,IWRITE,   &
                  XQUAD,IBUGA3,IERROR)
      TSTAT=REAL(NR1)*XQUAD
!
      AFACT=REAL(NC1*(NR1-1)/(NR1-NC1))
      CALL FPPF(0.90,NC1,NR1-NC1,ATEMP1)
      ASIG90=AFACT*ATEMP1
      CALL FPPF(0.95,NC1,NR1-NC1,ATEMP1)
      ASIG95=AFACT*ATEMP1
      CALL FPPF(0.99,NC1,NR1-NC1,ATEMP1)
      ASIG99=AFACT*ATEMP1
      CALL FPPF(0.995,NC1,NR1-NC1,ATEMP1)
      ASG995=AFACT*ATEMP1
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF HTTSQ1--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGA3,IERROR
 9012 FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE HTTSQ1
      SUBROUTINE HTTSQ2(AMAT1,AMAT2,AMAT3,MAXROM,MAXCOM,NR1,NR2,NC1,   &
                        TSTAT,ASIG90,ASIG95,ASIG99,ASG995,   &
                        DMEAN,Y1,Y2,Y3,INDEX,   &
                        IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE
!              2-SAMPLE HOTELLING T-SQUARE STATISTIC.
!              HO: U1 = U2
!              T2=N1*N2*(XBAR1-XBAR2)'*SINV*(XBAR1-XBAR2)/(N1+N2)
!              WHERE SINV IS THE INVERSE OF THE POOLED COVARIANCE
!              MATRIX.
!     INPUT  ARGUMENTS--AMAT1  = THE SAMPLE 1 SINGLE PRECISION MATRIX
!                     --AMAT2  = THE SAMPLE 2 SINGLE PRECISION MATRIX
!                     --MAXROM = THE INTEGER ROW DIMENSION OF AMAT1
!                     --MAXCOM = THE INTEGER COUMN DIMENSION OF AMAT1
!                     --NR1    = THE INTEGER NUMBER OF ROWS OF AMAT1
!                     --NR2    = THE INTEGER NUMBER OF ROWS OF AMAT2
!                     --NC1    = THE INTEGER NUMBER OF COLUMNS OF AMAT1
!                     --Y1     = DUMMY VECTOR CONTAINING SAMPLE 1 MEANS
!                     --Y2     = DUMMY VECTOR CONTAINING SAMPLE 2 MEANS
!     OUTPUT ARGUMENTS--AMAT3  = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED INVERTED VARIANCE-COVARIANCE
!                                MATRIX
!                     --TSTAT  = VALUE OF HOTELLING T-SQUARE
!                     --ASIG90 = CRITICAL VALUE FOR ALPHA = .90
!                     --ASIG95 = CRITICAL VALUE FOR ALPHA = .95
!                     --ASIG99 = CRITICAL VALUE FOR ALPHA = .99
!                     --ASG995= CRITICAL VALUE FOR ALPHA = .995
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             HOTELLING T-SQUARE VALUE
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--98.7
!     ORIGINAL VERSION--JULY      1998.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
!
      DIMENSION AMAT1(MAXROM,MAXCOM)
      DIMENSION AMAT2(MAXROM,MAXCOM)
      DIMENSION AMAT3(MAXROM,MAXCOM)
      DIMENSION Y1(*)
      DIMENSION Y2(*)
      DIMENSION Y3(*)
      DIMENSION INDEX(*)
      DOUBLE PRECISION DMEAN(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='HTTS'
      ISUBN2='Q2  '
      IWRITE='OFF'
      IERROR='NO'
!
      IF(IBUGA3.EQ.'OFF')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF HTTSQ2--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IBUGA3
   52 FORMAT('IBUGA3 = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)NR1,NR2,NC1
   53 FORMAT('NR1, NR2, NC1 = ',3I8)
      CALL DPWRST('XXX','BUG ')
   90 CONTINUE
!
!               **********************************
!               **  COMPUTE HOTELLING T-SQUARE  **
!               **********************************
!
      CALL VARPOO(AMAT1,AMAT2,AMAT3,MAXROM,MAXCOM,NR1,NC1,NR2,   &
                  DMEAN,IBUGA3,IERROR)
      CALL SGECO(AMAT3,MAXROM,NC1,INDEX,RCOND,Y1)
!
      IF(1.0+RCOND.EQ.1.0)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5171)
        CALL DPWRST('XXX','ERRO ')
        WRITE(ICOUT,5172)
        CALL DPWRST('XXX','ERRO ')
        WRITE(ICOUT,5173)
        CALL DPWRST('XXX','ERRO ')
        IERROR='YES'
        GO TO 9000
      ENDIF
 5171 FORMAT('*** ERROR FROM HTTSQ2: UNABLE TO COMPUTE THE INVERSE OF ',   &
             'THE POOLED COVARIANCE MATRIX.')
 5172 FORMAT('    PROBLEM: SOME COLUMNS ARE LINEARLY DEPDENDENT ON ',   &
             ' OTHER COLUMNS.')
 5173 FORMAT('    SUGGESTED SOLUTION: WORK WITH A SUBSET OF THE ',   &
             'ORIGINAL COLUMNS.')
!
      IJOB=1
      CALL SGEDI(AMAT3,MAXROM,NC1,INDEX,Y1,Y2,IJOB)
!
      DO 6000 I=1,NC1
        DO 6110 J=1,NR1
          Y1(J)=AMAT1(J,I)
 6110   CONTINUE
        DO 6120 J=1,NR2
          Y2(J)=AMAT2(J,I)
 6120   CONTINUE
        CALL MEAN(Y1,NR1,IWRITE,XMEAN1,IBUGA3,IERROR)
        CALL MEAN(Y2,NR2,IWRITE,XMEAN2,IBUGA3,IERROR)
        Y3(I)=XMEAN1-XMEAN2
 6000 CONTINUE
      CALL QUAFRM(AMAT3,MAXROM,MAXCOM,NC1,NC1,Y3,IWRITE,   &
                  XQUAD,IBUGA3,IERROR)
      TSTAT=REAL(NR1*NR2)*XQUAD/REAL(NR1+NR2)
!
      AFACT=REAL((Nr1+NR2-NC1-1)/((NR1+NR2-2)*NC1))
      CALL FPPF(0.90,NC1,NR1+NR2-NC1-1,ATEMP1)
      ASIG90=AFACT*ATEMP1
      CALL FPPF(0.95,NC1,NR1+NR2-NC1-1,ATEMP1)
      ASIG95=AFACT*ATEMP1
      CALL FPPF(0.99,NC1,NR1+NR2-NC1-1,ATEMP1)
      ASIG99=AFACT*ATEMP1
      CALL FPPF(0.995,NC1,NR1+NR2-NC1-1,ATEMP1)
      ASG995=AFACT*ATEMP1
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF HTTSQ2--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGA3,IERROR
 9012 FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE HTTSQ2
      SUBROUTINE HYGFX(A,B,C,X,HF,IERROR)
!
!       ====================================================
!       Purpose: Compute hypergeometric function F(a,b,c,x)
!       Input :  a --- Parameter
!                b --- Parameter
!                c --- Parameter, c <> 0,-1,-2,...
!                x --- Argument   ( x < 1 )
!       Output:  HF --- F(a,b,c,x)
!                IERROR--ERROR FLAG
!       Routines called:
!            (1) GAMMA for computing gamma function
!            (2) PSI for computing psi function
!       ====================================================
!
        IMPLICIT DOUBLE PRECISION (A-H,O-Z)
        LOGICAL L0,L1,L2,L3,L4,L5
!
        HW=0.0D0
        NM=0
!
        PI=3.141592653589793D0
        EL=.5772156649015329D0
        L0=C.EQ.INT(C).AND.C.LT.0.0
        L1=1.0D0-X.LT.1.0D-15.AND.C-A-B.LE.0.0
        L2=A.EQ.INT(A).AND.A.LT.0.0
        L3=B.EQ.INT(B).AND.B.LT.0.0
        L4=C-A.EQ.INT(C-A).AND.C-A.LE.0.0
        L5=C-B.EQ.INT(C-B).AND.C-B.LE.0.0
        IF (L0) THEN
           IERROR=1
!CCCC      WRITE(*,*)'The hypergeometric series is divergent'
           RETURN
        ENDIF
        IF (L1) THEN
           IERROR=2
!CCCC      WRITE(*,*)'The hypergeometric series is divergent'
           RETURN
        ENDIF
        EPS=1.0D-15
        IF (X.GT.0.95) EPS=1.0D-8
        IF (X.EQ.0.0.OR.A.EQ.0.0.OR.B.EQ.0.0) THEN
           HF=1.0D0
           RETURN
        ELSE IF (1.0D0-X.EQ.EPS.AND.C-A-B.GT.0.0) THEN
!CCCC USE CMLIB DGAMMA ROUTINE
!CCCC      CALL GAMMA(C,GC)
!CCCC      CALL GAMMA(C-A-B,GCAB)
!CCCC      CALL GAMMA(C-A,GCA)
!CCCC      CALL GAMMA(C-B,GCB)
           GC=DGAMMA(C)
           GCAB=DGAMMA(C-A-B)
           GCA=DGAMMA(C-A)
           GCB=DGAMMA(C-B)
           HF=GC*GCAB/(GCA*GCB)
           RETURN
        ELSE IF (1.0D0+X.LE.EPS.AND.DABS(C-A+B-1.0).LE.EPS) THEN
           G0=DSQRT(PI)*2.0D0**(-A)
!CCCC USE CMLIB DGAMMA ROUTINE
!CCCC      CALL GAMMA(C,G1)
!CCCC      CALL GAMMA(1.0D0+A/2.0-B,G2)
!CCCC      CALL GAMMA(0.5D0+0.5*A,G3)
           G1=DGAMMA(C)
           G2=DGAMMA(1.0D0+A/2.0-B)
           G3=DGAMMA(0.5D0+0.5*A)
           HF=G0*G1/(G2*G3)
           RETURN
        ELSE IF (L2.OR.L3) THEN
           IF (L2) NM=INT(ABS(A))
           IF (L3) NM=INT(ABS(B))
           HF=1.0D0
           R=1.0D0
           DO 10 K=1,NM
              R=R*(A+K-1.0D0)*(B+K-1.0D0)/(K*(C+K-1.0D0))*X
              HF=HF+R
10         CONTINUE
           RETURN
        ELSE IF (L4.OR.L5) THEN
           IF (L4) NM=INT(ABS(C-A))
           IF (L5) NM=INT(ABS(C-B))
           HF=1.0D0
           R=1.0D0
           DO 15 K=1,NM
              R=R*(C-A+K-1.0D0)*(C-B+K-1.0D0)/(K*(C+K-1.0D0))*X
              HF=HF+R
15         CONTINUE
           HF=(1.0D0-X)**(C-A-B)*HF
           RETURN
        ENDIF
        AA=A
        BB=B
        X1=X
        IF (X.LT.0.0D0) THEN
           X=X/(X-1.0D0)
           IF (C.GT.A.AND.B.LT.A.AND.B.GT.0.0) THEN
              A=BB
              B=AA
           ENDIF
           B=C-B
        ENDIF
        IF (X.GE.0.75D0) THEN
           GM=0.0D0
           IF (DABS(C-A-B-INT(C-A-B)).LT.1.0D-15) THEN
              M=INT(C-A-B)
!CCCC USE CMLIB DGAMMA ROUTINE
!CCCC         CALL GAMMA(A,GA)
!CCCC         CALL GAMMA(B,GB)
!CCCC         CALL GAMMA(C,GC)
!CCCC         CALL GAMMA(A+M,GAM)
!CCCC         CALL GAMMA(B+M,GBM)
              GA=DGAMMA(A)
              GB=DGAMMA(B)
              GC=DGAMMA(C)
              GAM=DGAMMA(A+M)
              GBM=DGAMMA(B+M)
!CCCC USE CMLIB DPSI ROUTINE
!CCCC         CALL PSI(A,PA)
!CCCC         CALL PSI(B,PB)
              PA=DPSI(A)
              PB=DPSI(B)
              IF (M.NE.0) GM=1.0D0
              DO 30 J=1,ABS(M)-1
                 GM=GM*J
30            CONTINUE
              RM=1.0D0
              DO 35 J=1,ABS(M)
                 RM=RM*J
35            CONTINUE
              F0=1.0D0
              R0=1.0D0
              R1=1.0D0
              SP0=0.D0
              SP=0.0D0
              IF (M.GE.0) THEN
                 C0=GM*GC/(GAM*GBM)
                 C1=-GC*(X-1.0D0)**M/(GA*GB*RM)
                 DO 40 K=1,M-1
                    R0=R0*(A+K-1.0D0)*(B+K-1.0)/(K*(K-M))*(1.0-X)
                    F0=F0+R0
40               CONTINUE
                 DO 45 K=1,M
                    SP0=SP0+1.0D0/(A+K-1.0)+1.0/(B+K-1.0)-1.0/K
45               CONTINUE
                 F1=PA+PB+SP0+2.0D0*EL+DLOG(1.0D0-X)
                 DO 55 K=1,250
                    SP=SP+(1.0D0-A)/(K*(A+K-1.0))+(1.0-B)/(K*(B+K-1.0))
                    SM=0.0D0
                    DO 50 J=1,M
                       SM=SM+(1.0D0-A)/((J+K)*(A+J+K-1.0))+1.0/   &
                          (B+J+K-1.0)
50                  CONTINUE
                    RP=PA+PB+2.0D0*EL+SP+SM+DLOG(1.0D0-X)
                    R1=R1*(A+M+K-1.0D0)*(B+M+K-1.0)/(K*(M+K))*(1.0-X)
                    F1=F1+R1*RP
                    IF (DABS(F1-HW).LT.DABS(F1)*EPS) GO TO 60
                    HW=F1
55               CONTINUE
60               HF=F0*C0+F1*C1
              ELSE IF (M.LT.0) THEN
                 M=-M
                 C0=GM*GC/(GA*GB*(1.0D0-X)**M)
                 C1=-(-1)**M*GC/(GAM*GBM*RM)
                 DO 65 K=1,M-1
                    R0=R0*(A-M+K-1.0D0)*(B-M+K-1.0)/(K*(K-M))*(1.0-X)
                    F0=F0+R0
65               CONTINUE
                 DO 70 K=1,M
                    SP0=SP0+1.0D0/K
70               CONTINUE
                 F1=PA+PB-SP0+2.0D0*EL+DLOG(1.0D0-X)
                 DO 80 K=1,250
                    SP=SP+(1.0D0-A)/(K*(A+K-1.0))+(1.0-B)/(K*(B+K-1.0))
                    SM=0.0D0
                    DO 75 J=1,M
                       SM=SM+1.0D0/(J+K)
75                  CONTINUE
                    RP=PA+PB+2.0D0*EL+SP-SM+DLOG(1.0D0-X)
                    R1=R1*(A+K-1.0D0)*(B+K-1.0)/(K*(M+K))*(1.0-X)
                    F1=F1+R1*RP
                    IF (DABS(F1-HW).LT.DABS(F1)*EPS) GO TO 85
                    HW=F1
80               CONTINUE
85               HF=F0*C0+F1*C1
              ENDIF
           ELSE
!CCCC USE CMLIB DGAMMA ROUTINE
!CCCC         CALL GAMMA(A,GA)
!CCCC         CALL GAMMA(B,GB)
!CCCC         CALL GAMMA(C,GC)
!CCCC         CALL GAMMA(C-A,GCA)
!CCCC         CALL GAMMA(C-B,GCB)
!CCCC         CALL GAMMA(C-A-B,GCAB)
!CCCC         CALL GAMMA(A+B-C,GABC)
              GA=DGAMMA(A)
              GB=DGAMMA(B)
              GC=DGAMMA(C)
              GCA=DGAMMA(C-A)
              GCB=DGAMMA(C-B)
              GCAB=DGAMMA(C-A-B)
              GABC=DGAMMA(A+B-C)
              C0=GC*GCAB/(GCA*GCB)
              C1=GC*GABC/(GA*GB)*(1.0D0-X)**(C-A-B)
              HF=0.0D0
              R0=C0
              R1=C1
              DO 90 K=1,250
                 R0=R0*(A+K-1.0D0)*(B+K-1.0)/(K*(A+B-C+K))*(1.0-X)
                 R1=R1*(C-A+K-1.0D0)*(C-B+K-1.0)/(K*(C-A-B+K))   &
                    *(1.0-X)
                 HF=HF+R0+R1
                 IF (DABS(HF-HW).LT.DABS(HF)*EPS) GO TO 95
                 HW=HF
90            CONTINUE
95            HF=HF+C0+C1
           ENDIF
        ELSE
           A0=1.0D0
           IF (C.GT.A.AND.C.LT.2.0D0*A.AND.   &
               C.GT.B.AND.C.LT.2.0D0*B) THEN
              A0=(1.0D0-X)**(C-A-B)
              A=C-A
              B=C-B
           ENDIF
           HF=1.0D0
           R=1.0D0
           DO 100 K=1,250
              R=R*(A+K-1.0D0)*(B+K-1.0D0)/(K*(C+K-1.0D0))*X
              HF=HF+R
              IF (DABS(HF-HW).LE.DABS(HF)*EPS) GO TO 105
              HW=HF
100        CONTINUE
105        HF=A0*HF
        ENDIF
        IF (X1.LT.0.0D0) THEN
           X=X1
           C0=1.0D0/(1.0D0-X)**AA
           HF=C0*HF
        ENDIF
        A=AA
        B=BB
        IF (K.GT.120) THEN
!CCCC     WRITE(*,115)
!115      FORMAT(1X,'Warning! You should check the accuracy')
          IERROR=3
        ENDIF
        RETURN
        END
      SUBROUTINE HYPCDF(LL,KK,NN,MM,POINT,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE AT THE INTEGER VALUE LL
!              FOR THE HYPERGEOMETRIC DISTRIBUTION.
!              THE HYPERGEOMETRIC DISTRIBUTION IS THE PROBABILITY OF
!              SELECTING LL MARKED ITEMS WHEN A RANDOM SAMPLE OF SIZE
!              KK IS TAKEN WITHOUT REPLACEMENT FROM A POPULATION OF
!              MM ITEMS, NN OF WHICH ARE MARKED.  IT HAS CDF OF:
!                 CDF = P(X<= LL | KK, NN, MM)
!     INPUT  ARGUMENTS--LL     = THE INTEGER VALUE
!                                AT WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                IT SHOULD BE INTEGRAL-VALUED,
!                                AND BETWEEN 0.0 (INCLUSIVELY)
!                                AND MM (INCLUSIVELY).
!                     --KK     = THE INTEGER VALUE INDICATING THE
!                                SAMPLE SIZE.
!                     --NN     = THE NUMBER OF MARKED ITEMS IN THE
!                                POPULATION.
!                     --MM     = THE POPULATION SIZE.
!                     --POINT  = LOGICAL VARIABLE THAT SPECIFIES
!                                WHETHER THE CDF OR PDF SHOULD BE
!                                COMPUTED.
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--LL SHOULD BE INTEGRAL-VALUED,
!                   AND BETWEEN 0 AND MM (INCLUSIVELY)
!                 --KK SHOULD BE A POSITIVE INTEGER BETWEEN 1 AND MM.
!                 --NN SHOULD BE A POSITIVE INTEGER BETWEEN 1 AND MM.
!     OTHER SUBROUTINES NEEDED--NORCDF, DLNGAM
!     LANGUAGE--ANSI FORTRAN (1977)
!     COMMENT--THIS ROUTINE USES ALGORITHM AS R77 FROM THE
!              APPLIED STATISTICS JOURNAL. CODE RETRIEVED FROM STATLIB.
!
!     ALGORITHM AS R77  APPL. STATIST. (1989), VOL.38, NO.1
!     Replaces AS 59 and AS 152
!     Incorporates AS R86 from vol.40(2)
!
!     Auxiliary routines required: ALNFAC (AS 245), ALNORM (AS 66)
!
!     REFERENCES--HASTINGS AND PEACOCK, STATISTICAL
!                 DISTRIBUTIONS--A HANDBOOK FOR
!                 STUDENTS AND PRACTITIONERS, 1975,
!               --JOHNSON AND KOTZ, DISCRETE
!                 DISTRIBUTIONS, 1969.
!               --REMARK AS R77, AS152, AND AS59 FROM THE APPLIED
!                 STATISTICS JOURNAL.
!               --"THE ACCURACY OF PIEZER APPROXIMATIONS TO THE
!                 HYPERGEOMETRIC DISTRIBUTION, WITH COMPARISONS TO
!                 SOME OTHER APPROXIMATIONS", LING AND PRATT, JASA,
!                 MARCH, 1984.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--94/9
!     ORIGINAL VERSION--SEPTEMBER 1994.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      INTEGER  KK, LL, MM, NN, K, L, M, N, I, J, NL, KL,   &
               MNKL, MVBIG, MBIG
!CCCC DOUBLE PRECISION ZERO, ONE, P, PT, HALF, DLNGAM, ELIMIT, MEAN,
!CCCC*                 SIG, SXTEEN, SCALE, ROOTPI, ARG, HUNDRD, DCDF,
      DOUBLE PRECISION ZERO, ONE, P, PT, HALF, DLNGAM, ELIMIT,   &
                       SXTEEN, SCALE, ROOTPI, HUNDRD, DCDF,   &
                       XMAX,XMAXT,DTERM1,   &
                       DTERM2,DTERM3,DTERM4,DTERM5,DTERM6,DTERM7,DTERM8
      DOUBLE PRECISION P1, P2, A, B, C, D, DCDF2
      LOGICAL   POINT, DIR
      PARAMETER (ZERO = 0.0D0, HALF = 0.5D0, ONE = 1.0D0, MVBIG = 1000,   &
                 MBIG = 600, SXTEEN = 16.0D0,   &
                 ROOTPI = 2.506628274631001D0,   &
                 HUNDRD = 100.0D0)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      CDF=0.0
      IF(NN.LE.0.OR.NN.GT.MM)THEN
        WRITE(ICOUT,11)
   11   FORMAT('***** ERROR--THE THIRD ARGUMENT TO HYPCDF ',   &
               '(THE NUMBER OF MARKED ITEMS)')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,12)
   12   FORMAT('      IS LESS THAN ZERO OR GREATER THAN THE POULATION ',   &
               'SIZE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)NN
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(KK.LE.0.OR.KK.GT.MM)THEN
        WRITE(ICOUT,21)
   21   FORMAT('***** ERROR--THE SECOND ARGUMENT TO HYPCDF ',   &
               '(THE SAMPLE SIZE)')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,22)
   22   FORMAT('      IS LESS THAN ZERO OR GREATER THAN THE POULATION ',   &
               'SIZE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)KK
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(LL.LT.0.OR.KK-LL.GT.MM-NN)THEN
        WRITE(ICOUT,31)MM-NN
   31   FORMAT('***** WARNING--THE FIRST INPUT ARGUMENT TO ',   &
               'HYPCDF IS OUTSIDE THE (0,',I8,') INTERVAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)LL
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(LL.GT.NN.OR.LL.GT.KK)THEN
        WRITE(ICOUT,41)
   41   FORMAT('***** WARNING--THE FIRST ARGUMENT TO HYPCDF ',   &
               'IS GREATER THAN THE SAMPLE SIZE ')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,42)
   42   FORMAT('      OR GREATER THAN THE NUMBER OF MARKED ITEMS.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)LL
        CALL DPWRST('XXX','BUG ')
        IF(.NOT.POINT)CDF=1.0
        GO TO 9000
      ENDIF
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,'.')
!
!  CALCULATE EXPONENTIAL LIMIT FOR UNDERFLOW
!
      XMAXT = -DLOG(D1MACH(1))
      XMAX = XMAXT - 0.5D0*XMAXT*DLOG(XMAXT)/(XMAXT+0.5D0) - 0.01D0
      ELIMIT=-XMAX
      SCALE = D1MACH(1) + 1000.D0*D1MACH(3)
!
!     TREAT IMMEDIATELY THE SPECIAL CASES WHICH RETURN A VALUE OF
!     0 OR 1.
!
      K = KK + 1
      L = LL + 1
      M = MM + 1
      N = NN + 1
      DIR = .TRUE.
      DCDF = ONE
      IF (K .EQ. 1 .OR. K .EQ. M .OR. N .EQ. 1 .OR. N .EQ. M) GO TO 9999
      IF (.NOT. POINT .AND. LL .EQ. MIN(KK, NN)) GO TO 9999
!
      P = DBLE(NN) / DBLE(MM - NN)
!
!     Use a normal approximation for sufficently large arguments
!
!     THE NORMAL APPROXIMATION HERE DOES NOT SEEM TO PRODUCE
!     PARTICULARLY ACCURATE RESULTS.  USE A BINOMIAL APPROXIMATION
!     INSTEAD (TAKEN FROM LING AND PRATT ARTICLE IN REFERENCE).
!CCCC IF (DBLE(MIN(KK, MM-KK)) .GT. SXTEEN * MAX(P, ONE/P) .AND.
!CCCC*   MM .GT. MVBIG .AND. ELIMIT .GT. -HUNDRD) THEN
      IF (DBLE(MIN(KK, MM-KK)) .GT. SXTEEN * MAX(P, ONE/P) .AND.   &
         MM .GT. MVBIG ) THEN
        K=KK
        M=MM
        N=NN
        L=LL
        IF (MIN(K-1, M-K) .GT. MIN(N-1, M-N)) THEN
          I = K
          K = N
          N = I
        END IF
        IF (M-K .LT. K-1) THEN
          DIR = .NOT. DIR
          L = N - L + 1
          K = M - K + 1
        END IF
!CCCC   MEAN = DBLE(K) * DBLE(N) / DBLE(M)
!CCCC   SIG = DSQRT(MEAN*(DBLE(M-N)/DBLE(M))*(DBLE(M-K)/(DBLE(M-1))))
!CCCC   IF (POINT) THEN
!CCCC     ARG = -HALF * (((DBLE(L) - MEAN) / SIG)**2)
!CCCC     DCDF = ZERO
!CCCC     IF (ARG .GE. ELIMIT) DCDF = DEXP(ARG)/(SIG*ROOTPI)
!CCCC   ELSE
!CCCC     DTERM1=(DBLE(L)+HALF-MEAN)/SIG
!CCCC     CALL NORCDF(SNGL(DTERM1),CDF)
!CCCC     DCDF = DBLE(CDF)
!CCCC     IF(.NOT.DIR)DCDF=1.0D0 - DCDF
!CCCC   END IF
!
!     BINOMIAL APPROXIMATION.
!
        A=DBLE(L)
        B=DBLE(K-L)
        C=DBLE(N-L)
        D=DBLE(M+L-N-K)
        P1=DBLE(2*N-L)/DBLE(2*M-K+1)
        DTERM1=DBLE(K+1)*(A*P1-(B-1.0D0)*(1.0D0-P1))
        DTERM2=-A*(A+2.0D0)/P1 + (B**2-1.0D0)/(1.0D0-P1)
        DTERM3=6.0D0*(2.0D0*DBLE(M)-DBLE(K)+1.0D0)**2
        P2=P1+(DTERM1+DTERM2)/DTERM3
        AP1=SNGL(P1)
        AP2=SNGL(P2)
        AX=REAL(L)
        IF (POINT) THEN
          CALL BINCDF(DBLE(AX),DBLE(AP2),K,DCDF)
          IF(AX.GT.0.1)THEN
            AX=AX-1.0
            CALL BINCDF(DBLE(AX),DBLE(AP2),K,DCDF2)
            DCDF=DCDF-DCDF2
          ENDIF
        ELSE
          CALL BINCDF(DBLE(AX),DBLE(AP2),K,DCDF)
          IF(.NOT.DIR) DCDF=1.0D0-DCDF
        ENDIF
!
!     Calculate exact hypergeometric probabilities.
!     Interchange K and N if this saves calculations.
!
      ELSE
        IF (MIN(K-1, M-K) .GT. MIN(N-1, M-N)) THEN
          I = K
          K = N
          N = I
        END IF
        IF (M-K .LT. K-1) THEN
          DIR = .NOT. DIR
          L = N - L + 1
          K = M - K + 1
        END IF
        IF (MM .GT. MBIG) THEN
!
!     Take logarithms of factorials.
!     Use fact that GAMMA(N)=(N-1)!.  USE DLNGAM function.
!
!CCCC     P = ALNFAC(NN) - ALNFAC(MM) + ALNFAC(MM-KK) + ALNFAC(KK) +
!CCCC*        ALNFAC(MM-NN)-ALNFAC(LL)-ALNFAC(NN-LL)-ALNFAC(KK-LL)
!CCCC*        - ALNFAC(MM-NN-KK+LL)
!CCCC     P = DLNGAM(DBLE(NN-1)) - DLNGAM(DBLE(MM-1)) +
!CCCC*        DLNGAM(DBLE(MM-KK-1)) + DLNGAM(DBLE(KK-1)) +
!CCCC*        DLNGAM(DBLE(MM-NN-1)) - DLNGAM(DBLE(LL-1)) -
!CCCC*        DLNGAM(DBLE(NN-LL-1)) - DLNGAM((KK-LL-1)) -
!CCCC*        DLNGAM(DBLE(MM-NN-KK+LL-1))
          DTERM1=DLNGAM(DBLE(NN+1))
          DTERM2=DLNGAM(DBLE(MM+1))
          DTERM3=DLNGAM(DBLE(MM-KK+1))
          DTERM4=DLNGAM(DBLE(KK+1))
          DTERM5=DLNGAM(DBLE(MM-NN+1))
          DTERM6=DLNGAM(DBLE(LL+1))
          DTERM7=DLNGAM(DBLE(NN-LL+1))
          DTERM8=DLNGAM(DBLE(KK-LL+1))
          DTERM9=DLNGAM(DBLE(MM-NN-KK+LL+1))
          P=DTERM1-DTERM2+DTERM3+DTERM4+DTERM5-   &
            DTERM6-DTERM7-DTERM8-DTERM9
          DCDF = ZERO
          IF (P .GE. ELIMIT) DCDF = DEXP(P)
!
!     Use Freeman/Lund algorithm
!
        ELSE
          DO 3 I = 1, L-1
            DCDF= DCDF*DBLE(K-I)*DBLE(N-I)/(DBLE(L-I)*DBLE(M-I))
    3     CONTINUE
          IF (L .NE. K) THEN
            J = M - N + L
            DO 5 I = L, K-1
              DCDF = DCDF * DBLE(J-I) / DBLE(M-I)
    5       CONTINUE
          END IF
!
        END IF
!
        IF (POINT) GO TO 9999
!
!     We must recompute the point probability since it has underflowed.
!
        IF (DCDF .EQ. ZERO) THEN
          IF (MM.LE.MBIG)   &
            P = DLNGAM(DBLE(NN+1)) - DLNGAM(DBLE(MM+1)) +   &
            DLNGAM(DBLE(KK+1)) + DLNGAM(DBLE(MM-NN+1)) -   &
            DLNGAM(DBLE(LL+1)) - DLNGAM(DBLE(NN-LL+1)) -   &
            DLNGAM(DBLE(KK-LL+1)) - DLNGAM(DBLE(MM-NN-KK+LL+1)) +   &
            DLNGAM(DBLE(MM-KK+1))
          P = P + DLOG(SCALE)
          IF (P .LT. ELIMIT) THEN
            WRITE(ICOUT,51)
   51       FORMAT('***** WARNING--UNDERFLOW DETECTED.  RESULT MAY ',   &
                   'BE IN ERROR.')
            CALL DPWRST('XXX','BUG ')
            IF (LL .GT. DBLE(NN*KK + NN + KK +1)/(MM +2)) DCDF = ONE
            GO TO 9999
          ELSE
            P = DEXP(P)
          END IF
        ELSE
!
!     Scale up at this point.
!
          P = DCDF * SCALE
        END IF
!
        PT = ZERO
        NL = N - L
        KL = K - L
        MNKL = M - N - KL + 1
        IF (L .LE. KL) THEN
          DO 7 I = 1, L-1
            P = P * DBLE(L-I) * DBLE(MNKL-I) /(DBLE(NL+I) * DBLE(KL+I))
            PT = PT + P
    7     CONTINUE
          IF (P .EQ. ZERO) THEN
            WRITE(ICOUT,51)
            CALL DPWRST('XXX','BUG ')
          ENDIF
        ELSE
          DIR = .NOT. DIR
          DO 9 J = 0, KL-1
            P=P*DBLE(NL-J)*DBLE(KL-J)/(DBLE(L+J)*DBLE(MNKL+J))
            PT = PT + P
    9     CONTINUE
          IF (P .EQ. ZERO) THEN
            WRITE(ICOUT,51)
            CALL DPWRST('XXX','BUG ')
          ENDIF
        END IF
!
        IF (DIR) THEN
          DCDF = DCDF + (PT / SCALE)
        ELSE
          DCDF = ONE - (PT / SCALE)
        END IF
!
      END IF
!
 9999 CONTINUE
      CDF=SNGL(DCDF)
 9000 CONTINUE
      RETURN
      END SUBROUTINE HYPCDF
      SUBROUTINE HYPPPF(P,K,N,M,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE AT THE SINGLE PRECISION VALUE P
!              FOR THE HYPERGEOMETRIC DISTRIBUTION
!              THE HYPERGEOMETRIC DISTRIBUTION IS THE PROBABILITY OF
!              SELECTING LL MARKED ITEMS WHEN A RANDOM SAMPLE OF SIZE
!              KK IS TAKEN WITHOUT REPLACEMENT FROM A POPULATION OF
!              MM ITEMS, NN OF WHICH ARE MARKED.  IT HAS CDF OF:
!                 CDF = P(X<= LL | KK, NN, MM)
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                                IT SHOULD BE IN THE INTERVAL (0,1).
!                     --KK     = THE INTEGER VALUE INDICATING THE
!                                SAMPLE SIZE.
!                     --NN     = THE NUMBER OF MARKED ITEMS IN THE
!                                POPULATION.
!                     --MM     = THE POPULATION SIZE.
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--P SHOULD BE BETWEEN 0 and 1 (INCLUSIVELY).
!                 --KK SHOULD BE A POSITIVE INTEGER BETWEEN 1 AND MM.
!                 --NN SHOULD BE A POSITIVE INTEGER BETWEEN 1 AND MM.
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION PERCENT
!                                POINT FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT  .
!             FUNCTION VALUE PPF
!             FOR THE HYPERGEOMETRIC DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--PPAR SHOULD BE BETWEEN 0.0 (EXCLUSIVELY)
!                   AND 1.0 (EXCLUSIVELY).
!                 --N SHOULD BE A POSITIVE INTEGER.
!                 --P SHOULD BE BETWEEN 0.0 (INCLUSIVELY)
!                   AND 1.0 (INCLUSIVELY).
!     OTHER DATAPAC   SUBROUTINES NEEDED--NORPPF, HYPCDF.
!     MODE OF INTERNAL OPERATIONS--SINGLE AND DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     COMMENT--NOTE THAT EVEN THOUGH THE OUTPUT
!              FROM THIS DISCRETE DISTRIBUTION
!              PERCENT POINT FUNCTION
!              SUBROUTINE MUST NECESSARILY BE A
!              DISCRETE INTEGER VALUE,
!              THE OUTPUT VARIABLE PPF IS SINGLE
!              PRECISION IN MODE.
!              PPF HAS BEEN SPECIFIED AS SINGLE
!              PRECISION SO AS TO CONFORM WITH THE DATAPAC
!              CONVENTION THAT ALL OUTPUT VARIABLES FROM ALL
!              DATAPAC SUBROUTINES ARE SINGLE PRECISION.
!              THIS CONVENTION IS BASED ON THE BELIEF THAT
!              1) A MIXTURE OF MODES (FLOATING POINT
!              VERSUS INTEGER) IS INCONSISTENT AND
!              AN UNNECESSARY COMPLICATION
!              IN A DATA ANALYSIS; AND
!              2) FLOATING POINT MACHINE ARITHMETIC
!              (AS OPPOSED TO INTEGER ARITHMETIC)
!              IS THE MORE NATURAL MODE FOR DOING
!              DATA ANALYSIS.
!     REFERENCES--JOHNSON AND KOTZ, DISCRETE
!                 DISTRIBUTIONS, 1969.
!               --HASTINGS AND PEACOCK, STATISTICAL
!                 DISTRIBUTIONS--A HANDBOOK FOR
!                 STUDENTS AND PRACTITIONERS, 1975,
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--94/9
!     ORIGINAL VERSION--SEPTEMBER 1994.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      LOGICAL POINT
!
      DOUBLE PRECISION DPPF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PPF=0.0
      IF(P.LT.0.0.OR.P.GT.1.0)THEN
        WRITE(ICOUT,1)
    1   FORMAT('***** ERROR--THE FIRST ARGUMENT TO HYPPPF ',   &
               'IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(N.LE.0.OR.N.GT.M)THEN
        WRITE(ICOUT,11)
   11   FORMAT('***** ERROR--THE THIRD ARGUMENT TO HYPPPF ',   &
               '(THE NUMBER OF MARKED ITEMS)')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,12)
   12   FORMAT('      IS LESS THAN ZERO OR GREATER THAN THE ',   &
               'POPULATION SIZE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(K.LE.0.OR.K.GT.M)THEN
        WRITE(ICOUT,21)
   21   FORMAT('***** ERROR--THE SECOND ARGUMENT TO HYPPPF ',   &
               '(THE SAMPLE SIZE) ')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,22)
   22   FORMAT('      IS LESS THAN ZERO OR GREATER THAN THE ',   &
               'POULATION SIZE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)K
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,'.')
!
      PPF=0.0
      IX0=0
      IX1=0
      IX2=0
      P0=0.0
      P1=0.0
      P2=0.0
!
!     TREAT CERTAIN SPECIAL CASES IMMEDIATELY--
!     1) P = 0.0 OR 1.0
!
      IF(P.EQ.0.0)GO TO 110
      IF(P.EQ.1.0)GO TO 120
      GO TO 190
  110 PPF=0.0
      RETURN
  120 PPF=REAL(MIN(N,K))
      RETURN
  190 CONTINUE
!
!     DETERMINE AN INITIAL APPROXIMATION TO THE HYPERGEOMETRIC
!     PERCENT POINT BY USE OF THE BINOMIAL APPROXIMATION
!     TO THE HYPERGEOMETRIC.
!
      PPAR=REAL(N)/REAL(M)
      IF(PPAR.LT.0.0.OR.PPAR.GT.1.0)PPAR=0.5
      CALL BINPPF(DBLE(P),DBLE(PPAR),K,DPPF)
      IX2=INT(DPPF)
!
!     CHECK AND MODIFY (IF NECESSARY) THIS INITIAL
!     ESTIMATE OF THE PERCENT POINT
!     TO ASSURE THAT IT BE IN THE CLOSED INTERVAL 0 TO MIN(N,K).
!
      ITERM=MIN(N,K)
      IF(IX2.LT.0)IX2=0
      IF(IX2.GT.ITERM)IX2=ITERM
!
!     DETERMINE UPPER AND LOWER BOUNDS ON THE DESIRED
!     PERCENT POINT BY ITERATING OUT (BOTH BELOW AND ABOVE)
!     FROM THE ORIGINAL APPROXIMATION AT STEPS
!     OF 1 STANDARD DEVIATION.
!     THE RESULTING BOUNDS WILL BE AT MOST
!     1 STANDARD DEVIATION APART.
!
      IX0=0
      IX1=N
      SD=(REAL(M-K)/REAL(M-1))*REAL(K)*(REAL(N)/REAL(M))*   &
      (1.0-REAL(N)/REAL(M))
      ISD=INT(SD+1.0)
      POINT=.FALSE.
      CALL HYPCDF(IX2,K,N,M,POINT,P2)
!
      IF(P2.LT.P)GO TO 210
      GO TO 250
!
  210 CONTINUE
      IX0=IX2
      I=1
  215 CONTINUE
      IX2=IX0+ISD
      IF(IX2.GE.IX1)GO TO 275
      CALL HYPCDF(IX2,K,N,M,POINT,P2)
      IF(P2.GE.P)GO TO 230
      IX0=IX2
      I=I+1
      IF(I.LE.1000000)GO TO 215
      WRITE(ICOUT,249)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,222)
      CALL DPWRST('XXX','BUG ')
      GO TO 950
  230 CONTINUE
      IX1=IX2
      GO TO 275
!
  250 CONTINUE
      IX1=IX2
      I=1
  255 CONTINUE
      IX2=IX1-ISD
      IF(IX2.LE.IX0)GO TO 275
      CALL HYPCDF(IX2,K,N,M,POINT,P2)
      IF(P2.LT.P)GO TO 270
      IX1=IX2
!
      I=I+1
      IF(I.LE.1000000)GO TO 255
      WRITE(ICOUT,249)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,262)
      CALL DPWRST('XXX','BUG ')
      GO TO 950
  270 CONTINUE
      IX0=IX2
!
  275 CONTINUE
      IF(IX0.EQ.IX1)GO TO 280
      GO TO 295
  280 CONTINUE
      IF(IX0.EQ.0)GO TO 285
      IF(IX0.EQ.N)GO TO 290
      WRITE(ICOUT,249)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,282)
      CALL DPWRST('XXX','BUG ')
      GO TO 950
  285 CONTINUE
      IX1=IX1+1
      GO TO 295
  290 CONTINUE
      IX0=IX0-1
  295 CONTINUE
!
!     COMPUTE HYPERGEOMETRIC PROBABILITIES FOR THE
!     DERIVED LOWER AND UPPER BOUNDS.
!
      CALL HYPCDF(IX0,K,N,M,POINT,P0)
      CALL HYPCDF(IX1,K,N,M,POINT,P1)
!
!     CHECK THE PROBABILITIES FOR PROPER ORDERING
!
      IF(P0.LT.P.AND.P.LE.P1)GO TO 490
      IF(P0.EQ.P)GO TO 410
      IF(P1.EQ.P)GO TO 420
      IF(P0.GT.P1)GO TO 430
      IF(P0.GT.P)GO TO 440
      IF(P1.LT.P)GO TO 450
      WRITE(ICOUT,249)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,401)
      CALL DPWRST('XXX','BUG ')
      GO TO 950
  410 CONTINUE
      PPF=IX0
      RETURN
  420 CONTINUE
      PPF=IX1
      RETURN
  430 CONTINUE
      WRITE(ICOUT,249)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,431)
      CALL DPWRST('XXX','BUG ')
      GO TO 950
  440 CONTINUE
      WRITE(ICOUT,249)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,441)
      CALL DPWRST('XXX','BUG ')
      GO TO 950
  450 CONTINUE
      WRITE(ICOUT,249)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,451)
      CALL DPWRST('XXX','BUG ')
      GO TO 950
  490 CONTINUE
!
!     THE STOPPING CRITERION IS THAT THE LOWER BOUND
!     AND UPPER BOUND ARE EXACTLY 1 UNIT APART.
!     CHECK TO SEE IF IX1 = IX0 + 1;
!     IF SO, THE ITERATIONS ARE COMPLETE;
!     IF NOT, THEN BISECT, COMPUTE PROBABILIIES,
!     CHECK PROBABILITIES, AND CONTINUE ITERATING
!     UNTIL IX1 = IX0 + 1.
!
  300 CONTINUE
      IX0P1=IX0+1
      IF(IX1.EQ.IX0P1)GO TO 690
      IX2=(IX0+IX1)/2
      IF(IX2.EQ.IX0)GO TO 610
      IF(IX2.EQ.IX1)GO TO 620
      CALL HYPCDF(IX2,K,N,M,POINT,P2)
      IF(P0.LT.P2.AND.P2.LT.P1)GO TO 630
      IF(P2.LE.P0)GO TO 640
      IF(P2.GE.P1)GO TO 650
  610 WRITE(ICOUT,249)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,611)
      CALL DPWRST('XXX','BUG ')
      GO TO 950
  620 WRITE(ICOUT,249)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,611)
      CALL DPWRST('XXX','BUG ')
      GO TO 950
  630 CONTINUE
      IF(P2.LE.P)GO TO 635
      IX1=IX2
      P1=P2
      GO TO 300
  635 CONTINUE
      IX0=IX2
      P0=P2
      GO TO 300
  640 CONTINUE
      WRITE(ICOUT,249)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,641)
      CALL DPWRST('XXX','BUG ')
      GO TO 950
  650 CONTINUE
      WRITE(ICOUT,249)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,651)
      CALL DPWRST('XXX','BUG ')
      GO TO 950
  690 CONTINUE
      PPF=IX1
      IF(P0.EQ.P)PPF=IX0
      RETURN
!
  950 CONTINUE
      WRITE(ICOUT,240)IX0,P0
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,241)IX1,P1
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,242)IX2,P2
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,244)P
      CALL DPWRST('XXX','BUG ')
!
  222 FORMAT('NO UPPER BOUND FOUND AFTER 10**7 ITERATIONS')
  240 FORMAT('IX0  = ',I8,10X,'P0 = ',F14.7)
  241 FORMAT('IX1  = ',I8,10X,'P1 = ',F14.7)
  242 FORMAT('IX2  = ',I8,10X,'P2 = ',F14.7)
  244 FORMAT('P    = ',F14.7)
  249 FORMAT('***** INTERNAL ERROR IN HYPPPF SUBROUTINE *****')
  262 FORMAT('NO LOWER BOUND FOUND AFTER 10**7 ITERATIONS')
  282 FORMAT('LOWER AND UPPER BOUND IDENTICAL')
  401 FORMAT('IMPOSSIBLE BRANCH CONDITION ENCOUNTERED')
  431 FORMAT('LOWER BOUND PROBABILITY (P0) GREATER THAN ',   &
             'UPPER BOUND PROBABILITY (P1)')
  441 FORMAT('LOWER BOUND PROBABILITY (P0) GREATER THAN ',   &
             'INPUT PROBABILITY (P)')
  451 FORMAT('UPPER BOUND PROBABILITY (P1) LESS    THAN ',   &
             'INPUT PROBABILITY (P)')
  611 FORMAT('BISECTION VALUE (X2) = LOWER BOUND (X0)')
!C621 FORMAT('BISECTION VALUE (X2) = UPPER BOUND (X1)')
  641 FORMAT('BISECTION VALUE PROBABILITY (P2) ',   &
             'LESS THAN LOWER BOUND PROBABILITY (P0)')
  651 FORMAT('BISECTION VALUE PROBABILITY (P2) ',   &
             'GREATER THAN UPPER BOUND PROBABILITY (P1)')
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE HYPPPF
      SUBROUTINE HYPRAN(KK,NN1,NN2,ISEED,JX)
!CCCC SUBROUTINE H2PEC(KK,NN1,NN2,ISEED,JX)
!
!      ALGORITHM 668, COLLECTED ALGORITHMS FROM ACM.
!      THIS WORK PUBLISHED IN TRANSACTIONS ON MATHEMATICAL SOFTWARE,
!      VOL. 14, NO. 4, PP. 397-398.
!
!
!     HYPERGEOMETRIC RANDOM VARIATE GENERATOR
!
!     METHOD
!        IF (MODE - MAX(0,KK-NN2) .LT. 10), USE THE INVERSE CDF.
!           OTHERWISE, USE ALGORITHM H2PE: ACCEPTANCE-REJECTION VIA
!           THREE REGION COMPOSITION.  THE THREE REGIONS ARE A
!           RECTANGLE, AND EXPONENTIAL LEFT AND RIGHT TAILS.
!        H2PE  REFERS TO HYPERGEOMETRIC-2 POINTS-EXPONENTIAL TAILS.
!        H2PEC REFERS TO H2PE AND "COMBINED."  THUS H2PE IS THE
!           RESEARCH RESULT AND H2PEC IS THE IMPLEMENTATION OF A
!           COMPLETE USABLE ALGORITHM.
!
!     REFERENCE
!        VORATAS KACHITVICHYANUKUL AND BRUCE SCHMEISER,
!
!        "COMPUTER GENERATION OF HYPERGEOMETRIC RANDOM VARIATES,"
!        JOURNAL OF STATISTICAL COMPUTATION AND SIMULATION,
!        22(1985), 2, 1985, 127-145.
!
!     REQUIRED SUBPROGRAMS
!        AFC() : A DOUBLE-PRECISION FUNCTION TO EVALUATE
!                   THE LOGARITHM OF THE FACTORIAL.
!        RAND(): A UNIFORM (0,1) RANDOM NUMBER GENERATOR.
!
!     ARGUMENTS
!        NN1   : NUMBER OF WHITE BALLS          (INPUT)
!        NN2   : NUMBER OF BLACK BALLS          (INPUT)
!        KK    : NUMBER OF BALLS TO BE DRAWN    (INPUT)
!        ISEED : RANDOM NUMBER SEED  (INPUT AND OUTPUT)
!        JX    : NUMBER OF WHITE BALLS DRAWN   (OUTPUT)
!
!     STRUCTURAL VARIABLES
!        REJECT: LOGICAL FLAG TO REJECT THE VARIATE GENERATE BY H2PE.
!        SETUP1: LOGICAL FLAG TO SETUP FOR NEW VALUES OF NN1 OR NN2.
!        SETUP2: LOGICAL FLAG TO SETUP FOR NEW VALUES OF KK.
!        IX    : INTEGER CANDIDATE VALUE.
!        M     : DISTRIBUTION MODE.
!        MINJX : DISTRIBUTION LOWER BOUND.
!        MAXJX : DISTRIBUTION UPPER BOUND.
!        KS    : SAVED VALUE OF KK FROM THE LAST CALL TO H2PEC.
!        N1S   : SAVED VALUE OF NN1 FROM THE LAST CALL TO H2PEC.
!        N2S   : SAVED VALUE OF NN2 FROM THE LAST CALL TO H2PEC.
!        K,N1,N2: ALTERNATE VARIABLES FOR KK, NN1, AND NN2
!                   (ALWAYS (N1 .LE. N2) AND (K .LE. (N1+N2)/2)).
!        TN    : TOTAL NUMBER OF WHITE AND BLACK BALLS
!
!     INVERSE-TRANSFORMATION VARIABLES
!        CON   : NATURAL LOGARITHM  OF SCALE.
!        P     : CURRENT SCALED PROBABILITY FOR THE INVERSE CDF.
!        SCALE : A BIG CONSTANT (1.E25) USED TO SCALE THE
!                   PROBABILITY TO AVOID NUMERICAL UNDERFLOW
!        U     : THE UNIFORM VARIATE BETWEEN (0, 1.E25).
!        W     : SCALED HYPERGEOMETRIC PROBABILITY OF MINJX.
!
!     H2PE VARIABLES
!        S     : DISTRIBUTION STANDARD DEVIATION.
!        D     : HALF THE AREA OF THE RECTANGLE.
!        XL    : LEFT END OF THE RECTANGLE.
!        XR    : RIGHT END OF THE RECTANGLE.
!        A     : A SCALING CONSTANT.
!        KL    : HIGHEST POINT OF THE LEFT-TAIL REGION.
!        KR    : HIGHEST POINT OF THE RIGHT-TAIL REGION.
!        LAMDL : RATE FOR THE LEFT EXPONENTIAL TAIL.
!        LAMDR : RATE FOR THE RIGHT EXPONENTIAL TAIL.
!        P1    : AREA OF THE RECTANGLE.
!        P2    : AREA OF THE LEFT EXPONENTIAL TAIL PLUS P1.
!        P3    : AREA OF THE RIGHT EXPONENTIAL TAIL PLUS P2.
!        U     : A UNIFORM (0,P3) RANDOM VARIATE USED FIRST TO SELECT
!                   ONE OF THE THREE REGIONS AND THEN CONDITIONALLY TO
!                   GENERATE A VALUE FROM THE REGION.
!        V     : U(0,1) RANDOM NUMBER USED TO GENERATE THE RANDOM
!                   VALUE OR TO ACCEPT OR REJECT THE CANDIDATE VALUE.
!        F     : THE HEIGHT OF THE SCALED DENSITY FUNCTION USED IN THE
!                   ACCEPT/REJECT DECISION WHEN BOTH M AND IX ARE SMALL.
!        I     : INDEX FOR EXPLICIT CALCULATION OF F FOR H2PE.
!
!   THE FOLLOWING VARIABLES ARE TEMPORARY VARIABLES USED IN
!   COMPUTING THE UPPER AND LOWER BOUNDS OF THE NATURAL LOGARITHM
!   OF THE SCALED DENSITY.  THE DETAILED DESCRIPTION IS GIVEN IN
!   PROPOSITIONS 2 AND 3 OF THE APPENDIX IN THE REFERENCE.
!              Y, Y1, YM, YN, YK, NK, R, S, T, E, G, DG, GU, GL, XM,
!              XN, XK, NM
!
!        Y     : PRELIMINARY CONTINUOUS CANDIDATE VALUE, FLOAT(IX)
!        UB    : UPPER BOUND FOR THE NATURAL LOGARITHM OF THE SCALED
!                   DENSITY.
!        ALV   : NATURAL LOGARITHM OF THE ACCEPT/REJECT VARIATE V.
!        DR, DS, DT, DE: ONE OF MANY TERMS SUBTRACTED FROM THE UPPER
!                   BOUND TO OBTAIN THE LOWER BOUND ON THE NATURAL
!                   LOGARITHM OF THE SCALED DENSITY.
!        DELTAU: A CONSTANT, THE VALUE 0.0034 IS OBTAINED BY SETTING
!                   N1 = N2 = 200, K = 199, M = 100, AND Y = 50 IN
!                   THE FUNCTION DELTA_U IN LEMMA 1 AND ROUNDING THE
!                   VALUE TO FOUR DECIMAL PLACES.
!        DELTAL: A CONSTANT, THE VALUE 0.0078 IS OBTAINED BY SETTING
!                   N1 = N2 = 200, K = 199, M = 100, AND Y = 50 IN
!                   THE FUNCTION DELTA_L IN LEMMA 1 AND ROUNDING THE
!                   VALUE TO FOUR DECIMAL PLACES.
!
      SAVE
!CCCC SEPTEMBER 1995.  USE DLNGAM FUNCTION IN PLACE OF AFC
!CCCC DOUBLE PRECISION AFC,CON,P,SCALE,U,W,A,XL,XR
      DOUBLE PRECISION DLNGAM,CON,P,SCALE,U,W,A,XL,XR
      REAL KL,KR,LAMDL,LAMDR,NK,NM
!CCCC AUGUST 1995.  ADD FOLLOWING ARRAY FOR DATAPLOT
!CCCC UNIFORM RANDOM NUMBER GENERATOR.
      REAL XTEMP(1)
!
      LOGICAL REJECT,SETUP1,SETUP2
      DATA KS,N1S,N2S/-1,-1,-1/
      DATA CON,DELTAL,DELTAU,SCALE/57.56462733D0,0.0078,0.0034,1.D25/
!
!*****CHECK PARAMETER VALIDITY
!
      IF (  (NN1 .LT. 0)  .OR.   &
            (NN2 .LT. 0)  .OR.   &
            (KK  .LT. 0)  .OR.   &
            (KK  .GT. NN1 + NN2 )  ) THEN
         JX     = -1
         RETURN
      ENDIF
!
!*****IF NEW PARAMETER VALUES, INITIALIZE
!
      REJECT = .TRUE.
      SETUP1 = .FALSE.
      SETUP2 = .FALSE.
      IF ((NN1 .NE. N1S) .OR. (NN2 .NE. N2S))  THEN
            SETUP1 = .TRUE.
            SETUP2 = .TRUE.
      ELSEIF (KK .NE. KS)  THEN
            SETUP2 = .TRUE.
      ENDIF
!
      IF (SETUP1)  THEN
         N1S   = NN1
         N2S   = NN2
         TN    = REAL(NN1 + NN2)
         IF (NN1 .LE. NN2)  THEN
            N1 = NN1
            N2 = NN2
         ELSE
            N1 = NN2
            N2 = NN1
         ENDIF
      ENDIF
!
      IF (SETUP2)  THEN
         KS    = KK
         IF (KK+KK .GE. INT(TN+0.1))  THEN
            K  = INT(TN - REAL(KK))
         ELSE
            K  = KK
         ENDIF
      ENDIF
!
      IF (SETUP1 .OR. SETUP2)  THEN
         M     = INT ((K+1.) * (N1+1.) / (TN+2.))
         MINJX = MAX (0, K-N2)
         MAXJX = MIN (N1, K)
      ENDIF
!
!*****GENERATE RANDOM VARIATE
!
      IF (MINJX .EQ. MAXJX)  THEN
!
!        ...DEGENERATE DISTRIBUTION...
!
         IX      = MAXJX
         RETURN
      ELSEIF (M-MINJX .LT. 10)  THEN
!
!        ...INVERSE TRANSFORMATION...
!
         IF (SETUP1 .OR. SETUP2)  THEN
            IF (K .LT. N2) THEN
!CCCC SEPTEMBER 1995.  USE DLNGAM INSTEAD OF AFC
!CCCC          W = EXP (CON + AFC(N2) + AFC(N1+N2-K)
!CCCC$                       - AFC(N2-K) - AFC(N1+N2))
               W = EXP (CON + DLNGAM(DBLE(N2+1))+DLNGAM(DBLE(N1+N2-K+1))   &
                       - DLNGAM(DBLE(N2-K+1)) - DLNGAM(DBLE(N1+N2+1)))
            ELSE
!CCCC SEPTEMBER 1995.  USE DLNGAM INSTEAD OF AFC
!CCCC          W = EXP (CON + AFC(N1) + AFC(K)
!CCCC$                       - AFC(K-N2) - AFC(N1+N2))
               W = EXP (CON + DLNGAM(DBLE(N1+1)) + DLNGAM(DBLE(K+1))   &
                       - DLNGAM(DBLE(K-N2+1)) - DLNGAM(DBLE(N1+N2+1)))
            ENDIF
         ENDIF
!
   10    P  = W
         IX = MINJX
!CCCC SEPTEMBER 1995.  REPLACE RAND WITH DATAPLOT UNIFORM RANDOM
!CCCC NUMBER GENERATOR.
         NTEMP=1
         CALL UNIRAN(NTEMP,ISEED,XTEMP)
         U = XTEMP(1)*SCALE
!CCCCC   U  = RANDDP (ISEED) * SCALE
   20    IF (U .GT. P)  THEN
            U  = U - P
            P  = P * (N1-IX)*(K-IX)
            IX = IX + 1
            P  = P / IX / (N2-K+IX)
            IF (IX .GT. MAXJX)  GO TO 10
            GO TO 20
         ENDIF
      ELSE
!
!        ...H2PE...
!
         IF (SETUP1 .OR. SETUP2)  THEN
            S     = SQRT ((TN-K) * K * N1 * N2 / (TN-1) / TN /TN)
!
!           ...REMARK:  D IS DEFINED IN REFERENCE WITHOUT INT.
!           THE TRUNCATION CENTERS THE CELL BOUNDARIES AT 0.5
!
            D     = INT (1.5*S) + .5
            XL    = M - D + .5
            XR    = M + D + .5
!CCCC SEPTEMBER 1995.  USE DLNGAM INSTEAD OF AFC
!CCCC       A     = AFC(M) + AFC(N1-M) + AFC(K-M) + AFC(N2-K+M)
!CCCC       KL    = EXP (A - AFC(INT(XL)) - AFC(INT(N1-XL))
!CCCC$                  - AFC(INT(K-XL)) - AFC(INT(N2-K+XL)))
!CCCC       KR    = EXP (A - AFC(INT(XR-1)) - AFC(INT(N1-XR+1))
!CCCC$                  - AFC(INT(K-XR+1)) - AFC(INT(N2-K+XR-1)))
            A     = DLNGAM(DBLE(M+1)) + DLNGAM(DBLE(N1-M+1)) +   &
                    DLNGAM(DBLE(K-M+1)) + DLNGAM(DBLE(N2-K+M+1))
            KL    = EXP (A - DLNGAM(DBLE(INT(XL)+1)) -   &
                    DLNGAM(DBLE(INT(N1-XL)+1))   &
                    - DLNGAM(DBLE(INT(K-XL)+1)) -   &
                    DLNGAM(DBLE(INT(N2-K+XL)+1)))
            KR    = EXP(A-DLNGAM(DBLE(INT(XR-1)+1)) -   &
                    DLNGAM(DBLE(INT(N1-XR+1)+1))   &
                    - DLNGAM(DBLE(INT(K-XR+1)+1)) -   &
                    DLNGAM(DBLE(INT(N2-K+XR-1)+1)))
            LAMDL = -LOG (XL * (N2-K+XL) / (N1-XL+1) / (K-XL+1))
            LAMDR = -LOG ((N1-XR+1) * (K-XR+1) / XR / (N2-K+XR))
            P1    = D + D
            P2    = P1 + KL / LAMDL
            P3    = P2 + KR / LAMDR
         ENDIF
!
 30      CONTINUE
!CCCC AUGUST 1995.  REPLACE RAND WITH DATAPLOT UNIFORM RANDOM
!CCCC NUMBER GENERATOR.
         NTEMP=1
         CALL UNIRAN(NTEMP,ISEED,XTEMP)
         U = XTEMP(1) * P3
         CALL UNIRAN(NTEMP,ISEED,XTEMP)
         V = XTEMP(1)
!CC30    U     = RANDDP (ISEED) * P3
!CCCC    V     = RANDDP (ISEED)
         IF (U .LT. P1)  THEN
!
!           ...RECTANGULAR REGION...
!
            IX    = INT(XL + U)
         ELSEIF (U .LE. P2)  THEN
!
!           ...LEFT TAIL...
!
            IX    = INT(XL + LOG(V)/LAMDL)
            IF (IX .LT. MINJX)  GO TO 30
            V     = V * (U-P1) * LAMDL
         ELSE
!
!           ...RIGHT TAIL...
!
            IX    = INT(XR - LOG(V)/LAMDR)
            IF (IX .GT. MAXJX)  GO TO 30
            V     = V * (U-P2) * LAMDR
         ENDIF
!
!        ...ACCEPTANCE/REJECTION TEST...
!
         IF (M .LT. 100 .OR. IX .LE. 50)  THEN
!
!           ...EXPLICIT EVALUATION...
!
            F     = 1.0
            IF (M .LT. IX)  THEN
               DO 40 I = M+1,IX
                  F      = F * (N1-I+1) * (K-I+1) / (N2-K+I) / I
   40          CONTINUE
            ELSEIF (M .GT. IX)  THEN
               DO 50 I = IX+1,M
                  F      = F * I * (N2-K+I) / (N1-I) / (K-I)
   50          CONTINUE
            ENDIF
            IF (V .LE. F)  THEN
               REJECT = .FALSE.
            ENDIF
         ELSE
!
!        ...SQUEEZE USING UPPER AND LOWER BOUNDS...
!
            Y   = IX
            Y1  = Y + 1.
            YM  = Y - M
            YN  = N1 - Y + 1.
            YK  = K - Y + 1.
            NK  = N2 - K + Y1
            R   = -YM / Y1
            S   = YM / YN
            T   = YM / YK
            E   = -YM / NK
            G   = YN * YK / (Y1*NK) - 1.
            DG  = 1.
            IF (G .LT. 0.)  DG = 1.+G
            GU  = G * (1.+G*(-.5+G/3.))
            GL  = GU - .25 * (G*G)**2 / DG
            XM  = M + .5
            XN  = N1 - M + .5
            XK  = K - M + .5
            NM  = N2 - K + XM
            UB  = Y * GU - M * GL + DELTAU   &
                    + XM * R * (1.+R*(-.5+R/3.))   &
                    + XN * S * (1.+S*(-.5+S/3.))   &
                    + XK * T * (1.+T*(-.5+T/3.))   &
                    + NM * E * (1.+E*(-.5+E/3.))
!
!           ...TEST AGAINST UPPER BOUND...
!
            ALV = LOG(V)
            IF (ALV .GT. UB)  THEN
               REJECT = .TRUE.
            ELSE
!
!              ...TEST AGAINST LOWER BOUND...
!
               DR = XM * (R*R)**2
               IF (R .LT. 0.)  DR = DR / (1.+R)
               DS = XN * (S*S)**2
               IF (S .LT. 0.)  DS = DS / (1.+S)
               DT = XK * (T*T)**2
               IF (T .LT. 0.)  DT = DT / (1.+T)
               DE = NM * (E*E)**2
               IF (E .LT. 0.)  DE = DE / (1.+E)
               IF (ALV .LT. UB-.25*(DR+DS+DT+DE)   &
                               +(Y+M)*(GL-GU)-DELTAL)  THEN
                  REJECT = .FALSE.
               ELSE
!
!                 ...STIRLING'S FORMULA TO MACHINE ACCURACY...
!
!CCCC SEPTEMBER 1995.  USE DLNGAM INSTEAD OF AFC
!CCCC             IF (ALV .LE. (A - AFC(IX) - AFC(N1-IX)
!CCCC$                       - AFC(K-IX) - AFC(N2-K+IX)) )  THEN
                  IF (ALV .LE.(A-DLNGAM(DBLE(IX+1)) -   &
                              DLNGAM(DBLE(N1-IX+1))   &
                              - DLNGAM(DBLE(K-IX+1))   &
                              - DLNGAM(DBLE(N2-K+IX+1))))   &
                  THEN
                     REJECT = .FALSE.
                  ELSE
                     REJECT = .TRUE.
                  ENDIF
               ENDIF
            ENDIF
         ENDIF
         IF (REJECT)  GO TO 30
      ENDIF
                                                                                                                                  
!
!*****RETURN APPROPRIATE VARIATE
!
      IF (KK + KK .GE. TN)  THEN
         IF (NN1 .GT. NN2)  THEN
            IX = KK - NN2 + IX
         ELSE
            IX =  NN1 - IX
         ENDIF
      ELSE
         IF (NN1 .GT. NN2)  IX = KK - IX
      ENDIF
      JX = IX
      RETURN
      END SUBROUTINE HYPRAN
      DOUBLE PRECISION FUNCTION I0INT(XVALUE)
!
!   DESCRIPTION:
!      This program computes the integral of the modified Bessel
!      function I0(x) using the definition
!
!         I0INT(x) = {integral 0 to x} I0(t) dt
!
!      The program uses Chebyshev expansions, the coefficients of
!      which are given to 20 decimal places.
!
!
!   ERROR RETURNS:
!      If |XVALUE| larger than a certain limit, the value of
!      I0INT would cause an overflow. If such a situation occurs
!      the programs prints an error message, and returns the
!      value sign(XVALUE)*XMAX, where XMAX is the largest
!      acceptable floating-pt. value.
!
!
!   MACHINE-DEPENDENT CONSTANTS:
!
!      NTERM1 - The no. of terms to be used from the array ARI01.
!                The recommended value is such that
!                    ABS(ARI01(NTERM1)) < EPS/100
!
!      NTERM2 - The no. of terms to be used from the array ARI0A.
!                The recommended value is such that
!                    ABS(ARI0A(NTERM2)) < EPS/100
!
!      XLOW - The value below which I0INT(x) = x, to machine precision.
!             The recommended value is
!                  sqrt(12*EPS).
!
!      XHIGH - The value above which overflow will occur. The
!              recommended value is
!                  ln(XMAX) + 0.5*ln(ln(XMAX)) + ln(2).
!
!      For values of EPS and XMAX refer to the file MACHCON.TXT.
!
!      The machine-dependent constants are computed internally by
!      using the D1MACH subroutine.
!
!
!   INTRINSIC FUNCTIONS USED:
!
!      EXP , LOG , SQRT
!
!
!   OTHER MISCFUN SUBROUTINES USED:
!
!          CHEVAL , ERRPRN, D1MACH
!
!
!   AUTHOR:
!
!      Dr. Allan J. MacLeod,
!      Dept. of Mathematics and Statistics,
!      University of Paisley,
!      High St.,
!      Paisley,
!      SCOTLAND
!      PA1 2BE
!
!      (e-mail :   macl_ms0@paisley.ac.uk )
!
!
!   LATEST REVISION:
!                   23 January, 1996
!
      INTEGER IND,NTERM1,NTERM2
      DOUBLE PRECISION ARI01(0:28),ARI0A(0:33),   &
           ATEEN,CHEVAL,HALF,LNR2PI,ONEHUN,T,TEMP,THREE,THIRT6,   &
           X,XHIGH,XLOW,XVALUE,ZERO
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
!CCCC CHARACTER FNNAME*6,ERRMSG*26
!CCCC DATA FNNAME/'I0INT '/
!CCCC DATA ERRMSG/'SIZE OF ARGUMENT TOO LARGE'/
      DATA ZERO,HALF,THREE/ 0.0D0,0.5D0,3.0D0 /
      DATA ATEEN,THIRT6,ONEHUN/ 18.0D0,36.0D0,100.0D0/
      DATA LNR2PI/0.91893853320467274178D0/
      DATA ARI01(0)/  0.41227906926781516801D0/
      DATA ARI01(1)/ -0.34336345150081519562D0/
      DATA ARI01(2)/  0.22667588715751242585D0/
      DATA ARI01(3)/ -0.12608164718742260032D0/
      DATA ARI01(4)/  0.6012484628777990271D-1/
      DATA ARI01(5)/ -0.2480120462913358248D-1/
      DATA ARI01(6)/  0.892773389565563897D-2/
      DATA ARI01(7)/ -0.283253729936696605D-2/
      DATA ARI01(8)/  0.79891339041712994D-3/
      DATA ARI01(9)/ -0.20053933660964890D-3/
      DATA ARI01(10)/ 0.4416816783014313D-4/
      DATA ARI01(11)/-0.822377042246068D-5/
      DATA ARI01(12)/ 0.120059794219015D-5/
      DATA ARI01(13)/-0.11350865004889D-6/
      DATA ARI01(14)/ 0.69606014466D-9/
      DATA ARI01(15)/ 0.180622772836D-8/
      DATA ARI01(16)/-0.26039481370D-9/
      DATA ARI01(17)/-0.166188103D-11/
      DATA ARI01(18)/ 0.510500232D-11/
      DATA ARI01(19)/-0.41515879D-12/
      DATA ARI01(20)/-0.7368138D-13/
      DATA ARI01(21)/ 0.1279323D-13/
      DATA ARI01(22)/ 0.103247D-14/
      DATA ARI01(23)/-0.30379D-15/
      DATA ARI01(24)/-0.1789D-16/
      DATA ARI01(25)/ 0.673D-17/
      DATA ARI01(26)/ 0.44D-18/
      DATA ARI01(27)/-0.14D-18/
      DATA ARI01(28)/-0.1D-19/
      DATA ARI0A(0)/  2.03739654571143287070D0/
      DATA ARI0A(1)/  0.1917631647503310248D-1/
      DATA ARI0A(2)/  0.49923334519288147D-3/
      DATA ARI0A(3)/  0.2263187103659815D-4/
      DATA ARI0A(4)/  0.158682108285561D-5/
      DATA ARI0A(5)/  0.16507855636318D-6/
      DATA ARI0A(6)/  0.2385058373640D-7/
      DATA ARI0A(7)/  0.392985182304D-8/
      DATA ARI0A(8)/  0.46042714199D-9/
      DATA ARI0A(9)/ -0.7072558172D-10/
      DATA ARI0A(10)/-0.6747183961D-10/
      DATA ARI0A(11)/-0.2026962001D-10/
      DATA ARI0A(12)/-0.87320338D-12/
      DATA ARI0A(13)/ 0.175520014D-11/
      DATA ARI0A(14)/ 0.60383944D-12/
      DATA ARI0A(15)/-0.3977983D-13/
      DATA ARI0A(16)/-0.8049048D-13/
      DATA ARI0A(17)/-0.1158955D-13/
      DATA ARI0A(18)/ 0.827318D-14/
      DATA ARI0A(19)/ 0.282290D-14/
      DATA ARI0A(20)/-0.77667D-15/
      DATA ARI0A(21)/-0.48731D-15/
      DATA ARI0A(22)/ 0.7279D-16/
      DATA ARI0A(23)/ 0.7873D-16/
      DATA ARI0A(24)/-0.785D-17/
      DATA ARI0A(25)/-0.1281D-16/
      DATA ARI0A(26)/ 0.121D-17/
      DATA ARI0A(27)/ 0.214D-17/
      DATA ARI0A(28)/-0.27D-18/
      DATA ARI0A(29)/-0.36D-18/
      DATA ARI0A(30)/ 0.7D-19/
      DATA ARI0A(31)/ 0.6D-19/
      DATA ARI0A(32)/-0.2D-19/
      DATA ARI0A(33)/-0.1D-19/
!
      XLOW=CPUMIN
!
!   Start computation
!
      IND = 1
      X = XVALUE
      IF ( XVALUE .LT. ZERO ) THEN
         IND = -1
         X = -X
      ENDIF
!
!   Compute the machine-dependent constants.
!
      T = LOG(D1MACH(2))
      XHIGH = T + LOG(T)*HALF - LOG(HALF)
!
!   Error test
!
      IF ( X .GT. XHIGH ) THEN
!CCCC    CALL ERRPRN(FNNAME,ERRMSG)
         WRITE(ICOUT,999)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,101)X
         CALL DPWRST('XXX','BUG ')
         I0INT = EXP ( XHIGH - LNR2PI - HALF * LOG(XHIGH) )
         IF ( IND .EQ. -1 ) I0INT = -I0INT
         RETURN
      ENDIF
  999 FORMAT(1X)
  101 FORMAT('***** ERROR FROM I0INT--SIZE OF THE INPUT ARGUMENT ',   &
              'IS TOO LARGE, ARGUMENT = ',G15.7)
!
!   Continue with machine-constants
!
      TEMP = D1MACH(3)
      T = TEMP / ONEHUN
      IF ( X .LE. ATEEN ) THEN
         DO 10 NTERM1 = 28 , 0 , -1
            IF ( ABS(ARI01(NTERM1)) .GT. T ) GO TO  19
 10      CONTINUE
 19      XLOW = SQRT ( THIRT6 * TEMP / THREE )
      ELSE
         DO 40 NTERM2 = 33 , 0 , -1
            IF ( ABS(ARI0A(NTERM2)) .GT. T ) GO TO  49
 40      CONTINUE
 49      CONTINUE
      ENDIF
!
!   Code for 0 <= |x| <= 18
!
      IF ( X .LE. ATEEN ) THEN
         IF ( X .LT. XLOW ) THEN
            I0INT = X
         ELSE
            T = ( THREE * X - ATEEN ) / ( X + ATEEN )
            I0INT = X * EXP(X) * CHEVAL(NTERM1,ARI01,T)
         ENDIF
      ELSE
!
!   Code for |x| > 18
!
         T = ( THIRT6 / X - HALF ) - HALF
         TEMP = X - HALF*LOG(X) - LNR2PI + LOG(CHEVAL(NTERM2,ARI0A,T))
         I0INT = EXP(TEMP)
      ENDIF
      IF ( IND .EQ. -1 ) I0INT = -I0INT
      RETURN
      END FUNCTION I0INT
      DOUBLE PRECISION FUNCTION I0ML0(XVALUE)
!
!   DESCRIPTION:
!
!      This program calculates the function I0ML0 defined as
!
!                I0ML0(x) = I0(x) - L0(x)
!
!      where I0(x) is the modified Bessel function of the first kind of
!      order 0, and L0(x) is the modified Struve function of order 0.
!
!      The code uses Chebyshev expansions with the coefficients
!      given to an accuracy of 20D.
!
!
!   ERROR RETURNS:
!
!      The coefficients are only suitable for XVALUE >= 0.0. If
!      XVALUE < 0.0, an error message is printed and the function
!      returns the value 0.0
!
!
!   MACHINE-DEPENDENT PARAMETERS:
!
!      NTERM1 - INTEGER - The number of terms required for the array
!                         AI0L0. The recommended value is such that
!                              ABS(AI0L0(NTERM1)) < EPS/100
!
!      NTERM2 - INTEGER - The number of terms required for the array
!                         AI0L0A. The recommended value is such that
!                              ABS(AI0L0A(NTERM2)) < EPS/100
!
!      XLOW - DOUBLE PRECISION - The value below which I0ML0(x) = 1 to machine
!                    precision. The recommended value is
!                               EPSNEG
!
!      XHIGH - DOUBLE PRECISION - The value above which I0ML0(x) = 2/(pi*x) to
!                     machine precision. The recommended value is
!                               SQRT(800/EPS)
!
!      For values of EPS, and EPSNEG see the file MACHCON.TXT
!
!      The machine-dependent constants are computed internally by
!      using the D1MACH subroutine.
!
!
!   INTRINSIC FUNCTIONS USED:
!
!      SQRT
!
!
!   OTHER MISCFUN SUBROUTINES USED:
!
!          CHEVAL , ERRPRN, D1MACH
!
!
!   AUTHOR:
!          Dr. Allan J. MacLeod
!          Dept. of Mathematics and Statistics
!          University of Paisley
!          High St.
!          Paisley
!          SCOTLAND
!          PA1 2BE
!
!          ( e-mail: macl_ms0@paisley.ac.uk )
!
!
!   LATEST REVISION:
!                    23 January, 1996
!
      INTEGER NTERM1,NTERM2
      DOUBLE PRECISION AI0L0(0:23),AI0L0A(0:23),ATEHUN,CHEVAL,   &
           FORTY,ONE,ONEHUN,SIX,SIXTEN,T,TWOBPI,TWO88,X,XHIGH,   &
           XLOW,XSQ,XVALUE,ZERO
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
!CCCC CHARACTER FNNAME*6,ERRMSG*14
!CCCC DATA FNNAME/'I0ML0 '/
!CCCC DATA ERRMSG/'ARGUMENT < 0.0'/
      DATA ZERO,ONE/ 0.0D0,1.0D0 /
      DATA SIX,SIXTEN/ 6.0D0,16.0D0 /
      DATA FORTY,ONEHUN/ 40.0D0,100.0D0 /
      DATA TWO88,ATEHUN/ 288.0D0,800.0D0 /
      DATA TWOBPI/0.63661977236758134308D0/
      DATA AI0L0(0)/  0.52468736791485599138D0/
      DATA AI0L0(1)/ -0.35612460699650586196D0/
      DATA AI0L0(2)/  0.20487202864009927687D0/
      DATA AI0L0(3)/ -0.10418640520402693629D0/
      DATA AI0L0(4)/  0.4634211095548429228D-1/
      DATA AI0L0(5)/ -0.1790587192403498630D-1/
      DATA AI0L0(6)/  0.597968695481143177D-2/
      DATA AI0L0(7)/ -0.171777547693565429D-2/
      DATA AI0L0(8)/  0.42204654469171422D-3/
      DATA AI0L0(9)/ -0.8796178522094125D-4/
      DATA AI0L0(10)/ 0.1535434234869223D-4/
      DATA AI0L0(11)/-0.219780769584743D-5/
      DATA AI0L0(12)/ 0.24820683936666D-6/
      DATA AI0L0(13)/-0.2032706035607D-7/
      DATA AI0L0(14)/ 0.90984198421D-9/
      DATA AI0L0(15)/ 0.2561793929D-10/
      DATA AI0L0(16)/-0.710609790D-11/
      DATA AI0L0(17)/ 0.32716960D-12/
      DATA AI0L0(18)/ 0.2300215D-13/
      DATA AI0L0(19)/-0.292109D-14/
      DATA AI0L0(20)/-0.3566D-16/
      DATA AI0L0(21)/ 0.1832D-16/
      DATA AI0L0(22)/-0.10D-18/
      DATA AI0L0(23)/-0.11D-18/
      DATA AI0L0A(0)/ 2.00326510241160643125D0/
      DATA AI0L0A(1)/ 0.195206851576492081D-2/
      DATA AI0L0A(2)/ 0.38239523569908328D-3/
      DATA AI0L0A(3)/ 0.7534280817054436D-4/
      DATA AI0L0A(4)/ 0.1495957655897078D-4/
      DATA AI0L0A(5)/ 0.299940531210557D-5/
      DATA AI0L0A(6)/ 0.60769604822459D-6/
      DATA AI0L0A(7)/ 0.12399495544506D-6/
      DATA AI0L0A(8)/ 0.2523262552649D-7/
      DATA AI0L0A(9)/ 0.504634857332D-8/
      DATA AI0L0A(10)/0.97913236230D-9/
      DATA AI0L0A(11)/0.18389115241D-9/
      DATA AI0L0A(12)/0.3376309278D-10/
      DATA AI0L0A(13)/0.611179703D-11/
      DATA AI0L0A(14)/0.108472972D-11/
      DATA AI0L0A(15)/0.18861271D-12/
      DATA AI0L0A(16)/0.3280345D-13/
      DATA AI0L0A(17)/0.565647D-14/
      DATA AI0L0A(18)/0.93300D-15/
      DATA AI0L0A(19)/0.15881D-15/
      DATA AI0L0A(20)/0.2791D-16/
      DATA AI0L0A(21)/0.389D-17/
      DATA AI0L0A(22)/0.70D-18/
      DATA AI0L0A(23)/0.16D-18/
!
      XLOW=CPUMIN
!
!   Start computation
!
      X = XVALUE
!
!   Error test
!
      IF ( X .LT. ZERO ) THEN
!CCCC    CALL ERRPRN(FNNAME,ERRMSG)
         WRITE(ICOUT,999)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,101)X
         CALL DPWRST('XXX','BUG ')
         I0ML0 = ZERO
         RETURN
      ENDIF
  999 FORMAT(1X)
  101 FORMAT('***** ERROR FROM I0ML0--ARGUMENT MUST BE ',   &
              'NON-NEGATIVE, ARGUMENT = ',G15.7)
!
!   Compute the machine-dependent constants.
!
      XSQ = D1MACH(3)
      T = XSQ / ONEHUN
      IF ( X .LE. SIXTEN ) THEN
         DO 10 NTERM1 = 23 , 0 , -1
            IF ( ABS(AI0L0(NTERM1)) .GT. T ) GO TO  19
 10      CONTINUE
 19      XLOW = XSQ
      ELSE
         DO 40 NTERM2 = 23 , 0 , -1
            IF ( ABS(AI0L0A(NTERM2)) .GT. T ) GO TO  49
 40      CONTINUE
 49      XHIGH = SQRT ( ATEHUN / XSQ )
      ENDIF
!
!   Code for x <= 16
!
      IF ( X .LE. SIXTEN ) THEN
         IF ( X .LT. XLOW ) THEN
            I0ML0 = ONE
            RETURN
         ELSE
            T = ( SIX * X - FORTY ) / ( X + FORTY )
            I0ML0 = CHEVAL(NTERM1,AI0L0,T)
            RETURN
         ENDIF
      ELSE
!
!   Code for x > 16
!
         IF ( X .GT. XHIGH ) THEN
            I0ML0 = TWOBPI / X
         ELSE
            XSQ = X * X
            T = ( ATEHUN - XSQ ) / ( TWO88 + XSQ )
            I0ML0 = CHEVAL(NTERM2,AI0L0A,T) * TWOBPI / X
         ENDIF
      ENDIF
      RETURN
      END FUNCTION I0ML0
      DOUBLE PRECISION FUNCTION I1ML1(XVALUE)
!
!   DESCRIPTION:
!
!      This program calculates the function I1ML1 defined as
!
!                I1ML1(x) = I1(x) - L1(x)
!
!      where I1(x) is the modified Bessel function of the first kind of
!      order 1, and L1(x) is the modified Struve function of order 1.
!
!      The code uses Chebyshev expansions with the coefficients
!      given to an accuracy of 20D.
!
!
!   ERROR RETURNS:
!
!      The coefficients are only suitable for XVALUE >= 0.0. If
!      XVALUE < 0.0, an error message is printed and the function
!      returns the value 0.0
!
!
!   MACHINE-DEPENDENT PARAMETERS:
!
!      NTERM1 - INTEGER - The number of terms required for the array
!                         AI1L1. The recommended value is such that
!                              ABS(AI1L1(NTERM1)) < EPS/100
!
!      NTERM2 - INTEGER - The number of terms required for the array
!                         AI1L1A. The recommended value is such that
!                              ABS(AI1L1A(NTERM2)) < EPS/100
!
!      XLOW - DOUBLE PRECISION - The value below which I1ML1(x) = x/2 to machine
!                    precision. The recommended value is
!                               2*EPSNEG
!
!      XHIGH - DOUBLE PRECISION - The value above which I1ML1(x) = 2/pi to
!                     machine precision. The recommended value is
!                               SQRT(800/EPS)
!
!      For values of EPS, and EPSNEG see the file MACHCON.TXT
!
!      The machine-dependent constants are computed internally by
!      using the D1MACH subroutine.
!
!
!   INTRINSIC FUNCTIONS USED:
!
!      ABS , SQRT
!
!
!   OTHER MISCFUN SUBROUTINES USED:
!
!          CHEVAL , ERRPRN, D1MACH
!
!
!   AUTHOR:
!          Dr. Allan J. MacLeod
!          Dept. of Mathematics and Statistics
!          University of Paisley
!          High St.
!          Paisley
!          SCOTLAND
!          PA1 2BE
!
!          (e-mail: macl_ms0@paisley.ac.uk )
!
!
!   LATEST REVISION:
!                    23 January, 1996
!
      INTEGER NTERM1,NTERM2
      DOUBLE PRECISION AI1L1(0:23),AI1L1A(0:25),ATEHUN,CHEVAL
!CCCC DOUBLE PRECISION FORTY,ONE,ONEHUN,SIX,SIXTEN,T,TWO,TWOBPI,TWO88
      DOUBLE PRECISION FORTY,ONEHUN,SIX,SIXTEN,T,TWO,TWOBPI,TWO88
      DOUBLE PRECISION X,XHIGH,XLOW,XSQ,XVALUE,ZERO
!CCCC CHARACTER FNNAME*6,ERRMSG*14
!CCCC DATA FNNAME/'I1ML1 '/
!CCCC DATA ERRMSG/'ARGUMENT < 0.0'/
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
!CCCC DATA ZERO,ONE,TWO/ 0.0 D 0 , 1.0 D 0 , 2.0 D 0 /
      DATA ZERO,TWO/ 0.0D0,2.0D0 /
      DATA SIX,SIXTEN,FORTY/ 6.0D0,16.0D0,40.0D0 /
      DATA ONEHUN,TWO88,ATEHUN/ 100.0D0,288.0D0,800.0D0 /
      DATA TWOBPI/0.63661977236758134308D0/
      DATA AI1L1(0)/  0.67536369062350576137D0/
      DATA AI1L1(1)/ -0.38134971097266559040D0/
      DATA AI1L1(2)/  0.17452170775133943559D0/
      DATA AI1L1(3)/ -0.7062105887235025061D-1/
      DATA AI1L1(4)/  0.2517341413558803702D-1/
      DATA AI1L1(5)/ -0.787098561606423321D-2/
      DATA AI1L1(6)/  0.214814368651922006D-2/
      DATA AI1L1(7)/ -0.50862199717906236D-3/
      DATA AI1L1(8)/  0.10362608280442330D-3/
      DATA AI1L1(9)/ -0.1795447212057247D-4/
      DATA AI1L1(10)/ 0.259788274515414D-5/
      DATA AI1L1(11)/-0.30442406324667D-6/
      DATA AI1L1(12)/ 0.2720239894766D-7/
      DATA AI1L1(13)/-0.158126144190D-8/
      DATA AI1L1(14)/ 0.1816209172D-10/
      DATA AI1L1(15)/ 0.647967659D-11/
      DATA AI1L1(16)/-0.54113290D-12/
      DATA AI1L1(17)/-0.308311D-14/
      DATA AI1L1(18)/ 0.305638D-14/
      DATA AI1L1(19)/-0.9717D-16/
      DATA AI1L1(20)/-0.1422D-16/
      DATA AI1L1(21)/ 0.84D-18/
      DATA AI1L1(22)/ 0.7D-19/
      DATA AI1L1(23)/-0.1D-19/
      DATA AI1L1A(0)/  1.99679361896789136501D0/
      DATA AI1L1A(1)/ -0.190663261409686132D-2/
      DATA AI1L1A(2)/ -0.36094622410174481D-3/
      DATA AI1L1A(3)/ -0.6841847304599820D-4/
      DATA AI1L1A(4)/ -0.1299008228509426D-4/
      DATA AI1L1A(5)/ -0.247152188705765D-5/
      DATA AI1L1A(6)/ -0.47147839691972D-6/
      DATA AI1L1A(7)/ -0.9020819982592D-7/
      DATA AI1L1A(8)/ -0.1730458637504D-7/
      DATA AI1L1A(9)/ -0.332323670159D-8/
      DATA AI1L1A(10)/-0.63736421735D-9/
      DATA AI1L1A(11)/-0.12180239756D-9/
      DATA AI1L1A(12)/-0.2317346832D-10/
      DATA AI1L1A(13)/-0.439068833D-11/
      DATA AI1L1A(14)/-0.82847110D-12/
      DATA AI1L1A(15)/-0.15562249D-12/
      DATA AI1L1A(16)/-0.2913112D-13/
      DATA AI1L1A(17)/-0.543965D-14/
      DATA AI1L1A(18)/-0.101177D-14/
      DATA AI1L1A(19)/-0.18767D-15/
      DATA AI1L1A(20)/-0.3484D-16/
      DATA AI1L1A(21)/-0.643D-17/
      DATA AI1L1A(22)/-0.118D-17/
      DATA AI1L1A(23)/-0.22D-18/
      DATA AI1L1A(24)/-0.4D-19/
      DATA AI1L1A(25)/-0.1D-19/
!
      XLOW=CPUMIN
!
!   Start computation
!
      X = XVALUE
!
!   Error test
!
      IF ( X .LT. ZERO ) THEN
!CCCC    CALL ERRPRN(FNNAME,ERRMSG)
         WRITE(ICOUT,999)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,101)X
         CALL DPWRST('XXX','BUG ')
         I1ML1 = ZERO
         RETURN
      ENDIF
  999 FORMAT(1X)
  101 FORMAT('***** ERROR FROM I1ML1--ARGUMENT MUST BE ',   &
              'NON-NEGATIVE, ARGUMENT = ',G15.7)
!
!   Compute the machine-dependent constants.
!
      XSQ = D1MACH(3)
      T = XSQ / ONEHUN
      IF ( X .LE. SIXTEN ) THEN
         DO 10 NTERM1 = 23 , 0 , -1
            IF ( ABS(AI1L1(NTERM1)) .GT. T ) GO TO  19
 10      CONTINUE
 19      XLOW = XSQ + XSQ
      ELSE
         DO 40 NTERM2 = 25 , 0 , -1
            IF ( ABS(AI1L1A(NTERM2)) .GT. T ) GO TO  49
 40      CONTINUE
 49      XHIGH = SQRT ( ATEHUN / XSQ )
      ENDIF
!
!   Code for x <= 16
!
      IF ( X .LE. SIXTEN ) THEN
         IF ( X .LT. XLOW ) THEN
            I1ML1 = X / TWO
            RETURN
         ELSE
            T = ( SIX * X - FORTY ) / ( X + FORTY )
            I1ML1 = CHEVAL(NTERM1,AI1L1,T) * X / TWO
            RETURN
         ENDIF
      ELSE
!
!   Code for x > 16
!
         IF ( X .GT. XHIGH ) THEN
            I1ML1 = TWOBPI
         ELSE
            XSQ = X * X
            T = ( ATEHUN - XSQ ) / ( TWO88 + XSQ )
            I1ML1 = CHEVAL(NTERM2,AI1L1A,T) * TWOBPI
         ENDIF
      ENDIF
      RETURN
      END FUNCTION I1ML1
      SUBROUTINE IBCDF(X,ALPHA,BETA,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE INVERTED BETA DISTRIBUTION
!              WITH SHAPE PARAMETERS ALPHA AND BETA.
!              THIS DISTRIBUTION IS DEFINED FOR ALL X AND HAS
!              THE PROBABILITY DENSITY FUNCTION
!              IBPDF(X,A,B) = X**(ALPHA-1)/
!                             [BETA(ALPHA,BETA)*(1+X)**(ALPHA+BETA),
!                             X, ALPHA, BETA > 0
!              THE CUMULATIVE DISTRIBUTION IS COMPUTED BY
!              ALPHAMERICALLY INTEGRATING THE PDF FUNCTION.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                     --ALPHA  = THE DEGREES OF FREEDOM PARAMETER
!                     --BETA   = THE SKEWNESS PARAMETER
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE INVERTED BETA DISTRIBUTION
!             WITH SHAPE PARAMETERS ALPHA AND BETA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--DQAGI.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME II", SECOND EDITION,
!                 JOHN WILEY, 1994.
!               --EVANS, HASTINGS, AND PEACOCK, "STATISTICAL
!                 DISTRIBUTIONS", THIRD EDITION, JOHN WILEY, 2000.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION ALPHAMBER--2003.12
!     ORIGINAL VERSION--DECEMBER  2003.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      INTEGER LIMIT
      INTEGER LENW
      PARAMETER(LIMIT=200)
      PARAMETER(LENW=4*LIMIT)
      INTEGER INF
      INTEGER NEVAL
      INTEGER IER
      INTEGER LAST
      INTEGER IWORK(LIMIT)
      REAL ALPHA
      REAL BETA
      REAL X
      REAL CDF
      DOUBLE PRECISION EPSABS
      DOUBLE PRECISION EPSREL
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DX
      DOUBLE PRECISION DA
      DOUBLE PRECISION ABSERR
      DOUBLE PRECISION WORK(LENW)
!
      DOUBLE PRECISION IBFUN
      EXTERNAL IBFUN
!
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DBETA
      COMMON/IBCOM/DALPHA,DBETA
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      CDF=0.0
      IF(ALPHA.LE.0.0)THEN
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,102)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,104)ALPHA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
      IF(BETA.LE.0.0)THEN
        WRITE(ICOUT,103)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,102)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,104)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
      IF(X.LE.0.0)THEN
        WRITE(ICOUT,106)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,104)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
  101 FORMAT('***** ERROR--THE FIRST SHAPE PARAMETER, ALPHA, TO THE')
  102 FORMAT('      IBCDF ROUTINE IS NON-POSITIVE.')
  103 FORMAT('***** ERROR--THE SECOND SHAPE PARAMETER, BETA, TO THE')
  104 FORMAT('      THE VALUE OF THE ARGUMENT IS ',E15.7,' ******')
  106 FORMAT('***** ERROR--THE FIRST ARGUMENT TO THE IBCDF ROUTINE ',   &
             'IS NON-POSITIVE.')
!
!
!               ************************************
!               **  STEP 1--                      **
!               **  COMPUTE THE DENSITY FUNCTION  **
!               ************************************
!
      INF=+1
      EPSABS=1.0D-7
      EPSREL=1.0D-7
      IER=0
      IKEY=3
      CDF=0.0D0
!
      DA=1.0D-7
      DX=DBLE(X)
      DALPHA=DBLE(ALPHA)
      DBETA=DBLE(BETA)
!
!CCCC REPLACE WITH A CODE FOR DEFINITE INTEGRAL.
!CCCC CALL DQAGI(IBFUN,DX,INF,EPSABS,EPSREL,DCDF,ABSERR,NEVAL,
!CCCC1          IER,LIMIT,LENW,LAST,IWORK,WORK)
!
!CCCC DCDF=1.0D0 - DCDF
!
      CALL DQAG(IBFUN,DA,DX,EPSABS,EPSREL,IKEY,DCDF,ABSERR,NEVAL,   &
                IER,LIMIT,LENW,LAST,IWORK,WORK)
      CDF=REAL(DCDF)
!
      IF(IER.EQ.1)THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR FROM IBCDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)
  113   FORMAT('      MAXIMUM NUMBER OF SUBDIVISIONS EXCEEDED.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,121)
  121   FORMAT('***** ERROR FROM IBCDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,123)
  123   FORMAT('      ROUNDOFF ERROR PREVENTS REQUESTED TOLERANCE ',   &
               'FROM BEING ACHIEVED.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.3)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,131)
  131   FORMAT('***** ERROR FROM IBCDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,133)
  133   FORMAT('      BAD INTEGRAND BEHAVIOUR DETECTED.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.4)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,141)
  141   FORMAT('***** ERROR FROM IBCDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,143)
  143   FORMAT('      INTEGRATION DID NOT CONVERGE.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.5)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,151)
  151   FORMAT('***** ERROR FROM IBCDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,153)
  153   FORMAT('      THE INTEGRATION IS PROBABLY DIVERGENT.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IER.EQ.6)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,161)
  161   FORMAT('***** ERROR FROM IBCDF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,163)
  163   FORMAT('      INVALID INPUT TO THE INTEGRATION ROUTINE.')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE IBCDF
      DOUBLE PRECISION FUNCTION IBFUN(DX)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE INVERTED BETA DISTRIBUTION
!              WITH SHAPE PARAMETERS ALPHA AND BETA.
!              THIS DISTRIBUTION IS DEFINED FOR X > 0 AND HAS
!              THE PROBABILITY DENSITY FUNCTION
!              IBPDF(X,A,B) = X**(ALPHA-1)/
!                             [BETA(ALPHA,BETA)*(1+X)**(ALPHA+BETA),
!                             X, ALPHA, BETA > 0
!              IDENTICAL TO IBPDF,
!              BUT DEFINE AS FUNCTION TO BE USED FOR INTEGRATION
!              CODE CALLED BY IBCDF.
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--IBFUN  = THE DOUBLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE SKEW-T DISTRIBUTION
!             WITH SHAPE PARAMETERS ALPHA AND BETA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--DLBETA.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME II", SECOND EDITION,
!                 JOHN WILEY, 1994.
!               --EVANS, HASTINGS, AND PEACOCK, "STATISTICAL
!                 DISTRIBUTIONS", THIRD EDITION, JOHN WILEY, 2000.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2003.12
!     ORIGINAL VERSION--DECEMBER  2003.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      EXTERNAL DLBETA
!
      DOUBLE PRECISION DLBETA
      DOUBLE PRECISION DX
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
!
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DBETA
      COMMON/IBCOM/DALPHA,DBETA
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!               ************************************
!               **  STEP 1--                      **
!               **  COMPUTE THE DENSITY FUNCTION  **
!               ************************************
!
      DTERM1=(DALPHA-1.0D0)*DLOG(DX)
      DTERM2=DLBETA(DALPHA,DBETA)
      DTERM3=(DALPHA+DBETA)*DLOG(1.0D0+DX)
!
      DPDF=DTERM1 - DTERM2 - DTERM3
      IF(DPDF.LT.LOG(CPUMAX))THEN
        DPDF=DEXP(DPDF)
      ELSE
        WRITE(ICOUT,501)
        CALL DPWRST('XXX','BUG ')
        DPDF=LOG(CPUMAX)
      ENDIF
  501 FORMAT('***** WARNING FROM INVERTED BETA PDF--OVERFLOW ',   &
             'DETECTED.')
!
      IBFUN=DPDF
      RETURN
      END FUNCTION IBFUN
      REAL FUNCTION IBFU2(X)
!
!     PURPOSE--IBPPF CALLS FZERO TO FIND A ROOT FOR THE PERCENT
!              POINT FUNCTION.  IBFU2 IS THE FUNCTION FOR WHICH
!              THE ZERO IS FOUND.  IT IS:
!                 P - IBCDF(X,LAMBDA)
!              WHERE P IS THE DESIRED PERCENT POINT.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE IBFU2.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--IBCDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 JOHN WILEY, 1994, PAGE 454.
!               --AZZALINI HAS AUTHORED A NUMBER OF PAPERS ON THIS
!                 DISTRIBUTION.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2003.12
!     ORIGINAL VERSION--DECEMBER  2003.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      REAL P
      COMMON/IB2COM/P
!
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DBETA
      COMMON/IBCOM/DALPHA,DBETA
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      CALL IBCDF(X,REAL(DALPHA),REAL(DBETA),CDF)
      IBFU2=P - CDF
!
      RETURN
      END FUNCTION IBFU2
      SUBROUTINE IBPDF(X,ALPHA,BETA,PDF)
!
!     NOTE--INVERTED BETA PDF IS:
!              IBPDF(X,A,B) = X**(ALPHA-1)/
!                             [BETA(ALPHA,BETA)*(1+X)**(ALPHA+BETA),
!                             X > 0
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME II", SECOND EDITION,
!                 JOHN WILEY, 1994.
!               --EVANS, HASTINGS, AND PEACOCK, "STATISTICAL
!                 DISTRIBUTIONS", THIRD EDITION, JOHN WILEY, 2000.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2003/5
!     ORIGINAL VERSION--MAY       2003.
!
!---------------------------------------------------------------------
!
      EXTERNAL DLBETA
      DOUBLE PRECISION DLBETA
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DBETA
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DPDF
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      PDF=0.0
      IF(ALPHA.LE.0.0)THEN
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,102)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,104)ALPHA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
      IF(BETA.LE.0.0)THEN
        WRITE(ICOUT,103)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,102)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,104)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
      IF(X.LE.0.0)THEN
        WRITE(ICOUT,106)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,104)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
  101 FORMAT('***** ERROR--THE FIRST SHAPE PARAMETER, ALPHA, TO THE')
  102 FORMAT('      IBPDF ROUTINE IS NON-POSITIVE.')
  103 FORMAT('***** ERROR--THE SECOND SHAPE PARAMETER, BETA, TO THE')
  104 FORMAT('      THE VALUE OF THE ARGUMENT IS ',E15.7,' ******')
  106 FORMAT('***** ERROR--THE FIRST ARGUMENT TO THE IBPDF ROUTINE ',   &
             'IS NON-POSITIVE.')
!
      DX=DBLE(X)
      DALPHA=DBLE(ALPHA)
      DBETA=DBLE(BETA)
!
      DTERM1=(DALPHA-1.0D0)*LOG(DX)
      DTERM2=DLBETA(DALPHA,DBETA)
      DTERM3=(DALPHA+DBETA)*LOG(1.0D0+DX)
!
      DPDF=DTERM1 - DTERM2 - DTERM3
      IF(DPDF.LT.LOG(CPUMAX))THEN
        DPDF=DEXP(DPDF)
      ELSE
        WRITE(ICOUT,501)
        CALL DPWRST('XXX','BUG ')
        DPDF=LOG(CPUMAX)
      ENDIF
  501 FORMAT('***** WARNING FROM INVERTED BETA PDF--OVERFLOW ',   &
             'DETECTED.')
      PDF=REAL(DPDF)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE IBPDF
      SUBROUTINE IBPPF(P,ALPHA,BETA,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE INVERTED BETA DISTRIBUTION
!              WITH SHAPE PARAMETERS ALPHA AND BETA.
!              THIS DISTRIBUTION IS DEFINED FOR POSITIVE X AND THE
!              PERCENT POINT FUNCTION IS COMPUTED BY
!              NUMERICALLY INVERTING THE CDF FUNCTION.
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --ALPHA  = THE FIRST SHAPE PARAMETER
!                     --BETA   = THE SECOND SHAPE PARAMETER
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT
!             FUNCTION VALUE PPF.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--FZERO.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME II", SECOND EDITION,
!                 JOHN WILEY, 1994.
!               --EVANS, HASTINGS, AND PEACOCK, "STATISTICAL
!                 DISTRIBUTIONS", THIRD EDITION, JOHN WILEY, 2000.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION ALPHAMBER--2003.12
!     ORIGINAL VERSION--DECEMBER  2003.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      REAL PPF
!
      REAL IBFU2
      EXTERNAL IBFU2
!
      REAL P2
      COMMON/IB2COM/P2
!
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DBETA
      COMMON/IBCOM/DALPHA,DBETA
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      PPF=0.0
      IF(ALPHA.LE.0.0)THEN
        WRITE(ICOUT,101)
  101   FORMAT('***** ERROR--THE FIRST SHAPE PARAMETER, ALPHA, TO THE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,102)
  102   FORMAT('      IBPPF ROUTINE IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,104)ALPHA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(BETA.LE.0.0)THEN
        WRITE(ICOUT,103)
  103   FORMAT('***** ERROR--THE SECOND SHAPE PARAMETER, BETA, TO THE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,102)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,104)BETA
  104   FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(P.LT.0.0.OR.P.GE.1.0)THEN
         WRITE(ICOUT,61)
   61    FORMAT('***** ERROR--THE FIRST ARGUMENT TO IBPPF')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,62)
   62    FORMAT('      IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL.')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,63)P
   63    FORMAT('      VALUE OF ARGUMENT = ',G15.7,'.')
         CALL DPWRST('XXX','BUG ')
         GO TO 9000
      ENDIF
!
      IF(P.EQ.0.0)THEN
        PPF=0.0
        GO TO 9000
      ENDIF
!
!  STEP 1: FIND BRACKETING INTERVAL.  LOWER BOUND IS ZERO.  START WITH
!          10 AS GUESS FOR UPPER BOUND.  MULTIPLY BY 10 UNTIL
!          BRACKETING INTERVAL FOUND.
!
      XLOW=0.0000001
      XUP2=10.0
  200 CONTINUE
      CALL IBCDF(XUP2,ALPHA,BETA,PTEMP)
      IF(PTEMP.GT.P)THEN
        XUP=XUP2
      ELSE
        XUP2=XUP2*10.0
        IF(XUP2.GT.CPUMAX/100.)THEN
          WRITE(ICOUT,201)
  201     FORMAT('***** ERROR FROM IBPPF--UNABLE TO FIND A ',   &
                 'BRACKETING INTERVAL')
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
        ENDIF
        GO TO 200
      ENDIF
!
      AE=1.E-6
      RE=1.E-6
      P2=P
      DALPHA=DBLE(ALPHA)
      DBETA=DBLE(BETA)
      CALL FZERO(IBFU2,XLOW,XUP,XUP,RE,AE,IFLAG)
!
      PPF=XLOW
!
      IF(IFLAG.EQ.2)THEN
!
!  NOTE: SUPPRESS THIS MESSAGE FOR NOW.
!CCCC   WRITE(ICOUT,999)
  999   FORMAT(1X)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,111)
!C111   FORMAT('***** WARNING FROM IBPPF--')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,113)
!C113   FORMAT('      PPF VALUE MAY NOT BE COMPUTED TO DESIRED ',
!CCCC1         'TOLERANCE.')
!CCCC   CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.3)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,121)
  121   FORMAT('***** WARNING FROM IBPPF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,123)
  123   FORMAT('      PPF VALUE MAY BE NEAR A SINGULAR POINT.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.4)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,131)
  131   FORMAT('***** ERROR FROM IBPPF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,133)
  133   FORMAT('      APPROPRIATE BRACKETING INTERVAL NOT FOUND.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.5)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,141)
  141   FORMAT('***** WARNING FROM IBPPF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,143)
  143   FORMAT('      MAXIMUM ITERATIONS EXCEEDED.')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE IBPPF
      SUBROUTINE IBRAN(N,ALPHA,BETA,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE INVERTED BETA DISTRIBUTION
!              WITH SINGLE PRECISION SHAPE PARAMETERS = ALPHA AND BETA.
!              THE PROTOTYPE INVERTED BETA DISTRIBUTION USED
!              HEREIN CAN BE EXPRESSED AS THE RATIO OF TWO INDEPENDENT
!              GAMMA DISTRIBUTIONS WITH SHAPE PARAMETERS ALPHA AND
!              BETA, RESPECTIVELY.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --ALPHA  = THE SINGLE PRECISION VALUE OF THE
!                                FIRST  SHAPE PARAMETER.
!                                ALPHA SHOULD BE GREATER THAN 0.0.
!                     --BETA   = THE SINGLE PRECISION VALUE OF THE
!                                SECOND SHAPE PARAMETER.
!                                BETA  SHOULD BE GREATER THAN 0.0.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE INVERTED BETA DISTRIBUTION
!             WITH SHAPE PARAMETER VALUES = ALPHA AND BETA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --ALPHA SHOULD BE GREATER THAN
!                   OR EQUAL TO 0.0.
!                 --BETA  SHOULD BE GREATER THAN
!                   OR EQUAL TO 0.0.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN, GAMRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--EVANS, HASTINGS AND PEACOCK, "STATISTICAL
!                 DISTRIBUTIONS--THIRD EDITION", WILEY, 2000.
!                 PAGES 41-42.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLARITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--2003.5
!     ORIGINAL VERSION--MAY       2003.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION XG1(1)
      DIMENSION XG2(1)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(ALPHA.LE.0.0)THEN
        WRITE(ICOUT,16)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(BETA.LT.0.0)THEN
        WRITE(ICOUT,26)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    5 FORMAT('***** ERROR--THE NUMBER OF REQUESTED INVERTED ',   &
      'BETA RANDOM NUMBERS IS NON-POSITIVE.')
   16 FORMAT('***** ERROR--THE FIRST SHAPE PARAMETER FOR THE ',   &
      'INVERTED BETA IS LESS THAN 0.0 *****')
   26 FORMAT('***** ERROR--THE SECOND SHAPE PARAMETER FOR THE ',   &
      'INVERTED BETA IS LESS THAN 0.0 *****')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,' *****')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,' *****')
!
!     GENERATE N BETA RANDOM NUMBERS BY USING THE FACT THAT THE
!     INVERTED BETA IS A RATIO OF TWO INDEPENDENT GAMMA VARIATES.
!
      NTEMP=1
      DO 100 I=1,N
!
        CALL GAMRAN(NTEMP,ALPHA,ISEED,XG1)
        CALL GAMRAN(NTEMP,BETA,ISEED,XG2)
        X(I)=0.0
        IF(XG2(1).GT.0.0)X(I)=XG1(1)/XG2(1)
!
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE IBRAN
      INTEGER FUNCTION IDAMAX(N,DX,INCX)
!***BEGIN PROLOGUE  IDAMAX
!***DATE WRITTEN   791001   (YYMMDD)
!***REVISION DATE  820801   (YYMMDD)
!***CATEGORY NO.  D1A2
!***KEYWORDS  BLAS,DOUBLE PRECISION,LINEAR ALGEBRA,MAXIMUM COMPONENT,
!             VECTOR
!***AUTHOR  LAWSON, C. L., (JPL)
!           HANSON, R. J., (SNLA)
!           KINCAID, D. R., (U. OF TEXAS)
!           KROGH, F. T., (JPL)
!***PURPOSE  Find largest component of d.p. vector
!***DESCRIPTION
!
!                B L A S  Subprogram
!    Description of Parameters
!
!     --Input--
!        N  number of elements in input vector(s)
!       DX  double precision vector with N elements
!     INCX  storage spacing between elements of DX
!
!     --Output--
!   IDAMAX  smallest index (zero if N .LE. 0)
!
!     Find smallest index of maximum magnitude of double precision DX.
!     IDAMAX =  first I, I = 1 to N, to minimize  ABS(DX(1-INCX+I*INCX)
!***REFERENCES  LAWSON C.L., HANSON R.J., KINCAID D.R., KROGH F.T.,
!                 *BASIC LINEAR ALGEBRA SUBPROGRAMS FOR FORTRAN USAGE*,
!                 ALGORITHM NO. 539, TRANSACTIONS ON MATHEMATICAL
!                 SOFTWARE, VOLUME 5, NUMBER 3, SEPTEMBER 1979, 308-323
!***ROUTINES CALLED  (NONE)
!***END PROLOGUE  IDAMAX
!
      DOUBLE PRECISION DX(*),DMAX,XMAG
!***FIRST EXECUTABLE STATEMENT  IDAMAX
      IDAMAX = 0
      IF(N.LE.0) RETURN
      IDAMAX = 1
      IF(N.LE.1)RETURN
      IF(INCX.EQ.1)GO TO  20
!
!        CODE FOR INCREMENTS NOT EQUAL TO 1.
!
      DMAX = DABS(DX(1))
      NS = N*INCX
      II = 1
          DO 10 I = 1,NS,INCX
          XMAG = DABS(DX(I))
          IF(XMAG.LE.DMAX) GO TO 5
          IDAMAX = II
          DMAX = XMAG
    5     II = II + 1
   10     CONTINUE
      RETURN
!
!        CODE FOR INCREMENTS EQUAL TO 1.
!
   20 DMAX = DABS(DX(1))
      DO 30 I = 2,N
          XMAG = DABS(DX(I))
          IF(XMAG.LE.DMAX) GO TO 30
          IDAMAX = I
          DMAX = XMAG
   30 CONTINUE
      RETURN
      END FUNCTION IDAMAX
      SUBROUTINE IGACDF(X,ALPHA,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE INVERTED GAMMA DISTRIBUTION
!              WITH POSITIVE SHAPE PARAMETER ALPHA.
!              THIS DISTRIBUTION IS DEFINED FOR ALL POSITIVE X.
!              THE PROBABILITY DENSITY FUNCTION IS GIVEN
!              IN THE REFERENCES BELOW.
!              THE CDF FOR THE STANDARD FORM OF THE DISTRIBUTION IS
!                  F(X,ALPHA) = GAMMAIP(1/X,ALPHA)
!              WHERE GAMMAIP = GAMMAI(ALPHA,X)/GAMMA(ALPHA).
!              THE CDF IS CAN BE COMPUTED WITH THE SLATEC ROUTINE
!              DGAMIC.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE NON-NEGATIVE.
!                     --ALPHA  = A POSITIVE SHAPE PARAMETER
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE INVERTED GAMMA DISTRIBUTION
!             WITH SHAPE PARAMETER ALPHA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE.
!                 --ALPHA SHOULD BE A POSITIVE NUMBER.
!     OTHER DATAPAC   SUBROUTINES NEEDED--GAMMIP.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--EVANS, HASTINGS, AND PEACOCK, "STATISTICAL
!                DISTRIBUTIONS", THIRD EDITION, WILEY, 2000,
!                GAMMA CHAPTER.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004/6
!     ORIGINAL VERSION--JUNE      2004. PREVIOUSLY IMPLEMENTED
!                                       AS SPECIAL CASE OF GGDCDF
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DGAMIP
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(X.LE.0.0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ENDIF
      IF(ALPHA.LE.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ENDIF
    4 FORMAT('***** ERROR--THE FIRST INPUT ARGUMENT ',   &
      'TO THE IGACDF SUBROUTINE IS NON-POSITIVE *****')
   15 FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO THE ',   &
      'IGACDF SUBROUTINE IS NON-POSITIVE *****')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
!
!
      IF(X.LE.R1MACH(1))THEN
        CDF=0.0
        RETURN
      ENDIF
!
      DX=DBLE(X)
      DALPHA=DBLE(ALPHA)
!
      DCDF=1.0D0 - DGAMIP(DALPHA,1.0D0/DX)
      CDF=REAL(DCDF)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE IGACDF
      SUBROUTINE IGAPDF(X,ALPHA,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE INVERTED GAMMA DISTRIBUTION
!              WITH POSITIVE SHAPE PARAMETER ALPHA.
!              THIS DISTRIBUTION IS DEFINED FOR ALL POSITIVE X.
!              THE PDF FOR THE STANDARD FORM OF THE DISTRIBUTION IS
!                  F(X,ALPHA) = X**(-(ALPHA+1))*EXP(-1/X)/GAMMA(ALPHA)
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE NON-NEGATIVE.
!                     --ALPHA  = A POSITIVE SHAPE PARAMETER
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE INVERTED GAMMA DISTRIBUTION
!             WITH SHAPE PARAMETER ALPHA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE.
!                 --ALPHA AND X SHOULD BE POSITIVE NUMBERS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--EVANS, HASTINGS, AND PEACOCK, "STATISTICAL
!                DISTRIBUTIONS", THIRD EDITION, WILEY, 2000,
!                GAMMA CHAPTER.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004/6
!     ORIGINAL VERSION--JUNE      2004. PREVIOUSLY COMPUTED USING
!                                       GENERALIZED GAMMA WITH C=-1
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DTERM4
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DLNGAM
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(X.LE.0.0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ENDIF
      IF(ALPHA.LE.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ENDIF
    4 FORMAT('***** ERROR--THE FIRST INPUT ARGUMENT ',   &
      'TO THE IGAPDF SUBROUTINE IS NON-POSITIVE *****')
   15 FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO THE ',   &
      'IGAPDF SUBROUTINE IS NON-POSITIVE *****')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
!
      IF(X.LE.R1MACH(1))THEN
        PDF=0.0
        RETURN
      ENDIF
!
      DX=DBLE(X)
      DALPHA=DBLE(ALPHA)
!
      DTERM1=-(DALPHA+1.0D0)*DLOG(DX)
      DTERM2=-1.0D0/DX
      DTERM3=DLNGAM(DALPHA)
      DTERM4=DTERM1+DTERM2-DTERM3
      DPDF=0.0D0
      IF(DTERM4.GE.-80.0D0)DPDF=DEXP(DTERM4)
      PDF=REAL(DPDF)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE IGAPDF
      SUBROUTINE IGAPPF(P,ALPHA,PPF)
!
!     PURPOSE   --PERCENT POINT FUNCTION FOR THE INVERTED GAMMA
!                 DISTRIBUTION.  USES A BISECTION METHOD.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004/6
!     ORIGINAL VERSION--JUNE      2004. PREVIOUSLY IMPLEMENTED AS
!                                       SPECIAL CASE OF GGDPPF
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DP
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION EPS
      DOUBLE PRECISION SIG
      DOUBLE PRECISION ZERO
      DOUBLE PRECISION DMEAN
      DOUBLE PRECISION DSD
      DOUBLE PRECISION XL
      DOUBLE PRECISION XR
      DOUBLE PRECISION XINC
      DOUBLE PRECISION X
      DOUBLE PRECISION FXL
      DOUBLE PRECISION FXR
      DOUBLE PRECISION P1
      DOUBLE PRECISION FCS
      DOUBLE PRECISION XRML
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION CDFL
      DOUBLE PRECISION CDFR
      DOUBLE PRECISION DGAMIP
!
      INCLUDE 'DPCOP2.INC'
!
      DATA EPS /0.0001D0/
      DATA SIG /1.0D-5/
      DATA ZERO /0.0D0/
      DATA MAXIT /5000/
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(P.LT.0.0.OR.P.GE.1.0)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9999
      ENDIF
!
      IF(ALPHA.LE.0.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ELSEIF(ALPHA.LT.0.1)THEN
        WRITE(ICOUT,25)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ENDIF
    1 FORMAT('***** ERROR--THE FIRST ARGUMENT TO IGAPPF ',   &
             'IS OUTSIDE THE ALLOWABLE (0,1] INTERVAL.')
   15 FORMAT('***** ERROR--THE SECOND ARGUMENT TO IGAPPF ',   &
             'IS NON-POSITIVE.')
   25 FORMAT('***** ERROR--THE SECOND ARGUMENT TO IGAPPF ',   &
             'IS < 0.1')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
      IF(P.EQ.0.)THEN
        PPF=0.
        GO TO 9999
      ENDIF
!
!  FIND BRACKETING INTERVAL.
!
      DP=DBLE(P)
      DALPHA=DBLE(ALPHA)
!
      XL=0.0D0
      IF(ALPHA.GT.1.0)THEN
        DMEAN=1.0D0/(DALPHA-1.0D0)
      ELSE
        IF(ALPHA.GE.0.9)THEN
          DMEAN=10.0
        ELSEIF(ALPHA.GE.0.5)THEN
          DMEAN=50.0
        ELSEIF(ALPHA.GE.0.1)THEN
          DMEAN=200.0
          IF(P.GT.0.75)DMEAN=100000.
        ELSE
          DMEAN=500.0
          IF(P.GT.0.75)DMEAN=1000000.
        ENDIF
      ENDIF
      IF(ALPHA.GT.2.0)THEN
        DSD=DSQRT(1.0D0/((DALPHA-1.0D0)**2*(DALPHA-2.0)))
      ELSEIF(ALPHA.GE.0.9)THEN
        DSD=3.0
      ELSEIF(ALPHA.GE.0.5)THEN
        DSD=10.0
      ELSEIF(ALPHA.GE.0.1)THEN
        IF(P.LE.0.75)THEN
          DSD=1000.0
        ELSE
          DSD=10000.0
        ENDIF
      ELSE
        IF(P.LE.0.75)THEN
          DSD=1000.0
        ELSE
          DSD=5000.0
        ENDIF
      ENDIF
!
      XR=DMEAN
      XINC=DSD
      ICOUNT=0
      MAXCNT=20000
!
   91 CONTINUE
      IF(XL.LE.0.0D0)THEN
        CDFL=0.0D0
      ELSE
        CDFL=1.0D0 - DGAMIP(DALPHA,1.0D0/XL)
      ENDIF
      IF(XR.LE.0.0D0)XR=XL+DMEAN
      CDFR=1.0D0 - DGAMIP(DALPHA,1.0D0/XR)
      IF(CDFL.LT.DP .AND. CDFR.LT.DP)THEN
        XL=XR
        XR=XL+XINC
      ELSEIF(CDFL.GT.DP .AND. CDFR.GT.DP)THEN
        XL=XL-XINC
        IF(XL.LT.0.0D0)XL=0.0D0
      ELSE
        GO TO 99
      ENDIF
      ICOUNT=ICOUNT+1
      IF(ICOUNT.GT.MAXCNT)THEN
        WRITE(ICOUT,96)
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9999
      ENDIF
   96 FORMAT('***** ERROR--IGAPPF UNABLE TO FIND BRACKETING ',   &
             'INTERVAL.')
      GO TO 91
!
!  BISECTION METHOD
!
   99 CONTINUE
      IC = 0
      FXL = -DP
      FXR = 1.0D0 - DP
  105 CONTINUE
      X = (XL+XR)*0.5D0
      DCDF=1.0D0 - DGAMIP(DALPHA,1.0D0/X)
      P1=DCDF
      PPF=REAL(X)
      FCS = P1 - DP
      IF(FCS*FXL.GT.ZERO)GO TO 110
      XR = X
      FXR = FCS
      GO TO 115
  110 CONTINUE
      XL = X
      FXL = FCS
  115 CONTINUE
      XRML = XR - XL
      IF(XRML.LE.SIG .AND. ABS(FCS).LE.EPS)GO TO 9999
      IC = IC + 1
      IF(IC.LE.MAXIT)GO TO 105
      WRITE(ICOUT,130)
      CALL DPWRST('XXX','BUG ')
  130 FORMAT('***** ERROR--IGAPPF ROUTINE DID NOT CONVERGE.')
      GO TO 9999
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE IGAPPF
      SUBROUTINE IGARAN(N,GAMMA,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE INVERTED GAMMA DISTRIBUTION
!              WITH TAIL LENGTH PARAMETER VALUE = GAMMA.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --GAMMA  = THE SINGLE PRECISION VALUE OF THE
!                                TAIL LENGTH PARAMETER.
!                                GAMMA SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE INVERTED GAMMA DISTRIBUTION
!             WITH TAIL LENGTH PARAMETER VALUE = GAMMA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --GAMMA SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--XX
!               --JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 2ND. ED., 1994.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--2001.10
!     ORIGINAL VERSION--OCTOBER   2001.
!     UPDATED  VERSION--JANUARY   2005. BUG IF ROUTINE CALLED MORE
!                                       THAN ONCE, RESET AA AND AAA
!                                       AND STORE IN COMMON
!     UPDATED  VERSION--JULY      2021. DO NOT USE GAMMA METHOD
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!CCCC COMMON/SGAMM/AA,AAA
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
    5   FORMAT('***** ERROR--THE FIRST ARGUMENT TO IGARAN IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
   47   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(GAMMA.LE.0.0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO IGARAN IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!CCCC AA=0.0
!CCCC AAA=0.0
!
!     GENERATE N INVERTED GAMMA DISTRIBUTION RANDOM NUMBERS
!     USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD.
!
!     NOTE 6/2004: USE RELATIONSHIP TO GAMMA DISTRIBUTION.
!     NOTE 7/2021: REVERT TO PERCENT POINT METHOD
!
!CCCC C=-1.0
      DO 100 I=1,N
!CCCC   ATEMP=SGAMMA(ISEED,GAMMA)
!CCCC   X(I)=1.0/ATEMP
        CALL IGAPPF(X(I),GAMMA,XTEMP)
        X(I)=XTEMP
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE IGARAN
      SUBROUTINE IGCDF(DX,DGAMMA,DMU,DCDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE INVERSE GAUSSIAN DISTRIBUTION
!              WITH TAIL LENGTH PARAMETER = GAMMA AND SHAPE PARAMETER
!              MU (ALTHOUGH MU IS ESSENTIALLY A SCALE PARAMETER, IT IS
!              NOT A SCALE PARAMETER IN THE TECHNICAL SENSE THAT THE
!              FOLLOWING RELATIONSHIP
!
!                  f(X;LOC,SCALE) = f((X-LOC)/SCALE;0,1)/SCALE
!
!              DOES NOT HOLD. THEREFORE, WE REFER TO IT AS A SHAPE
!              PARAMETER.
!
!              THE STANDARD FORM OF THE DISTRIBUTION IS DEFINED FOR ALL
!              NON-NEGATIVE X AND HAS CUMULATIVE DISTRIBUTION FUNCTION
!              (PAGE 247 OF VOLUME 4 OF THE OF ENCYCLOPEDIA OF
!              STATISTICAL SCIENCES.
!
!                  F(X) = NORCDF(SQRT(GAMMA/X)*(-1 + (X/MU))) +
!                         EXP(2*GAMMA/MU)*NORCDF(SQRT(GAMMA/X)*(1 + (X/MU)))
!
!              THE PARAMETERIZATION DESCRIBED ABOVE WILL BE REFERRED TO
!              AS THE "TWEEDIE" PARAMETERIZATION.  NOTE THAT WHAT WE
!              CALL GAMMA IS CALLED LAMBDA IN MANY REFERENCES.  A
!              RE-PARAMETERIZATION, WHICH WE CALL THE CHAN PARAMETERIZATION,
!              USES
!
!                 SIGMA = SQRT(MU**3/GAMMA)
!
!     NOTE--THE INVERSE GAUSSIAN DISTRIBUTION--
!           1) GOES FROM 0 TO INFINITY
!           2) HAS MEAN = MU
!           3) HAS STANDARD DEVIATION = SQRT((MU**3)/GAMMA) = SIGMA
!           4) HAS SHAPE PARAMETER = GAMMA
!           5) IS HIGHLY-SKEWED AND LONG-TAILED FOR SMALL GAMMA
!           6) IS SYMMETRIC AND MODERATE-TAILED FOR LARGE GAMMA
!           7) APPROACHES NORMALITY AS GAMMA APPROACHES INFINITY
!     INPUT  ARGUMENTS--X      = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE NON-NEGATIVE.
!                     --GAMMA  = THE FIRST SHAPE PARAMETER,
!                                GAMMA SHOULD BE POSITIVE.
!                     --AMU    = THE SECOND SHAPE PARAMETER,
!                                AMU SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--CDF    = THE DOUBLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE DISTRIBUTION FUNCTION
!             VALUE CDF FOR THE INVERSE GAUSSIAN DISTRIBUTION WITH
!             WITH TAIL LENGTH PARAMETER = GAMMA AND SHAP PARAMETER MU.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE.
!                 --GAMMA AND AMU SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NODCDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DEXP.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--KOTZ AND JOHNSON, "ENCYCLOPEDIA OF STATISTICAL SCIENCES",
!                 VOLUME 4, PP. 246-249.
!              --COHEN AND WHITTEN, "PARAMETER ESTIMATION IN RELIABILITY
!                AND LIFE SPAN MODELS", MARCEL DEKKER, INC., CHAPTER 5 AND
!                PP. 360-361.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--90.6
!     ORIGINAL VERSION--MAY       1990.
!     UPDATED         --JANUARY   1995. NEW CDF DEFINITION & REWRITTEN
!     UPDATED         --DECEMBER  1998. USE DOUBLE PRECISION
!     UPDATED         --OCTOBER   2001. BUG FIX.  MISSING SOME
!                                       DOUBLE PRECISION DECLARATIONS
!     UPDATED         --DECEMBER  2003. GENERAL CASE FOR MU (I.E.,
!                                       DON'T ASSUME MU=1)
!     UPDATED         --APRIL     2014. MAKE ARGUMENTS DOUBLE PRECISION
!     UPDATED         --APRIL     2014. SUPPORT CHAN PARAMETERIZATION
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DMU
      DOUBLE PRECISION DGAMMA
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
!CCCC OCTOBER 2001.  ADD FOLLOWING 3 LINES
      DOUBLE PRECISION DTERM4
      DOUBLE PRECISION DTERM5
      DOUBLE PRECISION DTERM6
      DOUBLE PRECISION DTRM12
      DOUBLE PRECISION DTRM14
      DOUBLE PRECISION DPI
!
      INCLUDE 'DPCOST.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      DCDF=0.0D0
!
      IF(DGAMMA.LE.0.0D0)THEN
         WRITE(ICOUT,51)
   51    FORMAT('***** ERROR--THE FIRST SHAPE PARAMETER TO IGCDF IS ',   &
                'NON-POSITIVE.')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,52)DGAMMA
   52    FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
         CALL DPWRST('XXX','BUG ')
         GO TO 9000
      ELSEIF(DMU.LE.0.0D0)THEN
         WRITE(ICOUT,71)
   71    FORMAT('***** ERROR--THE SECOND SHAPE PARAMETER TO IGCDF IS ',   &
                'NON-POSITIVE.')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,52)DMU
         CALL DPWRST('XXX','BUG ')
         GO TO 9000
      ENDIF
!
!     CHECK FOR CHAN PARAMETERIZATION: GAMMA = MU**3/SIGMA**2
!
      IF(IGAUDF.EQ.'CHAN')THEN
        DGAMMA=DMU**3/DGAMMA**2
      ENDIF
!
      IF(DX.GT.0.0D0)THEN
         DPI=3.141592653589793238462643383279503D0
         DTERM1=DSQRT(DGAMMA/DX)
         DTERM2=(-1.0D0+DX/DMU)
         DTERM3=2.0D0*DGAMMA/DMU
         DTERM4=(1.0D0+DX/DMU)
         DTRM12=DTERM1*DTERM2
         DTRM14=(-DTERM1*DTERM4)
         CALL NODCDF(DTRM12,DTERM5)
         CALL NODCDF(DTRM14,DTERM6)
         DCDF=DTERM5+DEXP(DTERM3)*DTERM6
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE IGCDF
      SUBROUTINE IGCHA(DX,DGAMMA,DMU,DHAZ)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE HAZARD
!              FUNCTION VALUE FOR THE INVERSE GAUSSIAN DISTRIBUTION
!              WITH TAIL LENGTH PARAMETER = GAMMA AND SHAPE PARAMETER
!              MU (ALTHOUGH MU IS ESSENTIALLY A SCALE PARAMETER, IT IS
!              NOT A SCALE PARAMETER IN THE TECHNICAL SENSE THAT THE
!              FOLLOWING RELATIONSHIP
!
!                  f(X;LOC,SCALE) = f((X-LOC)/SCALE;0,1)/SCALE
!
!              DOES NOT HOLD. THEREFORE, WE REFER TO IT AS A SHAPE
!              PARAMETER.
!
!              WE COMPUTE THE CUMULATIVE HAZARD FUNCTION IN TERMS OF THE
!              CDF FUNCTION.
!
!              THE DEFAULT PARAMETERIZATION WILL BE REFERRED TO
!              AS THE "TWEEDIE" PARAMETERIZATION.  NOTE THAT WHAT WE
!              CALL GAMMA IS CALLED LAMBDA IN MANY REFERENCES.  A
!              RE-PARAMETERIZATION, WHICH WE CALL THE CHAN PARAMETERIZATION,
!              USES
!
!                 SIGMA = SQRT(MU**3/GAMMA)
!
!     INPUT  ARGUMENTS--X      = THE DOUBLE PRECISION VALUE AT WHICH THE
!                                CUMULATIVE HAZARD FUNCTION IS TO BE
!                                EVALUATED.  X SHOULD BE NON-NEGATIVE.
!                     --GAMMA  = THE FIRST SHAPE PARAMETER,
!                                GAMMA SHOULD BE POSITIVE.
!                     --AMU    = THE SECOND SHAPE PARAMETER,
!                                AMU SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--HAZ    = THE DOUBLE PRECISION CUMULATIVE HAZARD
!                                FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE HAZARD FUNCTION VALUE HAZ
!             FOR THE INVERSE GAUSSIAN DISTRIBUTION.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE POSITIVE.
!                 --GAMMA AND MU SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--IGCDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--KOTZ AND JOHNSON, "ENCYCLOPEDIA OF STATISTICAL SCIENCES",
!                 VOLUME 4, PP. 246-249.
!              --COHEN AND WHITTEN, "PARAMETER ESTIMATION IN RELIABILITY
!                AND LIFE SPAN MODELS", MARCEL DEKKER, INC., CHAPTER 5 AND
!                PP. 360-361.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--98.4
!     ORIGINAL VERSION--APRIL     1998.
!     UPDATED         --DECEMBER  2003.
!     UPDATED         --APRIL     2014. CONVERT TO DOUBLE PRECISION
!     UPDATED         --APRIL     2014. SUPPORT FOR CHAN PARAMETERIZATION
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DGAMMA
      DOUBLE PRECISION DMU
      DOUBLE PRECISION DHAZ
      DOUBLE PRECISION DCDF
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT---------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      DHAZ=0.0D0
      IF(DGAMMA.LE.0.0D0)THEN
         WRITE(ICOUT,51)
   51    FORMAT('***** ERROR--THE FIRST SHAPE PARAMETER TO IGCHA IS ',   &
                'NON-POSITIVE.')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,52)DGAMMA
   52    FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
         CALL DPWRST('XXX','BUG ')
         GO TO 9000
      ELSEIF(DMU.LE.0.0D0)THEN
         WRITE(ICOUT,71)
   71    FORMAT('***** ERROR--THE SECOND SHAPE PARAMETER TO IGCHA IS ',   &
                'NON-POSITIVE.')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,52)DMU
         CALL DPWRST('XXX','BUG ')
         GO TO 9000
      ELSEIF(DX.LT.0.0D0)THEN
         WRITE(ICOUT,61)
   61    FORMAT('***** ERROR--THE FIRST ARGUMENT TO IGCHA IS ',   &
                'NON-POSITIVE.')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,52)DX
         CALL DPWRST('XXX','BUG ')
         GO TO 9000
      ENDIF
!
      IF(DX.EQ.0.0D0)GO TO 9000
!
      CALL IGCDF(DX,DGAMMA,DMU,DCDF)
      DCDF=1.0D0 - DCDF
      IF(DCDF.GT.0.0D0)THEN
        DHAZ=-DLOG(DCDF)
      ELSE
        WRITE(ICOUT,162)DX
  162   FORMAT('***** FOR THE VALUE OF THE ARGUMENT ',G15.7,   &
               ' THE CDF IS ESSENTIALLY 0, CUMULATIVE HAZARD SET TO 0.')
        CALL DPWRST('XXX','BUG ')
        DHAZ=0.0D0
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE IGCHA
      SUBROUTINE IGHAZ(DX,DGAMMA,DMU,DHAZ)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE HAZARD
!              FUNCTION VALUE FOR THE INVERSE GAUSSIAN DISTRIBUTION
!              WITH TAIL LENGTH PARAMETER = GAMMA AND SHAPE PARAMETER
!              MU (ALTHOUGH MU IS ESSENTIALLY A SCALE PARAMETER, IT IS
!              NOT A SCALE PARAMETER IN THE TECHNICAL SENSE THAT THE
!              FOLLOWING RELATIONSHIP
!
!                  f(X;LOC,SCALE) = f((X-LOC)/SCALE;0,1)/SCALE
!
!              DOES NOT HOLD. THEREFORE, WE REFER TO IT AS A SHAPE
!              PARAMETER.
!
!              WE COMPUTE THE HAZARD FUNCTION IN TERMS OF THE PDF AND
!              CDF FUNCTIONS.
!
!              THE DEFAULT PARAMETERIZATION WILL BE REFERRED TO
!              AS THE "TWEEDIE" PARAMETERIZATION.  NOTE THAT WHAT WE
!              CALL GAMMA IS CALLED LAMBDA IN MANY REFERENCES.  A
!              RE-PARAMETERIZATION, WHICH WE CALL THE CHAN PARAMETERIZATION,
!              USES
!
!                 SIGMA = SQRT(MU**3/GAMMA)
!
!     INPUT  ARGUMENTS--X      = THE DOUBLE PRECISION VALUE AT WHICH THE
!                                HAZARD FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE NON-NEGATIVE.
!                     --GAMMA  = THE FIRST SHAPE PARAMETER,
!                                GAMMA SHOULD BE POSITIVE.
!                     --AMU    = THE SECOND SHAPE PARAMETER,
!                                AMU SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--HAZ    = THE DOUBLE PRECISION HAZARD FUNCTION
!                                VALUE.
!     OUTPUT--THE DOUBLE PRECISION HAZARD FUNCTION VALUE HAZ FOR THE
!             INVERSE GAUSSIAN DISTRIBUTION.
!     PURPOSE--THIS SUBROUTINE COMPUTES THE HAZARD
!              FUNCTION VALUE FOR THE INVERSE GAUSSIAN DISTRIBUTION
!              WITH TAIL LENGTH PARAMETER = GAMMA
!              AND SHAPE PARAMETER = MU.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE POSITIVE.
!                 --GAMMA AND MU SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--IGPDF AND IGCDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--KOTZ AND JOHNSON, "ENCYCLOPEDIA OF STATISTICAL SCIENCES",
!                 VOLUME 4, PP. 246-249.
!              --COHEN AND WHITTEN, "PARAMETER ESTIMATION IN RELIABILITY
!                AND LIFE SPAN MODELS", MARCEL DEKKER, INC., CHAPTER 5 AND
!                PP. 360-361.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--98.4
!     ORIGINAL VERSION--APRIL     1998.
!     UPDATED  VERSION--DECEMBER  2003.
!     UPDATED         --APRIL     2014. CONVERT TO DOUBLE PRECISION
!     UPDATED         --APRIL     2014. SUPPORT FOR CHAN PARAMETERIZATION
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DGAMMA
      DOUBLE PRECISION DMU
      DOUBLE PRECISION DHAZ
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DPDF
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      DHAZ=0.0D0
      IF(DGAMMA.LE.0.0D0)THEN
         WRITE(ICOUT,51)
   51    FORMAT('***** ERROR--THE FIRST SHAPE PARAMETER TO IGHAZ IS ',   &
                'NON-POSITIVE.')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,52)DGAMMA
   52    FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
         CALL DPWRST('XXX','BUG ')
         GO TO 9000
      ELSEIF(DMU.LE.0.0D0)THEN
         WRITE(ICOUT,71)
   71    FORMAT('***** ERROR--THE SECOND SHAPE PARAMETER TO IGHAZ IS ',   &
                'NON-POSITIVE.')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,52)DMU
         CALL DPWRST('XXX','BUG ')
         GO TO 9000
      ELSEIF(DX.LT.0.0D0)THEN
         WRITE(ICOUT,61)
   61    FORMAT('***** ERROR--THE FIRST ARGUMENT TO IGHAZ IS ',   &
                'NON-POSITIVE.')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,52)DX
         CALL DPWRST('XXX','BUG ')
         GO TO 9000
      ENDIF
!
      IF(DX.EQ.0.0D0)GO TO 9000
!
      CALL IGPDF(DX,DGAMMA,DMU,DPDF)
      CALL IGCDF(DX,DGAMMA,DMU,DCDF)
      DCDF=1.0D0 - DCDF
      IF(DCDF.GT.0.0D0)THEN
        DHAZ=DPDF/DCDF
      ELSE
        WRITE(ICOUT,162)DX
  162   FORMAT('***** FOR THE VALUE OF THE ARGUMENT, ',   &
               G15.7,', THE CDF IS ESSENTIALLY 0, HAZARD SET TO 0.')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE IGHAZ
      SUBROUTINE IGLI1(Y,N,ICASPL,ALOC,AMU,GAMMA,   &
                       ALIK,AIC,AICC,BIC,   &
                       ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE LIKELIHOOD FUNCTION FOR
!              THE INVERSE GUASSIAN DISTRIBUTION.  THIS IS
!              FOR THE RAW DATA CASE (I.E., NO GROUPING AND NO CENSORING).
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2014/4
!     ORIGINAL VERSION--APRIL     2014.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DLOC
      DOUBLE PRECISION DMU
      DOUBLE PRECISION DG
      DOUBLE PRECISION DN
      DOUBLE PRECISION DNP
      DOUBLE PRECISION DLIK
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DPI
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      DATA DPI/3.14159265358979D+00/
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='IGLI'
      ISUBN2='1   '
      IERROR='NO'
!
      ALIK=CPUMIN
      AIC=CPUMIN
      AICC=CPUMIN
      BIC=CPUMIN
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'GLI1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF IGLI1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,ICASPL
   52   FORMAT('IBUGA3,ISUBRO,ICASPL = ',2(A4,2X),A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,55)N,ALOC,AMU,GAMMA
   55   FORMAT('N,ALOC,AMU,GAMMA = ',I8,3G15.7)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  COMPUTE LIKELIHOOD FUNCTION         **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'GLI1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IERROR='NO'
      IWRITE='OFF'
      IF(ICASPL.EQ.'2IGA')ALOC=0.0
!
!     LOG-LIKELIHOOD FUNCTION IS:
!
!     (N/2)*LOG(GAMMA/(2*PI)) -
!     (3/2)*SUM[i=1 to N][LOG(Y(i) - LOC)] -
!     (GAMMA/(2*MU**2))*SUM[i=1 to N][(Y(i)-LOC-MU)**2/(Y(i)-LOC)]
!
      DN=DBLE(N)
      DLOC=DBLE(ALOC)
      DMU=DBLE(AMU)
      DG=DBLE(GAMMA)
!
      DTERM1=(DN/2.0D0)*DLOG(DG/(2.0D0*DPI))
      DSUM1=0.0D0
      DSUM2=0.0D0
!
      DO 1010 I=1,N
        DX=DBLE(Y(I))
        DSUM1=DSUM1 + DLOG(DX-DLOC)
        DSUM2=DSUM2 + (DX-DLOC-DMU)**2/(DX-DLOC)
 1010 CONTINUE
!
      DLIK=DTERM1 - 1.5D0*DSUM1 - (DG/(2.0D0*DMU**2))*DSUM2
      ALIK=REAL(DLIK)
      DNP=2.0D0
      IF(ICASPL.EQ.'3IGA')DNP=3.0
      AIC=REAL(-2.0D0*DLIK + 2.0D0*DNP)
      DTERM3=(2.0D0*DNP*(DNP+1.0D0))/(DN-DNP-1.0D0)
      AICC=REAL(-2.0D0*DLIK + 2.0D0*DNP + DTERM3)
      BIC=REAL(-2.0D0*DLIK + DNP*LOG(DN))
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'GLI1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF IGLI1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)DSUM1,DSUM2,DTERM1
 9013   FORMAT('DSUM1,DSUM2,DTERM1 = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9014)ALIK,AIC,AICC,BIC
 9014   FORMAT('ALIK,AIC,AICC,BIC = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE IGLI1
      SUBROUTINE IGLI2(Y,X,N,NTOT,ICASPL,ALOC,AMU,GAMMA,   &
                       ALIK,AIC,AICC,BIC,   &
                       ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE LIKELIHOOD FUNCTION FOR THE
!              INVERSE GUASSIAN DISTRIBUTION FOR GROUPED DATA WITH
!              EQUAL BIN SIZES (I.E., X DENOTES THE BIN MID-POINTS) AND
!              NO  CENSORING.
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2014/4
!     ORIGINAL VERSION--APRIL     2014.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DW
      DOUBLE PRECISION DLOC
      DOUBLE PRECISION DMU
      DOUBLE PRECISION DGAMMA
      DOUBLE PRECISION DN
      DOUBLE PRECISION DNP
      DOUBLE PRECISION DLIK
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DPDF
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='IGL2'
      ISUBN2='1   '
      IERROR='NO'
!
      ALIK=CPUMIN
      AIC=CPUMIN
      AICC=CPUMIN
      BIC=CPUMIN
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'GLI2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF IGLI2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,ICASPL
   52   FORMAT('IBUGA3,ISUBRO,ICASPL = ',2(A4,2X),A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,55)N,ALOC,AMU,GAMMA
   55   FORMAT('N,ALOC,AMU,GAMMA = ',I8,3G15.7)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I),X(I)
   57     FORMAT('I,Y(I),X(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  COMPUTE LIKELIHOOD FUNCTION         **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'GLI2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IERROR='NO'
      IWRITE='OFF'
      IF(ICASPL.EQ.'2IGA')ALOC=0.0
!
!     NOTE THAT THE INVERSE GAUSSIAN MAY SUPPORT AN OPTIONAL
!     LOCATION PARAMETER.  HOWEVER, THE SCALE PARAMETER IS NOT
!     TYPICALLY USED SINCE MU IS ESSENTIALLY A SCALE PARAMETER
!     (ALTHOUGH NOT IN THE STRICT TECHNICAL SENSE).  THE SCALE
!     PARAMETER IS NOT SUPPORTED HERE.
!
      DGAMMA=DBLE(GAMMA)
      DMU=DBLE(AMU)
      DLOC=DBLE(ALOC)
      DLIK=0.0D0
      DN=DBLE(NTOT)
!
      DO 1010 I=1,N
        IF(Y(I).LE.0.0)GO TO 1010
        DX=DBLE(X(I)) - DLOC
        DW=DBLE(Y(I))
        CALL IGPDF(DX,DGAMMA,DMU,DPDF)
        IF(DPDF.LE.0.0D0)THEN
          IERROR='YES'
          GO TO 9000
        ENDIF
        DLIK=DLIK + DLOG(DW*DPDF)
!
        IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'GLI2')THEN
          WRITE(ICOUT,1011)I,DX,DW,DPDF,DLIK
 1011     FORMAT('I,DX,DW,DPDF,DLIK = ',I8,4G15.7)
          CALL DPWRST('XXX','WRIT')
        ENDIF
!
 1010 CONTINUE
!
      ALIK=REAL(DLIK)
      DNP=2.0D0
      IF(ICASPL.EQ.'3IGA')DNP=3.0
      AIC=REAL(-2.0D0*DLIK + 2.0D0*DNP)
      DTERM3=(2.0D0*DNP*(DNP+1.0D0))/(DN-DNP-1.0D0)
      AICC=REAL(-2.0D0*DLIK + 2.0D0*DNP + DTERM3)
      BIC=REAL(-2.0D0*DLIK + DNP*LOG(DN))
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'GLI2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF IGLI2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9014)ALIK,AIC,AICC,BIC
 9014   FORMAT('ALIK,AIC,AICC,BIC = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE IGLI2
      SUBROUTINE IGML1(Y,N,PSTAMV,   &
                       XMEAN,XSD,XMIN,XSKEW,   &
                       ALOCML,AMUML,SIGMML,GAMMML,   &
                       ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES MAXIMUM LIKELIHOOD ESTIMATES
!              FOR THE 3-PARAMETER INVERSE GAUSSIAN DISTRIBUTION.
!
!              THIS IS FOR THE UNCENSORED, UPGROUPED CASE.
!
!              NOTE THAT THERE ARE SEVERAL PARAMETERIZATIONS OF THE
!              INVERSE GAUSSIAN DISTRIBUTION.
!
!              1) DATAPLOT USES THE TWEEDIE PARAMETERIZATION.  THIS
!                 PARAMETERIZATION HAS SHAPE PARAMETERS MU AND GAMMA
!                 (COHEN CALLS THE GAMMA PARAMETER LAMBDA) AND A
!                 THRESHOLD (LOCATION) PARAMETER.  COHEN USES GAMMA
!                 FOR THE THRESHOLD PARAMETER.
!
!              2) THE COHEN ALGORITHM ESTIMATES THE PARAMETERS BASED
!                 ON THE CHAN RE-PARAMETERIZATION:
!
!                    GAMMA = LAMBDA
!                          = MU**3/SIGMA**2
!
!                 THE COHEN/WHITTEN ALGORITHM GIVEN HERE ESTIMATES THE
!                 LOCATION PARAMETER, MU, AND SIGMA.  NOTE THAT GAMMA
!                 CAN BE COMPUTED FROM THE MU AND SIGMA.
!
!                 NOTE THAT NO ESTIMATION WILL BE PERFORMED FOR THE
!                 CASE WHERE THE SKEWNESS PARAMETER IS NEGATIVE.
!
!     REFERENCE--COHEN AND WHITTEN, "PARAMETER ESTIMATION IN RELIABILITY
!                AND LIFE SPAN MODELS", MARCEL DEKKER, INC., CHAPTER 5 AND
!                PP. 360-361.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2014/4
!     ORIGINAL VERSION--APRIL     2014
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      REAL Y(*)
!
      DOUBLE PRECISION AMOM(3)
      DOUBLE PRECISION VML(5)
      DOUBLE PRECISION TL
      DOUBLE PRECISION TU
      DOUBLE PRECISION T
      DOUBLE PRECISION FL
      DOUBLE PRECISION FU
      DOUBLE PRECISION F
      DOUBLE PRECISION EPS
      DOUBLE PRECISION DN
      DOUBLE PRECISION BOUND
      DOUBLE PRECISION STEP
      DOUBLE PRECISION S1
      DOUBLE PRECISION S2
      DOUBLE PRECISION S3
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*40 IDIST
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='IGML'
      ISUBN2='1   '
      IERROR='NO'
!
      ALOCML=CPUMIN
      AMUML=CPUMIN
      SIGMML=CPUMIN
      GAMMML=CPUMIN
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'GML1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF IGML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N,PSTAMV
   52   FORMAT('IBUGA3,ISUBRO,N,PSTAMV = ',2(A4,2X),I8,G15.7)
        CALL DPWRST('XXX','WRIT')
        DO 55 I=1,N
          WRITE(ICOUT,54)I,Y(I)
   54     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   55   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  CARRY OUT CALCULATIONS FOR THE      **
!               **  INVERSE GAUSSIAN ML     ESTIMATES   **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'GML1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IFLAG=0
      IDIST='INVERSE GAUSSIAN'
      CALL SUMRAW(Y,N,IDIST,IFLAG,   &
                  XMEAN,XVAR,XSD,XMIN,XMAX,   &
                  ISUBRO,IBUGA3,IERROR)
      AMOM(1)=DBLE(XMEAN)
      AMOM(2)=DBLE(XSD)
      AMOM(3)=DBLE(XSKEW)
!
      IF(XSKEW.LE.0.0)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
  101   FORMAT('***** ERROR IN INVERSE GAUSSIAN MLE ESTIMATION--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,112)
  112   FORMAT('      THE SAMPLE SKEWNESS IS NON-POSTIVE.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,113)XSKEW
  113   FORMAT('      SKEWNESS = ',G15.7)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ELSEIF(N.LT.5)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,122)
  122   FORMAT('      THE SAMPLE SIZE IS LESS THAN FIVE.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,123)N
  123   FORMAT('      SAMPLE SIZE  = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ******************************************
!               **  STEP 2--                            **
!               **  ML     ESTIMATES                    **
!               ******************************************
!
      ISTEPN='2'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'GML1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     IN CODE BELOW:
!
!        VML(1) = ESTIMATE OF LOCATION
!        VML(2) = ESTIMATE OF MU
!        VML(3) = ESTIMATE OF SIGMA
!        VML(4) = ESTIMATE OF MEAN
!               = LOC + MU
!        VML(5) = A3 (THIRD STANDARD MOMENT)
!               = 3*SIGMA/MU
!     CODE FROM PAGE 360-361 OF COHEN AND WHITTEN
!
      IERR=0
      EPS=0.1D-08
      DN=DBLE(N)
!
!     PLACE A LOWER BOUND ON THE LOCATION PARAMETER AND SET THE INITIAL
!     GUESS TO THE MINIMUM MINUS AN EPSILON (THIS WILL ALSO BE THE UPPER
!     BOUND.
!
      BOUND=DBLE(XMIN) - 30.0D0*AMOM(2)
      STEP=AMOM(2)/50.0D0
      TU=DBLE(XMIN) - EPS
      S1=0.0D0
      S2=0.0D0
      S3=0.0D0
      DO 211 I=1,N
        DX=DBLE(Y(I))
        S3=S3 + (DX-AMOM(1))**2/(DX-TU)
        S2=S2 + 1.0D0/(DX-TU)
        S1=S1 + 1.0D0/(DX-TU)**2
  211 CONTINUE
      FU=3.0D0*S3*S2/DN + DN - (AMOM(1)-TU)**2*S1
!
!     LOCATE A LOWER BOUND FOR THE LOCATION AND CHECK THAT IT IS IN
!     THE INTERVAL (TL,TU).
!
      TL=XMIN
      FL=FU
!
  300 CONTINUE
      IF(FL*FU.GT.0.0D0)THEN
        TL=TL-STEP
        IF(TL.LT.BOUND)THEN
          IERROR='YES'
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,101)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,322)
  322     FORMAT('      UNABLE TO FIND BRACKETING INTERVAL FOR THE ',   &
                 'LOCATION PARMETER.')
          CALL DPWRST('XXX','WRIT')
          GO TO 9000
        ELSE
          S1=0.0D0
          S2=0.0D0
          S3=0.0D0
          DO 311 I=1,N
            DX=DBLE(Y(I))
            S3=S3 + (DX-AMOM(1))**2/(DX-TL)
            S2=S2 + 1.0D0/(DX-TL)
            S1=S1 + 1.0D0/(DX-TL)**2
  311     CONTINUE
          FL=3.0D0*S3*S2/DN + DN - (AMOM(1)-TL)**2*S1
          GO TO 300
        ENDIF
      ELSE
!
!       USE BINARY SEARCH TO FIND THE ESTIMATE OF THE LOCATION PARAMETER.
!
  400   CONTINUE
        T=(TU+TL)/2.0D0
        S1=0.0D0
        S2=0.0D0
        S3=0.0D0
        DO 411 I=1,N
          DX=DBLE(Y(I))
          S3=S3 + (DX-AMOM(1))**2/(DX-T)
          S2=S2 + 1.0D0/(DX-T)
          S1=S1 + 1.0D0/(DX-T)**2
  411   CONTINUE
        F=3.0D0*S3*S2/DN + DN - (AMOM(1)-T)**2*S1
        IF(DABS(T-TL).GT.EPS)THEN
          IF(F*FL.LT.0.0D0)THEN
            TU=T
          ELSE
            TL=T
            FL=F
          ENDIF
          GO TO 400
        ELSE
          VML(2)=(AMOM(1) - T)
          VML(3)=DSQRT(VML(2)/DN*S3)
          VML(1)=T
          VML(4)=VML(2)+ VML(1)
          VML(5)=3.0D0*VML(3)/VML(2)
        ENDIF
      ENDIF
!
      ALOCML=REAL(VML(1))
      AMUML=REAL(VML(2))
      SIGMML=REAL(VML(3))
      GAMMML=REAL(VML(2)**3/VML(3)**2)
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'GML1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF IGML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9012)ALOCML,AMUML,SIGMML,GAMMML
 9012   FORMAT('ALOCML,AMUML,SIGMML,GAMMML = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE IGML1
      SUBROUTINE IGML5(ALOC,AMU,SIGMA,GAMMA,N,ICASAN,IGAUDF,COV,   &
                       XTEMP,ITEMP,MAXNXT,   &
                       ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE PARAMETER VARIANCE-COVARIANCE
!              MATRIX FOR THE 3-PARAMETER INVERSE GAUSSIAN DISTRIBUTION.
!
!              NOTE THAT THERE ARE 2 COMMON PARAMETERIZATIONS FOR THE
!              IVERSE GAUSSIAN DISTRIBUTION.
!
!              FOR THE CHAN/COHEN AND WHITEN PARAMETERIZATION:
!
!              THE EXPECTED INFORMATION MATRIX IS OBTAINED FROM THE
!              FOLLOWING QUANTITIES (3-PARAMETER CASE):
!
!                 I(1,1) = (N/SIGMA**2)*[7*A3**4*((A3**2/9) + 1)/54 +
!                          (A3**2/2) + 1]
!                 I(1,2) = (N/SIGMA**2)*((A3/2)*((A3**2/9) + 1) + 1)
!                 I(1,3) = -(N/SIGMA**2)*A3*((A3**2/9) + 1)
!                 I(2,2) = (N/SIGMA**2)*((A3**2/2) + 1)
!                 I(2,3) = -(N/SIGMA**2)*A3
!                 I(3,3) = 2*N/SIGMA**2
!
!              WHERE A3 = 3*SIGMA/MU
!
!              THE PARAMETER VARIANCE-COVARIANCE MATRIX IS THE
!              INVERSE OF THE INFORMATION MATRIX.
!
!              FOR THE ORIGINAL TWEEDIE PARAMETERIZATION, THE COVARIANCE
!              MATRIX TERMS ARE SIGMA(I,J)/D WHERE
!
!                 SIGMA(1,1) = 0.5/(GAMMA*MU**3)
!                 SIGMA(1,2) = -0.5/(GAMMA*MU**3)
!                 SIGMA(1,3) = -1.5*((1/MU**4) + 1/(GAMMA*MU**3))
!                 SIGMA(2,3) = 1.5*((1/MU**4) + 1/(GAMMA*MU**3))
!                 SIGMA(2,2) = 0.5*MU**3/GAMMA + 0.75/(GAMMA**3*MU) +
!                              3/GAMMA**4
!                 SIGMA(3,3) = 4.5*GAMMA/MU**5 + 10.5/MU**4 +
!                              10.5/(GAMMA*MU**3)
!
!                 D=0.75/(GAMMA**2*MU**4) + 3/(GAMMA**3*MU**3)
!
!
!     REFERENCE--COHEN AND WHITTEN (1988), "PARAMETER ESTIMATION IN
!                RELIABILITY AND LIFE SPAN MODELS", MARCEL DEKKER, INC.,
!                CHAPTER 5.
!              --CHENG AND AMIN (1981), "MAXIMUM LIKELIHOOD ESTIMATION
!                OF PARAMETERS IN THE INVERSE GAUSSIAN DISTRIBUTION,
!                WITH UNKNOWN ORIGIN", TECHNOMETRICS, VOL. 23, NO. 3,
!                PP. 257-263.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2014/4
!     ORIGINAL VERSION--APRIL     2014
!
      REAL XTEMP(*)
      REAL FISH(3,3)
      REAL COV(3,3)
!
      INTEGER ITEMP(*)
!
      CHARACTER*4 ICASAN
      CHARACTER*4 IGAUDF
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DLOC
      DOUBLE PRECISION DSIGMA
      DOUBLE PRECISION DMU
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION A3
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='IGML'
      ISUBN2='5   '
      IWRITE='OFF'
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'IML5')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF IGML5--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,ICASAN,IGAUDF,N
   52   FORMAT('IBUGA3,ISUBRO,ICASAN,IGAUDF,N = ',4(A4,2X),I8)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,54)ALOC,SIGMA,AMU,GAMMA
   54   FORMAT('ALOC,SIGMA,AMU,GAMMA = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  CARRY OUT CALCULATIONS              **
!               **  FOR VARIANCE-COVARIANCE MATRIX      **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'IML5')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      DO 101 J=1,3
        DO 103 I=1,3
          FISH(I,J)=CPUMIN
          COV(I,J)=CPUMIN
  103   CONTINUE
  101 CONTINUE
!
      DN=REAL(N)
      DLOC=DBLE(ALOC)
      DSIGMA=DBLE(SIGMA)
      DMU=DBLE(AMU)
      DGAMMA=DBLE(GAMMA)
      A3=3.0D0*DSIGMA/DMU
!
!     CHAN PARAMETERIZATION
!
      IF(IGAUDF.EQ.'CHAN')THEN
!
!       2-PARAMETER CASE
!
        IF(ICASAN.EQ.'2IGA')THEN
          DTERM1=DSIGMA**2/DN
          COV(1,1)=REAL(DTERM1)
          COV(2,2)=REAL((DTERM1/2.0D0)*((A3**2/2.0D0) + 1.0D0))
          COV(1,2)=REAL(DTERM1*A3/2.0D0)
          COV(2,1)=COV(1,2)
          GO TO 9000
        ENDIF
!
!     3-PARAMETER CASE
!
        DTERM1=DN/DSIGMA**2
        DTERM2=7.0D0*A3**4*((A3**2/9.0D0) + 1.0D0)/54.0D0 +   &
               (A3**2/2.0D0) + 1.0D0
        FISH(1,1)=REAL(DTERM1*DTERM2)
        DTERM2=(A3**2/2.0D0)*((A3**2/9.0D0) + 1.0D0) + 1.0D0
        FISH(1,2)=REAL(DTERM1*DTERM2)
        DTERM2=A3*((A3**2/9.0D0) + 1.0D0)
        FISH(1,3)=REAL(-DTERM1*DTERM2)
        FISH(2,2)=REAL(DTERM1*((A3**2/2.0D0) + 1.0D0))
        FISH(2,3)=REAL(-DTERM1*A3)
        FISH(3,3)=REAL(2.0D0*DTERM1)
        FISH(2,1)=FISH(1,2)
        FISH(3,1)=FISH(1,3)
        FISH(3,2)=FISH(2,3)
!
        IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'IML5')THEN
          DO 120 I=1,3
            WRITE(ICOUT,121)FISH(I,1),FISH(I,2),FISH(I,3)
  121       FORMAT('FISH(I,1),FISH(I,2),FISH(I,3) = ',3G15.7)
            CALL DPWRST('XXX','WRIT')
  120     CONTINUE
        ENDIF
!
        CALL SGECO(FISH,3,3,ITEMP,RCOND,XTEMP)
        IJOB=1
        CALL SGEDI(FISH,3,3,ITEMP,XTEMP,XTEMP(MAXNXT/2),IJOB)
        DO 130 J=1,3
          DO 135 I=1,3
            COV(I,J)=FISH(I,J)
  135     CONTINUE
  130   CONTINUE
!
!     TWEEDIE PARAMETERIZATION
!
      ELSE
        DTERM2=DGAMMA*DMU**3
        D=0.75D0/(DGAMMA**2*DMU**4) + 3.0D0/(DGAMMA**3*DMU**3)
!
        DTERM1=0.5D0/DTERM2
        COV(1,1)=REAL(DTERM1/D)
        DTERM1=-0.5D0/DTERM2
        COV(1,2)=REAL(DTERM1/D)
        DTERM1=-1.5D0*((1.0D0/DMU**4) + (1.0D0/DTERM2))
        COV(1,3)=REAL(DTERM1/D)
        DTERM1=1.5D0*((1.0D0/DMU**4) + (1.0D0/DTERM2))
        COV(2,3)=REAL(DTERM1/D)
        DTERM1=(0.5D0/DTERM2) + 0.75D0/(DGAMMA**3*DMU) +   &
               3.0D0/DGAMMA**4
        COV(2,2)=REAL(DTERM1/D)
        DTERM1=(4.5D0/(DGAMMA*DMU**5)) + (10.5D0/DMU**4) +   &
               (10.5D0/DTERM2)
        COV(3,3)=REAL(DTERM1/D)
        COV(2,1)=COV(1,2)
        COV(3,1)=COV(1,3)
        COV(3,2)=COV(2,3)
!
      ENDIF
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'GML5')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF IGML5--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9012)RCOND
 9012   FORMAT('RCOND = ',G15.7)
        CALL DPWRST('XXX','WRIT')
        DO 9020 I=1,3
          WRITE(ICOUT,9021)COV(I,1),COV(I,2),COV(I,3)
 9021     FORMAT('COV(I,1),COV(I,2),COV(I,3) = ',3G15.7)
          CALL DPWRST('XXX','WRIT')
 9020   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE IGML5
      SUBROUTINE IGMO1(XMEAN,XSD,XMIN,XSKEW,N,PSTAMV,   &
                       ALOCMO,AMUMO,SIGMMO,GAMMMO,   &
                       ALOCMM,AMUMM,SIGMMM,GAMMMM,   &
                       ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES MOMENT AND MODIFIED MOMENT
!              ESTIMATES FOR THE 3-PARAMETER INVERSE GAUSSIAN
!              DISTRIBUTION.  THE INPUT VALUES ARE:
!
!                 XMEAN   - THE SAMPLE MEAN
!                 XSD     - THE SAMPLE STANDARD DEVIATION
!                 XSKEW   - THE SAMPLE SKEWNESS
!                 XMIN    - THE SAMPLE MINIMUM
!
!              THIS IS FOR THE UNCENSORED CASE.
!
!              NOTE THAT THERE ARE SEVERAL PARAMETERIZATIONS OF THE
!              INVERSE GAUSSIAN DISTRIBUTION.
!
!              1) DATAPLOT USES THE TWEEDIE PARAMETERIZATION.  THIS
!                 PARAMETERIZATION HAS SHAPE PARAMETERS MU AND GAMMA
!                 (COHEN CALLS THE GAMMA PARAMETER LAMBDA) AND A
!                 THRESHOLD (LOCATION) PARAMETER.  COHEN USES GAMMA
!                 FOR THE THRESHOLD PARAMETER.
!
!              2) THE COHEN ALGORITHM ESTIMATES THE PARAMETERS BASED
!                 ON THE CHAN RE-PARAMETERIZATION:
!
!                    GAMMA = LAMBDA
!                          = MU**3/SIGMA**2
!
!                 THE COHEN/WHITTEN ALGORITHM GIVEN HERE ESTIMATES THE
!                 LOCATION PARAMETER, MU, AND SIGMA.  NOTE THAT GAMMA
!                 CAN BE COMPUTED FROM THE MU AND SIGMA.
!
!                 NOTE THAT NO ESTIMATION WILL BE PERFORMED FOR THE
!                 CASE WHERE THE SKEWNESS PARAMETER IS NEGATIVE.
!
!     REFERENCE--COHEN AND WHITTEN, "PARAMETER ESTIMATION IN RELIABILITY
!                AND LIFE SPAN MODELS", MARCEL DEKKER, INC., CHAPTER 5 AND
!                PP. 357-359.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2014/4
!     ORIGINAL VERSION--APRIL     2014
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION AMOM(3)
      DOUBLE PRECISION VMOM(5)
      DOUBLE PRECISION VMMOM(5)
      DOUBLE PRECISION A3
      DOUBLE PRECISION A3L
      DOUBLE PRECISION A3U
      DOUBLE PRECISION FL
      DOUBLE PRECISION FU
      DOUBLE PRECISION F
      DOUBLE PRECISION EPS
      DOUBLE PRECISION DN
      DOUBLE PRECISION DNN
      DOUBLE PRECISION Z
      DOUBLE PRECISION P1
      DOUBLE PRECISION P2
      DOUBLE PRECISION VAL
      DOUBLE PRECISION VAL1
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='IGMO'
      ISUBN2='1   '
      IERROR='NO'
!
      ALOCMO=CPUMIN
      AMUMO=CPUMIN
      SIGMMO=CPUMIN
      GAMMMO=CPUMIN
      ALOCMM=CPUMIN
      AMUMM=CPUMIN
      SIGMMM=CPUMIN
      GAMMMM=CPUMIN
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'GMO1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF IGMO1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO
   52   FORMAT('IBUGA3,ISUBRO = ',A4,2X,A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,54)XMEAN,XSD,XMIN,XSKEW
   54   FORMAT('XMEAN,XSD,XMIN,XSKEW = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  CARRY OUT CALCULATIONS FOR THE      **
!               **  INVERSE GAUSSIAN MOMENT ESTIMATES   **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'GMO1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(XMEAN.EQ.CPUMIN .OR. XMEAN.EQ.PSTAMV)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
  101   FORMAT('***** ERROR IN GAMMA MOMENT ESTIMATION--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,102)
  102   FORMAT('      THE SAMPLE MEAN IS UNDEFINED.')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ELSEIF(XSD.EQ.CPUMIN .OR. XSD.EQ.PSTAMV .OR. XSD.LE.0.0)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,107)
  107   FORMAT('      THE SAMPLE STANDARD DEVIATION IS UNDEFINED OR ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ELSEIF(XSKEW.LE.0.0)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,112)
  112   FORMAT('      THE SAMPLE SKEWNESS IS NON-POSTIVE.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,113)XSKEW
  113   FORMAT('      SKEWNESS = ',G15.7)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ELSEIF(N.LT.5)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,122)
  122   FORMAT('      THE SAMPLE SIZE IS LESS THAN FIVE.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,123)N
  123   FORMAT('      SAMPLE SIZE  = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ******************************************
!               **  STEP 2--                            **
!               **  MOMENT ESTIMATES                    **
!               ******************************************
!
      ISTEPN='2'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'GMO1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     IN CODE BELOW:
!
!        VMOM(1) = ESTIMATE OF LOCATION
!        VMOM(2) = ESTIMATE OF MU
!        VMOM(3) = ESTIMATE OF SIGMA
!        VMOM(4) = ESTIMATE OF MEAN
!                = LOC + MU
!        VMOM(5) = A3 (THIRD STANDARD MOMENT)
!                = 3*SIGMA/MU
!     CODE FROM PAGE 357 OF COHEN AND WHITTEN
!
      AMOM(1)=DBLE(XMEAN)
      AMOM(2)=DBLE(XSD)
      AMOM(3)=DBLE(XSKEW)
!
      VMOM(3)=AMOM(2)
      VMOM(2)=3.0D0*VMOM(3)/AMOM(3)
      VMOM(1)=AMOM(1) - VMOM(2)
      VMOM(4)=VMOM(1) + VMOM(2)
      VMOM(5)=3.0D0*VMOM(3)/VMOM(2)
!
      ALOCMO=REAL(VMOM(1))
      AMUMO=REAL(VMOM(2))
      SIGMMO=REAL(VMOM(3))
      GAMMMO=REAL(VMOM(2)**3/VMOM(3)**2)
!
!     IN CODE BELOW:
!
!        VMMOM(1) = ESTIMATE OF LOCATION
!        VMMOM(2) = ESTIMATE OF MU
!        VMMOM(3) = ESTIMATE OF SIGMA
!        VMMOM(4) = ESTIMATE OF MEAN
!                 = LOC + MU
!        VMMOM(5) = A3 (THIRD STANDARD MOMENT)
!                 = 3*SIGMA/MU
!
!     COMPUTE MODIFIED MOMENT ESTIMATORS USING CODE FOUND ON
!     PP. 358-359 OF COHEN/WHITTEN BOOK.
!
!     IF XMIN PARAMETER NOT GIVEN, THEN SKIP THIS CASE.
!
      IF(XMIN.EQ.CPUMIN)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,212)
  212   FORMAT('      MINIMUM VALUE NOT SPECIFIED.  MODIFIED ',   &
               'MOMENTS WILL NOT BE COMPUTED.')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IERR=0
      EPS=0.1D-08
      DN=DBLE(N)
      DNN=1.0D0/(DN+1.0D0)
!
!     FIND THE STANDARDIZED FIRST ORDER STATISTIC
!
      Z=(DBLE(XMIN) - AMOM(1))/AMOM(2)
!
!     SET THE UPPER AND LOWER BOUND ON A3
!
      A3U=3.0D0*AMOM(2)/(AMOM(1)-DBLE(XMIN))
      A3L=0.18D0
!
!     CALCULATE FUNCTION AT UPPER AND LOWER BOUNDS, A3U
!
      FU=-DNN
      VAL=Z/DSQRT(1.0D0 + A3L*Z/3.0D0)
      CALL NODCDF(VAL,P1)
      VAL1=-VAL - 6.0D0/(A3L*DSQRT(1.0D0+A3L*Z/3.0D0))
      CALL NODCDF(VAL1,P2)
      FL=(P1+DEXP(18.D0/A3L**2)*P2)-DNN
!
!     DETERMINE IF THERE EXISTS AN A3 IN THE INTERVAL (A3L,A3U)
!     THAT SATISFIES THE EQUATION
!
      IF(FL*FU.GT.0.0D0)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,222)
  222   FORMAT('      NO MODIFIED MOMENT ESTIMATOR FOUND.')
        CALL DPWRST('XXX','WRIT')
        GO TO 9000
      ELSE
!
!       USE BINARY SEARCH TO FIND THE SOLUTUION OF THE MODIFIED
!       MOMENTS EQUATION.
!
        F=FL
300     CONTINUE
        A3=(A3U+A3L)/2.0D0
        IF(DABS(A3-A3L).GT.EPS)THEN
          VAL=Z/DSQRT(1.0D0 + A3*Z/3.0D0)
          CALL NODCDF(VAL,P1)
          VAL1=-VAL - 6.0D0/(A3*DSQRT(1.0D0+A3*Z/3.0D0))
          CALL NODCDF(VAL1,P2)
          F=(P1+DEXP(18.D0/A3**2)*P2)-DNN
          IF(F*FL.LT.0.0D0)THEN
            A3U=A3
          ELSE
            A3L=A3
            FL=F
          ENDIF
          A3=(A3U+A3L)/2.0D0
          GO TO 300
        ELSE
          VMMOM(1)=AMOM(1) - 3.0D0*AMOM(2)/A3
          VMMOM(2)=3.0D0*AMOM(2)/A3
          VMMOM(3)=AMOM(2)
          VMMOM(4)=VMMOM(1)+ VMMOM(2)
          VMMOM(5)=A3
        ENDIF
      ENDIF
!
      ALOCMM=REAL(VMMOM(1))
      AMUMM=REAL(VMMOM(2))
      SIGMMM=REAL(VMMOM(3))
      GAMMMM=REAL(VMMOM(2)**3/VMMOM(3)**2)
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'GMO1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF IGMO1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9012)ALOCMO,AMUMO,SIGMMO,GAMMMO
 9012   FORMAT('ALOCMO,AMUMO,SIGMMO,GAMMMO = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)ALOCMM,AMUMM,SIGMMM,GAMMMM
 9013   FORMAT('ALOCMM,AMUMM,SIGMMM,GAMMMM = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE IGMO1
      SUBROUTINE IGPDF(DX,DGAMMA,DMU,DPDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY FUNCTION
!              VALUE FOR THE INVERSE GAUSSIAN DISTRIBUTION
!              WITH TAIL LENGTH PARAMETER = GAMMA AND SHAPE PARAMETER
!              MU.  ALTHOUGH MU IS ESSENTIALLY A SCALE PARAMETER, IT IS
!              NOT A SCALE PARAMETER IN THE TECHNICAL SENSE THAT THE
!              FOLLOWING RELATIONSHIP
!
!                  f(X;LOC,SCALE) = f((X-LOC)/SCALE;0,1)/SCALE
!
!              DOES NOT HOLD. THEREFORE, WE REFER TO IT AS A SHAPE
!              PARAMETER.
!
!              THE STANDARD FORM OF THE DISTRIBUTION IS DEFINED FOR ALL
!              NON-NEGATIVE X AND HAS THE PROBABILITY DENSITY  FUNCTION
!              (PAGE 246 OF VOLUME 4 OF THE OF ENCYCLOPEDIA OF
!              STATISTICAL SCIENCES):
!
!                  f(X) = SQRT(GAMMA/(2*PI*X**3))*
!                         EXP((-GAMMA/(2*MU**2))*(X-MU)**2/X)
!
!              THE PARAMETERIZATION DESCRIBED ABOVE WILL BE REFERRED TO
!              AS THE "TWEEDIE" PARAMETERIZATION.  NOTE THAT WHAT WE
!              CALL GAMMA IS CALLED LAMBDA IN MANY REFERENCES.  A
!              RE-PARAMETERIZATION, WHICH WE CALL THE CHAN PARAMETERIZATION,
!              USES
!
!                 SIGMA = SQRT(MU**3/GAMMA)
!
!     NOTE--THE INVERSE GAUSSIAN DISTRIBUTION--
!           1) GOES FROM 0 TO INFINITY
!           2) HAS MEAN = MU
!           3) HAS STANDARD DEVIATION = SQRT((MU**3)/GAMMA) = SIGMA
!           4) HAS SHAPE PARAMETER = GAMMA
!           5) IS HIGHLY-SKEWED AND LONG-TAILED FOR SMALL GAMMA
!           6) IS SYMMETRIC AND MODERATE-TAILED FOR LARGE GAMMA
!           7) APPROACHES NORMALITY AS GAMMA APPROACHES INFINITY
!     INPUT  ARGUMENTS--X      = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE NON-NEGATIVE.
!                     --GAMMA  = THE FIRST SHAPE PARAMETER,
!                                GAMMA SHOULD BE POSITIVE.
!                     --AMU    = THE SECOND SHAPE PARAMETER,
!                                AMU SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--CDF    = THE DOUBLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY DENSITY FUNCTION
!             VALUE CDF FOR THE INVERSE GAUSSIAN DISTRIBUTION WITH
!             WITH TAIL LENGTH PARAMETER = GAMMA AND SHAP PARAMETER MU.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X, GAMMA, M SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--KOTZ AND JOHNSON, "ENCYCLOPEDIA OF STATISTICAL SCIENCES",
!                 VOLUME 4, PP. 246-249.
!              --COHEN AND WHITTEN, "PARAMETER ESTIMATION IN RELIABILITY
!                AND LIFE SPAN MODELS", MARCEL DEKKER, INC., CHAPTER 5 AND
!                PP. 360-361.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--90.6
!     ORIGINAL VERSION--MAY       1990.
!     UPDATED         --JANUARY   1995. NEW PDF DEFINITION AND
!                                       REWRITTEN
!     UPDATED         --DECEMBER  2003. USE GENERAL VALUE OF MU
!                                       INSTEAD OF ASSUMING MU=1
!     UPDATED         --APRIL     2014. CONVERT TO DOUBLE PRECISION
!     UPDATED         --APRIL     2014. SUPPORT FOR CHAN PARAMETERIZATION
!
!-------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DGAMMA
      DOUBLE PRECISION DMU
      DOUBLE PRECISION DPI
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DLOW
      DOUBLE PRECISION DPDF
!
      INCLUDE 'DPCOST.INC'
      INCLUDE 'DPCOP2.INC'
!
      DATA DPI / 3.141592653589793238462643383279503D0 /
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      DPDF=0.0D0
      IF(DGAMMA.LE.0.0D0)THEN
        WRITE(ICOUT,51)
   51   FORMAT('***** ERROR--THE FIRST SHAPE PARAMETER TO IGPDF IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)DGAMMA
   52   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(DMU.LE.0.0D0 .AND. IGAUDF.NE.'STAN')THEN
        WRITE(ICOUT,71)
   71   FORMAT('***** ERROR--THE SECOND SHAPE PARAMETER TO IGPDF IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)DMU
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(IGAUDF.EQ.'STAN')THEN
        DLOW=-3.0D0/DGAMMA
        IF(DX.LE.DLOW)THEN
          WRITE(ICOUT,81)
   81     FORMAT('***** ERROR--THE FIRST ARGUMENT TO IGPDF IS ',   &
                 'LESS THAN -3/SHAPE.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,52)DX
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,53)DLOW
   53     FORMAT('      THE VALUE OF -3/SHAPE IS ',G15.7)
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
        ENDIF
      ELSE
        IF(DX.LT.0.0D0)THEN
          WRITE(ICOUT,61)
   61     FORMAT('***** ERROR--THE FIRST ARGUMENT TO IGPDF IS ',   &
                 'NON-POSITIVE.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,52)DX
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
        ENDIF
      ENDIF
!
!     CHECK FOR:
!
!          1. CHAN PARAMETERIZATION: GAMMA = MU**3/SIGMA**2
!
!          2. CHAN "STANDARD" PARAMETERIZATION
!
!             f(X;alpha) = (1/SQRT(2*PI))*(3/(3+ALPHA*X))**(3/2)*
!                          EXP((-X**2/2)*(3/(3+ALPHA*X)))
!                          X > -3/ALPHA
!
      IF(IGAUDF.EQ.'STAN')THEN
        DTERM1=(3.0D0/(3.0D0 + DGAMMA*DX))**1.5D0*   &
               (1.0D0/DSQRT(2.0D0*DPI))
        DTERM2=DEXP(-(DX**2/2.0D0)*(3.0D0/(3.0D0+DGAMMA*DX)))
        DPDF=DTERM1*DTERM2
        GO TO 9000
      ELSEIF(IGAUDF.EQ.'CHAN')THEN
        DGAMMA=DMU**3/DGAMMA**2
      ENDIF
!
      IF(DX.EQ.0.0D0)GO TO 9000
!
      DTERM1=0.5D0*DLOG(DGAMMA/(2.0D0*DPI*DX**3))
      DTERM2=(-DGAMMA/(2.0D0*DMU*DMU*DX))
      DTERM3=(DX-DMU)**2
      DPDF=DTERM1 + DTERM2*DTERM3
      DPDF=DEXP(DPDF)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE IGPDF
      SUBROUTINE IGPPF(DP,DGAMMA,DMU,DPPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT FUNCTION
!              VALUE FOR THE INVERSE GAUSSIAN DISTRIBUTION WITH TAIL
!              LENGTH PARAMETER = GAMMA AND SHAPE PARAMETER MU.
!              ALTHOUGH MU IS ESSENTIALLY A SCALE PARAMETER, IT IS
!              NOT A SCALE PARAMETER IN THE TECHNICAL SENSE THAT THE
!              FOLLOWING RELATIONSHIP
!
!                  f(X;LOC,SCALE) = f((X-LOC)/SCALE;0,1)/SCALE
!
!              DOES NOT HOLD. THEREFORE, WE REFER TO IT AS A SHAPE
!              PARAMETER.
!
!              THE STANDARD FORM OF THE DISTRIBUTION IS DEFINED FOR ALL
!              NON-NEGATIVE X AND HAS CUMULATIVE DISTRIBUTION FUNCTION
!              (PAGE 247 OF VOLUME 4 OF THE OF ENCYCLOPEDIA OF
!              STATISTICAL SCIENCES.
!
!                  F(X) = NORCDF(SQRT(GAMMA/X)*(-1 + (X/MU))) +
!                         EXP(2*GAMMA/MU)*NORCDF(SQRT(GAMMA/X)*(1 + (X/MU)))
!
!              THE PERCENT POINT FUNCTION IS COMPUTED BY NUMERICALLY
!              INVERTING THE CDF FUNCTION.
!
!              THE PARAMETERIZATION DESCRIBED ABOVE WILL BE REFERRED TO
!              AS THE "TWEEDIE" PARAMETERIZATION.  NOTE THAT WHAT WE
!              CALL GAMMA IS CALLED LAMBDA IN MANY REFERENCES.  A
!              RE-PARAMETERIZATION, WHICH WE CALL THE CHAN PARAMETERIZATION,
!              USES
!
!                 SIGMA = SQRT(MU**3/GAMMA)
!
!     INPUT  ARGUMENTS--P      = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --GAMMA  = THE FIRST SHAPE PARAMETER,
!                                GAMMA SHOULD BE POSITIVE.
!                     --AMU    = THE SECOND SHAPE PARAMETER,
!                                AMU SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--PPF    = THE DOUBLE PRECISION PERCENT POINT
!                                FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PERCENT POINT FUNCTION
!             VALUE PPF FOR THE INVERSE GAUSSIAN DISTRIBUTION WITH
!             WITH TAIL LENGTH PARAMETER = GAMMA AND SHAPE PARAMETER MU.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--P SHOULD BE BETWEEN 0.0 (INCLUSIVELY) AND 1.0 (EXCLUSIVELY).
!                 --GAMMA AND MU SHOULD BE POSITIVE
!     OTHER DATAPAC   SUBROUTINES NEEDED--IGCDF, NORCDF
!     FORTRAN LIBRARY SUBROUTINES NEEDED--
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--KOTZ AND JOHNSON, "ENCYCLOPEDIA OF STATISTICAL SCIENCES",
!                 VOLUME 4, PP. 246-249.
!              --COHEN AND WHITTEN, "PARAMETER ESTIMATION IN RELIABILITY
!                AND LIFE SPAN MODELS", MARCEL DEKKER, INC., CHAPTER 5 AND
!                PP. 360-361.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--90.6
!     ORIGINAL VERSION--MAY       1990.
!     UPDATED         --JANUARY   1995. NEW CDF DEFINITION & REWRITTEN
!     UPDATED         --DECEMBER  2003. SUPPORT FOR MU NOT EQUAL 1
!     UPDATED         --APRIL     2014. CONVERT TO DOUBLE PRECISION
!     UPDATED         --APRIL     2014. SUPPORT FOR CHAN PARAMETERIZATION
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DP
      DOUBLE PRECISION DGAMMA
      DOUBLE PRECISION DMU
      DOUBLE PRECISION DPPF
      DOUBLE PRECISION DX
      DOUBLE PRECISION TOL
      DOUBLE PRECISION DSD
      DOUBLE PRECISION XMIN
      DOUBLE PRECISION XMAX
      DOUBLE PRECISION XLOW
      DOUBLE PRECISION XUP
      DOUBLE PRECISION XMID
      DOUBLE PRECISION XDEL
      DOUBLE PRECISION PCALC
!
      INCLUDE 'DPCOST.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      DPPF=0.0D0
      IF(DGAMMA.LE.0.0D0)THEN
         WRITE(ICOUT,51)
   51    FORMAT('***** ERROR--THE FIRST SHAPE PARAMETER TO IGPPF IS ',   &
                'NON-POSITIVE.')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,52)DGAMMA
   52    FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
         CALL DPWRST('XXX','BUG ')
         GO TO 9000
      ELSEIF(DMU.LE.0.0D0)THEN
         WRITE(ICOUT,71)
   71    FORMAT('***** ERROR--THE SECOND SHAPE PARAMETER TO IGPPF IS ',   &
                'NON-POSITIVE.')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,52)DMU
         CALL DPWRST('XXX','BUG ')
         GO TO 9000
      ELSEIF(DP.LT.0.0D0 .OR. DP.GE.1.0D0)THEN
         WRITE(ICOUT,61)
   61    FORMAT('***** ERROR--THE FIRST ARGUMENT TO IGPPF IS OUTSIDE')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,62)
   62    FORMAT('      THE ALLOWABLE [0,1) INTERVAL.')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,52)DP
         CALL DPWRST('XXX','BUG ')
         GO TO 9000
      ENDIF
!
      IF(DP.EQ.0.0D0)GO TO 9000
!
!     CHECK FOR CHAN PARAMETERIZATION: GAMMA = MU**3/SIGMA**2
!
      IF(IGAUDF.EQ.'CHAN')THEN
        DGAMMA=DMU**3/DGAMMA**2
      ENDIF
!
      TOL=0.0000000001D0
      MAXIT=500
      XMIN=0.0D0
!
!     FROM THE KARLIN-STUDDEN INEQUALITY (PATEL/KAPADIA/OWEN, P. 30)
!     (BUT TRUE ONLY FOR X >= 1.5*MU)
!     FOR THE PROTOTYPE INVERSE GAUSSIAN DISTRIBUTION,
!     MU = MU (AND HERE MU = 1)
!CCCC XMAX=10.0**30
!
      DSD=DSQRT(DMU**3/DGAMMA)
      XMAX=DMU/(2.0D0*(1.0D0-DP))
!
      XLOW=XMIN
      XUP=XMAX
!
!CCCC HOPEFULLY, SAM SAUNDERS CAN GIVE ME A BETTER
!CCCC FIRST APPROXIMATION TO G(P) THAN MY 1.0   !
!CCCC XMID=1.0
!
      XMID=DMU
      ICOUNT=0
!
  200 CONTINUE
      DX=XMID
      CALL IGCDF(DX,DGAMMA,DMU,PCALC)
!
      IF(PCALC.EQ.DP)THEN
        DPPF=XMID
        GO TO 9000
      ELSEIF(PCALC.GT.DP)THEN
!
  220   CONTINUE
        XUP=XMID
        DX=XMID/2.0D0
        IF(DX.GT.XLOW)THEN
          XMID=DX
          CALL IGCDF(DX,DGAMMA,DMU,PCALC)
          IF(PCALC.EQ.DP)THEN
            DPPF=XMID
            GO TO 9000
          ENDIF
          IF(PCALC.GT.DP)GO TO 220
          XLOW=DX
        ENDIF
        XMID=(XLOW+XUP)/2.0D0
!
      ELSE
!
  210   CONTINUE
        XLOW=XMID
        DX=XMID*2.0D0
        IF(DX.LT.XUP)THEN
          XMID=DX
          CALL IGCDF(DX,DGAMMA,DMU,PCALC)
          IF(PCALC.EQ.DP)THEN
            DPPF=XMID
            GO TO 9000
          ENDIF
          IF(PCALC.LT.DP)GO TO 210
          XUP=DX
        ENDIF
        XMID=(XLOW+XUP)/2.0D0
      ENDIF
!
      XDEL=DABS(XMID-XLOW)
      ICOUNT=ICOUNT+1
      IF(XDEL.LT.TOL .OR. ICOUNT.GT.MAXIT)THEN
        DPPF=XMID
        GO TO 9000
      ENDIF
      GO TO 200
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE IGPPF
      SUBROUTINE IGRAN(N,GAMMA,AMU,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE INVERSE GAUSSIAN DISTRIBUTION
!              WITH SHAPE PARAMETER VALUE = GAMMA
!              AND LOCATION PARAMETER MU = 1.
!              THE PROTOTYPE INVERSE GAUSSIAN DISTRIBUTION USED
!              HEREIN IS DEFINED FOR ALL POSITIVE X,
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              AS GIVEN IN VOLUME 4, PAGE 246, BOTTOM
!              OF ENCYCLOPEDIA OF STATISTICAL SCIENCES
!                 WITH MU = 1
!     NOTE--THE GENERAL INVERSE GAUSSIAN DISTRIBUTION--
!              GOES FROM 0 TO INFINITY
!              HAS MEAN = MU (HERE = 1)
!              HAS STANDARD DEVIATION = SQRT((MU**3)/GAMMA)
!              HAS SHAPE PARAMETER = GAMMA
!              IS HIGHLY-SKEWED AND LONG-TAILED FOR SMALL GAMMA
!              IS SYMMETRIC AND MODERATE-TAILED FOR KARGE GAMMA
!              APPROACHES NORMALITY AS GAMMA APPROACHES INFINITY
!     NOTE--TO OBTAIN THE PDF FOR GENERAL MU,
!           COMPUTE THE PDF FOR X AROUND 1, AND THEN
!           SIMPLY SCALE UP THE HORIZONTAL AXIS X BY THE DESIRED MU
!           AS IN Y2 = MU*Y
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --GAMMA  = THE SINGLE PRECISION VALUE OF THE
!                                TAIL LENGTH PARAMETER.
!                                GAMMA SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE INVERSE GAUSSIAN DISTRIBUTION
!             WITH TAIL LENGTH PARAMETER VALUE = GAMMA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --GAMMA SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE HEREIN.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--KOTZ & JOHNSON, ENCYCLOPEDIA OF STAT SCIENCES
!                 VOLUME 4, PAGE 247, COLUMN 1 (FOR CDF).
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--90.6
!     ORIGINAL VERSION--MAY       1990.
!     UPDATED         --JANUARY   1995. NEW CDF DEFINITION & REWRITTEN
!     UPDATED         --NOVEMBER  2003. USE MICHEAL/SCHUCANY/HAAS
!                                       METHOD (FROM JAMES GENTLE
!                                       "RANDOM NUMBER GENERATION AND
!                                       MONTE CARLO METHODS", SECOND
!                                       EDITION, SPRINGER-VARLANG,
!                                       2003, P. 193.
!     UPDATED         --APRIL     2014. SUPPORT CHAN PARAMETERIZATION
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOST.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
         WRITE(ICOUT,51)
   51    FORMAT('***** ERROR--THE REQUESTED NUMBER OF INVERSE ',   &
                'GAUSSIAN RANDOM NUMBERS IS NON-POSITIVE.')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,52)N
   52    FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
         CALL DPWRST('XXX','BUG ')
         GO TO 9000
      ELSEIF(GAMMA.LE.0.0)THEN
         WRITE(ICOUT,61)
   61    FORMAT('***** ERROR--THE GAMMA SHAPE PARAMETER FOR THE ',   &
                'INVERSE GAUSSIAN')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,62)
   62    FORMAT('      RANDOM NUMBERS IS NON-POSITIVE.')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,63)GAMMA
   63    FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
         CALL DPWRST('XXX','BUG ')
         GO TO 9000
      ELSEIF(AMU.LE.0.0)THEN
         WRITE(ICOUT,71)
   71    FORMAT('***** ERROR--THE MU SHAPE PARAMETER FOR THE',   &
                ' INVERSE GAUSSIAN')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,72)
   72    FORMAT('      RANDOM NUMBERS IS NON-POSITIVE.')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,63)AMU
         CALL DPWRST('XXX','BUG ')
         GO TO 9000
      ENDIF
!
!     CHECK FOR CHAN PARAMETERIZATION: GAMMA = MU**3/SIGMA**2
!
      IF(IGAUDF.EQ.'CHAN')THEN
        GAMMA=AMU**3/GAMMA**2
      ENDIF
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
!CCCC CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N INVERSE GAUSSIAN DISTRIBUTION RANDOM NUMBERS
!     USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD.
!
!CCCC DO100I=1,N
!CCCC XI=X(I)
!CCCC CALL IGPPF(XI,GAMMA,X(I))
! 100 CONTINUE
!
!     MICHEAL/SCHUCANY/HAAS ALGORITHM.
!
!     GENERATE N NORMAL (0,1) RANDOM NUMBERS;
!
      CALL NORRAN(N,ISEED,X)
!
      NTEMP=1
      DO 100 I=1,N
        Y=X(I)*X(I)
        X1=AMU + AMU*AMU*Y/(2.0*GAMMA) -   &
           (AMU/(2.0*GAMMA))*SQRT(4.0*AMU*GAMMA*Y + AMU*AMU*Y*Y)
        CALL UNIRAN(NTEMP,ISEED,X(I))
        U=X(I)
        IF(U.LE.AMU/(AMU+X1))THEN
          X(I)=X1
        ELSE
          X(I)=AMU*AMU/X1
        ENDIF
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE IGRAN
      SUBROUTINE IMTQL2(NM,N,D,E,Z,IERR)
!***BEGIN PROLOGUE  IMTQL2
!***DATE WRITTEN   760101   (YYMMDD)
!***REVISION DATE  830518   (YYMMDD)
!***CATEGORY NO.  D4A5,D4C2A
!***KEYWORDS  EIGENVALUES,EIGENVECTORS,EISPACK
!***AUTHOR  SMITH, B. T., ET AL.
!***PURPOSE  Computes eigenvalues and eigenvectors of symmetric
!            tridiagonal matrix using implicit QL method.
!***DESCRIPTION
!
!     This subroutine is a translation of the ALGOL procedure IMTQL2,
!     NUM. MATH. 12, 377-383(1968) by Martin and Wilkinson,
!     as modified in NUM. MATH. 15, 450(1970) by Dubrulle.
!     HANDBOOK FOR AUTO. COMP., VOL.II-LINEAR ALGEBRA, 241-248(1971).
!
!     This subroutine finds the eigenvalues and eigenvectors
!     of a SYMMETRIC TRIDIAGONAL matrix by the implicit QL method.
!     The eigenvectors of a FULL SYMMETRIC matrix can also
!     be found if  TRED2  has been used to reduce this
!     full matrix to tridiagonal form.
!
!     On INPUT
!
!        NM must be set to the row dimension of two-dimensional
!          array parameters as declared in the calling program
!          dimension statement.
!
!        N is the order of the matrix.
!
!        D contains the diagonal elements of the input matrix.
!
!        E contains the subdiagonal elements of the input matrix
!          in its last N-1 positions.  E(1) is arbitrary.
!
!        Z contains the transformation matrix produced in the
!          reduction by  TRED2, if performed.  If the eigenvectors
!          of the tridiagonal matrix are desired, Z must contain
!          the identity matrix.
!
!      On OUTPUT
!
!        D contains the eigenvalues in ASCENDING order.  If an
!          error exit is made, the eigenvalues are correct but
!          UNORDERED for indices 1,2,...,IERR-1.
!
!        E has been destroyed.
!
!        Z contains orthonormal eigenvectors of the symmetric
!          tridiagonal (or full) matrix.  If an error exit is made,
!          Z contains the eigenvectors associated with the stored
!          eigenvalues.
!
!        IERR is set to
!          ZERO       for normal return,
!          J          if the J-th eigenvalue has not been
!                     determined after 30 iterations.
!
!     Calls PYTHAG(A,B) for sqrt(A**2 + B**2).
!
!     Questions and comments should be directed to B. S. Garbow,
!     APPLIED MATHEMATICS DIVISION, ARGONNE NATIONAL LABORATORY
!     ------------------------------------------------------------------
!***REFERENCES  B. T. SMITH, J. M. BOYLE, J. J. DONGARRA, B. S. GARBOW,
!                 Y. IKEBE, V. C. KLEMA, C. B. MOLER, *MATRIX EIGEN-
!                 SYSTEM ROUTINES - EISPACK GUIDE*, SPRINGER-VERLAG,
!                 1976.
!***ROUTINES CALLED  PYTHAG
!***END PROLOGUE  IMTQL2
!
      INTEGER I,J,K,L,M,N,II,NM,MML,IERR
      REAL D(N),E(N),Z(NM,N)
      REAL B,C,F,G,P,R,S,S1,S2
      REAL PYTHAG
!
!***FIRST EXECUTABLE STATEMENT  IMTQL2
      IERR = 0
      IF (N .EQ. 1) GO TO 1001
!
      DO 100 I = 2, N
        E(I-1) = E(I)
  100 CONTINUE
!
      E(N) = 0.0E0
!
      DO 240 L = 1, N
         J = 0
!     .......... LOOK FOR SMALL SUB-DIAGONAL ELEMENT ..........
  105    DO 110 M = L, N
            IF (M .EQ. N) GO TO 120
            S1 = ABS(D(M)) + ABS(D(M+1))
            S2 = S1 + ABS(E(M))
            IF (S2 .EQ. S1) GO TO 120
  110    CONTINUE
!
  120    P = D(L)
         IF (M .EQ. L) GO TO 240
         IF (J .EQ. 30) GO TO 1000
         J = J + 1
!     .......... FORM SHIFT ..........
         G = (D(L+1) - P) / (2.0E0 * E(L))
         R = PYTHAG(G,1.0E0)
         G = D(M) - P + E(L) / (G + SIGN(R,G))
         S = 1.0E0
         C = 1.0E0
         P = 0.0E0
         MML = M - L
!     .......... FOR I=M-1 STEP -1 UNTIL L DO -- ..........
         DO 200 II = 1, MML
            I = M - II
            F = S * E(I)
            B = C * E(I)
            IF (ABS(F) .LT. ABS(G)) GO TO 150
            C = G / F
            R = SQRT(C*C+1.0E0)
            E(I+1) = F * R
            S = 1.0E0 / R
            C = C * S
            GO TO 160
  150       S = F / G
            R = SQRT(S*S+1.0E0)
            E(I+1) = G * R
            C = 1.0E0 / R
            S = S * C
  160       G = D(I+1) - P
            R = (D(I) - G) * S + 2.0E0 * C * B
            P = S * R
            D(I+1) = G + P
            G = C * R - B
!     .......... FORM VECTOR ..........
            DO 180 K = 1, N
               F = Z(K,I+1)
               Z(K,I+1) = S * Z(K,I) + C * F
               Z(K,I) = C * Z(K,I) - S * F
  180       CONTINUE
!
  200    CONTINUE
!
         D(L) = D(L) - P
         E(L) = G
         E(M) = 0.0E0
         GO TO 105
  240 CONTINUE
!     .......... ORDER EIGENVALUES AND EIGENVECTORS ..........
      DO 300 II = 2, N
         I = II - 1
         K = I
         P = D(I)
!
         DO 260 J = II, N
            IF (D(J) .GE. P) GO TO 260
            K = J
            P = D(J)
  260    CONTINUE
!
         IF (K .EQ. I) GO TO 300
         D(K) = D(I)
         D(I) = P
!
         DO 280 J = 1, N
            P = Z(J,I)
            Z(J,I) = Z(J,K)
            Z(J,K) = P
  280    CONTINUE
!
  300 CONTINUE
!
      GO TO 1001
!     .......... SET ERROR -- NO CONVERGENCE TO AN
!                EIGENVALUE AFTER 30 ITERATIONS ..........
 1000 IERR = L
 1001 RETURN
      END SUBROUTINE IMTQL2
