!               **************************************************
                                                                                                                                  
!               **************************************************
!               **  INITIALIZE EXPERIMENTAL SIMULATION SETTINGS **
!               **     GMEAN     = GRAND MEAN                   **
!               **     NUMB      = TOTAL NUMBER OF COEFFICIENTS **(EXCLUDING GRA
!               **     INDEXB(.) = INDEX FOR COEFFICIENTS (EXCLU**DING GRAND MEA
!               **     B(.)      = COEFFICIENTS (EXCLUDING GRAND** MEAN)
!               **     GSD       = GENERAL STANDARD DEVIATION   **
!               **               = SD OF ERROR IN Y = GRAND MEAN** + ERROR
!               **     NUMS      = XX                           **
!               **     BMINT     = INTERCEPT FOR GRAND MEAN DRIF**T IN TIME
!               **     BMSLOP    = SLOPE     FOR GRAND MEAN DRIF**T IN TIME
!               **     DSINT     = INTERCEPT FOR SD         DRIF**T IN TIME
!               **     DSSLOP    = SLOPE     FOR SD         DRIF**T IN TIME
!               **************************************************
!
      ISIMID=0
      IAUTH='BOXB'
      ITEXT='TECH'
      IPAGE=17
!
      GMEAN=71.25
      NUMB=7
      INDEXB(1)=1
      INDEXB(2)=2
      INDEXB(3)=3
      INDEXB(4)=12
      INDEXB(5)=13
      INDEXB(6)=23
      INDEXB(7)=123
      B(1)=23.0
      B(2)=(-5.0)
      B(3)=1.5
      B(4)=1.5
      B(5)=10.0
      B(6)=0.0
      B(7)=0.5
!
!CCCC GSD=0.1
