      SUBROUTINE INITL (P, X, N0, N, MU, SIGMA,   &
                        FUNC, DEVIAT, IFAULT)
!
!       ALGORITHM AS 95.1 APPL. STATIST. (1976) VOL.25, NO.1
!
!       COMPUTES ROUGH LEAST SQUARES ESTIMATES OF MU AND SIGMA
!       ( FOR DEFINITION OF MU AND SIGMA SEE SUBROUTINE CURVE ).
!
!       THIS IS JUST USED TO FIND STARTING VALUES FOR "CURVE"
!       ROUTINE (WHICH IS USED TO ESTIMATE LOCATION/SCALE FOR
!       GROUPED DATA WHEN THE DISTRIBUTION HAS NO SHAPE
!       PARAMETERS).
!
      INTEGER P
      REAL MU, ONE, ZERO
      DIMENSION X(P), N(P)
!
      EXTERNAL FUNC
      EXTERNAL DEVIAT
!
      DATA ONE/1.0/
      DATA ZERO/0.0/
!
!       ERROR EXIT IF P TOO SMALL
!
      IF (P.LT.2) THEN
         IFAULT = 1
         GO TO 9000
      ENDIF
      IFAULT = 0
!
!       COMPUTE AND FLOAT SUM OF FREQUENCIES
!
      NSUM = N0
      DO 10 I = 1, P
        NSUM = NSUM + N(I)
 10   CONTINUE
      XNSUM = FLOAT(NSUM)
!
!       ZERO ACCUMULATORS
!
      NPAR = N0
      XBAR = ZERO
      YBAR = ZERO
      SXX = ZERO
      SXY = ZERO
      SW = ZERO
!
!       COMPUTE WEIGHTED MEANS XAR, YBAR, AND CORRECTED SUMS
!       OF X*X AND X*Y.
!
      DO 30 I = 1, P
!
!       NULL FREQUENCIES AT EITHER END OF THE RANGE ARE
!       ZERO WEIGHTED
!
        IF (NPAR.EQ.0 .OR. NPAR.EQ.NSUM) GO TO 20
        PROB = REAL(NPAR)/XNSUM
        Y = DEVIAT(PROB)
        CALL FUNC (Y, DUMMY, DFY)
        DX = X(I) - XBAR
        DY = Y - YBAR
        W = DFY*DFY/(PROB*(ONE - PROB))
        SW = SW + W
        FAC = W/SW
        XBAR = XBAR + FAC*DX
        YBAR = YBAR + FAC*DY
        FAC = W*DX*(ONE - FAC)
        SXX = SXX + FAC*DX
        SXY = SXY + FAC*DY
 20     NPAR = NPAR + N(I)
 30   CONTINUE
      SIGMA = SXX/SXY
      MU = XBAR - SIGMA*YBAR
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE INITL 
