!CCCC THE FOLLOWING SECTION WAS ADDED    AUGUST       2011
!
!               *****************************************************
!               **  TREAT THE SET POSTSCRIPT VIEWER <NAME>         **
!               **            SET PDF        VIEWER <NAME>         **
!               **            SET IMAGE      VIEWER <NAME>         **
!               **            SET BACKUP     VIEWER <NAME>         **
!               *****************************************************
!
!     NOTE: COMMENTS FOR LINUX/MacOS SYSTEMS
!
!           1. "open" FOR MacOS AND "xdg-open" FOR LINUX USE THE
!              FILE EXTENSION TO DETERMINE THE APPROPRIATE APPLICATION
!              TO USE.  HOWEVER, THE "PSVIEW" COMMAND IS OFTEN USED
!              WITH THE dppl1f.dat AND dppl2f.dat FILES WHICH DO
!              NOT HAVE THE APPROPRIATE FILE EXTENSIONS.
!
!           2. ALSO, THE ghostview APPLICATION IS LESS LIKELY
!              TO BE INSTALLED BY DEFAULT.  THE "okular" APPLICATION
!              IS MORE LIKELY TO BE AVAILABLE.
!
!           SO TO ALLOW xdg-open AND open TO BE USED AS THE DEFAULT
!           VIEWER, ALSO DEFINE A "BACKUP" VIEWER.  THIS WILL BE USED
!           WHEN THE REQUESTED FILE DOES NOT HAVE THE APPROPRIATE
!           FILE EXTENSION.  FOR LINUX, WE WILL USE THE "okular"
!           APPLICATION AS THIS IS INSTALLLED BY DEFAULT ON MANY
!           SYSTEMS AND CAN HANDLE A NUMBER OF IMAGE TYPES AS WELL
!           AS POSTSCRIPT AND PDF FILES.  FOR MacOS, USE
!           "/Applications/Preview.app"
!
      IF(IOPSY1.EQ.'UNIX' .OR. IOPSY1.EQ.'LINU')THEN
        IF(IOPSY2.EQ.'MAC ')THEN
          IPSTVW='open'
          NCPSVW=4
          IPDFVW='open'
          NCPDVW=4
          IIMAVW='open'
          NCIMVW=4
          IBCKVW='/Applications/Preview.app'
          NCBKVW=25
        ELSE
          IPSTVW='xdg-open'
          NCPSVW=8
          IPDFVW='xdg-open'
          NCPDVW=8
          IIMAVW='xdg-open'
          NCIMVW=8
          IBCKVW='okular'
          NCBKVW=6
        ENDIF
      ELSEIF(IOPSY1.EQ.'PC-D')THEN
!
!       2019/12: TAKE INITIAL PATH FROM SYSTEM ENVIRONMENT
!                VARIABLES.  THIS IS MORE ROBUST FOR NON-ENGLISH
!                PLATFORMS.
!
        CALL DPCONA(92,IBASLC)
        IF(WINBIT.EQ.'64')THEN
          IPSTVW(1:NCP86F)=P86FIL(1:NCP86F)
          IPDFVW(1:NCP86F)=P86FIL(1:NCP86F)
          IBCKVW(1:NCP86F)=P86FIL(1:NCP86F)
          NCPSVW=NCP86F
          NCPDVW=NCP86F
          NCBKVW=NCP86F
        ELSE
          IPSTVW(1:NCPROF)=PROFIL(1:NCPROF)
          IPDFVW(1:NCPROF)=PROFIL(1:NCPROF)
          IBCKVW(1:NCPROF)=PROFIL(1:NCPROF)
          NCPSVW=NCPROF
          NCPDVW=NCPROF
          NCBKVW=NCPROF
        ENDIF
!
        NCPSVW=NCPSVW+1
        IPSTVW(NCPSVW:NCPSVW)=IBASLC
        IPSTVW(NCPSVW+1:NCPSVW+8)='GHOSTGUM'
        NCPSVW=NCPSVW+8
        IPSTVW(NCPSVW:NCPSVW)=IBASLC
        IPSTVW(NCPSVW+1:NCPSVW+6)='GSVIEW'
        NCPSVW=NCPSVW+6
        NCPSVW=NCPSVW+1
        IPSTVW(NCPSVW:NCPSVW)=IBASLC
        IPSTVW(NCPSVW+1:NCPSVW+12)='GSVIEW32.EXE'
        NCPSVW=NCPSVW+12
!
        NCPDVW=NCPDVW+1
        IPDFVW(NCPDVW:NCPDVW)=IBASLC
        IPDFVW(NCPDVW+1:NCPDVW+5)='ADOBE'
        NCPDVW=NCPDVW+5
        NCPDVW=NCPDVW+1
        IPDFVW(NCPDVW:NCPDVW)=IBASLC
        IPDFVW(NCPDVW+1:NCPDVW+17)='Acrobat Reader DC'
        NCPDVW=NCPDVW+17
        NCPDVW=NCPDVW+1
        IPDFVW(NCPDVW:NCPDVW)=IBASLC
        IPDFVW(NCPDVW+1:NCPDVW+6)='Reader'
        NCPDVW=NCPDVW+6
        NCPDVW=NCPDVW+1
        IPDFVW(NCPDVW:NCPDVW)=IBASLC
        IPDFVW(NCPDVW+1:NCPDVW+12)='AcroRd32.exe'
        NCPDVW=NCPDVW+12
!
        NCBKVW=NCBKVW+1
        IBCKVW(NCBKVW:NCBKVW)=IBASLC
        IBCKVW(NCBKVW+1:NCBKVW+8)='GHOSTGUM'
        NCBKVW=NCBKVW+8
        IBCKVW(NCBKVW:NCBKVW)=IBASLC
        IBCKVW(NCBKVW+1:NCBKVW+6)='GSVIEW'
        NCBKVW=NCBKVW+6
        NCBKVW=NCBKVW+1
        IBCKVW(NCBKVW:NCBKVW)=IBASLC
        IBCKVW(NCBKVW+1:NCBKVW+12)='GSVIEW32.EXE'
        NCBKVW=NCBKVW+12
!
        IIMAVW=' '
        NCIMVW=0
      ENDIF
