!CCCC THE FOLLOWING SECTION WAS ADDED    NOVEMBER       2019
!
!               *****************************************************
!               **  TREAT THE SET LIST VIEWER   <NAME>             **
!               **  TREAT THE SET LIST LAUNCHER <NAME>             **
!               **  TREAT THE SET EXCEL VIEWER  <NAME>             **
!               **  TREAT THE SET WORD  VIEWER  <NAME>             **
!               **  TREAT THE SET POWER POINT  VIEWER  <NAME>      **
!               *****************************************************
!
!     FOR WINDOWS, YOU CAN SIMPLY DO A
!
!         SYSTEM FILE.
!
!     AND THE FILE ASSOCIATIONS WILL INVOKE TO PROPER APPLICATION.
!     FOR LINUX, YOU NEED TO SPECIFY AN EXPLICIT APPLICATION TO VIEW
!     AN EXCEL OR WORD FILE.
!
!     ON MANY LINUX/UNIX INSTALLATIONS, YOU CAN USE THE
!     "xdg-open" WHICH WILL USE FILE ASSOCIATIONS ON THE
!     SYSTEM TO AUTOMATICALLY DETERMINE THE USER'S PREFERRED
!     APPLICATION.
!
!     ON MacOS, "open" HAS SIMILAR FUNCTIONALITY AS "xdg-open"
!     ON LINUX.
!
      IF(IOPSY1.EQ.'UNIX' .OR. IOPSY1.EQ.'LINU')THEN
!CCCC   IEXCVW='libreoffice --calc'
!CCCC   NCEXCW=18
!CCCC   IWORVW='libreoffice --writer'
!CCCC   NCWOVW=20
        IF(IOPSY2.EQ.'MAC ')THEN
          ILSTVW=' '
          NCLSVW=0
          ILSTLA='open -t '
          NCLSLA=8
          IEXCVW='open'
          NCEXVW=4
          IWORVW='open'
          NCWOVW=4
          IPPTVW='open'
          NCPPVW=4
        ELSE
          ILSTVW='vi'
          NCLSVW=2
          ILSTLA='gnome-terminal -e'
          NCLSLA=17
          IEXCVW='xdg-open'
          NCEXVW=8
          IWORVW='xdg-open'
          NCWOVW=8
          IPPTVW='xdg-open'
          NCPPVW=8
        ENDIF
      ELSE
!
        ILSTVW='notepad'
        NCLSVW=7
        ILSTLA=' '
        NCLSLA=0
        IEXCVW=' '
        NCEXCW=0
        IWORVW=' '
        NCWOVW=0
        IPPTVW=' '
        NCPPVW=0
      ENDIF
