      FUNCTION INITS (OS, NOS, ETA)
!***BEGIN PROLOGUE  INITS
!***PURPOSE  Determine the number of terms needed in an orthogonal
!            polynomial series so that it meets a specified accuracy.
!***LIBRARY   SLATEC (FNLIB)
!***CATEGORY  C3A2
!***TYPE      SINGLE PRECISION (INITS-S, INITDS-D)
!***KEYWORDS  CHEBYSHEV, FNLIB, INITIALIZE, ORTHOGONAL POLYNOMIAL,
!             ORTHOGONAL SERIES, SPECIAL FUNCTIONS
!***AUTHOR  Fullerton, W., (LANL)
!***DESCRIPTION
!
!  Initialize the orthogonal series, represented by the array OS, so
!  that INITS is the number of terms needed to insure the error is no
!  larger than ETA.  Ordinarily, ETA will be chosen to be one-tenth
!  machine precision.
!
!             Input Arguments --
!   OS     single precision array of NOS coefficients in an orthogonal
!          series.
!   NOS    number of coefficients in OS.
!   ETA    single precision scalar containing requested accuracy of
!          series.
!
!***REFERENCES  (NONE)
!***ROUTINES CALLED  XERMSG
!***REVISION HISTORY  (YYMMDD)
!   770401  DATE WRITTEN
!   890831  Modified array declarations.  (WRB)
!   891115  Modified error message.  (WRB)
!   891115  REVISION DATE from Version 3.2
!   891214  Prologue converted to Version 4.0 format.  (BAB)
!   900315  CALLs to XERROR changed to CALLs to XERMSG.  (THJ)
!***END PROLOGUE  INITS
      REAL OS(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
!***FIRST EXECUTABLE STATEMENT  INITS
      IF (NOS .LT. 1) THEN
        WRITE(ICOUT,11)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,12)
        CALL DPWRST('XXX','BUG ')
        INITS = 0
        RETURN
      ENDIF
   11 FORMAT('***** ERROR FROM INITS.  THE NUMBER OF ')
   12 FORMAT('      COEFFICIENTS IS LESS THAN 1.      *****')
!
      ERR = 0.
      DO 10 II = 1,NOS
        I = NOS + 1 - II
        ERR = ERR + ABS(OS(I))
        IF (ERR.GT.ETA) GO TO 20
   10 CONTINUE
!
   20 IF (I .EQ. NOS) THEN
      WRITE(ICOUT,21)
 21   FORMAT('***** ERROR FROM INITS.  CHEBYSHEV SERIES TOO ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,22)
 22   FORMAT('      SHORT FOR SPECIFIED ACCURACY.             *****')
      CALL DPWRST('XXX','BUG ')
      ENDIF
      INITS = I
!
      RETURN
      END FUNCTION INITS 
      SUBROUTINE INOUT(XA,YA,X,Y,NP,IO)
!
!     PURPOSE--XX
!
!     WRITTEN BY--DAVID W. BEHRINGER NOAA/AOML (MIAMI).
!                 AS PART OF NOAA'S CONCX V.3   MARCH 1988.
!     ORIGINAL VERSION (IN DATAPLOT)--AUGUST    1988.
!     UPDATED         --JANUARY   1989.  MORE CHANGES TO STANDARD FORTRAN 77--
!                                        CHANGED DO WHILE/END DO
!                                        AND ATAN2D TO ATAN2
!                                        (ATAN2D IS A VAX DOUB. PREC. ATAN2)
!                                        (ALAN HECKERT).
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION Y(*)
!
!-----START POINT-----------------------------------------------------
!
      AS=0.
      XX=X(1)-XA
      YY=Y(1)-YA
!CCCC A0=ATAN2D(YY,XX)
      A0=ATAN2(YY,XX)
      DO 10 N=2,NP+1
        M=MOD(N-1,NP)+1
        XX=X(M)-XA
        YY=Y(M)-YA
!CCCC   A=ATAN2D(YY,XX)
        A=ATAN2(YY,XX)
        DA=A-A0
        IF (DA.LT.-180.) DA=DA+360.
        IF (DA.GT.180.)  DA=DA-360.
        AS=AS+DA
        A0=A
 10   CONTINUE
      IF (ABS(AS).LT.180.) THEN
        IO=0
      ELSE
        IO=1
      END IF
      RETURN
      END SUBROUTINE INOUT
      SUBROUTINE INSERT(Y1,N1,Y2,N2,NLOC,IWRITE,YOUT,NOUT,MAXNXT,   &
                        IINSOW,IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--THIS SUBROUTINE INSERTS THE CONTENTS OF Y2 INTO
!              Y1 STARTING AT ROW NLOC.
!
!     INPUT  ARGUMENTS--Y1     = THE SINGLE PRECISION VECTOR OF
!                                OBSERVATIONS.
!                     --N1     = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR Y1.
!                     --Y2     = THE SINGLE PRECISION VECTOR OF
!                                OBSERVATIONS TO BE INSERTED INTO Y1.
!                     --N2     = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR Y2.
!                     --NLOC   = THE INTEGER NUMBER THAT SPECIFIES THE
!                                STARTING ROW IN Y1.
!     OUTPUT ARGUMENTS--Y      = THE SINGLE PRECISION VECTOR OF THE
!                                MERGED VALUES.
!                     --NOUT   = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE OUTPUT VECTOR YOUT.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VECTOR OF THE MERGED VALUES.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCE--ISO 13528, FIRST EDITION, STATISTICAL METHODS FOR USE
!                IN PROFICIENCY TESTING BY INTERLABORATORY COMPARISONS,
!                2005, PP. 25-30.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2020.02
!     ORIGINAL VERSION--FEBRUARY  2020.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IINSOW
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION Y1(*)
      DIMENSION Y2(*)
      DIMENSION YOUT(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='INSE'
      ISUBN2='RT  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'SERT')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF INSERT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N1,N2
   52   FORMAT('IBUGA3,ISUBRO,N1,N2 = ',2(A4,2X),2I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,MAX(N1,N2)
          WRITE(ICOUT,56)I,Y1(I),Y2(I)
   56     FORMAT('I,Y1(I),Y2(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(N1.LT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN INSERT ')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE NUMBER OF OBSERVATIONS IN THE FIRST ',   &
               'RESPONSE VARIABLE IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N1
  117   FORMAT('      THE NUMBER OF OBSERVATIONS = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ELSEIF(N2.LT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,122)
  122   FORMAT('      THE NUMBER OF OBSERVATIONS IN THE SECOND ',   &
               'RESPONSE VARIABLE IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N2
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ELSEIF(NLOC.LT.1 .OR. NLOC.GT.N1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,132)NLOC
  132   FORMAT('      THE INSERTION ROW, (',I8,') IS GREATER THAN THE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,134)N1
  134   FORMAT('      NUMBER OF ROWS IN THE FIRST RESPONSE VARIABLE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,136)N1
  136   FORMAT('      THE NUMBER OF ROWS IN THE FIRST RESPONSE ',   &
               'VARIABLE = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               *****************************
!               **  STEP 2--               **
!               **  PERFORM THE INSERTION  **
!               *****************************
!
      NOUT=0
      DO 210 II=1,NLOC-1
        NOUT=NOUT+1
        YOUT(NOUT)=Y1(II)
  210 CONTINUE
!
      DO 220 II=1,N2
        NOUT=NOUT+1
        IF(NOUT.GT.MAXNXT)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,111)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,222)
  222     FORMAT('      THE MAXIMUM NUMBER OF ROWS IS EXCEEDED FOR ',   &
                 'THE OUTPUT VARIABLE.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,226)N1
  226     FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE ',   &
                 'FIRST RESPONSE VARIABLE = ',I8,'.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,227)N2
  227     FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE ',   &
                 'SECOND RESPONSE VARIABLE = ',I8,'.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,228)MAXNXT
  228     FORMAT('      THE MAXIMUM NUMBER OF ROWS = ',   &
                 I8,'.')
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
        YOUT(NOUT)=Y2(II)
  220 CONTINUE
!
      IF(NOUT.LT.N1 .OR. IINSOW.EQ.'OFF')THEN
        IF(IINSOW.EQ.'ON')THEN
          NSTRT=NOUT+1
        ELSE
          NSTRT=NLOC
        ENDIF
        DO 230 II=NSTRT,N1
          NOUT=NOUT+1
!
          IF(NOUT.GT.MAXNXT)THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,111)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,222)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,226)N1
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,227)N2
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,228)MAXNXT
            CALL DPWRST('XXX','BUG ')
            IERROR='YES'
            GO TO 9000
          ENDIF
!
          YOUT(NOUT)=Y1(II)
  230   CONTINUE
      ENDIF
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,811)NOUT
  811   FORMAT('THE NUMBER OF VALUES GENERATED BY THE INSERT ',   &
               'COMMAND = ',I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'SERT')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END OF INSERT--')
        CALL DPWRST('XXX','BUG ')
        DO 9012 I=1,NOUT
          WRITE(ICOUT,9015)I,YOUT(I)
 9015     FORMAT('I,YOUT(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
 9012   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE INSERT
      SUBROUTINE INTARR(X,NX,IWRITE,Y,NY,IBUGA3,IERROR)
!
!     PURPOSE--COMPUTE INTERARRIVAL TIMES OF A SERIES OF FAILURE
!              TIMES.
!              SORT FAILURE TIMES
!              Y(1) = X(1)
!              Y(2) = X(2)-X(1)
!              Y(2) = X(3)-X(2)
!              Y(3) = X(4)-X(3)
!              ETC.
!     NOTE--IT IS PERMISSIBLE TO HAVE THE OUTPUT VECTOR Y(.)
!           BEING IDENTICAL TO THE INPUT VECTOR X(.).
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--98/5
!     ORIGINAL VERSION--MAY       1998.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION Y(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='INTA'
      ISUBN2='RR  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF INTARR--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IWRITE,IBUGA3,NX
   52   FORMAT('IWRITE,IBUGA3,NX = ',A4,2X,I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,NX
          WRITE(ICOUT,56)I,X(I)
   56     FORMAT('I,X(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               **************************************
!               **  COMPUTE SEQUENTIAL DIFFERENCE.  **
!               **************************************
!
      CALL SORT(X,NX,X)
      NXM1=NX-1
      IF(NXM1.LT.1)GO TO 150
      DO 100 I=NX,2,-1
      IP1=I-1
      Y(I)=X(I)-X(IP1)
  100 CONTINUE
      Y(1)=X(1)
      NY=NX
      GO TO 190
!
  150 CONTINUE
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,151)
  151 FORMAT('***** ERROR IN INTARR--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,152)
  152 FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE RESPONSE ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,155)
  155 FORMAT('      VARIABLE MUST BE 2 OR LARGER.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,157)NX
  157 FORMAT('      THE NUMBER OF OBSERVATIONS = ',I8,'.')
      CALL DPWRST('XXX','BUG ')
!
  190 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF INTARR--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)NY,IERROR
 9012   FORMAT('NY,IERROR = ',I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
        DO 9015 I=1,NX
          WRITE(ICOUT,9016)I,X(I),Y(I)
 9016     FORMAT('I,X(I),Y(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
 9015   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE INTARR
      SUBROUTINE INTCNT(X,N,ALOWLM,AUPPLM,IWRITE,XCOUNT,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE COUNT FOR THE NUMBER
!              OF VALUES IN X THAT FALL WITHIN CERTAIN LIMITS.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!                     --ALOWLM = THE REAL NUMBER THAT SPECIFIES THE
!                                LOWER LIMIT FOR THE COUNT.
!                     --AUPPLM = THE REAL NUMBER THAT SPECIFIES THE
!                                UPPER LIMIT FOR THE COUNT.
!     OUTPUT ARGUMENTS--XCOUNT = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SAMPLE COUNT.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE SAMPLE COUNT.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2018.08
!     ORIGINAL VERSION--AUGUST    2018.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='INTC'
      ISUBN2='NT  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'TCNT')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF INTCNT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N,ALOWLM,AUPPLM
   52   FORMAT('IBUGA3,ISUBRO,N,ALOWLM,AUPPLM = ',2(A4,2X),I8,2G15.7)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I)
   56     FORMAT('I,X(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN INTERVAL COUNT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE NUMBER OF OBSERVATIONS IN THE RESPONSE ',   &
               'VARIABLE IS LESS THAN 1.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE NUMBER OF OBSERVATIONS = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               *************************
!               **  STEP 2--           **
!               **  COMPUTE THE COUNT. **
!               *************************
!
      ICNT=0
      DO 200 I=1,N
        IF(X(I).GE.ALOWLM .AND. X(I).LE.AUPPLM)ICNT=ICNT+1
  200 CONTINUE
      XCOUNT=REAL(ICNT)
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,811)N,ALOWLM,AUPPLM,ICNT
  811   FORMAT('THE COUNT OF THE ',I8,' OBSERVATIONS IN (',   &
               E15.7,',',E15.17,') = ',I10)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'TCNT')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF INTCNT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IERROR,XCOUNT
 9012   FORMAT('IERROR,XCOUNT = ',A4,2X,G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE INTCNT
      SUBROUTINE INTERP(Y,X,N,X2,N2,IWRITE,Y2,   &
                        YTEMP,YDIST,XDIST,DELX,DELY,DERIV,DELX6,   &
                        P,B,Z,C,A,MAXNXT,   &
                        IBUGG3,ISUBRO,IERROR)
!
!     PURPOSE--COMPUTE SPLINE INTERPOLATION OF A VARIABLE
!              (GENERATE INTERPOLATED POINTS).
!     INPUT  ARGUMENTS--Y      = SINGLE PRECISION VARIABLE
!                                CONTAINING THE ORIGINAL
!                                VERTICAL AXIS DATA POINTS.
!                     --X      = SINGLE PRECISION VARIABLE
!                                CONTAINING THE ORIGINAL
!                                HORIZONTAL AXIS DATA POINTS.
!                     --X2     = SINGLE PRECISION VARIABLE
!                                CONTAINING THE DESIRED
!                                HORIZONTAL AXIS INTERPOLATION
!                                POINTS.
!     OUTPUT ARGUMENTS--Y2     = SINGLE PRECISION VARIABLE
!                                CONTAINING THE COMPUTED
!                                VERTICAL AXIS INTERPOLATION
!                                POINTS.
!     NOTE--IT IS PROBABLY NOT PERMISSIBLE TO HAVE THE OUTPUT VECTOR Y2(.)
!           BEING IDENTICAL TO THE INPUT VECTOR Y(.)
!     NOTE--THIS SUBROUTINE DOES NOT ASSUME THAT THE INPUT
!           DATA IS ALREADY SORTED ACCORDING TO THE
!           HORIZONTAL AXIS VARIABLE.
!           SUCH SORTING IS DOEN HEREIN.
!     CAUTION--THE INPUT VECTORS Y AND X ARE SORTED HEREIN
!              AND SO MAY BE DIFFERENT UPON LEAVING THIS SUBROUTINE
!              THAN UPON ENTERING THIS SUBROUTINE.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--87/4
!     ORIGINAL VERSION--APRIL     1987.
!     UPDATED         --MAY       1989. SORT THE INPUT DATA
!     UPDATED         --JUNE      1990. TEMPORARY ARRAYS TO GARBAGE COMMON.
!                                       ARRAY DECLARATIONS MOVED FROM INTER2
!     UPDATED         --MAY       1994. ADD ISUBRO ARGUMENT
!     UPDATED         --JULY      2019. MOVE CREATION OF SCRATCH STORAGE
!                                       TO CALLING ROUTINE
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGG3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION X(*)
      DIMENSION X2(*)
      DIMENSION Y2(*)
!
      DIMENSION YTEMP(*)
      DIMENSION YDIST(*)
      DIMENSION XDIST(*)
!
      DIMENSION DELX(*)
      DIMENSION DELY(*)
      DIMENSION DERIV(*)
      DIMENSION DELX6(*)
      DIMENSION P(*)
      DIMENSION B(*)
      DIMENSION Z(*)
      DIMENSION C(4,MAXNXT)
      DIMENSION A(MAXNXT,3)
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='INTE'
      ISUBN2='RP  '
      IERROR='NO'
!
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'TERP')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF INTERP--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)N,N2
   52   FORMAT('N,N2 = ',2I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,Y(I),X(I)
   56     FORMAT('I,Y(I),X(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
        DO 65 I=1,N2
          WRITE(ICOUT,66)I,X2(I)
   66     FORMAT('I,X2(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   65   CONTINUE
      ENDIF
!
!               ****************************************
!               **  STEP 11--                         **
!               **  SORT THE INPUT DATA ACCORDING     **
!               **  TO THE HORIZONTAL AXIS VARIABLE   **
!               ****************************************
!
!CCCC THE FOLLOWING LINE WAS INSERTED MAY 1989
      CALL SORTC(X,Y,N,X,Y)
!
!               ********************************************************
!               **  STEP 12--                                         **
!               **  DETERMINE THE NUMBER OF DISTINCT X VALUES         **
!               ********************************************************
!
      ISTEPN='12'
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'TERP')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NDIST=0
      DO 1210 I=1,N
        IF(NDIST.EQ.0)GO TO 1220
        DO 1215 I2=1,NDIST
          IF(X(I).EQ.XDIST(I2))GO TO 1210
 1215   CONTINUE
 1220   CONTINUE
        NDIST=NDIST+1
        XDIST(NDIST)=X(I)
 1210 CONTINUE
!
      CALL SORT(XDIST,NDIST,XDIST)
!
!               *****************************************************
!               **  STEP 13--                                      **
!               **  IF ALL DISTINCT (THAT IS, NO REPLICATION),     **
!               **  (THAT IS, HAVE NO REPLICATION),                **
!               **  THEN COPY OVER Y VALUES.                       **
!               **  IF NOT ALL DISTINCT                            **
!               **  (THAT IS, HAVE SOME REPLICATION),              **
!               **  THEN COMPUTE A MEAN VALUE OVER THE REPLICATES  **
!               **  AND TREAT THAT AS THE COMMON VALUE.            **
!               **  THE CORE OF THE INTERPOLATION CODE             **
!               **  IS EXPECTING SORTED, DISTINCT X VALUES.        **
!               *****************************************************
!
      IF(NDIST.EQ.N)THEN
        DO 1311 K=1,NDIST
          YDIST(K)=Y(K)
 1311   CONTINUE
      ELSE
        DO 1321 K=1,NDIST
          TAG=XDIST(K)
          J=0
          DO 1322 I=1,N
            IF(X(I).EQ.TAG)THEN
              J=J+1
              YTEMP(J)=Y(I)
            ENDIF
 1322     CONTINUE
          NI=J
          CALL MEAN(YTEMP,NI,IWRITE,YMEAN,IBUGG3,IERROR)
          YDIST(K)=YMEAN
 1321   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 14--                             **
!               **  COMPUTE INTERPOLATED VALUES           **
!               ********************************************
!
!CCCC THE REMAINDER OF THIS SUBROUTINE WAS REPLACED    MAY 1989
!CCCC BY A CALL TO INTER2                              MAY 1989
!
!CCCC JUNE, 1990.  MOVE SOME DIMENSIONING FROM INTER2 TO INTERP
!
      CALL INTER2(YDIST,XDIST,NDIST,X2,N2,Y2,   &
                  DELX,DELY,DERIV,DELX6,P,B,Z,C,A,MAXNXT,   &
                  IBUGG3,ISUBRO,IERROR)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'TERP')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF INTERP--')
        CALL DPWRST('XXX','BUG ')
        DO 9015 I=1,N
          WRITE(ICOUT,9016)A(I,1),A(I,2),A(I,3)
 9016     FORMAT('A(I,1),A(I,2),A(I,3)        = ',3G15.7)
          CALL DPWRST('XXX','BUG ')
 9015   CONTINUE
        DO 9025 I=1,N
          WRITE(ICOUT,9026)DELX(I),DELY(I),DERIV(I),DELX6(I),B(I),Z(I)
 9026     FORMAT('DELX(I),DELY(I),DERIV(I),DELX6(I),B(I),Z(I) = ',   &
                 6F10.5)
          CALL DPWRST('XXX','BUG ')
 9025   CONTINUE
        DO 9035 I=1,N
          WRITE(ICOUT,9036)C(1,I),C(2,I),C(3,I),C(4,I)
 9036     FORMAT('C(1,I),C(2,I),C(3,I),C(4,I) = ',4F10.5)
          CALL DPWRST('XXX','BUG ')
 9035   CONTINUE
        DO 9042 I=1,N2
          WRITE(ICOUT,9043)I,X2(I),Y2(I)
 9043     FORMAT('I,X2(I),Y2(I) = ',I8,2E15.7)
          CALL DPWRST('XXX','BUG ')
 9042   CONTINUE
        WRITE(ICOUT,9051)NDIST
 9051   FORMAT('NDIST = ',I8)
        CALL DPWRST('XXX','BUG ')
        DO 9052 I=1,NDIST
          WRITE(ICOUT,9053)I,XDIST(I),YDIST(I)
 9053     FORMAT('I,XDIST(I),YDIST(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
 9052   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE INTERP
      SUBROUTINE INTER2(Y,X,N,X2,N2,Y2,   &
                        DELX,DELY,DERIV,DELX6,P,B,Z,C,A,MAXOBV,   &
                        IBUGG3,ISUBRO,IERROR)
!CCCC MAY, 1994.  ADD ISUBRO ARGUMENT
!CCCC JUNE, 1990.  SOME DIMENSIONING MOVED FROM INTER2 TO INTERP
!
!     PURPOSE--COMPUTE SPLINE INTERPOLATION OF A VARIABLE
!              (GENERATE INTERPOLATED POINTS).
!     INPUT  ARGUMENTS--Y      = SINGLE PRECISION VARIABLE
!                                CONTAINING THE ORIGINAL
!                                VERTICAL AXIS DATA POINTS.
!                     --X      = SINGLE PRECISION VARIABLE
!                                CONTAINING THE ORIGINAL
!                                HORIZONTAL AXIS DATA POINTS.
!                     --X2     = SINGLE PRECISION VARIABLE
!                                CONTAINING THE DESIRED
!                                HORIZONTAL AXIS INTERPOLATION
!                                POINTS.
!     OUTPUT ARGUMENTS--Y2     = SINGLE PRECISION VARIABLE
!                                CONTAINING THE COMPUTED
!                                VERTICAL AXIS INTERPOLATION
!                                POINTS.
!     NOTE--IT IS PROBABLY NOT PERMISSIBLE TO HAVE THE OUTPUT VECTOR Y2(.)
!           BEING IDENTICAL TO THE INPUT VECTOR Y(.)
!     NOTE--THIS SUBROUTINE DOES NOT ASSUME THAT THE INPUT
!           DATA IS ALREADY SORTED ACCORDING TO THE
!           HORIZONTAL AXIS VARIABLE.
!           SUCH SORTING IS DOEN HEREIN.
!     CAUTION--THE INPUT VECTORS Y AND X ARE SORTED HEREIN
!              AND SO MAY BE DIFFERENT UPON LEAVING THIS SUBROUTINE
!              THAN UPON ENTERING THIS SUBROUTINE.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--87/4
!     ORIGINAL VERSION--APRIL     1987.
!     UPDATED         --MAY       1989.  SORT THE INPUT DATA
!     UPDATED         --JUNE      1990.  MOVE DIMENSIONS FROM INTER2 TO INTERP
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IBUGG3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!CCCC CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
!CCCC JUNE, 1990.  FOLLOWING INCLUDE FILE NO LONGER NEEDED
!CCCC      INCLUDE 'DPCOPA.INC'
!
      DIMENSION Y(*)
      DIMENSION X(*)
      DIMENSION X2(*)
      DIMENSION Y2(*)
!
!CCCC JUNE, 1990.  FOLLOWING DIMENSIONS NOW DONE IN INTERP
!CCCC DIMENSION DELX(MAXOBV)
!CCCC DIMENSION DELY(MAXOBV)
!CCCC DIMENSION DERIV(MAXOBV)
!CCCC DIMENSION DELX6(MAXOBV)
!CCCC DIMENSION P(MAXOBV)
!CCCCCDIMENSION B(MAXOBV)
!CCCC DIMENSION Z(MAXOBV)
      DIMENSION DELX(*)
      DIMENSION DELY(*)
      DIMENSION DERIV(*)
      DIMENSION DELX6(*)
      DIMENSION P(*)
      DIMENSION B(*)
      DIMENSION Z(*)
      DIMENSION C(4,MAXOBV)
      DIMENSION A(MAXOBV,3)
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='INTE'
      ISUBN2='RP  '
      IERROR='NO'
!
      IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'TER2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF INTER2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)N,N2,P(1)
   52   FORMAT('N,N2,P(1) = ',2I8,2X,G15.7)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,Y(I),X(I)
   56     FORMAT('I,Y(I),X(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
        DO 65 I=1,N2
          WRITE(ICOUT,66)I,X2(I)
   66     FORMAT('I,X2(I) = ',I8,E15.7)
          CALL DPWRST('XXX','BUG ')
   65   CONTINUE
      ENDIF
!
      NM1=N-1
      NM2=N-2
!
!               ********************************************
!               **  STEP 21--                             **
!               **  FORM FIRST DIFFERENCES AND THE RATIOS **
!               ********************************************
!
      DO 2100 I=1,NM1
      IP1=I+1
      DELX(I)=X(IP1)-X(I)
      DELY(I)=Y(IP1)-Y(I)
      DERIV(I)=DELY(I)/DELX(I)
      DELX6(I)=DELX(I)/6.0
 2100 CONTINUE
!
!               **********************************
!               **  STEP 22--                   **
!               **  FORM DIFFERENCES OF RATIOS  **
!               **********************************
!
      DO 2200 I=2,NM1
      IM1=I-1
      B(I)=DERIV(I)-DERIV(IM1)
 2200 CONTINUE
!
!               **********************
!               **  STEP 23--
!               **********************
!
      A(1,2)=(-1.0-DELX(1)/DELX(2))
      A(1,3)=DELX(1)/DELX(2)
      A(2,3)=DELX6(2)-DELX6(1)*A(1,3)
      A(2,2)=2.0*(DELX6(1)+DELX6(2))-DELX6(1)*A(1,2)
      A(2,3)=A(2,3)/A(2,2)
      B(2)=B(2)/A(2,2)
!
!               ****************************************
!               **  STEP 24--
!               ****************************************
!
      DO 2400 I=3,NM1
      IM1=I-1
      A(I,2)=2.0*(DELX6(IM1)+DELX6(I))-DELX6(IM1)*A(IM1,3)
      B(I)=B(I)-DELX6(IM1)*B(IM1)
      A(I,3)=DELX6(I)/A(I,2)
      B(I)=B(I)/A(I,2)
 2400 CONTINUE
!
!               ****************************************
!               **  STEP 25--
!               ****************************************
!
      Q=DELX(NM2)/DELX(NM1)
      A(N,1)=1.0+Q+A(NM2,3)
      A(N,2)=(-Q-A(N,1)*A(NM1,3))
      B(N)=B(NM2)-A(N,1)*B(NM1)
      Z(N)=B(N)/A(N,2)
!
!               ****************************************
!               **  STEP 26--
!               ****************************************
!
      DO 2600 I=1,NM2
      K=N-I
      KP1=K+1
      Z(K)=B(K)-A(K,3)*Z(KP1)
 2600 CONTINUE
      Z(1)=(-A(1,2)*Z(2)-A(1,3)*Z(3))
!
!               ****************************************
!               **  STEP 27--                         **
!               ****************************************
!
      DO 2700 I=1,NM1
      IP1=I+1
      Q=1.0/(6.0*DELX(I))
      C(1,I)=Z(I)*Q
      C(2,I)=Z(IP1)*Q
      C(3,I)=Y(I)/DELX(I)-Z(I)*DELX6(I)
      C(4,I)=Y(IP1)/DELX(I)-Z(IP1)*DELX6(I)
 2700 CONTINUE
!
!               ****************************************
!               **  STEP 28--
!               **  PRINT OUT Z'S
!               ****************************************
!
      IF(IBUGG3.EQ.'ON')THEN
        DO 2800 I=1,N
          WRITE(ICOUT,2810)I,Z(I)
 2810     FORMAT('I,Z(I) = ',I8,E15.7)
          CALL DPWRST('XXX','BUG ')
 2800   CONTINUE
      ENDIF
!
!               ****************************************
!               **  STEP 31--
!               **  COMPUTE INTERPOLATION VALUES
!               ****************************************
!
      DO 3100 J=1,N2
      XT=X2(J)
      IF(X(1).GT.XT)GO TO 3110
      GO TO 3119
!
 3110 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3111)
 3111 FORMAT('***** ERROR IN INTER2--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3112)
 3112 FORMAT('      AN ATTEMPT WAS MADE TO COMPUTE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3113)
 3113 FORMAT('      A SMOOTHED VALUE BEYOND THE RANGE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3114)
 3114 FORMAT('      OF THE DATA--SUCH EXTRAPOLATION')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3115)
 3115 FORMAT('      IS UNRELIABLE AND NOT PERMITTED.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3116)X(1)
 3116 FORMAT('         SMALLEST DATA POINT X(1)      = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3117)XT
 3117 FORMAT('         ATTEMPTED EXTRAPOLATION POINT = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
 3119 CONTINUE
!
      DO 3200 I=1,N
      I2=I
      IF(X(I).EQ.XT)GO TO 3210
      IF(X(I).GT.XT)GO TO 3220
 3200 CONTINUE
!
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3201)
 3201 FORMAT('***** ERROR IN INTER2--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3202)
 3202 FORMAT('      AN ATTEMPT WAS MADE TO COMPUTE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3203)
 3203 FORMAT('      A SMOOTHED VALUE BEYOND THE RANGE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3204)
 3204 FORMAT('      OF THE DATA--SUCH EXTRAPOLATION')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3205)
 3205 FORMAT('      IS UNRELIABLE AND NOT PERMITTED.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3206)X(1)
 3206 FORMAT('         LARGEST  DATA POINT X(1)      = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3207)XT
 3207 FORMAT('         ATTEMPTED EXTRAPOLATION POINT = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
!
 3210 CONTINUE
      Y2(J)=Y(I2)
      GO TO 3100
!
 3220 CONTINUE
      K=I2-1
      KP1=K+1
      DELU=X(KP1)-XT
      DELL=XT-X(K)
      TERM1=DELU*(C(1,K)*DELU**2+C(3,K))
      TERM2=DELL*(C(2,K)*DELL**2+C(4,K))
      Y2(J)=TERM1+TERM2
 3100 CONTINUE
!
!               ****************************************
!               **  STEP 41--
!               **  IF CALLED FOR,
!               **  WRITE OUT INTERPOLATION VALUES
!               ****************************************
!
      IF(IBUGG3.EQ.'ON')THEN
        DO 4100 J=1,N2
          WRITE(ICOUT,4110)X2(J),Y2(J)
          CALL DPWRST('XXX','BUG ')
 4110     FORMAT('X2(J),Y2(J) = ',2E15.7)
 4100   CONTINUE
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'TER2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF INTER2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)N,N2
 9012   FORMAT('N,N2 = ',2I8)
        CALL DPWRST('XXX','BUG ')
        DO 9015 I=1,N
          WRITE(ICOUT,9016)A(I,1),A(I,2),A(I,3)
 9016     FORMAT('A(I,1),A(I,2),A(I,3)        = ',3E15.7)
          CALL DPWRST('XXX','BUG ')
 9015   CONTINUE
        DO 9025 I=1,N
         WRITE(ICOUT,9026)DELX(I),DELY(I),DERIV(I),DELX6(I),B(I),Z(I)
 9026    FORMAT('DELX(I),DELY(I),DERIV(I),DELX6(I),B(I),Z(I) = ',   &
                6F10.5)
         CALL DPWRST('XXX','BUG ')
 9025   CONTINUE
        DO 9035 I=1,N
          WRITE(ICOUT,9036)C(1,I),C(2,I),C(3,I),C(4,I)
 9036     FORMAT('C(1,I),C(2,I),C(3,I),C(4,I) = ',4F10.5)
          CALL DPWRST('XXX','BUG ')
 9035   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE INTER2
      SUBROUTINE INTFCN(XTEMP,FHAT)
!
!     PURPOSE--AUXILLARY FUNCTION FOR THE QAGI (INDEFINITE INTEGRATION
!              ROUTINES).  IT COMPUTES THE FUNCTION BEING INTEGRATED
!              AT THE VALUE X AND RETURNS THE FUNCTION VALUE IN FHAT.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2013/6
!     ORIGINAL VERSION--JUNE      2013.
!     UPDATED         --SEPTEMBER 2015. SUPPORT FUNCTION BLOCKS
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      REAL XTEMP
      REAL FHAT
!
      CHARACTER*4 IH
      CHARACTER*4 IH2
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOFB.INC'
!
      COMMON/IFBL2/IFLGFB
!
      CHARACTER*8 IFBNAM
      CHARACTER*8 IFBANS
!
      CHARACTER*4 IFEESV
      COMMON/IFEED/IFEESV
!
      CHARACTER*4 ZMODEL
      CHARACTER*4 IPARN
      CHARACTER*4 IPARN2
      CHARACTER*4 IANGLU
      CHARACTER*4 ITYPEH
      CHARACTER*4 IW21HO
      CHARACTER*4 IW22HO
      CHARACTER*4 IVARN
      CHARACTER*4 IVARN2
      CHARACTER*4 IBUGA3
      CHARACTER*4 IBUGCO
      CHARACTER*4 IBUGEV
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IFTEXP
      CHARACTER*4 IFTORD
      CHARACTER*4 IFORSW
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
!
!---------------------------------------------------------------------
!
      PARAMETER (IOPTCH=1000)
      PARAMETER (IOPTC2=100)
!
      DIMENSION PARAM(IOPTC2)
      DIMENSION IPARN(IOPTC2)
      DIMENSION IPARN2(IOPTC2)
      DIMENSION IVARN(IOPTC2)
      DIMENSION IVARN2(IOPTC2)
!
      DIMENSION ZMODEL(IOPTCH)
      DIMENSION ITYPEH(IOPTCH)
      DIMENSION IW21HO(IOPTCH)
      DIMENSION IW22HO(IOPTCH)
      DIMENSION W2HOLD(IOPTCH)
!
      DIMENSION ILOCV(IOPTC2)
!CCCC DIMENSION ILAB(IOPTC2)
!
      COMMON /OPTCMC/ IBUGA3, ITYPEH, IW21HO, IW22HO, IPARN, IPARN2,   &
                      IVARN, IVARN2, ZMODEL
      COMMON /OPTCMR/ PARAM, W2HOLD,   &
                      NUMCHA, NUMVAR, NWHOLD, NUMDV, ILOCV
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IERROR='NO'
      IFOUND='NO'
      ISUBRO='NULL'
      IFTEXP='+'
      IFTORD='DATA'
      IFORSW='E'
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('AT THE BEGINNING OF INTFCN--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)NUMCHA,NUMDV,NUMVAR,IFLGFB,XTEMP
   53   FORMAT('NUMCHA,NUMDV,NUMVAR,IFLGFB,XTEMP = ',4I8,G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,54)(ZMODEL(J),J=1,MIN(NUMCHA,25))
   54   FORMAT('ZMODEL(I) = ',25A4)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,NUMVAR
          WRITE(ICOUT,56)I,PARAM(I),IPARN(I),IPARN2(I)
   56     FORMAT('I,PARAM(I),IPARN(I),IPARN2(I) = ',I8,G15.7,A4,A4)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
        DO 59 I=1,NUMDV
          WRITE(ICOUT,61)I,IVARN(I),IVARN2(I)
   61     FORMAT('I, IVARN(I),IVARN2(I) = ',I8,2X,A4,A4)
          CALL DPWRST('XXX','BUG ')
   59   CONTINUE
      ENDIF
!
!               ***************************
!               **  STEP 3--             **
!               **  INITIALIZE PARAMETERS**
!               ***************************
!
      ISTEPN='3'
      IF(IBUGA3.EQ.'ON')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IFBNAM=' '
      IFBANS=' '
      IF(IFLGFB.EQ.1)THEN
        IFBNAM=IFBNA1
        IFBANS=IFBAN1
        IH=IFBPL1(1)(1:4)
        IH2=IFBPL1(1)(5:8)
      ELSEIF(IFLGFB.EQ.2)THEN
        IFBNAM=IFBNA2
        IFBANS=IFBAN2
        IH=IFBPL2(1)(1:4)
        IH2=IFBPL2(1)(5:8)
      ELSEIF(IFLGFB.EQ.3)THEN
        IFBNAM=IFBNA3
        IFBANS=IFBAN3
        IH=IFBPL3(1)(1:4)
        IH2=IFBPL3(1)(5:8)
      ENDIF
!
      IF(IFLGFB.LE.0)THEN
        JLOC=ILOCV(1)
        PARAM(JLOC)=XTEMP
!
        IPASS=2
        IBUGCO=IBUGA3
        IBUGEV=IBUGA3
        FX=0.0
        CALL COMPIM(ZMODEL,NUMCHA,IPASS,PARAM,IPARN,IPARN2,NUMVAR,   &
                    IANGLU,ITYPEH,IW21HO,IW22HO,W2HOLD,NWHOLD,FX,   &
                    IBUGCO,IBUGEV,IERROR)
        FHAT=FX
      ELSE
!
!       FUNCTION BLOCK CASE:
!
!       STEP 1: COMPUTE FUNCTION BLOCK (BUT FIRST SET CURRENT
!               VALUE OF DESIRED PARAMETER)
!
        DO 3305 II=1,NUMNAM
          IF(IH.EQ.IHNAME(II) .AND. IH2.EQ.IHNAM2(II) .AND.   &
             IUSE(II).EQ.'P')THEN
            VALUE(II)=XTEMP
            IVALUE(II)=INT(XTEMP+0.5)
            GO TO 3309
          ENDIF
 3305   CONTINUE
!
!       PARAMETER NAME NOT FOUND IN CURRENT LIST, SO NEED TO ADD
!       TO NAME LIST
!
        IF(NUMNAM.LT.MAXNAM)THEN
          NUMNAM=NUMNAM+1
          IHNAME(NUMNAM)=IH
          IHNAM2(NUMNAM)=IH2
          IUSE(NUMNAM)='P'
          VALUE(NUMNAM)=XTEMP
          IVALUE(NUMNAM)=INT(XTEMP + 0.5)
        ELSE
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,3306)
 3306     FORMAT('***** ERROR IN INTEGRATION--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,3307)
 3307     FORMAT('      MAXIMUM NUMBER OF NAMES EXCEEDED.')
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
 3309   CONTINUE
!
        IFEEDB='OFF'
        CALL DPFBEX(IFBNAM,IANGLU,ISEED,IFTEXP,IFTORD,IFORSW,   &
                    IBUGA3,IBUGA3,IBUGCO,IBUGEV,IBUGEV,   &
                    ISUBRO,IFOUND,IERROR)
        IFEEDB=IFEESV
!
!       STEP 2: RETRIEVE RESPONSE
!
        DO 3320 II=1,NUMNAM
          IF(IFBANS(1:4).EQ.IHNAME(II) .AND.   &
             IFBANS(5:8).EQ.IHNAM2(II))THEN
            IF(IUSE(II).EQ.'P')THEN
              FHAT=VALUE(II)
              GO TO 3329
            ELSEIF(IUSE(II).EQ.'V')THEN
              ICOLR=IVALUE(II)
              IJ=MAXN*(ICOLR-1)+1
              IF(ICOLR.LE.MAXCOL)FHAT=V(IJ)
              IF(ICOLR.EQ.MAXCP1)FHAT=PRED(1)
              IF(ICOLR.EQ.MAXCP2)FHAT=RES(1)
              IF(ICOLR.EQ.MAXCP3)FHAT=YPLOT(1)
              IF(ICOLR.EQ.MAXCP4)FHAT=XPLOT(1)
              IF(ICOLR.EQ.MAXCP5)FHAT=X2PLOT(1)
              IF(ICOLR.EQ.MAXCP6)FHAT=TAGPLO(1)
              GO TO 3329
            ENDIF
          ENDIF
 3320   CONTINUE
!
!       PARAMETER/VARIABLE NAME NOT FOUND
!
        WRITE(ICOUT,3306)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,3321)
 3321   FORMAT('      EXPECTED PARAMETER/VARIABLE NOT FOUND IN ',   &
               'NAME TABLE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,3323)IFBANS
 3323   FORMAT('      EXPECTED NAME = ',A8)
        CALL DPWRST('XXX','BUG ')
!
 3329   CONTINUE
!
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END      OF INTFCN--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9021)IERROR
 9021   FORMAT('IERROR = ',A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9101)XTEMP,FHAT
 9101   FORMAT('XTEMP,FHAT = ',2G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE INTFCN
      SUBROUTINE INTLIN (X1,Y1,X2,Y2,X3,Y3,X4,Y4,N,   &
                         XOUT,YOUT,NOUT,   &
                         IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--THIS ROUTINE FINDS THE INTERSECTION POINT OF TWO
!              LINES.  EACH LINE IS DEFINED BY TWO POINTS, SO
!              THERE ARE FOUR POINTS IN ALL:
!
!                 (X1,Y1) = COORDINATES FOR POINT ONE OF LINE ONE
!                 (X2,Y2) = COORDINATES FOR POINT TWO OF LINE ONE
!                 (X3,Y3) = COORDINATES FOR POINT ONE OF LINE TWO
!                 (X4,Y4) = COORDINATES FOR POINT TWO OF LINE TWO
!
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2012.10
!     ORIGINAL VERSION--OCTOBER   2012.
!
!-----NON-COMMON VARIABLES (GRAPHICS)-------------------------------------
!
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      REAL X1(*)
      REAL Y1(*)
      REAL X2(*)
      REAL Y2(*)
      REAL X3(*)
      REAL Y3(*)
      REAL X4(*)
      REAL Y4(*)
      REAL XOUT(*)
      REAL YOUT(*)
      REAL A1
      REAL B1
      REAL C1
      REAL A2
      REAL B2
      REAL C2
      REAL DENOM
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'TLIN')THEN
        WRITE(ICOUT,51)N
   51   FORMAT('AT THE BEGININNING OF INTLIN--N = ',I8)
        CALL DPWRST('XXX','BUG ')
        DO 59 I=1,N
          WRITE(ICOUT,53)I,X1(I),Y1(I),X2(I),Y2(I)
   53     FORMAT('I,X1(I),Y1(I),X2(I),Y2(I) = ',I8,4G15.7)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,55)I,X3(I),Y3(I),X4(I),Y4(I)
   55     FORMAT('I,X3(I),Y3(I),X4(I),Y4(I) = ',I8,4G15.7)
          CALL DPWRST('XXX','BUG ')
   59   CONTINUE
      ENDIF
!
      IERROR='NO'
!
      DO 100 I=1,N
        A1=Y2(I) - Y1(I)
        B1=X1(I) - X2(I)
        C1=X2(I)*Y1(I) - X1(I)*Y2(I)
        A2=Y4(I) - Y3(I)
        B2=X3(I) - X4(I)
        C2=X4(I)*Y3(I) - X3(I)*Y4(I)
        DENOM=A1*B2 - A2*B1
        IF(DENOM.EQ.0.0)THEN
          XOUT(I)=CPUMIN
          YOUT(I)=CPUMIN
        ELSE
          XOUT(I)=(B1*C2 - B2*C1)/DENOM
          YOUT(I)=(A2*C1 - A1*C2)/DENOM
        ENDIF
  100 CONTINUE
      NOUT=N
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'TLIN')THEN
        WRITE(ICOUT,9051)
 9051   FORMAT('AT THE END OF INTLIN')
        CALL DPWRST('XXX','BUG ')
        DO 9059 I=1,N
          WRITE(ICOUT,9053)I,XOUT(I),YOUT(I)
 9053     FORMAT('I,X3(I),Y3(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
 9059   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE INTLIN 
      SUBROUTINE INTLI2 (X1,Y1,X2,Y2,X3,Y3,X4,Y4,   &
                         XOUT,YOUT,   &
                         IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--THIS ROUTINE FINDS THE INTERSECTION POINT OF TWO
!              LINES.  EACH LINE IS DEFINED BY TWO POINTS, SO
!              THERE ARE FOUR POINTS IN ALL:
!
!                 (X1,Y1) = COORDINATES FOR POINT ONE OF LINE ONE
!                 (X2,Y2) = COORDINATES FOR POINT TWO OF LINE ONE
!                 (X3,Y3) = COORDINATES FOR POINT ONE OF LINE TWO
!                 (X4,Y4) = COORDINATES FOR POINT TWO OF LINE TWO
!
!              THIS IS SIMILAR TO INTLIN.  THE DISTINCTION IS THAT
!              INTLIN ACCEPTS ARRAY ARGUMENTS WHILE INTLI2 ACCEPTS
!              SCALAR ARGUMENTS.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2012.10
!     ORIGINAL VERSION--OCTOBER   2012.
!
!-----NON-COMMON VARIABLES (GRAPHICS)-------------------------------------
!
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      REAL X1
      REAL Y1
      REAL X2
      REAL Y2
      REAL X3
      REAL Y3
      REAL X4
      REAL Y4
      REAL XOUT
      REAL YOUT
      REAL A1
      REAL B1
      REAL C1
      REAL A2
      REAL B2
      REAL C2
      REAL DENOM
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'TLI2')THEN
        WRITE(ICOUT,51)
   51   FORMAT('AT THE BEGININNING OF INTLI2')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)X1,Y1,X2,Y2,X3,Y3,X4,Y4
   53   FORMAT('X1,Y1,X2,Y2,X3,Y3,X4,Y4 = ',8G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IERROR='NO'
!
      A1=Y2 - Y1
      B1=X1 - X2
      C1=X2*Y1 - X1*Y2
      A2=Y4 - Y3
      B2=X3 - X4
      C2=X4*Y3 - X3*Y4
      DENOM=A1*B2 - A2*B1
      IF(DENOM.EQ.0.0)THEN
        XOUT=CPUMIN
        YOUT=CPUMIN
      ELSE
        XOUT=(B1*C2 - B2*C1)/DENOM
        YOUT=(A2*C1 - A1*C2)/DENOM
      ENDIF
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'TLIN')THEN
        WRITE(ICOUT,9051)
 9051   FORMAT('AT THE END OF INTLIN')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9053)XOUT,YOUT
 9053   FORMAT('X3(I),Y3(I) = ',2G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE INTLI2 
      SUBROUTINE INTRV(XT,LXT,X,ILO,ILEFT,MFLAG)
!***BEGIN PROLOGUE  INTRV
!***DATE WRITTEN   800901   (YYMMDD)
!***REVISION DATE  820801   (YYMMDD)
!***CATEGORY NO.  E3,K6
!***KEYWORDS  B-SPLINE,DATA FITTING,INTERPOLATION,SPLINE
!***AUTHOR  AMOS, D. E., (SNLA)
!***PURPOSE  Computes the largest integer ILEFT in 1.LE.ILEFT.LE.LXT
!            such that XT(ILEFT).LE.X where XT(*) is a subdivision
!            of the X interval.
!***DESCRIPTION
!
!     Written by Carl de Boor and modified by D. E. Amos
!
!     Reference
!         SIAM J. Numerical Analysis, 14, No. 3, June 1977, pp. 441-472.
!
!     Abstract
!         INTRV is the INTERV routine of the reference.
!
!         INTRV computes the largest integer ILEFT in 1 .LE. ILEFT .LE.
!         LXT such that XT(ILEFT) .LE. X where XT(*) is a subdivision of
!         the X interval.  Precisely,
!
!                      X .LT. XT(1)                1         -1
!         if  XT(I) .LE. X .LT. XT(I+1)  then  ILEFT=I  , MFLAG=0
!           XT(LXT) .LE. X                         LXT        1,
!
!         That is, when multiplicities are present in the break point
!         to the left of X, the largest index is taken for ILEFT.
!
!     Description of Arguments
!         Input
!          XT      - XT is a knot or break point vector of length LXT
!          LXT     - length of the XT vector
!          X       - argument
!          ILO     - an initialization parameter which must be set
!                    to 1 the first time the spline array XT is
!                    processed by INTRV.
!
!         Output
!          ILO     - ILO contains information for efficient process-
!                    ing after the initial call, and ILO must not be
!                    changed by the user.  Distinct splines require
!                    distinct ILO parameters.
!          ILEFT   - largest integer satisfying XT(ILEFT) .LE. X
!          MFLAG   - signals when X lies out of bounds
!
!     Error Conditions
!         None
!***REFERENCES  C. DE BOOR, *PACKAGE FOR CALCULATING WITH B-SPLINES*,
!                 SIAM JOURNAL ON NUMERICAL ANALYSIS, VOLUME 14, NO. 3,
!                 JUNE 1977, PP. 441-472.
!***ROUTINES CALLED  (NONE)
!***END PROLOGUE  INTRV
!
!
      INTEGER IHI, ILEFT, ILO, ISTEP, LXT, MFLAG, MIDDLE
      REAL X, XT
      DIMENSION XT(LXT)
!***FIRST EXECUTABLE STATEMENT  INTRV
      IHI = ILO + 1
      IF (IHI.LT.LXT) GO TO 10
      IF (X.GE.XT(LXT)) GO TO 110
      IF (LXT.LE.1) GO TO 90
      ILO = LXT - 1
      IHI = LXT
!
   10 IF (X.GE.XT(IHI)) GO TO 40
      IF (X.GE.XT(ILO)) GO TO 100
!
! *** NOW X .LT. XT(IHI) . FIND LOWER BOUND
      ISTEP = 1
   20 IHI = ILO
      ILO = IHI - ISTEP
      IF (ILO.LE.1) GO TO 30
      IF (X.GE.XT(ILO)) GO TO 70
      ISTEP = ISTEP*2
      GO TO 20
   30 ILO = 1
      IF (X.LT.XT(1)) GO TO 90
      GO TO 70
! *** NOW X .GE. XT(ILO) . FIND UPPER BOUND
   40 ISTEP = 1
   50 ILO = IHI
      IHI = ILO + ISTEP
      IF (IHI.GE.LXT) GO TO 60
      IF (X.LT.XT(IHI)) GO TO 70
      ISTEP = ISTEP*2
      GO TO 50
   60 IF (X.GE.XT(LXT)) GO TO 110
      IHI = LXT
!
! *** NOW XT(ILO) .LE. X .LT. XT(IHI) . NARROW THE INTERVAL
   70 MIDDLE = (ILO+IHI)/2
      IF (MIDDLE.EQ.ILO) GO TO 100
!     NOTE. IT IS ASSUMED THAT MIDDLE = ILO IN CASE IHI = ILO+1
      IF (X.LT.XT(MIDDLE)) GO TO 80
      ILO = MIDDLE
      GO TO 70
   80 IHI = MIDDLE
      GO TO 70
! *** SET OUTPUT AND RETURN
   90 MFLAG = -1
      ILEFT = 1
      RETURN
  100 MFLAG = 0
      ILEFT = ILO
      RETURN
  110 MFLAG = 1
      ILEFT = LXT
      RETURN
      END SUBROUTINE INTRV
      SUBROUTINE INTVEC(Y,X,N,NUMVAR,IWRITE,XYINT,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE
!              INTEGRAL OF THE DATA IN THE INPUT VECTOR Y (IF NUMVAR = 1)
!              OR OF THE INTEGRAL OF Y (VERTICALLY)
!              WITH RESPECT TO X (HORIZONTALLY) (IF NUMVAR = 2).
!     NOTE--WHEN NUMVAR = 1, IT IS ASSUMED THAT THE
!           HORIZONTAL AXIS VARIABLE IS EQUALLY-SPACED
!           WITH UNIT SPACING.
!     NOTE--THE TRAPEZOID RULE IS USED.
!     INPUT  ARGUMENTS--Y      = THE SINGLE PRECISION VECTOR OF
!                                VERTICAL AXIS OBSERVATIONS.
!                     --X      = THE SINGLE PRECISION VECTOR OF
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--XYINT  = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SAMPLE INTEGRAL.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE INTEGRAL.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--82.6
!     ORIGINAL VERSION--JANUARY   1979.
!     UPDATED         --JUNE      1979.
!     UPDATED         --JULY      1979.
!     UPDATED         --AUGUST    1981.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DXI
      DOUBLE PRECISION DYI
      DOUBLE PRECISION DXIM1
      DOUBLE PRECISION DYIM1
      DOUBLE PRECISION DDELX
      DOUBLE PRECISION DDELY
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DSUM
!
      DIMENSION X(*)
      DIMENSION Y(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='INTV'
      ISUBN2='EC  '
      IERROR='NO'
!
      DXI=0.0D0
      DYI=0.0D0
      DXIM1=0.0D0
      DYIM1=0.0D0
!
      IF(IBUGA3.EQ.'OFF')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF INTVEC--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IBUGA3
   52 FORMAT('IBUGA3 = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)N,NUMVAR
   53 FORMAT('N,NUMVAR = ',2I8)
      CALL DPWRST('XXX','BUG ')
      DO 55 I=1,N
      WRITE(ICOUT,56)I,X(I),Y(I)
   56 FORMAT('I,X(I),Y(I) = ',I8,2E15.7)
      CALL DPWRST('XXX','BUG ')
   55 CONTINUE
   90 CONTINUE
!
!               *******************************************
!               **  COMPUTE     (NUMERICAL) INTEGRAL     **
!               *******************************************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.GE.1)GO TO 119
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,111)
  111 FORMAT('***** ERROR IN INTVEC--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,112)
  112 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,113)
  113 FORMAT('      IN THE VARIABLE FOR WHICH')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,114)
  114 FORMAT('      THE INTEGRAL IS TO BE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,115)
  115 FORMAT('      COMPUTED, MUST BE 1 OR LARGER.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,116)
  116 FORMAT('      SUCH WAS NOT THE CASE HERE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,117)N
  117 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS HERE = ',I8,   &
      '.')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
  119 CONTINUE
!
      IF(N.EQ.1)GO TO 120
      GO TO 129
  120 CONTINUE
!CCCC WRITE(ICOUT,999)
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,121)
!C121 FORMAT('***** NON-FATAL DIAGNOSTIC IN INTVEC--',
!CCCC1'THE THIRD INPUT ARGUMENT (N) HAS THE VALUE 1')
!CCCC CALL DPWRST('XXX','BUG ')
      XYINT=0.0
      GO TO 800
  129 CONTINUE
!
      IF(NUMVAR.EQ.1.OR.NUMVAR.EQ.2)GO TO 139
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,131)
  131 FORMAT('***** INTERNAL ERROR IN INTVEC--',   &
      'THE FOURTH INPUT ARGUMENT (NUMVAR) HAS VALUE OTHER THAN 1 OR 2')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,132)NUMVAR
  132 FORMAT('      NUMVAR = ',I8)
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
  139 CONTINUE
!
      HOLD=Y(1)
      DO 145 I=2,N
      IF(Y(I).NE.HOLD)GO TO 149
  145 CONTINUE
!CCCC WRITE(ICOUT,999)
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,146)HOLD
!C146 FORMAT('***** NON-FATAL DIAGNOSTIC IN INTVEC--',
!CCCC1'THE FIRST  INPUT ARGUMENT (A VECTOR Y) HAS ALL ELEMENTS = ',
!CCCC1E15.7)
!CCCC CALL DPWRST('XXX','BUG ')
      GO TO 190
  149 CONTINUE
!
      IF(NUMVAR.LE.1)GO TO 159
      HOLD=X(1)
      DO 155 I=2,N
      IF(Y(I).NE.HOLD)GO TO 159
  155 CONTINUE
!CCCC WRITE(ICOUT,999)
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,156)HOLD
!C156 FORMAT('***** NON-FATAL DIAGNOSTIC IN INTVEC--',
!CCCC1'THE SECOND INPUT ARGUMENT (A VECTOR X) HAS ALL ELEMENTS = ',
!CCCC1E15.7)
!CCCC CALL DPWRST('XXX','BUG ')
      XYINT=0.0
      GO TO 800
  159 CONTINUE
!
  190 CONTINUE
!
!               ****************************************
!               **  STEP 2--                          **
!               **  COMPUTE THE (NUMERICAL) INTEGRAL  **
!               ****************************************
!
      DSUM=0.0D0
      I=1
      IF(NUMVAR.EQ.1)DXI=I
      IF(NUMVAR.EQ.2)DXI=X(I)
      DYI=Y(1)
      DO 200 I=2,N
      DXIM1=DXI
      DYIM1=DYI
      IF(NUMVAR.EQ.1)DXI=I
      IF(NUMVAR.EQ.2)DXI=X(I)
      DYI=Y(I)
      DDELX=DXI-DXIM1
      DDELY=DYI-DYIM1
      DTERM1=DYIM1*DDELX
      DTERM2=DDELY*DDELX/2.0D0
      DSUM=DSUM+DTERM1+DTERM2
  200 CONTINUE
      XYINT=DSUM
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
  800 CONTINUE
      IF(IFEEDB.EQ.'OFF')GO TO 890
      IF(IWRITE.EQ.'OFF')GO TO 890
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,811)N,XYINT
  811 FORMAT('THE (TRAPEZOID RULE) INTEGRAL OF THE ',I8,   &
      ' OBSERVATIONS = ',E15.7)
      CALL DPWRST('XXX','BUG ')
  890 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF INTVEC--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGA3,IERROR
 9012 FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)N
 9013 FORMAT('N = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9014)DXI,DYI,DXIM1,DYIM1
 9014 FORMAT('DXI,DYI,DXIM1,DYIM1 = ',4D15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9015)XYINT
 9015 FORMAT('XYINT = ',E15.7)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE INTVEC
      SUBROUTINE INT2D(Z,Y,X,N,Y2,NY,X2,NX,IWRITE,Z2,N2,   &
                       YTEMP,XTEMP,YDIST,XDIST,ZDIST,   &
                       ZTEMP,ZTEMP2,XNEW,YNEW,   &
                       WORK,IWORK,   &
                       IBUGG3,ISUBRO,IERROR)
!
!     PURPOSE--COMPUTE BIVARIATE INTERPOLATION OF SCATTERED DATA.
!              THE INTERPOLATION IS GENERATED ON A GRID.
!              THE BILINEAR INTERPOLATION WORKS ON DATA THAT FORMS A
!              GRID TO POINTS NOT ON THE GRID WHILE THIS ROUTINE
!              INTERPOLATES NON-GRIDDED DATA TO FORM A GRID.
!              A TYPICAL USE OF THIS ROUTINE IS TO GENERATE A CONTOUR
!              PLOT FROM NON-GRIDDED DATA.
!              (GENERATE INTERPOLATED POINTS).
!     INPUT  ARGUMENTS--Z      = SINGLE PRECISION VARIABLE
!                                CONTAINING THE ORIGINAL
!                                Z AXIS DATA POINTS.
!                     --Y      = SINGLE PRECISION VARIABLE
!                                CONTAINING THE ORIGINAL
!                                VERTICAL AXIS DATA POINTS.
!                     --X      = SINGLE PRECISION VARIABLE
!                                CONTAINING THE ORIGINAL
!                                HORIZONTAL AXIS DATA POINTS.
!                     --Y2     = SINGLE PRECISION VARIABLE
!                                CONTAINING THE DESIRED
!                                VERTICAL AXIS INTERPOLATION
!                     --X2     = SINGLE PRECISION VARIABLE
!                                CONTAINING THE DESIRED
!                                HORIZONTAL AXIS INTERPOLATION
!                                POINTS.
!     OUTPUT ARGUMENTS--Z2     = SINGLE PRECISION VARIABLE
!                                CONTAINING THE COMPUTED
!                                Z AXIS INTERPOLATION
!                                POINTS.
!     NOTE--IT IS PROBABLY NOT PERMISSIBLE TO HAVE THE OUTPUT VECTOR
!           Y2(.) BEING IDENTICAL TO THE INPUT VECTOR Y(.)
!     NOTE--THIS SUBROUTINE DOES NOT ASSUME THAT THE INPUT
!           DATA IS ALREADY SORTED ACCORDING TO THE
!           HORIZONTAL AXIS VARIABLE.
!           SUCH SORTING IS DOEN HEREIN.
!     CAUTION--THE INPUT VECTORS Y AND X ARE SORTED HEREIN
!              AND SO MAY BE DIFFERENT UPON LEAVING THIS SUBROUTINE
!              THAN UPON ENTERING THIS SUBROUTINE.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--94/5
!     ORIGINAL VERSION--MAY       1994.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGG3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 ISUBRO
!
      CHARACTER*4 IHP
      CHARACTER*4 IHP2
      CHARACTER*4 IHWUSE
      CHARACTER*4 MESSAG
!
!---------------------------------------------------------------------
!
      DIMENSION Z(*)
      DIMENSION Y(*)
      DIMENSION X(*)
      DIMENSION X2(*)
      DIMENSION Y2(*)
      DIMENSION Z2(*)
!
      DIMENSION YTEMP(*)
      DIMENSION XTEMP(*)
      DIMENSION YDIST(*)
      DIMENSION XDIST(*)
      DIMENSION ZDIST(*)
      DIMENSION ZTEMP2(*)
      DIMENSION ZTEMP(*)
      DIMENSION XNEW(*)
      DIMENSION YNEW(*)
!CCCC DIMENSION IWORK(7*MAXOBV)
!CCCC DIMENSION WORK(7*MAXOBV)
      DIMENSION IWORK(*)
      DIMENSION WORK(*)
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='INT2'
      ISUBN2='D   '
      IERROR='NO'
!
      ILAST=-99
!
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'NT2D')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF INT2D--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)N,NX,NY
   52   FORMAT('N,NX,NY = ',3I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,Z(I),Y(I),X(I)
   56     FORMAT('I,Z(I),Y(I),X(I) = ',I8,3G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
        DO 65 I=1,NX
          WRITE(ICOUT,66)I,X2(I)
   66     FORMAT('I,X2(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   65   CONTINUE
        DO 75 I=1,NY
          WRITE(ICOUT,76)I,Y2(I)
   76     FORMAT('I,Y2(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   75   CONTINUE
      ENDIF
!
!               ****************************************
!               **  STEP 11--                         **
!               **  SORT THE INPUT DATA ACCORDING     **
!               **  TO THE HORIZONTAL AXIS VARIABLE   **
!               ****************************************
!
      ISTEPN='11'
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'NT2D')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      DO 1010 ,I=1,N
        XTEMP(I)=X(I)
 1010 CONTINUE
!
      CALL SORTC(X,Y,N,X,Y)
      CALL SORTC(XTEMP,Z,N,XTEMP,Z)
!
!               *******************************************************
!               **  STEP 12--                                        **
!               **  DETERMINE THE NUMBER OF DISTINCT X VALUES        **
!               *******************************************************
!
      ISTEPN='12'
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'NT2D')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NDISTX=0
      DO 1210 I=1,N
        IF(NDISTX.EQ.0)GO TO 1220
        DO 1215 I2=1,NDISTX
          IF(X(I).EQ.XDIST(I2))GO TO 1210
 1215   CONTINUE
 1220   CONTINUE
        NDISTX=NDISTX+1
        XDIST(NDISTX)=X(I)
 1210 CONTINUE
!
      CALL SORT(XDIST,NDISTX,XDIST)
!
!               *******************************************************
!               **  STEP 13--                                        **
!               **  DETERMINE THE NUMBER OF DISTINCT Y VALUES        **
!               *******************************************************
!
      ISTEPN='13'
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'NT2D')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NDISTY=0
      DO 1310 I=1,N
        IF(NDISTY.EQ.0)GO TO 1320
        DO 1315 I2=1,NDISTY
          IF(Y(I).EQ.YDIST(I2))GO TO 1310
 1315   CONTINUE
 1320   CONTINUE
        NDISTY=NDISTY+1
        YDIST(NDISTY)=Y(I)
 1310 CONTINUE
!
      CALL SORT(YDIST,NDISTY,YDIST)
!
!               *******************************************************
!               **  STEP 14--                                        **
!               **  SORT Y ASSOCIATED WITH EACH DISTINCT X VALUE     **
!               **  CHECK FOR REPLICATION OF POINTS                  **
!               **  IF ALL DISTINCT (THAT IS, NO REPLICATION),     **
!               **  (THAT IS, HAVE NO REPLICATION),                **
!               **  THEN COPY OVER Z VALUES.                       **
!               **  IF NOT ALL DISTINCT                            **
!               **  (THAT IS, HAVE SOME REPLICATION),              **
!               **  THEN COMPUTE A MEAN VALUE OVER THE REPLICATES  **
!               **  AND TREAT THAT AS THE COMMON VALUE.            **
!               *******************************************************
!
      ISTEPN='14'
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'NT2D')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NUMZ=0
      ISTART=1
      DO 1410 I=1,NDISTX
        XT=XDIST(I)
        ICOUNT=0
        DO 1420 J=ISTART,N
        IF(X(J).EQ.XT)THEN
          IF(ICOUNT.EQ.0)IFRST=J
          ICOUNT=ICOUNT+1
          YTEMP(ICOUNT)=Y(J)
          ZTEMP(ICOUNT)=Z(J)
          ILAST=J
        ELSEIF(X(J).GT.XT)THEN
          GO TO 1421
        ENDIF
 1420   CONTINUE
 1421   CONTINUE
!
        ISTART=ILAST+1
        CALL SORTC(YTEMP,ZTEMP,ICOUNT,YTEMP,ZTEMP)
        DO 1471 K=1,NDISTY
          TAG=YDIST(K)
          J=0
          DO 1472 II=1,ICOUNT
            IF(YTEMP(II).EQ.TAG)THEN
              J=J+1
              ZTEMP2(J)=ZTEMP(II)
            END IF
 1472     CONTINUE
          NI=J
          IF(NI.EQ.1)THEN
            NUMZ=NUMZ+1
            ZDIST(NUMZ)=ZTEMP2(1)
            XNEW(NUMZ)=XT
            YNEW(NUMZ)=TAG
          ELSE IF(NI.GT.1)THEN
            CALL MEAN(ZTEMP2,NI,IWRITE,ZMEAN,IBUGG3,IERROR)
            NUMZ=NUMZ+1
            ZDIST(NUMZ)=ZMEAN
            XNEW(NUMZ)=XT
            YNEW(NUMZ)=TAG
          ENDIF
 1471   CONTINUE
!
 1410 CONTINUE
!
!               *******************************************************
!               **  STEP 15--                                        **
!               **  DETERMINE THE NUMBER OF DISTINCT X VALUES        **
!               **  FOR THE INTERPOLATION POINTS                     **
!               *******************************************************
!
      ISTEPN='15'
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'NT2D')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NDISTX=0
      DO 1510 I=1,NX
        IF(NDISTX.EQ.0)GO TO 1520
        DO 1515 I2=1,NDISTX
          IF(X2(I).EQ.XDIST(I2))GO TO 1510
 1515   CONTINUE
 1520   CONTINUE
        NDISTX=NDISTX+1
        XDIST(NDISTX)=X2(I)
 1510 CONTINUE
!
      CALL SORT(XDIST,NDISTX,XDIST)
!
!               *******************************************************
!               **  STEP 16--                                        **
!               **  DETERMINE THE NUMBER OF DISTINCT Y VALUES        **
!               **  FOR THE INTERPOLATION POINTS                     **
!               *******************************************************
!
      ISTEPN='16'
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'NT2D')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NDISTY=0
      DO 1610 I=1,NY
        IF(NDISTY.EQ.0)GO TO 1620
        DO 1615 I2=1,NDISTY
          IF(Y2(I).EQ.YDIST(I2))GO TO 1610
 1615   CONTINUE
 1620   CONTINUE
        NDISTY=NDISTY+1
        YDIST(NDISTY)=Y2(I)
 1610 CONTINUE
!
      CALL SORT(YDIST,NDISTY,YDIST)
!
      N2=NDISTX*NDISTY
      IF(N2.LE.MAXOBV)GO TO 1699
!
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1651)
 1651 FORMAT('***** ERROR IN INT2D--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1652)
 1652 FORMAT('      THE NUMBER OF REQUESTED INTERPOLATION POINTS')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1653)MAXOBV
 1653 FORMAT('      WILL EXCEED THE MAXIMUM ALLOWABLE OF ',I8,'.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1654)
 1654 FORMAT('      THE NUMBER OF DISTINCT X AND Y INTERPOLATION')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1655)NDISTX,NDISTY
 1655 FORMAT('      IS ',I8,' AND ',I8,' RESPECTIVELY.   *****')
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
!
 1699 CONTINUE
!
!               ********************************************
!               **  STEP 17--                             **
!               **  CHECK FOR USER PARAMETER NPPR         **
!               ********************************************
!
      NPPR=10
      ANPPR=10.0
      IHP='NPPR'
      IHP2='    '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IHP,IHP2,IHWUSE,   &
                  IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                  ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'YES')GO TO 1710
      ANPPR=VALUE(ILOCP)
 1710 CONTINUE
!
      NPPR=INT(ANPPR+0.5)
      IF(NPPR.GE.3)GO TO 1719
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1651)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1712)
 1712 FORMAT('      THE AVERAGE NUMBER OF POINTS PER REGION MUST BE ',   &
             'GRETAER')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1715)
 1715 FORMAT('      THAN OR EQUAL TO 3;  SUCH WAS NOT THE CASE HERE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1716)NPPR
 1716 FORMAT('      THE CURRENT VALUE OF NPPR IS ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1717)
 1717 FORMAT('      A VALUE OF 10 WILL BE USED')
      CALL DPWRST('XXX','BUG ')
      NPPR=10
 1719 CONTINUE
!
!
!
!               ********************************************
!               **  STEP 18--                             **
!               **  COMPUTE INTERPOLATED VALUES           **
!               ********************************************
!
      NIWK=7*MAXOBV
      NWK=7*MAXOBV
      CALL INT2D2(ZDIST,YNEW,XNEW,N,YDIST,NY,XDIST,NX,Z2,N2,   &
                  NPPR,NIWK,NWK,WORK,IWORK,   &
                  IBUGG3,ISUBRO,IERROR)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'NT2D')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF INT2D--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)N,N2
 9012   FORMAT('N,N2 = ',2I8)
        CALL DPWRST('XXX','BUG ')
        DO 9042 I=1,N2
          WRITE(ICOUT,9043)I,X2(I),Y2(I),Z2(I)
 9043     FORMAT('I,X2(I),Y2(I),Z2(I) = ',I8,3G15.7)
          CALL DPWRST('XXX','BUG ')
 9042   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE INT2D
      SUBROUTINE INT2D2(Z,Y,X,N,Y2,NY,X2,NX,Z2,N2,   &
      NPPR,NIWK,NWK,WORK,IWORK,   &
      IBUGG3,ISUBRO,IERROR)
!
!     PURPOSE--COMPUTE BI-VARIATE INTERPOLATION OF A VARIABLE
!              (GENERATE INTERPOLATED POINTS).
!              THIS ROUTINE STARTS FROM SCATTERED DATA AND INTERPOLATES
!              POINTS ON A GRID.  NOTE THAT X2 AND Y2 DEFINE THE GRID
!              TO INTERPOLATE OVER.
!              THIS ROUTINE USES THE LOTPS ROUTINE WRITTEN BY RICHARD
!              FRANKE OF THE NAVAL POSTGRADUATE SCHOOL.
!     INPUT  ARGUMENTS--Z      = SINGLE PRECISION VARIABLE
!                                CONTAINING THE ORIGINAL
!                                Z AXIS DATA POINTS.
!                     --Y      = SINGLE PRECISION VARIABLE
!                                CONTAINING THE ORIGINAL
!                                VERTICAL AXIS DATA POINTS.
!                     --X      = SINGLE PRECISION VARIABLE
!                                CONTAINING THE ORIGINAL
!                                HORIZONTAL AXIS DATA POINTS.
!                     --Y2     = SINGLE PRECISION VARIABLE
!                                CONTAINING THE DESIRED
!                                VERTICAL AXIS INTERPOLATION
!                     --X2     = SINGLE PRECISION VARIABLE
!                                CONTAINING THE DESIRED
!                                HORIZONTAL AXIS INTERPOLATION
!                                POINTS.
!     OUTPUT ARGUMENTS--Z2     = SINGLE PRECISION VARIABLE
!                                CONTAINING THE COMPUTED
!                                VERTICAL AXIS INTERPOLATION
!                                POINTS.
!     NOTE--IT IS PROBABLY NOT PERMISSIBLE TO HAVE THE OUTPUT VECTOR
!           Z2(.) BEING IDENTICAL TO THE INPUT VECTOR Z(.)
!     NOTE--THE X AND Y POINTS ARE ASSUMED TO LIE ON A RECTANGULAR GRID
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--94/5
!     ORIGINAL VERSION--MAY       1994.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IBUGG3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
!
      DIMENSION Z(*)
      DIMENSION Y(*)
      DIMENSION X(*)
      DIMENSION Z2(*)
      DIMENSION Y2(*)
      DIMENSION X2(*)
      DIMENSION WORK(*)
      DIMENSION IWORK(*)
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='INT2'
      ISUBN2='D2  '
      IERROR='NO'
!
      ISTART=-99
!
      DO 10 I=1,N2
      Z2(I)=0.0
 10   CONTINUE
!
      IF(IBUGG3.EQ.'OFF'.AND.ISUBRO.NE.'T2D2')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF INT2D2--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)NX,NY
   52 FORMAT('NX, NY = ',2I8)
      CALL DPWRST('XXX','BUG ')
      DO 54 I=1,N
      WRITE(ICOUT,53)I,X(I),Y(I),Z(I)
      CALL DPWRST('XXX','BUG ')
 53   FORMAT('I,X(I),Y(I),Z(I) = ',I8,3E15.7)
      CALL DPWRST('XXX','BUG ')
 54   CONTINUE
      WRITE(ICOUT,62)N2
   62 FORMAT('N2 = ',I8)
      CALL DPWRST('XXX','BUG ')
   90 CONTINUE
!
!               ****************************************
!               **  STEP 31--
!               **  COMPUTE INTERPOLATION VALUES
!               ****************************************
!
      IMODE=1
      CALL LOTPS(IMODE,NPPR,N,X,Y,Z,NX,X2,NY,Y2,IWORK,NIWK,NIWKU,   &
      WORK,NWK,NWKU,Z2,KERR)
      IF(KERR.GT.0)THEN
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ****************************************
!               **  STEP 41--
!               **  IF CALLED FOR,
!               **  WRITE OUT INTERPOLATION VALUES
!               ****************************************
!
      IF(IBUGG3.EQ.'OFF'.AND.ISUBRO.NE.'T2D2')GO TO 4190
      J1=0
      DO 4100 I=1,NX
      DO 4110 J=1,NY
      J1=J1+1
      WRITE(ICOUT,4112)X2(I),Y2(J),Z2(J1)
      CALL DPWRST('XXX','BUG ')
 4112 FORMAT('I,J,X2(I),Y2(J),Z2(I,J) = ',2I8,3E15.7)
 4110 CONTINUE
 4100 CONTINUE
 4190 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG3.EQ.'OFF'.AND.ISUBRO.NE.'T2D2')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF INT2D2--')
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE INT2D2
      INTEGER FUNCTION ISAMAX(N,SX,INCX)
!***BEGIN PROLOGUE  ISAMAX
!***DATE WRITTEN   791001   (YYMMDD)
!***REVISION DATE  820801   (YYMMDD)
!***CATEGORY NO.  D1A2
!***KEYWORDS  BLAS,LINEAR ALGEBRA,MAXIMUM COMPONENT,VECTOR
!***AUTHOR  LAWSON, C. L., (JPL)
!           HANSON, R. J., (SNLA)
!           KINCAID, D. R., (U. OF TEXAS)
!           KROGH, F. T., (JPL)
!***PURPOSE  Find largest component of s.p. vector
!***DESCRIPTION
!
!                B L A S  Subprogram
!    Description of Parameters
!
!     --Input--
!        N  number of elements in input vector(s)
!       SX  single precision vector with N elements
!     INCX  storage spacing between elements of SX
!
!     --Output--
!   ISAMAX  smallest index (zero if N .LE. 0)
!
!     Find smallest index of maximum magnitude of single precision SX.
!     ISAMAX =  first I, I = 1 to N, to minimize  ABS(SX(1-INCX+I*INCX)
!***REFERENCES  LAWSON C.L., HANSON R.J., KINCAID D.R., KROGH F.T.,
!                 *BASIC LINEAR ALGEBRA SUBPROGRAMS FOR FORTRAN USAGE*,
!                 ALGORITHM NO. 539, TRANSACTIONS ON MATHEMATICAL
!                 SOFTWARE, VOLUME 5, NUMBER 3, SEPTEMBER 1979, 308-323
!***ROUTINES CALLED  (NONE)
!***END PROLOGUE  ISAMAX
!
      REAL SX(*),SMAX,XMAG
!***FIRST EXECUTABLE STATEMENT  ISAMAX
      ISAMAX = 0
      IF(N.LE.0) RETURN
      ISAMAX = 1
      IF(N.LE.1)RETURN
      IF(INCX.EQ.1)GO TO  20
!
!        CODE FOR INCREMENTS NOT EQUAL TO 1.
!
      SMAX = ABS(SX(1))
      NS = N*INCX
      II = 1
          DO 10 I=1,NS,INCX
          XMAG = ABS(SX(I))
          IF(XMAG.LE.SMAX) GO TO 5
          ISAMAX = II
          SMAX = XMAG
    5     II = II + 1
   10     CONTINUE
      RETURN
!
!        CODE FOR INCREMENTS EQUAL TO 1.
!
   20 SMAX = ABS(SX(1))
      DO 30 I = 2,N
         XMAG = ABS(SX(I))
         IF(XMAG.LE.SMAX) GO TO 30
         ISAMAX = I
         SMAX = XMAG
   30 CONTINUE
      RETURN
      END FUNCTION ISAMAX
      subroutine isort (n, ix)
!-----------------------------------------------------------------------
!  Name:       ISORT  (Used by Fisher Exact Test)
!
!  Purpose:    Shell sort for an integer vector.
!
!  Usage:      CALL ISORT (N, IX)
!
!  Arguments:
!     N      - Lenth of vector IX.  (Input)
!     IX     - Vector to be sorted.  (Input/output)
!-----------------------------------------------------------------------
!                                  SPECIFICATIONS FOR ARGUMENTS
      integer    n, ix(*)
!                                  SPECIFICATIONS FOR LOCAL VARIABLES
      integer    i, ikey, il(10), it, iu(10), j, kl, ku, m
!                                  SPECIFICATIONS FOR SUBROUTINES
!CCCC external   prterr
!                                  Sort IX
      INCLUDE 'DPCOP2.INC'
!
      m = 1
      i = 1
      j = n
   10 if (i .ge. j) go to 40
      kl   = i
      ku   = j
      ikey = i
      j    = j + 1
!                                  Find element in first half
   20 i = i + 1
      if (i .lt. j) then
         if (ix(ikey) .gt. ix(i)) go to 20
      end if
!                                  Find element in second half
   30 j = j - 1
      if (ix(j) .gt. ix(ikey)) go to 30
!                                  Interchange
      if (i .lt. j) then
         it    = ix(i)
         ix(i) = ix(j)
         ix(j) = it
         go to 20
      end if
      it       = ix(ikey)
      ix(ikey) = ix(j)
      ix(j)    = it
!                                  Save upper and lower subscripts of
!                                  the array yet to be sorted
      if (m .lt. 11) then
         if (j-kl .lt. ku-j) then
            il(m) = j + 1
            iu(m) = ku
            i     = kl
            j     = j - 1
         else
            il(m) = kl
            iu(m) = j - 1
            i     = j + 1
            j     = ku
         end if
         m = m + 1
         go to 10
      else
!CCCC    call prterr (20, 'This should never occur.')
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** ERROR FROM ISORT--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)
 9013 FORMAT('      This should never occur.')
      CALL DPWRST('XXX','BUG ')
      end if
!                                  Use another segment
   40 m = m - 1
      if (m .eq. 0) go to 9000
      i = il(m)
      j = iu(m)
      go to 10
!
 9000 return
      end
      SUBROUTINE IWECDF(X,GAMMA,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE INVERTED WEIBULL
!              DISTRIBUTION WITH SINGLE PRECISION
!              TAIL LENGTH PARAMETER = GAMMA.
!              THE INVERTED WEIBULL DISTRIBUTION USED
!              HEREIN IS DEFINED FOR ALL POSITIVE X,
!              AND HAS THE CUMULATIVE DISTRIBUTION  FUNCTION
!              F(X) = EXP(-(X**(-GAMMA))).
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE NON-NEGATIVE.
!                     --GAMMA  = THE SHAPE PARAMETER
!                                GAMMA SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE WEIBULL DISTRIBUTION
!             WITH TAIL LENGTH PARAMETER = GAMMA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE.
!                 --GAMMA SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--XX
!               --JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, XX.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--2001.9
!     ORIGINAL VERSION--SEPTEMBER 2001.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DGAMMA
      DOUBLE PRECISION DCDF
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      CDF=0.0
!
      IF(GAMMA.LE.0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** FATAL ERROR--THE SECOND INPUT ARGUMENT TO THE ',   &
               'IWECDF SUBROUTINE IS NON-POSITIVE *****')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9000
      ENDIF
!
      IF(X.LE.0.0)THEN
        CDF=0.0
      ELSE
        DGAMMA=DBLE(GAMMA)
        DX=DBLE(X)
        DCDF=DEXP(-(DX**(-DGAMMA)))
        CDF=REAL(DCDF)
      ENDIF
!
 9000 CONTINUE
!
      RETURN
      END SUBROUTINE IWECDF
      SUBROUTINE IWEPDF(X,GAMMA,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE INVERTED WEIBULL
!              DISTRIBUTION WITH SINGLE PRECISION
!              TAIL LENGTH PARAMETER = GAMMA.
!              THE INVERTED WEIBULL DISTRIBUTION USED
!              HEREIN IS DEFINED FOR ALL POSITIVE X,
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              F(X) = GAMMA*(X**(-GAMMA-1))*EXP(-(X**(-GAMMA))).
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                     --GAMMA  = THE SHAPE PARAMETER
!                                GAMMA SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE WEIBULL DISTRIBUTION
!             WITH TAIL LENGHT PARAMETER = GAMMA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--GAMMA SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--XX
!               --JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, XX.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--2001.9
!     ORIGINAL VERSION--SEPTEMBER 2001.
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DGAMMA
      DOUBLE PRECISION DPDF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(GAMMA.LE.0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** FATAL ERROR--THE SECOND INPUT ARGUMENT TO THE ',   &
               'IWEPDF SUBROUTINE IS NON-POSITIVE *****')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9000
      ENDIF
!
      IF(X.LE.0.0)THEN
        PDF=0.0
      ELSE
        DGAMMA=DBLE(GAMMA)
        DX=DBLE(X)
        DPDF=DGAMMA*(DX**(-DGAMMA-1.0D0))*DEXP(-(DX**(-DGAMMA)))
        PDF=REAL(DPDF)
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE IWEPDF
      SUBROUTINE IWEPPF(P,GAMMA,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE INVERTED WEIBULL
!              DISTRIBUTION WITH SINGLE PRECISION
!              TAIL LENGTH PARAMETER = GAMMA.
!              THE INVERTED WEIBULL DISTRIBUTION USED
!              HEREIN IS DEFINED FOR ALL POSITIVE X,
!              AND HAS THE PERCENT POINT FUNCTION
!              G(P) = -[LOG(P)]**(-1/GAMMA)
!              NOTE THAT THE PERCENT POINT FUNCTION OF A DISTRIBUTION
!              IS IDENTICALLY THE SAME AS THE INVERSE CUMULATIVE
!              DISTRIBUTION FUNCTION OF THE DISTRIBUTION.
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE
!                                (BETWEEN 0.0 (INCLUSIVELY)
!                                AND 1.0 (EXCLUSIVELY))
!                                AT WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --GAMMA  = THE SINGLE PRECISION VALUE
!                                OF THE TAIL LENGTH PARAMETER.
!                                GAMMA SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION PERCENT
!                                POINT FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT FUNCTION .
!             VALUE PPF FOR THE WEIBULL DISTRIBUTION
!             WITH TAIL LENGTH PARAMETER VALUE = GAMMA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--GAMMA SHOULD BE POSITIVE.
!                 --P SHOULD BE BETWEEN 0.0 (INCLUSIVELY)
!                   AND 1.0 (EXCLUSIVELY).
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--XX
!               --JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, XX.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--2001.9
!     ORIGINAL VERSION--SEPTEMBER 2001.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DP
      DOUBLE PRECISION DGAMMA
      DOUBLE PRECISION DPPF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PPF=0.0
!
      IF(P.LT.0.0.OR.P.GE.1.0)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9000
      ENDIF
      IF(GAMMA.LE.0.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9000
      ENDIF
    1 FORMAT('***** FATAL ERROR--THE FIRST INPUT ARGUMENT TO THE ',   &
      'IWEPPF SUBROUTINE IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL')
   15 FORMAT('***** FATAL ERROR--THE SECOND INPUT ARGUMENT TO THE ',   &
      'IWEPPF SUBROUTINE IS NON-POSITIVE *****')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
!
      DGAMMA=DBLE(GAMMA)
      DP=DBLE(P)
      DTERM1=-DLOG(DP)
      DTERM2=-1.0D0/DGAMMA
      DPPF=DTERM1**DTERM2
      PPF=REAL(DPPF)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE IWEPPF
      SUBROUTINE IWERAN(N,GAMMA,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE INVERTED WEIBULL DISTRIBUTION
!              WITH TAIL LENGTH PARAMETER VALUE = GAMMA.
!              THE PROTOTYPE WEIBULL DISTRIBUTION USED
!              HEREIN IS DEFINED FOR ALL POSITIVE X,
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              F(X) = GAMMA * (X**(-GAMMA-1)) * EXP(-(X**-GAMMA)).
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --GAMMA  = THE SINGLE PRECISION VALUE OF THE
!                                TAIL LENGTH PARAMETER.
!                                GAMMA SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE INVERTED WEIBULL DISTRIBUTION
!             WITH TAIL LENGTH PARAMETER VALUE = GAMMA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --GAMMA SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--XX
!               --JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 2ND. ED., 1994.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--2001.9
!     ORIGINAL VERSION--SEPTEMBER 2001.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
      IF(GAMMA.LE.0.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    5 FORMAT('***** FATAL ERROR--THE 1ST INPUT ARGUMENT TO THE ',   &
      'IWERAN SUBROUTINE IS NON-POSITIVE *****')
   15 FORMAT('***** FATAL ERROR--THE 2ND INPUT ARGUMENT TO THE ',   &
      'IWERAN SUBROUTINE IS NON-POSITIVE *****')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,' *****')
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N INVERTED WEIBULL DISTRIBUTION RANDOM NUMBERS
!     USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD.
!
      DO 100 I=1,N
        CALL IWEPPF(X(I),GAMMA,XTEMP)
        X(I)=XTEMP
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE IWERAN
      integer function iwork (iwkmax, iwkpt, number, itype)
!-----------------------------------------------------------------------
!  Name:       IWORK
!
!  Purpose:    Routine for allocating workspace.
!
!  Usage:      IWORK (IWKMAX, IWKPT, NUMBER, ITYPE)
!
!  Arguments:
!     IWKMAX - Maximum length of workspace.  (Input)
!     IWKPT  - Amount of workspace currently allocated.  (Input/output)
!     NUMBER - Number of elements of workspace desired.  (Input)
!     ITYPE  - Worspace type.  (Input)
!              ITYPE  TYPE
!                2    Integer
!                3    Real
!                4    Double Precision
!     IWORK  - Index in RWRK, DWRK, or IWRK of the beginning of the
!              first element in the workspace array.  (Output)
!-----------------------------------------------------------------------
!                                  SPECIFICATIONS FOR ARGUMENTS
      integer    iwkmax, iwkpt, number, itype
!                                  SPECIFICATIONS FOR INTRINSICS
      intrinsic  mod
!cccc integer    mod
!                                  SPECIFICATIONS FOR SUBROUTINES
!CCCC external   prterr
!
      INCLUDE 'DPCOP2.INC'
!
      iwork = iwkpt
      if (itype.eq.2 .or. itype.eq.3) then
         iwkpt = iwkpt + number
      else
         if (mod(iwork,2) .ne. 0) iwork = iwork + 1
         iwkpt = iwkpt + 2*number
         iwork = iwork/2
      end if
      if (iwkpt .gt. iwkmax+1) then
!CCCC    call prterr (40, 'Out of workspace.')
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** ERROR FROM IWORK--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)
 9013 FORMAT('      Out of workspace.')
      CALL DPWRST('XXX','BUG ')
      end if
      return
      end
      DOUBLE PRECISION FUNCTION J1FUN(DX)
!
!     PURPOSE--THIS FUNCTION COMPUTES THE FOLLOWING FUNCTION:
!                 J(X,A) = INTEGRAL[0 to X][T**(A-1)*LOG(T)*EXP(-T)]dt
!              THIS FUNCTION IS USED IN COMPUTING MAXIMUM LIKELIHOOD
!              ESTIMATES FOR THE GAMMA DISTRIBUTION FOR MULTIPLY
!              CENSORED DATA.
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE J(X,A) FUNCTION IS TO BE
!                                EVALUATED.
!     OUTPUT ARGUMENTS--J1FUN  = THE DOUBLE PRECISION FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION VALUE FOR THE J(X,A) FUNCTION.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DLOG.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN
!                ENGINEERING", CAMBRIDGE UNIVERSITY PRESS,
!                1999, CHAPTER 13.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.11
!     ORIGINAL VERSION--NOVEMBER  2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
!
      DOUBLE PRECISION DX
!
      DOUBLE PRECISION DA
      COMMON/J1COM/DA
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!               ************************************
!               **  STEP 1--                      **
!               **  COMPUTE THE DENSITY FUNCTION  **
!               ************************************
!
      J1FUN=DX**(DA-1.0D0)*DLOG(DX)*DEXP(-DX)
!
      RETURN
      END FUNCTION J1FUN
      DOUBLE PRECISION FUNCTION J2FUN(DX)
!
!     PURPOSE--THIS FUNCTION COMPUTES THE FOLLOWING FUNCTION:
!                 J(X,A) = INTEGRAL[0 to X]
!                          [T**(A-1)*(LOG(T)**2)**EXP(-T)]dt
!              THIS FUNCTION IS USED IN COMPUTING THE STANDARD
!              ERRORS OF THE MAXIMUM LIKELIHOOD ESTIMATES FOR THE
!              GAMMA DISTRIBUTION FOR MULTIPLY CENSORED DATA.
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE J(X,A) FUNCTION IS TO BE
!                                EVALUATED.
!     OUTPUT ARGUMENTS--J2FUN  = THE DOUBLE PRECISION FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION VALUE FOR THE J(X,A) FUNCTION.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DLOG.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN
!                ENGINEERING", CAMBRIDGE UNIVERSITY PRESS,
!                1999, CHAPTER 13.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.11
!     ORIGINAL VERSION--NOVEMBER  2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
!
      DOUBLE PRECISION DX
!
      DOUBLE PRECISION DA
      COMMON/J1COM/DA
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!               ************************************
!               **  STEP 1--                      **
!               **  COMPUTE THE DENSITY FUNCTION  **
!               ************************************
!
      J2FUN=DX**(DA-1.0D0)*(DLOG(DX)**2)*DEXP(-DX)
!
      RETURN
      END FUNCTION J2FUN
      DOUBLE PRECISION FUNCTION J0INT(XVALUE)
!
!   DESCRIPTION:
!
!      This function calculates the integral of the Bessel
!      function J0, defined as
!
!        J0INT(x) = {integral 0 to x} J0(t) dt
!
!      The code uses Chebyshev expansions whose coefficients are
!      given to 20 decimal places.
!
!
!   ERROR RETURNS:
!
!      If the value of |x| is too large, it is impossible to
!      accurately compute the trigonometric functions used. An
!      error message is printed, and the function returns the
!      value 1.0.
!
!
!   MACHINE-DEPENDENT CONSTANTS:
!
!      NTERM1 - The no. of terms to be used from the array
!                ARJ01. The recommended value is such that
!                   ABS(ARJ01(NTERM1)) < EPS/100, provided that
!
!      NTERM2 - The no. of terms to be used from the array
!                ARJ0A1. The recommended value is such that
!                   ABS(ARJ0A1(NTERM2)) < EPS/100, provided that
!
!      NTERM3 - The no. of terms to be used from the array
!                ARJ0A2. The recommended value is such that
!                   ABS(ARJ0A2(NTERM3)) < EPS/100, provided that
!
!      XLOW - The value of |x| below which J0INT(x) = x to
!             machine-precision. The recommended value is
!                 sqrt(12*EPSNEG)
!
!      XHIGH - The value of |x| above which it is impossible
!              to calculate (x-pi/4) accurately. The recommended
!              value is      1/EPSNEG
!
!      For values of EPS and EPSNEG for various machine/compiler
!      combinations refer to the file MACHCON.TXT.
!
!      The machine-dependent constants are computed internally by
!      using the D1MACH subroutine.
!
!
!   INTRINSIC FUNCTIONS USED:
!
!      COS , SIN , SQRT
!
!
!   OTHER MISCFUN SUBROUTINES USED:
!
!          CHEVAL , ERRPRN, D1MACH
!
!
!   AUTHOR:
!          Dr. Allan J. MacLeod,
!          Dept. of Mathematics and Statistics,
!          University of Paisley,
!          Paisley,
!          SCOTLAND
!          PA1 2BE
!
!          (e-mail:   macl_ms0@paisley.ac.uk )
!
!
!   LATEST REVISION:
!                    23 January, 1996
!
      INTEGER IND,NTERM1,NTERM2,NTERM3
      DOUBLE PRECISION ARJ01(0:23),ARJ0A1(0:21),ARJ0A2(0:18),   &
           CHEVAL,FIVE12,ONE,ONEHUN,ONE28,PIB41,PIB411,PIB412,   &
           PIB42,RT2BPI,SIXTEN,T,TEMP,TWELVE,X,XHIGH,XLOW,   &
           XMPI4,XVALUE,ZERO
!CCCC CHARACTER FNNAME*6,ERRMSG*26
!CCCC DATA FNNAME/'J0INT '/
!CCCC DATA ERRMSG/'ARGUMENT TOO LARGE IN SIZE'/
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
      DATA ZERO,ONE/ 0.0D0,1.0D0 /
      DATA TWELVE,SIXTEN/ 12.0D0,16.0D0 /
      DATA ONEHUN,ONE28,FIVE12/ 100.0D0 , 128.0D0 , 512D0 /
      DATA RT2BPI/0.79788456080286535588D0/
      DATA PIB411,PIB412/ 201.0D0 , 256.0D0/
      DATA PIB42/0.24191339744830961566D-3/
      DATA ARJ01(0)/  0.38179279321690173518D0/
      DATA ARJ01(1)/ -0.21275636350505321870D0/
      DATA ARJ01(2)/  0.16754213407215794187D0/
      DATA ARJ01(3)/ -0.12853209772196398954D0/
      DATA ARJ01(4)/  0.10114405455778847013D0/
      DATA ARJ01(5)/ -0.9100795343201568859D-1/
      DATA ARJ01(6)/  0.6401345264656873103D-1/
      DATA ARJ01(7)/ -0.3066963029926754312D-1/
      DATA ARJ01(8)/  0.1030836525325064201D-1/
      DATA ARJ01(9)/ -0.255670650399956918D-2/
      DATA ARJ01(10)/ 0.48832755805798304D-3/
      DATA ARJ01(11)/-0.7424935126036077D-4/
      DATA ARJ01(12)/ 0.922260563730861D-5/
      DATA ARJ01(13)/-0.95522828307083D-6/
      DATA ARJ01(14)/ 0.8388355845986D-7/
      DATA ARJ01(15)/-0.633184488858D-8/
      DATA ARJ01(16)/ 0.41560504221D-9/
      DATA ARJ01(17)/-0.2395529307D-10/
      DATA ARJ01(18)/ 0.122286885D-11/
      DATA ARJ01(19)/-0.5569711D-13/
      DATA ARJ01(20)/ 0.227820D-14/
      DATA ARJ01(21)/-0.8417D-16/
      DATA ARJ01(22)/ 0.282D-17/
      DATA ARJ01(23)/-0.9D-19/
      DATA ARJ0A1(0)/  1.24030133037518970827D0/
      DATA ARJ0A1(1)/ -0.478125353632280693D-2/
      DATA ARJ0A1(2)/  0.6613148891706678D-4/
      DATA ARJ0A1(3)/ -0.186042740486349D-5/
      DATA ARJ0A1(4)/  0.8362735565080D-7/
      DATA ARJ0A1(5)/ -0.525857036731D-8/
      DATA ARJ0A1(6)/  0.42606363251D-9/
      DATA ARJ0A1(7)/ -0.4211761024D-10/
      DATA ARJ0A1(8)/  0.488946426D-11/
      DATA ARJ0A1(9)/ -0.64834929D-12/
      DATA ARJ0A1(10)/ 0.9617234D-13/
      DATA ARJ0A1(11)/-0.1570367D-13/
      DATA ARJ0A1(12)/ 0.278712D-14/
      DATA ARJ0A1(13)/-0.53222D-15/
      DATA ARJ0A1(14)/ 0.10844D-15/
      DATA ARJ0A1(15)/-0.2342D-16/
      DATA ARJ0A1(16)/ 0.533D-17/
      DATA ARJ0A1(17)/-0.127D-17/
      DATA ARJ0A1(18)/ 0.32D-18/
      DATA ARJ0A1(19)/-0.8D-19/
      DATA ARJ0A1(20)/ 0.2D-19/
      DATA ARJ0A1(21)/-0.1D-19/
      DATA ARJ0A2(0)/  1.99616096301341675339D0/
      DATA ARJ0A2(1)/ -0.190379819246668161D-2/
      DATA ARJ0A2(2)/  0.1539710927044226D-4/
      DATA ARJ0A2(3)/ -0.31145088328103D-6/
      DATA ARJ0A2(4)/  0.1110850971321D-7/
      DATA ARJ0A2(5)/ -0.58666787123D-9/
      DATA ARJ0A2(6)/  0.4139926949D-10/
      DATA ARJ0A2(7)/ -0.365398763D-11/
      DATA ARJ0A2(8)/  0.38557568D-12/
      DATA ARJ0A2(9)/ -0.4709800D-13/
      DATA ARJ0A2(10)/ 0.650220D-14/
      DATA ARJ0A2(11)/-0.99624D-15/
      DATA ARJ0A2(12)/ 0.16700D-15/
      DATA ARJ0A2(13)/-0.3028D-16/
      DATA ARJ0A2(14)/ 0.589D-17/
      DATA ARJ0A2(15)/-0.122D-17/
      DATA ARJ0A2(16)/ 0.27D-18/
      DATA ARJ0A2(17)/-0.6D-19/
      DATA ARJ0A2(18)/ 0.1D-19/
!
      XLOW=CPUMIN
!
!   Start computation
!
      X = XVALUE
      IND = 1
      IF ( X .LT. ZERO ) THEN
         X = -X
         IND = -1
      ENDIF
!
!   Compute the machine-dependent constants.
!
      TEMP = D1MACH(3)
      XHIGH = ONE / TEMP
!
!   Error test
!
      IF ( X .GT. XHIGH ) THEN
!CCCC    CALL ERRPRN(FNNAME,ERRMSG)
         WRITE(ICOUT,999)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,101)X
         CALL DPWRST('XXX','BUG ')
         J0INT = ONE
         IF ( IND .EQ. -1 ) J0INT = -J0INT
         RETURN
      ENDIF
  999 FORMAT(1X)
  101 FORMAT('***** ERROR FROM J0INT--SIZE OF THE INPUT ARGUMENT ',   &
              'IS TOO LARGE, ARGUMENT = ',G15.7)
!
!   continue with constants
!
      T = TEMP / ONEHUN
      IF ( X .LE. SIXTEN ) THEN
         DO 10 NTERM1 = 23 , 0 , -1
            IF ( ABS(ARJ01(NTERM1)) .GT. T ) GO TO  19
 10      CONTINUE
 19      XLOW = SQRT ( TWELVE * TEMP )
      ELSE
         DO 40 NTERM2 = 21 , 0 , -1
            IF ( ABS(ARJ0A1(NTERM2)) .GT. T ) GO TO  49
 40      CONTINUE
 49      DO 50 NTERM3 = 18 , 0 , -1
            IF ( ABS(ARJ0A2(NTERM3)) .GT. T ) GO TO  59
 50      CONTINUE
 59      CONTINUE
      ENDIF
!
!   Code for 0 <= |x| <= 16
!
      IF ( X .LE. SIXTEN ) THEN
         IF ( X .LT. XLOW ) THEN
            J0INT = X
         ELSE
            T = X * X / ONE28 - ONE
            J0INT = X * CHEVAL(NTERM1,ARJ01,T)
         ENDIF
      ELSE
!
!   Code for |x| > 16
!
         T = FIVE12 / ( X * X ) - ONE
         PIB41 = PIB411 / PIB412
         XMPI4 = ( X - PIB41 ) - PIB42
         TEMP = COS(XMPI4) * CHEVAL(NTERM2,ARJ0A1,T) / X
         TEMP = TEMP - SIN(XMPI4) * CHEVAL(NTERM3,ARJ0A2,T)
         J0INT = ONE - RT2BPI * TEMP / SQRT(X)
      ENDIF
      IF ( IND .EQ. -1 ) J0INT = -J0INT
      RETURN
      END FUNCTION J0INT
      SUBROUTINE JACELL(AX,AMC,SNR,CNR,DNR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE JACOBIAN ELLIPTIC
!              FUNCTIONS.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION INPUT ARGUMENT
!                       AMC    = THE SINGLE PRECISION VALUE FOR THE
!                                PARAMETER OF THE FUNCTIONS
!     OUTPUT ARGUMENTS--SN     = THE SINGLE PRECISION VALUE OF THE SN
!                                FUNCTION.
!                     --CN     = THE SINGLE PRECISION VALUE OF THE CN
!                                FUNCTION.
!                     --DN     = THE SINGLE PRECISION VALUE OF THE DN
!                                FUNCTION.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--"NUMERICAL CALCULATION OF ELLIPTIC INTEGRALS AND
!                 ELLIPTIC FUNCTIONS", BULIRSCH, NUMERISCHE MATHEMATIK,
!                 VOL. 7, PP. 78-90, 1965.
!                 THE ROUTINE HERE IS A FORTRAN TRANSLATION OF THE
!                 ALGOL-60 CODE GIVEN IN THE REFERENCE.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--NOVEMBER   1994.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      PARAMETER (MAXELE=13)
      LOGICAL B0
      DOUBLE PRECISION AM(MAXELE)
      DOUBLE PRECISION AN(MAXELE)
      DOUBLE PRECISION MC, C1, CA, X, A, B, C, D
      DOUBLE PRECISION SN, DN, CN
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
      DATA C1 / 3.96825396825D-4/
      DATA CA / 0.0001D0 /
!
!---------------------------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
      X=DBLE(AX)
      MC=DBLE(AMC)
      DO 10 I=1,MAXELE
        AN(I)=0.0D0
        AM(I)=0.0D0
 10   CONTINUE
!
      IF(MC.EQ.0.0D0)GO TO 1000
      B0=.TRUE.
      IF(MC.LT.0.0D0)THEN
        B0=.TRUE.
      ELSE
        B0=.FALSE.
      ENDIF
      IF(B0)THEN
        D=1.0D0-MC
        MC=-MC/D
        D=SQRT(D)
        X=D*X
      ENDIF
      DN=1.0D0
      A=1.0D0
      DO 100 I=1,MAXELE
        L=I
        AM(I)=A
        MC=DSQRT(MC)
        AN(I)=MC
        C=0.5D0*(A+MC)
        IF(DABS(A-MC).LE.CA*A)GO TO 199
        MC=A*MC
        A=C
 100  CONTINUE
 199  CONTINUE
      X=C*X
      SN=DSIN(X)
      CN=DCOS(X)
      IF(SN.EQ.0.0D0)GO TO 299
      A=CN/SN
      C=A*C
      DO 200 I=L,1,-1
        B=AM(I)
        A=C*A
        C=DN*C
        DN=(AN(I)+A)/(B+A)
        A=C/B
 200  CONTINUE
      A=1.0D0/DSQRT(C*C+1.0D0)
      IF(SN.LT.0.0D0)THEN
        SN=-A
      ELSE
        SN=A
      ENDIF
      CN=C*SN
 299  CONTINUE
      IF(B0)THEN
        A=DN
        DN=CN
        CN=A
        SN=SN/D
      ENDIF
      GO TO 9999
!
 1000 CONTINUE
      D=DEXP(X)
      A=1.0D0/D
      B=A+D
      CN=2.0D0/B
      DN=2.0D0/B
      IF(DABS(X).LT.0.3D0)THEN
        D=X*X*X
        SN=CN*(D*((1.0D0/3.0D0)+D*X*C1)+DSIN(X))
      ELSE
        SN=(D-A)/B
      ENDIF
      GO TO 9999
!
 9999 CONTINUE
      SNR=SNGL(SN)
      CNR=SNGL(CN)
      DNR=SNGL(DN)
      RETURN
      END SUBROUTINE JACELL
      SUBROUTINE JACKIN(A1,A2,IWRITE,   &
      Y3,N3,IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--GENERATE A JACKNIFE INDEX
!              THIS WILL BE SEQUENCE 1 1 N WITH A SINGLE ELEMENT
!              DELETED
!     INPUT  ARGUMENTS--A1     =  ELEMENT TO DELETE
!                     --A2     =  SIZE OF SEQUENCE
!     OUTPUT ARGUMENTS--Y3     =  JACKNIFE INDEX
!
!      NOTE--IF A2 IS SMALLER THAN 1 OR LARGER THAN A1,
!            THEN THIS WILL BE INTERPRETED AS A NON-OPERATION.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--93/10
!     ORIGINAL VERSION--OCTOBER  1993.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION Y3(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='JACK'
      ISUBN2='IN  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'OFF'.AND.ISUBRO.NE.'CKIN')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF JACKIN--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IBUGA3,ISUBRO,IWRITE
   52 FORMAT('IBUGA3,ISUBRO,IWRITE = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)A1,A2
   53 FORMAT('A1,A2 = ',2F8.2)
      CALL DPWRST('XXX','BUG ')
   90 CONTINUE
!
!               *************************************
!               **  CONSTRUCT A   JACKNIFE INDEX   **
!               *************************************
!
!               ********************************************
!               **  STEP 11--                             **
!               **  CHECK NUMBER OF INPUT OBSERVATIONS.   **
!               ********************************************
!
      NSKIP=INT(A1+0.5)
      N1=INT(A2+0.5)
      IF(NSKIP.LT.1.OR.NSKIP.GT.N1)GO TO 1110
      GO TO 1119
!
 1110 CONTINUE
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1111)
 1111 FORMAT('***** ERROR IN JACKIN--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1112)
 1112 FORMAT('      THE ELEMENT TO SKIP MUST BE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1113)N1
 1113 FORMAT('      BETWEEN 1 AND ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1116)
 1116 FORMAT('      SUCH WAS NOT THE CASE HERE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1117)NSKIP
 1117 FORMAT('      THE ELEMENT TO SKIP IS = ',I8,'.')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
 1119 CONTINUE
!
      DO 1300 I=1,N1
      Y3(I)=REAL(I)
 1300 CONTINUE
      Y3(NSKIP)=0.0
      N3=N1
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGA3.EQ.'OFF'.AND.ISUBRO.NE.'PARI')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF JACKIN--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGA3,ISUBRO,IWRITE
 9012 FORMAT('IBUGA3,ISUBRO,IWRITE = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)IERROR
 9013 FORMAT('IERROR = ',A4)
      CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,9017)N1,N2,N3
!9017 FORMAT('N1,N2,N3 = ',3I8)
      WRITE(ICOUT,9017)N1,N3
 9017 FORMAT('N1,N3 = ',2I8)
      CALL DPWRST('XXX','BUG ')
      IF(N3.LE.0)GO TO 9043
      DO 9041 I=1,N3
      WRITE(ICOUT,9042)I,Y3(I)
 9042 FORMAT('I,Y3(I) = ',I8,E13.5)
      CALL DPWRST('XXX','BUG ')
 9041 CONTINUE
 9043 CONTINUE
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE JACKIN
      SUBROUTINE JACOBP(DEGREE,ALFA,BETA,X,F,FD,E,ED,FLAGF,FLAGD)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE JACOBI
!              POLYNOMIAL OF ORDER N.
!     INPUT  ARGUMENTS--DEGREE = THE INTEGER VALUE FOR THE ORDER OF
!                                THE POLYNOMIAL
!                       ALPHA  = THE DOUBLE PRECISION VALUE FOR THE
!                                FIRST SHAPE PARAMETER
!                       BETA   = THE DOUBLE PRECISION VALUE FOR THE
!                                SECOND SHAPE PARAMETER
!                       X      = THE DOUBLE PRECISION VALUE FOR THE
!                                INPUT ARGUMENT
!     OUTPUT ARGUMENTS--F      = THE DOUBLE PRECISION VALUE OF THE
!                                JACOBI POLYNOMIAL.
!                       FD     = THE DOUBLE PRECISION VALUE OF THE
!                                DERIVATIVE OF THE JACOBI POLYNOMIAL.
!                       E      = THE SINGLE PRECISION VALUE OF THE
!                                RELATIVE ERROR OF F
!                       ED     = THE SINGLE PRECISION VALUE OF THE
!                                RELATIVE ERROR OF FD
!                       FLAGF  = THE INTEGER VALUE WHICH SPECIFIES
!                                WHETHER F IS RELATIVE OR ABSOLUTE ERROR
!                       FLAGD  = THE INTEGER VALUE WHICH SPECIFIES
!                                WHETHER FD IS RELATIVE OR ABSOLUTE ERROR
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE
!     MODE OF INTERNAL OPERATIONS--SOME DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--"HANDBOOK OF MATHEMATICAL FUNCTIONS, AMS 55",
!                 ABRAMOWITZ AND STEGUM.
!                 "ALGORITHM 332.  JACOBI POLYNOMIALS", WITTE,
!                 COMMUNICATIONS OF THE ACM, VOL. 11, 1968.
!                 FOLLOWING CODE USES ACM ALGORTHM 332
!     ORIGINAL VERSION--JULY       1995.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!
      DOUBLE PRECISION A, ALF, ALFA, B, BET, BETA
      DOUBLE PRECISION C, D, F, FD, G, H, P, PD, Q, QD
      DOUBLE PRECISION T1, T2, U, V, W, X
!
      REAL E, ED, EG, E1, E2, S, Y
!
      INTEGER I, J, K, M, N, DEGREE, FLAGF, FLAGD
!
      DIMENSION U(25), V(25), W(25), P(25), PD(25), Q(25), QD(25)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      DATA M /-2/
      DATA ALF /-2.0D0/
      DATA BET /-2.0D0/
!CCCC DATA Y /3.0E-26/
      DATA RMXINT /134217727. /
!
!-----START POINT-----------------------------------------------------
!
!CCCC IF(X.LT.-1.0.OR.X.GT.1.0)THEN
!CCCC   WRITE(ICOUT,104)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,46)X
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   GO TO 9999
!CCCC ENDIF
!C104 FORMAT('***** NON-FATAL DIAGNOSTIC--THE 1ST INPUT ARGUMENT ',
!CCCC1'TO THE JACOBP SUBROUTINE IS OUTSIDE THE (-1,1) INTERVAL *****')
!CC46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
      IF(DEGREE.LT.0 .OR. DEGREE.GT.25)THEN
        WRITE(ICOUT,106)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 12
      ENDIF
  106 FORMAT('***** NON-FATAL DIAGNOSTIC--THE 2ND INPUT ARGUMENT ',   &
      'TO THE JACOBP SUBROUTINE IS OUTSIDE THE (0,25) INTERVAL *****')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,' *****')
!
      CALL SPDIV(RMXINT,2.0,IND,RESULT)
      ETA=RESULT+1.0
      CALL SPDIV(1.0,ETA,IND,ETA)
      Y=ETA
!
      IF(DEGREE.EQ.0)THEN
        F=1.0D0
        E=0.0
        FD=0.0D0
        ED=0.0
        FLAGF=2
        FLAGD=2
        GO TO 12
      ENDIF
!
!  CALCULATE THE U(J), V(J), W(J), IN THE RECURRENCE RELATION.
!  P(J) = P(J-1)*(U(J)+V(J)*X)-P(J-2)*W(J)
!
      M = DEGREE
      ALF = ALFA
      BET = BETA
      A = ALF+BET
      B = ALF-BET
      U(1) = B/2.0D0
      V(1) = 1.0D0+A/2.0D0
      W(1) = 0.0D0
!
      IF(DEGREE.EQ.1)GO TO 5
!
      U(2) = A*B*(A+3.0D0)/(4.0D0*(A+2.0D0)**2)
      V(2) = (A+3.0D0)*(A+4.0D0)/(4.0D0*(A+2.0D0))
      W(2) = (1.0D0 + ALF)*(1.0D0 + BET)*(A+4.0D0)
      W(2) = W(2)/(2.0D0*(A+2.0D0)**2)
      I = 2
      K = DEGREE - 1
!
      IF((DEGREE.EQ.2) .OR. (I.GT.K))GO TO 5
!
      DO 4 J=I,K
        A = DBLE(2*J+2)
        D = ALF+BET
        A = A+D
        B = D*(A-1.0D0)*(ALF-BET)
        C = DBLE(J+1)
        C = 2.0D0*C*(A-2.0D0)*(C+D)
        U(J+1) = B/C
        D = A*(A-1.0D0)*(A-2.0D0)
        V(J+1) = D/C
        D = J
        A = 2.0D0*(D+ALF)*(D+BET)*A
        W(J+1) = A/C
    4 CONTINUE
!
!  FIND THE STARTING VALUES FOR J=1 AND J=2 FOR USE IN THE RECURSION.
!
    5 CONTINUE
      T1 = V(1)*X
      P(1) = U(1)+T1
      S = Y*DMAX1(DABS(U(1)),DABS(T1))
      Q(1) = P(1)+S
      PD(1) = V(1)
      QD(1) = V(1)
!
      IF(DEGREE.EQ.1)GO TO 7
!
      T1 = V(2)*X
      G = U(2)+T1
      EG = Y*DMAX1(DABS(U(2)),DABS(T1))
      H = G+EG
      T1 = G*P(1)
      E1 = DABS(EG*P(1))
      P(2) = T1 - W(2)
      S = Y*DABS(W(2))
      S = AMAX1(E1,S)
      Q(2) = H*Q(1)-W(2)+S
      PD(2) = G*PD(1)+V(2)*P(1)
      QD(2) = H*QD(1)+V(2)*Q(1)
!
      IF(DEGREE.EQ.2)GO TO 7
!
!  USE THE RECURSION
!
      DO 6 J=3,DEGREE
        T2 = V(J)*X
        G = U(J)+T2
        EG = Y*DMAX1(DABS(U(J)),DABS(T2))
        H = G+EG
        T1 = G*P(J-1)
        T2 = W(J)*P(J-2)
        E1 = DABS(EG*P(J-1))
        E2 = DABS(T2)*Y
        P(J) = T1 - T2
        S = AMAX1(E1,E2)
        Q(J) = H*Q(J-1)-W(J)*Q(J-2)+S
        PD(J) = G*PD(J-1)-W(J)*PD(J-2)
        QD(J) = H*QD(J-1)-W(J)*QD(J-2)
        PD(J) = PD(J)+V(J)*P(J-1)
        QD(J) = QD(J)+V(J)*Q(J-1)
    6 CONTINUE
!
!  PREPARE THE OUTPUT
!
    7 CONTINUE
      N = DEGREE
      F = P(N)
      IF(DABS(F).LT.Y)THEN
        E=DABS(F-Q(N))
        FLAGF = 1
      ELSE
        E=DABS(1.0D0-Q(N)/F)
        FLAGF = 0
      ENDIF
      FD = PD(N)
      IF(DABS(FD).LT.Y)THEN
        ED=DABS(FD-QD(N))
        FLAGD=1
      ELSE
        ED=DABS(1.0D0-QD(N)/FD)
        FLAGD=0
      ENDIF
      GO TO 12
!
   12 CONTINUE
      RETURN
      END SUBROUTINE JACOBP
      SUBROUTINE JAIRY (X, RX, C, AI, DAI)
!***BEGIN PROLOGUE  JAIRY
!***SUBSIDIARY
!***PURPOSE  Subsidiary to BESJ and BESY
!***LIBRARY   SLATEC
!***TYPE      SINGLE PRECISION (JAIRY-S, DJAIRY-D)
!***AUTHOR  Amos, D. E., (SNLA)
!           Daniel, S. L., (SNLA)
!           Weston, M. K., (SNLA)
!***DESCRIPTION
!
!                  JAIRY computes the Airy function AI(X)
!                   and its derivative DAI(X) for ASYJY
!
!                                   INPUT
!
!         X - Argument, computed by ASYJY, X unrestricted
!        RX - RX=SQRT(ABS(X)), computed by ASYJY
!         C - C=2.*(ABS(X)**1.5)/3., computed by ASYJY
!
!                                  OUTPUT
!
!        AI - Value of function AI(X)
!       DAI - Value of the derivative DAI(X)
!
!***SEE ALSO  BESJ, BESY
!***ROUTINES CALLED  (NONE)
!***REVISION HISTORY  (YYMMDD)
!   750101  DATE WRITTEN
!   891009  Removed unreferenced variable.  (WRB)
!   891214  Prologue converted to Version 4.0 format.  (BAB)
!   900328  Added TYPE section.  (WRB)
!   910408  Updated the AUTHOR section.  (WRB)
!***END PROLOGUE  JAIRY
!
      INTEGER I, J, M1, M1D, M2, M2D, M3, M3D, M4, M4D, N1, N1D, N2,   &
       N2D, N3, N3D, N4, N4D
