       4.53724043420422E-11,-3.99655065847223E-12,-3.24089119830323E-13,   &
       1.62098952568741E-13,-2.40765247974057E-14, 1.69384811284491E-16,   &
       8.17900786477396E-16/
      DATA DB(1),  DB(2),  DB(3),  DB(4),  DB(5),  DB(6),  DB(7),   &
           DB(8),  DB(9),  DB(10), DB(11), DB(12), DB(13), DB(14),   &
           DB(15)          /-2.77571356944231E-01, 4.44212833419920E-03,   &
      -8.42328522190089E-05,-2.58040318418710E-06, 3.42389720217621E-07,   &
      -6.24286894709776E-09,-2.36377836844577E-09, 3.16991042656673E-10,   &
      -4.40995691658191E-12,-5.18674221093575E-12, 9.64874015137022E-13,   &
      -4.90190576608710E-14,-1.77253430678112E-14, 5.55950610442662E-15,   &
      -7.11793337579530E-16/
!***FIRST EXECUTABLE STATEMENT  JAIRY
      IF (X.LT.0.0E0) GO TO 90
      IF (C.GT.5.0E0) GO TO 60
      IF (X.GT.1.20E0) GO TO 30
      T = (X+X-1.2E0)*CON4
      TT = T + T
      J = N1
      F1 = AK1(J)
      F2 = 0.0E0
      DO 10 I=1,M1
        J = J - 1
        TEMP1 = F1
        F1 = TT*F1 - F2 + AK1(J)
        F2 = TEMP1
   10 CONTINUE
      AI = T*F1 - F2 + AK1(1)
!
      J = N1D
      F1 = DAK1(J)
      F2 = 0.0E0
      DO 20 I=1,M1D
        J = J - 1
        TEMP1 = F1
        F1 = TT*F1 - F2 + DAK1(J)
        F2 = TEMP1
   20 CONTINUE
      DAI = -(T*F1-F2+DAK1(1))
      RETURN
!
   30 CONTINUE
      T = (X+X-CON2)*CON3
      TT = T + T
      J = N2
      F1 = AK2(J)
      F2 = 0.0E0
      DO 40 I=1,M2
        J = J - 1
        TEMP1 = F1
        F1 = TT*F1 - F2 + AK2(J)
        F2 = TEMP1
   40 CONTINUE
      RTRX = SQRT(RX)
      EC = EXP(-C)
      AI = EC*(T*F1-F2+AK2(1))/RTRX
      J = N2D
      F1 = DAK2(J)
      F2 = 0.0E0
      DO 50 I=1,M2D
        J = J - 1
        TEMP1 = F1
        F1 = TT*F1 - F2 + DAK2(J)
        F2 = TEMP1
   50 CONTINUE
      DAI = -EC*(T*F1-F2+DAK2(1))*RTRX
      RETURN
!
   60 CONTINUE
      T = 10.0E0/C - 1.0E0
      TT = T + T
      J = N1
      F1 = AK3(J)
      F2 = 0.0E0
      DO 70 I=1,M1
        J = J - 1
        TEMP1 = F1
        F1 = TT*F1 - F2 + AK3(J)
        F2 = TEMP1
   70 CONTINUE
      RTRX = SQRT(RX)
      EC = EXP(-C)
      AI = EC*(T*F1-F2+AK3(1))/RTRX
      J = N1D
      F1 = DAK3(J)
      F2 = 0.0E0
      DO 80 I=1,M1D
        J = J - 1
        TEMP1 = F1
        F1 = TT*F1 - F2 + DAK3(J)
        F2 = TEMP1
   80 CONTINUE
      DAI = -RTRX*EC*(T*F1-F2+DAK3(1))
      RETURN
!
   90 CONTINUE
      IF (C.GT.5.0E0) GO TO 120
      T = 0.4E0*C - 1.0E0
      TT = T + T
      J = N3
      F1 = AJP(J)
      E1 = AJN(J)
      F2 = 0.0E0
      E2 = 0.0E0
      DO 100 I=1,M3
        J = J - 1
        TEMP1 = F1
        TEMP2 = E1
        F1 = TT*F1 - F2 + AJP(J)
        E1 = TT*E1 - E2 + AJN(J)
        F2 = TEMP1
        E2 = TEMP2
  100 CONTINUE
      AI = (T*E1-E2+AJN(1)) - X*(T*F1-F2+AJP(1))
      J = N3D
      F1 = DAJP(J)
      E1 = DAJN(J)
      F2 = 0.0E0
      E2 = 0.0E0
      DO 110 I=1,M3D
        J = J - 1
        TEMP1 = F1
        TEMP2 = E1
        F1 = TT*F1 - F2 + DAJP(J)
        E1 = TT*E1 - E2 + DAJN(J)
        F2 = TEMP1
        E2 = TEMP2
  110 CONTINUE
      DAI = X*X*(T*F1-F2+DAJP(1)) + (T*E1-E2+DAJN(1))
      RETURN
!
  120 CONTINUE
      T = 10.0E0/C - 1.0E0
      TT = T + T
      J = N4
      F1 = A(J)
      E1 = B(J)
      F2 = 0.0E0
      E2 = 0.0E0
      DO 130 I=1,M4
        J = J - 1
        TEMP1 = F1
        TEMP2 = E1
        F1 = TT*F1 - F2 + A(J)
        E1 = TT*E1 - E2 + B(J)
        F2 = TEMP1
        E2 = TEMP2
  130 CONTINUE
      TEMP1 = T*F1 - F2 + A(1)
      TEMP2 = T*E1 - E2 + B(1)
      RTRX = SQRT(RX)
      CV = C - FPI12
      CCV = COS(CV)
      SCV = SIN(CV)
      AI = (TEMP1*CCV-TEMP2*SCV)/RTRX
      J = N4D
      F1 = DA(J)
      E1 = DB(J)
      F2 = 0.0E0
      E2 = 0.0E0
      DO 140 I=1,M4D
        J = J - 1
        TEMP1 = F1
        TEMP2 = E1
        F1 = TT*F1 - F2 + DA(J)
        E1 = TT*E1 - E2 + DB(J)
        F2 = TEMP1
        E2 = TEMP2
  140 CONTINUE
      TEMP1 = T*F1 - F2 + DA(1)
      TEMP2 = T*E1 - E2 + DB(1)
      E1 = CCV*CON5 + 0.5E0*SCV
      E2 = SCV*CON5 - 0.5E0*CCV
      DAI = (TEMP1*E1-TEMP2*E2)*RTRX
      RETURN
      END SUBROUTINE JAIRY 
      SUBROUTINE JNSN(XBAR, SD, RB1, BB2, ITYPE, GAMMA, DELTA,   &
        XLAM, XI, IFAULT)
!START OF AS 99
!
!        ALGORITHM AS 99  APPL. STATIST. (1976) VOL.25, P.180
!
!        FINDS TYPE AND PARAMETERS OF A JOHNSON CURVE
!        WITH GIVEN FIRST FOUR MOMENTS
!
      REAL XBAR, SD, RB1, BB2, GAMMA, DELTA, XLAM, XI, TOL,   &
        B1, B2, Y, X, U, W, ZERO, ONE, TWO, THREE, FOUR, HALF,   &
        QUART, ZABS, ZEXP, ZLOG, ZSIGN, ZSQRT
      LOGICAL FAULT
!
      DATA TOL /0.01/
      DATA ZERO, QUART, HALF, ONE, TWO, THREE, FOUR   &
           /0.0,  0.25,  0.5, 1.0, 2.0,   3.0,  4.0/
!
      ZABS(X) = ABS(X)
      ZEXP(X) = EXP(X)
      ZLOG(X) = LOG(X)
      ZSIGN(X, Y) = SIGN(X, Y)
      ZSQRT(X) = SQRT(X)
!
      IFAULT = 1
      IF (SD .LT. ZERO) RETURN
      IFAULT = 0
      XI = ZERO
      XLAM = ZERO
      GAMMA = ZERO
      DELTA = ZERO
      IF (SD .GT. ZERO) GO TO  10
      ITYPE = 5
      XI = XBAR
      RETURN
   10 B1 = RB1 * RB1
      B2 = BB2
      FAULT = .FALSE.
!
!        TEST WHETHER LOGNORMAL (OR NORMAL) REQUESTED
!
      IF (B2 .GE. ZERO) GO TO  30
   20 IF (ZABS(RB1) .LE. TOL) GO TO  70
      GO TO  80
!
!        TEST FOR POSITION RELATIVE TO BOUNDARY LINE
!
   30 IF (B2 .GT. B1 + TOL + ONE) GO TO  60
      IF (B2 .LT. B1 + ONE) GO TO  50
!
!        ST DISTRIBUTION
!
   40 ITYPE = 5
      Y = HALF + HALF * ZSQRT(ONE - FOUR / (B1 + FOUR))
      IF (RB1 .GT. ZERO) Y = ONE - Y
      X = SD / ZSQRT(Y * (ONE - Y))
      XI = XBAR - Y * X
      XLAM = XI + X
      DELTA = Y
      RETURN
   50 IFAULT = 2
      RETURN
   60 IF (ZABS(RB1) .GT. TOL .OR. ZABS(B2 - THREE) .GT. TOL) GO TO  80
!
!        NORMAL DISTRIBUTION
!
   70 ITYPE = 4
      DELTA = ONE / SD
      GAMMA = -XBAR / SD
      RETURN
!
!        TEST FOR POSITION RELATIVE TO LOGNORMAL LINE
!
   80 X = HALF * B1 + ONE
      Y = ZABS(RB1) * ZSQRT(QUART * B1 + ONE)
      U = (X + Y) ** (ONE / THREE)
      W = U + ONE / U - ONE
      U = W * W * (THREE + W * (TWO + W)) - THREE
      IF (B2 .LT. ZERO .OR. FAULT) B2 = U
      X = U - B2
      IF (ZABS(X) .GT. TOL) GO TO  90
!
!        LOGNORMAL (SL) DISTRIBUTION
!
      ITYPE = 1
      XLAM = ZSIGN(ONE, RB1)
      U = XLAM * XBAR
      X = ONE / ZSQRT(ZLOG(W))
      DELTA = X
      Y = HALF * X * ZLOG(W * (W - ONE) / (SD * SD))
      GAMMA = Y
      XI = XLAM * (U - ZEXP((HALF / X - Y) / X))
      RETURN
!
!        SB OR SU DISTRIBUTION
!
   90 IF (X .GT. ZERO) GO TO  100
      ITYPE = 2
      CALL SUFIT(XBAR, SD, RB1, B2, GAMMA, DELTA, XLAM, XI)
      RETURN
  100 ITYPE = 3
      CALL SBFIT(XBAR, SD, RB1, B2, GAMMA, DELTA, XLAM, XI, FAULT)
      IF (.NOT. FAULT) RETURN
!
!        FAILURE - TRY TO FIT APPROXIMATE RESULT
!
      IFAULT = 3
      IF (B2 .GT. B1 + TWO) GO TO  20
      GO TO  40
      END SUBROUTINE JNSN
      SUBROUTINE JITTER(X,NX,DELTA,Y,NY,ISEED,IBUGA3,IERROR)
!
!     PURPOSE--JITTER A UNIVARIATE VARIABLE.  THAT IS, ADD A
!              UNIFORM RANDOM NUMBER (D DEFINES THE SCALE FOR
!              THIS RANDOM NUMBER).  THIS CAN BE HELPFUL IN
!              AVOIDING "OVERPLOTTING" ON CERTAIN TYPES OF
!              PLOTS.
!     NOTE--IT IS PERMISSIBLE TO HAVE THE OUTPUT VECTOR Y(.)
!           BEING IDENTICAL TO THE INPUT VECTOR X(.).
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007/1
!     ORIGINAL VERSION--JANUARY   2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION Y(*)
!
      REAL XTEMP(1)
!
!-----COMMON---------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='JITT'
      ISUBN2='ER  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF JITTER--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)NX,DELTA,IBUGA3
   53   FORMAT('NX,DELTA,IBUGA3 = ',I8,G15.7,2X,A4)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,MAX(100,NX)
          WRITE(ICOUT,56)I,X(I)
   56     FORMAT('I,X(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ********************************
!               **  STEP 1--                  **
!               **  COMPUTE JITTERED VALUES   **
!               ********************************
!
      IF(NX.LT.1)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,151)
  151   FORMAT('***** ERROR IN JITTER--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,152)
  152   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS IN THE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,154)
  154   FORMAT('      VARIABLE FOR WHICH THE DISTINCT VALUES ARE TO')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,155)
  155   FORMAT('      BE FOUND MUST BE 1 OR LARGER.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,156)
  156   FORMAT('      SUCH WAS NOT THE CASE HERE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,157)NX
  157   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      DELTA=ABS(DELTA)
      NTEMP=1
      IF(DELTA.EQ.0.0)DELTA=1.0
      DO 100 I=1,NX
        CALL UNIRAN(NTEMP,ISEED,XTEMP)
        XTEMP(1)=DELTA*XTEMP(1)
        ALOC=-DELTA/2.0
        ATEMP= ALOC + DELTA*XTEMP(1)
        Y(I)=X(I) + ATEMP
  100 CONTINUE
      NY=NX
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF JITTER--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGA3,IERROR
 9012   FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        DO 9015 I=1,MAX(NY,100)
          WRITE(ICOUT,9016)I,X(I),Y(I)
 9016     FORMAT('I,X(I),Y(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
 9015   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE JITTER
      SUBROUTINE JOIN(Y1,X1,Y2,N1,Y3,X3,TAG3,N3,MAXOBV,   &
                        IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--GIVEN AN (X,Y) VECTOR AND AN INDEX VARIABLE OF THE SAME
!              LENGTH, CREATE AN OUTPUT VARIABLE WHERE EACH ROW OF THE
!              (X,Y) VECTOR IS CONNECTED TO THE ROW SPECIFIED BY THE
!              INDEX VARIABLE.
!
!              THIS COMMAND IS TYPICALLY USED TO PLOT 2-D NEAREST
!              NEIGHBORS.  THAT IS, NEAREST NEIGHBORS CAN BE PLOTTED
!              WITH THE FOLLOWING SEQUENCE OF COMMANDS:
!
!                  LET INDX = NEAREST NEIGHBOR X Y
!                  LET X3 Y3 TAG3 = JOIN X Y INDX
!                  PLOT Y3 X3 TAG3
!
!     INPUT  ARGUMENTS--X1 (REAL)
!                     --Y1 (REAL)
!                     --Y2 (REAL)
!     OUTPUT ARGUMENTS--Y3 (REAL)
!                     --X3 (REAL)
!                     --TAG3 (REAL)
!
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2013/8
!     ORIGINAL VERSION--AUGUST     2013
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      REAL X1(*)
      REAL Y1(*)
      REAL Y2(*)
      REAL X3(*)
      REAL Y3(*)
      REAL TAG3(*)
!
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IERROR='NO'
      N3=0
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'JOIN')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF JOIN--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N1,MAXOBV
   52   FORMAT('IBUGA3,ISUBRO,N1,MAXOBV = ',2(A4,2X),2I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N1
          WRITE(ICOUT,56)I,X1(I),Y1(I),Y2(I)
   56     FORMAT('I,X1(I),Y1(I),Y2(I) = ',I8,3G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 11--                             **
!               **  CHECK NUMBER OF INPUT OBSERVATIONS.   **
!               ********************************************
!
      IF(N1.LT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1151)
 1151   FORMAT('***** ERROR IN JOIN--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1152)
 1152   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS IS LESS THAN ',   &
               'ONE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1154)N1
 1154   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ************************************************
!               **  STEP 2--                                  **
!               **  NOW GENERATED THE JOINED VECTOR           **
!               ************************************************
!
      ICNT1=0
      ICNT2=0
      DO 2000 K=1,N1
        IINDX=INT(Y2(K)+0.5)
        IF(IINDX.LT.1 .OR. IINDX.GT.N1)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1151)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2011)K
 2011     FORMAT('      ROW ',I8,' OF THE INDEX VARIABLE IS LESS THAN ',   &
                 '1 OR')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2013)N1
 2013     FORMAT('      GREATER THAN ',I8,'.  IT HAS THE VALUE ',I8)
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
        ICNT1=ICNT1+1
        IF(ICNT1.GT.MAXOBV)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1151)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2111)
 2111     FORMAT('      THE NUMBER OF ROWS IN THE OUTPUT VARIABLE ',   &
                 'HAS EXCEEDED ')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2113)MAXOBV
 2113     FORMAT('      THE MAXIMUM ALLOWABLE OF ',I8,'.')
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
        ICNT2=ICNT2+1
        X3(ICNT1)=X1(K)
        Y3(ICNT1)=Y1(K)
        TAG3(ICNT1)=REAL(ICNT2)
        ICNT1=ICNT1+1
        IF(ICNT1.GT.MAXOBV)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1151)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2111)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2113)MAXOBV
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
        X3(ICNT1)=X1(IINDX)
        Y3(ICNT1)=Y1(IINDX)
        TAG3(ICNT1)=REAL(ICNT2)
 2000 CONTINUE
      N3=ICNT1
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'JOIN')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF JOIN--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)IERROR,N3
 9013   FORMAT('IERROR,N3 = ',A4,2X,I8)
        CALL DPWRST('XXX','BUG ')
        DO 9021 I=1,N3
          WRITE(ICOUT,9022)I,X3(I),Y3(I),TAG3(I)
 9022     FORMAT('I,X3(I),Y3(I),TAG3(I) = ',I8,3G15.7)
          CALL DPWRST('XXX','BUG ')
 9021   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE JOIN
      SUBROUTINE JSBCDF(X,ALPHA1,ALPHA2,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE JOHNSON SB SYSTEM DISTRIBUTION.
!              THIS DISTRIBUTION CAN BE DEFINED IN TERMS OF THE
!              NORMAL DISTRIBUTION:
!              F(X) = NORCDF(ALPHA1 + ALPHA2*LOG(X/(1-X))
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE POSITIVE.
!                     --ALPHA1 = FIRST SHAPE PARAMETER
!                     --ALPHA2 = SECOND SHAPE PARAMETER
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE JOHNSON SB
!             DISTRIBUTION.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NORCDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 2ND ED., 1994, PAGE 34.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--SEPTEMBER 2001.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DARG
      DOUBLE PRECISION DCDF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(X.LE.0.0)THEN
        CDF=0.0
        GO TO 9000
      ENDIF
      IF(X.GE.1.0)THEN
        CDF=1.0
        GO TO 9000
      ENDIF
!
      IF(ALPHA2.LE.0.0)THEN
        WRITE(ICOUT,14)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA1
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9000
      ENDIF
!
   14 FORMAT('***** ERROR--THE THIRD INPUT ARGUMENT TO THE JSBCDF ')
   15 FORMAT('      SUBROUTINE IS NON-POSITIVE.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
!
!-----START POINT-----------------------------------------------------
!
      CDF=0.0
!
      ARG=ALPHA1 + ALPHA2*LOG(X/(1.0-X))
      DARG=DBLE(ARG)
      CALL NODCDF(DARG,DCDF)
      CDF=REAL(DCDF)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE JSBCDF
      SUBROUTINE JSBPDF(X,ALPHA1,ALPHA2,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE JOHNSON SB SYSTEM DISTRIBUTION.
!              THIS DISTRIBUTION CAN BE DEFINED IN TERMS OF THE
!              NORMAL DISTRIBUTION:
!              F(X) = (ALPHA2/(X*(1-X))*
!                     NORPDF(ALPHA1 + ALPHA2*LOG(X/(1-X))
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE POSITIVE.
!                     --ALPHA1 = FIRST SHAPE PARAMETER
!                     --ALPHA2 = SECOND SHAPE PARAMETER
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE JOHNSON SB
!             DISTRIBUTION.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NORPDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 2ND ED., 1994, PAGE 34.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--SEPTEMBER 2001.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DARG
      DOUBLE PRECISION DX
      DOUBLE PRECISION DPDF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(X.LE.0.0 .OR. X.GE.1.0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9000
      ENDIF
!
      IF(ALPHA2.LE.0.0)THEN
        WRITE(ICOUT,14)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA1
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9000
      ENDIF
!
    4 FORMAT('***** ERROR--THE FIRST INPUT ARGUMENT TO THE JSBPDF ')
    5 FORMAT('      SUBROUTINE IS OUTSIDE THE (0,1) INTERVAL.')
   14 FORMAT('***** ERROR--THE THIRD INPUT ARGUMENT TO THE JSBPDF ')
   15 FORMAT('      SUBROUTINE IS NON-POSITIVE.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
!
!-----START POINT-----------------------------------------------------
!
      PDF=0.0
!
      ARG=ALPHA1 + ALPHA2*LOG(X/(1.0-X))
      DARG=DBLE(ARG)
      CALL NODPDF(DARG,DPDF)
      DX=DBLE(X)
      DPDF=(DBLE(ALPHA2)/(DX*(1.0D0-DX)))*DPDF
      PDF=REAL(DPDF)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE JSBPDF
      SUBROUTINE JSBPPF(P,ALPHA1,ALPHA2,PPF)
!
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2001/9
!     ORIGINAL VERSION--SEPTEMBER 2001.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES----------------
!
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DALPH1
      DOUBLE PRECISION DALPH2
      DOUBLE PRECISION DX
      DOUBLE PRECISION DARG
      DOUBLE PRECISION DP
      DOUBLE PRECISION EPS
      DOUBLE PRECISION SIG
      DOUBLE PRECISION ZERO
      DOUBLE PRECISION A
      DOUBLE PRECISION B
      DOUBLE PRECISION AB
      DOUBLE PRECISION XL
      DOUBLE PRECISION XR
      DOUBLE PRECISION XRML
      DOUBLE PRECISION FXL
      DOUBLE PRECISION FXR
      DOUBLE PRECISION FCS
!
!-----COMMON-------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      DATA EPS /1.0D-6/
      DATA SIG /1.0D-5/
      DATA ZERO /0.D0/
      DATA MAXIT /3000/
!
!-----START POINT---------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(P.LE.0.0)THEN
        PPF=0.0
        GO TO 9999
      ELSEIF(P.GE.1.0)THEN
        PPF=1.0
        GO TO 9999
      ENDIF
!
      IF(ALPHA2.LE.0.0)THEN
        WRITE(ICOUT,14)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA1
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9999
      ENDIF
!
    4 FORMAT('***** ERROR--THE FIRST INPUT ARGUMENT TO THE JSBPPF ')
    5 FORMAT('      SUBROUTINE IS NON-POSITIVE.')
   14 FORMAT('***** ERROR--THE THIRD INPUT ARGUMENT TO THE JSBPPF ')
   15 FORMAT('      SUBROUTINE IS NON-POSITIVE.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
!
      A = ALPHA1
      B = ALPHA2
      DP = DBLE(P)
!
      IERR=0
      IC = 0
      AB = A/B
      XL = 0.0D0
      XR = 1.0D0
      FXL = -DP
      FXR = 1.0D0 - DP
!
      IF(FXL*FXR .GT. ZERO)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9999
      ENDIF
!
!  BISECTION METHOD
!
  105 CONTINUE
      DX = (XL+XR)*0.5D0
      DALPH1=DBLE(A)
      DALPH2=DBLE(B)
      DARG=DALPH1 + DALPH2*DLOG(DX/(1.0D0-DX))
      CALL NODCDF(DARG,DCDF)
      P1=DCDF
      PPF=REAL(DX)
!
      FCS = P1 - DP
      IF(FCS*FXL.GT.ZERO)GO TO 110
      XR = DX
      FXR = FCS
      GO TO 115
  110 CONTINUE
      XL = DX
      FXL = FCS
  115 CONTINUE
      XRML = XR - XL
      IF(XRML.LE.SIG .AND. ABS(FCS).LE.EPS)GO TO 9999
      IC = IC + 1
      IF(IC.LE.MAXIT)GO TO 105
      WRITE(ICOUT,130)
      CALL DPWRST('XXX','BUG ')
  130 FORMAT('***** FATAL ERROR--JSBPPF ROUTINE DID NOT CONVERGE. ',   &
             '***')
      GO TO 9999
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE JSBPPF
      SUBROUTINE JSBRAN(N,ALPHA1,ALPHA2,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE JOHNSON SB DISTRIBUTION
!              WITH SHAPE PARAMETER VALUES = ALPHA1, ALPHA2.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --ALPHA1  = THE SINGLE PRECISION VALUE OF THE
!                                FIRST SHAPE PARAMETER.
!                                ALPHA1 SHOULD BE POSITIVE.
!                     --ALPHA2  = THE SINGLE PRECISION VALUE OF THE
!                                SECOND SHAPE PARAMETER.
!                                ALPHA2 SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE JOHNSON SB DISTRIBUTION
!             WITH SHAPE PARAMETER VALUES = ALPHA1 AND ALPHA2.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --ALPHA2 SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2001.10
!     ORIGINAL VERSION--OCTOBER   2001.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    5 FORMAT('***** FATAL ERROR--THE 1ST INPUT ARGUMENT TO THE ',   &
      'JSBRAN SUBROUTINE IS NON-POSITIVE *****')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,' *****')
!
!     GENERATE N STANDARD NORMAL RANDOM NUMBERS;
!
      CALL NORRAN(N,ISEED,X)
!
!     GENERATE N JOHNSON SB DISTRIBUTION RANDOM NUMBERS
!     USING APPLIED STATISTICS ALGORITHM AS100.
!
      ITYPE=3
      ALOC=0.0
      SCALE=1.0
      DO 100 I=1,N
        XTEMP=X(I)
        XTEMP2=AJV(XTEMP,ITYPE,ALPHA1,ALPHA2,SCALE,ALOC,IFAULT)
        X(I)=XTEMP2
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE JSBRAN
      SUBROUTINE JSCORE(Z,ROUND,N,IWRITE,XIDTEM,TEMP1,Y,NY,   &
                        IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE JSCORE STATISTIC.
!              THIS IS USED IN ISO 13528 TYPE PROFICIENCY STUDIES.
!              THE INPUT IS ASSUMED TO BE A SERIES OF Z-SCORES
!              (THE ISO 13528 DEFINES MULTIPLE WAYS FOR COMPUTING
!              THE Z-SCORES, SO THIS COMMAND ASSUMES THAT THE INPUT
!              DATA IS ALREADY A Z-SCORE).
!
!              THE J-SCORE IS TYPICALLY DEFINED AS:
!
!                  IF  +3 <= Z          THEN J =  8
!                  IF  +2 <= Z <  +3    THEN J =  4
!                  IF  +1 <= Z <  +2    THEN J =  2
!                  IF  -1 <  Z <  +1    THEN J =  0
!                  IF  -2 <  Z <= -1    THEN J = -2
!                  IF  -3 <  Z <= -2    THEN J = -4
!                  IF  -3 <= Z          THEN J = -8
!
!              Z-SCORES ARE TYPICALLY COMPUTED OVER ONE OR MORE
!              MATERIALS AND ONE OR MORE ROUNDS.  J-SCORES ARE
!              TYPICALLY SUMMED OVER MULTIPLE ROUNDS UNTIL
!              ABS(JSCORE) >= 8.  THIS TYPICALLY TRIGGERS AN
!              ACTION SIGNAL AND THE J-SCORE IS RESET TO 0.
!              ALSO, WHEN SUCCESSIVE VALUES ARE OF DIFFERENT
!              SIGNS, THE JSCORE IS RESET TO 0.
!
!              THIS SUBROUTINE ASSUMES A SINGLE MATERIAL (I.E.,
!              WHEN THERE ARE MULTIPLE MATERIALS, THE DATA FOR A
!              SINGLE MATERIAL SHOULD BE EXTRACTED BEFORE CALLING
!              THIS ROUTINE).
!
!              IF THERE IS REPLICATION IN A ROUND, AN AVERAGE
!              Z-SCORE IS COMPUTED FOR THE ROUND BEFORE COMPUTING
!              THE J-SCORE.  ALTERNATIVELY, THE EXTREME Z-SCORE
!              CAN BE COMPUTED.
!
!              J-SCORES ARE TYPICALLY USED IN SHEWHART CONTROL
!              CHARTS AND ZONE PLOTS.
!
!     INPUT  ARGUMENTS--Z      = THE SINGLE PRECISION VECTOR OF
!                                Z-SCORES.
!                     --ROUND  = THE SINGLE PRECISION VECTOR THAT
!                                IDENTIFIES THE ROUND.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTORS Z AND ROUND.
!     OUTPUT ARGUMENTS--Y      = THE SINGLE PRECISION VECTOR OF THE
!                                COMPUTED JSCORE VALUES (ONE FOR EACH
!                                DISTINCT ROUND).
!                     --NY     = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE OUTPUT VECTOR Y.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VECTOR OF THE JSCORE VALUES.
!     OTHER DATAPAC   SUBROUTINES NEEDED--DISTIN, SORT.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--THOMPSON, ELLISON, WOOD (2006), "THE INTERNATIONAL
!                 HARMONIZED PROTOCOL FOR THE PROFICIENCY TESTING OF
!                 ANALYTICAL CHEMISTRY LABORATORIES", PURE APPLIED
!                 CHEMISTRY, VOL. 78, NO. 1, PP. 145-196.
!     REFERENCES--ISO 13528, FIRST EDITION, STATISTICAL METHODS FOR USE
!                 IN PROFICIENCY TESTING BY INTERLABORATORY COMPARISONS,
!                 2005, PP. 27-28.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2012.1
!     ORIGINAL VERSION--JANUARY   2012.
!     UPDATED         --OCTOBER   2015. WHEN THERE IS REPLICATION, ALLOW
!                                       EITHER AN AVERAGE OR AN EXTREME
!                                       Z-SCORE TO BE COMPUTED.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION Z(*)
      DIMENSION Y(*)
      DIMENSION ROUND(*)
      DIMENSION XIDTEM(*)
      DIMENSION TEMP1(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOST.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='JSCO'
      ISUBN2='RE  '
      IERROR='NO'
!
      ISIGN=-99
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CORE')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF JSCORE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,IWRITE,N
   52   FORMAT('IBUGA3,ISUBRO,IWRITE,N = ',3(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,Z(I),ROUND(I)
   56     FORMAT('I,Z(I),ROUND(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN JSCORE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE NUMBER OF OBSERVATIONS IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ****************************************************
!               **  STEP 2--                                     **
!               **  DETERMINE (AND SORT) THE UNIQUE VALUES FOR   **
!               **  ROUND-ID VARIABLE                            **
!               ****************************************************
!
      CALL DISTIN(ROUND,N,IWRITE,XIDTEM,NY,IBUGA3,IERROR)
      CALL SORT(XIDTEM,NY,XIDTEM)
!
!               ***************************************************
!               **  STEP 3--                                     **
!               **  COMPUTE THE JSCORE FOR EACH ROUND            **
!               **    1) COMPUTE THE AVERAGE Z-SCORE FOR THE     **
!               **       ROUND.                                  **
!               **    2) COMPUTE THE JSCORE FOR THE ROUND.       **
!               ***************************************************
!
      AJ=0.0
      AJPREV=0.0
      SUM1=0.0
      EPS=0.000001
!
      DO 110 IR=1,NY
        HOLD1=XIDTEM(IR)
        K=0
        AMIN=CPUMAX
        AMAX=CPUMIN
        DO 120 J=1,N
          IF(ROUND(J).EQ.HOLD1)THEN
            K=K+1
            TEMP1(K)=Z(J)
          ENDIF
  120   CONTINUE
!
!       2015/10: SUPPORT FOLLOWING OPTIONS FOR THE CASE WHEN THERE
!                IS REPLICATION WITHIN A ROUND.
!
!                  1. TAKE THE AVERAGE OF THE Z-SCORES (THIS WAS THE
!                     PREVIOUSLY IMPLMENTED OPTION.
!                  2. TAKE THE MOST EXTREME Z-SCORE IN THE CELL.
!
!CCCC   ZSCORE=REAL(DSUM2/DBLE(K))
!
        IF(K.EQ.1)THEN
          ZSCORE=TEMP1(1)
        ELSE
          IF(IJSREP.EQ.'AVER')THEN
            CALL MEAN(TEMP1,K,IWRITE,ZSCORE,IBUGA3,IERROR)
          ELSEIF(IJSREP.EQ.'EXTR')THEN
            CALL MINIM(TEMP1,K,IWRITE,ZMIN,IBUGA3,IERROR)
            CALL MAXIM(TEMP1,K,IWRITE,ZMAX,IBUGA3,IERROR)
            ZSCORE=ZMIN
            IF(ABS(ZMAX).GT.ABS(ZMIN))ZSCORE=ZMAX
          ENDIF
        ENDIF
!
!       STEP 1: CONVERT Z-SCORE TO A NON-CUMULATIVE J-SCORE
!
        IF(ZSCORE.LE.-3.0)THEN
          AJSCOR=-8.0
        ELSEIF(ZSCORE.LE.-2.0)THEN
          AJSCOR=-4.0
        ELSEIF(ZSCORE.LE.-1.0)THEN
          AJSCOR=-2.0
        ELSEIF(ZSCORE.GE.3.0)THEN
          AJSCOR=8.0
        ELSEIF(ZSCORE.GE.2.0)THEN
          AJSCOR=4.0
        ELSEIF(ZSCORE.GE.1.0)THEN
          AJSCOR=2.0
        ELSE
          AJSCOR=0.0
          ISIGN=1
          IF(ZSCORE.LT.0.0)ISIGN=-1
        ENDIF
!
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CORE')THEN
          WRITE(ICOUT,211)IR,ZSCORE,AJSCOR
  211     FORMAT('STEP 1: IR,ZSCORE,AJSCOR = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
!       STEP 2: CONVERT NON-CUMULATIVE J-SCORE TO A CUMULATIVE J-SCORE
!
!               THERE ARE 2 SPECIAL CASES FOR THE CUMULAIVE Z-SCORE:
!
!                1) IF THE ABSOLUTE VALUE IS GREATER THAN 8, SET THE
!                   THE CURRENT J-SCORE TO 8 BUT RESET THE CUMULATIVE
!                   SUM TO 0.
!
!                2) IF THERE IS A CHANGE OF SIGN, SET THE CUMULATIVE
!                   J-SCORE FOR THAT CELL EQUAL TO THE NON-CUMULATIVE
!                   J-SCORE.  HOWEVER, RESET THE CUMULATIVE SCORE
!                   FOR THE NEXT CELL TO 0.
!
        IF(AJSCOR.LE.-8.0)THEN
          AJ=-8.0
          IF(AJPREV.LT.0.0)THEN
            SUM1=AJ + AJPREV
          ELSE
            SUM1=AJ
          ENDIF
          AJPREV=0.0
        ELSEIF(AJSCOR.GE.8.0)THEN
          AJ=8.0
          IF(AJPREV.GT.0.0)THEN
            SUM1=AJ + AJPREV
          ELSE
            SUM1=AJ
          ENDIF
          AJPREV=0.0
        ELSEIF(AJSCOR.LE.-4.0)THEN
          AJ=-4.0
          IF(AJPREV.LE.0.0)THEN
            SUM1=SUM1+AJ
            AJPREV=SUM1
          ELSE
            SUM1=AJ
            AJPREV=AJ
          ENDIF
        ELSEIF(AJSCOR.GE.4.0)THEN
          AJ=4.0
          IF(AJPREV.GE.0.0)THEN
            SUM1=SUM1+AJ
            AJPREV=SUM1
          ELSE
            SUM1=AJ
            AJPREV=AJ
          ENDIF
        ELSEIF(AJSCOR.LE.-2.0)THEN
          AJ=-2.0
          IF(AJPREV.LE.0.0)THEN
            SUM1=SUM1+AJ
            AJPREV=SUM1
          ELSE
            SUM1=AJ
            AJPREV=AJ
          ENDIF
        ELSEIF(AJSCOR.GE.2.0)THEN
          AJ=2.0
          IF(AJPREV.GE.0.0)THEN
            SUM1=SUM1+AJ
            AJPREV=SUM1
          ELSE
            SUM1=AJ
            AJPREV=AJ
          ENDIF
        ELSE
          IF(ISIGN.EQ.-1)THEN
            AJ=0.0
            IF(AJPREV.LE.0.0)THEN
              SUM1=SUM1+AJ
              AJPREV=SUM1
            ELSE
              SUM1=AJ
              AJPREV=AJ
            ENDIF
          ELSEIF(ISIGN.EQ.1)THEN
            AJ=0.0
            IF(AJPREV.GE.0.0)THEN
              SUM1=SUM1+AJ
              AJPREV=SUM1
            ELSE
              SUM1=AJ
              AJPREV=AJ
            ENDIF
          ENDIF
        ENDIF
!
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CORE')THEN
          WRITE(ICOUT,131)IR,HOLD1,ZSCORE,AJ,AJPREV,SUM1
  131     FORMAT('IR,HOLD1,ZSCORE,AJ,AJPREV,SUM1 = ',I8,5G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        Y(IR)=SUM1
        SUM1=AJPREV
  110 CONTINUE
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,811)NY
  811   FORMAT('THE NUMBER OF JSCORE VALUES GENERATED = ',I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CORE')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END OF JSCORE--')
        CALL DPWRST('XXX','BUG ')
        DO 9012 I=1,NY
          WRITE(ICOUT,9015)I,Y(I)
 9015     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
 9012   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE JSCORE
      SUBROUTINE JSCTAB(Z,ROUND,MATID,N,IWRITE,   &
                        XIDTEM,XIDTE2,TEMP1,   &
                        Y,RNDOUT,MATOUT,NY,   &
                        IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE JSCORE STATISTIC.
!              THIS IS USED IN ISO 13528 TYPE PROFICIENCY STUDIES.
!              THE INPUT IS ASSUMED TO BE A SERIES OF Z-SCORES
!              (THE ISO 13528 DEFINES MULTIPLE WAYS FOR COMPUTING
!              THE Z-SCORES, SO THIS COMMAND ASSUMES THAT THE INPUT
!              DATA IS ALREADY A Z-SCORE).
!
!              THE J-SCORE IS TYPICALLY DEFINED AS:
!
!                  IF  +3 <= Z          THEN J =  8
!                  IF  +2 <= Z <  +3    THEN J =  4
!                  IF  +1 <= Z <  +2    THEN J =  2
!                  IF  -1 <  Z <  +1    THEN J =  0
!                  IF  -2 <  Z <= -1    THEN J = -2
!                  IF  -3 <  Z <= -2    THEN J = -4
!                  IF  -3 <= Z          THEN J = -8
!
!              Z-SCORES ARE TYPICALLY COMPUTED OVER ONE OR MORE
!              MATERIALS AND ONE OR MORE ROUNDS.  J-SCORES ARE
!              TYPICALLY SUMMED OVER MULTIPLE ROUNDS UNTIL
!              ABS(JSCORE) >= 8.  THIS TYPICALLY TRIGGERS AN
!              ACTION SIGNAL AND THE J-SCORE IS RESET TO 0.
!              ALSO, WHEN SUCCESSIVE VALUES ARE OF DIFFERENT
!              SIGNS, THE JSCORE IS RESET TO 0.
!
!              THIS SUBROUTINE IS SIMILAR TO JSCORE.  THE DISTINCTION
!              IS THAT THIS ROUTINE PROCESSES MULTIPLE MATERIALS WHILE
!              JSCORE ASSUMES A SINGLE MATERIAL.  THIS ROUTINE WILL
!              RETURN THE CORRESPONDING ROUND AND MATERIAL ID'S FOR
!              THE CORRESPONDING J-SCORES.
!
!              IF THERE IS REPLICATION IN A ROUND, AN AVERAGE
!              Z-SCORE IS COMPUTED FOR THE ROUND BEFORE COMPUTING
!              THE J-SCORE.  ALTERNATIVELY, THE EXTREME Z-SCORE
!              CAN BE COMPUTED.
!
!              J-SCORES ARE TYPICALLY USED IN SHEWHART CONTROL
!              CHARTS AND ZONE PLOTS.
!
!     INPUT  ARGUMENTS--Z      = THE SINGLE PRECISION VECTOR OF
!                                Z-SCORES.
!                     --ROUND  = THE SINGLE PRECISION VECTOR THAT
!                                IDENTIFIES THE ROUND.
!                     --ROUND  = THE SINGLE PRECISION VECTOR THAT
!                                IDENTIFIES THE MATERIAL.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTORS Z AND ROUND.
!     OUTPUT ARGUMENTS--Y      = THE SINGLE PRECISION VECTOR OF THE
!                                COMPUTED JSCORE VALUES (ONE FOR EACH
!                                DISTINCT ROUND).
!                     --RNDOUT = THE SINGLE PRECISION VECTOR OF THE
!                                ROUND-ID CORRESPONDING TO THE J-SCORE.
!                     --MATOUT = THE SINGLE PRECISION VECTOR OF THE
!                                MATERIAL-ID CORRESPONDING TO THE J-SCORE.
!                     --NY     = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE OUTPUT VECTOR Y.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VECTOR OF THE JSCORE VALUES.
!     OTHER DATAPAC   SUBROUTINES NEEDED--DISTIN, SORT.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--THOMPSON, ELLISON, WOOD (2006), "THE INTERNATIONAL
!                 HARMONIZED PROTOCOL FOR THE PROFICIENCY TESTING OF
!                 ANALYTICAL CHEMISTRY LABORATORIES", PURE APPLIED
!                 CHEMISTRY, VOL. 78, NO. 1, PP. 145-196.
!     REFERENCES--ISO 13528, FIRST EDITION, STATISTICAL METHODS FOR USE
!                 IN PROFICIENCY TESTING BY INTERLABORATORY COMPARISONS,
!                 2005, PP. 27-28.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2015.10
!     ORIGINAL VERSION--OCTOBER   2015.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      REAL Z(*)
      REAL ROUND(*)
      REAL MATID(*)
      REAL Y(*)
      REAL RNDOUT(*)
      REAL MATOUT(*)
      REAL XIDTEM(*)
      REAL XIDTE2(*)
      REAL TEMP1(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOST.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='JSCT'
      ISUBN2='AB  '
      IERROR='NO'
!
      ISIGN=-99
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CTAB')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF JSCTAB--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,IWRITE,N
   52   FORMAT('IBUGA3,ISUBRO,IWRITE,N = ',3(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,Z(I),ROUND(I),MATID(I)
   56     FORMAT('I,Z(I),ROUND(I),MATID(I) = ',I8,3G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,101)
  101   FORMAT('***** ERROR IN JSCORE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,102)
  102   FORMAT('      THE NUMBER OF OBSERVATIONS IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,103)N
  103   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ****************************************************
!               **  STEP 2--                                     **
!               **  DETERMINE (AND SORT) THE UNIQUE VALUES FOR   **
!               **  ROUND-ID VARIABLE                            **
!               ****************************************************
!
      CALL DISTIN(ROUND,N,IWRITE,XIDTEM,NRND,IBUGA3,IERROR)
      CALL SORT(XIDTEM,NRND,XIDTEM)
      CALL DISTIN(MATID,N,IWRITE,XIDTE2,NMAT,IBUGA3,IERROR)
      CALL SORT(XIDTE2,NMAT,XIDTE2)
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CTAB')THEN
        WRITE(ICOUT,201)NRND,NMAT
  201   FORMAT('NRND,NMAT = ',2I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ***************************************************
!               **  STEP 3--                                     **
!               **  LOOP THROUGH EACH MATERIAL                   **
!               ***************************************************
!
      NY=0
      DO 310 IMAT=1,NMAT
        HOLD2=XIDTE2(IMAT)
!
!               ***************************************************
!               **  STEP 4--                                     **
!               **  COMPUTE THE JSCORE FOR EACH ROUND            **
!               **    1) COMPUTE THE AVERAGE Z-SCORE FOR THE     **
!               **       ROUND.                                  **
!               **    2) COMPUTE THE JSCORE FOR THE ROUND.       **
!               ***************************************************
!
!
        AJ=0.0
        AJPREV=0.0
        SUM1=0.0
        EPS=0.000001
!
        DO 410 IRND=1,NRND
          HOLD1=XIDTEM(IRND)
          K=0
          AMIN=CPUMAX
          AMAX=CPUMIN
          DO 420 J=1,N
            IF(ROUND(J).EQ.HOLD1 .AND. MATID(J).EQ.HOLD2)THEN
              K=K+1
              TEMP1(K)=Z(J)
            ENDIF
  420     CONTINUE
!
!         SUPPORT FOLLOWING OPTIONS FOR THE CASE WHEN THERE
!         IS REPLICATION WITHIN A ROUND.
!
!            1. TAKE THE AVERAGE OF THE Z-SCORES (THIS WAS THE
!               PREVIOUSLY IMPLMENTED OPTION.
!            2. TAKE THE MOST EXTREME Z-SCORE IN THE CELL.
!
          IF(K.EQ.0)THEN
            GO TO 410
          ELSEIF(K.EQ.1)THEN
            ZSCORE=TEMP1(1)
          ELSE
            IF(IJSREP.EQ.'AVER')THEN
              CALL MEAN(TEMP1,K,IWRITE,ZSCORE,IBUGA3,IERROR)
            ELSEIF(IJSREP.EQ.'EXTR')THEN
              CALL MINIM(TEMP1,K,IWRITE,ZMIN,IBUGA3,IERROR)
              CALL MAXIM(TEMP1,K,IWRITE,ZMAX,IBUGA3,IERROR)
              ZSCORE=ZMIN
              IF(ABS(ZMAX).GT.ABS(ZMIN))ZSCORE=ZMAX
            ENDIF
          ENDIF
!
!         STEP 1: CONVERT Z-SCORE TO A NON-CUMULATIVE J-SCORE
!
          IF(ZSCORE.LE.-3.0)THEN
            AJSCOR=-8.0
          ELSEIF(ZSCORE.LE.-2.0)THEN
            AJSCOR=-4.0
          ELSEIF(ZSCORE.LE.-1.0)THEN
            AJSCOR=-2.0
          ELSEIF(ZSCORE.GE.3.0)THEN
            AJSCOR=8.0
          ELSEIF(ZSCORE.GE.2.0)THEN
            AJSCOR=4.0
          ELSEIF(ZSCORE.GE.1.0)THEN
            AJSCOR=2.0
          ELSE
            AJSCOR=0.0
            ISIGN=1
            IF(ZSCORE.LT.0.0)ISIGN=-1
          ENDIF
!
          IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CTAB')THEN
            WRITE(ICOUT,411)IMAT,IR,ZSCORE,AJSCOR
  411       FORMAT('STEP 1: IMAT,IR,ZSCORE,AJSCOR = ',2I8,2G15.7)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
!         STEP 2: CONVERT NON-CUMULATIVE J-SCORE TO A CUMULATIVE J-SCORE
!
!                 THERE ARE 2 SPECIAL CASES FOR THE CUMULAIVE Z-SCORE:
!
!                  1) IF THE ABSOLUTE VALUE IS GREATER THAN 8, SET THE
!                     THE CURRENT J-SCORE TO 8 BUT RESET THE CUMULATIVE
!                     SUM TO 0.
!
!                  2) IF THERE IS A CHANGE OF SIGN, SET THE CUMULATIVE
!                     J-SCORE FOR THAT CELL EQUAL TO THE NON-CUMULATIVE
!                     J-SCORE.  HOWEVER, RESET THE CUMULATIVE SCORE
!                     FOR THE NEXT CELL TO 0.
!
          IF(AJSCOR.LE.-8.0)THEN
            AJ=-8.0
            IF(AJPREV.LT.0.0)THEN
              SUM1=AJ + AJPREV
            ELSE
              SUM1=AJ
            ENDIF
            AJPREV=0.0
          ELSEIF(AJSCOR.GE.8.0)THEN
            AJ=8.0
            IF(AJPREV.GT.0.0)THEN
              SUM1=AJ + AJPREV
            ELSE
              SUM1=AJ
            ENDIF
            AJPREV=0.0
          ELSEIF(AJSCOR.LE.-4.0)THEN
            AJ=-4.0
            IF(AJPREV.LE.0.0)THEN
              SUM1=SUM1+AJ
              AJPREV=SUM1
            ELSE
              SUM1=AJ
              AJPREV=AJ
            ENDIF
          ELSEIF(AJSCOR.GE.4.0)THEN
            AJ=4.0
            IF(AJPREV.GE.0.0)THEN
              SUM1=SUM1+AJ
              AJPREV=SUM1
            ELSE
              SUM1=AJ
              AJPREV=AJ
            ENDIF
          ELSEIF(AJSCOR.LE.-2.0)THEN
            AJ=-2.0
            IF(AJPREV.LE.0.0)THEN
              SUM1=SUM1+AJ
              AJPREV=SUM1
            ELSE
              SUM1=AJ
              AJPREV=AJ
            ENDIF
          ELSEIF(AJSCOR.GE.2.0)THEN
            AJ=2.0
            IF(AJPREV.GE.0.0)THEN
              SUM1=SUM1+AJ
              AJPREV=SUM1
            ELSE
              SUM1=AJ
              AJPREV=AJ
            ENDIF
          ELSE
            IF(ISIGN.EQ.-1)THEN
              AJ=0.0
              IF(AJPREV.LE.0.0)THEN
                SUM1=SUM1+AJ
                AJPREV=SUM1
              ELSE
                SUM1=AJ
                AJPREV=AJ
              ENDIF
            ELSEIF(ISIGN.EQ.1)THEN
              AJ=0.0
              IF(AJPREV.GE.0.0)THEN
                SUM1=SUM1+AJ
                AJPREV=SUM1
              ELSE
                SUM1=AJ
                AJPREV=AJ
              ENDIF
            ENDIF
          ENDIF
!
          IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CTAB')THEN
            WRITE(ICOUT,431)HOLD2,HOLD1,ZSCORE,AJ,AJPREV,SUM1
  431       FORMAT('HOLD2,HOLD1,ZSCORE,AJ,AJPREV,SUM1 = ',6G15.7)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
          NY=NY+1
          Y(NY)=SUM1
          RNDOUT(NY)=HOLD1
          MATOUT(NY)=HOLD2
          SUM1=AJPREV
  410   CONTINUE
!
  310   CONTINUE
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,811)NY
  811   FORMAT('THE NUMBER OF JSCORE VALUES GENERATED = ',I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CTAB')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END OF JSCTAB--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)IERROR,NY
 9013   FORMAT('IERROR,NY = ',A4,2X,I8)
        CALL DPWRST('XXX','BUG ')
        IF(NY.GT.0)THEN
          DO 9012 I=1,NY
            WRITE(ICOUT,9015)I,Y(I),RNDOUT(I),MATOUT(I)
 9015       FORMAT('I,Y(I),RNDOUT(I),MATOUT(I) = ',I8,3G15.7)
            CALL DPWRST('XXX','BUG ')
 9012     CONTINUE
        ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE JSCTAB
      SUBROUTINE JSUCDF(X,ALPHA1,ALPHA2,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE JOHNSON SU SYSTEM DISTRIBUTION.
!              THIS DISTRIBUTION CAN BE DEFINED IN TERMS OF THE
!              NORMAL DISTRIBUTION:
!              F(X) = NORCDF(ALPHA1 + ALPHA2*LOG(X + SQRT(x**2+1))
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE POSITIVE.
!                     --ALPHA1 = FIRST SHAPE PARAMETER
!                     --ALPHA2 = SECOND SHAPE PARAMETER
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE JOHNSON SU
!             DISTRIBUTION.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NORCDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 2ND ED., 1994, PAGE 34.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--SEPTEMBER 2001.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DARG
      DOUBLE PRECISION DCDF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(ALPHA2.LE.0.0)THEN
        WRITE(ICOUT,14)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA1
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9000
      ENDIF
!
   14 FORMAT('***** ERROR--THE THIRD INPUT ARGUMENT TO THE JSUCDF ')
   15 FORMAT('      SUBROUTINE IS NON-POSITIVE.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
!
!-----START POINT-----------------------------------------------------
!
      CDF=0.0
!
      ARG=ALPHA1 + ALPHA2*LOG(X + SQRT(X**2+1))
      DARG=DBLE(ARG)
      CALL NODCDF(DARG,DCDF)
      CDF=REAL(DCDF)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE JSUCDF
      SUBROUTINE JSUPDF(X,ALPHA1,ALPHA2,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE JOHNSON SU SYSTEM DISTRIBUTION.
!              THIS DISTRIBUTION CAN BE DEFINED IN TERMS OF THE
!              NORMAL DISTRIBUTION:
!              F(X) = (ALPHA2/SQRT(X**2 + 1))*
!                     NORPDF(ALPHA1 + ALPHA2*LOG(X + SQRT(X**2+1)))
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE POSITIVE.
!                     --ALPHA1 = FIRST SHAPE PARAMETER
!                     --ALPHA2 = SECOND SHAPE PARAMETER
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE JOHNSON SU
!             DISTRIBUTION.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NORPDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 2ND ED., 1994, PAGE 34.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--SEPTEMBER 2001.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DARG
      DOUBLE PRECISION DX
      DOUBLE PRECISION DPDF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(ALPHA2.LE.0.0)THEN
        WRITE(ICOUT,14)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA1
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9000
      ENDIF
!
   14 FORMAT('***** ERROR--THE THIRD INPUT ARGUMENT TO THE JSUPDF ')
   15 FORMAT('      SUBROUTINE IS NON-POSITIVE.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
!
!-----START POINT-----------------------------------------------------
!
      PDF=0.0
!
      ARG=ALPHA1 + ALPHA2*LOG(X + SQRT(X**2+1.0))
      DARG=DBLE(ARG)
      CALL NODPDF(DARG,DPDF)
      DX=DBLE(X)
      DPDF=(DBLE(ALPHA2)/DSQRT(DX*DX+1.0D0))*DPDF
      PDF=REAL(DPDF)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE JSUPDF
      SUBROUTINE JSUPPF(P,ALPHA1,ALPHA2,PPF)
!
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--THE PERCENT POINT FUNCTION FOR THE JOHNSON SU
!           FUNCTION IS:
!           G(P,ALPHA1,ALPHA2) = SINH[(NORPPF(P) - ALPHA1)/ALPHA2]
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2001/9
!     ORIGINAL VERSION--SEPTEMBER 2001.
!     UPDATED         --NOVEMBER  2003. USE CLOSED FORMULA BASED
!                                       ON NORPPF
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES----------------
!
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
!
!-----COMMON-------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT---------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(P.LE.0.0)THEN
        PPF=0.0
        GO TO 9999
      ELSEIF(P.GE.1.0)THEN
        PPF=0.0
        GO TO 9999
      ENDIF
!
      IF(ALPHA2.LE.0.0)THEN
        WRITE(ICOUT,14)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA1
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9999
      ENDIF
!
   14 FORMAT('***** ERROR--THE THIRD ARGUMENT TO JSUPPF ')
   15 FORMAT('      IS NON-POSITIVE.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
!
!  NOTE: NOVEMBER 2003.  USE CLOSED FORM SOLUTION FOR PPF FUNCTION.
!
      CALL NODPPF(DBLE(P),DTERM1)
      DTERM2=(DTERM1 - DBLE(ALPHA1))/DBLE(ALPHA2)
      DTERM3=(DEXP(DTERM2) - DEXP(-DTERM2))/2.0D0
      PPF=REAL(DTERM3)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE JSUPPF
      SUBROUTINE JSURAN(N,ALPHA1,ALPHA2,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE JOHNSON SU DISTRIBUTION
!              WITH SHAPE PARAMETER VALUES = ALPHA1, ALPHA2.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --ALPHA1  = THE SINGLE PRECISION VALUE OF THE
!                                FIRST SHAPE PARAMETER.
!                                ALPHA1 SHOULD BE POSITIVE.
!                     --ALPHA2  = THE SINGLE PRECISION VALUE OF THE
!                                SECOND SHAPE PARAMETER.
!                                ALPHA2 SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE JOHNSON SU DISTRIBUTION
!             WITH SHAPE PARAMETER VALUES = ALPHA1 AND ALPHA2.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --ALPHA2 SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2001.10
!     ORIGINAL VERSION--OCTOBER   2001.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    5 FORMAT('***** FATAL ERROR--THE 1ST INPUT ARGUMENT TO THE ',   &
      'JSURAN SUBROUTINE IS NON-POSITIVE *****')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,' *****')
!
!     GENERATE N STANDARD NORMAL RANDOM NUMBERS;
!
      CALL NORRAN(N,ISEED,X)
!
!     GENERATE N JOHNSON SU DISTRIBUTION RANDOM NUMBERS
!     USING APPLIED STATISTICS ALGORITHM.
!
!     GENERATE N JOHNSON SU DISTRIBUTION RANDOM NUMBERS
!     USING APPLIED STATISTICS ALGORITHM AS100.
!
      ITYPE=2
      ALOC=0.0
      SCALE=1.0
      DO 100 I=1,N
        XTEMP=X(I)
        XTEMP2=AJV(XTEMP,ITYPE,ALPHA1,ALPHA2,SCALE,ALOC,IFAULT)
        X(I)=XTEMP2
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE JSURAN
      DOUBLE PRECISION FUNCTION K0INT(XVALUE)
!
!   DESCRIPTION:
!
!      This function calculates the integral of the modified Bessel function
!      defined by
!
!         K0INT(x) = {integral 0 to x} K0(t) dt
!
!      The code uses Chebyshev expansions, whose coefficients are
!      given to 20 decimal places.
!
!
!   ERROR RETURNS:
!
!      If XVALUE < 0.0, the function is undefined. An error message is
!      printed and the function returns the value 0.0.
!
!
!   MACHINE-DEPENDENT CONSTANTS:
!
!      NTERM1 - The no. of terms to be used in the array AK0IN1. The
!                recommended value is such that
!                   ABS(AK0IN1(NTERM1)) < EPS/100,
!
!      NTERM2 - The no. of terms to be used in the array AK0IN2. The
!                recommended value is such that
!                   ABS(AK0IN2(NTERM2)) < EPS/100,
!
!      NTERM3 - The no. of terms to be used in the array AK0INA. The
!                recommended value is such that
!                   ABS(AK0INA(NTERM3)) < EPS/100,
!
!      XLOW - The value below which K0INT = x * ( const - ln(x) ) to
!             machine precision. The recommended value is
!                   sqrt (18*EPSNEG).
!
!      XHIGH - The value above which K0INT = pi/2 to machine precision.
!              The recommended value is
!                   - log (2*EPSNEG)
!
!      For values of EPS and EPSNEG refer to the file MACHCON.TXT.
!
!      The machine-dependent constants are computed internally by
!      using the D1MACH subroutine.
!
!
!   INTRINSIC FUNCTIONS USED:
!
!      EXP , LOG , SQRT
!
!
!   OTHER MISCFUN SUBROUTINES USED:
!
!          CHEVAL , ERRPRN, D1MACH
!
!
!   AUTHOR:
!         Dr. Allan J. MacLeod,
!         Dept. of Mathematics and Statistics,
!         University of Paisley,
!         High St.,
!         Paisley,
!         SCOTLAND
!
!         (e-mail: macl_ms0@paisley.ac.uk )
!
!
!   LATEST REVISION:
!                   23 January, 1996
!
      INTEGER NTERM1,NTERM2,NTERM3
      DOUBLE PRECISION AK0IN1(0:15),AK0IN2(0:15),AK0INA(0:27),   &
           CHEVAL,CONST1,CONST2,EIGHTN,FVAL,HALF,   &
           ONEHUN,PIBY2,RT2BPI,SIX,T,TEMP,TWELVE,X,   &
           XHIGH,XLOW,XVALUE,ZERO
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
!CCCC CHARACTER FNNAME*8,ERRMSG*14
!CCCC DATA FNNAME/'K0INT '/
!CCCC DATA ERRMSG/'ARGUMENT < 0.0'/
      DATA ZERO,HALF,SIX/ 0.0D0 , 0.5D0 , 6.0D0 /
      DATA TWELVE,EIGHTN,ONEHUN/ 12.0D0 , 18.0D0 , 100.0D0 /
      DATA CONST1/1.11593151565841244881D0/
      DATA CONST2/-0.11593151565841244881D0/
      DATA PIBY2/1.57079632679489661923D0/
      DATA RT2BPI/0.79788456080286535588D0/
      DATA AK0IN1/16.79702714464710959477D0,   &
                   9.79134687676889407070D0,   &
                   2.80501316044337939300D0,   &
                   0.45615620531888502068D0,   &
                   0.4716224457074760784D-1,   &
                   0.335265148269698289D-2,   &
                   0.17335181193874727D-3,   &
                   0.679951889364702D-5,   &
                   0.20900268359924D-6,   &
                   0.516603846976D-8,   &
                   0.10485708331D-9,   &
                   0.177829320D-11,   &
                   0.2556844D-13,   &
                   0.31557D-15,   &
                   0.338D-17,   &
                   0.3D-19/
      DATA AK0IN2/10.76266558227809174077D0,   &
                   5.62333479849997511550D0,   &
                   1.43543664879290867158D0,   &
                   0.21250410143743896043D0,   &
                   0.2036537393100009554D-1,   &
                   0.136023584095623632D-2,   &
                   0.6675388699209093D-4,   &
                   0.250430035707337D-5,   &
                   0.7406423741728D-7,   &
                   0.176974704314D-8,   &
                   0.3485775254D-10,   &
                   0.57544785D-12,   &
                   0.807481D-14,   &
                   0.9747D-16,   &
                   0.102D-17,   &
                   0.1D-19/
      DATA AK0INA(0)/  1.91172065445060453895D0/
      DATA AK0INA(1)/ -0.4183064565769581085D-1/
      DATA AK0INA(2)/  0.213352508068147486D-2/
      DATA AK0INA(3)/ -0.15859497284504181D-3/
      DATA AK0INA(4)/  0.1497624699858351D-4/
      DATA AK0INA(5)/ -0.167955955322241D-5/
      DATA AK0INA(6)/  0.21495472478804D-6/
      DATA AK0INA(7)/ -0.3058356654790D-7/
      DATA AK0INA(8)/  0.474946413343D-8/
      DATA AK0INA(9)/ -0.79424660432D-9/
      DATA AK0INA(10)/ 0.14156555325D-9/
      DATA AK0INA(11)/-0.2667825359D-10/
      DATA AK0INA(12)/ 0.528149717D-11/
      DATA AK0INA(13)/-0.109263199D-11/
      DATA AK0INA(14)/ 0.23518838D-12/
      DATA AK0INA(15)/-0.5247991D-13/
      DATA AK0INA(16)/ 0.1210191D-13/
      DATA AK0INA(17)/-0.287632D-14/
      DATA AK0INA(18)/ 0.70297D-15/
      DATA AK0INA(19)/-0.17631D-15/
      DATA AK0INA(20)/ 0.4530D-16/
      DATA AK0INA(21)/-0.1190D-16/
      DATA AK0INA(22)/ 0.319D-17/
      DATA AK0INA(23)/-0.87D-18/
      DATA AK0INA(24)/ 0.24D-18/
      DATA AK0INA(25)/-0.7D-19/
      DATA AK0INA(26)/ 0.2D-19/
      DATA AK0INA(27)/-0.1D-19/
!
      XLOW=CPUMIN
!
!   Start computation
!
      X = XVALUE
!
!   Error test
!
      IF ( X .LT. ZERO ) THEN
!CCCC    CALL ERRPRN(FNNAME,ERRMSG)
         WRITE(ICOUT,999)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,101)X
         CALL DPWRST('XXX','BUG ')
         K0INT = ZERO
         RETURN
      ENDIF
  999 FORMAT(1X)
  101 FORMAT('***** ERROR FROM I0INT--ARGUMENT MUST BE ',   &
              'NON-NEGATIVE, ARGUMENT = ',G15.7)
!
!   Compute the machine-dependent constants.
!
      TEMP = D1MACH(3)
      T = TEMP / ONEHUN
      IF ( X .LE. SIX ) THEN
         DO 10 NTERM1 = 15 , 0 , -1
            IF ( ABS(AK0IN1(NTERM1)) .GT. T ) GO TO  19
 10      CONTINUE
 19      DO 20 NTERM2 = 15 , 0 , -1
            IF ( ABS(AK0IN2(NTERM2)) .GT. T ) GO TO  29
 20      CONTINUE
 29      XLOW = SQRT ( EIGHTN * TEMP )
      ELSE
         DO 40 NTERM3 = 27 , 0 , -1
            IF ( ABS(AK0INA(NTERM3)) .GT. T ) GO TO  49
 40      CONTINUE
 49      XHIGH = - LOG ( TEMP + TEMP )
      ENDIF
!
!   Code for 0 <= XVALUE <= 6
!
      IF ( X .LE. SIX ) THEN
         IF ( X .LT. XLOW ) THEN
            FVAL = X
            IF ( X .GT. ZERO ) THEN
               FVAL = FVAL * ( CONST1 - LOG(X) )
            ENDIF
            K0INT = FVAL
         ELSE
            T = ( ( X * X ) / EIGHTN - HALF ) - HALF
            FVAL = ( CONST2 + LOG(X) ) * CHEVAL(NTERM2,AK0IN2,T)
            K0INT = X * ( CHEVAL(NTERM1,AK0IN1,T) - FVAL )
         ENDIF
!
!   Code for x > 6
!
      ELSE
         FVAL = PIBY2
         IF ( X .LT. XHIGH ) THEN
            T = ( TWELVE / X - HALF ) - HALF
            TEMP = EXP(-X) * CHEVAL(NTERM3,AK0INA,T)
            FVAL = FVAL - TEMP / ( SQRT(X) * RT2BPI)
         ENDIF
         K0INT = FVAL
      ENDIF
      RETURN
      END FUNCTION K0INT
      SUBROUTINE KAPCDF(DX,DK,DH,DXI,DALPHA,DCDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE KAPPA DISTRIBUTION
!              WITH SHAPE PARAMETERS K AND H.
!              THE CDF FOR THE DISTRIBUTION IS
!
!              F(X) = [1 - H*[1 - k*(X - XI)/ALPHA]**(1/K)]**(1/H)
!
!                     X < XI + ALPHA*(1 - H**(-K)    IF K >  0
!                     X < INFINITY                   IF K <= 0
!
!                     X > XI + ALPHA*(1 - H**(-K))/K  IF H >  0
!                     X > XI ALPHA/K                  IF H <= 0, K <  0
!                     X > -INFINITY                   IF H <= 0, K >= 0
!
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                     --DK     = THE FIRST SHAPE PARAMETER
!                     --DH     = THE SECOND SHAPE PARAMETER
!                     --DXI    = THE LOCATION PARAMETER
!                     --DALPHA = THE SCALE PARAMETER
!     OUTPUT ARGUMENTS--DCDF   = THE DOUBLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE KAPPA DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--RANGE OF X DEPENDENT ON H AND K
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--HOSKING AND WALLIS (1997), "REGIONAL FREQUENCY
!                 ANALYSIS: xxx", CAMBRIDGE UNVERSITY PRESS,
!                 PP. 202-204.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2008/5
!     ORIGINAL VERSION--MAY       2008.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DK
      DOUBLE PRECISION DH
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DXI
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION CDFKAP
      EXTERNAL CDFKAP
!
      DOUBLE PRECISION PARA(4)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(DALPHA.LE.0.0D0)THEN
        WRITE(ICOUT,35)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DALPHA
        CALL DPWRST('XXX','BUG ')
        DCDF=0.0D0
        GO TO 9999
      ENDIF
   35 FORMAT('***** ERROR--THE THIRD ARGUMENT TO KAPCDF ',   &
             '(THE SCALE PARAMETER) IS NON-POSITIVE')
!
      DTERM1=DXI + DALPHA/DK
      IF(DK.GT.0.0D0 .AND. DX.GT.DTERM1)THEN
!CCCC   WRITE(ICOUT,5)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,6)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,46)DX
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,7)DTERM1
!CCCC   CALL DPWRST('XXX','BUG ')
        DCDF=1.0D0
        GO TO 9999
      ENDIF
!CCC5 FORMAT('***** ERROR--THE FIRST ARGUMENT TO KAPCDF IS ',
!CCCC1       '> XI + ALPHA/K')
!CCC6 FORMAT('      WHEN THE FIRST SHAPE PARAMETER (K) IS POSITIVE.')
!CCC7 FORMAT('      THE VALUE OF XI + ALPHA/K IS ',G15.7)
!
      DTERM1=DXI + DALPHA*(1.0D0 - DH**(-DK))/DK
      IF(DH.GT.0.0D0 .AND. DX.LT.DTERM1)THEN
!CCCC   WRITE(ICOUT,15)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,16)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,46)DX
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,17)DTERM1
!CCCC   CALL DPWRST('XXX','BUG ')
        DCDF=0.0D0
        GO TO 9999
      ENDIF
!CC15 FORMAT('***** ERROR--THE FIRST ARGUMENT TO KAPCDF IS ',
!CCCC1       '< XI + ALPHA*(1 - H**(-K))')
!CC16 FORMAT('      WHEN THE SECOND SHAPE PARAMETER (H) IS POSITIVE.')
!CC17 FORMAT('      THE VALUE OF XI + ALPHA*(1 - H**(-K))/K IS ',
!CCCC1       G15.7)
!
      DTERM1=DXI + DALPHA/DK
      IF(DH.LE.0.0D0 .AND. DK.GT.0.0D0 .AND. DX.LT.DTERM1)THEN
!CCCC   WRITE(ICOUT,25)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,26)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,27)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,46)DX
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,28)DTERM1
!CCCC   CALL DPWRST('XXX','BUG ')
        DCDF=0.0D0
        GO TO 9999
      ENDIF
!CC25 FORMAT('***** ERROR--THE FIRST ARGUMENT TO KAPCDF IS ',
!CCCC1       '< XI + ALPHA/K')
!CC26 FORMAT('      WHEN THE SECOND SHAPE PARAMETER (H) IS POSITIVE')
!CC27 FORMAT('      AND THE SECOND SHAPE PARAMETER (K) IS NEGATIVE.')
!CC28 FORMAT('      THE VALUE OF XI + ALPHA/K IS ',G15.7)
!
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
      PARA(1)=DXI
      PARA(2)=DALPHA
      PARA(3)=DK
      PARA(4)=DH
      DCDF=CDFKAP(DX,PARA)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE KAPCDF
      SUBROUTINE KAPML1(Y,N,   &
                        DTEMP1,XMOM,NMOM,   &
                        XMEAN,XSD,XVAR,XMIN,XMAX,   &
                        ALOCLM,SCALLM,SHA1LM,SHA2LM,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE L-MOMENTS ESTIMATES FOR THE
!              KAPPA DISTRIBUTION FOR THE RAW DATA CASE (I.E.,
!              NO CENSORING AND NO GROUPING).  THIS ROUTINE RETURNS ONLY
!              THE POINT ESTIMATES.
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!              PUT THIS IN A SEPARATE ROUTINE AS IT MAY BE CALLED
!              FROM MULTIPLE PLACES (DPMLKP WILL GENERATE THE OUTPUT
!              FOR THE KAPPA MLE COMMAND).
!
!     REFERENCE--FORTRAN CODE WRITTEN FOR INCLUSION IN IBM
!                RESEARCH REPORT RC20525, 'FORTRAN ROUTINES FOR
!                USE WITH THE METHOD OF L-MOMENTS, VERSION 3',
!                J. R. M. HOSKING, IBM RESEARCH DIVISION,
!                T. J. WATSON RESEARCH CENTER, YORKTOWN HEIGHTS
!                NEW YORK 10598, U.S.A., VERSION 3     AUGUST 1996
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/7
!     ORIGINAL VERSION--JULY      2010. EXTRACTED AS A SEPARATE
!                                       SUBROUTINE (FROM DPMLKP)
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DIMENSION Y(*)
      DOUBLE PRECISION DTEMP1(*)
      DOUBLE PRECISION XMOM(*)
      DOUBLE PRECISION XPAR(4)
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*40 IDIST
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='KAPM'
      ISUBN2='L1  '
      IERROR='NO'
      IWRITE='NO'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PML1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF KAPML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N
   52   FORMAT('IBUGA3,ISUBRO,N = ',A4,2X,A4,2X,I8)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               *******************************************
!               **  STEP 2--                             **
!               **  CARRY OUT CALCULATIONS               **
!               **  FOR KAPPA MLE ESTIMATE               **
!               *******************************************
!
      ISTEPN='2'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PML1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IDIST='KAPPA'
      ALOCLM=CPUMIN
      SCALLM=CPUMIN
      SHA1LM=CPUMIN
      SHA2LM=CPUMIN
!
      IFLAG=0
      CALL SUMRAW(Y,N,IDIST,IFLAG,   &
                  XMEAN,XVAR,XSD,XMIN,XMAX,   &
                  ISUBRO,IBUGA3,IERROR)
!
      CALL SORT(Y,N,Y)
      NMOM=4
      DO 2110 I=1,N
        DTEMP1(I)=DBLE(Y(I))
 2110 CONTINUE
      CALL SAMLMU(DTEMP1,N,XMOM,NMOM)
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PML1')THEN
        WRITE(ICOUT,2120)XMOM(1),XMOM(2),XMOM(3),XMOM(4)
 2120   FORMAT('XMOM(1),XMOM(2),XMOM(3),XMOM(4) = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      CALL PELKAP(XMOM,XPAR,IFAIL)
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MLKP')THEN
        WRITE(ICOUT,2130)XPAR(1),XPAR(2),XPAR(3),XPAR(4)
 2130   FORMAT('XPAR(1),XPAR(2),XPAR(3),XPAR(4) = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      IF(IFAIL.GE.1)GO TO 9000
!
      ALOCLM=REAL(XPAR(1))
      SCALLM=REAL(XPAR(2))
      SHA1LM=REAL(XPAR(3))
      SHA2LM=REAL(XPAR(4))
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'PML1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF KAPML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)N,XMEAN,XSD,XMIN,XMAX
 9013   FORMAT('N,XMEAN,XSD,XMIN,XMAX = ',I8,4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9017)SHA1LM,SHA2LM,SCALLM,ALOCLM
 9017   FORMAT('SHA1ML,SHA2ML,SCALML,ALOCML =  ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE KAPML1
      SUBROUTINE KAPPDF(DX,DK,DH,DXI,DALPHA,DPDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE KAPPA DISTRIBUTION
!              WITH SHAPE PARAMETERS K AND H.
!              THE PDF FOR THE KAPPA DISTRIBUTION IS
!
!              f(X;K,H,XI,ALPHA) =
!                  (1/ALPHA)*[1 - K*(X-XI)/ALPHA]**((1/K)-1)*
!                  [F(X;K,H,XI,ALPHA)]**(1-H)
!
!              WHERE F IS THE KAPPA CUMULATIVE DISTRIBUTION
!              FUNCTION.
!
!                     X < XI + ALPHA*(1 - H**(-K)    IF K >  0
!                     X < INFINITY                   IF K <= 0
!
!                     X > XI + ALPHA*(1 - H**(-K))/K  IF H >  0
!                     X > XI ALPHA/K                  IF H <= 0, K <  0
!                     X > -INFINITY                   IF H <= 0, K >= 0
!
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                     --DK     = THE FIRST SHAPE PARAMETER
!                     --DH     = THE SECOND SHAPE PARAMETER
!                     --DXI    = THE LOCATION PARAMETER
!                     --DALPHA = THE SCALE PARAMETER
!     OUTPUT ARGUMENTS--DPDF   = THE DOUBLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE KAPPA DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--RANGE OF X DEPENDENT ON H AND K
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--HOSKING AND WALLIS (1997), "REGIONAL FREQUENCY
!                 ANALYSIS: xxx", CAMBRIDGE UNVERSITY PRESS,
!                 PP. 202-204.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2008/5
!     ORIGINAL VERSION--MAY       2008.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DK
      DOUBLE PRECISION DH
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DXI
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION CDFKAP
      EXTERNAL CDFKAP
!
      DOUBLE PRECISION PARA(4)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(DALPHA.LE.0.0D0)THEN
        WRITE(ICOUT,35)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DALPHA
        CALL DPWRST('XXX','BUG ')
        DPDF=0.0D0
        GO TO 9999
      ENDIF
   35 FORMAT('***** ERROR--THE THIRD ARGUMENT TO KAPPDF ',   &
             '(THE SCALE PARAMETER) IS NON-POSITIVE')
!
      DTERM1=DXI + DALPHA/DK
      IF(DK.GT.0.0D0 .AND. DX.GT.DTERM1)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DX
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,7)DTERM1
        CALL DPWRST('XXX','BUG ')
        DPDF=0.0D0
        GO TO 9999
      ENDIF
    5 FORMAT('***** ERROR--THE FIRST ARGUMENT TO KAPPDF IS ',   &
             '> XI + ALPHA/K')
    6 FORMAT('      WHEN THE FIRST SHAPE PARAMETER (K) IS POSITIVE.')
    7 FORMAT('      THE VALUE OF XI + ALPHA/K IS ',G15.7)
!
      DTERM1=DXI + DALPHA*(1.0D0 - DH**(-DK))/DK
      IF(DH.GT.0.0D0 .AND. DX.LT.DTERM1)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,16)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DX
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,17)DTERM1
        CALL DPWRST('XXX','BUG ')
        DPDF=0.0D0
        GO TO 9999
      ENDIF
   15 FORMAT('***** ERROR--THE FIRST ARGUMENT TO KAPPDF IS ',   &
             '< XI + ALPHA*(1 - H**(-K))')
   16 FORMAT('      WHEN THE SECOND SHAPE PARAMETER (H) IS POSITIVE.')
   17 FORMAT('      THE VALUE OF XI + ALPHA*(1 - H**(-K))/K IS ',   &
             G15.7)
!
      DTERM1=DXI + DALPHA/DK
      IF(DH.LE.0.0D0 .AND. DK.GT.0.0D0 .AND. DX.LT.DTERM1)THEN
        WRITE(ICOUT,25)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,26)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,27)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DX
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,28)DTERM1
        CALL DPWRST('XXX','BUG ')
        DPDF=0.0D0
        GO TO 9999
      ENDIF
   25 FORMAT('***** ERROR--THE FIRST ARGUMENT TO KAPPDF IS ',   &
             '< XI + ALPHA/K')
   26 FORMAT('      WHEN THE SECOND SHAPE PARAMETER (H) IS POSITIVE')
   27 FORMAT('      AND THE SECOND SHAPE PARAMETER (K) IS NEGATIVE.')
   28 FORMAT('      THE VALUE OF XI + ALPHA/K IS ',G15.7)
!
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
      PARA(1)=DXI
      PARA(2)=DALPHA
      PARA(3)=DK
      PARA(4)=DH
      DTERM1=CDFKAP(DX,PARA)**(1.0D0 - DH)
      DTERM2=(1.0D0/DALPHA)*   &
             (1.0D0 - DK*(DX-DXI)/DALPHA)**((1.0D0/DK) - 1.0D0)
      DPDF=DTERM1*DTERM2
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE KAPPDF
      SUBROUTINE KAPPPF(DP,DK,DH,DXI,DALPHA,DPPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE KAPPA DISTRIBUTION
!              WITH SHAPE PARAMETERS K AND H.
!              THE PPF FOR THE DISTRIBUTION IS
!
!              G(P) = XI + (ALPHA/K)*{1 - ((1-P**H)/H)**K}
!                     0 < P < 1
!
!     INPUT  ARGUMENTS--DP     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --DK     = THE FIRST SHAPE PARAMETER
!                     --DH     = THE SECOND SHAPE PARAMETER
!                     --DXI    = THE LOCATION PARAMETER
!                     --DALPHA = THE SCALE PARAMETER
!     OUTPUT ARGUMENTS--DPPF   = THE DOUBLE PRECISION PERCENT POINT
!                                FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PERCENT POINT
!             FUNCTION VALUE PPF FOR THE KAPPA DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--0 < P < 1
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--HOSKING AND WALLIS (1997), "REGIONAL FREQUENCY
!                 ANALYSIS: xxx", CAMBRIDGE UNVERSITY PRESS,
!                 PP. 202-204.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2008/5
!     ORIGINAL VERSION--MAY       2008.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DP
      DOUBLE PRECISION DK
      DOUBLE PRECISION DH
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DXI
      DOUBLE PRECISION DPPF
      DOUBLE PRECISION QUAKAP
      EXTERNAL QUAKAP
!
      DOUBLE PRECISION PARA(4)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      DPPF=0.0D0
      IF(DALPHA.LE.0.0D0)THEN
        WRITE(ICOUT,25)
   25   FORMAT('***** ERROR--THE THIRD ARGUMENT TO KAPPPF ',   &
             '(THE SCALE PARAMETER) IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DALPHA
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(DK.GT.0.0D0)THEN
        IF(DP.GT.1.0D0)THEN
          WRITE(ICOUT,5)
    5     FORMAT('***** ERROR--THE FIRST ARGUMENT TO KAPPPF IS ',   &
                 'GREATER THAN 1.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)DP
          CALL DPWRST('XXX','BUG ')
          GO TO 9999
        ENDIF
      ELSE
        IF(DP.GE.1.0D0)THEN
          WRITE(ICOUT,6)
    6     FORMAT('***** ERROR--THE FIRST ARGUMENT TO KAPPPF IS ',   &
                 'GREATER THAN OR EQUAL TO 1.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)DP
          CALL DPWRST('XXX','BUG ')
          GO TO 9999
        ENDIF
      ENDIF
!
      IF(DH.GT.0.0D0)THEN
        IF(DP.LT.0.0D0)THEN
          WRITE(ICOUT,15)
   15     FORMAT('***** ERROR--THE FIRST ARGUMENT TO KAPPPF IS ',   &
                 'LESS THAN 0.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)DP
          CALL DPWRST('XXX','BUG ')
          GO TO 9999
        ENDIF
      ELSEIF(DH.LE.0.0D0 .AND. DK.LT.0.0D0)THEN
        IF(DP.LT.0.0D0)THEN
          WRITE(ICOUT,16)
   16     FORMAT('***** ERROR--THE FIRST ARGUMENT TO KAPPPF IS ',   &
                 'LESS THAN OR EQUAL TO 0.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)DP
          CALL DPWRST('XXX','BUG ')
          GO TO 9999
        ENDIF
      ELSEIF(DH.LE.0.0D0 .AND. DK.GT.0.0D0)THEN
        IF(DP.LE.0.0D0)THEN
          WRITE(ICOUT,16)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)DP
          CALL DPWRST('XXX','BUG ')
          GO TO 9999
        ENDIF
      ENDIF
!
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
      PARA(1)=DXI
      PARA(2)=DALPHA
      PARA(3)=DK
      PARA(4)=DH
      DPPF=QUAKAP(DP,PARA)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE KAPPPF
      SUBROUTINE KAPRAN(N,AK,H,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE KAPPA DISTRIBUTION WITH SHAPE PARAMETERS
!              K AND H.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE GENERATED.
!                     --K      = THE SINGLE PRECISION VALUE OF THE
!                                K SHAPE PARAMETER.
!                     --H      = THE SINGLE PRECISION VALUE OF THE
!                                H SHAPE PARAMETER.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N FROM THE KAPPA DISTRIBUTION
!             WITH SHAPE PARAMETERS K AND H.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN, QUAKAP.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2008.5
!     ORIGINAL VERSION--MAY       2008.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
      DOUBLE PRECISION DPPF
      DOUBLE PRECISION QUAKAP
      DOUBLE PRECISION PARA(4)
!
      EXTERNAL QUAKAP
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
    5 FORMAT('***** ERROR--THE REQUESTED NUMBER OF KAPPA ',   &
             'RANDOM NUMBERS IS NON-POSITIVE.')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N KAPPA DISTRIBUTION RANDOM NUMBERS USING THE
!     PERCENT POINT FUNCTION TRANSFORMATION METHOD.
!
      PARA(1)=0.0D0
      PARA(2)=1.0D0
      PARA(3)=DBLE(AK)
      PARA(4)=DBLE(H)
!
      DO 100 I=1,N
        DPPF=QUAKAP(DBLE(X(I)),PARA)
        X(I)=REAL(DPPF)
  100 CONTINUE
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE KAPRAN
      SUBROUTINE KATCDF(X,ALPHA,BETA,IKATDF,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE KATZ DISTRIBUTION WITH SHAPE
!              PARAMETERS ALPHA AND BETA.  THIS DISTRIBUTION IS
!              DEFINED FOR ALL NON-NEGATIVE INTEGERS  X >= 0.
!
!              THE KATZ DISTRIBUTION IS DEFINED BY THE
!              RELATIONSHIP
!                  p(X+1;ALPHA,BETA)/P(X;ALPHA,BETA) =
!                  (ALPHA + BETA*X)/(1 + X)
!                  X = 0, 1, 2, 3, ,...
!                  ALPHA > 0, BETA < 1
!
!              AND
!
!                  p(0;ALPHA,BETA) = (1-BETA)**(ALPHA/BETA)
!
!              THE CUMULATIVE DISTRIBUTION FUNCTION IS COMPUTED
!              FROM THE FOLLOWING RECURRENCE RELATION:
!
!              p(X+1;ALPHA,BETA) = {(ALPHA + BETA*X)/(1 + X)}*
!                                  p(X;ALPHA,BETA)
!
!     INPUT  ARGUMENTS--X      = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE A NON-NEGATIVE INTEGER.
!                     --ALPHA  = THE FIRST SHAPE PARAMETER
!                     --BETA   = THE SECOND SHAPE PARAMETER
!                     --IKATDF = SPECIFY WHICH PARAMETERIZATION
!                                OF THE KATZ DISTRIBUTION TO USE.
!     OUTPUT ARGUMENTS--CDF    = THE DOUBLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE DISTRIBUTION FUNCTION
!             VALUE CDF FOR THE KATZ DISTRIBUTION WITH
!             SHAPE PARAMETERS ALPHA AND BETA
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE A NON-NEGATIVE INTEGER
!                 --ALPHA > 0, BETA < 1
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KEMP, AND KOTZ (2005), "UNIVARIATE
!                 DISCRETE DISTRIBUTIONS", THIRD EDITION, WILEY,
!                 PP. 82-83.
!               --CONSUL AND FAMOYE (2006), "LAGRANGIAN PROBABILITY
!                 DISTRIBUTIONS", BIRKHAUSER, CHAPTER 12.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007/1
!     ORIGINAL VERSION--JANUARY   2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      IMPLICIT DOUBLE PRECISION (A-H, O-Z)
      REAL RESULT
      CHARACTER*4 IKATDF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IX=INT(X+0.5D0)
      IF(IX.LT.0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        CDF=0.0D0
        GO TO 9000
      ENDIF
    4 FORMAT('***** ERROR--THE FIRST ARGUMENT TO KATCDF IS LESS ',   &
      'THAN 0')
!
      IF(IKATDF.EQ.'DEFA')THEN
        IF(ALPHA.LE.0.0D0)THEN
          WRITE(ICOUT,15)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)ALPHA
          CALL DPWRST('XXX','BUG ')
          CDF=0.0D0
          GO TO 9000
        ENDIF
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO KATCDF IS ',   &
               'NON-POSITIVE.')
!
        IF(BETA.GE.1.0D0)THEN
          WRITE(ICOUT,25)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)BETA
          CALL DPWRST('XXX','BUG ')
          CDF=0.0D0
          GO TO 9000
        ENDIF
   25   FORMAT('***** ERROR--THE THIRD ARGUMENT TO KATCDF IS ',   &
               'GREATER THAN OR EQUAL TO 1.')
!
      ELSE
        DMU=ALPHA
        DNU=BETA
        IF(DMU.LE.0.0D0)THEN
          WRITE(ICOUT,15)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)DMU
          CALL DPWRST('XXX','BUG ')
          CDF=0.0D0
          GO TO 9000
        ENDIF
        ALPHA=DMU/(DNU+1.0D0)
        BETA=DNU/(DNU+1.0D0)
      ENDIF
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!     USE THE RECURRENCE RELATION (PAGE 243 OF CONSUL AND FAMOYE):
!
      IF(BETA.EQ.0.0D0)THEN
        CALL POICDF(REAL(IX),REAL(ALPHA),RESULT)
        CDF=DBLE(RESULT)
        GO TO 9000
      ENDIF
!
      CDF=(1.0D0 - BETA)**(ALPHA/BETA)
      IF(IX.EQ.0)GO TO 9000
      DPDFSV=CDF
!
      DO 100 I=1,IX
        DX=DBLE(I-1)
        DTERM1=ALPHA + BETA*DX
        IF(DTERM1.LE.0.0D0)THEN
          CDF=1.0D0
          GO TO 9000
        ELSE
          DTERM2=DLOG(DTERM1)
          DTERM3=DLOG(1.0D0 + DX)
          IF(DPDFSV.LE.0.0D0)THEN
            GO TO 9000
          ELSE
            DTERM4=DLOG(DPDFSV)
          ENDIF
!
          DPDF=DEXP(DTERM2 - DTERM3 + DTERM4)
          CDF=CDF + DPDF
          IF(CDF.GE.1.0D0)THEN
            CDF=1.0D0
            GO TO 9000
          ENDIF
          DPDFSV=DPDF
        ENDIF
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE KATCDF
      SUBROUTINE KATPDF(X,ALPHA,BETA,IKATDF,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY MASS
!              FUNCTION VALUE FOR THE KATZ DISTRIBUTION WITH SHAPE
!              PARAMETERS ALPHA AND BETA.  THIS DISTRIBUTION IS
!              DEFINED FOR ALL NON-NEGATIVE INTEGERS  X >= 0.
!
!              THE KATZ DISTRIBUTION IS DEFINED BY THE
!              RELATIONSHIP
!                  p(X+1;ALPHA,BETA)/P(X;ALPHA,BETA) =
!                  (ALPHA + BETA*X)/(1 + X)
!                  X = 0, 1, 2, 3, ,...
!                  ALPHA > 0, BETA < 1
!
!              AND
!
!                  p(0;ALPHA,BETA) = (1-BETA)**(ALPHA/BETA)
!
!              THE CUMULATIVE DISTRIBUTION FUNCTION IS COMPUTED
!              FROM THE FOLLOWING RECURRENCE RELATION:
!
!              p(X+1;ALPHA,BETA) = {(ALPHA + BETA*X)/(1 + X)}*
!                                  p(X;ALPHA,BETA)
!
!              WE USE THIS RECURRENCE RELATION TO COMPUTE THE
!              PROBABILITY MASS FUNCTION AS WELL.
!
!     INPUT  ARGUMENTS--X      = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY MASS
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE A NON-NEGATIVE INTEGER.
!                     --ALPHA  = THE FIRST SHAPE PARAMETER
!                     --BETA   = THE SECOND SHAPE PARAMETER
!                     --IKATDF = SPECIFY WHICH PARAMETERIZATION
!                                OF THE KATZ DISTRIBUTION TO USE.
!     OUTPUT ARGUMENTS--CDF    = THE DOUBLE PRECISION PROBABILITY
!                                MASS FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY MASS FUNCTION
!             VALUE PDF FOR THE KATZ DISTRIBUTION WITH
!             SHAPE PARAMETERS ALPHA AND BETA
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE A NON-NEGATIVE INTEGER
!                 --ALPHA > 0, BETA < 1
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KEMP, AND KOTZ (2005), "UNIVARIATE
!                 DISCRETE DISTRIBUTIONS", THIRD EDITION, WILEY,
!                 PP. 82-83.
!               --CONSUL AND FAMOYE (2006), "LAGRANGIAN PROBABILITY
!                 DISTRIBUTIONS", BIRKHAUSER, CHAPTER 12.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007/1
!     ORIGINAL VERSION--JANUARY   2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      IMPLICIT DOUBLE PRECISION (A-H, O-Z)
      REAL RESLT1
      REAL RESLT2
      CHARACTER*4 IKATDF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IX=INT(X+0.5D0)
      IF(IX.LT.0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        PDF=0.0D0
        GO TO 9000
      ENDIF
    4 FORMAT('***** ERROR--THE FIRST ARGUMENT TO KATPDF IS LESS ',   &
      'THAN 0')
!
      IF(IKATDF.EQ.'DEFA')THEN
        IF(ALPHA.LE.0.0D0)THEN
          WRITE(ICOUT,15)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)ALPHA
          CALL DPWRST('XXX','BUG ')
          PDF=0.0D0
          GO TO 9000
        ENDIF
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO KATPDF IS ',   &
               'NON-POSITIVE.')
!
        IF(BETA.GE.1.0D0)THEN
          WRITE(ICOUT,25)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)BETA
          CALL DPWRST('XXX','BUG ')
          PDF=0.0D0
          GO TO 9000
        ENDIF
   25   FORMAT('***** ERROR--THE THIRD ARGUMENT TO KATPDF IS ',   &
               'GREATER THAN OR EQUAL TO 1.')
!
      ELSE
        DMU=ALPHA
        DNU=BETA
        IF(DMU.LE.0.0D0)THEN
          WRITE(ICOUT,15)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)DMU
          CALL DPWRST('XXX','BUG ')
          PDF=0.0D0
          GO TO 9000
        ENDIF
        ALPHA=DMU/(DNU+1.0D0)
        BETA=DNU/(DNU+1.0D0)
      ENDIF
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!     USE THE RECURRENCE RELATION (PAGE 82 OF JOHNSON, KEMP, AND
!     KOTZ):
!
      IF(BETA.EQ.0.0D0)THEN
        CALL POICDF(REAL(IX),REAL(ALPHA),RESLT1)
        IF(IX.EQ.0)THEN
          PDF=DBLE(RESLT1)
        ELSE
          CALL POICDF(REAL(IX-1),REAL(ALPHA),RESLT2)
          PDF=DBLE(RESLT1-RESLT2)
        ENDIF
        GO TO 9000
      ENDIF
!
      CDF=(1.0D0 - BETA)**(ALPHA/BETA)
      IF(IX.EQ.0)THEN
        PDF=CDF
        GO TO 9000
      ENDIF
      DPDFSV=CDF
!
      DO 100 I=1,IX
        DX=DBLE(I-1)
        DTERM1=ALPHA + BETA*DX
        IF(DTERM1.LE.0.0D0)THEN
          PDF=0.0D0
          GO TO 9000
        ELSE
          DTERM2=DLOG(DTERM1)
          DTERM3=DLOG(1.0D0 + DX)
          IF(DPDFSV.LE.0.0D0)THEN
            PDF=0.0D0
            GO TO 9000
          ELSE
            DTERM4=DLOG(DPDFSV)
          ENDIF
!
          DPDF=DEXP(DTERM2 - DTERM3 + DTERM4)
          CDF=CDF + DPDF
          IF(CDF.GE.1.0D0)THEN
            PDF=0.0D0
            GO TO 9000
          ENDIF
          DPDFSV=DPDF
        ENDIF
  100 CONTINUE
      PDF=DPDF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE KATPDF
      SUBROUTINE KATPPF(P,ALPHA,BETA,IKATDF,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE KATZ DISTRIBUTION WITH SHAPE
!              PARAMETERS ALPHA AND BETA.  THIS DISTRIBUTION IS
!              DEFINED FOR ALL NON-NEGATIVE INTEGERS  X >= 0.
!
!              THE KATZ DISTRIBUTION IS DEFINED BY THE
!              RELATIONSHIP
!                  p(X+1;ALPHA,BETA)/P(X;ALPHA,BETA) =
!                  (ALPHA + BETA*X)/(1 + X)
!                  X = 0, 1, 2, 3, ,...
!                  ALPHA > 0, BETA < 1
!
!              AND
!
!                  p(0;ALPHA,BETA) = (1-BETA)**(ALPHA/BETA)
!
!              THE CUMULATIVE DISTRIBUTION FUNCTION IS COMPUTED
!              FROM THE FOLLOWING RECURRENCE RELATION:
!
!              p(X+1;ALPHA,BETA) = {(ALPHA + BETA*X)/(1 + X)}*
!                                  p(X;ALPHA,BETA)
!
!              THE PERCENT POINT FUNCTION IS COMPUTED BY
!              CALCULATING THE CDF FUNCTION UNTIL THE SPECIFIED
!              PROBABILITY IS OBTAINED.
!     INPUT  ARGUMENTS--P      = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                                0 <= P <= 1
!                     --ALPHA  = THE FIRST SHAPE PARAMETER
!                     --BETA   = THE SECOND SHAPE PARAMETER
!                     --IKATDF = SPECIFY WHICH PARAMETERIZATION
!                                OF THE KATZ DISTRIBUTION TO USE.
!     OUTPUT ARGUMENTS--PPF    = THE DOUBLE PRECISION PERCENT POINT
!                                FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PERCENT POINT FUNCTION
!             VALUE PPF FOR THE KATZ DISTRIBUTION WITH
!             SHAPE PARAMETERS ALPHA AND BETA
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--0 <= P <= 1 (BETA < 0)
!                   0 <= P < 1  (BETA >= 0)
!                 --ALPHA > 0, BETA < 1
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KEMP, AND KOTZ (2005), "UNIVARIATE
!                 DISCRETE DISTRIBUTIONS", THIRD EDITION, WILEY,
!                 PP. 82-83.
!               --CONSUL AND FAMOYE (2006), "LAGRANGIAN PROBABILITY
!                 DISTRIBUTIONS", BIRKHAUSER, CHAPTER 12.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007/1
!     ORIGINAL VERSION--JANUARY   2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      IMPLICIT DOUBLE PRECISION (A-H, O-Z)
      REAL RESULT
      CHARACTER*4 IKATDF
!
!-----COMMON----------------------------------------------------------
!
      REAL R1MACH
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(IKATDF.EQ.'DEFA')THEN
!
        IF(BETA.GE.0.0D0)THEN
          IF(P.LT.0.0D0 .OR. P.GE.1.0D0)THEN
            WRITE(ICOUT,4)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,46)P
            CALL DPWRST('XXX','BUG ')
            PPF=0.0D0
            GO TO 9000
          ENDIF
        ELSE
          IF(P.LT.0.0D0 .OR. P.GT.1.0D0)THEN
            WRITE(ICOUT,4)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,46)P
            CALL DPWRST('XXX','BUG ')
            PPF=0.0D0
            GO TO 9000
          ENDIF
        ENDIF
    4   FORMAT('***** ERROR--THE FIRST ARGUMENT TO KATPPF IS ',   &
               'OUTSIDE THE ALLOWABLE (0,1) INTERVAL)')
!
        IF(ALPHA.LE.0.0D0)THEN
          WRITE(ICOUT,15)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)ALPHA
          CALL DPWRST('XXX','BUG ')
          PPF=0.0D0
          GO TO 9000
        ENDIF
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO KATPPF IS ',   &
               'NON-POSITIVE.')
!
        IF(BETA.GE.1.0D0)THEN
          WRITE(ICOUT,25)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)BETA
          CALL DPWRST('XXX','BUG ')
          PPF=0.0D0
          GO TO 9000
        ENDIF
   25   FORMAT('***** ERROR--THE THIRD ARGUMENT TO KATPPF IS ',   &
               'GREATER THAN OR EQUAL TO 1.')
!
      ELSE
        IF(P.LT.0.0D0 .OR. P.GT.1.0D0)THEN
          WRITE(ICOUT,4)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)P
          CALL DPWRST('XXX','BUG ')
          PPF=0.0D0
          GO TO 9000
        ENDIF
        DMU=ALPHA
        DNU=BETA
        IF(DMU.LE.0.0D0)THEN
          WRITE(ICOUT,15)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,46)DMU
          CALL DPWRST('XXX','BUG ')
          PPF=0.0D0
          GO TO 9000
        ENDIF
        ALPHA=DMU/(DNU+1.0D0)
        BETA=DNU/(DNU+1.0D0)
      ENDIF
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!     USE THE RECURRENCE RELATION (PAGE 82 OF
!     JOHNSON, KEMP, AND KOTZ)
!
      IF(P.LE.0.0D0)THEN
        PPF=0.0D0
        GO TO 9000
      ENDIF
!
      IF(BETA.EQ.0.0D0)THEN
        CALL POIPPF(REAL(P),REAL(ALPHA),RESULT)
        PPF=DBLE(RESULT)
        GO TO 9000
      ENDIF
!
!     FOR BETA < 0, CHECK FOR MAXIMUM ALLOWABLE X
!     (ALPHA + BETA*X >= 0  => X <= ALPHA/ABS(BETA))
!
      IF(BETA.LT.0.0D0 .AND. P.GE.1.0D0)THEN
        IPPF=INT(ALPHA/ABS(BETA))
        PPF=DBLE(IPPF)
        GO TO 9000
      ENDIF
!
!     COMPUTE PDF FOR X = 0
!
      DEPS=1.0D-7
      CDF=(1.0D0 - BETA)**(ALPHA/BETA)
      IF(CDF.GE.P-DEPS)THEN
         PPF=0.0D0
         GO TO 9000
      ENDIF
      DPDFSV=CDF
      I=0
!
  100 CONTINUE
        I=I+1
        IF(DBLE(I).GE.DBLE(I1MACH(9)))THEN
          WRITE(ICOUT,55)
   55     FORMAT('***** ERROR--THE COMPUTED PERCENT POINT VALUE ',   &
                 'EXCEEDS THE LARGEST MACHINE INTEGER.')
          CALL DPWRST('XXX','BUG ')
          PPF=0.0
          GO TO 9000
        ENDIF
        DX=DBLE(I-1)
!
        DTERM1=ALPHA + BETA*DX
        IF(DTERM1.LE.0.0D0)THEN
          PPF=DX
          GO TO 9000
        ELSE
          DTERM2=DLOG(DTERM1)
          DTERM3=DLOG(1.0D0 + DX)
          IF(DPDFSV.LE.0.0D0)THEN
            PPF=DX
            GO TO 9000
          ELSE
            DTERM4=DLOG(DPDFSV)
          ENDIF
!
          DPDF=DEXP(DTERM2 - DTERM3 + DTERM4)
          CDF=CDF + DPDF
          IF(CDF.GE.P-DEPS)THEN
            PPF=DBLE(I)
            GO TO 9000
          ENDIF
          DPDFSV=DPDF
        ENDIF
      GO TO 100
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE KATPPF
      SUBROUTINE KATRAN(N,ALPHA,BETA,IKATDF,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE KATZ DISTRIBUTION WITH SHAPE PARAMETERS
!              ALPHA AND BETA.
!
!              THE KATZ DISTRIBUTION IS DEFINED BY THE
!              RELATIONSHIP
!                  p(X+1;ALPHA,BETA)/P(X;ALPHA,BETA) =
!                  (ALPHA + BETA*X)/(1 + X)
!                  X = 0, 1, 2, 3, ,...
!                  ALPHA > 0, BETA < 1
!
!              AND
!
!                  p(0;ALPHA,BETA) = (1-BETA)**(ALPHA/BETA)
!
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --A      = THE DOUBLE PRECISION VALUE
!                                OF THE FIRST SHAPE PARAMETER.
!                     --BETA   = THE DOUBLE PRECISION VALUE
!                                OF THE THIRD SHAPE PARAMETER.
!                     --IKATDF = SPECIFY WHICH PARAMETERIZATION
!                                OF THE KATZ DISTRIBUTION TO USE.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE KATZ DISTRIBUTION
!             WITH SHAPE PARAMETERS ALPHA AND BETA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --ALPHA > 0, BETA < 1
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN, LKPPF
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KEMP, AND KOTZ (2005), "UNIVARIATE
!                 DISCRETE DISTRIBUTIONS", THIRD EDITION, WILEY,
!                 PP. 82-83.
!               --CONSUL AND FAMOYE (2006), "LAGRANGIAN PROBABILITY
!                 DISTRIBUTIONS", BIRKHAUSER, CHAPTER 12.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007/1
!     ORIGINAL VERSION--JANUARY   2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION ALPHA
      DOUBLE PRECISION BETA
!
      CHARACTER*4 IKATDF
!
      DOUBLE PRECISION DPPF
!
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
    5 FORMAT('***** ERROR--THE REQUESTED NUMBER OF KATZ')
    6 FORMAT('      RANDOM NUMBERS IS NON-POSITIVE')
!
      IF(ALPHA.LE.0.0D0)THEN
        WRITE(ICOUT,11)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,12)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
   11 FORMAT('***** ERROR--THE ALPHA PARAMETER FOR THE KATZ')
   12 FORMAT('      RANDOM NUMBERS IS NON-POSITIVE.')
!
      IF(BETA.GE.1.0D0)THEN
        WRITE(ICOUT,21)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,22)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
   21 FORMAT('***** ERROR--THE BETA PARAMETER FOR THE KATZ')
   22 FORMAT('      RANDOM NUMBERS IS GREATER THAN OR EQUAL TO 1.')
!
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
!
!     GENERATE N KATZ DISTRIBUTION RANDOM NUMBERS USING
!     THE INVERSION METHOD.
!
      CALL UNIRAN(N,ISEED,X)
      DO 100 I=1,N
        ZTEMP=X(I)
        CALL KATPPF(DBLE(ZTEMP),ALPHA,BETA,IKATDF,DPPF)
        X(I)=REAL(DPPF)
  100 CONTINUE
!
 9999 CONTINUE
!
      RETURN
      END SUBROUTINE KATRAN
      SUBROUTINE KCONS(Y,X,XIDTEM,TEMP,TEMP3,NCELL,N,   &
                       IWRITE,YOUT,NUMSET,IBAL,AKCV,   &
                       ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE K CONSISTENCY STATISTIC
!              OF THE DATA IN THE INPUT VECTOR Y WITH LAB ID
!              VECTOR X.  THE K CONSISTENCY STATISTIC IS DEFINED AS:
!
!                 K(i) = SD(i)/Sr
!
!              WITH SD(i) DENOTING THE STANDARD DEVIATION OF
!              LAB i AND THE REPEATABILITY STANDARD DEVIATION,
!              RESPECTIVELY.  THE REPEATABILITY STANDARD
!              DEVIATION IS DEFINED AS:
!
!                 Sr = SQRT(SUM[i=1 to p][s(i)**2/p]
!
!              WITH
!                 p      = NUMBER OF LABS
!                 s(i)   = STANDARD DEVIATION OF GROUP i.
!
!              2024/04: THE 2023 VERSION OF THE E691 STANDARD UPDATED
!                       THE FORMULAS TO SUPPORT THE UNBALANCED CASE.
!                       SEE THE STANDARD FOR DETAILS.
!     INPUT  ARGUMENTS--Y      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --X      = THE SINGLE PRECISION VECTOR OF
!                                GROUP ID's.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR Y.
!     OUTPUT ARGUMENTS--YOUT   = THE SINGLE PRECISION VECTOR OF THE
!                                COMPUTED SAMPLE K CONSISTENCY
!                                STATISTIC.
!                     --NUMSET = THE INTEGER VALUE CONTAINING THE
!                                NUMBER OF GROUPS IN X
!     OUTPUT--THE COMPUTED SINGLE PRECISION VECTOR OF THE
!             SAMPLE K CONSISTENCY STATISTIC.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--SORT, DISTIN, SD.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--SQRT.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--"Standard Practice for Conducting an
!                 Interlaboratory Study to Determine the Precision
!                 of a Test Method", ASTM International,
!                 100 Barr Harbor Drive, PO BOX C700,
!                 West Conshohoceken, PA 19428-2959, USA.
!                 This document is in support of
!                 ASTM Standard E 691 - 99.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2005.2
!     ORIGINAL VERSION--FEBRUARY  2005.
!     UPDATED         --APRIL     2024. SUPPORT FOR UNBALANCED DATA
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBAL
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DSUM
!
      DIMENSION Y(*)
      DIMENSION X(*)
      DIMENSION YOUT(*)
      DIMENSION XIDTEM(*)
      DIMENSION TEMP(*)
      DIMENSION TEMP3(*)
      DIMENSION NCELL(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='KCON'
      ISUBN2='S   '
      IERROR='NO'
      IBAL='YES'
      AKCV=CPUMIN
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CONS')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF KCONS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N
   52   FORMAT('IBUGA3,ISUBRO,N = ',2(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,Y(I),X(I)
   56     FORMAT('I,Y(I),X(I) = ',I8,2E15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.LE.1)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN COMPUTING K CONSISTENCY STATISTIC--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS IN THE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,114)
  114   FORMAT('      VARIABLES FOR WHICH THE K CONSISTENCY ',   &
               'STATISTIC')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,115)
  115   FORMAT('      IS TO BE COMPUTED MUST BE 2 OR LARGER.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,116)
  116   FORMAT('      SUCH WAS NOT THE CASE HERE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ****************************************************
!               **  STEP 2--                                      **
!               **  COMPUTE THE K CONSISTENCY STATISTIC           **
!               ****************************************************
!
      IWRITE='OFF'
      CALL DISTIN(X,N,IWRITE,XIDTEM,NUMSET,IBUGA3,IERROR)
      CALL SORT(XIDTEM,NUMSET,XIDTEM)
!
      IF(NUMSET.LT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,192)
  192   FORMAT('      NUMBER OF LABS    NUMSET < 1')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!     2024/03: CHECK FOR UNBALANCED CASE AND PROCESS DIFFERENTLY IF
!              DETECTED
!
      DSUM=0.0D0
      J=0
      NHOLD=-1
      DO 1110 ISET1=1,NUMSET
        K=0
        DO 1130 I=1,N
          IF(XIDTEM(ISET1).EQ.X(I))THEN
            K=K+1
            TEMP(K)=Y(I)
          ENDIF
 1130   CONTINUE
        NTEMP=K
!
!       CHECK FOR UNBALANCED CASE
!
        IF(ISET1.EQ.1)THEN
          NHOLD=NTEMP
        ELSE
          IF(NTEMP.NE.NHOLD)GO TO 2000
        ENDIF
!
        CALL SD(TEMP,NTEMP,IWRITE,XSD,IBUGA3,IERROR)
        DSUM=DSUM + DBLE(XSD)**2
        YOUT(ISET1)=XSD
        NCELL(ISET1)=NTEMP
!
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CONS')THEN
          WRITE(ICOUT,1131)ISET1,XSD
 1131     FORMAT('***** GROUP ',I8,' SD = ',G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
 1110 CONTINUE
!
      XREP=REAL(DSQRT(DSUM/DBLE(NUMSET)))
      P=REAL(NUMSET)
      DO 1150 I=1,NUMSET
        YOUT(I)=YOUT(I)/XREP
!
!       COMPUTE THE CRITICAL VALUE
!
        ANI=REAL(NHOLD)
        IDF1=NHOLD-1
        IDF2=(NUMSET-1)*(NHOLD-1)
        ALP=0.995
        CALL FPPF(ALP,IDF1,IDF2,APPF)
        DENOM=1.0 + REAL(NUMSET-1)/APPF
        AKCV=SQRT(P/DENOM)
!
 1150 CONTINUE
!
      GO TO 9000
!
!     2024/03: UNBALANCED CASE
!
 2000 CONTINUE
!
      IBAL='NO'
!
!     DETERMINE CELL SIZES
!
      SUM=0.0
      DO 2110 ISET1=1,NUMSET
        K=0
        DO 2130 I=1,N
          IF(XIDTEM(ISET1).EQ.X(I))THEN
            K=K+1
            TEMP(K)=Y(I)
          ENDIF
 2130   CONTINUE
        NCELL(ISET1)=K
        IF(K.GT.1)THEN
          CALL SD(TEMP,K,IWRITE,XSD,IBUGA3,IERROR)
        ELSE
          XSD=0.0
        ENDIF
        TEMP3(ISET1)=XSD
 2110 CONTINUE
!
      P=REAL(NUMSET)
      AN=REAL(N)
      SUM3=0.0
      DO 2150 ISET1=1,NUMSET
        IINDX=ISET1
        AVAL=REAL(NCELL(IINDX))
        SDI=TEMP3(IINDX)
        SUM3=SUM3 + (AVAL-1.0)*SDI**2
        YOUT(ISET1)=SDI
!
!       COMPUTE THE CRITICAL VALUE
!
        ANI=REAL(NCELL(IINDX))
        PI=(AN-P)/(ANI-1.0)
        IDF1=NCELL(IINDX)-1
        IDF2=N-NUMSET-NCELL(IINDX)+1
        ALP=0.995
        CALL FPPF(ALP,IDF1,IDF2,APPF)
        DENOM=1.0 + ((PI-1.0)/APPF)
        AKCV=SQRT(PI/DENOM)
!
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CONS')THEN
          WRITE(ICOUT,2153)ISET1,IINDX,AVAL,TEMP3(IINDX)
 2153     FORMAT('ISET1,IINDX,AVAL,TEMP3(IINDX) = ',2I6,2G15.7)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2154)P,ANI,PI,APPF,AKCV,IDF1,IDF2
 2154     FORMAT('P,ANI,PI,APPF,AKCV,IDF1,IDF2 = ',5G15.7,2I8)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
 2150 CONTINUE
      XREP=SQRT(SUM3/REAL(N-NUMSET))
!
      DO 2160 ISET1=1,NUMSET
        YOUT(ISET1)=YOUT(ISET1)/XREP
 2160 CONTINUE
!
!
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'CONS')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF KCONS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGA3,ISUBRO,IERROR
 9012   FORMAT('IBUGA3,ISUBRO,IERROR = ',A4,2X,A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)N,NUMSET,XREP
 9013   FORMAT('N,NUMSET,XREP = ',2I8,G15.7)
        CALL DPWRST('XXX','BUG ')
        DO 9018 I=1,NUMSET
          WRITE(ICOUT,9019)I,YOUT(I)
 9019     FORMAT('I,YOUT(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
 9018   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE KCONS
      SUBROUTINE KCONS2(Y,X1,X2,XIDTEM,XIDTE2,   &
                        TEMP,TEMP2,TEMP3,TEMP4,TEMP5,ITEMP1,N,   &
                        IWRITE,YOUT,TAG,TAG2,CVAL,NOUT,IBAL,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE K CONSISTENCY STATISTIC
!              OF THE DATA IN THE INPUT VECTOR Y WITH LAB ID
!              VECTOR X.  THE K CONSISTENCY STATISTIC IS DEFINED AS:
!
!                 K(i) = SD(i)/Sr
!
!              WITH SD(i) DENOTING THE STANDARD DEVIATION OF
!              LAB i AND THE REPEATABILITY STANDARD DEVIATION,
!              RESPECTIVELY.  THE REPEATABILITY STANDARD
!              DEVIATION IS DEFINED AS:
!
!                 Sr = SQRT(SUM[i=1 to p][s(i)**2/p]
!
!              WITH
!                 p      = NUMBER OF LABS
!                 s(i)   = STANDARD DEVIATION OF GROUP i.
!
!              THE DISTINCTION BETWEEN KCONS AND KCONS2 IS THAT
!              KCONS IS USED TO COMPUTE THE K CONSISTENCY STATISTIC
!              FOR A SINGLE MATERIAL WHILE KCONS2 COMPUTES THE
!              K CONSISTENCY STATISTIC FOR MULTIPLE MATERIALS.
!
!              2024/04: E-691 WAS UPDATED TO SUPPORT UNBALANCED
!                       DATA.  REWRITE THIS ROUTINE TO CALL
!                       "KCONS" WHICH HAS BEEN UPDATED FOR UNBLANCED
!                       DATA.
!
!     INPUT  ARGUMENTS--Y      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --X1     = THE SINGLE PRECISION VECTOR OF
!                                GROUP ID's.
!                     --X2     = THE SINGLE PRECISION VECTOR OF
!                                MATERIAL ID's.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR Y.
!     OUTPUT ARGUMENTS--YOUT   = THE SINGLE PRECISION VECTOR OF THE
!                                COMPUTED SAMPLE K CONSISTENCY
!                                STATISTIC.
!                     --TAG    = THE SINGLE PRECISION VECTOR OF THE
!                                MATERIAL ID's.
!                     --TAG2   = THE SINGLE PRECISION VECTOR OF THE
!                                LAB ID's.
!                     --NOUT   = THE INTEGER VALUE CONTAINING THE
!                                NUMBER OF VALUES IN YOUT
!     OUTPUT--THE COMPUTED SINGLE PRECISION VECTOR OF THE
!             SAMPLE K CONSISTENCY STATISTIC.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--SORT, DISTIN, KCONS.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--"Standard Practice for Conducting an
!                 Interlaboratory Study to Determine the Precision
!                 of a Test Method", ASTM International,
!                 100 Barr Harbor Drive, PO BOX C700,
!                 West Conshohoceken, PA 19428-2959, USA.
!                 This document is in support of
!                 ASTM Standard E 691 - 99.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2005.2
!     ORIGINAL VERSION--FEBRUARY  2005.
!     UPDATED         --APRIL     2024. REWRITE TO USE KCONS
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBAL
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION X1(*)
      DIMENSION X2(*)
      DIMENSION YOUT(*)
      DIMENSION TAG(*)
      DIMENSION TAG2(*)
      DIMENSION CVAL(*)
      DIMENSION XIDTEM(*)
      DIMENSION XIDTE2(*)
      DIMENSION TEMP(*)
      DIMENSION TEMP2(*)
      DIMENSION TEMP3(*)
      DIMENSION TEMP4(*)
      DIMENSION TEMP5(*)
      DIMENSION ITEMP1(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='KCON'
      ISUBN2='S2  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'ONS2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF KCONS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N
   52   FORMAT('IBUGA3,ISUBRO,N = ',A4,1X,A4,1X,I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,Y(I),X1(I),X2(I)
   56     FORMAT('I,Y(I),X1(I),X2(I) = ',I8,3G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.LE.1)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN COMPUTING K CONSISTENCY STATISTIC--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS IN THE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,114)
  114   FORMAT('      VARIABLES FOR WHICH THE K CONSISTENCY ',   &
               'STATISTIC')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,115)
  115   FORMAT('      IS TO BE COMPUTED MUST BE 2 OR LARGER.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,116)
  116   FORMAT('      SUCH WAS NOT THE CASE HERE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ****************************************************
!               **  STEP 2--                                      **
!               **  COMPUTE THE K CONSISTENCY STATISTIC           **
!               ****************************************************
!
      IWRITE='OFF'
      CALL DISTIN(X2,N,IWRITE,XIDTE2,NUMSE2,IBUGA3,IERROR)
      CALL SORT(XIDTE2,NUMSE2,XIDTE2)
!
      IF(NUMSE2.LT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,194)
  194   FORMAT('      NUMBER OF MATERIALS IS LESS THAN 1.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      NOUT=0
      DO 1110 ISET2=1,NUMSE2
!
        K=0
        DO 1140 I=1,N
          IF(XIDTE2(ISET2).EQ.X2(I))THEN
            K=K+1
            TEMP(K)=Y(I)
            TEMP2(K)=X1(I)
          ENDIF
 1140   CONTINUE
        NTEMP=K
!
        IERROR='NO'
        CALL KCONS(TEMP,TEMP2,XIDTEM,TEMP3,TEMP4,ITEMP1,NTEMP,   &
                   IWRITE,TEMP5,NUMSET,IBAL,AKCV,   &
                   ISUBRO,IBUGA3,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
!
        DO 1160 I=1,NUMSET
          NOUT=NOUT+1
          YOUT(NOUT)=TEMP5(I)
          TAG(NOUT)=XIDTE2(ISET2)
          TAG2(NOUT)=XIDTEM(I)
          CVAL(NOUT)=AKCV
 1160   CONTINUE
!
 1110 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'ONS2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF KCONS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IERROR,NUMSE2
 9012   FORMAT('IERROR,NUMSE2 = ',A4,2X,I8)
        CALL DPWRST('XXX','BUG ')
        DO 9018 I=1,NOUT
          WRITE(ICOUT,9019)I,TAG2(I),TAG(I),YOUT(I),CVAL(I)
 9019     FORMAT('I,TAG2(I),TAG(I),YOUT(I),CVAL(I) = ',I8,4G15.7)
          CALL DPWRST('XXX','BUG ')
 9018   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE KCONS2
      SUBROUTINE KENTAU(X,Y,N,ICASAN,IKTATA,IWRITE,XTEMP,YTEMP,MAXNXT,   &
                        XYKTAU,KTAUA,KTAUB,KTAUC,   &
                        STATCD,PVAL,PVALLT,PVALUT,   &
                        CUTU90,CUTU95,CTU975,CUTU99,CTU995,   &
                        CUTL90,CUTL95,CTL975,CUTL99,CTL995,   &
                        IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE KENDALL'S TAU COEFFICIENT
!              BETWEEN THE 2 SETS OF DATA IN THE INPUT VECTORS X AND Y.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS
!                                WHICH CONSTITUTE THE FIRST SET
!                                OF DATA.
!                     --Y      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS
!                                WHICH CONSTITUTE THE SECOND SET
!                                OF DATA.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X, OR EQUIVALENTLY,
!                                THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR Y.
!     OUTPUT ARGUMENTS--XYKTAU = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED KENDALL'S TAU
!                                COEFFICIENT BETWEEN THE 2 SETS OF
!                                DATA IN THE INPUT VECTORS X AND Y.
!                                THIS SINGLE PRECISION VALUE
!                                WILL BE BETWEEN -1.0 AND 1.0
!                                (INCLUSIVELY).
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             KENDALL'S TAU BETWEEN THE 2 SETS
!             OF DATA IN THE INPUT VECTORS X AND Y.
!     OTHER DATAPAC   SUBROUTINES NEEDED--SORTC.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DSQRT.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--W. J. CONOVER, "PRACTICAL NON-PARAMETRIC
!                 STATISTICS", THIRD EDITION, WILEY, 1999,
!                 PP. 318-322.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004/10
!     ORIGINAL VERSION--OCTOBER   2004.
!     UPDATED         --FEBRUARY  2013. RETURN CRITICAL VALUES FOR
!                                       SMALL SAMPLES, CDF/PVALUES
!                                       FOR LARGE SAMPLES
!     UPDATED         --AUGUST    2019. SUPPORT SOME DIFFERENT
!                                       FORMULATIONS OF KENDALL'S TAU
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASAN
      CHARACTER*4 IKTATA
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION Y(*)
!
      DIMENSION XTEMP(*)
      DIMENSION YTEMP(*)
!
      DIMENSION WP900(60)
      DIMENSION WP950(60)
      DIMENSION WP975(60)
      DIMENSION WP990(60)
      DIMENSION WP995(60)
!
      REAL KTAUA
      REAL KTAUB
      REAL KTAUC
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!     FOLLOWING VALUES ARE FROM TABLE A11 IN CONOVER.
!
      DATA WP900/   &
         0.0000, 0.0000, 0.0000, 0.6667, 0.6000, 0.4667, 0.4286, 0.3571,   &
         0.3333, 0.3333, 0.3091, 0.2727, 0.2821, 0.2527, 0.2571, 0.2333,   &
         0.2353, 0.2288, 0.2164, 0.2105, 0.2000, 0.1948, 0.1937, 0.1884,   &
         0.1867, 0.1815, 0.1738, 0.1746, 0.1675, 0.1678, 0.1613, 0.1613,   &
         0.1591, 0.1551, 0.1529, 0.1492, 0.1471, 0.1465, 0.1444, 0.1372,   &
         0.1390, 0.1382, 0.1362, 0.1353, 0.1333, 0.1304, 0.1304, 0.1277,   &
         0.1276, 0.1249, 0.1247, 0.1222, 0.1219, 0.1209, 0.1192, 0.1182,   &
         0.1165, 0.1155, 0.1151, 0.1141/
!
      DATA WP950/   &
         0.0000, 0.0000, 0.0000, 0.6667, 0.6000, 0.6000, 0.5238, 0.5000,   &
         0.4444, 0.4222, 0.3818, 0.3636, 0.3333, 0.3407, 0.3143, 0.3000,   &
         0.2941, 0.2810, 0.2749, 0.2632, 0.2571, 0.2554, 0.2490, 0.2391,   &
         0.2333, 0.2308, 0.2251, 0.2222, 0.2167, 0.2138, 0.2086, 0.2056,   &
         0.2008, 0.1979, 0.1933, 0.1905, 0.1892, 0.1863, 0.1849, 0.1821,   &
         0.1780, 0.1754, 0.1739, 0.1712, 0.1697, 0.1671, 0.1656, 0.1649,   &
         0.1616, 0.1608, 0.1592, 0.1569, 0.1553, 0.1544, 0.1529, 0.1506,   &
         0.1504, 0.1482, 0.1467, 0.1458/
!
      DATA WP975/   &
         0.0000, 0.0000, 0.0000, 1.0000, 0.8000, 0.7333, 0.6190, 0.5714,   &
         0.5000, 0.4667, 0.4545, 0.4242, 0.4103, 0.3846, 0.3714, 0.3667,   &
         0.3529, 0.3333, 0.3216, 0.3158, 0.3048, 0.2987, 0.2885, 0.2826,   &
         0.2800, 0.2738, 0.2650, 0.2593, 0.2562, 0.2506, 0.2473, 0.2419,   &
         0.2386, 0.2335, 0.2303, 0.2286, 0.2252, 0.2205, 0.2173, 0.2154,   &
         0.2122, 0.2102, 0.2071, 0.2051, 0.2020, 0.2000, 0.1970, 0.1950,   &
         0.1939, 0.1902, 0.1890, 0.1870, 0.1858, 0.1838, 0.1811, 0.1792,   &
         0.1779, 0.1760, 0.1748, 0.1729/
!
      DATA WP990/   &
         0.0000, 0.0000, 0.0000, 1.0000, 0.8000, 0.7333, 0.7143, 0.6429,   &
         0.6111, 0.5556, 0.5273, 0.5152, 0.4872, 0.4505, 0.4476, 0.4167,   &
         0.4118, 0.3987, 0.3801, 0.3684, 0.3619, 0.3506, 0.3439, 0.3333,   &
         0.3267, 0.3231, 0.3162, 0.3069, 0.3054, 0.2966, 0.2903, 0.2863,   &
         0.2841, 0.2763, 0.2739, 0.2698, 0.2643, 0.2603, 0.2578, 0.2538,   &
         0.2512, 0.2474, 0.2447, 0.2410, 0.2383, 0.2367, 0.2340, 0.2305,   &
         0.2279, 0.2261, 0.2235, 0.2217, 0.2192, 0.2173, 0.2148, 0.2130,   &
         0.2105, 0.2087, 0.2075, 0.2056/
!
      DATA WP995/   &
         0.0000, 0.0000, 0.0000, 1.0000, 1.0000, 0.8667, 0.8095, 0.7143,   &
         0.6667, 0.6000, 0.5636, 0.5455, 0.5285, 0.4945, 0.4857, 0.4667,   &
         0.4559, 0.4379, 0.4269, 0.4105, 0.4000, 0.3853, 0.3834, 0.3696,   &
         0.3600, 0.3538, 0.3504, 0.3386, 0.3350, 0.3287, 0.3204, 0.3185,   &
         0.3106, 0.3084, 0.3008, 0.2984, 0.2943, 0.2888, 0.2848, 0.2821,   &
         0.2780, 0.2729, 0.2713, 0.2664, 0.2646, 0.2618, 0.2581, 0.2553,   &
         0.2517, 0.2490, 0.2471, 0.2443, 0.2424, 0.2397, 0.2377, 0.2351,   &
         0.2331, 0.2305, 0.2285, 0.2271/
!
!-----START POINT-----------------------------------------------------
!
!     2019/08: NOTE THAT THERE ARE SEVERAL ALTERNATIVE FORMULATIONS
!              OF KENDALL'S TAU IN THE LITERATURE.  OUR ORIGINAL
!              IMPLEMENTATION IS FROM CONOVER WHICH IS:
!
!                 K = (Nc - Nd)/(Nc + Nd)
!
!              WHERE Nc IS THE NUMBER OF CONCORDANT PAIRS AND Nd IS THE
!              NUMBER OF DISCORDANT PAIRS.  THIS IS ALSO CALLED THE
!              GOODMAN AND KRUSKAL GAMMA COEFFICIENT.
!
!              KENDALL'S ORIGINAL FORMULATION IS:
!
!                K = (Nc - Nd)/{N*(N-1)/2}
!
!              THIS IS ALSO REFERRED TO AS KENDALL'S TAU-A IN THE
!              LITERATURE.
!
!              THE DISTINCTION BETWEEN THE 2 STATISTICS IS THAT THE
!              CONOVER (GAMMA) FORMULATION TAKES TIES INTO ACCOUNT WHILE
!              KENDALL'S TAU-A DOES NOT.
!
!              THERE ARE SEVERAL ADDITIONAL VARIANTS.  THESE USE
!              (Nc - Nd) IN THE NUMERATOR, BUT USE DIFFERENT
!              DENOMINATORS.
!
      ISUBN1='KENT'
      ISUBN2='AU  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'NTAU')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF KENTAU--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)ICASAN,IBUGA3,N
   52   FORMAT('ICASAN,IBUGA3,N = ',2(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I),Y(I)
   56     FORMAT('I,X(I),Y(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
       ENDIF
!
!               ********************************************
!               **  COMPUTE RANK CORRELATION COEFFICIENT  **
!               ********************************************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.LT.1.OR.N.GT.MAXNXT)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN KENDALLS TAU--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE  RESPONSE ',   &
               'VARIABLES')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,115)MAXNXT
  115   FORMAT('      MUST BE BETWEEN 1 AND ',I8,' (INCLUSIVELY).')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,116)
  116   FORMAT('      SUCH WAS NOT THE CASE HERE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE NUMBER OF OBSERVATIONS   = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(N.EQ.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,121)
  121   FORMAT('***** WARNING IN KENDALLS TAU--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,123)
  123   FORMAT('      THE NUMBER OF PAIRS (N) HAS THE VALUE 1.')
        CALL DPWRST('XXX','BUG ')
        XYKTAU=1.0
        GO TO 9000
      ENDIF
!
!               *************************************************
!               **  STEP 2--                                   **
!               **  COMPUTE THE RANK CORRELATION COEFFICIENT.  **
!               *************************************************
!
      CALL DISTIN(X,N,IWRITE,XTEMP,NXD,IBUGA3,IERROR)
      CALL DISTIN(Y,N,IWRITE,YTEMP,NYD,IBUGA3,IERROR)
      M=MIN(NXD,NYD)
      AM=REAL(M)
!CCCC CALL SORTC(X,Y,N,XTEMP,YTEMP)
!
      ANC=0.0
      AND=0.0
      AN=REAL(N)
      DENOM1=(AN/2.0)*(AN-1.0)
      TX=0.0
      TY=0.0
      TXY=0.0
      ANC2=0.0
      AND2=0.0
      AN1=0.0
      AN2=0.0
!
      NM1=N-1
      DO 200 J=1,NM1
        M=J+1
        DO 300 I=M,N
          ANUM=Y(J) - Y(I)
          ADENOM=X(J) - X(I)
          IF(ADENOM.NE.0.0)THEN
            RATIO=ANUM/ADENOM
            IF(RATIO.GT.0.0)THEN
              ANC=ANC+1.0
              ANC2=ANC2+1.0
            ELSEIF(RATIO.LT.0.0)THEN
              AND=AND+1.0
              AND2=AND2+1.0
            ELSE
              ANC=ANC+0.5
              AND=AND+0.5
              TY=TY+1.0
            ENDIF
          ELSE
            IF(Y(I).NE.Y(J))THEN
              TX=TX+1.0
            ELSE
              TXY=TXY+1.0
            ENDIF
          ENDIF
  300   CONTINUE
  200 CONTINUE
      XYKTAU=(ANC-AND)/(ANC+AND)
!
!     KENDALL'S TAU-A
!
      KTAUA=(ANC-AND)/DENOM1
!
!     KENDALL'S TAU-B
!
      DENOM2=SQRT((ANC2+AND2+TX)*(ANC2+AND2+TY))
      KTAUB=(ANC2-AND2)/DENOM2
!
!     KENDALL'S TAU-C
!
      DENOM3=(AM-1.0)/AM
      DENOM3=DENOM3*AN*AN
      KTAUC=2.0*(ANC2-AND2)/DENOM3
!
!               *************************************************
!               **  STEP 2B--                                  **
!               **  NOW COMPUTE CDF, PVALUE, AND CRITICAL      **
!               **  VALUES.                                    **
!               *************************************************
!
!     USE TABLED CRITICAL VALUES FROM TABLE A11 FOR N <= 60.  OTHERWISE,
!     USE
!
!           W(p) = Z(p)*SQRT(N*(2*N+5))/(3*SQRT(N*(N-1)))
!
!     ONLY COMPUTE THESE FOR CONOVER DEFINITION OF KENDALL'S TAU.
!
      AN=REAL(N)
      ANUM=SQRT(2.0*(2.0*AN+5.0))
      DENOM=3.0*SQRT(AN*(AN-1.0))
      AFACT=ANUM/DENOM
      ATEMP=XYKTAU/AFACT
      CALL NORCDF(ATEMP,STATCD)
      PVALLT=STATCD
      PVALUT=1.0 - STATCD
      PVAL=2.0*MIN(PVALLT,PVALUT)
!
      IF(N.GT.60 .OR. IKTATA.EQ.'NORM')THEN
        P=0.90
        CALL NORPPF(P,CUTU90)
        P=0.95
        CALL NORPPF(P,CUTU95)
        P=0.975
        CALL NORPPF(P,CTU975)
        P=0.99
        CALL NORPPF(P,CUTU99)
        P=0.995
        CALL NORPPF(P,CTU995)
        CUTU90=AFACT*CUTU90
        CUTU95=AFACT*CUTU95
        CTU975=AFACT*CTU975
        CUTU99=AFACT*CUTU99
        CTU995=AFACT*CTU995
      ELSE
        CUTU90=WP900(N)
        CUTU95=WP950(N)
        CTU975=WP975(N)
        CUTU99=WP990(N)
        CTU995=WP995(N)
      ENDIF
      CUTL90=-CUTU90
      CUTL95=-CUTU95
      CTL975=-CTU975
      CUTL95=-CUTU95
      CUTL99=-CUTU99
      CTL995=-CTU995
!
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,811)N,XYKTAU
  811   FORMAT('THE KENDALLS TAU COEFFICIENT OF THE ',I8,   &
               ' OBSERVATIONS = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'NTAU')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF KENTAU--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IERROR,ANC,AND,XYKTAU
 9012   FORMAT('IERROR,ANC,AND,XYKTAU = ',A4,2X,3G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)KTAUA,KTAUB,KTAUC,TX,TY,TXY
 9014   FORMAT('KTAUA,KTAUB,KTAUC,TX,TY,TXY = ',6G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9016)ANC2,AND2,DENOM1,DENOM2,DENOM3,AM
 9016   FORMAT('ANC2,AND2,DENOM1,DENOM2,DENOM3,AM = ',6G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE KENTAU
      INTEGER FUNCTION KINDEX(N,I,J)
!
!     PURPOSE--FOR A SQUARE UPPER TRIANGULAR MATRIX WHERE WE DO NOT
!              INCLUDE THE DIAGONAL, IT CAN SAVE CONSIDERABLE SPACE
!              TO STORE THE DATA AS A ONE DIMENSIONAL VECTOR RATHER
!              AS A MATRIX.  GIVEN THE I-TH ROW AND J-TH COLUMN,
!              THIS FUNCTION RETURNS THE CORRESPONDING INDEX IN THE
!              ONE DIMENSIONAL ARRAY.  SPECIFICALLY,
!
!                  K = (N*(N-1)/2) - (N-I)**((N-I)-1)/2*J + J - I -1
!
!              WHERE N IS THE NUMBER OF ROWS, I IS THE ROW INDEX AND
!              J IS THE COLUMN INDEX.
!     INPUT  ARGUMENTS--N      = THE INTEGER SCALAR THAT SPECIFIES THE
!                                NUMBER OF ROWS/COLUMNS IN THE MATRIX.
!                     --I      = THE INTEGER SCALAR THAT SPECIFIES THE
!                                ROW INDEX OF THE MATRIX.
!                     --J      = THE INTEGER SCALAR THAT SPECIFIES THE
!                                COLUMN INDEX OF THE MATRIX.
!     OUTPUT--THE SINGLE PRECISION FUNCTION VALUE KINDEX.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--INTEGER.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2024.07
!     ORIGINAL VERSION--JULY      2024.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      KINDEX=-1
      IF(N.LT.1)GO TO 9000
      IF(I.GE.J)GO TO 9000
      IF(I.LT.1 .OR. I.GT.N)GO TO 9000
      IF(J.LT.1 .OR. J.GT.N)GO TO 9000
!
!     FORMULAS ARE FOR ZERO-BASED ARRAYS, SO SUBTRACT 1 TO
!     USE FOR ONe-BASE ARRAYS
!
      IT=I-1
      JT=J-1
      KINDEX=((2*N - 3 - IT)*IT/2) + JT
!
 9000 CONTINUE
      RETURN
      END FUNCTION KINDEX
      SUBROUTINE KLVNA(X,BER,BEI,GER,GEI,DER,DEI,HER,HEI)
!
!       ======================================================
!       Purpose: Compute Kelvin functions ber x, bei x, ker x
!                and kei x, and their derivatives  ( x > 0 )
!       Input :  x   --- Argument of Kelvin functions
!       Output:  BER --- ber x
!                BEI --- bei x
!                GER --- ker x
!                GEI --- kei x
!                DER --- ber'x
!                DEI --- bei'x
!                HER --- ker'x
!                HEI --- kei'x
!       ================================================
!
        IMPLICIT DOUBLE PRECISION (A-H,O-Z)
        PI=3.141592653589793D0
        EL=.5772156649015329D0
        EPS=1.0D-15
        IF (X.EQ.0.0D0) THEN
           BER=1.0D0
           BEI=0.0D0
           GER=1.0D+300
           GEI=-0.25D0*PI
           DER=0.0D0
           DEI=0.0D0
           HER=-1.0D+300
           HEI=0.0D0
           RETURN
        ENDIF
        X2=0.25D0*X*X
        X4=X2*X2
        IF (DABS(X).LT.10.0D0) THEN
           BER=1.0D0
           R=1.0D0
           DO 10 M=1,60
              R=-0.25D0*R/(M*M)/(2.0D0*M-1.0D0)**2*X4
              BER=BER+R
              IF (DABS(R).LT.DABS(BER)*EPS) GO TO 15
10         CONTINUE
15         BEI=X2
           R=X2
           DO 20 M=1,60
              R=-0.25D0*R/(M*M)/(2.0D0*M+1.0D0)**2*X4
              BEI=BEI+R
              IF (DABS(R).LT.DABS(BEI)*EPS) GO TO 25
20         CONTINUE
25         GER=-(DLOG(X/2.0D0)+EL)*BER+0.25D0*PI*BEI
           R=1.0D0
           GS=0.0D0
           DO 30 M=1,60
              R=-0.25D0*R/(M*M)/(2.0D0*M-1.0D0)**2*X4
              GS=GS+1.0D0/(2.0D0*M-1.0D0)+1.0D0/(2.0D0*M)
              GER=GER+R*GS
              IF (DABS(R*GS).LT.DABS(GER)*EPS) GO TO 35
30         CONTINUE
35         GEI=X2-(DLOG(X/2.0D0)+EL)*BEI-0.25D0*PI*BER
           R=X2
           GS=1.0D0
           DO 40 M=1,60
              R=-0.25D0*R/(M*M)/(2.0D0*M+1.0D0)**2*X4
              GS=GS+1.0D0/(2.0D0*M)+1.0D0/(2.0D0*M+1.0D0)
              GEI=GEI+R*GS
              IF (DABS(R*GS).LT.DABS(GEI)*EPS) GO TO 45
40         CONTINUE
45         DER=-0.25D0*X*X2
           R=DER
           DO 50 M=1,60
              R=-0.25D0*R/M/(M+1.0D0)/(2.0D0*M+1.0D0)**2*X4
              DER=DER+R
              IF (DABS(R).LT.DABS(DER)*EPS) GO TO 55
50         CONTINUE
55         DEI=0.5D0*X
           R=DEI
           DO 60 M=1,60
              R=-0.25D0*R/(M*M)/(2.D0*M-1.D0)/(2.D0*M+1.D0)*X4
              DEI=DEI+R
              IF (DABS(R).LT.DABS(DEI)*EPS) GO TO 65
60            CONTINUE
65         R=-0.25D0*X*X2
           GS=1.5D0
           HER=1.5D0*R-BER/X-(DLOG(X/2.D0)+EL)*DER+0.25*PI*DEI
           DO 70 M=1,60
              R=-0.25D0*R/M/(M+1.0D0)/(2.0D0*M+1.0D0)**2*X4
              GS=GS+1.0D0/(2*M+1.0D0)+1.0D0/(2*M+2.0D0)
              HER=HER+R*GS
              IF (DABS(R*GS).LT.DABS(HER)*EPS) GO TO 75
70         CONTINUE
75         R=0.5D0*X
           GS=1.0D0
           HEI=0.5D0*X-BEI/X-(DLOG(X/2.D0)+EL)*DEI-0.25*PI*DER
           DO 80 M=1,60
              R=-0.25D0*R/(M*M)/(2*M-1.0D0)/(2*M+1.0D0)*X4
              GS=GS+1.0D0/(2.0D0*M)+1.0D0/(2*M+1.0D0)
              HEI=HEI+R*GS
              IF (DABS(R*GS).LT.DABS(HEI)*EPS) RETURN
80         CONTINUE
        ELSE
           PP0=1.0D0
           PN0=1.0D0
           QP0=0.0D0
           QN0=0.0D0
           R0=1.0D0
           KM=18
           IF (DABS(X).GE.40.0) KM=10
           FAC=1.0D0
           DO 85 K=1,KM
              FAC=-FAC
              XT=0.25D0*K*PI-INT(0.125D0*K)*2.0D0*PI
              CS=COS(XT)
              SS=SIN(XT)
              R0=0.125D0*R0*(2.0D0*K-1.0D0)**2/K/X
              RC=R0*CS
              RS=R0*SS
              PP0=PP0+RC
              PN0=PN0+FAC*RC
              QP0=QP0+RS
              QN0=QN0+FAC*RS
85         CONTINUE
           XD=X/DSQRT(2.0D0)
           XE1=DEXP(XD)
           XE2=DEXP(-XD)
           XC1=1.D0/DSQRT(2.0D0*PI*X)
           XC2=DSQRT(.5D0*PI/X)
           CP0=DCOS(XD+0.125D0*PI)
           CN0=DCOS(XD-0.125D0*PI)
           SP0=DSIN(XD+0.125D0*PI)
           SN0=DSIN(XD-0.125D0*PI)
           GER=XC2*XE2*(PN0*CP0-QN0*SP0)
           GEI=XC2*XE2*(-PN0*SP0-QN0*CP0)
           BER=XC1*XE1*(PP0*CN0+QP0*SN0)-GEI/PI
           BEI=XC1*XE1*(PP0*SN0-QP0*CN0)+GER/PI
           PP1=1.0D0
           PN1=1.0D0
           QP1=0.0D0
           QN1=0.0D0
           R1=1.0D0
           FAC=1.0D0
           DO 90 K=1,KM
              FAC=-FAC
              XT=0.25D0*K*PI-INT(0.125D0*K)*2.0D0*PI
              CS=DCOS(XT)
              SS=DSIN(XT)
              R1=0.125D0*R1*(4.D0-(2.0D0*K-1.0D0)**2)/K/X
              RC=R1*CS
              RS=R1*SS
              PP1=PP1+FAC*RC
              PN1=PN1+RC
              QP1=QP1+FAC*RS
              QN1=QN1+RS
90         CONTINUE
           HER=XC2*XE2*(-PN1*CN0+QN1*SN0)
           HEI=XC2*XE2*(PN1*SN0+QN1*CN0)
           DER=XC1*XE1*(PP1*CP0+QP1*SP0)-HEI/PI
           DEI=XC1*XE1*(PP1*SP0-QP1*CP0)+HER/PI
        ENDIF
        RETURN
        END
      SUBROUTINE KROBOV( NDIM, MINVLS, MAXVLS, FUNCTN, ABSEPS, RELEPS,   &
                         ABSERR, FINEST, INFORM )
!
!  Automatic Multidimensional Integration Subroutine
!
!         AUTHOR: Alan Genz
!                 Department of Mathematics
!                 Washington State University
!                 Pulman, WA 99164-3113
!                 Email: AlanGenz@wsu.edu
!
!         Last Change: 4/15/98
!
!  KROBOV computes an approximation to the integral
!
!      1  1     1
!     I  I ... I       F(X)  dx(NDIM)...dx(2)dx(1)
!      0  0     0
!
!
!  KROBOV uses randomized Korobov rules. The primary references are
!  "Randomization of Number Theoretic Methods for Multiple Integration"
!   R. Cranley and T.N.L. Patterson, SIAM J Numer Anal, 13, pp. 904-14,
!  and
!   "Optimal Parameters for Multidimensional Integration",
!    P. Keast, SIAM J Numer Anal, 10, pp.831-838.
!
!**************  Parameters ********************************************
!***** Input parameters
!  NDIM    Number of variables, must exceed 1, but not exceed 40
!  MINVLS  Integer minimum number of function evaluations allowed.
!          MINVLS must not exceed MAXVLS.  If MINVLS < 0 then the
!          routine assumes a previous call has been made with
!          the same integrand and continues that calculation.
!  MAXVLS  Integer maximum number of function evaluations allowed.
!  FUNCTN  EXTERNALly declared user defined function to be integrated.
!          It must have parameters (NDIM,Z), where Z is a real array
!          of dimension NDIM.
!  ABSEPS  Required absolute accuracy.
!  RELEPS  Required relative accuracy.
!***** Output parameters
!  MINVLS  Actual number of function evaluations used.
!  ABSERR  Estimated absolute accuracy of FINEST.
!  FINEST  Estimated value of integral.
!  INFORM  INFORM = 0 for normal exit, when
!                     ABSERR <= MAX(ABSEPS, RELEPS*ABS(FINEST))
!                  and
!                     INTVLS <= MAXCLS.
!          INFORM = 1 If MAXVLS was too small to obtain the required
!          accuracy. In this case a value FINEST is returned with
!          estimated absolute accuracy ABSERR.
!***********************************************************************
      EXTERNAL FUNCTN
      INTEGER NDIM, MINVLS, MAXVLS, INFORM, NP, PLIM, NLIM,   &
              SAMPLS, I, INTVLS, MINSMP
      PARAMETER ( PLIM = 20, NLIM = 100, MINSMP = 6 )
      INTEGER C(PLIM,NLIM), P(PLIM)
      DOUBLE PRECISION FUNCTN, ABSEPS, RELEPS, FINEST, ABSERR, DIFINT,   &
             FINVAL, VARSQR, VAREST, VARPRD, VALUE
      DOUBLE PRECISION ALPHA(NLIM), X(NLIM), VK(NLIM), ONE
      PARAMETER ( ONE = 1 )
