!
      DIMENSION P1(0:4),P2(0:4),P3(0:4),P4(0:3),P5(0:3)
      DIMENSION Q1(0:4),Q2(0:4),Q3(0:4),Q4(0:3),Q5(0:3)
      DIMENSION A0(0:5),A1(1:3),A2(1:4)
                                                                                                                                  
      DATA (P1(I),I=0,4),(Q1(I),I=0,4)   &
      /-0.8949374280E+0, 0.4631783434E+0,-0.4053332915E-1,   &
        0.1580075560E-1,-0.3423874194E-2,   &
        1.0             , 0.1002930749E+0, 0.3575271633E-1,   &
       -0.1915882099E-2, 0.4811072364E-4/
                                                                                                                                  
      DATA (P2(I),I=0,4),(Q2(I),I=0,4)   &
      /-0.8933384046E+0, 0.1161296496E+0, 0.1200082940E+0,   &
        0.2185699725E-1, 0.2128892058E-2,   &
        1.0             , 0.4935531886E+0, 0.1066347067E+0,   &
        0.1250161833E-1, 0.5494243254E-3/
                                                                                                                                  
      DATA (P3(I),I=0,4),(Q3(I),I=0,4)   &
      /-0.8933322067E+0, 0.2339544896E+0, 0.8257653222E-1,   &
        0.1411226998E-1, 0.2892240953E-3,   &
        1.0             , 0.3616538408E+0, 0.6628026743E-1,   &
        0.4839298984E-2, 0.5248310361E-4/
                                                                                                                                  
      DATA (P4(I),I=0,3),(Q4(I),I=0,3)   &
      / 0.9358419425E+0, 0.6716831438E+2,-0.6765069077E+3,   &
        0.9026661865E+3,   &
        1.0             , 0.7752562854E+2,-0.5637811998E+3,   &
       -0.5513156752E+3/
                                                                                                                                  
      DATA (P5(I),I=0,3),(Q5(I),I=0,3)   &
      / 0.9489335583E+0, 0.5561246706E+3, 0.3208274617E+5,   &
       -0.4889926524E+5,   &
        1.0             , 0.6028275940E+3, 0.3716962017E+5,   &
        0.3686272898E+5/
                                                                                                                                  
      DATA (A0(I),I=0,5)   &
      /-0.4227843351E+0,-0.1544313298E+0, 0.4227843351E+0,   &
        0.3276496874E+1, 0.2043403138E+1,-0.8681296500E+1/
                                                                                                                                  
      DATA (A1(I),I=1,3)   &
      /-0.4583333333E+0, 0.6675347222E+0,-0.1641741416E+1/
                                                                                                                                  
      DATA (A2(I),I=1,4)   &
      /-0.1958333333E+1, 0.5563368056E+1,-0.2111352961E+2,   &
        0.1006946266E+3/
                                                                                                                                  
      V=X
      IF(V .LT. -4.5D0) THEN
       U=EXP(V+1.0)
       LANXM1=V-U*(1.0D0+(A2(1)+(A2(2)+(A2(3)+A2(4)*U)*U)*U)*U)/   &
                  (1.0D0+(A1(1)+(A1(2)+A1(3)*U)*U)*U)
      ELSEIF(V .LT. -2.0D0) THEN
       LANXM1=(P1(0)+(P1(1)+(P1(2)+(P1(3)+P1(4)*V)*V)*V)*V)/   &
              (Q1(0)+(Q1(1)+(Q1(2)+(Q1(3)+Q1(4)*V)*V)*V)*V)
      ELSEIF(V .LT. 2.0D0) THEN
       LANXM1=(P2(0)+(P2(1)+(P2(2)+(P2(3)+P2(4)*V)*V)*V)*V)/   &
              (Q2(0)+(Q2(1)+(Q2(2)+(Q2(3)+Q2(4)*V)*V)*V)*V)
      ELSEIF(V .LT. 10.0D0) THEN
       LANXM1=(P3(0)+(P3(1)+(P3(2)+(P3(3)+P3(4)*V)*V)*V)*V)/   &
              (Q3(0)+(Q3(1)+(Q3(2)+(Q3(3)+Q3(4)*V)*V)*V)*V)
      ELSEIF(V .LT. 40.0D0) THEN
       U=1.0D0/V
       LANXM1=LOG(V)*(P4(0)+(P4(1)+(P4(2)+P4(3)*U)*U)*U)/   &
                      (Q4(0)+(Q4(1)+(Q4(2)+Q4(3)*U)*U)*U)
      ELSEIF(V .LT. 200.0D0) THEN
       U=1.0D0/V
       LANXM1=LOG(V)*(P5(0)+(P5(1)+(P5(2)+P5(3)*U)*U)*U)/   &
                      (Q5(0)+(Q5(1)+(Q5(2)+Q5(3)*U)*U)*U)
      ELSE
       U=V-V*LOG(V)/(V+1.0D0)
       V=1.0D0/(U-U*(U+LOG(U)-V)/(U+1.0D0))
       U=-LOG(V)
       LANXM1=   &
          (U+A0(0)+(-U+A0(1)+(A0(2)*U+A0(3)+(A0(4)*U+A0(5))*V)*V)*V)   &
          /(1.0D0-(1.0D0-(A0(2)+A0(4)*V)*V)*V)
      ENDIF
      RETURN
      END FUNCTION LANXM1
