       -0.2171466507E+4, 0.7010168358E+4,   &
        1.0             , 0.1022487911E+3, 0.1377646350E+4,   &
        0.3699184961E+4, 0.4251315610E+4/
                                                                                                                                  
      DATA (P5(I),I=0,3),(Q5(I),I=0,3)   &
