       -0.7075963938E+5,   &
        1.0             , 0.3605950254E+3, 0.1392784158E+5,   &
       -0.1881680027E+5/
                                                                                                                                  
      DATA (A0(I),I=0,6)   &
      /-0.2043403138E+1,-0.8455686702E+0,-0.3088626596E+0,   &
        0.5821346754E+1, 0.4227843351E+0, 0.6552993748E+1,   &
       -0.1076714945E+2/
                                                                                                                                  
      DATA (A1(I),I=1,3)   &
      /-0.4583333333E+0, 0.6675347222E+0,-0.1641741416E+1/
                                                                                                                                  
      DATA (A2(I),I=0,3)   &
      /-0.1958333333E+1, 0.5563368056E+1,-0.2111352961E+2,   &
        0.1006946266E+3/
                                                                                                                                  
      DATA (A3(I),I=0,3)   &
      /-1.0             , 0.4458333333E+1,-0.2116753472E+2,   &
        0.1163674359E+3/
                                                                                                                                  
      V=X
      IF(V .LT. -4.5D0) THEN
       U=EXP(V+1.0D0)
       LANXM2=V**2-2.0D0*U**2*   &
              (V/U+A2(0)*V+A3(0)+(A2(1)*V+A3(1)+(A2(2)*V+A3(2)+   &
              (A2(3)*V+A3(3))*U)*U)*U)/   &
              (1.0D0+(A1(1)+(A1(2)+A1(3)*U)*U)*U)
      ELSEIF(V .LT. -2.0D0) THEN
       LANXM2=(P1(0)+(P1(1)+(P1(2)+(P1(3)+P1(4)*V)*V)*V)*V)/   &
              (Q1(0)+(Q1(1)+(Q1(2)+(Q1(3)+Q1(4)*V)*V)*V)*V)
      ELSEIF(V .LT. 2.0D0) THEN
       LANXM2=(P2(0)+(P2(1)+(P2(2)+(P2(3)+P2(4)*V)*V)*V)*V)/   &
              (Q2(0)+(Q2(1)+(Q2(2)+(Q2(3)+Q2(4)*V)*V)*V)*V)
      ELSEIF(V .LT. 5.0D0) THEN
       U=1.0D0/V
       LANXM2=V*(P3(0)+(P3(1)+(P3(2)+P3(3)*U)*U)*U)/   &
                (Q3(0)+(Q3(1)+(Q3(2)+Q3(3)*U)*U)*U)
      ELSEIF(V .LT. 50.0D0) THEN
       U=1.0D0/V
       LANXM2=V*(P4(0)+(P4(1)+(P4(2)+(P4(3)+P4(4)*U)*U)*U)*U)/   &
                (Q4(0)+(Q4(1)+(Q4(2)+(Q4(3)+Q4(4)*U)*U)*U)*U)
      ELSEIF(V .LT. 200.0D0) THEN
       U=1.0D0/V
       LANXM2=V*(P5(0)+(P5(1)+(P5(2)+P5(3)*U)*U)*U)/   &
                (Q5(0)+(Q5(1)+(Q5(2)+Q5(3)*U)*U)*U)
      ELSE
       U=V-V*LOG(V)/(V+1.0D0)
       V=1.0D0/(U-U*(U+LOG(U)-V)/(U+1.0D0))
       U=-LOG(V)
       LANXM2=(1.0D0/V+U**2+A0(0)+A0(1)*U+(-U**2+A0(2)*U+A0(3)+   &
         (A0(4)*U**2+A0(5)*U+A0(6))*V)*V)/(1.0D0-(1.0D0-A0(4)*V)*V)
      ENDIF
      RETURN
      END FUNCTION LANXM2
      Function lcmrnd(ix)
!
!  THIS FUNCTION USED BY THE "R250" RANDOM NUMBER GENERATOR
!
!     The minimal standard PRNG for 31 bit unsigned integers
!     designed with automatic overflow protection
!     uses ix as the seed value if it is greater than zero
!     otherwise it is ignored
      Integer*4 ix
      Integer*4 a, b, m, q, r
      Integer*4 hi, lo, test
      Integer*4 x
      SAVE x
      Parameter (a = 16807, b = 0, m = 2147483647)
      Parameter (q = 127773, r = 2836)
!
      If ( ix .gt. 0 ) x = ix
!
      hi = x / q
      lo = mod( x, q )
      test = a * lo - r * hi
      if ( test .gt. 0 ) then
          x = test
      else
          x = test + m
      endif
!
      lcmrnd = x
!
      return
      End
      SUBROUTINE LATCON(IA,IWIDTH,IB,IWIDT2,MAXWID,ISUBRO,IERROR)
!
!     PURPOSE--CONVERT DATAPLOT SPECIAL CHARACTERS (E.G., GREEK
!              CHARACTERS, SUBSCRIPTS, SUPERSCRIPTS, MATH SYMBOLS)
!              FROM DATAPLOT CODING TO COMPARABLE LATEX CODING.
!
!     INPUT  ARGUMENTS--IA     = INITIAL CHARACTER STRING
!                       IWIDTH = NUMBER OF CHARACTERS IN IA
!                       ISUBRO = BUG TRACE VARIABLE
!     OUTPUT ARGUMENTS--IB     = OUTPUT CHARACTER STRING
!                       IWIDT2 = NUMBER OF CHARACTERS IN IB
!                       IERROR = HOLLERITH VARIABLE
!
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/2
!     ORIGINAL VERSION--FEBRUARY  2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*(*) IA
      CHARACTER*(*) IB
!
      CHARACTER*4 ICASFL
      CHARACTER*4 IBASLC
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(ISUBRO.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF LATCON--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IWIDTH,MAXWID,ISUBRO,IERROR
   52   FORMAT('IWIDTH,MAXWID,ISUBRO,IERROR = ',I8,2X,I8,2X,A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)(IA(I:I),I=1,MIN(100,IWIDTH))
   53   FORMAT('(IA(I),I=1,IWIDTH) = ',100A1)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IBASLC=CHAR(92)
!
!               *****************************************************
!               **  THE FOLLOWING CODE WILL SEARCH FOR DATAPLOT'S  **
!               **  SPECIAL CHARACTER CODES AND CONVERT THEM TO    **
!               **  EQUIVALENT LATEX CODES.                        **
!               *****************************************************
!
!
!     UC()   = UPPER CASE
!     LC()   = LOWER CASE
!     MU()   = GREEK MU
!     NU()   = GREEK NU
!     XI()   = GREEK XI
!     PI()   = GREEK PI
!     LT()   = LESS THAN
!     GT()   = GREATER THAN
!     +-()   = + OR -
!     -+()   = - OR +
!     SP()   = SPACE
!     SUB()  = ENTER SUBSCRIPT MODE
!     SUP()  = ENTER SUPERSCRIPT MODE
!     ETA()  = GREEK ETA
!     RHO()  = GREEK RHO
!     TAU()  = GREEK TAU
!     PHI()  = GREEK PHI
!     CHI()  = GREEK CHI
!     PSI()  = GREEK PSI
!     DEL()  = VECTOR PRODUCT
!     UNSB() = LEAVE SUBSCRIPT MODE
!     UNSP() = LEAVE SUPERSCRIPT MODE
!     ALPH() = GREEK ALPHA
!     BETA() = GREEK BETA
!     GAMM() = GREEK GAMMA
!     DELT() = GREEK DELTA
!     EPSI() = GREEK EPSILON
!     ZETA() = GREEK ZETA
!     THET() = GREEK THETA
!     IOTA() = GREEK IOTA
!     KAPP() = GREEK KAPPA
!     LAMB() = GREEK LAMBDA
!     OMIC() = GREEK OMICON
!     SIGM() = GREEK SIGMA
!     UPSI() = GREEK UPSILON
!     OMEG() = GREEK OMEGA
!     PART() = PARTIAL DERIVATIVE
!     INTE() = INTEGRAL
!     CINT() = CIRCULAR INTEGRAL
!     SUMM() = SUMMATION
!     PROD() = PRODUCT
!     INFI() = INFINITY
!     TIME() = TIMES
!     DOTP() = DOT PRODUCT
!     DIVI() = DIVISION
!     LTEQ() = LESS THAN OR EQUAL TO
!     GTEQ() = GREATER THAN OR EQUAL TO
!     NOT=() = NOT EQUAL
!     APPR() = APPROXIMATELY EQUAL TO
!     EQUI() = EQUIVALENCE
!     VARI() = VARIES
!     TILD() = TILDE
!     CARA() = CARAT
!     PRIM() = PRIME
!     RADI() = RADICAL
!     LRAD() = LARGE RADICAL
!     SUBS() = SUBSET
!     SUPE() = SUPERSET
!     UNIO() = UNION
!     INTR() = INTERSECTION
!     ELEM() = IS AN ELEMENT OF
!     THEX() = THERE EXISTS
!     THFO() = THEREFORE
!     LAPO() = LEFT APOSTROPHE
!     RAPO() = RIGHT APOSTROPHE
!     LBRA() = LEFT BRACKET
!     RBRA() = RIGHT BRACKET
!     LCBR() = LEFT CURLY BRACKET
!     RCBR() = RIGHT CURLY BRACKET
!     LELB() = LEFT ELBOW
!     RELB() = RIGHT ELBOW
!     LACC() = LEFT ACCENT
!     BREV() = BREVE
!     RQUO() = RIGHT QUOTE
!     LQUO() = LEFT QUOTE
!     NASP() = NORMAL ASPIRATE    (NOT CURRENTLY SUPPORTED)
!     IASP() = INVERTED ASPIRATE  (NOT CURRENTLY SUPPORTED)
!     RARR() = RIGHT ARROW
!     LARR() = LEFT ARROW
!     UARR() = UP ARROW
!     DARR() = DOWN ARROW
!     PARA() = PARAGRAPH
!     DAGG() = DAGGER
!     DDAG() = DOUBLE DAGGER
!     VBAR() = VERTICAL BAR
!     DVBA() = DOUBLE VERTICAL BAR
!     LVBA() = LONG VERTICAL BAR
!     HBAR() = HORIZONTAL BAR
!     LHBA() = LONG HORIZONTAL BAR
!     DEGR() = DEGREE
!
      IWIDT2=0
      IB(1:MAXWID)=' '
      ICASFL='UPPE'
      ISUBFL=0
      ISUPFL=0
      NSKIP=0
!
      IF(IWIDTH.GE.4)THEN
        NTEMP=IWIDTH-3
        DO 100 I=1,NTEMP
!
          IF(ISUBRO.EQ.'TCON')THEN
            WRITE(ICOUT,151)I,IWIDT2,NSKIP,IA(I:I)
  151       FORMAT('I,IWIDT2,NSKIP,IA(I:I) = ',3I8,A1)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
          IF(NSKIP.GT.0)THEN
            NSKIP=NSKIP-1
            GO TO 100
          ENDIF
!
!         SET UPPER CASE FLAG
!
          IF((IA(I:I).EQ.'U'.OR.IA(I:I).EQ.'u') .AND.   &
             (IA(I+1:I+1).EQ.'C'.OR.IA(I+1:I+1).EQ.'c') .AND.   &
             IA(I+2:I+2).EQ.'(' .AND. IA(I+3:I+3).EQ.')')THEN
            ICASFL='UPPE'
            NSKIP=3
!
!         SET LOWER CASE FLAG
!
          ELSEIF((IA(I:I).EQ.'L'.OR.IA(I:I).EQ.'l') .AND.   &
             (IA(I+1:I+1).EQ.'C'.OR.IA(I+1:I+1).EQ.'c') .AND.   &
             IA(I+2:I+2).EQ.'(' .AND. IA(I+3:I+3).EQ.')')THEN
            ICASFL='UPPE'
            NSKIP=3
!
!         SET SPACE
!
          ELSEIF((IA(I:I).EQ.'S'.OR.IA(I:I).EQ.'s') .AND.   &
             (IA(I+1:I+1).EQ.'P'.OR.IA(I+1:I+1).EQ.'p') .AND.   &
             IA(I+2:I+2).EQ.'(' .AND. IA(I+3:I+3).EQ.')')THEN
            IWIDT2=IWIDT2+1
            IB(IWIDT2:IWIDT2)=' '
            NSKIP=3
!
