!CCCC1           (IA(I+1:I+1).EQ.'A'.OR.IA(I+1:I+1).EQ.'a') .AND.
!CCCC1           (IA(I+2:I+2).EQ.'R'.OR.IA(I+2:I+2).EQ.'r') .AND.
!CCCC1           (IA(I+3:I+3).EQ.'R'.OR.IA(I+3:I+3).EQ.'r') .AND.
!CCCC1           IA(I+4:I+4).EQ.'(' .AND. IA(I+5:I+5).EQ.')')THEN
!CCCC       IWIDT2=IWIDT2+1
!CCCC       NLAST=IWIDT2+9
!CCCC       IF(NLAST.GT.MAXWID)GO TO 8010
!CCCC       IB(IWIDT2:NLAST)='$ uparrow$'
!CCCC       IB(IWIDT2+1:IWIDT2+1)=IBASLC
!CCCC       IWIDT2=IWIDT2+9
!CCCC       NSKIP=5
!
!         SET DAGGER = $\dagger$
!
          ELSEIF(I.LE.IWIDTH-5.AND.   &
                 (IA(I:I).EQ.'D'.OR.IA(I:I).EQ.'d') .AND.   &
                 (IA(I+1:I+1).EQ.'A'.OR.IA(I+1:I+1).EQ.'a') .AND.   &
                 (IA(I+2:I+2).EQ.'G'.OR.IA(I+2:I+2).EQ.'g') .AND.   &
                 (IA(I+3:I+3).EQ.'G'.OR.IA(I+3:I+3).EQ.'g') .AND.   &
                 IA(I+4:I+4).EQ.'(' .AND. IA(I+5:I+5).EQ.')')THEN
            IWIDT2=IWIDT2+1
            NLAST=IWIDT2+8
            IF(NLAST.GT.MAXWID)GO TO 8010
            IB(IWIDT2:NLAST)='$ dagger$'
            IB(IWIDT2+1:IWIDT2+1)=IBASLC
            IWIDT2=IWIDT2+8
            NSKIP=5
!
!         SET DOUBLE DAGGER = $\ddagger$
!
          ELSEIF(I.LE.IWIDTH-5.AND.   &
                 (IA(I:I).EQ.'D'.OR.IA(I:I).EQ.'d') .AND.   &
                 (IA(I+1:I+1).EQ.'D'.OR.IA(I+1:I+1).EQ.'d') .AND.   &
                 (IA(I+2:I+2).EQ.'A'.OR.IA(I+2:I+2).EQ.'a') .AND.   &
                 (IA(I+3:I+3).EQ.'G'.OR.IA(I+3:I+3).EQ.'g') .AND.   &
                 IA(I+4:I+4).EQ.'(' .AND. IA(I+5:I+5).EQ.')')THEN
            IWIDT2=IWIDT2+1
            NLAST=IWIDT2+9
            IF(NLAST.GT.MAXWID)GO TO 8010
            IB(IWIDT2:NLAST)='$ ddagger$'
            IB(IWIDT2+1:IWIDT2+1)=IBASLC
            IWIDT2=IWIDT2+9
            NSKIP=5
!
!         SET VERTICAL BAR = $\mid$
!
          ELSEIF(I.LE.IWIDTH-5.AND.   &
                 (IA(I:I).EQ.'V'.OR.IA(I:I).EQ.'v') .AND.   &
                 (IA(I+1:I+1).EQ.'B'.OR.IA(I+1:I+1).EQ.'b') .AND.   &
                 (IA(I+2:I+2).EQ.'A'.OR.IA(I+2:I+2).EQ.'a') .AND.   &
                 (IA(I+3:I+3).EQ.'R'.OR.IA(I+3:I+3).EQ.'r') .AND.   &
                 IA(I+4:I+4).EQ.'(' .AND. IA(I+5:I+5).EQ.')')THEN
            IWIDT2=IWIDT2+1
            NLAST=IWIDT2+5
            IF(NLAST.GT.MAXWID)GO TO 8010
            IB(IWIDT2:NLAST)='$ mid$'
            IB(IWIDT2+1:IWIDT2+1)=IBASLC
            IWIDT2=IWIDT2+5
            NSKIP=5
!
!         SET LONG VERTICAL BAR = $\mid$
!
          ELSEIF(I.LE.IWIDTH-5.AND.   &
                 (IA(I:I).EQ.'L'.OR.IA(I:I).EQ.'l') .AND.   &
                 (IA(I+1:I+1).EQ.'V'.OR.IA(I+1:I+1).EQ.'v') .AND.   &
                 (IA(I+2:I+2).EQ.'B'.OR.IA(I+2:I+2).EQ.'b') .AND.   &
                 (IA(I+3:I+3).EQ.'A'.OR.IA(I+3:I+3).EQ.'a') .AND.   &
                 IA(I+4:I+4).EQ.'(' .AND. IA(I+5:I+5).EQ.')')THEN
            IWIDT2=IWIDT2+1
            NLAST=IWIDT2+5
            IF(NLAST.GT.MAXWID)GO TO 8010
            IB(IWIDT2:NLAST)='$ mid$'
            IB(IWIDT2+1:IWIDT2+1)=IBASLC
            IWIDT2=IWIDT2+5
            NSKIP=5
!
!         SET HORIZONTAL BAR = DON'T KNOW HOW TO DO THIS ONE
!
!CCCC     ELSEIF((IA(I:I).EQ.'H'.OR.IA(I:I).EQ.'h') .AND.
!CCCC1           (IA(I+1:I+1).EQ.'B'.OR.IA(I+1:I+1).EQ.'b') .AND.
!CCCC1           (IA(I+2:I+2).EQ.'A'.OR.IA(I+2:I+2).EQ.'a') .AND.
!CCCC1           (IA(I+3:I+3).EQ.'R'.OR.IA(I+3:I+3).EQ.'r') .AND.
!CCCC1           IA(I+4:I+4).EQ.'(' .AND. IA(I+5:I+5).EQ.')')THEN
!CCCC       IWIDT2=IWIDT2+1
!CCCC       NLAST=IWIDT2+5
!CCCC       IF(NLAST.GT.MAXWID)GO TO 8010
!CCCC       IB(IWIDT2:NLAST)='$ mid$'
!CCCC       IB(IWIDT2+1:IWIDT2+1)=IBASLC
!CCCC       IWIDT2=IWIDT2+5
!CCCC       NSKIP=5
!
!         SET LONG HORIZONTAL BAR = DON'T KNOW HOW TO DO THIS ONE
!
!CCCC     ELSEIF((IA(I:I).EQ.'L'.OR.IA(I:I).EQ.'l') .AND.
!CCCC1           (IA(I+1:I+1).EQ.'H'.OR.IA(I+1:I+1).EQ.'h') .AND.
!CCCC1           (IA(I+2:I+2).EQ.'B'.OR.IA(I+2:I+2).EQ.'b') .AND.
!CCCC1           (IA(I+3:I+3).EQ.'A'.OR.IA(I+3:I+3).EQ.'a') .AND.
!CCCC1           IA(I+4:I+4).EQ.'(' .AND. IA(I+5:I+5).EQ.')')THEN
!CCCC       IWIDT2=IWIDT2+1
!CCCC       NLAST=IWIDT2+5
!CCCC       IF(NLAST.GT.MAXWID)GO TO 8010
!CCCC       IB(IWIDT2:NLAST)='$ mid$'
!CCCC       IB(IWIDT2+1:IWIDT2+1)=IBASLC
!CCCC       IWIDT2=IWIDT2+5
!CCCC       NSKIP=5
!
!         SET DEGREE = $\deg$
!
          ELSEIF(I.LE.IWIDTH-5.AND.   &
                 (IA(I:I).EQ.'D'.OR.IA(I:I).EQ.'d') .AND.   &
                 (IA(I+1:I+1).EQ.'E'.OR.IA(I+1:I+1).EQ.'e') .AND.   &
                 (IA(I+2:I+2).EQ.'G'.OR.IA(I+2:I+2).EQ.'g') .AND.   &
                 (IA(I+3:I+3).EQ.'R'.OR.IA(I+3:I+3).EQ.'r') .AND.   &
                 IA(I+4:I+4).EQ.'(' .AND. IA(I+5:I+5).EQ.')')THEN
            IWIDT2=IWIDT2+1
            NLAST=IWIDT2+5
            IF(NLAST.GT.MAXWID)GO TO 8010
            IB(IWIDT2:NLAST)='$ deg$'
            IB(IWIDT2+1:IWIDT2+1)=IBASLC
            IWIDT2=IWIDT2+5
            NSKIP=5
          ELSE
            IWIDT2=IWIDT2+1
            IB(IWIDT2:IWIDT2)=IA(I:I)
          ENDIF
  100   CONTINUE
      ELSE
        DO 190 I=1,IWIDTH
          IWIDT2=IWIDT2+1
          IB(IWIDT2:IWIDT2)=IA(I:I)
  190   CONTINUE
        GO TO 9000
      ENDIF
!
      ISTRT=IWIDTH-2
      ISTRT=ISTRT+NSKIP
      IF(ISTRT.LE.IWIDTH)THEN
        DO 200 I=ISTRT,IWIDTH
          IWIDT2=IWIDT2+1
          IB(IWIDT2:IWIDT2)=IA(I:I)
  200   CONTINUE
      ENDIF
!
      IF(ISUBFL.GT.0)THEN
        DO 300 I=1,ISUBFL
          IWIDT2=IWIDT2+1
          IB(IWIDT2:IWIDT2+1)='}$'
          IWIDT2=IWIDT2+1
  300   CONTINUE
      ENDIF
!
      IF(ISUPFL.GT.0)THEN
        DO 400 I=1,ISUPFL
          IWIDT2=IWIDT2+1
          IB(IWIDT2:IWIDT2+1)='}$'
          IWIDT2=IWIDT2+1
  400   CONTINUE
      ENDIF
!
      GO TO 9000
!
 8010 CONTINUE
      WRITE(ICOUT,8011)
 8011 FORMAT('***** ERROR IN CONVERTING DATAPLOT SPECIAL ',   &
             'CHARACTERS TO EQUIVALENT LATEX--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8013)
 8013 FORMAT('      MAXIMUM NUMBER OF CHARACTERS, ',I5,',',   &
             'IN LATEX STRING EXCEEDED.')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(ISUBRO.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF LATCON--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IWIDTH,ISUBRO,IERROR
 9012   FORMAT('IWIDTH,ISUBRO,IERROR = ',I8,2X,A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)(IB(I:I),I=1,MIN(100,IWIDT2))
 9014   FORMAT('(IB(I:I),I=1,IWIDT2) = ',100A1)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE LATCON
      SUBROUTINE LBECDF(X,ALPHA,BETA,C,D,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE LOG-BETA DISTRIBUTION.
!              THE LOG-BETA CDF IS COMPUTED AS:
!
!              LBECDF(X;ALPHA,BETA,C,D) = BETCDF(Z;ALPHA,BETA,C,D)
!                                         0 < C <= X <= D
!                                         ALPHA, BETA > 0
!
!              WHERE
!
!                  Z = (LOG(X) - LOG(C)/(LOG(D) - LOG(C))
!
!              AND BETCDF IS THE BETA CUMULATIVE DISTRIBUTION
!              FUNCTION.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE POSITIVE.
!                     --ALPHA  = THE SINGLE PRECISION VALUE OF THE
!                                FIRST SHAPE PARAMETER
!                     --BETA   = THE SINGLE PRECISION VALUE OF THE
!                                SECOND SHAPE PARAMETER
!                     --C      = THE SINGLE PRECISION VALUE OF THE
!                                THIRD (LOWER LIMIT) SHAPE PARAMETER
!                     --D      = THE SINGLE PRECISION VALUE OF THE
!                                FOURTH (UPPER LIMIT) SHAPE PARAMETER
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE LOG-BETA DISTRIBUTION.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE > C.
!     OTHER DATAPAC   SUBROUTINES NEEDED--BETCDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--NADARAJAH AND GUPTA (2004).  "APPLICATIONS OF THE
!                 BETA DISTRIBUTION" in "HANDBOOK OF THE BETA
!                 DISTRIBUTION", EDITED BY GUPTA AND NADARAJAH,
!                 MARCEL-DEKKER, PP.100-102.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2899
!     ORIGINAL VERSION--MAY       2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-----------------
!
!-----COMMON--------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      CDF=0.0
!
      IF(ALPHA.LE.0.0)THEN
        WRITE(ICOUT,4)
    4   FORMAT('***** ERROR--THE FIRST SHAPE PARAMETER (ALPHA) TO ',   &
               'LBECDF IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(BETA.LE.0.0)THEN
        WRITE(ICOUT,5)
    5   FORMAT('***** ERROR--THE SECOND SHAPE PARAMETER (BETA) TO ',   &
             'LBECDF IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(C.LE.0.0)THEN
        WRITE(ICOUT,6)
    6   FORMAT('***** ERROR--THE LOWER LIMIT PARAMETER TO ',   &
               'LBECDF IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)C
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(X.LE.C)THEN
        CDF=0.0
!CCCC   WRITE(ICOUT,7)
!CCC7 FORMAT('***** ERROR--THE FIRST ARGUMENT TO LBECDF ',
!CCCC1       'IS LESS THAN THE LOWER LIMIT.')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,46)X
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,48)C
!CCCC   CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(D.LE.C)THEN
        WRITE(ICOUT,8)
    8   FORMAT('***** ERROR--THE UPPER LIMIT TO LBECDF ',   &
               'IS LESS THAN THE LOWER LIMIT.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,48)C
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,49)D
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(X.GE.D)THEN
!CCCC   WRITE(ICOUT,9)
!CCC9   FORMAT('***** ERROR--THE FIRST ARGUMENT TO LBECDF ',
!CCCC1         'IS GREATER THAN THE UPPER LIMIT.')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,46)X
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,49)D
!CCCC   CALL DPWRST('XXX','BUG ')
        CDF=1.0
        GO TO 9999
      ENDIF
!
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
   48 FORMAT('***** THE VALUE OF THE LOWER LIMIT IS ',G15.7)
   49 FORMAT('***** THE VALUE OF THE UPPER LIMIT IS ',G15.7)
!
!-----START POINT---------------------------------------------------
!
      CDF=0.0
      Z=(LOG(X) - LOG(C))/(LOG(D) - LOG(C))
      CALL BETCDF(Z,ALPHA,BETA,CDF)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE LBECDF
      SUBROUTINE LBEPDF(X,ALPHA,BETA,C,D,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE LOG-BETA DISTRIBUTION.
!              THE LOG-BETA PDF IS COMPUTED AS:
!
!              LBEPDF(X;ALPHA,BETA,C,D) = BETPDF(Z;ALPHA,BETA,C,D)
!                                         0 < C <= X <= D
!                                         ALPHA, BETA > 0
!
!              WHERE
!
!                  Z = (LOG(X) - LOG(C)/(LOG(D) - LOG(C))
!
!              AND BETPDF IS THE BETA PROBABILITY DENSITY
!              FUNCTION.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE POSITIVE.
!                     --ALPHA  = THE SINGLE PRECISION VALUE OF THE
!                                FIRST SHAPE PARAMETER
!                     --BETA   = THE SINGLE PRECISION VALUE OF THE
!                                SECOND SHAPE PARAMETER
!                     --C      = THE SINGLE PRECISION VALUE OF THE
!                                THIRD (LOWER LIMIT) SHAPE PARAMETER
!                     --D      = THE SINGLE PRECISION VALUE OF THE
!                                FOURTH (UPPER LIMIT) SHAPE PARAMETER
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE LOG-BETA DISTRIBUTION.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE > C.
!     OTHER DATAPAC   SUBROUTINES NEEDED--BETPDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--NADARAJAH AND GUPTA (2004).  "APPLICATIONS OF THE
!                 BETA DISTRIBUTION" in "HANDBOOK OF THE BETA
!                 DISTRIBUTION", EDITED BY GUPTA AND NADARAJAH,
!                 MARCEL-DEKKER, PP.100-102.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2899
!     ORIGINAL VERSION--MAY       2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-----------------
!
!-----COMMON--------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PDF=0.0
!
      IF(ALPHA.LE.0.0)THEN
        WRITE(ICOUT,4)
    4   FORMAT('***** ERROR--THE FIRST SHAPE PARAMETER (ALPHA) TO ',   &
               'LBEPDF IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(BETA.LE.0.0)THEN
        WRITE(ICOUT,5)
    5   FORMAT('***** ERROR--THE SECOND SHAPE PARAMETER (BETA) TO ',   &
               'LBEPDF IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(C.LE.0.0)THEN
        WRITE(ICOUT,6)
    6   FORMAT('***** ERROR--THE LOWER LIMIT PARAMETER TO ',   &
               'LBEPDF IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)C
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(X.LE.C)THEN
        WRITE(ICOUT,7)
    7   FORMAT('***** ERROR--THE FIRST ARGUMENT TO LBEPDF ',   &
               'IS LESS THAN THE LOWER LIMIT.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,48)C
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(D.LE.C)THEN
        WRITE(ICOUT,8)
    8   FORMAT('***** ERROR--THE UPPER LIMIT TO LBEPDF ',   &
               'IS LESS THAN THE LOWER LIMIT.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,48)C
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,49)D
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(X.GE.D)THEN
        WRITE(ICOUT,9)
    9   FORMAT('***** ERROR--THE FIRST ARGUMENT TO LBEPDF ',   &
               'IS GREATER THAN THE UPPER LIMIT.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,49)D
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
!
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
   48 FORMAT('***** THE VALUE OF THE LOWER LIMIT IS ',G15.7)
   49 FORMAT('***** THE VALUE OF THE UPPER LIMIT IS ',G15.7)
!
!-----START POINT---------------------------------------------------
!
      PDF=0.0
      Z=(LOG(X) - LOG(C))/(LOG(D) - LOG(C))
      CALL BETPDF(Z,ALPHA,BETA,PDF)
      PDF=PDF/(X*(LOG(D)-LOG(C)))
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE LBEPDF
      SUBROUTINE LBEPPF(P,ALPHA,BETA,C,D,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE LOG-BETA DISTRIBUTION.
!              THE LOG-BETA PPF IS COMPUTED AS:
!
!              LBEPPF(P;ALPHA,BETA,C,D) = EXP(LOG(C)+
!                    (LOG(D) - LOG(C))*BETPPF(P;ALPHA,BETA,C,D))
!                                         0 < C <= X <= D
!                                         ALPHA, BETA > 0
!
!              BETPPF IS THE BETA PERCENT POINT FUNCTION.
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --ALPHA  = THE SINGLE PRECISION VALUE OF THE
!                                FIRST SHAPE PARAMETER
!                     --BETA   = THE SINGLE PRECISION VALUE OF THE
!                                SECOND SHAPE PARAMETER
!                     --C      = THE SINGLE PRECISION VALUE OF THE
!                                THIRD (LOWER LIMIT) SHAPE PARAMETER
!                     --D      = THE SINGLE PRECISION VALUE OF THE
!                                FOURTH (UPPER LIMIT) SHAPE PARAMETER
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION PERCENT POINT
!                                FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT
!             FUNCTION VALUE CDF FOR THE LOG-BETA DISTRIBUTION.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--0 < P < 1, ALPHA, BETA, C > 0, D > C
!     OTHER DATAPAC   SUBROUTINES NEEDED--BETPPF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--NADARAJAH AND GUPTA (2004).  "APPLICATIONS OF THE
!                 BETA DISTRIBUTION" in "HANDBOOK OF THE BETA
!                 DISTRIBUTION", EDITED BY GUPTA AND NADARAJAH,
!                 MARCEL-DEKKER, PP.100-102.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2899
!     ORIGINAL VERSION--MAY       2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-----------------
!
!-----COMMON--------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PPF=0.0
!
      IF(ALPHA.LE.0.0)THEN
        WRITE(ICOUT,4)
    4   FORMAT('***** ERROR--THE FIRST SHAPE PARAMETER (ALPHA) TO ',   &
               'LBECDF IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)ALPHA
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(BETA.LE.0.0)THEN
        WRITE(ICOUT,5)
    5   FORMAT('***** ERROR--THE SECOND SHAPE PARAMETER (BETA) TO ',   &
               'LBECDF IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(C.LT.0.0)THEN
        WRITE(ICOUT,6)
    6   FORMAT('***** ERROR--THE LOWER LIMIT PARAMETER TO ',   &
               'LBECDF IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)C
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(D.LE.C)THEN
        WRITE(ICOUT,8)
    8   FORMAT('***** ERROR--THE UPPER LIMIT PARAMETER TO LBECDF ',   &
               'IS LESS THAN THE LOWER LIMIT.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,48)C
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,49)D
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(P.LE.0.0 .OR. P.GE.1.0)THEN
        WRITE(ICOUT,7)
    7   FORMAT('***** ERROR--THE FIRST ARGUMENT TO LBECDF ',   &
               'IS OUTSIDE THE (0,1) INTERVAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)P
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
!
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
   48 FORMAT('***** THE VALUE OF THE LOWER LIMIT IS ',G15.7)
   49 FORMAT('***** THE VALUE OF THE UPPER LIMIT IS ',G15.7)
!
!-----START POINT---------------------------------------------------
!
      PPF=0.0
      CALL BETPPF(P,ALPHA,BETA,PPF)
      PPF=EXP(LOG(C) + PPF*(LOG(D)-LOG(C)))
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE LBEPPF
      SUBROUTINE LBERAN(N,ALPHA,BETA,C,D,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE LOG-BETA DISTRIBUTION WITH SINGLE PRECISION
!              SHAPE PARAMETERS ALPHA AND BETA AND LOWER AND UPPER
!              LIMIT PARAMETERS C AND D.
!              THE LOG-BETA PDF IS COMPUTED AS:
!
!              LBEPDF(X;ALPHA,BETA,C,D) = BETPDF(Z;ALPHA,BETA,C,D)
!                                         0 < C <= X <= D
!                                         ALPHA, BETA > 0
!
!              WHERE
!
!                  Z = (LOG(X) - LOG(C)/(LOG(D) - LOG(C))
!
!              AND BETPDF IS THE BETA PROBABILITY DENSITY
!              FUNCTION.
!
!              LIKEWISE, LOG-BETA RANDOM NUMBERS ARE GENERATED
!              BY APPLYING THE APPROPRIATE TRANSFORMATION TO
!              BETA RANDOM NUMBERS.
!
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --ALPHA  = THE SINGLE PRECISION VALUE OF THE
!                                FIRST SHAPE PARAMETER
!                     --BETA   = THE SINGLE PRECISION VALUE OF THE
!                                SECOND SHAPE PARAMETER
!                     --C      = THE SINGLE PRECISION VALUE OF THE
!                                THIRD (LOWER LIMIT) SHAPE PARAMETER
!                     --D      = THE SINGLE PRECISION VALUE OF THE
!                                FOURTH (UPPER LIMIT) SHAPE PARAMETER
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE LOG-BETA DISTRIBUTION
!             WITH SHAPE PARAMETER VALUES ALPHA, BETA, C, AND D.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --ALPHA > 0
!                 --BETA > 0
!                 --C > 0
!                 --D > C
!     OTHER DATAPAC   SUBROUTINES NEEDED--BETRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--NADARAJAH AND GUPTA (2004).  "APPLICATIONS OF THE
!                 BETA DISTRIBUTION" in "HANDBOOK OF THE BETA
!                 DISTRIBUTION", EDITED BY GUPTA AND NADARAJAH,
!                 MARCEL-DEKKER, PP.100-102.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006.6
!     ORIGINAL VERSION--JUNE      2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
    5   FORMAT('***** ERROR--THE REQUESTED NUMBER OF LOG-BETA ',   &
               'RANDOM NUMBERS IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(ALPHA.LE.0.0)THEN
        WRITE(ICOUT,11)
   11   FORMAT('***** ERROR--THE ALPHA SHAPE PARAMETER ',   &
               'FOR LOG-BETA RANDOM NUMBERS IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(BETA.LE.0.0)THEN
        WRITE(ICOUT,12)
   12   FORMAT('***** ERROR--THE BETA SHAPE PARAMETER ',   &
               'FOR LOG-BETA RANDOM NUMBERS IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(C.LE.0.0)THEN
        WRITE(ICOUT,13)
   13   FORMAT('***** ERROR--THE LOWER LIMIT PARAMETER C ',   &
               'FOR LOG-BETA RANDOM NUMBERS IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)C
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(D.LE.C)THEN
        WRITE(ICOUT,16)
   16   FORMAT('***** ERROR--THE UPPER LIMIT PARAMETER D ',   &
               'FOR LOG-BETA RANDOM NUMBERS IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)C
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)D
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
!
      CALL BETRAN(N,ALPHA,BETA,ISEED,X)
      DO 100 I=1,N
        X(I)=EXP(LOG(C) + (LOG(D)-LOG(C))*X(I))
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE LBERAN
      SUBROUTINE LCTCDF(X,N,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE LEADS IN COIN TOSSING
!              DISTRIBUTION ON THE INTERVAL (0,N).
!              THIS DISTRIBUTION HAS MEAN = N/2
!              AND STANDARD DEVIATION = SQRT(N(N+1)/8)
!              THIS DISTRIBUTION HAS THE PROBABILITY
!              MASS FUNCTION:
!
!                P(X;N) = (2*X)!(2*N-2*X)!*2**(-2*N)/
!                         X!*X!*(N-X)!*(N-X)!
!                         X = 0, 1, ..., N
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                       N      = THE INTEGER VALUE THAT SPECIFIES
!                                THE MAXIMUM VALUE
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE BETWEEN 0 AND N, INCLUSIVELY.
!     OTHER DATAPAC   SUBROUTINES NEEDED--DLNGAMM.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON, KOTZ, AND KEMP (1992).  "UNIVARIATE
!                 DISCRETE DISTRIBUTIONS" SECOND EDITION,
!                 PAGES 274-275.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--JUNE      2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DN
      DOUBLE PRECISION DNUM
      DOUBLE PRECISION DENOM
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DLNGAM
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      CDF=0.0
!
      IF(N.LT.0)THEN
        WRITE(ICOUT,12)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
   12 FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO THE ',   &
             'LCTCDF SUBROUTINE IS LESS THAN 0.')
!
      IX=INT(X+0.5)
      IF(IX.LT.0 .OR. IX.GT.N)THEN
        WRITE(ICOUT,2)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)IX
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    2 FORMAT('***** ERROR--THE FIRST INPUT ARGUMENT TO THE ',   &
             'LCTCDF SUBROUTINE IS OUTSIDE THE (0,N) INTERVAL')
!
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
!
!-----START POINT-----------------------------------------------------
!
      DN=DBLE(N)
!
      DCDF=0.0D0
      DO 100 I=0,IX
        DX=DBLE(I)
        DNUM=DLNGAM(2.0D0*DX+1) + DLNGAM(2.0D0*DN-2.0D0*DX+1)   &
             -2.0D0*DN*DLOG(2.0D0)
        DENOM=2.0D0*(DLNGAM(DX+1.0D0) + DLNGAM(DN-DX+1))
        DPDF=DEXP(DNUM-DENOM)
        DCDF=DCDF + DPDF
  100 CONTINUE
      CDF=REAL(DCDF)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE LCTCDF
      SUBROUTINE LCTPDF(X,N,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE LEADS IN COIN TOSSING
!              DISTRIBUTION ON THE INTERVAL (0,N).
!              THIS DISTRIBUTION HAS MEAN = N/2
!              AND STANDARD DEVIATION = SQRT(N(N+1)/8)
!              THIS DISTRIBUTION HAS THE PROBABILITY
!              MASS FUNCTION:
!
!                P(X;N) = (2*X)!(2*N-2*X)!*2**(-2*N)/
!                         X!*X!*(N-X)!*(N-X)!
!                         X = 0, 1, ..., N
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                       N      = THE INTEGER VALUE THAT SPECIFIES
!                                THE MAXIMUM VALUE
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE BETWEEN 0 AND N, INCLUSIVELY.
!     OTHER DATAPAC   SUBROUTINES NEEDED--DLNGAMM.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON, KOTZ, AND KEMP (1992).  "UNIVARIATE
!                 DISCRETE DISTRIBUTIONS" SECOND EDITION,
!                 PAGES 274-275.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--JUNE      2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DN
      DOUBLE PRECISION DNUM
      DOUBLE PRECISION DENOM
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DLNGAM
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PDF=0.0
!
      IF(N.LT.0)THEN
        WRITE(ICOUT,12)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
   12 FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO THE ',   &
             'LCTPDF SUBROUTINE IS LESS THAN 0.')
!
      IX=INT(X+0.5)
      IF(IX.LT.0 .OR. IX.GT.N)THEN
        WRITE(ICOUT,2)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)IX
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    2 FORMAT('***** ERROR--THE FIRST INPUT ARGUMENT TO THE ',   &
             'LCTPDF SUBROUTINE IS OUTSIDE THE (0,N) INTERVAL')
!
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
!
!-----START POINT-----------------------------------------------------
!
      DX=DBLE(IX)
      DN=DBLE(N)
      DNUM=DLNGAM(2.0D0*DX+1) + DLNGAM(2.0D0*DN-2.0D0*DX+1)   &
           -2.0D0*DN*DLOG(2.0D0)
      DENOM=2.0D0*(DLNGAM(DX+1.0D0) + DLNGAM(DN-DX+1))
      DPDF=DEXP(DNUM-DENOM)
      PDF=REAL(DPDF)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE LCTPDF
      SUBROUTINE LCTPPF(P,N,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE LEADS IN COIN TOSSING
!              DISTRIBUTION ON THE INTERVAL (0,N).
!              THIS DISTRIBUTION HAS MEAN = N/2
!              AND STANDARD DEVIATION = SQRT(N(N+1)/8)
!              THIS DISTRIBUTION HAS THE PROBABILITY
!              MASS FUNCTION:
!
!                P(X;N) = (2*X)!(2*N-2*X)!*2**(-2*N)/
!                         X!*X!*(N-X)!*(N-X)!
!                         X = 0, 1, ..., N
!
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                       N      = THE INTEGER VALUE THAT SPECIFIES
!                                THE MAXIMUM VALUE
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION PERCENT POINT
!                                FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT
!             FUNCTION VALUE PPF.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--0 <= P <= 1
!     OTHER DATAPAC   SUBROUTINES NEEDED--DLNGAMM.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON, KOTZ, AND KEMP (1992).  "UNIVARIATE
!                 DISCRETE DISTRIBUTIONS" SECOND EDITION,
!                 PAGES 274-275.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--JUNE      2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DP
      DOUBLE PRECISION DX
      DOUBLE PRECISION DN
      DOUBLE PRECISION DNUM
      DOUBLE PRECISION DENOM
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DEPS
      DOUBLE PRECISION DLNGAM
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PPF=0.0
!
      IF(N.LT.0)THEN
        WRITE(ICOUT,12)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
   12 FORMAT('***** ERROR--THE SECOND ARGUMENT TO ',   &
             'LCTPPF IS LESS THAN 0.')
!
      IF(P.LT.0.0 .OR. P.GT.1.0)THEN
        WRITE(ICOUT,2)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)P
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    2 FORMAT('***** ERROR--THE FIRST ARGUMENT TO ',   &
             'LCTPPF IS OUTSIDE THE (0,1) INTERVAL')
!
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!-----START POINT-----------------------------------------------------
!
!     P = 0 AND P = 1 CASES
!
      IF(P.LE.0.0)THEN
        PPF=0.0
        GO TO 9000
      ELSEIF(P.GE.1.0)THEN
        PPF=REAL(N)
        GO TO 9000
      ENDIF
!
      DP=DBLE(P)
      DN=DBLE(N)
!
      DEPS=1.0D-7
      DCDF=0.0D0
      DO 100 I=0,N
        DX=DBLE(I)
        DNUM=DLNGAM(2.0D0*DX+1) + DLNGAM(2.0D0*DN-2.0D0*DX+1)   &
             -2.0D0*DN*DLOG(2.0D0)
        DENOM=2.0D0*(DLNGAM(DX+1.0D0) + DLNGAM(DN-DX+1))
        DPDF=DEXP(DNUM-DENOM)
        DCDF=DCDF + DPDF
!
        IF(DCDF.GE.DP-DEPS)THEN
          PPF=REAL(I)
          GO TO 9000
        ENDIF
!
  100 CONTINUE
!
      PPF=REAL(N)
      GO TO 9000
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE LCTPPF
      SUBROUTINE LCTRAN(N,NPAR,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE LEADS IN COIN TOSSING DISTRIBUTION
!              WITH SHAPE PARAMETERS NPAR.
!              THIS DISTRIBUTION IS DEFINED FOR
!              NON-NEGATIVE INTEGERS IN THE RANGE 0 TO NPAR.
!              THIS DISTRIBUTION HAS THE PROBABILITY FUNCTION
!
!                P(X;N) = (2*X)!(2*N-2*X)!*2**(-2*N)/
!                         X!*X!*(N-X)!*(N-X)!
!                         X = 0, 1, ..., N
!
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --NPAR   = THE INTEGER VALUE
!                                OF THE SHAPE PARAMETER.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE LEADS IN COIN TOSSING DISTRIBUTION
!             WITH SHAPE PARAMETERS N AND NPAR.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --NPAR > 0
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN, LCTPPF
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND KEMP (1992).  "UNIVARIATE
!                 DISCRETE DISTRIBUTIONS", SECOND EDITION,
!                 WILEY, PP. 242-244.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/6
!     ORIGINAL VERSION--JUNE      2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      INTEGER N
      INTEGER NPAR
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
!
      IF(NPAR.LE.0.0)THEN
        WRITE(ICOUT,12)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)NPAR
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
    5 FORMAT('***** ERROR--THE REQUESTED NUMBER OF ',   &
      'LEADS IN COIN TOSSING RANDOM NUMBERS IS NON-POSITIVE')
   12 FORMAT('***** ERROR--THE NPAR PARAMETER FOR THE ',   &
      'LEADS IN COIN TOSSING RANDOM NUMBERS IS NON-POSITIVE')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
!
! 100 CONTINUE
!
      CALL UNIRAN(N,ISEED,X)
      DO 100 I=1,N
        XTEMP=X(I)
        CALL LCTPPF(XTEMP,NPAR,PPF)
        X(I)=PPF
  100 CONTINUE
!
 9999 CONTINUE
!
      RETURN
      END SUBROUTINE LCTRAN
      SUBROUTINE LDECDF(X,ALPHA,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE LOG DOUBLE EXPONENTIAL
!              (LAPLACE) DISTRIBUTION.
!              THIS DISTRIBUTION IS DEFINED FOR ALL POSITIVE X AND
!              HAS THE CUMULATIVE DISTRIBUTION FUNCTION
!              F(X) = 0.5*X**ALPHA           0 < X < 1
!                   = 1.0 - 0.5*X**ALPHA     X >= 1
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                     --ALPHA  = THE SINLE PRECISION SHAPE PARAMETER
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--XX
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2899
!     ORIGINAL VERSION--SEPTEMBER 2001.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DCDF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS.
!     NO INPUT ARGUMENT ERRORS POSSIBLE
!     FOR THIS DISTRIBUTION.
!
      CDF=0.0
!
      IF(X.LE.0.0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** FATAL ERROR--THE FIRST INPUT ARGUMENT TO THE ',   &
               'LDECDF SUBROUTINE IS NON-POSITIVE *****')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(ALPHA.LE.0.0)THEN
        WRITE(ICOUT,25)
   25   FORMAT('***** FATAL ERROR--THE SECOND INPUT ARGUMENT TO THE ',   &
               'LDECDF SUBROUTINE IS NON-POSITIVE *****')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!-----START POINT-----------------------------------------------------
!
      DX=DBLE(X)
      DALPHA=DBLE(ALPHA)
!
      IF(X.LT.1.0)THEN
        DCDF=0.5D0*DX**DALPHA
      ELSE
        DCDF=1.0D0 - 0.5D0*DX**(-DALPHA)
      ENDIF
      CDF=REAL(DCDF)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE LDECDF
      SUBROUTINE LDEPDF(X,ALPHA,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE LOG DOUBLE EXPONENTIAL
!              (LAPLACE) DISTRIBUTION.
!              THIS DISTRIBUTION IS DEFINED FOR ALL POSITIVE X AND
!              HAS THE PROBABILITY DENSITY FUNCTION
!              F(X) = (ALPHA/2)*X**(ALPHA-1)   0 < X < 1
!                   = (ALPHA/2)*X**(-ALPHA-1)   X>= 1
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                     --ALPHA  = THE SINLE PRECISION SHAPE PARAMETER
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP, LOG.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--XX
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE:  301-975-2899
!     ORIGINAL VERSION--SEPTEMBER 2001.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DTWO
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DTERM
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS.
!
      PDF=0.0
!
      IF(X.LE.0.0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** FATAL ERROR--THE FIRST INPUT ARGUMENT TO THE ',   &
               'LDEPDF SUBROUTINE IS NON-POSITIVE *****')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(ALPHA.LE.0.0)THEN
        WRITE(ICOUT,25)
   25   FORMAT('***** FATAL ERROR--THE SECOND INPUT ARGUMENT TO THE ',   &
               'LDEPDF SUBROUTINE IS NON-POSITIVE *****')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!-----START POINT-----------------------------------------------------
!
      DX=DBLE(X)
      DALPHA=DBLE(ALPHA)
      DTWO=DLOG(2.0D0)
!
      IF(X.LT.1.0)THEN
        DTERM=DLOG(DALPHA) - DTWO + (DALPHA-1.0D0)*DLOG(DX)
        DPDF=DEXP(DTERM)
      ELSE
        DTERM=DLOG(DALPHA) - DTWO + (-DALPHA-1.0D0)*DLOG(DX)
        DPDF=DEXP(DTERM)
      ENDIF
      PDF=REAL(DPDF)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE LDEPDF
      SUBROUTINE LDEPPF(P,ALPHA,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE LOG DOUBLE EXPONENTIAL
!              (LAPLACE) DISTRIBUTION.
!              THIS DISTRIBUTION IS DEFINED FOR ALL POSITIVE X AND
!              HAS THE PERCENT POINT FUNCTION
!              G(P) = SQRT(2*P)
!              NOTE THAT THE PERCENT POINT FUNCTION OF A DISTRIBUTION
!              IS IDENTICALLY THE SAME AS THE INVERSE CUMULATIVE
!              DISTRIBUTION FUNCTION OF THE DISTRIBUTION.
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE
!                                (BETWEEN 0.0 AND 1.0)
!                                AT WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --ALPHA  = THE SINLE PRECISION SHAPE PARAMETER
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION PERCENT
!                                POINT FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT
!             FUNCTION VALUE PPF.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--P SHOULD BE BETWEEN 0.0 AND 1.0, EXCLUSIVELY.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--XX
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--2001/9
!     ORIGINAL VERSION--SEPTEMBER 2001.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DP
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DPPF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(P.LE.0.0.OR.P.GE.1.0)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    1 FORMAT('***** FATAL ERROR--THE 1ST INPUT ARGUMENT TO THE ',   &
      'LDEPPF SUBROUTINE IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
!
      IF(ALPHA.LE.0.0)THEN
        WRITE(ICOUT,25)
   25   FORMAT('***** FATAL ERROR--THE SECOND INPUT ARGUMENT TO THE ',   &
               'LDEPPF SUBROUTINE IS NON-POSITIVE *****')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      AONE=1.0
      DP=DBLE(P)
      DALPHA=DBLE(ALPHA)
      CALL LDECDF(AONE,ALPHA,CDF)
!
      IF(P.LT.CDF)THEN
        DPPF=(2.0D0*DP)**(1.0D0/DALPHA)
      ELSE
        DPPF=(2.0D0*(1.0D0-DP))**(-1.0D0/DALPHA)
      ENDIF
      PPF=REAL(DPPF)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE LDEPPF
      SUBROUTINE LDERAN(N,ALPHA,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE LOG DOUBLE EXPONENTIAL DISTRIBUTION
!              WITH TAIL LENGTH PARAMETER VALUE = ALPHA.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --ALPHA  = THE SINGLE PRECISION VALUE OF THE
!                                TAIL LENGTH PARAMETER.
!                                ALPHA SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE LOG DOUBLE EXPONENTIAL DISTRIBUTION
!             WITH TAIL LENGTH PARAMETER VALUE = ALPHA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --ALPHA SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--KOZUBOWSKI AND PODGORSKI, "LOG-LAPLACE
!                 DISTRIBUTIONS", PAPER DOWNLOADED FROM THEIR
!                 WEB SITE.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2001.10
!     ORIGINAL VERSION--OCTOBER   2001.
!     UPDATED         --MARCH     2006. COMPUTE RANDOM NUMBERS
!                                       AS RATIO OF UNIFORMS
!                                       NOTE: THIS SEEMS TO GENERATE
!                                       EXCESIVELY LARGE NUMBERS, SO
!                                       REVERT BACK TO PPF ALGORITHM
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION Y(2)
!
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DY1
      DOUBLE PRECISION DY2
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
      IF(ALPHA.LE.0.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    5 FORMAT('***** ERROR--THE REQUESTED NUMBER OF LOG DOUBLE ',   &
      'EXPONENTIAL RANDOM NUMBERS IS NON-POSITIVE.')
   15 FORMAT('***** ERROR--THE SHAPE PARAMETER FOR THE LOG DOUBLE',   &
      ' EXPONENTIAL RANDOM NUMBERS IS NON-POSITIVE.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,' *****')
!
!     GENERATE N LOG DOUBLE EXPONENTIAL DISTRIBUTION RANDOM NUMBERS
!     USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD.
!
!     NOTE 3/2006: LOG DOUBLE EXPONENTIAL CAN BE REPRESENTED AS
!                  U1**(1/ALPHA)/U2**(1/ALPHA)
!
!     RUNNING SOME SIMULATIONS SEEMS TO SHOW THAT THE RATIO OF
!     UNIFORM METHOD RESULTS IN SOME EXCESSIVELY LARGE RANDOM
!     NUMBERS.
!
      IALG=0
      IF(IALG.EQ.0)THEN
        CALL UNIRAN(N,ISEED,X)
        DO 100 I=1,N
          CALL LDEPPF(X(I),ALPHA,XTEMP)
          X(I)=XTEMP
  100   CONTINUE
      ELSE
        NTEMP=2
        DALPHA=DBLE(ALPHA)
        DO 200 I=1,N
          CALL UNIRAN(NTEMP,ISEED,Y)
          DY1=DBLE(Y(1))
          DY2=DBLE(Y(2))
          X(I)=REAL(DY1**(1.0D0/DALPHA)/DY2**(1.0D0/DALPHA))
  200   CONTINUE
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE LDERAN
      SUBROUTINE LEGNDR(X,AN,PN)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE LEGENDRE
!              POLYNOMIAL OF ORDER N.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION INPUT ARGUMENT
!                       AN     = THE SINGLE PRECISION VALUE FOR THE
!                                ORDER OF THE FUNCTION (SHOULD BE
!                                NON-NEGATIVE ORDER)
!     OUTPUT ARGUMENTS--PN    = THE SINGLE PRECISION VALUE OF THE
!                                LEGENDRE POLYNOMIAL.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE
!     MODE OF INTERNAL OPERATIONS--SOME DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--"HANDBOOK OF MATHEMATICAL FUNCTIONS, AMS 55",
!                 ABRAMOWITZ AND STEGUM.
!                 USE FOLLOWING RECURRENCE FORMULA:
!                    P(N+1) = X*P(N)+(N/N+1)*(X*P(N)-P(N-1))
!                 FIRST FEW TERMS ARE FROM TABLE 22.9 OF ABRAMOWITZ
!                 AND STEGUM.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--JULY       1995.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DN
      DOUBLE PRECISION DPN, DPN1, DPN2
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!CCCC IF(X.LT.-1.0.OR.X.GT.1.0)THEN
!CCCC   WRITE(ICOUT,4)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,46)X
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   GO TO 9999
!CCCC ENDIF
!CCC4 FORMAT('***** NON-FATAL DIAGNOSTIC--THE 1ST INPUT ARGUMENT ',
!CCCC1'TO THE LEGNDR SUBROUTINE IS OUTSIDE THE (-1,1) INTERVAL *****')
!CC46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
      N=INT(AN+0.5)
      IF(N.LT.0)THEN
        WRITE(ICOUT,6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
    6 FORMAT('***** NON-FATAL DIAGNOSTIC--THE 2ND INPUT ARGUMENT ',   &
      'TO THE LEGNDR SUBROUTINE IS NEGATIVE *****')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,' *****')
!
      DX=DBLE(X)
      DN=DBLE(N)
!
      IF(N.LE.0)THEN
        PN=1.0
      ELSEIF(N.EQ.1)THEN
        PN=X
      ELSEIF(N.EQ.2)THEN
        PN=1.5*X**2-0.5
      ELSEIF(N.EQ.3)THEN
        DPN=2.5D0*DX**3-1.5D0*DX
        PN=REAL(DPN)
      ELSE
        DPN1=2.5D0*DX**3-1.5D0*DX
        DPN2=1.5D0*DX**2-0.5D0
        DO 1000 I=4,N
          DN=DBLE(I)-1.0D0
          DPN=DX*DPN1+(DN/(DN+1.0D0))*(DX*DPN1-DPN2)
          DPN2=DPN1
          DPN1=DPN
 1000   CONTINUE
        PN=REAL(DPN)
      ENDIF
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE LEGNDR
      SUBROUTINE LEXCDF(X,BETA,CDF)
!
!     NOTE--LOGISTIC-EXPONENTIAL CDF IS:
!
!           F(X;ALPHA,BETA) = 1 - 1/[1 + EXP(ALPHA*X) -1)**BETA]
!                             X > 0; ALPHA, BETA > 0
!
!           WITH (1/ALPHA) DENOTING THE SCALE PARAMETER AND
!           BETA DENOTING THE SHAPE PARAMETER.
!
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCE--LEEMIS AND MCQUESTION (2008), "UNIVARIATE DISTRIBUTION
!                RELATIONSHIPS", THE AMERICAN STATISTICIAN, VOL. 62,
!                NO. 1, PP. 45-53.
!              --LAN AND LEEMIS (2007), "THE LOGISTIC-EXPONENTIAL
!                SURVIVAL DISTRIBUTION", TECHNICAL REPORT, THE
!                COLLEGE OF WILLIAM AND MARY, DEPARTMENT OF
!                MATHEMATICS.
!              --LAN AND LEEMIS (2008), "THE LOGISTIC-EXPONENTIAL
!                SURVIVAL DISTRIBUTION", NAVAL RESEARCH LOGISTICS,
!                VOL. xx, NO. xx, PP. xx.
!     VERSION NUMBER--2008/2
!     ORIGINAL VERSION--FEBRUARY  2008.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      CDF=0.0D0
!
      IF(BETA.LT.1.0D0)THEN
        IF(X.LT.0.0D0)THEN
          WRITE(ICOUT,106)
  106     FORMAT('***** WARNING--THE FIRST ARGUMENT TO LEXCDF IS ',   &
                 'NON-POSITIVE.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,102)X
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
        ENDIF
      ELSE
        IF(X.LT.0.0D0)THEN
          WRITE(ICOUT,101)
  101     FORMAT('***** WARNING--THE FIRST ARGUMENT TO LEXCDF IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,102)X
  102     FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
        ENDIF
      ENDIF
!
      IF(BETA.LE.0.0D0)THEN
        WRITE(ICOUT,301)
  301   FORMAT('***** ERROR--THE SECOND ARGUMENT TO LEXCDF IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,102)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(X.LE.0.0D0)THEN
        CDF=0.0D0
      ELSE
        CDF=1.0D0 - 1.0D0/(1.0D0 + (DEXP(X) - 1.0D0)**BETA)
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE LEXCDF
      SUBROUTINE LEXCHA(X,BETA,HAZ)
!
!     NOTE--LOGISTIC-EXPONENTIAL CUMULATIVE HAZARD IS:
!
!           H(X;ALPHA,BETA) = -LOG(1/[1 + EXP(ALPHA*X) -1)**BETA])
!                             X >= 0; ALPHA, BETA > 0
!
!           WITH (1/ALPHA) DENOTING THE SCALE PARAMETER AND
!           BETA DENOTING THE SHAPE PARAMETER.
!
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCE--LEEMIS AND MCQUESTION (2008), "UNIVARIATE DISTRIBUTION
!                RELATIONSHIPS", THE AMERICAN STATISTICIAN, VOL. 62,
!                NO. 1, PP. 45-53.
!              --LAN AND LEEMIS (2007), "THE LOGISTIC-EXPONENTIAL
!                SURVIVAL DISTRIBUTION", TECHNICAL REPORT, THE
!                COLLEGE OF WILLIAM AND MARY, DEPARTMENT OF
!                MATHEMATICS.
!              --LAN AND LEEMIS (2008), "THE LOGISTIC-EXPONENTIAL
!                SURVIVAL DISTRIBUTION", NAVAL RESEARCH LOGISTICS,
!                VOL. xx, NO. xx, PP. xx.
!     VERSION NUMBER--2008/2
!     ORIGINAL VERSION--FEBRUARY  2008.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      HAZ=0.0D0
!
      IF(BETA.LT.1.0D0)THEN
        IF(X.LT.0.0D0)THEN
          WRITE(ICOUT,106)
  106     FORMAT('***** WARNING--THE FIRST ARGUMENT TO LEXCHAZ IS ',   &
                 'NON-POSITIVE.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,102)X
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
        ENDIF
      ELSE
        IF(X.LT.0.0D0)THEN
          WRITE(ICOUT,101)
  101     FORMAT('***** WARNING--THE FIRST ARGUMENT TO LEXCHAZ IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,102)X
  102     FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
        ENDIF
      ENDIF
!
      IF(BETA.LE.0.0D0)THEN
        WRITE(ICOUT,301)
  301   FORMAT('***** ERROR--THE SECOND ARGUMENT TO LEXCHAZ IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,102)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      TERM1=1.0D0/(1.0D0 + (DEXP(X) - 1.0D0)**BETA)
      IF(TERM1.GT.0.0D0)THEN
        HAZ=-DLOG(TERM1)
      ELSE
        HAZ=0.0D0
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE LEXCHA
      SUBROUTINE LEXFUN (N, X, FVEC, IFLAG, XDATA, NOBS)
!
!     PURPOSE-THIS ROUTINE COMPUTES THE FUNCTIONS FOR THE
!             LOGISTIC-EXPONENTIAL MAXIMUM LIKELIHOOD EQUATIONS.
!
!             (N/BETA) + SUM[i=1 to N][LOG(EXP(ALPHA*X(i)) - 1) -
!             2*SUM[i=1 to N][(EXP(ALPHA*X(I) - 1)**BETA*
!             LOG(EXP(ALPHA*X(i)) -1)/{1 + (EXP(ALPHA*X(i)) - 1)**BETA}
!             = 0
!
!             (N/ALPHA) + SUM[i=1 to N][(BETA-1)*X(i)*EXP(ALPHA*X(i))/
!             (EXP(ALHA*X(i)) - 1) + SUM[i=1 to N][X(i)] -
!             2*SUM[i=1 to N][BETA*(EXP(ALPHA*X(I) - 1)**(BETA - 1)*
!             X9I)*EXP(ALPHA*X(i))/{1 + (EXP(ALPHA*X(i)) - 1)**BETA}
!             = 0
!
!             WHERE
!
!               BETA     = SHAPE PARAMETER
!               ALPHA    = SCALE PARAMETER
!
!             CALLED BY DNSQE ROUTINE FOR SOLVING SIMULTANEOUS
!             NONLINEAR EQUATIONS.  NOTE THAT THE CALLING SEQUENCE
!             DID NOT ACCOMODATE A DATA ARRAY (AND ASSCIATED NUMBER OF
!             OBSERVATIONS), SO THESE WERE ADDED TO THE CALL LIST.
!     EXAMPLE--LOGISTIC-EXPONENTIAL MAXIMUM LIKELIHOOD Y
!     REFERENCE--LEEMIS AND MCQUESTION (2008), "UNIVARIATE DISTRIBUTION
!                RELATIONSHIPS", THE AMERICAN STATISTICIAN, VOL. 62,
!                NO. 1, PP. 45-53.
!              --LAN AND LEEMIS (2007), "THE LOGISTIC-EXPONENTIAL
!                SURVIVAL DISTRIBUTION", TECHNICAL REPORT, THE
!                COLLEGE OF WILLIAM AND MARY, DEPARTMENT OF
!                MATHEMATICS.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2008/2
!     ORIGINAL VERSION--FEBRUARY  2008.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION X(*)
      DOUBLE PRECISION FVEC(*)
      REAL XDATA(*)
!
      DOUBLE PRECISION DBETA
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DN
      DOUBLE PRECISION DX
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DSUM3
      DOUBLE PRECISION DSUM4
      DOUBLE PRECISION DSUM5
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  COMPUTE SOME SUMS
!
      N=2
      IFLAG=0
!
      DN=DBLE(NOBS)
      DBETA=DBLE(X(1))
      DALPHA=DBLE(X(2))
!
      DTERM1=DN/DBETA
      DTERM2=DN/DALPHA
      DSUM1=0.0D0
      DSUM2=0.0D0
      DSUM3=0.0D0
      DSUM4=0.0D0
      DSUM5=0.0D0
!
      DO 200 I=1,NOBS
!
        DX=DBLE(XDATA(I))
        DTERM4=DEXP(DALPHA*DX)
        DTERM3=DTERM4 - 1.0D0
!
        DSUM1=DSUM1 + DLOG(DTERM3)
        DSUM2=DSUM2 + DTERM3**DBETA*DLOG(DTERM3)/(1.0D0 + DTERM3**DBETA)
        DSUM3=DSUM3 + (DBETA-1.0D0)*DX*DTERM4/DTERM3
        DSUM4=DSUM4 + DBETA*DTERM3**(DBETA-1.0D0)*DX*DTERM4/   &
              (1.0D0 + DTERM3**DBETA)
        DSUM5=DSUM5 + DX
!
  200 CONTINUE
!
      FVEC(1)=DTERM1 + DSUM1 - 2.0D0*DSUM2
      FVEC(2)=DTERM2 + DSUM3 + DSUM5 - 2.0D0*DSUM4
!
      RETURN
      END SUBROUTINE LEXFUN 
      SUBROUTINE LEXFU2 (N, X, FVEC, IFLAG, XDATA, NOBS)
!
!     PURPOSE-THIS ROUTINE COMPUTES THE FUNCTIONS FOR THE
!             STARTING VALUES OF THE LOGISTIC-EXPONENTIAL
!             MAXIMUM LIKELIHOOD EQUATIONS.
!
!             G(P1) = (1/ALPHA)*LOG(1 + (P1/(1 - P1)**(1/BETA))
!             G(P2) = (1/ALPHA)*LOG(1 + (P2/(1 - P2)**(1/BETA))
!
!             WHERE
!
!               BETA     = SHAPE PARAMETER
!               ALPHA    = SCALE PARAMETER
!
!             THAT IS, WE EQUATE TWO PERCENTILES OF THE DATA
!             (USUALLY 0.25 AND 0.75) WITH THE THEORETICAL
!             PERCENTILES.
!
!             CALLED BY DNSQE ROUTINE FOR SOLVING SIMULTANEOUS
!             NONLINEAR EQUATIONS.  NOTE THAT THE CALLING SEQUENCE
!             DID NOT ACCOMODATE A DATA ARRAY (AND ASSCIATED NUMBER OF
!             OBSERVATIONS), SO THESE WERE ADDED TO THE CALL LIST.
!     EXAMPLE--LOGISTIC-EXPONENTIAL MAXIMUM LIKELIHOOD Y
!     REFERENCE--LEEMIS AND MCQUESTION (2008), "UNIVARIATE DISTRIBUTION
!                RELATIONSHIPS", THE AMERICAN STATISTICIAN, VOL. 62,
!                NO. 1, PP. 45-53.
!              --LAN AND LEEMIS (2007), "THE LOGISTIC-EXPONENTIAL
!                SURVIVAL DISTRIBUTION", TECHNICAL REPORT, THE
!                COLLEGE OF WILLIAM AND MARY, DEPARTMENT OF
!                MATHEMATICS.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2008/2
!     ORIGINAL VERSION--FEBRUARY  2008.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION X(*)
      DOUBLE PRECISION FVEC(*)
      REAL XDATA(*)
!
      DOUBLE PRECISION DBETA
      DOUBLE PRECISION DALPHA
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
!
      DOUBLE PRECISION DP1
      DOUBLE PRECISION DP2
      DOUBLE PRECISION DGP1
      DOUBLE PRECISION DGP2
      COMMON/LEXCO2/DP1,DP2,DGP1,DGP2
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOBE.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      N=2
      IFLAG=0
!
      IF(ISUBG4.EQ.'XFU2')THEN
        WRITE(ICOUT,52)NOBS,XDATA(1)
   52   FORMAT('NOBS,XDATA(1) = ',I8,G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      DBETA=X(1)
      DALPHA=X(2)
      DTERM1=DP1/(1.0D0 - DP1)
      DTERM2=DP2/(1.0D0 - DP2)
!
      FVEC(1)=(1.0D0/DALPHA)*DLOG(1.0D0 + DTERM1**(1.0D0/DBETA)) - DGP1
      FVEC(2)=(1.0D0/DALPHA)*DLOG(1.0D0 + DTERM2**(1.0D0/DBETA)) - DGP2
!
      RETURN
      END SUBROUTINE LEXFU2 
      SUBROUTINE LEXHAZ(X,BETA,HAZ)
!
!     NOTE--LOGISTIC-EXPONENTIAL HAZARD IS:
!
!           h(X;BETA) = BETA*(EXP(X) - 1)**(BETA-1)*EXP(X)/
!                       [1 + (EXP(X) - 1)**BETA]
!                             X >= 0; BETA > 0
!
!           WITH BETA DENOTING THE SHAPE PARAMETER.
!
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCE--LEEMIS AND MCQUESTION (2008), "UNIVARIATE DISTRIBUTION
!                RELATIONSHIPS", THE AMERICAN STATISTICIAN, VOL. 62,
!                NO. 1, PP. 45-53.
!              --LAN AND LEEMIS (2007), "THE LOGISTIC-EXPONENTIAL
!                SURVIVAL DISTRIBUTION", TECHNICAL REPORT, THE
!                COLLEGE OF WILLIAM AND MARY, DEPARTMENT OF
!                MATHEMATICS.
!              --LAN AND LEEMIS (2008), "THE LOGISTIC-EXPONENTIAL
!                SURVIVAL DISTRIBUTION", NAVAL RESEARCH LOGISTICS,
!                VOL. xx, NO. xx, PP. xx.
!     VERSION NUMBER--2008/2
!     ORIGINAL VERSION--FEBRUARY  2008.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      HAZ=0.0D0
!
      IF(BETA.LT.1.0D0)THEN
        IF(X.LT.0.0D0)THEN
          WRITE(ICOUT,106)
  106     FORMAT('***** WARNING--THE FIRST ARGUMENT TO LEXHAZ IS ',   &
                 'NON-POSITIVE.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,102)X
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
        ENDIF
      ELSE
        IF(X.LT.0.0D0)THEN
          WRITE(ICOUT,101)
  101     FORMAT('***** WARNING--THE FIRST ARGUMENT TO LEXHAZ IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,102)X
  102     FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
        ENDIF
      ENDIF
!
      IF(BETA.LE.0.0D0)THEN
        WRITE(ICOUT,301)
  301   FORMAT('***** ERROR--THE SECOND ARGUMENT TO LEXHAZ IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,102)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      TERM1=DLOG(BETA) + X + (BETA - 1.0D0)*DLOG(DEXP(X) - 1.0D0)
      TERM2=DLOG(1.0D0 + (DEXP(X) - 1.0D0)**BETA)
      HAZ=DEXP(TERM1 - TERM2)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE LEXHAZ
      SUBROUTINE LEXML1(Y,N,MAXNXT,   &
                        TEMP1,DTEMP1,   &
                        XMEAN,XSD,XVAR,XMIN,XMAX,XSUM,   &
                        SCALSV,SHAPSV,SCALML,SHAPML,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE MAXIMUM LIKELIHOOD ESTIMATES FOR
!              THE 2-PARAMETER LOGISTIC-EXPONENTIAL DISTRIBUTION FOR THE
!              RAW DATA CASE (I.E., NO CENSORING AND NO GROUPING).  THIS
!              ROUTINE RETURNS ONLY THE POINT ESTIMATES (CONFIDENCE
!              INTERVALS WILL BE COMPUTED IN A SEPARATE ROUTINE).
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!              PUT THIS IN A SEPARATE ROUTINE AS IT MAY BE CALLED
!              FROM MULTIPLE PLACES (DPMB10 WILL GENERATE THE OUTPUT
!              FOR THE LOGISTIC-EXPONENTIAL MLE COMMAND).
!
!     REFERENCE--LEEMIS AND MCQUESTION (2008), "UNIVARIATE DISTRIBUTION
!                RELATIONSHIPS", THE AMERICAN STATISTICIAN, VOL. 62,
!                NO. 1, PP. 45-53.
!              --LAN AND LEEMIS (2007), "THE LOGISTIC-EXPONENTIAL
!                SURVIVAL DISTRIBUTION", TECHNICAL REPORT, THE
!                COLLEGE OF WILLIAM AND MARY, DEPARTMENT OF
!                MATHEMATICS.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/2
!     ORIGINAL VERSION--FEBRUARY  2010. EXTRACTED AS A SEPARATE
!                                       SUBROUTINE (FROM DPMB10)
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DIMENSION Y(*)
      DIMENSION TEMP1(*)
      DOUBLE PRECISION DTEMP1(*)
!
      DOUBLE PRECISION TOL
      DOUBLE PRECISION XPAR(2)
      DOUBLE PRECISION FVEC(2)
!
      DOUBLE PRECISION DP1
      DOUBLE PRECISION DP2
      DOUBLE PRECISION DGP1
      DOUBLE PRECISION DGP2
!
      EXTERNAL LEXFUN
      EXTERNAL LEXFU2
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*40 IDIST
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='B10M'
      ISUBN2='L1  '
      IERROR='NO'
      IWRITE='OFF'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'XML1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF LEXML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO
   52   FORMAT('IBUGA3,ISUBRO = ',A4,2X,A4)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'XML1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!               *****************************************************
!               **  STEP 2--                                       **
!               **  CARRY OUT CALCULATIONS                         **
!               **  FOR LOGISTIC-EXPONENTIAL MLE ESTIMATE          **
!               *****************************************************
!
      ISTEPN='2'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'XML1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IDIST='LOGISTIC-EXPONENTIAL'
!
      IFLAG=2
      CALL SUMRAW(Y,N,IDIST,IFLAG,   &
                  XMEAN,XVAR,XSD,XMIN,XMAX,   &
                  ISUBRO,IBUGA3,IERROR)
      CALL SUMDP(Y,N,IWRITE,XSUM,IBUGA3,IERROR)
!
      SHAPML=CPUMIN
      SCALML=CPUMIN
!
      IF(SCALSV.GT.0.0)THEN
        XPAR(2)=DBLE(SCALSV)
      ELSE
        AN=REAL(N)
        XPAR(2)=DBLE(AN*LOG(2.0)/XSUM)
      ENDIF
      IF(SHAPSV.GT.0.0)THEN
        XPAR(1)=DBLE(SHAPSV)
      ELSE
        AN=REAL(N)
        ATEMP=AN*LOG(2.0)/XSUM
        DSUM=0.0D0
        DO 2109 I=1,N
          DSUM=DSUM + DBLE(ABS(LOG(EXP(ATEMP*Y(I)) - 1.0)))
 2109   CONTINUE
        XPAR(1)=DBLE(N)/DSUM
      ENDIF
!
!               *************************************
!               **  STEP 22--                      **
!               **  IF NO STARTING VALUES GIVEN,   **
!               **  USE PERCENTILES METHOD TO      **
!               **  OBTAIN THEM.                   **
!               *************************************
!
!
        P1=25.0
        CALL PERCEN(P1,Y,N,IWRITE,TEMP1,MAXNXT,P1OUT,IBUGA3,IERROR)
        P2=75.0
        CALL PERCEN(P2,Y,N,IWRITE,TEMP1,MAXNXT,P2OUT,IBUGA3,IERROR)
        DP1=DBLE(P1)/100.0D0
        DP2=DBLE(P2)/100.0D0
        DGP1=DBLE(P1OUT)
        DGP2=DBLE(P2OUT)
!
        IOPT=2
        TOL=1.0D-6
        NVAR=2
        NPRINT=-1
        INFO=0
        LWA=MAXNXT
        CALL DNSQE(LEXFU2,JAC,IOPT,NVAR,XPAR,FVEC,TOL,NPRINT,INFO,   &
                   DTEMP1,MAXNXT,Y,N)
!
!               *************************************
!               **  STEP 23--                      **
!               **  NOW COMPUTE THE MAXIMUM        **
!               **  LIKELIHOOD ESTIMATES.          **
!               *************************************
!
!CCCC NOTE: ALPHA IN LEEMIS PARAMETERIZATION IS ACTUALLY
!CCCC       (1/SCALE).  FOR DATAPLOT, GENERATE TRUE SCALE
!CCCC        PARAMETER.
!
      IOPT=2
      TOL=1.0D-6
      NVAR=2
      NPRINT=-1
      INFO=0
      LWA=MAXNXT
      CALL DNSQE(LEXFUN,JAC,IOPT,NVAR,XPAR,FVEC,TOL,NPRINT,INFO,   &
                 DTEMP1,MAXNXT,Y,N)
!
      SHAPML=REAL(XPAR(1))
      SCALML=1.0/REAL(XPAR(2))
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'XML1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF LEXML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)N,XMEAN,XSD,XMIN,XMAX,XSUM
 9013   FORMAT('N,XMEAN,XSD,XMIN,XMAX,XSUM = ',I8,5G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9017)SHAPSV,SCALSV,SHAPML,SCALML
 9017   FORMAT('SHAPSV,SCALSV,SHAPML,SCALML =  ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE LEXML1
      SUBROUTINE LEXPDF(X,BETA,PDF)
!
!     NOTE--LOGISTIC-EXPONENTIAL PDF IS:
!
!           f(X;ALPHA,BETA) = ALPHA*BETA*(EXP(ALPHA*X)-1)**(BETA-1)*
!                             EXP(ALPHA*X)/
!                             {(1+(EXP(ALPHA*X)-1)**BETA)**2}
!                             X > 0; ALPHA, BETA > 0
!
!           WITH (1/ALPHA) DENOTING THE SCALE PARAMETER AND
!           BETA DENOTING THE SHAPE PARAMETER.
!
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCE--LEEMIS AND MCQUESTION (2008), "UNIVARIATE DISTRIBUTION
!                RELATIONSHIPS", THE AMERICAN STATISTICIAN, VOL. 62,
!                NO. 1, PP. 45-53.
!              --LAN AND LEEMIS (2007), "THE LOGISTIC-EXPONENTIAL
!                SURVIVAL DISTRIBUTION", TECHNICAL REPORT, THE
!                COLLEGE OF WILLIAM AND MARY, DEPARTMENT OF
!                MATHEMATICS.
!     VERSION NUMBER--2008/1
!     ORIGINAL VERSION--JANUARY   2008.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      PDF=0.0D0
!
      IF(BETA.LT.1.0D0)THEN
        IF(X.LE.0.0D0)THEN
          WRITE(ICOUT,106)
  106     FORMAT('***** WARNING--THE FIRST ARGUMENT TO LEXPDF IS ',   &
                 'NON-POSITIVE.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,102)X
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
        ENDIF
      ELSE
        IF(X.LT.0.0D0)THEN
          WRITE(ICOUT,101)
  101     FORMAT('***** WARNING--THE FIRST ARGUMENT TO LEXPDF IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,102)X
  102     FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
        ENDIF
      ENDIF
!
      IF(BETA.LE.0.0D0)THEN
        WRITE(ICOUT,301)
  301   FORMAT('***** ERROR--THE SECOND ARGUMENT TO LEXPDF IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,102)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      TERM1=DLOG(BETA)
      TERM2=(BETA-1.0D0)*DLOG(DEXP(X) - 1.0D0)
      TERM3=2.0D0*DLOG(1.0D0 + (DEXP(X) - 1.0D0)**BETA)
      TERM4=TERM1 + TERM2 + X - TERM3
      PDF=DEXP(TERM4)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE LEXPDF
      SUBROUTINE LEXPPF(P,BETA,PPF)
!
!     NOTE--LOGISTIC-EXPONENTIAL PPF IS:
!
!           G(P;BETA) = LOG[1 + (1/(1-P) - 1)**(1/BETA)]
!                       0 <= P < 1; BETA > 0
!
!           WITH BETA DENOTING THE SHAPE PARAMETER.
!
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCE--LEEMIS AND MCQUESTION (2008), "UNIVARIATE DISTRIBUTION
!                RELATIONSHIPS", THE AMERICAN STATISTICIAN, VOL. 62,
!                NO. 1, PP. 45-53.
!              --LAN AND LEEMIS (2007), "THE LOGISTIC-EXPONENTIAL
!                SURVIVAL DISTRIBUTION", TECHNICAL REPORT, THE
!                COLLEGE OF WILLIAM AND MARY, DEPARTMENT OF
!                MATHEMATICS.
!              --LAN AND LEEMIS (2008), "THE LOGISTIC-EXPONENTIAL
!                SURVIVAL DISTRIBUTION", NAVAL RESEARCH LOGISTICS,
!                VOL. xx, NO. xx, PP. xx.
!     VERSION NUMBER--2008/2
!     ORIGINAL VERSION--FEBRUARY  2008.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      PPF=0.0D0
!
      IF(BETA.LT.1.0D0)THEN
        IF(P.LE.0.0D0 .OR. P.GT.1.0D0)THEN
          WRITE(ICOUT,106)
  106     FORMAT('***** ERROR--THE FIRST ARGUMENT TO LEXPPF IS ',   &
                 'OUTSIDE THE ALLOWABLE [0,1] INTERVAL.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,102)P
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
        ENDIF
      ELSE
        IF(P.LT.0.0D0 .OR. P.GT.1.0D0)THEN
          WRITE(ICOUT,101)
  101     FORMAT('***** ERROR--THE FIRST ARGUMENT TO LEXPPF IS ',   &
                 'OUTSIDE THE ALLOWABLE (0,1] INTERVAL.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,102)P
  102     FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
        ENDIF
      ENDIF
!
      IF(BETA.LE.0.0D0)THEN
        WRITE(ICOUT,301)
  301   FORMAT('***** ERROR--THE SECOND ARGUMENT TO LEXPPF IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,102)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(P.LE.0.0D0)THEN
        PPF=0.0D0
      ELSE
        TERM1=P/(1.0D0 - P)
        PPF=DLOG(1.0D0 + TERM1**(1.0D0/BETA))
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE LEXPPF
      SUBROUTINE LEXRAN(N,BETA,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE LOGISTIC-EXPONENTIAL DISTRIBUTION
!              WITH SHAPE PARAMETER VALUE = BETA.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --BETA   = THE SINGLE PRECISION VALUE OF THE
!                                SHAPE PARAMETER.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE LOGISTIC-EXPONENTIAL DISTRIBUTION
!             WITH SHAPE PARAMETER VALUE = BETA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --BETA > 0
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN, LEXPPF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCE--LEEMIS AND MCQUESTION (2008), "UNIVARIATE DISTRIBUTION
!                RELATIONSHIPS", THE AMERICAN STATISTICIAN, VOL. 62,
!                NO. 1, PP. 45-53.
!              --LAN AND LEEMIS (2007), "THE LOGISTIC-EXPONENTIAL
!                SURVIVAL DISTRIBUTION", TECHNICAL REPORT, THE
!                COLLEGE OF WILLIAM AND MARY, DEPARTMENT OF
!                MATHEMATICS.
!              --LAN AND LEEMIS (2008), "THE LOGISTIC-EXPONENTIAL
!                SURVIVAL DISTRIBUTION", NAVAL RESEARCH LOGISTICS,
!                VOL. xx, NO. xx, PP. xx.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2008.1
!     ORIGINAL VERSION--JANUARY   2008.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
      DOUBLE PRECISION DTEMP
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(BETA.LE.0.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,16)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    5 FORMAT('***** ERROR--THE REQUESTED NUMBER OF ',   &
             'LOGISTIC-EXPONENTIAL RANDOM NUMBERS IS NON-POSITIVE.')
   15 FORMAT('***** ERROR--THE SHAPE PARAMETER, BETA, FOR THE ',   &
             'LOGISTIC-EXPONENTIAL DISTRIBUTION')
   16 FORMAT('      IS NON-POSITIVE.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N LOGISTIC-EXPONENTIAL DISTRIBUTION RANDOM NUMBERS
!     USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD.
!
      DO 100 I=1,N
        CALL LEXPPF(DBLE(X(I)),DBLE(BETA),DTEMP)
        X(I)=REAL(DTEMP)
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE LEXRAN
      SUBROUTINE LE3CDF(X,BETA,THETA,ALPHA,CDF)
!
!     NOTE--3-PARAMETER LOGISTIC-EXPONENTIAL CDF IS:
!
!           F(X;ALPHA,BETA,THETA) = 1 -
!           [1 + (EXP(ALPHA*THETA) - 1)**BETA]/
!           [1 + (EXP(ALPHA*(X+THETA) - 1)**BETA]
!           X > 0; ALPHA, BETA > 0, THETA >= 0
!
!           WITH ALPHA, BETA AND THETA DENOTING THE SHAPE
!           PARAMETERS.  NOTE THAT ALTHOUGH (1/ALPHA) IS A
!           SCALE PARAMETER FOR THE LOGISTIC-EXPONENTIAL, IT
!           IS NOT A SCALE PARAMETER FOR THE 3-PARAMETER
!           LOGISTIC-EXPONENTIAL IN THE SENSE THAT THE
!           RELATION
!
!           F(X;BETA,THETA,LOC,SCALE) = F((X-LOC)/SCALE;BETA,THETA,0,1)
!
!           DOES NOT HOLD.  THEREFORE, WE TREAT IT AS A SHAPE
!           PARAMETER IN DATAPLOT.
!
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCE--LEEMIS AND MCQUESTION (2008), "UNIVARIATE DISTRIBUTION
!                RELATIONSHIPS", THE AMERICAN STATISTICIAN, VOL. 62,
!                NO. 1, PP. 45-53.
!              --LAN AND LEEMIS (2007), "THE LOGISTIC-EXPONENTIAL
!                SURVIVAL DISTRIBUTION", TECHNICAL REPORT, THE
!                COLLEGE OF WILLIAM AND MARY, DEPARTMENT OF
!                MATHEMATICS.
!     VERSION NUMBER--2008/3
!     ORIGINAL VERSION--MARCH     2008.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      CDF=0.0D0
!
      IF(BETA.LT.1.0D0)THEN
        IF(X.LT.0.0D0)THEN
          WRITE(ICOUT,106)
  106     FORMAT('***** WARNING--THE FIRST ARGUMENT TO LE3CDF IS ',   &
                 'NON-POSITIVE.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,102)X
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
        ENDIF
      ELSE
        IF(X.LT.0.0D0)THEN
          WRITE(ICOUT,101)
  101     FORMAT('***** WARNING--THE FIRST ARGUMENT TO LE3CDF IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,102)X
  102     FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
        ENDIF
      ENDIF
!
      IF(BETA.LE.0.0D0)THEN
        WRITE(ICOUT,301)
  301   FORMAT('***** ERROR--THE SECOND ARGUMENT TO LE3CDF IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,102)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(THETA.LT.0.0D0)THEN
        WRITE(ICOUT,401)
  401   FORMAT('***** ERROR--THE THIRD ARGUMENT TO LE3CDF IS ',   &
               'NEGATIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,102)THETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(ALPHA.LE.0.0D0)THEN
        WRITE(ICOUT,501)
  501   FORMAT('***** ERROR--THE FOURTH ARGUMENT TO LE3CDF IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,102)ALPHA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      TERM1=1.0D0 + (DEXP(ALPHA*THETA) - 1.0D0)**BETA
      TERM2=1.0D0 + (DEXP(ALPHA*(X+THETA)) - 1.0D0)**BETA
      CDF=1.0D0 - (TERM1/TERM2)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE LE3CDF
      SUBROUTINE LE3CHA(X,BETA,THETA,ALPHA,HAZ)
!
!     NOTE--3-PARAMETER LOGISTIC-EXPONENTIAL CUMULATIVE HAZARD IS:
!
!           H(X;ALPHA,BETA,THETA) =
!           -LOG{[1 + (EXP(ALPHA*THETA) - 1)**BETA]/
!           [1 + (EXP(ALPHA*(X+THETA) - 1)**BETA]}
!           X > 0; ALPHA, BETA > 0, THETA >= 0
!
!           WITH ALPHA, BETA AND THETA DENOTING THE SHAPE
!           PARAMETERS.  NOTE THAT ALTHOUGH (1/ALPHA) IS A
!           SCALE PARAMETER FOR THE LOGISTIC-EXPONENTIAL, IT
!           IS NOT A SCALE PARAMETER FOR THE 3-PARAMETER
!           LOGISTIC-EXPONENTIAL IN THE SENSE THAT THE
!           RELATION
!
!           H(X;BETA,THETA,LOC,SCALE) = H((X-LOC)/SCALE;BETA,THETA,0,1)
!
!           DOES NOT HOLD.  THEREFORE, WE TREAT IT AS A SHAPE
!           PARAMETER IN DATAPLOT.
!
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCE--LEEMIS AND MCQUESTION (2008), "UNIVARIATE DISTRIBUTION
!                RELATIONSHIPS", THE AMERICAN STATISTICIAN, VOL. 62,
!                NO. 1, PP. 45-53.
!              --LAN AND LEEMIS (2007), "THE LOGISTIC-EXPONENTIAL
!                SURVIVAL DISTRIBUTION", TECHNICAL REPORT, THE
!                COLLEGE OF WILLIAM AND MARY, DEPARTMENT OF
!                MATHEMATICS.
!     VERSION NUMBER--2008/3
!     ORIGINAL VERSION--MARCH     2008.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      HAZ=0.0D0
!
      IF(BETA.LT.1.0D0)THEN
        IF(X.LT.0.0D0)THEN
          WRITE(ICOUT,106)
  106     FORMAT('***** WARNING--THE FIRST ARGUMENT TO LE3CHAZ IS ',   &
                 'NON-POSITIVE.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,102)X
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
        ENDIF
      ELSE
        IF(X.LT.0.0D0)THEN
          WRITE(ICOUT,101)
  101     FORMAT('***** WARNING--THE FIRST ARGUMENT TO LE3CHAZ IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,102)X
  102     FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
        ENDIF
      ENDIF
!
      IF(BETA.LE.0.0D0)THEN
        WRITE(ICOUT,301)
  301   FORMAT('***** ERROR--THE SECOND ARGUMENT TO LE3CHAZ IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,102)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(THETA.LT.0.0D0)THEN
        WRITE(ICOUT,401)
  401   FORMAT('***** ERROR--THE THIRD ARGUMENT TO LE3CHAZ IS ',   &
               'NEGATIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,102)THETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(ALPHA.LE.0.0D0)THEN
        WRITE(ICOUT,501)
  501   FORMAT('***** ERROR--THE FOURTH ARGUMENT TO LE3CHAZ IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,102)ALPHA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      TERM1=1.0D0 + (DEXP(ALPHA*THETA) - 1.0D0)**BETA
      TERM2=1.0D0 + (DEXP(ALPHA*(X+THETA)) - 1.0D0)**BETA
      HAZ=-DLOG(TERM1/TERM2)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE LE3CHA
      SUBROUTINE LE3HAZ(X,BETA,THETA,ALPHA,HAZ)
!
!     NOTE--3-PARAMETER LOGISTIC-EXPONENTIAL HAZARD IS:
!
!           h(X;ALPHA,BETA,THETA) =
!           ALHA*BETA*(EXP(ALPHA*(X+THETA) - 1)**(BETA-1)*
!           EXP(ALPHA*(X+THETA))/
!           [1 + (EXP(ALPHA*(X+THETA) - 1)**BETA]
!           X > 0; ALPHA, BETA > 0, THETA >= 0
!
!           WITH ALPHA, BETA AND THETA DENOTING THE SHAPE
!           PARAMETERS.  NOTE THAT ALTHOUGH (1/ALPHA) IS A
!           SCALE PARAMETER FOR THE LOGISTIC-EXPONENTIAL, IT
!           IS NOT A SCALE PARAMETER FOR THE 3-PARAMETER
!           LOGISTIC-EXPONENTIAL IN THE SENSE THAT THE
!           RELATION
!
!           h(X;BETA,THETA,LOC,SCALE) = h((X-LOC)/SCALE;BETA,THETA,0,1)/
!                                       SCALE
!
!           DOES NOT HOLD.  THEREFORE, WE TREAT IT AS A SHAPE
!           PARAMETER IN DATAPLOT.
!
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCE--LEEMIS AND MCQUESTION (2008), "UNIVARIATE DISTRIBUTION
!                RELATIONSHIPS", THE AMERICAN STATISTICIAN, VOL. 62,
!                NO. 1, PP. 45-53.
!              --LAN AND LEEMIS (2007), "THE LOGISTIC-EXPONENTIAL
!                SURVIVAL DISTRIBUTION", TECHNICAL REPORT, THE
!                COLLEGE OF WILLIAM AND MARY, DEPARTMENT OF
!                MATHEMATICS.
!     VERSION NUMBER--2008/3
!     ORIGINAL VERSION--MARCH     2008.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      HAZ=0.0D0
!
      IF(BETA.LT.1.0D0)THEN
        IF(X.LT.0.0D0)THEN
          WRITE(ICOUT,106)
  106     FORMAT('***** WARNING--THE FIRST ARGUMENT TO LE3HAZ IS ',   &
                 'NON-POSITIVE.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,102)X
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
        ENDIF
      ELSE
        IF(X.LT.0.0D0)THEN
          WRITE(ICOUT,101)
  101     FORMAT('***** WARNING--THE FIRST ARGUMENT TO LE3HAZ IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,102)X
  102     FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
        ENDIF
      ENDIF
!
      IF(BETA.LE.0.0D0)THEN
        WRITE(ICOUT,301)
  301   FORMAT('***** ERROR--THE SECOND ARGUMENT TO LE3HAZ IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,102)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(THETA.LT.0.0D0)THEN
        WRITE(ICOUT,401)
  401   FORMAT('***** ERROR--THE THIRD ARGUMENT TO LE3HAZ IS ',   &
               'NEGATIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,102)THETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(ALPHA.LE.0.0D0)THEN
        WRITE(ICOUT,501)
  501   FORMAT('***** ERROR--THE FOURTH ARGUMENT TO LE3HAZ IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,102)ALPHA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      TERM1=DLOG(ALPHA) + DLOG(BETA)
      TERM2=(BETA - 1.0D0)*DLOG(EXP(ALPHA*(X+THETA)) - 1.0D0)
      TERM3=ALPHA*(X+THETA)
      TERM4=DLOG(1.0D0 + (EXP(ALPHA*(X+THETA)) - 1.0D0)**BETA)
      HAZ=DEXP(TERM1 + TERM2 + TERM3 - TERM4)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE LE3HAZ
      SUBROUTINE LE3PDF(X,BETA,THETA,ALPHA,PDF)
!
!     NOTE--LOGISTIC-EXPONENTIAL PDF IS:
!
!           f(X;ALPHA,BETA,THETA) =
!           ALPHA*BETA*(1 + EXP(ALPHA*THETA) - 1)**BETA*
!           (EXP(ALPHA*(X+THETA))-1)**(BETA-1)*
!           EXP(ALPHA*(X+THETA))/
!           {(1+(EXP(ALPHA*(X+THETA))-1)**BETA)**2}
!           X > 0; ALPHA, BETA > 0, THETA >= 0
!
!           WITH ALPHA, BETA AND THETA DENOTING THE SHAPE
!           PARAMETERS.  NOTE THAT ALTHOUGH (1/ALPHA) IS A
!           SCALE PARAMETER FOR THE LOGISTIC-EXPONENTIAL, IT
!           IS NOT A SCALE PARAMETER FOR THE 3-PARAMETER
!           LOGISTIC-EXPONENTIAL IN THE SENSE THAT THE
!           RELATION
!
!           f(X;BETA,THETA,LOC,SCALE) = F((X-LOC)/SCALE;BETA,THETA)/SCALE
!
!           DOES NOT HOLD.  THEREFORE, WE TREAT IT AS A SHAPE
!           PARAMETER IN DATAPLOT.
!
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCE--LEEMIS AND MCQUESTION (2008), "UNIVARIATE DISTRIBUTION
!                RELATIONSHIPS", THE AMERICAN STATISTICIAN, VOL. 62,
!                NO. 1, PP. 45-53.
!              --LAN AND LEEMIS (2007), "THE LOGISTIC-EXPONENTIAL
!                SURVIVAL DISTRIBUTION", TECHNICAL REPORT, THE
!                COLLEGE OF WILLIAM AND MARY, DEPARTMENT OF
!                MATHEMATICS.
!     VERSION NUMBER--2008/3
!     ORIGINAL VERSION--MARCH     2008.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      PDF=0.0D0
!
      IF(BETA.LT.1.0D0)THEN
        IF(X.LT.0.0D0)THEN
          WRITE(ICOUT,106)
  106     FORMAT('***** WARNING--THE FIRST ARGUMENT TO LE3PDF IS ',   &
                 'NON-POSITIVE.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,102)X
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
        ENDIF
      ELSE
        IF(X.LT.0.0D0)THEN
          WRITE(ICOUT,101)
  101     FORMAT('***** WARNING--THE FIRST ARGUMENT TO LE3PDF IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,102)X
  102     FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
        ENDIF
      ENDIF
!
      IF(BETA.LE.0.0D0)THEN
        WRITE(ICOUT,301)
  301   FORMAT('***** ERROR--THE SECOND ARGUMENT TO LE3PDF IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,102)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(THETA.LT.0.0D0)THEN
        WRITE(ICOUT,401)
  401   FORMAT('***** ERROR--THE THIRD ARGUMENT TO LE3PDF IS ',   &
               'NEGATIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,102)THETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(ALPHA.LE.0.0D0)THEN
        WRITE(ICOUT,501)
  501   FORMAT('***** ERROR--THE FOURTH ARGUMENT TO LE3PDF IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,102)ALPHA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      TERM1=DLOG(ALPHA) + DLOG(BETA)
      TERM2=DLOG(1.0D0 + (DEXP(ALPHA*THETA) - 1.0D0)**BETA)
      TERM3=(BETA-1.0D0)*DLOG(DEXP(ALPHA*(X+THETA)) - 1.0D0)
      TERM4=ALPHA*(X + THETA)
      ANUM=TERM1 + TERM2 + TERM3 + TERM4
!
      ADEN=2.0D0*DLOG(1.0D0 + (DEXP(ALPHA*(X+THETA)) - 1.0D0)**BETA)
      PDF=DEXP(ANUM - ADEN)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE LE3PDF
      SUBROUTINE LE3PPF(P,BETA,THETA,ALPHA,PPF)
!
!     NOTE--LOGISTIC-EXPONENTIAL PPF IS:
!
!           G(P;BETA,THETA) =
!           LOG[1 + {((EXP(THETA)-1)**BETA + P)/(1-P)}**(1/BETA)]
!           - THETA
!           0 <= P < 1; BETA > 0, THETA >= 0
!
!           WITH ALPHA, BETA AND THETA DENOTING THE SHAPE
!           PARAMETERS.  NOTE THAT ALTHOUGH (1/ALPHA) IS A
!           SCALE PARAMETER FOR THE LOGISTIC-EXPONENTIAL, IT
!           IS NOT A SCALE PARAMETER FOR THE 3-PARAMETER
!           LOGISTIC-EXPONENTIAL IN THE SENSE THAT THE
!           RELATION
!
!           G(P;BETA,THETA,LOC,SCALE) = LOC + SCALE*F(P;BETA,THETA,0,1)
!
!           DOES NOT HOLD.  THEREFORE, WE TREAT IT AS A SHAPE
!           PARAMETER IN DATAPLOT.
!
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCE--LEEMIS AND MCQUESTION (2008), "UNIVARIATE DISTRIBUTION
!                RELATIONSHIPS", THE AMERICAN STATISTICIAN, VOL. 62,
!                NO. 1, PP. 45-53.
!              --LAN AND LEEMIS (2007), "THE LOGISTIC-EXPONENTIAL
!                SURVIVAL DISTRIBUTION", TECHNICAL REPORT, THE
!                COLLEGE OF WILLIAM AND MARY, DEPARTMENT OF
!                MATHEMATICS.
!              --LAN AND LEEMIS (2008), "THE LOGISTIC-EXPONENTIAL
!                SURVIVAL DISTRIBUTION", NAVAL RESEARCH LOGISTICS,
!                VOL. xx, NO. xx, PP. xx.
!     VERSION NUMBER--2008/3
!     ORIGINAL VERSION--MARCH     2008.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      PPF=0.0D0
!
      IF(BETA.LT.1.0D0)THEN
        IF(P.LE.0.0D0 .OR. P.GT.1.0D0)THEN
          WRITE(ICOUT,106)
  106     FORMAT('***** ERROR--THE FIRST ARGUMENT TO LE3PPF IS ',   &
                 'OUTSIDE THE ALLOWABLE [0,1] INTERVAL.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,102)P
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
        ENDIF
      ELSE
        IF(P.LT.0.0D0 .OR. P.GT.1.0D0)THEN
          WRITE(ICOUT,101)
  101     FORMAT('***** ERROR--THE FIRST ARGUMENT TO LE3PPF IS ',   &
                 'OUTSIDE THE ALLOWABLE (0,1] INTERVAL.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,102)P
  102     FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
        ENDIF
      ENDIF
!
      IF(BETA.LE.0.0D0)THEN
        WRITE(ICOUT,301)
  301   FORMAT('***** ERROR--THE SECOND ARGUMENT TO LE3PPF IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,102)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(THETA.LT.0.0D0)THEN
        WRITE(ICOUT,401)
  401   FORMAT('***** ERROR--THE THIRD ARGUMENT TO LE3PPF IS ',   &
               'NEGATIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,102)THETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(ALPHA.LE.0.0D0)THEN
        WRITE(ICOUT,501)
  501   FORMAT('***** ERROR--THE FOURTH ARGUMENT TO LE3PPF IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,102)ALPHA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(P.LE.0.0D0)THEN
        PPF=0.0D0
      ELSE
        ANUM=(DEXP(ALPHA*THETA) - 1.0D0)**BETA + P
        ADEN=1.0D0 - P
        PPF=(1.0D0/ALPHA)*DLOG(1.0D0 + (ANUM/ADEN)**(1.0D0/BETA))   &
            - THETA
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE LE3PPF
      SUBROUTINE LE3RAN(N,BETA,THETA,ALPHA,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE 3-PARAMETER LOGISTIC-EXPONENTIAL DISTRIBUTION
!              WITH SHAPE PARAMETER VALUE = BETA.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --BETA   = THE SINGLE PRECISION VALUE OF THE
!                                FIRST SHAPE PARAMETER.
!                     --THETA  = THE SINGLE PRECISION VALUE OF THE
!                                SECOND SHAPE PARAMETER.
!                     --ALPHA  = THE SINGLE PRECISION VALUE OF THE
!                                THIRD SHAPE PARAMETER.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE 3-PARAMETER LOGISTIC-EXPONENTIAL DISTRIBUTION
!             WITH SHAPE PARAMETER VALUES = BETA, THETA AND ALPHA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --BETA > 0; THETA >= 0.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN, LE3PPF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCE--LEEMIS AND MCQUESTION (2008), "UNIVARIATE DISTRIBUTION
!                RELATIONSHIPS", THE AMERICAN STATISTICIAN, VOL. 62,
!                NO. 1, PP. 45-53.
!              --LAN AND LEEMIS (2007), "THE LOGISTIC-EXPONENTIAL
!                SURVIVAL DISTRIBUTION", TECHNICAL REPORT, THE
!                COLLEGE OF WILLIAM AND MARY, DEPARTMENT OF
!                MATHEMATICS.
!              --LAN AND LEEMIS (2008), "THE LOGISTIC-EXPONENTIAL
!                SURVIVAL DISTRIBUTION", NAVAL RESEARCH LOGISTICS,
!                VOL. xx, NO. xx, PP. xx.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2008.3
!     ORIGINAL VERSION--MARCH     2008.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
      DOUBLE PRECISION DTEMP
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT, 6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(BETA.LE.0.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,16)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(THETA.LT.0.0)THEN
        WRITE(ICOUT,25)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,26)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(ALPHA.LE.0.0)THEN
        WRITE(ICOUT,35)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,36)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ALPHA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    5 FORMAT('***** ERROR--THE REQUESTED NUMBER OF ',   &
             '3-PARAMETER LOGISTIC-EXPONENTIAL ')
    6 FORMAT('      RANDOM NUMBERS IS NON-POSITIVE.')
   15 FORMAT('***** ERROR--THE SHAPE PARAMETER, BETA, FOR THE ',   &
             '3-PARAMETER LOGISTIC-EXPONENTIAL DISTRIBUTION')
   16 FORMAT('      IS NON-POSITIVE.')
   25 FORMAT('***** ERROR--THE LOCATION PARAMETER, THETA, FOR ',   &
             'THE 3-PARAMETER LOGISTIC-EXPONENTIAL')
   26 FORMAT('      DISTRIBUTION IS NON-POSITIVE.')
   35 FORMAT('***** ERROR--THE SCALE PARAMETER, ALPHA, FOR ',   &
             'THE 3-PARAMETER LOGISTIC-EXPONENTIAL')
   36 FORMAT('      DISTRIBUTION IS NON-POSITIVE.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N 3-PARAMETER LOGISTIC-EXPONENTIAL DISTRIBUTION
!     RANDOM NUMBERS USING THE PERCENT POINT FUNCTION
!     TRANSFORMATION METHOD.
!
      DO 100 I=1,N
        CALL LE3PPF(DBLE(X(I)),DBLE(BETA),DBLE(THETA),   &
                    DBLE(ALPHA),DTEMP)
        X(I)=REAL(DTEMP)
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE LE3RAN
      SUBROUTINE LG1FUN (NPAR, XPAR, FVEC, IFLAG, XDATA, R)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE FUNCTIONS FOR THE
!              LOGNORMAL MAXIMUM LIKELIHOOD EQUATIONS FOR THE
!              SINGLY TIME CENSORED CASE (FROM PP. 161-162 OF BURY).
!
!      SUM[i=1 to r][Z(I)] + M*H(Z(I)) = 0
!
!      SUM[i=1 to r][Z(I)**2] + M*Z*H(Z) - R = 0
!
!      WHERE
!
!
!         R        = NUMBER OF FAILURES
!         M        = NUMBER OF CENSORING TIMES
!         C        = CENSORING TIME (ALL CENSORED DATA WILL HAVE
!                    THE SAME CENSORING TIME)
!         Z(I)     = [LOG(X(I) - UHAT]/SHAT
!         UHAT     = FVEC(1) = CURRENT ESTIMATE OF MU PARAMETER
!         SHAT     = FVEC(2) = CURRENT ESTIMATE OF SIGMA PARAMETER
!         Z        = [LOG(C) - UHAT]/SHAT
!         H(Z)     = NORPDF(Z)/(1 - NOCDF(Z))
!
!              CALLED BY DNSQE ROUTINE FOR SOLVING SIMULTANEOUS
!              NONLINEAR EQUATIONS.  NOTE THAT THE CALLING SEQUENCE
!              DID NOT ACCOMODATE A DATA ARRAY (AND ASSCIATED NUMBER OF
!              OBSERVATIONS), SO THESE WERE ADDED TO THE CALL LIST.
!     EXAMPLE--LOGNORMAL MAXIMUM LIKELIHOOD Y X
!     REFERENCE--KARL BURY, (1999). "STATISTICAL DISTRIBUTIONS IN
!                ENGINEERING", CAMBRIDGE UNIVERSITY PRESS,
!                PP. 161-162.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 CENTER FOR APPLIED MATHEMATICS
!                 NATIONAL BUREAU OF STANDARDS
!                 WASHINGTON, D. C. 20234
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004/11
!     ORIGINAL VERSION--NOVEMBER  2004.
!
!---------------------------------------------------------------------
!
      INTEGER R
      DOUBLE PRECISION XPAR(*)
      DOUBLE PRECISION FVEC(*)
      REAL XDATA(*)
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DR
      DOUBLE PRECISION DM
      DOUBLE PRECISION DZ
      DOUBLE PRECISION DH
      DOUBLE PRECISION DX
      DOUBLE PRECISION UHAT
      DOUBLE PRECISION SHAT
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
!
      DOUBLE PRECISION C
      INTEGER N
      INTEGER M
      COMMON/LG1COM/C,N,M
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      NPAR=2
      IFLAG=0
!
      DN=DBLE(N)
      DR=DBLE(R)
      DM=DBLE(M)
      UHAT=XPAR(1)
      SHAT=XPAR(2)
      DZ=(DLOG(C)-UHAT)/SHAT
      CALL NODPDF(DZ,DTERM1)
      CALL NODCDF(DZ,DTERM2)
      DH=DTERM1/(1.0D0 - DTERM2)
!
      DTERM1=DM*DH
      DTERM2=DTERM1*DZ - DR
      DSUM1=0.0D0
      DSUM2=0.0D0
!
      IF(R.GT.0)THEN
        DO 100 I=1,R
          DX=DBLE(XDATA(I))
          DX=(DLOG(DX) - UHAT)/SHAT
          DSUM1=DSUM1 + DX
          DSUM2=DSUM2 + DX*DX
  100   CONTINUE
      ENDIF
!
      FVEC(1) = DTERM1 + DSUM1
      FVEC(2) = DTERM2 + DSUM2
!
      RETURN
      END SUBROUTINE LG1FUN 
      DOUBLE PRECISION FUNCTION LG2FUN (DU,DX)
!
!     PURPOSE--THIS ROUTINE IS USED IN FINDING THE LIKELIHOOD RATIO
!              BASED CONFIDENCE INTERVAL FOR THE MU (=LOG(SCALE)
!              PARAMETER OF A 2-PARAMETER LOGNORMAL MODEL
!              (SINGLY TIME CENSORED SAMPLE).  THE FOLLOWING
!              EQUATION NEEDS TO BE SOLVED.
!
!                 2*LL(UHAT,SHAT) - 2*LL(U,S(U)) - CHSPPF(alpha,1)
!
!              WITH
!
!                 LL(UHAT,SHAT) = -R*LOG(SHAT) -
!                                 SUM[i=1 tp r][LOG(X(I))] -
!                                 0.5*SUM[i=1 to r]
!                                 [((LOG(X(I)) - UHAT)/SHAT)**2] +
!                                 DM*LOG(1 - NORCDF(
!
!              LL(UHAT,SHAT) IS COMPUTED ONCE BY THE CALLING ROUTINE
!              AND PASSED VIA COMMON BLOCK.
!
!              THEN GIVEN THE CURRENT GUESS FOR U, WE NEED TO
!              SOLVE THE FOLLOWING EQUATION FOR S:
!
!                 SUM[i=1 to r][{(LOG(X(I)-U)/S}**2] +
!                 M*(LOG(C)-U)/S)*H(Z) - R
!
!              WITH
!
!                 Z    = (LOG(X(I))-U)/S
!                 HZ   = NORPDF(Z)/(1-NORCDF(Z))
!
!              WE THEN COMPUTE LL(UHAT,SHAT) WITH THESE U AND S(U)
!              VALUES.
!
!     EXAMPLE--LOGNORMAL MAXIMUM LIKELIHOOD Y X
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN ENGINEERING",
!                CAMBRIDGE UNIVERSITY PRESS, 1999, CHAPTER 11 (SEE
!                EXAMPLE 11.5).
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004/11
!     ORIGINAL VERSION--NOVEMBER   2004.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DU
      DOUBLE PRECISION DX(*)
!
      INTEGER N
      INTEGER IR
      INTEGER IM
      DOUBLE PRECISION DLLUS
      DOUBLE PRECISION DC
      DOUBLE PRECISION DK
      DOUBLE PRECISION DSIGMA
      COMMON/LG2COM/DLLUS,DC,DK,DSIGMA,N,IR,IM
!
      INTEGER N2
      INTEGER IR2
      INTEGER IM2
      DOUBLE PRECISION DU2
      DOUBLE PRECISION DC2
      COMMON/LG3COM/DU2,DC2,N2,IR2,IM2
!
      DOUBLE PRECISION LG3FUN
      EXTERNAL LG3FUN
!
      DOUBLE PRECISION AE
      DOUBLE PRECISION RE
      DOUBLE PRECISION XLOW
      DOUBLE PRECISION XUP
      DOUBLE PRECISION XSTRT
      DOUBLE PRECISION DS
      DOUBLE PRECISION DN
      DOUBLE PRECISION DR
      DOUBLE PRECISION DM
      DOUBLE PRECISION DZ
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  STEP 1: GIVEN VALUE OF SCALE PARAMETER (DB), NEED TO COMPUTE
!          THE SHAPE PARAMETER (WHICH IN TURN INVOLVES FINDING A
!          ROOT).
                                                                                                                                  
      N2=N
      IR2=IR
      IM2=IM
      DC2=DC
      DU2=DU
!
      AE=1.D-7
      RE=1.D-7
      XSTRT=DSIGMA
      XLOW=XSTRT/5.0D0
      XUP=XSTRT*5.0D0
      CALL DFZER3(LG3FUN,XLOW,XUP,XSTRT,RE,AE,IFLAG,DX)
      DS=XLOW
!
!  COMPUTE LL(S,G)
!
      DN=DBLE(N)
      DR=DBLE(IR)
      DM=DBLE(IM)
!
      DZ=(DLOG(DC) - DU)/DS
      CALL NODCDF(DZ,DTERM2)
      DTERM1=-DR*DLOG(DS) + DM*DLOG(1.0D0 - DTERM2)
      DSUM1=0.0D0
      DSUM2=0.0D0
      DO 100 I=1,IR
        DZ=DLOG(DX(I))
        DSUM1=DSUM1 + DZ
        DSUM2=DSUM2 + ((DZ - DU)/DS)**2
  100 CONTINUE
      DTERM2=DTERM1 - DSUM1 - 0.5D0*DSUM2
!
      LG2FUN=2.0*DLLUS - 2.0D0*DTERM2 - DK
!
      RETURN
      END FUNCTION LG2FUN 
      DOUBLE PRECISION FUNCTION LG3FUN (DS,DX)
!
!     PURPOSE--THIS ROUTINE IS USED IN FINDING THE LIKELIHOOD RATIO
!              BASED CONFIDENCE INTERVAL FOR THE MU (=LOG(SCALE)
!              PARAMETER OF A 2-PARAMETER LOGNORMAL MODEL
!              (SINGLY TIME CENSORED SAMPLE).  IT IS CALLED BY
!              LG2FUN TO SOLVE THE EQUATION
!
!                 SUM[i=1 to r][{(LOG(X(I)-U)/S}**2] +
!                 M*(LOG(C)-U)/S)*H(Z) - R
!
!              WITH
!
!                 Z    = (LOG(X(I))-U)/S
!                 HZ   = NORPDF(Z)/(1-NORCDF(Z))
!
!              WE ARE GIVEN THE VALUE OF U AND WE NEED TO SOLVE FOR S.
!
!     EXAMPLE--LOGNORMAL MAXIMUM LIKELIHOOD Y X
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN ENGINEERING",
!                CAMBRIDGE UNIVERSITY PRESS, 1999, CHAPTER 11 (SEE
!                EXAMPLE 11.5).
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004/11
!     ORIGINAL VERSION--NOVEMBER   2004.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DS
      DOUBLE PRECISION DX(*)
!
      INTEGER N
      INTEGER IR
      INTEGER IM
      DOUBLE PRECISION DU
      DOUBLE PRECISION DC
      COMMON/LG3COM/DU,DC,N,IR,IM
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DR
      DOUBLE PRECISION DM
      DOUBLE PRECISION DZ
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DSUM1
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      DN=DBLE(N)
      DR=DBLE(IR)
      DM=DBLE(IM)
!
      DTERM1=(DLOG(DC)-DU)/DS
      CALL NODPDF(DTERM1,DTERM2)
      CALL NODCDF(DTERM1,DTERM3)
!
      DSUM1=0.0D0
      DO 100 I=1,IR
        DZ=DX(I)
        DZ=(DLOG(DZ) - DU)/DS
        DSUM1=DSUM1 + DZ*DZ
  100 CONTINUE
!
      LG3FUN=DSUM1 + DM*DTERM1*DTERM2/(1.0D0-DTERM3) - DR
!
      RETURN
      END FUNCTION LG3FUN 
      DOUBLE PRECISION FUNCTION LG4FUN (DSIGMA,DX)
!
!     PURPOSE--THIS ROUTINE IS USED IN FINDING THE LIKELIHOOD RATIO
!              BASED CONFIDENCE INTERVAL FOR THE SIGMA
!              PARAMETER OF A 2-PARAMETER LOGNORMAL MODEL
!              (SINGLY TIME CENSORED SAMPLE).  THE FOLLOWING
!              EQUATION NEEDS TO BE SOLVED.
!
!                 2*LL(UHAT,SHAT) - 2*LL(G(S),S) - CHSPPF(alpha,1)
!
!              WITH
!
!                 LL(UHAT,SHAT) = -R*LOG(SHAT) -
!                                 SUM[i=1 tp r][LOG(X(I))] -
!                                 0.5*SUM[i=1 to r]
!                                 [((LOG(X(I)) - UHAT)/SHAT)**2] +
!                                 DM*LOG(1 - NORCDF(
!
!              LL(UHAT,SHAT) IS COMPUTED ONCE BY THE CALLING ROUTINE
!              AND PASSED VIA COMMON BLOCK.
!
!              THEN GIVEN THE CURRENT GUESS FOR SIGMA, WE NEED TO
!              SOLVE THE FOLLOWING EQUATION FOR U:
!
!                 SUM[i=1 to r][(LOG(X(I)-U)/S] + M*H(Z)
!
!              WITH
!
!                 Z    = (LOG(X(I))-U)/S
!                 HZ   = NORPDF(Z)/(1-NORCDF(Z))
!
!              WE THEN COMPUTE LL(UHAT,SHAT) WITH THESE G(S) AND S
!              VALUES.
!
!     EXAMPLE--LOGNORMAL MAXIMUM LIKELIHOOD Y X
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN ENGINEERING",
!                CAMBRIDGE UNIVERSITY PRESS, 1999, CHAPTER 11 (SEE
!                EXAMPLE 11.5).
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004/11
!     ORIGINAL VERSION--NOVEMBER   2004.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DSIGMA
      DOUBLE PRECISION DX(*)
!
      INTEGER N
      INTEGER IR
      INTEGER IM
      DOUBLE PRECISION DLLUS
      DOUBLE PRECISION DC
      DOUBLE PRECISION DK
      DOUBLE PRECISION DU
      COMMON/LG4COM/DLLUS,DC,DK,DU,N,IR,IM
!
      INTEGER N2
      INTEGER IR2
      INTEGER IM2
      DOUBLE PRECISION DS2
      DOUBLE PRECISION DC2
      COMMON/LG5COM/DS2,DC2,N2,IR2,IM2
!
      DOUBLE PRECISION LG5FUN
      EXTERNAL LG5FUN
!
      DOUBLE PRECISION AE
      DOUBLE PRECISION RE
      DOUBLE PRECISION XLOW
      DOUBLE PRECISION XUP
      DOUBLE PRECISION XSTRT
      DOUBLE PRECISION DS
      DOUBLE PRECISION DN
      DOUBLE PRECISION DR
      DOUBLE PRECISION DM
      DOUBLE PRECISION DZ
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  STEP 1: GIVEN VALUE OF SHAPE PARAMETER (DSIGMA), NEED TO COMPUTE
!          THE SCALE PARAMETER (WHICH IN TURN INVOLVES FINDING A
!          ROOT).
                                                                                                                                  
      N2=N
      IR2=IR
      IM2=IM
      DC2=DC
      DS2=DSIGMA
!
      AE=1.D-7
      RE=1.D-7
      XSTRT=DU
      XLOW=XSTRT/5.0D0
      XUP=XSTRT*5.0D0
      CALL DFZER3(LG5FUN,XLOW,XUP,XSTRT,RE,AE,IFLAG,DX)
      DU=XLOW
      DS=DSIGMA
!
!  COMPUTE LL(S,G)
!
      DN=DBLE(N)
      DR=DBLE(IR)
      DM=DBLE(IM)
!
      DZ=(DLOG(DC) - DU)/DS
      CALL NODCDF(DZ,DTERM2)
      DTERM1=-DR*DLOG(DS) + DM*DLOG(1.0D0 - DTERM2)
      DSUM1=0.0D0
      DSUM2=0.0D0
      DO 100 I=1,IR
        DZ=DLOG(DX(I))
        DSUM1=DSUM1 + DZ
        DSUM2=DSUM2 + ((DZ - DU)/DS)**2
  100 CONTINUE
      DTERM2=DTERM1 - DSUM1 - 0.5D0*DSUM2
!
      LG4FUN=2.0*DLLUS - 2.0D0*DTERM2 - DK
!
      RETURN
      END FUNCTION LG4FUN 
      DOUBLE PRECISION FUNCTION LG5FUN (DU,DX)
!
!     PURPOSE--THIS ROUTINE IS USED IN FINDING THE LIKELIHOOD RATIO
!              BASED CONFIDENCE INTERVAL FOR THE SHAPE PARAMETER,
!              SIGMA, OF A 2-PARAMETER LOGNORMAL MODEL
!              (SINGLY TIME CENSORED SAMPLE).  IT IS CALLED BY
!              LG4FUN TO SOLVE THE EQUATION
!
!                 SUM[i=1 to r][{(LOG(X(I)-U)/S}**2] + M*H(Z)
!
!              WITH
!
!                 Z    = (LOG(X(I))-U)/S
!                 HZ   = NORPDF(Z)/(1-NORCDF(Z))
!
!              WE ARE GIVEN THE VALUE OF U AND WE NEED TO SOLVE FOR S.
!
!     EXAMPLE--LOGNORMAL MAXIMUM LIKELIHOOD Y X
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN ENGINEERING",
!                CAMBRIDGE UNIVERSITY PRESS, 1999, CHAPTER 11 (SEE
!                EXAMPLE 11.5).
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004/11
!     ORIGINAL VERSION--NOVEMBER   2004.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DU
      DOUBLE PRECISION DX(*)
!
      INTEGER N
      INTEGER IR
      INTEGER IM
      DOUBLE PRECISION DS
      DOUBLE PRECISION DC
      COMMON/LG5COM/DS,DC,N,IR,IM
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DR
      DOUBLE PRECISION DM
      DOUBLE PRECISION DZ
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DSUM1
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      DN=DBLE(N)
      DR=DBLE(IR)
      DM=DBLE(IM)
!
      DTERM1=(DLOG(DC)-DU)/DS
      CALL NODPDF(DTERM1,DTERM2)
      CALL NODCDF(DTERM1,DTERM3)
!
      DSUM1=0.0D0
      DO 100 I=1,IR
        DZ=DX(I)
        DZ=(DLOG(DZ) - DU)/DS
        DSUM1=DSUM1 + DZ
  100 CONTINUE
!
      LG5FUN=DSUM1 + DM*DTERM2/(1.0D0-DTERM3)
!
      RETURN
      END FUNCTION LG5FUN 
      DOUBLE PRECISION FUNCTION LG6FUN (DXQ,DX)
!
!     PURPOSE--THIS ROUTINE IS USED IN FINDING THE LIKELIHOOD RATIO
!              BASED CONFIDENCE INTERVAL FOR A GIVEN PERCENTILE
!              OF A 2-PARAMETER LOGNORMAL MODEL
!              (SINGLY TIME CENSORED SAMPLE).  THE FOLLOWING
!              EQUATION NEEDS TO BE SOLVED.
!
!                 2*LL(UHAT,SHAT) - 2*LL(g(xq),s(xq)) - CHSPPF(alpha,1)
!
!              WITH
!
!                 LL(UHAT,SHAT) = -R*LOG(SHAT) -
!                                 SUM[i=1 tp r][LOG(X(I))] -
!                                 0.5*SUM[i=1 to r]
!                                 [((LOG(X(I)) - UHAT)/SHAT)**2] +
!                                 DM*LOG(1 - NORCDF(
!
!              LL(UHAT,SHAT) IS COMPUTED ONCE BY THE CALLING ROUTINE
!              AND PASSED VIA COMMON BLOCK.
!
!              THEN GIVEN THE CURRENT MAXIMUM LIKELIHOOD ESTIMATE OF
!              SIGMA, WE NEED TO SOLVE THE FOLLOWING EQUATION FOR
!              XQ:
!
!
!                 (1/B**2)*SUM[i=1 to r]
!                 [{(LOG(X(I)/X05} + B*Z05]*LOG(X(I)/X05) +
!                 (M/B)*(LOG(C)/X05)*H(Z) - R
!
!              WITH
!
!                 Z05  = NORPPF(1 - ALPHA/2)
!                 X05  = LGNPPF(P) (P IS THE DESIRED PERCENTILE)
!                 Z    = LOG(C/XQ)/B + Z05
!                 HZ   = NORPDF(Z)/(1-NORCDF(Z))
!
!              WE ARE GIVEN THE VALUE OF B (= MAXIMUM LIKELIHOOD
!              ESTIMATE OF SIGMA) AND WE NEED TO SOLVE FOR XQ.
!              WE THEN COMPUTE LL(UHAT,SHAT) WITH THESE U AND S(U)
!              VALUES.
!
!     EXAMPLE--LOGNORMAL MAXIMUM LIKELIHOOD Y X
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN ENGINEERING",
!                CAMBRIDGE UNIVERSITY PRESS, 1999, CHAPTER 11 (SEE
!                EXAMPLE 11.5).
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004/11
!     ORIGINAL VERSION--NOVEMBER   2004.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DXQ
      DOUBLE PRECISION DX(*)
!
      INTEGER N
      INTEGER IR
      INTEGER IM
      DOUBLE PRECISION DLLUS
      DOUBLE PRECISION DC
      DOUBLE PRECISION DK
      DOUBLE PRECISION DSIGMA
      DOUBLE PRECISION DU
      DOUBLE PRECISION DX05
      DOUBLE PRECISION DZ05
      DOUBLE PRECISION SEXQP
      COMMON/LG6COM/DLLUS,DC,DK,DSIGMA,DU,DX05,DZ05,SEXQP,N,IR,IM
!
      INTEGER N2
      INTEGER IR2
      INTEGER IM2
      DOUBLE PRECISION DX052
      DOUBLE PRECISION DZ052
      DOUBLE PRECISION DC2
      DOUBLE PRECISION DS2
      COMMON/LG7COM/DX052,DZ052,DC2,DS2,N2,IR2,IM2
!
      DOUBLE PRECISION LG7FUN
      EXTERNAL LG7FUN
!
      DOUBLE PRECISION AE
      DOUBLE PRECISION RE
      DOUBLE PRECISION XLOW
      DOUBLE PRECISION XUP
      DOUBLE PRECISION XSTRT
      DOUBLE PRECISION DS
      DOUBLE PRECISION DU2
      DOUBLE PRECISION DN
      DOUBLE PRECISION DR
      DOUBLE PRECISION DM
      DOUBLE PRECISION DZ
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  STEP 1: GIVEN VALUE OF SCALE PARAMETER (DB), NEED TO COMPUTE
!          THE SHAPE PARAMETER (WHICH IN TURN INVOLVES FINDING A
!          ROOT).
!
      DX052=DX05
      DZ052=DZ05
      DC2=DC
      DS2=DSIGMA
      N2=N
      IR2=IR
      IM2=IM
!
      AE=1.D-7
      RE=1.D-7
      XSTRT=DXQ
      XLOW=XSTRT/5.0D0
      XUP=XSTRT*5.0D0
      CALL DFZER3(LG7FUN,XLOW,XUP,XSTRT,RE,AE,IFLAG,DX)
      DSXQ=XLOW
!
!  COMPUTE LL(S,G)
!
      DN=DBLE(N)
      DR=DBLE(IR)
      DM=DBLE(IM)
!
      DU2=DLOG(DXQ) - DZ05*DSXQ
      DS=DSXQ
      DZ=(DLOG(DC) - DU2)/DS
      CALL NODCDF(DZ,DTERM2)
      DTERM1=-DR*DLOG(DS) + DM*DLOG(1.0D0 - DTERM2)
      DSUM1=0.0D0
      DSUM2=0.0D0
      DO 100 I=1,IR
        DZ=DLOG(DX(I))
        DSUM1=DSUM1 + DZ
        DSUM2=DSUM2 + ((DZ - DU2)/DS)**2
  100 CONTINUE
      DTERM2=DTERM1 - DSUM1 - 0.5D0*DSUM2
!
      LG6FUN=2.0*DLLUS - 2.0D0*DTERM2 - DK
!
      RETURN
      END FUNCTION LG6FUN 
      DOUBLE PRECISION FUNCTION LG7FUN (DXQ,DX)
!
!     PURPOSE--THIS ROUTINE IS USED IN FINDING THE LIKELIHOOD RATIO
!              BASED CONFIDENCE INTERVAL FOR THE PERCENTILE FUNCTION
!              OF A 2-PARAMETER LOGNORMAL MODEL (SINGLY TIME CENSORED
!              SAMPLE).  IT IS CALLED BY LG6FUN TO SOLVE THE EQUATION
!
!                 (1/B**2)*SUM[i=1 to r]
!                 [{(LOG(X(I)/X05} + B*Z05]*LOG(X(I)/X05) +
!                 (M/B)*(LOG(C)/X05)*H(Z) - R
!
!              WITH
!
!                 Z05  = NORPPF(1 - ALPHA/2)
!                 X05  = LGNPPF(P) (P IS THE DESIRED PERCENTILE)
!                 Z    = LOG(C/XQ)/B + Z05
!                 HZ   = NORPDF(Z)/(1-NORCDF(Z))
!
!              WE ARE GIVEN THE VALUE OF B (= MAXIMUM LIKELIHOOD
!              ESTIMATE OF SIGMA) AND WE NEED TO SOLVE FOR XQ.
!
!              THE VALUES OF Z05 AND X05 ARE CALCULATED IN DPMLL2
!              AND STORED IN A COMMON BLOCK.
!
!     EXAMPLE--LOGNORMAL MAXIMUM LIKELIHOOD Y X
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN ENGINEERING",
!                CAMBRIDGE UNIVERSITY PRESS, 1999, CHAPTER 11 (SEE
!                EXAMPLE 11.5).
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004/11
!     ORIGINAL VERSION--NOVEMBER   2004.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DXQ
      DOUBLE PRECISION DX(*)
!
      INTEGER N
      INTEGER IR
      INTEGER IM
      DOUBLE PRECISION DX05
      DOUBLE PRECISION DZ05
      DOUBLE PRECISION DC
      DOUBLE PRECISION DS
      COMMON/LG7COM/DX05,DZ05,DC,DS,N,IR,IM
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DR
      DOUBLE PRECISION DM
      DOUBLE PRECISION DZ
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DSUM1
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      DN=DBLE(N)
      DR=DBLE(IR)
      DM=DBLE(IM)
!
      DTERM1=(DLOG(DC/DXQ)/DS) + DZ05
      CALL NODPDF(DTERM1,DTERM2)
      CALL NODCDF(DTERM1,DTERM3)
!
      DSUM1=0.0D0
      DO 100 I=1,IR
        DZ=DLOG(DX(I)/DXQ)
        DSUM1=DSUM1 + (DZ + DS*DZ05)*DZ
  100 CONTINUE
!
      LG7FUN=(1.0D0/DS**2)*DSUM1 +   &
             (DM/DS)*DLOG(DC/DXQ)*DTERM2/(1.0D0-DTERM3) - DR
!
      RETURN
      END FUNCTION LG7FUN 
      SUBROUTINE LGACDF(X,GAMMA,ILGADF,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE LOG-GAMMA DISTRIBUTION
!              WITH POSITIVE SHAPE PARAMETER GAMMA
!              THIS DISTRIBUTION IS DEFINED FOR ALL REAL X.
!              THE PDF FOR THE STANDARD FORM OF THE DISTRIBUTION IS
!                  F(X,G) = EXP(G*X-EXP(X))/GAMMA(G)
!              WHERE GAMMA IS THE GAMMA FUNCTION.
!              THE CORRESPONDING CDF IS:
!                  F(X,G) = I(EXP(Y)(GAMMA)
!              WHERE I(X)(GAMMA) IS THE INCOMPLETE GAMMA FUNCTION RATIO
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE NON-NEGATIVE.
!                     --GAMMA  = A POSITIVE SHAPE PARAMETER
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE LOG GAMMA DISTRIBUTION
!             WITH SHAPE PARAMETER GAMMA
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE.
!                 --GAMMA SHOULD BE A POSITIVE NUMBER.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 1994, PAGE 89-90.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--95/10
!     ORIGINAL VERSION--OCTOBER   1995.
!     UPDATED         --JULY      2005. SUPPORT FOR RE-PARAMETERIZED
!                                       DEFINITION THAT IS USEFUL FOR
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      CHARACTER*4 ILGADF
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DGAMMA
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DGAMIP
      DOUBLE PRECISION DTERM1
!
      EXTERNAL DGAMIP
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(GAMMA.LE.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9999
      ENDIF
   15 FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO THE ',   &
      'LGACDF SUBROUTINE IS NON-POSITIVE')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
!
      DX=DBLE(X)
      DGAMMA=DBLE(GAMMA)
!
      IF(ILGADF.EQ.'DEFA')THEN
        DCDF=DGAMIP(DGAMMA,DEXP(DX))
      ELSE
        DTERM1=DGAMMA*DEXP(DX/DSQRT(DGAMMA))
        DCDF=DGAMIP(DGAMMA,DTERM1)
      ENDIF
      CDF=REAL(DCDF)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE LGACDF
      SUBROUTINE LGAPDF(X,GAMMA,ILGADF,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE LOG-GAMMA DISTRIBUTION
!              WITH POSITIVE SHAPE PARAMETER GAMMA
!              THIS DISTRIBUTION IS DEFINED FOR ALL REAL X.
!              THE PDF FOR THE STANDARD FORM OF THE DISTRIBUTION IS
!                  F(X,G) = EXP(G*X-EXP(X))/GAMMA(G)
!              WHERE GAMMA IS THE GAMMA FUNCTION.
!
!              FOR FITTING PURPOSES, THE FOLLOWING REPARAMETERIZED
!              PDF IS OFTEN PREFERRED:
!                  F(X,G) = (G**(G-0.5)/GAMMA(G)*
!                           EXP(SQRT(G)*X-G*EXP(X/SQRT(G)))
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE NON-NEGATIVE.
!                     --GAMMA  = A POSITIVE SHAPE PARAMETER
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE LOG GAMMA DISTRIBUTION
!             WITH SHAPE PARAMETER GAMMA
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE.
!                 --GAMMA SHOULD BE A POSITIVE NUMBER.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 1994, PAGE 89-90.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--95/10
!     ORIGINAL VERSION--OCTOBER   1995.
!     UPDATED         --JULY      2005. SUPPORT FOR RE-PARAMETERIZED
!                                       DEFINITION THAT IS USEFUL FOR
!                                       FITTING
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      CHARACTER*4 ILGADF
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DGAMMA
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DLNGAM
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(GAMMA.LE.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ENDIF
   15 FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO THE ',   &
      'LGAPDF SUBROUTINE IS NON-POSITIVE')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
!
      DX=DBLE(X)
      DGAMMA=DBLE(GAMMA)
!
      IF(ILGADF.EQ.'DEFA')THEN
        DTERM1=DGAMMA*DX - DEXP(DX)
        DTERM2=DTERM1-DLNGAM(DGAMMA)
        DPDF=0.0D0
        IF(DTERM2.GE.-80.0D0)DPDF=DEXP(DTERM2)
        PDF=REAL(DPDF)
      ELSE
        DTERM1=(DGAMMA - 0.5D0)*DLOG(DGAMMA) - DLNGAM(DGAMMA)
        DTERM2=DSQRT(DGAMMA)*DX - DGAMMA*DEXP(DX/DSQRT(DGAMMA))
        DTERM3=DTERM1 + DTERM2
        DPDF=0.0D0
        IF(DTERM3.GE.-80.0D0)DPDF=DEXP(DTERM3)
        PDF=REAL(DPDF)
      ENDIF
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE LGAPDF
      SUBROUTINE LGAPPF(P,GAMMA,ILGADF,PPF)
!
!     PURPOSE   --PERCENT POINT FUNCTION FOR THE LOG-GAMMA
!                 DISTRIBUTION.  USES A BISECTION METHOD.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--95/10
!     ORIGINAL VERSION--OCTOBER   1995.
!     UPDATED         --JULY      2005. SUPPORT FOR RE-PARAMETERIZED
!                                       DEFINITION THAT IS USEFUL FOR
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ILGADF
!
      INCLUDE 'DPCOP2.INC'
!
      DATA EPS /0.0001/
      DATA SIG /1.0E-5/
      DATA ZERO /0./
      DATA MAXIT /2000/
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(P.LE.0.0.OR.P.GE.1.0)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9999
      ENDIF
      IF(GAMMA.LE.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9999
      ENDIF
!
    1 FORMAT('***** ERROR--THE FIRST INPUT ARGUMENT TO THE ',   &
      ' LGAPPF SUBROUTINE IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL.')
   15 FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO THE ',   &
      'LGAPPF SUBROUTINE IS NON-POSITIVE *****')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
!
!
!  FIND BRACKETING INTERVAL.
!
      XL=-50.0
      XINC=25.0
      ICOUNT=0
      MAXCNT=10000
!
   91 CONTINUE
      XR=XL+XINC
      CALL LGACDF(XL,GAMMA,ILGADF,CDFL)
      CALL LGACDF(XR,GAMMA,ILGADF,CDFR)
      IF(CDFL.LT.P .AND. CDFR.LT.P)THEN
        XL=XR
      ELSEIF(CDFL.GT.P .AND. CDFR.GT.P)THEN
        XL=XL-XINC
      ELSE
        GO TO 99
      ENDIF
      ICOUNT=ICOUNT+1
      IF(ICOUNT.GT.MAXCNT)THEN
        WRITE(ICOUT,96)
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9999
      ENDIF
   96 FORMAT('***** ERROR--LGAPPF UNABLE TO FIND A BRACKETING ',   &
            'INTERVAL. *****')
      GO TO 91
!
!  BISECTION METHOD
!
   99 CONTINUE
      IC = 0
      FXL = -P
      FXR = 1.0 - P
  105 CONTINUE
      X = (XL+XR)*0.5
      CALL LGACDF(X,GAMMA,ILGADF,CDF)
      P1=CDF
      PPF=X
      FCS = P1 - P
      IF(FCS*FXL.GT.ZERO)GO TO 110
      XR = X
      FXR = FCS
      GO TO 115
  110 CONTINUE
      XL = X
      FXL = FCS
  115 CONTINUE
      XRML = XR - XL
      IF(XRML.LE.SIG .AND. ABS(FCS).LE.EPS)GO TO 9999
      IC = IC + 1
      IF(IC.LE.MAXIT)GO TO 105
      WRITE(ICOUT,130)
      CALL DPWRST('XXX','BUG ')
  130 FORMAT('***** ERROR--THE LGAPPF ROUTINE DID NOT CONVERGE. ***')
      GO TO 9999
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE LGAPPF
      SUBROUTINE LGARAN(N,GAMMA,ILGADF,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE LOG GAMMA DISTRIBUTION
!              WITH TAIL LENGTH PARAMETER VALUE = GAMMA.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --GAMMA  = THE SINGLE PRECISION VALUE OF THE
!                                TAIL LENGTH PARAMETER.
!                                GAMMA SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE LOG GAMMA DISTRIBUTION
!             WITH TAIL LENGTH PARAMETER VALUE = GAMMA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --GAMMA SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--XX
!               --JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 2ND. ED., 1994.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--2001.10
!     ORIGINAL VERSION--OCTOBER   2001.
!     UPDATED         --JULY      2005. SUPPORT FOR RE-PARAMETERIZED
!                                       DEFINITION THAT IS USEFUL FOR
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
      CHARACTER*4 ILGADF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
      IF(GAMMA.LE.0.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)GAMMA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    5 FORMAT('***** ERROR--THE REQUESTED NUMBER OF LOG GAMMA RANDOM',   &
      ' NUMBERS IS NON-POSITIVE.')
   15 FORMAT('***** ERROR--THE SHAPE PARAMETER FOR LOG GAMMA RANDOM',   &
      ' NUMBERS IS NON-POSITIVE.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,'.')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,'.')
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N LOG GAMMA DISTRIBUTION RANDOM NUMBERS
!     USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD.
!
      DO 100 I=1,N
        CALL LGAPPF(X(I),GAMMA,ILGADF,XTEMP)
        X(I)=XTEMP
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE LGARAN
      SUBROUTINE LGDCDF(DX,DSD,DCDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE LOGNORMAL DISTRIBUTION.
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE AT WHICH
!                                THE CUMULATIVE DISTRIBUTION FUNCTION IS
!                                TO BE EVALUATED (DX > 0).
!                    --DSD    = THE DOUBLE PRECISION VALUE FOR THE
!                               SHAPE PARAMETER
!     OUTPUT ARGUMENTS--DCDF  = THE DOUBLE PRECISION CUMULATIVE
!                               DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE DISTRIBUTION FUNCTION VALUE
!             DCDF FOR THE LOGNORMAL DISTRIBUTION.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--DX SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NODCDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DLOG.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES 112-136.
!               --CRAMER, MATHEMATICAL METHODS OF STATISTICS,
!                 1946, PAGES 219-220.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2899
!     ORIGINAL VERSION--MARCH     2014.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DSD
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DARG
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      DCDF=0.0
      IF(DX.LE.0.0D0)THEN
        GO TO 9000
      ELSEIF(DSD.LE.0.0D0)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DSD
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    5 FORMAT('***** ERROR--THE SECOND ARGUMENT TO LGNCDF IS ',   &
             'NON-POSITIVE.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!-----START POINT-----------------------------------------------------
!
      IF(DSD.EQ.1.0D0)THEN
        DARG=DLOG(DX)
        CALL NODCDF(DARG,DCDF)
      ELSE
        DARG=DLOG(DX)/DSD
        CALL NODCDF(DARG,DCDF)
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE LGDCDF
      SUBROUTINE LGNLI1(Y,N,ALOC,SCALE,SHAPE,   &
                        ALIK,AIC,AICC,BIC,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE LIKELIHOOD FUNCTION FOR
!              THE LOGNORMAL DISTRIBUTION.  THIS IS FOR THE RAW DATA
!              CASE (I.E., NO GROUPING AND NO CENSORING).
!
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN ENGINEERING",
!                CAMBRIDGE UNIVERSITY PRESS, 1999, CHAPTER 11.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2014/3
!     ORIGINAL VERSION--MARCH     2014.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DLOC
      DOUBLE PRECISION DSCALE
      DOUBLE PRECISION DSHAPE
      DOUBLE PRECISION DN
      DOUBLE PRECISION DNP
      DOUBLE PRECISION DLIK
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DPDF
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='LGNL'
      ISUBN2='I1  '
      IWRITE='OFF'
      IERROR='NO'
!
      ALIK=CPUMIN
      AIC=CPUMIN
      AICC=CPUMIN
      BIC=CPUMIN
!
      IF(ALOC.EQ.CPUMIN)THEN
        ALOCT=0.0
      ELSE
        ALOCT=ALOC
      ENDIF
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'NLI1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF LGNLI1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO
   52   FORMAT('IBUGA3,ISUBRO = ',A4,2X,A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,55)N,ALOC,SCALE,SHAPE
   55   FORMAT('N,ALOC,SCALE,SHAPE = ',I8,3G15.7)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
      DO 110 I=1,N
        IF(Y(I).LE.ALOC)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,111)
  111     FORMAT('**** AT THE BEGINNING OF LGNLI1--')
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,113)I,Y(I),ALOC
  113     FORMAT('     THE VALUE FOR ROW ',I8,'(',G15.7,') IS LESS ',   &
                 'THAN THE LOCATION (',G15.7,')')
          CALL DPWRST('XXX','WRIT')
          IERROR='YES'
          GO TO 9000
        ENDIF
  110 CONTINUE
!
!               ******************************************
!               **  STEP 1--                            **
!               **  COMPUTE LIKELIHOOD FUNCTION         **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'NLI1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      DLIK=0.0D0
      DLOC=DBLE(ALOC)
      DSCALE=DBLE(SCALE)
      DSHAPE=DBLE(SHAPE)
      DN=DBLE(N)
!
      DO 1020 I=1,N
        DX=DBLE(Y(I))
        DX=(DX-DLOC)/DSCALE
        CALL LGDPDF(DX,DBLE(SHAPE),DPDF)
        DPDF=DPDF/DSCALE
        IF(DPDF.GT.0.0D0)THEN
          DLIK=DLIK + DLOG(DPDF)
        ELSE
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,111)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,1023)I
 1023     FORMAT('     FOR ROW ',I8,' A NON-POSITIVE PDF VALUE ',   &
                 'WAS ENCOUNTERED.')
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,1025)Y(I),DLOC
 1025     FORMAT('     Y(I),LOCATION VALUE = ',2G15.7)
          CALL DPWRST('XXX','WRIT')
          IERROR='YES'
          GO TO 9000
        ENDIF
 1020 CONTINUE
!
      ALIK=REAL(DLIK)
      DNP=2.0D0
      EPS=1.0E-7
      IF(ABS(ALOCT).GT.EPS)DNP=3.0D0
      AIC=REAL(-2.0D0*DLIK + 2.0D0*DNP)
      DTERM3=(2.0D0*DNP*(DNP+1.0D0))/(DN-DNP-1.0D0)
      AICC=REAL(-2.0D0*DLIK + 2.0D0*DNP + DTERM3)
      BIC=REAL(-2.0D0*DLIK + DNP*LOG(DN))
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'NLI1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF LGNLI1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9014)ALIK,AIC,AICC,BIC
 9014   FORMAT('ALIK,AIC,AICC,BIC = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE LGNLI1
      SUBROUTINE LGDPDF(DX,DSD,DPDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE LOGNORMAL DISTRIBUTION
!              (DOUBLE PRECISION VERSION).
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE AT WHICH
!                                THE PROBABILITY DENSITY FUNCTION IS
!                                TO BE EVALUATED (DX > 0).
!                    --DSD    = THE DOUBLE PRECISION VALUE FOR THE
!                               SHAPE PARAMETER
!     OUTPUT ARGUMENTS--DPDF  = THE DOUBLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY DENSITY FUNCTION VALUE
!             DPDF FOR THE LOGNORMAL DISTRIBUTION.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--DX SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NODPDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DLOG.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES 112-136.
!               --CRAMER, MATHEMATICAL METHODS OF STATISTICS,
!                 1946, PAGES 219-220.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--MARCH     2014.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DSD
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DARG
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      DPDF=0.0D0
      IF(DX.LT.0.0D0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DX
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(DSD.LE.0.0D0)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DSD
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    4 FORMAT('***** ERROR--THE FIRST ARGUMENT TO LGNPDF IS NEGATIVE.')
    5 FORMAT('***** ERROR--THE SECOND ARGUMENT TO LGNPDF IS ',   &
             'NON-POSITIVE.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!-----START POINT-----------------------------------------------------
!
      IF(DX.GT.0.0D0)THEN
        IF(DSD.EQ.1.0D0)THEN
          DARG=DLOG(DX)
          CALL NODPDF(DARG,DPDF)
          DPDF=(1.0D0/DX)*DPDF
        ELSE
          DARG=DLOG(DX)/DSD
          CALL NODPDF(DARG,DPDF)
          DPDF=(1.0D0/(DSD*DX))*DPDF
        ENDIF
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE LGDPDF
      SUBROUTINE LGDPPF(DP,DSD,DPPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT FUNCTION FOR
!              FOR THE LOGNORMAL DISTRIBUTION.
!     INPUT  ARGUMENTS--DP     = THE DOUBLE PRECISION VALUE AT WHICH
!                                THE PERCENT POINT FUNCTION IS
!                                TO BE EVALUATED (0 <= DP < 1).
!                    --DSD    = THE DOUBLE PRECISION VALUE FOR THE
!                               SHAPE PARAMETER
!     OUTPUT ARGUMENTS--DPDF  = THE DOUBLE PRECISION PERCENT POINT
!                               FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PERCENT POINT FUNCTION VALUE
!             DPPF FOR THE LOGNORMAL DISTRIBUTION.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--P SHOULD BE BETWEEN 0.0 (INCLUSIVELY)
!                   AND 1.0 (EXCLUSIVELY).
!     OTHER DATAPAC   SUBROUTINES NEEDED--NODPPF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES 112-136.
!               --CRAMER, MATHEMATICAL METHODS OF STATISTICS,
!                 1946, PAGES 219-220.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2899
!     ORIGINAL VERSION--MARCH     2014.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DP
      DOUBLE PRECISION DSD
      DOUBLE PRECISION DPPF
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      DPPF=0.0D0
      IF(DP.LT.0.0D0 .OR. DP.GE.1.0D0)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DP
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(DSD.LE.0.0D0)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DSD
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    1 FORMAT('***** ERROR--THE FIRST ARGUMENT TO LGNPPF IS OUTSIDE ',   &
             'THE ALLOWABLE (0,1) INTERVAL.')
    5 FORMAT('***** ERROR--THE SECOND ARGUMENT TO LGNPDF IS ',   &
             'NON-POSITIVE.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!-----START POINT-----------------------------------------------------
!
      IF(DP.GT.0.0D0)THEN
        IF(DSD.EQ.1.0D0)THEN
          CALL NODPPF(DP,DPPF)
          DPPF=DEXP(DPPF)
        ELSE
          CALL NODPPF(DP,DPPF)
          DPPF=DEXP(DPPF*DSD)
        ENDIF
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE LGDPPF
      SUBROUTINE LGNAFR(X1,X2,SIGMA,ALOC,SCALE,AFR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE AVERAGE FAILURE RATE
!              (AFR) FUNCTION VALUE FOR THE LOGNORMAL DISTRIBUTION.
!              THE AFR IS DEFINED AS:
!
!              AFR(X1,X2,SHAPE,LOC,SCALE) = (H(X2,SHAPE,LOC,SCALE) -
!                                            H(X1,LOC,SCALE))/(X2-X1)
!
!              WHERE
!
!              H(X,SHAPE,LOC,SCALE) = H((X-LOC)/SCALE,SHAPE)
!
!              FOR THE LOGNORMAL, WE USE THE LGNCHA FUNCTION.
!
!     INPUT  ARGUMENTS--X1     = THE SINGLE PRECISION VALUE AT
!                                WHICH THE AFR FUNCTION IS TO BE
!                                EVALUATED.
!                     --X2     = THE SINGLE PRECISION VALUE AT
!                                WHICH THE AFR FUNCTION IS TO BE
!                                EVALUATED.
!                     --SIGMA  = THE (POSITIVE) SHAPE PARAMETER
!                     --ALOC   = THE LOCATION PARAMETER
!                     --SCALE  = THE (POSITIVE) SCALE PARAMETER
!     OUTPUT ARGUMENTS--AFR    = THE SINGLE PRECISION AVERAGE
!                                FAILURE RATE FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION AVERAGE FAILURE RATE FOR THE
!             LOGNORMAL DISTRIBUTION.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--SIGMA AND SCALE SHOULD BE POSITIVE, X2 NOT EQUAL X1.
!     OTHER DATAPAC   SUBROUTINES NEEDED--LGNCHA.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--TOBIAS AND TRINDALE, "APPLIED RELIABILITY", SECOND
!                 EDITION, CHAPMAN AND HALL/CRC, 1995.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2005.3
!     ORIGINAL VERSION--MARCH     2005.
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      X1MN=MIN(X1,X2)
      X1MX=MAX(X1,X2)
      IF(X1MN.EQ.X1MX)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)X1MN
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,48)X1MX
        CALL DPWRST('XXX','BUG ')
        AFR=0.0
        GO TO 9000
      ELSEIF(X1MN.LT.ALOC)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X1MN
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,49)ALOC
        CALL DPWRST('XXX','BUG ')
        AFR=0.0
        GO TO 9000
      ELSEIF(SIGMA.LE.0.0)THEN
        WRITE(ICOUT,8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)SIGMA
        CALL DPWRST('XXX','BUG ')
        AFR=0.0
        GO TO 9000
      ELSEIF(SCALE.LE.0.0)THEN
        WRITE(ICOUT,6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)SCALE
        CALL DPWRST('XXX','BUG ')
        AFR=0.0
        GO TO 9000
      ENDIF
    4 FORMAT('***** ERROR--THE FIRST INPUT ARGUMENT TO LGNAFR ',   &
             'IS LESS THAN THE LOCATION')
    5 FORMAT('***** ERROR--THE FIRST AND SECOND INPUT ARGUMENTS TO ',   &
             'LGNAFR ARE EQUAL')
    6 FORMAT('***** ERROR--THE FIFTH INPUT ARGUMENT TO LGNAFR ',   &
             '(THE SCALE) IS NON-POSITIVE')
    8 FORMAT('***** ERROR--THE THIRD INPUT ARGUMENT TO LGNAFR ',   &
             '(THE SHAPE) IS NON-POSITIVE')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
   47 FORMAT('***** THE VALUE OF THE FIRST ARGUMENT IS ',G15.7)
   48 FORMAT('***** THE VALUE OF THE SECOND ARGUMENT IS ',G15.7)
   49 FORMAT('***** THE VALUE OF THE LOCATION PARAMETER IS ',G15.7)
!
      IF(X1MN.LT.ALOC)THEN
         AFR=0.0
      ELSE IF(X1MN.EQ.ALOC)THEN
         TERM1=(X1MX-ALOC)/SCALE
         CALL LGNCHA(TERM1,SIGMA,CHAZ1)
         AFR=CHAZ1/(X1MX - X1MN)
      ELSE
         TERM1=(X1MX-ALOC)/SCALE
         CALL LGNCHA(TERM1,SIGMA,CHAZ1)
         TERM2=(X1MN-ALOC)/SCALE
         CALL LGNCHA(TERM2,SIGMA,CHAZ2)
         AFR=(CHAZ1 - CHAZ2)/(X1MX - X1MN)
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE LGNAFR
      SUBROUTINE LGNCDF(X,SD,CDF)
!CCCC SUBROUTINE LGNCDF(X,CDF)
!CCCC APRIL 1995.  SUPPORT SHAPE PARAMETER
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE LOGNORMAL
!              DISTRIBUTION.
!              THE LOGNORMAL DISTRIBUTION USED
!              HEREIN HAS MEAN = SQRT(E) = 1.64872127
!              AND STANDARD DEVIATION = SQRT(E*(E-1)) = 2.16119742.
!              THIS DISTRIBUTION IS DEFINED FOR ALL POSITIVE X
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              F(X) = (1/(X*SQRT(2*PI))) * EXP(-LOG(X)*LOG(X)/2)
!              THE LOGNORMAL DISTRIBUTION USED HEREIN
!              IS THE DISTRIBUTION OF THE VARIATE X = EXP(Z) WHERE
!              THE VARIATE Z IS NORMALLY DISTRIBUTED
!              WITH MEAN = 0 AND STANDARD DEVIATION = 1.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE LOGNORMAL
!             DISTRIBUTION WITH MEAN = SQRT(E) = 1.64872127
!             AND STANDARD DEVIATION = SQRT(E*(E-1)) = 2.16119742.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NORCDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES 112-136.
!               --CRAMER, MATHEMATICAL METHODS OF STATISTICS,
!                 1946, PAGES 219-220.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-921-2315
!     ORIGINAL VERSION--APRIL     1994.
!     UPDATED         --JANUARY   1995. DEFINE X = 0 CASE AS 0
!     UPDATED         --APRIL     1995. SHAPE PARAMETER
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      CDF=0.0
      IF(X.LT.0.0)THEN
!CCCC   WRITE(ICOUT,4)
!CCC4 FORMAT('***** WARNING--THE FIRST ARGUMENT TO LGNCDF IS NEGATIVE.')
!CCCC   CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!-----START POINT-----------------------------------------------------
!
      IF(X.GT.0.0)THEN
        IF(SD.EQ.1.0)THEN
          ARG=LOG(X)
          CALL NORCDF(ARG,CDF)
        ELSE
          ARG=LOG(X)/SD
          CALL NORCDF(ARG,CDF)
        ENDIF
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE LGNCDF
      SUBROUTINE LGNCHA(X,SD,HAZ)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE HAZARD
!              FUNCTION VALUE FOR THE LOGNORMAL
!              DISTRIBUTION.
!              THE LOGNORMAL DISTRIBUTION USED
!              HEREIN HAS MEAN = SQRT(E) = 1.64872127
!              AND STANDARD DEVIATION = SQRT(E*(E-1)) = 2.16119742.
!              THIS DISTRIBUTION IS DEFINED FOR ALL POSITIVE X
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              F(X) = (1/(X*SQRT(2*PI))) * EXP(-LOG(X)*LOG(X)/2)
!              THE LOGNORMAL DISTRIBUTION USED HEREIN
!              IS THE DISTRIBUTION OF THE VARIATE X = EXP(Z) WHERE
!              THE VARIATE Z IS NORMALLY DISTRIBUTED
!              WITH MEAN = 0 AND STANDARD DEVIATION = 1.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE CUMULATIVE HAZARD
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--HAZ    = THE SINGLE PRECISION CUMULATIVE HAZARD
!                                FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE HAZARD
!             FUNCTION VALUE FOR THE LOGNORMAL
!             DISTRIBUTION WITH MEAN = SQRT(E) = 1.64872127
!             AND STANDARD DEVIATION = SQRT(E*(E-1)) = 2.16119742.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE POSITIVE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES 112-136.
!               --CRAMER, MATHEMATICAL METHODS OF STATISTICS,
!                 1946, PAGES 219-220.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--APRIL     1998.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DSD
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DHAZ
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      HAZ=0.0
      IF(X.LT.0.0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    4 FORMAT('***** WARNING--THE FIRST ARGUMENT TO LGNCHA IS NEGATIVE.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!-----START POINT-----------------------------------------------------
!
      IF(X.GT.0.0)THEN
        DX=DBLE(X)
        DSD=DBLE(SD)
        CALL NODCDF(DLOG(DX)/DSD,DCDF)
        DCDF=1.0D0-DCDF
        IF(DCDF.GT.0.0D0)THEN
          DHAZ=-DLOG(DCDF)
          HAZ=REAL(DHAZ)
        ELSE
          HAZ=0.0
          WRITE(ICOUT,901)X
  901     FORMAT('****ERROR FROM LGNHAZ: FOR X = ',E15.7,' THE CDF ',   &
                 'VALUE IS ESSENTIALLY 1.')
          CALL DPWRST('XXX','BUG ')
        ENDIF
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE LGNCHA
      DOUBLE PRECISION FUNCTION LGNFU3 (DLOCML,X)
!
!     PURPOSE--THIS ROUTINE IS USED IN FINDING THE MAXIMUM LIKELIHOOD
!              ESTIMATE OF THE LOCATION PARAMETER FOR THE 3-PARAMETER
!              LOGNORMAL MODEL FOR FULL SAMPLE DATA (NO CENSORING).  THIS
!              FUNCTION FINDS THE ROOT OF THE EQUATION:
!
!                 SUM[1/(X(i) - LOC)]*{SUM[LOG(X(i) - LOC] -
!                 SUM[LOG((X(i) - LOC)**2] +
!                 (1/N)*{SUM[LOG(X(i)) - LOC)]**2] -
!                 N*SUM[LOG(X(i) - LOC)/(X(i) - LOC)] = 0
!
!              WHERE ALL SUMMATIONS ARE FROM 1 TO N AND WITH LOC
!              DENOTING THE ESTIMATE OF THE LOCATION PARAMETER.
!
!              CALLED BY DFZER2 ROUTINE FOR FINDING THE ROOT OF A
!              FUNCTION.
!     EXAMPLE--3-PARAMETER LOGNORMAL MAXIMUM LIKELIHOOD Y
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN
!                ENGINEERING", CAMBRIDGE UNIVERSITY PRESS,
!                1999, CHAPTER 13.
!              --COHEN AND WHITTEN (1988), "PARAMETER ESTIMATION IN
!                RELIABILITY AND LIFE SPAN MODELS", MARCEL DEKKER, INC.,
!                CHAPTER 4.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2014/04
!     ORIGINAL VERSION--APRIL      2014.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DLOCML
      DOUBLE PRECISION X(*)
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DSUM3
      DOUBLE PRECISION DSUM4
      DOUBLE PRECISION DS11
      DOUBLE PRECISION DS22
      DOUBLE PRECISION DX
      DOUBLE PRECISION DL
      DOUBLE PRECISION DN
!
      INTEGER IN
      COMMON/LGNMLE/IN
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  COMPUTE SOME SUMS
!
      DSUM1=0.0D0
      DSUM2=0.0D0
      DSUM3=0.0D0
      DSUM4=0.0D0
      DN=DBLE(IN)
!
      DO 100 I=1,IN
        DX=X(I) - DLOCML
        DL=DLOG(DX)
        DSUM1=DSUM1 + DL
        DSUM2=DSUM2 + DL**2
        DSUM3=DSUM3 + (1.0D0/DX)
        DSUM4=DSUM4 + DL/DX
  100 CONTINUE
!
      DS11=DSUM1/DN
      DS22=(DSUM2/DN) - DS11**2
      LGNFU3=DSUM3*(DS11-DS22) - DSUM4
!
      RETURN
      END FUNCTION LGNFU3 
      SUBROUTINE LGNHAZ(X,SD,HAZ)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE LOGNORMAL
!              FUNCTION VALUE FOR THE LOGNORMAL
!              DISTRIBUTION.
!              THE LOGNORMAL DISTRIBUTION USED
!              HEREIN HAS MEAN = SQRT(E) = 1.64872127
!              AND STANDARD DEVIATION = SQRT(E*(E-1)) = 2.16119742.
!              THIS DISTRIBUTION IS DEFINED FOR ALL POSITIVE X
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              F(X) = (1/(X*SQRT(2*PI))) * EXP(-LOG(X)*LOG(X)/2)
!              THE LOGNORMAL DISTRIBUTION USED HEREIN
!              IS THE DISTRIBUTION OF THE VARIATE X = EXP(Z) WHERE
!              THE VARIATE Z IS NORMALLY DISTRIBUTED
!              WITH MEAN = 0 AND STANDARD DEVIATION = 1.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE HAZARD
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--HAZ    = THE SINGLE PRECISION HAZARD
!                                FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION HAZARD
!             FUNCTION VALUE PDF FOR THE LOGNORMAL
!             DISTRIBUTION WITH MEAN = SQRT(E) = 1.64872127
!             AND STANDARD DEVIATION = SQRT(E*(E-1)) = 2.16119742.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE POSITIVE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES 112-136.
!               --CRAMER, MATHEMATICAL METHODS OF STATISTICS,
!                 1946, PAGES 219-220.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--APRIL     1998.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DXLOG
      DOUBLE PRECISION DHAZ
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DTERM4
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      HAZ=0.0
      IF(X.LT.0.0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    4 FORMAT('***** WARNING--THE FIRST ARGUMENT TO LGNHAZ IS NEGATIVE.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!-----START POINT-----------------------------------------------------
!
      IF(X.GT.0.0)THEN
        DX=DBLE(X)
        DXLOG=DLOG(DX)
        DTERM1=-DXLOG/DBLE(SD)
        CALL NODCDF(DTERM1,DTERM2)
        IF(DTERM2.NE.0.0D0)THEN
          DTERM3=DXLOG/DBLE(SD)
          CALL NODPDF(DTERM3,DTERM4)
          DHAZ=1.D0/(DX*DBLE(SD))*DTERM4/DTERM2
          HAZ=REAL(DHAZ)
        ELSE
          HAZ=0.0
          WRITE(ICOUT,901)X
  901     FORMAT('****ERROR FROM LGNHAZ: FOR X = ',E15.7,' THE CDF ',   &
                 'VALUE IS ESSENTIALLY 1.')
          CALL DPWRST('XXX','BUG ')
        ENDIF
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE LGNHAZ
      SUBROUTINE LGNML1(Y,N,MAXNXT,   &
                        TEMP1,   &
                        XMEAN,XMED,XSD,XVAR,XMIN,XMAX,XMEANL,XSDL,   &
                        SCALML,SCALSE,SHAPML,SHAPSE,UHATML,UHATSE,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE MAXIMUM LIKELIHOOD ESTIMATES
!              FOR THE 2-PARAMETER LOGNORMAL DISTRIBUTION FOR THE RAW DATA
!              CASE (I.E., NO CENSORING AND NO GROUPING).  THIS ROUTINE
!              RETURNS ONLY THE POINT ESTIMATES (CONFIDENCE INTERVALS
!              WILL BE COMPUTED IN A SEPARATE ROUTINE).
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!              PUT THIS IN A SEPARATE ROUTINE AS IT MAY BE CALLED
!              FROM MULTIPLE PLACES (DPMLL1 WILL GENERATE THE OUTPUT
!              FOR THE LOGNORMAL MLE COMMAND).
!
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN
!                ENGINEERING", CAMBRIDGE UNIVERSITY PRESS,
!                1999, CHAPTER 13.
!              --"STATISTICAL DISTRIBUTIONS", THIRD EDITION,
!                EVANS, HASTINGS, AND PEACOCK, WILEY, 2001.
!              --"METHODS FOR STATISTICAL ANALYSIS OF RELIABILITY
!                AND LIFE DATA", MANN, SCHAFER, AND SINGPURWALLA,
!                WILEY, 1974, PP. 264-268.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/2
!     ORIGINAL VERSION--FEBRUARY  2010. EXTRACTED AS A SEPARATE
!                                       SUBROUTINE (FROM DPMLE1)
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DIMENSION Y(*)
      DIMENSION TEMP1(*)
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*40 IDIST
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='LGNM'
      ISUBN2='L1  '
      IERROR='NO'
      IWRITE='OFF'
!
      AN=REAL(N)
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'NML1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF LGNML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO
   52   FORMAT('IBUGA3,ISUBRO = ',A4,2X,A4)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  CARRY OUT CALCULATIONS              **
!               **  FOR LOGNORMAL MLE ESTIMATE          **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'NML1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IDIST='LOGNORMAL'
!
      IFLAG=2
      CALL SUMRAW(Y,N,IDIST,IFLAG,   &
                  XMEAN,XVAR,XSD,XMIN,XMAX,   &
                  ISUBRO,IBUGA3,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
      CALL MEDIAN(Y,N,IWRITE,TEMP1,MAXNXT,XMED,IBUGA3,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      SHAPML=CPUMIN
      SHAPSE=CPUMIN
      SCALML=CPUMIN
      SCALSE=CPUMIN
      UHATML=CPUMIN
      UHATSE=CPUMIN
!
!     THE MAXIMUM LIKELIHOOD ESTIMATES ARE:
!
!     NOTE THAT A COMMON PARAMETERIZATION USES
!
!         U = LOG(SCALE)
!
!     UHAT      = (1/N)*SUM[i=1 to N][LOG(Y(I))]
!     SCALEHAT  = EXP(UHAT)
!     SIGMAHAT  = SQRT((1/N)*SUM[i=1 to N][(LOG(Y(I)) - UHAT)**2]
!
!     COMPUTE SOME SAMPLE STATISTICS ON LOG OF DATA
!
      DO 4103 I=1,N
        TEMP1(I)=LOG(Y(I))
 4103 CONTINUE
!
      CALL MEAN(TEMP1,N,IWRITE,XMEANL,IBUGA3,IERROR)
      CALL SD(TEMP1,N,IWRITE,XSDL,IBUGA3,IERROR)
!
!     COMPUTE MLE ESTIMATES
!
      UHATML=XMEANL
      SCALML=EXP(XMEANL)
      SHAPML=XSDL
!
!     COMPUTE STANDARD ERRORS
!
      UHATSE=SHAPML/SQRT(AN)
      SCALSE=EXP(UHATML + UHATSE) - EXP(UHATML)
      SHAPSE=SHAPML/SQRT(2.0*(AN-1.0))
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'NML1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF LGNML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)N,XMEAN,XMED,XSD,XMIN,XMAX
 9013   FORMAT('N,XMEAN,XMED,XSD,XMIN,XMAX = ',I8,5G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9015)XMEANL,XSDL
 9015   FORMAT('XMEANL,XSDL = ',2G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9017)SHAPML,SCALML,SHAPSE,SCALSE
 9017   FORMAT('SHAPML,SCALML,SHAPSE,SCALSE =  ',4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9019)UHATML,UHATSE
 9019   FORMAT('UHATML,UHATSE =  ',2G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE LGNML1
      SUBROUTINE LGNML2(Y,TAG,N,MAXNXT,   &
                        ICASE,IDIST,   &
                        TEMP1,XTEMP,DTEMP1,ITEMP,   &
                        XMEANF,XSDF,XVARF,XMINF,XMAXF,XMEDF,   &
                        XMEANC,XSDC,XVARC,XMINC,XMAXC,XMEDC,   &
                        SCALML,UHATML,UHATSE,SHAPML,SHAPSE,COVSE,   &
                        IRSAV,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE MAXIMUM LIKELIHOOD ESTIMATES
!              FOR THE 2-PARAMETER LOGNORMAL DISTRIBUTION FOR THE RAW DATA
!              CASE WITH CENSORING (BUT NO GROUPING).  THIS ROUTINE
!              RETURNS ONLY THE POINT ESTIMATES (CONFIDENCE INTERVALS
!              WILL BE COMPUTED IN A SEPARATE ROUTINE).
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!              PUT THIS IN A SEPARATE ROUTINE AS IT MAY BE CALLED
!              FROM MULTIPLE PLACES (DPMLL2 WILL GENERATE THE OUTPUT
!              FOR THE LOGNORMAL MLE COMMAND).
!
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN
!                ENGINEERING", CAMBRIDGE UNIVERSITY PRESS,
!                1999, CHAPTER 11.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/7
!     ORIGINAL VERSION--JULY      2010. EXTRACTED AS A SEPARATE
!                                       SUBROUTINE (FROM DPMLL2)
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DIMENSION Y(*)
      DIMENSION TAG(*)
      DIMENSION TEMP1(*)
      DIMENSION XTEMP(*)
      DOUBLE PRECISION DTEMP1(*)
      INTEGER ITEMP(*)
!
      CHARACTER*4 ICASE
      CHARACTER*40 IDIST
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
      CHARACTER*4 IWRITE
!
      DOUBLE PRECISION LG1FUN
      EXTERNAL LG1FUN
!
      DOUBLE PRECISION C
      INTEGER IN
      INTEGER IM
      COMMON/LG1COM/C,IN,IM
!
      DOUBLE PRECISION TOL
      DOUBLE PRECISION XPAR(2)
      DOUBLE PRECISION FVEC(2)
!
      DIMENSION FISH(2,2)
      DIMENSION COV(2,2)
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DR
      DOUBLE PRECISION DM
      DOUBLE PRECISION DX
      DOUBLE PRECISION DS
      DOUBLE PRECISION DU
      DOUBLE PRECISION DZ
      DOUBLE PRECISION DH
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='LGNM'
      ISUBN2='L2  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'NML2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF LGNML2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,ICASE,N,MAXNXT
   52   FORMAT('IBUGA3,ISUBRO,N,MAXNXT = ',3(A4,2X),2I8)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I),TAG(I)
   57     FORMAT('I,Y(I),TAG(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  CARRY OUT CALCULATIONS              **
!               **  FOR CENSORD LOGNORMAL MLE ESTIMATE  **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'NML2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IDIST='LOGNORMAL'
!
      CALL CKCENS(TAG,TEMP1,N,IDIST,   &
                  ISUBRO,IBUGA3,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IFLAG=1
      CALL SUMRAW(Y,N,IDIST,IFLAG,   &
                  XMEANF,XVARF,XSDF,XMINF,XMAXF,   &
                  ISUBRO,IBUGA3,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
      CALL MEDIAN(Y,N,IWRITE,TEMP1,MAXNXT,XMEDF,IBUGA3,IERROR)
!
      CALL SORTC(Y,TAG,N,Y,TAG)
      IR=0
      DO 2120 I=1,N
        IF(TAG(I).EQ.1.0)IR=IR+1
 2120 CONTINUE
      IRSAV=IR
!
      ICNT=0
      DO 2122 I=1,N
        IF(TAG(I).EQ.1.0)THEN
          ICNT=ICNT+1
          XTEMP(ICNT)=Y(I)
        ENDIF
 2122 CONTINUE
      DO 2124 I=1,N
        IF(TAG(I).EQ.0.0)THEN
          ICNT=ICNT+1
          XTEMP(ICNT)=Y(I)
        ENDIF
 2124 CONTINUE
      DO 2126 I=1,N
        Y(I)=XTEMP(I)
        IF(I.LE.IR)THEN
          TAG(I)=1.0
        ELSE
          TAG(I)=0.0
        ENDIF
 2126 CONTINUE
      IM=N-IR
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'NML2')THEN
        WRITE(ICOUT,2127)N,IR,IM
 2127   FORMAT(1X,'N,IR,IM = ',3I8)
        CALL DPWRST('XXX','BUG ')
        DO 2128 I=1,MIN(100,N)
          WRITE(ICOUT,2129)I,Y(I),TAG(I)
 2129     FORMAT(1X,'I,Y(I),TAG(I)=',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
 2128   CONTINUE
      ENDIF
!
      IR1=IR
      IR2=IR
      IR3=IR
!
      AR=REAL(IR)
      DR=DBLE(IR)
      AN=REAL(N)
      AM=REAL(IM)
!
      IF(IM.EQ.0)THEN
        ICASE='NONE'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2131)
 2131   FORMAT('***** WARNING FROM LOGNORMAL MAXIMUM LIKELIHOOD--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2133)
 2133   FORMAT('      NO CENSORING TIMES DETECTED.  IT IS RECOMMENDED')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2135)
 2135   FORMAT('      THAT THE FULL SAMPLE SYNTAX BE USED:')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2137)
 2137   FORMAT('      LOGNORMAL MAXIMUM LIKELIHOOD  Y')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
      ELSE
        ICASE='SING'
        AHOLD=Y(IR+1)
        DO 2140 I=IR+1,N
          IF(Y(I).NE.AHOLD)THEN
            ICASE='MULT'
            GO TO 2149
          ENDIF
 2140   CONTINUE
 2149   CONTINUE
        C=DBLE(AHOLD)
      ENDIF
!
      IF(ICASE.EQ.'MULT')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2141)
 2141   FORMAT('***** ERROR FROM LOGNORMAL MAXIMUM LIKELIHOOD--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2143)
 2143   FORMAT('      CURRENTLY, ONLY SINGLY CENSORED DATA IS ',   &
               'SUPPORTED FOR THE LOGNORMAL DISTRIBUTION.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,2145)
 2145   FORMAT('      MULTIPLY CENSORED DATA WAS DETECTED.')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ************************************
!               **  STEP 41--                     **
!               **  CARRY OUT CALCULATIONS        **
!               **  FOR LOGNORMAL MLE             **
!               **  ESTIMATE (TIME CENSORED CASE) **
!               ************************************
!
!     THE MAXIMUM LIKELIHOOD EQUATIONS ARE SOLVED USING THE DNSQE
!     ROUTINE.
!
!
      ISTEPN='31'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'NML2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IERROR='NO'
      IWRITE='OFF'
!
!     COMPUTE STATISTICS FOR FAILURE ONLY DATA
!
      ISTEPN='32'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MLL2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL MEAN(Y,IR,IWRITE,AMEAN,IBUGA3,IERROR)
      CALL MEDIAN(Y,IR,IWRITE,XTEMP,MAXNXT,XMEDC,IBUGA3,IERROR)
      CALL SD(Y,IR,IWRITE,ASD,IBUGA3,IERROR)
      CALL MINIM(Y,IR,IWRITE,AMIN,IBUGA3,IERROR)
      CALL MAXIM(Y,IR,IWRITE,AMAX,IBUGA3,IERROR)
      XMEANC=AMEAN
      XSDC=ASD
      XVARC=SQRT(ASD)
      XMINC=AMIN
      XMAXC=AMAX
!
      ISTEPN='32B'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'NML2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!  USE PARAMETERS ESTIMATED FROM FAILURE DATA AS STARTING VALUES
!  FOR EQUATION SOLVER.
!
      DO 3103 I=1,IR
        XTEMP(I)=LOG(Y(I))
 3103 CONTINUE
!
      CALL MEAN(XTEMP,IR,IWRITE,XMEAN,IBUGA3,IERROR)
      CALL SD(XTEMP,IR,IWRITE,XSD,IBUGA3,IERROR)
!
      XPAR(1)=DBLE(XMEAN)
      XPAR(2)=DBLE(XSD)
!
      IN=N
      JAC=0
      IOPT=2
      TOL=1.0D-6
      NVAR=2
      NPRINT=-1
      INFO=0
      LWA=MAXNXT
      FVEC(1)=0.0D0
      FVEC(2)=0.0D0
      CALL DNSQE(LG1FUN,JAC,IOPT,NVAR,XPAR,FVEC,TOL,NPRINT,INFO,   &
                 DTEMP1,MAXNXT,Y,IR)
!
      UHATML=REAL(XPAR(1))
      SCALML=EXP(UHATML)
      SIGMML=REAL(XPAR(2))
      SHAPML=SIGMML
!
      ISTEPN='33'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MLL2')THEN
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,2201)UHATML,SCALML,SIGMML
 2201   FORMAT('UHATML,SCALML,SIGMML = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
!  COMPUTE STANDARD ERRORS.  FORMULAS FOR LOCAL FISHER INFORMATION
!  MATRIX GIVEN ON PAGE 162 OF BURY.
!
      DN=DBLE(N)
      DR=DBLE(IR)
      DM=DBLE(IM)
      DS=DBLE(SIGMML)
      DU=DBLE(UHATML)
      DZ=(DLOG(C)-DU)/DS
      CALL NODPDF(DZ,DTERM1)
      CALL NODCDF(DZ,DTERM2)
      DH=DTERM1/(1.0D0 - DTERM2)
      DSUM1=0.0D0
      DSUM2=0.0D0
      DO 100 I=1,IR
        DX=DBLE(Y(I))
        DX=(DLOG(DX) - DU)/DS
        DSUM1=DSUM1 + DX
        DSUM2=DSUM2 + DX*DX
  100 CONTINUE
!
      DTERM1=(1.0D0/DS**2)*(DR + DM*DH*(DH-DZ))
      FISH(1,1)=REAL(DTERM1)
      DTERM1=(1.0D0/DS**2)*(2.0D0*DSUM1 +DM*DH*(1.0D0 + DZ*(DH-DZ)))
      FISH(2,1)=REAL(DTERM1)
      FISH(1,2)=FISH(2,1)
      DTERM1=(1.0D0/DS**2)*   &
             (3.0D0*DSUM2 +DM*DZ*DH*(2.0D0 + DZ*DH -DZ**2) - DR)
      FISH(2,2)=REAL(DTERM1)
!
      NDIM=2
      CALL SGECO(FISH,NDIM,NDIM,ITEMP,RCOND,XTEMP)
      IJOB=1
      CALL SGEDI(FISH,NDIM,NDIM,ITEMP,XTEMP,XTEMP(MAXNXT/2),IJOB)
      DO 2410 J=1,NDIM
        DO 2415 I=1,NDIM
          COV(I,J)=FISH(I,J)
 2415   CONTINUE
 2410 CONTINUE
!
      SCALSE=0.0
      SIGMSE=0.0
      IF(COV(1,1).GE.0.0)SCALSE=SQRT(COV(1,1))
      IF(COV(2,2).GE.0.0)SIGMSE=SQRT(COV(2,2))
      COVSE=COV(2,1)
      UHATSE=SCALSE
      SHAPSE=SIGMSE
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'NML2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF LGNML2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)N,XMEAN,XSD,XMIN,XMAX
 9013   FORMAT('N,XMEAN,XSD,XMIN,XMAX = ',I8,4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9017)SHAPML,SCALML,SHAPSE,SCALSE
 9017   FORMAT('SHAPML,SCALML,SHAPSE,SCALSE =  ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE LGNML2
      SUBROUTINE LGNML3(Y,N,DTEMP1,   &
                        XMEAN,XSD,XVAR,XMIN,XMAX,XSKEW,   &
                        ALOCML,SCALML,SHAPML,UHATML,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE MAXIMUM LIKELIHOOD ESTIMATES
!              FOR THE 3-PARAMETER LOGNORMAL DISTRIBUTION FOR THE RAW DATA
!              CASE (I.E., NO CENSORING AND NO GROUPING).
!
!              THIS USES THE METHOD DESCRIBED IN COHEN AND WHITTEN (AND
!              ALSO IN BURY).
!
!              PUT THIS IN A SEPARATE ROUTINE AS IT MAY BE CALLED
!              FROM MULTIPLE PLACES (DPMLL3 WILL GENERATE THE OUTPUT
!              FOR THE 3-PARAMATER LOGNORMAL MLE COMMAND).
!
!     REFERENCE--KARL BURY, "STATISTICAL DISTRIBUTIONS IN
!                ENGINEERING", CAMBRIDGE UNIVERSITY PRESS,
!                1999, CHAPTER 13.
!              --COHEN AND WHITTEN (1988), "PARAMETER ESTIMATION IN
!                RELIABILITY AND LIFE SPAN MODELS", MARCEL DEKKER, INC.,
!                CHAPTER 4.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2014/04
!     ORIGINAL VERSION--APRIL     2014
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DIMENSION Y(*)
      DOUBLE PRECISION DTEMP1(*)
!
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      DOUBLE PRECISION LGNFU3
      EXTERNAL LGNFU3
!
      INTEGER IN
      COMMON/LGNMLE/IN
!
      DOUBLE PRECISION XSTART
      DOUBLE PRECISION XLOW
      DOUBLE PRECISION XUP
      DOUBLE PRECISION DAE
      DOUBLE PRECISION DRE
      DOUBLE PRECISION DX
      DOUBLE PRECISION DN
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION BOUND
      DOUBLE PRECISION FL
      DOUBLE PRECISION FU
      DOUBLE PRECISION DINC
!
      CHARACTER*4 IWRITE
      CHARACTER*40 IDIST
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='LGNM'
      ISUBN2='L3  '
!
      IDIST='LOGNORMAL'
      IWRITE='OFF'
      IERROR='NO'
      ALOCML=CPUMIN
      SCALML=CPUMIN
      SHAPML=CPUMIN
      UHATML=CPUMIN
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'NML3')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF LGNML3--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N
   52   FORMAT('IBUGA3,ISUBRO,N = ',2(A4,2X),I8)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  CARRY OUT CALCULATIONS              **
!               **  FOR LOGNORMAL MLE ESTIMATE          **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'NML3')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(N.LE.4)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN 3-PARAMETER LOGNORMAL MAXIMUM ',   &
               'LIKELIHOOD--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,112)
  112   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE RESPONSE ',   &
               'VARIABLE IS LESS THAN 5.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,113)N
  113   FORMAT('      SAMPLE SIZE = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IFLAG=1
      CALL SUMRAW(Y,N,IDIST,IFLAG,   &
                  XMEAN,XVAR,XSD,XMIN,XMAX,   &
                  ISUBRO,IBUGA3,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
      CALL STMOM3(Y,N,IWRITE,XSKEW,IBUGA3,IERROR)
!
!     STEP 1: SOLVE EQUATION IN LGNFU3 TO ESTIMATE THE LOCATION
!             PARAMETER.
!
!             FIRST NEED TO FIND A BRACKETING INTERVAL.  USE
!             MINIMUM VALUE AS UPPER LIMITS.  DESCEND IN SMALL
!             INCREMENTS UNTIL "MEAN - 60*SD".  IF NO BRACKETING
!             INTERVAL FOUND AT THAT POINT, THEN NO ML SOLUTION.
!
      DO 210 I=1,N
        DTEMP1(I)=DBLE(Y(I))
  210 CONTINUE
      IN=N
!
      BOUND=DBLE(XMEAN) - 60.0D0*DBLE(XSD)
      IF((DBLE(XMIN)-BOUND).GT.100.)THEN
        DINC=(DBLE(XMIN)-BOUND)/100.0D0
      ELSEIF((DBLE(XMIN)-BOUND).GT.50.)THEN
        DINC=0.5D0
      ELSEIF((DBLE(XMIN)-BOUND).GT.10.)THEN
        DINC=0.1D0
      ELSE
        DINC=0.01D0
      ENDIF
!
      XUP=DBLE(XMIN) - 1.0D-06
      FU=LGNFU3(XUP,DTEMP1)
      XLOW=DBLE(XMIN)
      FL=FU
!
  290 CONTINUE
      IF(XLOW.GT.BOUND .AND. (FL*FU).GT.0.0D0)THEN
        XLOW=XLOW - DINC
        FL=LGNFU3(XLOW,DTEMP1)
        GO TO 290
      ELSE
        IF(XLOW.LT.BOUND)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,111)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,292)
  292     FORMAT('      NO LOCAL MAXIMIM LIKELIHOOD ESTIMATE CAN ',   &
                 'BE FOUND.')
          CALL DPWRST('XXX','WRIT')
          IERROR='YES'
          GO TO 9000
        ENDIF
      ENDIF
!
      XSTART=(XLOW+XUP)/2.0D0
      DAE=1.0D-7
      DRE=1.0D-7
      IFLAG=0
      ITBRAC=0
!
      CALL DFZER2(LGNFU3,XLOW,XUP,XSTART,DRE,DAE,IFLAG,DTEMP1)
!
      IF(IFLAG.EQ.2)THEN
!
!  NOTE: SUPPRESS THIS MESSAGE FOR NOW.
!CCCC   WRITE(ICOUT,999)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,3111)
!3111   FORMAT('***** WARNING FROM LOGNORMAL MAXIMUM LIKELIHOOD--')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,3113)
!3113   FORMAT('      ESTIMATE OF LOCATION MAY NOT BE COMPUTED TO ',
!CCCC1         'DESIRED TOLERANCE.')
!CCCC   CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.3)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,3121)
 3121   FORMAT('***** WARNING FROM LOGNORMAL MAXIMUM LIKELIHOOD--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,3123)
 3123   FORMAT('      ESTIMATE OF LOCATION MAY BE NEAR A SINGULAR ',   &
               'POINT.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.4)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,3133)
 3133   FORMAT('      APPROPRIATE BRACKETING INTERVAL NOT FOUND.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.5)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,3121)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,3143)
 3143   FORMAT('      MAXIMUM ITERATIONS EXCEEDED.')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!     ONCE LOCATION ESTIMATE DETERMINED
!
!         UHAT = (1/N*SUM[i=1 to N][LOG(X(i) - LOC]
!
!         SIGMA**2 = (1/N)*SUM[i=1 to N][LOG(X(i) - LOC]**2 -
!                    [(1/N)*SUM[i=1 to N][LOG(X(i) - LOC)]]**2
!
      ALOCML=REAL(XLOW)
      DSUM1=0.0D0
      DSUM2=0.0D0
      DN=DBLE(N)
      DO 4000 I=1,N
        DX=DBLE(Y(I) - ALOCML)
        DSUM1=DSUM1 + DLOG(DX)
        DSUM2=DSUM2 + DLOG(DX)**2
 4000 CONTINUE
      UHATML=REAL(DSUM1/DN)
      SCALML=EXP(UHATML)
      DTERM1=DSQRT((DSUM2/DN) - (DSUM1/DN)**2)
      SHAPML=REAL(DTERM1)
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'NML3')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF LGNML3--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)DSUM1,DSUM2,DTERM1
 9013   FORMAT('DSUM1,DSUM2,DTERM1 = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE LGNML3
      SUBROUTINE LGNML5(ALOC,SCALE,SHAPE,N,COV,UHATSE,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE PARAMETER VARIANCE-COVARIANCE
!              MATRIX FOR THE 3-PARAMETER LOGNORMAL DISTRIBUTION.  NOTE
!              THAT THESE ARE ONLY APPROXIMATE SINCE THE 3-PARAMETER
!              LOGNORMAL HAS REGULARITY PROBLEMS.  HOWEVER, ACCORDING
!              TO COHEN AND WHITTEN, SIMULATION STUDIES HAVE SHOWN
!              THAT THESE ARE REASONABLE ESTIMATES.  THE FORMULAS
!              FOR THE VARIANCE-COVARIANCE TERMS ARE GIVEN ON
!              PAGE 64 OF COHEN AND WHITTEN.
!
!     REFERENCE--COHEN AND WHITTEN (1988), "PARAMETER ESTIMATION IN
!                RELIABILITY AND LIFE SPAN MODELS", MARCEL DEKKER, INC.,
!                CHAPTER 4.
!              --KARL BURY, "STATISTICAL DISTRIBUTIONS IN
!                ENGINEERING", CAMBRIDGE UNIVERSITY PRESS,
!                1999, CHAPTER 13.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2014/4
!     ORIGINAL VERSION--APRIL     2014
!
      REAL COV(3,3)
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DLOC
      DOUBLE PRECISION DSCALE
      DOUBLE PRECISION DSHAPE
      DOUBLE PRECISION DH
      DOUBLE PRECISION DW
      DOUBLE PRECISION DSIGMA
      DOUBLE PRECISION DBETA2
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='LGNM'
      ISUBN2='L5  '
!
      IWRITE='OFF'
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'IML5')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF LGNML5--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N
   52   FORMAT('IBUGA3,ISUBRO,N = ',A4,2X,A4,2X,I8)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,54)ALOC,SCALE,SHAPE
   54   FORMAT('ALOC,SCALE,SHAPE = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  CARRY OUT CALCULATIONS              **
!               **  FOR VARIANCE-COVARIANCE MATRIX      **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'IML5')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      DO 101 J=1,3
        DO 103 I=1,3
          COV(I,J)=CPUMIN
  103   CONTINUE
  101 CONTINUE
!
      DN=REAL(N)
      DLOC=DBLE(ALOC)
      DSCALE=DBLE(SCALE)
      DSHAPE=DBLE(SHAPE)
      DSIGMA=DSHAPE**2
      DBETA2=DSCALE**2
      DW=DEXP(DSHAPE**2)
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'IML5')THEN
        WRITE(ICOUT,111)DN,DLOC,DSCALE,DSHAPE
  111   FORMAT('LGNML5: DN,DLOC,DSCALE,DSHAPE=',4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,112)DSIGMA,DBETA2,DW
  112   FORMAT('        DSIGMA,DBETA2,DW=',3G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
!     FORMULAS ARE (P. 64 OF COHEN AND WHITTEN):
!
!        VAR(LOC)         = (SHAPE**2/N)*(SCALE**2/W)*H
!        VAR(SCALE)       = (SHAPE**2/N)*SCALE**2*(1 + H)
!        VAR(SHAPE)       = (SHAPE**2/(2*N))*(1 + 2*SHAPE**2*H)
!        COV(LOC,SCALE)   = (-SHAPE**3/N)*(SCALE**2/SQRT(w))*H
!        COV(LOC,SHAPE)   = (SHAPE**3/N)*(SCALE**2/SQRT(W))*H
!        COV(SCALE,SHAPE) = (-SHAPE**3/N)*SCALE**2*H
!        VAR(UHAT)        = (SHAPE**2/N)*(1 + H)
!
!        H = 1/[W*(1+SHAPE**2) - (1+2*SHAPE**2)]
!
      DH=1.0D0/(DW*(1.0D0+DSIGMA) - (1.0D0+2.0D0*DSIGMA))
      COV(1,1)=REAL((DSIGMA/DN)*(DBETA2/DW)*DH)
      COV(2,2)=REAL((DSIGMA/DN)*DBETA2*(1.0D0+DH))
      COV(3,3)=REAL((DSIGMA/(2.0D0*DN))*(1.0D0+2.0D0*DSIGMA*DH))
      COV(1,3)=REAL((DSHAPE**3/DN)*(DBETA2/DSQRT(DW))*DH)
      COV(1,2)=-COV(1,3)
      COV(2,3)=REAL(-(DSHAPE**3/DN)*DBETA2*DH)
      COV(3,1)=COV(1,3)
      COV(2,1)=COV(1,2)
      COV(3,2)=COV(2,3)
      UHATSE=REAL(DSQRT((DSIGMA/DN)*(1.0D0+DH)))
!
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'IML5')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF LGNML5--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9012)DH,UHATSE
 9012   FORMAT('DH,UHATSE = ',2G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE LGNML5
      SUBROUTINE LGNML8(Y,N,MAXNXT,P3LNMI,IOPFLG,   &
                        TEMP1,Y2,   &
                        ALOCML,SCALML,SHAPML,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--USE THE LAWLESS "PROFILE LIKELIHOOD" METHOD (THIS WAS
!              DEVELOPED FOR THE 3-PARAMETER WEIBULL DISTRIBUTION, BUT
!              THE SAME IDEA CAN BE APPLIED TO THE 3-PARAMETER LOGNORMAL
!              DISTRIBUTION.  THIS CAN BE USEFUL AS THE COHEN-WHITTEN
!              ALGORITHM CAN SOMETIMES FAIL.
!
!     PURPOSE--THIS SUBROUTINE IMPLEMENTS THE PROFILE LOG-LIKELIHOOD
!              METHOD ORIGINALLY PROPOSED BY LAWLESS FOR THE 3-PARAMETER
!              WEIBULL.  THIS METHOD DOES THE FOLLOWING:
!
!                1. CREATE A GRID FOR THE LOCATION PARAMETER FROM 0 TO
!                   THE DATA MINIMUM (MINUS AN EPSILON) VALUE.
!
!                2. ITERATE THROUGH THE GRID AND DO THE FOLLOWING:
!
!                    A. SET THE LOCATION PARAMETER TO THE GRID VALUE.
!                       CALL THIS VALUE A0.
!
!                    B. LET Y2 = Y - A0.
!
!                    C. ESTIMATE THE SCALE AND SHAPE PARAMETER USING
!                       STANDARD 2-PARAMETER LOGNORMAL ML METHODS.
!
!                    D. COMPUTE THE LOG-LIKELIHOOD OF THE 3-PARAMETER
!                       LOGNORMAL BASED ON THESE PARAMETER ESTIMATES.
!
!              THE PARAMETER ESTIMATES THAT GENERATE THE MAXIMUM
!              LIKELIHOOD VALUE ARE THE ESTIMATES USED.
!
!     REFERENCES--LAWLESS (2003), "STATISTICAL MODELS AND METHODS FOR
!                 LIFETIME DATA", SECOND EDITION, WILEY, PP. 187-190.
!              --COHEN AND WHITTEN, "PARAMETER ESTIMATION IN RELIABILITY
!                AND LIFE SPAN MODELS", MARCEL DEKKER, INC.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2014/4
!     ORIGINAL VERSION--APRIL     2014
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DIMENSION Y(*)
      DIMENSION Y2(*)
      DIMENSION TEMP1(*)
!
      CHARACTER*4 IOPFLG
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IOP
      CHARACTER*40 IDIST
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='LGNM'
      ISUBN2='L8  '
      IWRITE='OFF'
      IERROR='NO'
      EPS=0.1E-5
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'NML8')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF LGNML8--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N
   52   FORMAT('IBUGA3,ISUBRO,N = ',2(A4,2X),I8)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!
!               **************************************************
!               **  STEP 0--OPEN THE STORAGE FILES              **
!               **************************************************
!
      ISTEPN='1.1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'NML8')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IOPFLG.EQ.'ON' .OR. IOPFLG.EQ.'YES')THEN
        IOP='OPEN'
        IFLAG1=0
        IFLAG2=1
        IFLAG3=0
        IFLAG4=0
        IFLAG5=0
        CALL DPAUFI(IOP,IFLAG1,IFLAG2,IFLAG3,IFLAG4,IFLAG5,   &
                    IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                    IBUGA3,ISUBRO,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  CARRY OUT CALCULATIONS              **
!               **  FOR LOGNORMAL MLE ESTIMATE          **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'NML8')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IDIST='LOGNORMAL'
!
      IF(N.LE.4)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN LOGNORMAL MAXIMUM LIKELIHOOD--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,112)
  112   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE RESPONSE ',   &
               'VARIABLE IS LESS THAN 5.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,113)N
  113   FORMAT('      SAMPLE SIZE = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!     THIS METHOD ASSUMES LOCATION IS NON-NEGATIVE (IT CAN BE EXTENDED
!     TO A NEGATIVE LOWER LIMITS, BUT DEFER ON IMPLEMENTING THAT FOR
!     NOW).
!
      DO 120 I=1,N
        IF(Y(I).LE.0.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,111)IDIST(1:16)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,127)I,Y(I)
  127     FORMAT('      ROW ',I8,' IS NON-POSITIVE (',G15.7,')')
          CALL DPWRST('XXX','WRIT')
          IERROR='YES'
          GO TO 9000
        ENDIF
  120 CONTINUE
!
!     STEP 1: COMPUTE 2-PARAMETER ML ESTIMATES FOR ORIGINAL DATA SET
!
      CALL LGNML1(Y,N,MAXNXT,   &
                  TEMP1,   &
                  XMEAN,XMED,XSD,XVAR,XMIN,XMAX,XMEANL,XSDL,   &
                  SCALML,SCALSE,SHAPML,SHAPSE,UHATML,UHATSE,   &
                  ISUBRO,IBUGA3,IERROR)
      YMIN=P3LNMI
      IF(YMIN.GE.XMIN)YMIN=0.0
      ALOCML=YMIN
      CALL LGNLI1(Y,N,ALOCML,SCALML,SHAPML,   &
                  ALIK,AIC,AICC,BIC,   &
                  ISUBRO,IBUGA3,IERROR)
!
      IF(IOPFLG.EQ.'ON' .OR. IOPFLG.EQ.'YES')THEN
        WRITE(IOUNI2,151)ALOCML,ALIK,SCALML,SHAPML
  151   FORMAT(4E15.7)
      ENDIF
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'NML8')THEN
        WRITE(ICOUT,131)SCALML,SHAPML,ALIK
  131   FORMAT('ZERO CASE: SCALML,SHAPML,ALIK = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
!     STEP 2: NOW ITERATE THROUGH VALUES OF THE LOCATION PARAMETER
!
!             IF MINIMUM VALUE IS SUFFICIENTLY SMALL, JUST DEFINE A
!             SINGLE GRID.  IF IT IS LARGE, THEN DO 2 PASSES.  ONCE
!             WITH A BROAD GRID AND THEN WITH A FINER GRID.
!
      XMINT=XMIN - EPS
      IF(XMIN.LE.100.0)THEN
        NITER=1
        IPASS=1
        IF(XMIN.LE.10)THEN
          AINC=0.001
        ELSE
          AINC=0.01
        ENDIF
        NLOOP=INT(((XMINT-YMIN)/AINC)+0.1)
      ELSE
        NITER=2
        IPASS=1
        NLOOP=100
        AINC=(XMIN-YMIN)/REAL(NLOOP)
      ENDIF
!
 1000 CONTINUE
!
      IF(IPASS.EQ.2)THEN
        XSTRT=ALOCML - AINC
        IF(XSTRT.LE.0.0)XSTRT=0.0
        XSTOP=ALOCML + AINC
        NLOOP=100
        AINC=XMIN/REAL(NLOOP)
      ELSE
        XSTRT=YMIN
      ENDIF
!
      ALIK=CPUMIN
      ALIKT=CPUMIN
      DO 1100 ILOOP=1,NLOOP
!
!       STEP 2A: SUBTRACT OFF CONDITIONAL VALUE OF LOCATION
!
        ALOC=XSTRT + REAL(ILOOP)*AINC
        IF(ALOC.GE.XMIN)GO TO 1100
        DO 1110 I=1,N
          Y2(I)=Y(I) - ALOC
 1110   CONTINUE
!
!       STEP 2B: COMPUTE 2-PARAMETER ML ESTIMATES FOR MODIFIED DATA SET
!                (BUT NOT THAT LIKELIHOOD IS COMPUTED FOR ORIGINAL DATA)
!
        CALL LGNML1(Y2,N,MAXNXT,   &
                    TEMP1,   &
                    XMEAN,XMED,XSD,XVAR,XMIN,XMAX,XMEANL,XSDL,   &
                    SCALMT,SCALSE,SHAPMT,SHAPSE,UHATMT,UHATSE,   &
                    ISUBRO,IBUGA3,IERROR)
        CALL LGNLI1(Y,N,ALOC,SCALMT,SHAPMT,   &
                    ALIKT,AIC,AICC,BIC,   &
                    ISUBRO,IBUGA3,IERROR)
!
      IF(IOPFLG.EQ.'ON' .OR. IOPFLG.EQ.'YES')THEN
        WRITE(IOUNI2,151)ALOC,ALIKT,SCALMT,SHAPMT
      ENDIF
!
!
!       STEP 2C: COMPARE LIKELIHOOD TO CURRENT MAXIMUM
!
        IF(ALIKT.GT.ALIK)THEN
          ALIK=ALIKT
          ALOCML=ALOC
          SCALML=SCALMT
          SHAPML=SHAPMT
          ITEMP=ILOOP
        ENDIF
!
 1100 CONTINUE
!
      IF(NITER.EQ.2 .AND. IPASS.EQ.1)THEN
        IPASS=2
        GO TO 1000
      ENDIF
!
 9000 CONTINUE
!
      IF(IOPFLG.EQ.'ON' .OR. IOPFLG.EQ.'YES')THEN
        IOP='CLOS'
        CALL DPAUFI(IOP,IFLAG1,IFLAG2,IFLAG3,IFLAG4,IFLAG5,   &
                    IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                    IBUGA3,ISUBRO,IERROR)
      ENDIF
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'NML8')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF LGNML8--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)NITER,NLOOP,IPASS,IERROR
 9013   FORMAT('NITER,NLOOP,IPASS,IERROR = ',3I8,2X,A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9021)ALOCML,SCALML,SHAPML,ALIK
 9021   FORMAT('MLE: ALOCML,SCALML,SHAPML,ALIK = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE LGNML8
      SUBROUTINE LGNMO1(XMEAN,XSD,XMIN,XSKEW,N,PSTAMV,   &
                        ALOCMO,SCALMO,SHAPMO,UHATMO,   &
                        ALOCMM,SCALMM,SHAPMM,UHATMM,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES MOMENT ESTIMATES FOR THE 3-PARAMETER
!              LOGNORMAL DISTRIBUTION.  THE INPUT VALUES ARE:
!
!                 XMEAN   - THE SAMPLE MEAN
!                 XSD     - THE SAMPLE STANDARD DEVIATION
!                 XSKEW   - THE SAMPLE SKEWNESS
!                 XMIN    - THE SAMPLE MINIMUM
!
!              THIS IS FOR THE UNCENSORED CASE.
!
!     REFERENCE--COHEN AND WHITTEN, "PARAMETER ESTIMATION IN RELIABILITY
!                AND LIFE SPAN MODELS", MARCEL DEKKER, INC., P. 61 AND
!                PP. 352-354.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2014/4
!     ORIGINAL VERSION--APRIL     2014
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION AMOM(3)
      DOUBLE PRECISION VMOM(8)
      DOUBLE PRECISION VMMOM(8)
      DOUBLE PRECISION DW
      DOUBLE PRECISION DWL
      DOUBLE PRECISION DWU
      DOUBLE PRECISION FL
      DOUBLE PRECISION FU
      DOUBLE PRECISION F
      DOUBLE PRECISION EPS
      DOUBLE PRECISION BETA
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DPPF
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      DOUBLE PRECISION LGNMO2
      DOUBLE PRECISION LGNMO3
      DOUBLE PRECISION LGNMO4
      EXTERNAL LGNMO2
      EXTERNAL LGNMO3
      EXTERNAL LGNMO4
!
      REAL LININ3
      EXTERNAL LININ3
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='LGNM'
      ISUBN2='O1  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'NMO1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF LGNMO1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO
   52   FORMAT('IBUGA3,ISUBRO = ',A4,2X,A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,54)XMEAN,XSD,XMIN,XSKEW
   54   FORMAT('XMEAN,XSD,XMIN,XSKEW = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  CARRY OUT CALCULATIONS              **
!               **  FOR LOGNORMAL MOMENT ESTIMATE       **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'NMO1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(XMEAN.EQ.CPUMIN .OR. XMEAN.EQ.PSTAMV)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
  101   FORMAT('***** ERROR IN LOGNORMAL MOMENT ESTIMATION--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,102)
  102   FORMAT('      THE SAMPLE MEAN IS UNDEFINED.')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ELSEIF(XSD.EQ.CPUMIN .OR. XSD.EQ.PSTAMV)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,107)
  107   FORMAT('      THE SAMPLE STANDARD DEVIATION IS UNDEFINED.')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ELSEIF(XSD.LE.0.0)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,112)
  112   FORMAT('      THE SAMPLE STANDARD DEVIATION IS NON-POSTIVE.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,113)XSD
  113   FORMAT('      STANDARD DEVIATION = ',G15.7)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ELSEIF(N.LT.5)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,122)
  122   FORMAT('      THE SAMPLE SIZE IS LESS THAN FIVE.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,123)N
  123   FORMAT('      SAMPLE SIZE  = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      DEPS=0.1D-7
!
      ALOCMO=CPUMIN
      SCALMO=CPUMIN
      SHAPMO=CPUMIN
      UHATMO=CPUMIN
!
      ALOCMM=CPUMIN
      SCALMM=CPUMIN
      UHATMM=CPUMIN
      SHAPMM=CPUMIN
!
      VMMOM(1)=CPUMIN
      VMMOM(2)=CPUMIN
      VMMOM(3)=CPUMIN
      VMMOM(4)=CPUMIN
      VMMOM(5)=CPUMIN
      VMMOM(6)=CPUMIN
      VMMOM(7)=CPUMIN
      VMMOM(8)=CPUMIN
!
!               ******************************************
!               **  STEP 2--                            **
!               **  MOMENT ESTIMATES                    **
!               ******************************************
!
      ISTEPN='2'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'NMO1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     IN CODE BELOW:
!
!        VMOM(1) = ESTIMATE OF LOCATION
!        VMOM(2) = ESTIMATE OF U
!        VMOM(3) = ESTIMATE OF SHAPE (SIGMA)
!        VMOM(4) = DW = EXP(SIGMA**2)
!        VMOM(5) = BETA = SCALE = EXP(U)
!        VMOM(6) = A3 = = SQRT(PEARSON'S BETA1) (SKEWNESS)
!                = (DW + 2.0)*SQRT(DW-1.0)
!        VMOM(7) = E(X) = V(1) + BETA*SQRT(DW)
!        VMOM(8) = SD(X) = BETA*SQRT(DW*(DW-1.0))
!
!     FOR OUR PURPOSES, WE ARE PRIMARILY INTERESTED IN THE PARAMETER
!     ESTIMATES.
!
      AMOM(1)=DBLE(XMEAN)
      AMOM(2)=DBLE(XSD)
      AMOM(3)=DBLE(XSKEW)
      DW=LGNMO4(AMOM(3))
!
      IERR=0
      KOUNT=1
  100 CONTINUE
      IF(DABS(LGNMO2(DW,AMOM)).GE.1.0D-9 .AND. KOUNT.LT.500)THEN
        DW=DW - LGNMO2(DW,AMOM)/LGNMO3(DW)
        KOUNT=KOUNT+1
        GO TO 100
      ELSE
        IF(KOUNT.LT.500)THEN
          VMOM(1)=AMOM(1) - AMOM(2)/DSQRT(DW - 1.0)
          IF(VMOM(1).LE.AMOM(1) - 50.0D0*AMOM(2))THEN
            IERR=1
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,101)
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,132)
  132       FORMAT('      NO MOMENT ESTIMATOR FOUND.')
            CALL DPWRST('XXX','WRIT')
            GO TO 199
          ELSE
            BETA=AMOM(2)/DSQRT(DW*(DW-1.0D0))
            VMOM(2)=DLOG(BETA)
            VMOM(3)=DSQRT(DLOG(DW))
            VMOM(4)=DW
            VMOM(5)=BETA
            VMOM(6)=(DW+2.0D0)*DSQRT(DW-1.0D0)
            VMOM(7)=VMOM(1) + BETA*DSQRT(DW)
            VMOM(8)=BETA*DSQRT(DW*(DW-1.0D0))
          ENDIF
        ELSE
          IERR=1
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,101)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,132)
          CALL DPWRST('XXX','WRIT')
          GO TO 199
        ENDIF
      ENDIF
!
      ALOCMO=REAL(VMOM(1))
      SCALMO=REAL(VMOM(5))
      SHAPMO=REAL(VMOM(3))
      UHATMO=REAL(VMOM(2))
!
  199 CONTINUE
!
!     IN CODE BELOW:
!
!        VMMOM(1) = ESTIMATE OF LOCATION
!        VMMOM(2) = ESTIMATE OF U
!        VMMOM(3) = ESTIMATE OF SHAPE (SIGMA)
!        VMMOM(4) = DW = EXP(SIGMA**2)
!        VMMOM(5) = BETA = SCALE = EXP(U)
!        VMMOM(6) = A3 = = SQRT(PEARSON'S BETA1) (SKEWNESS)
!                 = (DW + 2.0)*SQRT(DW-1.0)
!        VMMOM(7) = E(X) = V(1) + BETA*SQRT(DW)
!        VMMOM(8) = SD(X) = BETA*SQRT(DW*(DW-1.0))
!
!     COMPUTE MODIFIED MOMENT ESTIMATORS USING CODE FOUND ON
!     PP. 352-354 OF COHEN/WHITTEN BOOK.
!
!     IF XMIN PARAMETER NOT GIVEN, THEN SKIP THIS CASE.
!
      IF(XMIN.EQ.CPUMIN)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,212)
  212   FORMAT('      MINIMUM VALUE NOT SPECIFIED.  MODIFIED ',   &
               'MOMENTS WILL NOT BE COMPUTED.')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!     FIRST OBTAIN VALUE OF EXPECTED VALUE OF FIRST ORDER
!     STATISTIC.
!
      SI=0.0
      IF(N.GE.1000)THEN
        DTERM1=1.0D0/DBLE(N+1)
        CALL NODPPF(DTERM1,DPPF)
        SI=REAL(DPPF)
      ELSEIF(N.EQ.5)THEN
        SI=-1.16296
      ELSEIF(N.GT.5 .AND. N.LT.10)THEN
        AY1=-1.16296
        AY2=-1.53875
        AX1=5.0
        AX2=10.0
        AX3=REAL(N)
        SI=LININ3(AX1,AY1,AX2,AY2,AX3,IBUGA3,ISUBRO,IERROR)
      ELSEIF(N.EQ.10)THEN
        SI=-1.53875
      ELSEIF(N.EQ.11)THEN
        SI=(-1.53875 + (-1.62923))/2.0
      ELSEIF(N.EQ.12)THEN
        SI=-1.62923
      ELSEIF(N.EQ.13)THEN
        SI=(-1.62923 + (-1.70338))/2.0
      ELSEIF(N.EQ.14)THEN
        SI=-1.70338
      ELSEIF(N.EQ.15)THEN
        SI=(-1.70338 + (-1.75699))/2.0
      ELSEIF(N.EQ.16)THEN
        SI=-1.75699
      ELSEIF(N.EQ.17)THEN
        SI=(-1.75699 + (-1.82003))/2.0
      ELSEIF(N.EQ.18)THEN
        SI=-1.82003
      ELSEIF(N.EQ.19)THEN
        SI=(-1.82003 + (-1.86748))/2.0
      ELSEIF(N.EQ.20)THEN
        SI=-1.86748
      ELSEIF(N.EQ.21)THEN
        SI=(-1.86748 + (-1.90969))/2.0
      ELSEIF(N.EQ.22)THEN
        SI=-1.90969
      ELSEIF(N.EQ.23)THEN
        SI=(-1.90969 + (-1.94767))/2.0
      ELSEIF(N.EQ.24)THEN
        SI=-1.94767
      ELSEIF(N.EQ.25)THEN
        SI=(-1.94767 + (-1.98216))/2.0
      ELSEIF(N.EQ.26)THEN
        SI=-1.98216
      ELSEIF(N.EQ.27)THEN
        SI=(-1.98216 + (-2.01371))/2.0
      ELSEIF(N.EQ.28)THEN
        SI=-2.01371
      ELSEIF(N.EQ.29)THEN
        SI=(-2.01371 + (-2.04276))/2.0
      ELSEIF(N.EQ.30)THEN
        SI=-2.04276
      ELSEIF(N.EQ.31)THEN
        SI=(-2.04276 + (-2.06967))/2.0
      ELSEIF(N.EQ.32)THEN
        SI=-2.06967
      ELSEIF(N.EQ.33)THEN
        SI=(-2.06967 + (-2.09471))/2.0
      ELSEIF(N.EQ.34)THEN
        SI=-2.09471
      ELSEIF(N.EQ.35)THEN
        SI=(-2.09471 + (-2.11812))/2.0
      ELSEIF(N.EQ.36)THEN
        SI=-2.11812
      ELSEIF(N.EQ.37)THEN
        SI=(-2.11812 + (-2.14009))/2.0
      ELSEIF(N.EQ.38)THEN
        SI=-2.14009
      ELSEIF(N.EQ.39)THEN
        SI=(-2.14099 + (-2.16078))/2.0
      ELSEIF(N.EQ.40)THEN
        SI=-2.16078
      ELSEIF(N.GT.40 .AND. N.LT.45)THEN
        AY1=-2.16078
        AY2=-2.20772
        AX1=40.0
        AX2=45.0
        AX3=REAL(N)
        SI=LININ3(AX1,AY1,AX2,AY2,AX3,IBUGA3,ISUBRO,IERROR)
      ELSEIF(N.EQ.45)THEN
        SI=-2.20772
      ELSEIF(N.GT.45 .AND. N.LT.50)THEN
        AY1=-2.20772
        AY2=-2.24907
        AX1=45.0
        AX2=50.0
        AX3=REAL(N)
        SI=LININ3(AX1,AY1,AX2,AY2,AX3,IBUGA3,ISUBRO,IERROR)
      ELSEIF(N.EQ.50)THEN
        SI=-2.24907
      ELSEIF(N.GT.50 .AND. N.LT.55)THEN
        AY1=-2.24907
        AY2=-2.28598
        AX1=50.0
        AX2=55.0
        AX3=REAL(N)
        SI=LININ3(AX1,AY1,AX2,AY2,AX3,IBUGA3,ISUBRO,IERROR)
      ELSEIF(N.EQ.55)THEN
        SI=-2.28598
      ELSEIF(N.GT.55 .AND. N.LT.60)THEN
        AY1=-2.28598
        AY2=-2.31928
        AX1=55.0
        AX2=60.0
        AX3=REAL(N)
        SI=LININ3(AX1,AY1,AX2,AY2,AX3,IBUGA3,ISUBRO,IERROR)
      ELSEIF(N.EQ.60)THEN
        SI=-2.31928
      ELSEIF(N.GT.60 .AND. N.LT.65)THEN
        AY1=-2.31928
        AY2=-2.34958
        AX1=60.0
        AX2=65.0
        AX3=REAL(N)
        SI=LININ3(AX1,AY1,AX2,AY2,AX3,IBUGA3,ISUBRO,IERROR)
      ELSEIF(N.EQ.65)THEN
        SI=-2.34958
      ELSEIF(N.GT.65 .AND. N.LT.70)THEN
        AY1=-2.34958
        AY2=-2.37736
        AX1=65.0
        AX2=70.0
        AX3=REAL(N)
        SI=LININ3(AX1,AY1,AX2,AY2,AX3,IBUGA3,ISUBRO,IERROR)
      ELSEIF(N.EQ.70)THEN
        SI=-2.37736
      ELSEIF(N.GT.70 .AND. N.LT.75)THEN
        AY1=-2.37736
        AY2=-2.40299
        AX1=70.0
        AX2=75.0
        AX3=REAL(N)
        SI=LININ3(AX1,AY1,AX2,AY2,AX3,IBUGA3,ISUBRO,IERROR)
      ELSEIF(N.EQ.75)THEN
        SI=-2.40299
      ELSEIF(N.GT.75 .AND. N.LT.80)THEN
        AY1=-2.40299
        AY2=-2.42677
        AX1=75.0
        AX2=80.0
        AX3=REAL(N)
        SI=LININ3(AX1,AY1,AX2,AY2,AX3,IBUGA3,ISUBRO,IERROR)
      ELSEIF(N.EQ.80)THEN
        SI=-2.42677
      ELSEIF(N.GT.80 .AND. N.LT.85)THEN
        AY1=-2.42677
        AY2=-2.44894
        AX1=80.0
        AX2=85.0
        AX3=REAL(N)
        SI=LININ3(AX1,AY1,AX2,AY2,AX3,IBUGA3,ISUBRO,IERROR)
      ELSEIF(N.EQ.85)THEN
        SI=-2.44894
      ELSEIF(N.GT.85 .AND. N.LT.90)THEN
        AY1=-2.44894
        AY2=-2.46970
        AX1=85.0
        AX2=90.0
        AX3=REAL(N)
        SI=LININ3(AX1,AY1,AX2,AY2,AX3,IBUGA3,ISUBRO,IERROR)
      ELSEIF(N.EQ.90)THEN
        SI=-2.46970
      ELSEIF(N.GT.90 .AND. N.LT.95)THEN
        AY1=-2.46970
        AY2=-2.48920
        AX1=90.0
        AX2=95.0
        AX3=REAL(N)
        SI=LININ3(AX1,AY1,AX2,AY2,AX3,IBUGA3,ISUBRO,IERROR)
      ELSEIF(N.EQ.95)THEN
        SI=-2.48920
      ELSEIF(N.GT.95 .AND. N.LT.100)THEN
        AY1=-2.48920
        AY2=-2.50759
        AX1=95.0
        AX2=100.0
        AX3=REAL(N)
        SI=LININ3(AX1,AY1,AX2,AY2,AX3,IBUGA3,ISUBRO,IERROR)
      ELSEIF(N.EQ.100)THEN
        SI=-2.50759
      ELSEIF(N.GT.100 .AND. N.LT.125)THEN
        AY1=-2.50759
        AY2=-2.58634
        AX1=100.0
        AX2=125.0
        AX3=REAL(N)
        SI=LININ3(AX1,AY1,AX2,AY2,AX3,IBUGA3,ISUBRO,IERROR)
      ELSEIF(N.EQ.125)THEN
        SI=-2.58634
      ELSEIF(N.GT.125 .AND. N.LT.150)THEN
        AY1=-2.58634
        AY2=-2.64925
        AX1=125.0
        AX2=150.0
        AX3=REAL(N)
        SI=LININ3(AX1,AY1,AX2,AY2,AX3,IBUGA3,ISUBRO,IERROR)
      ELSEIF(N.EQ.150)THEN
        SI=-2.64925
      ELSEIF(N.GT.150 .AND. N.LT.175)THEN
        AY1=-2.64925
        AY2=-2.70148
        AX1=150.0
        AX2=175.0
        AX3=REAL(N)
        SI=LININ3(AX1,AY1,AX2,AY2,AX3,IBUGA3,ISUBRO,IERROR)
      ELSEIF(N.EQ.175)THEN
        SI=-2.70148
      ELSEIF(N.GT.175 .AND. N.LT.200)THEN
        AY1=-2.70148
        AY2=-2.74604
        AX1=175.0
        AX2=200.0
        AX3=REAL(N)
        SI=LININ3(AX1,AY1,AX2,AY2,AX3,IBUGA3,ISUBRO,IERROR)
      ELSEIF(N.EQ.200)THEN
        SI=-2.74604
      ELSEIF(N.GT.200 .AND. N.LT.225)THEN
        AY1=-2.74604
        AY2=-2.74845
        AX1=200.0
        AX2=225.0
        AX3=REAL(N)
        SI=LININ3(AX1,AY1,AX2,AY2,AX3,IBUGA3,ISUBRO,IERROR)
      ELSEIF(N.EQ.225)THEN
        SI=-2.78485
      ELSEIF(N.GT.225 .AND. N.LT.250)THEN
        AY1=-2.74845
        AY2=-2.81918
        AX1=225.0
        AX2=250.0
        AX3=REAL(N)
        SI=LININ3(AX1,AY1,AX2,AY2,AX3,IBUGA3,ISUBRO,IERROR)
      ELSEIF(N.EQ.250)THEN
        SI=-2.81918
      ELSEIF(N.GT.250 .AND. N.LT.280)THEN
        AY1=-2.81918
        AY2=-2.85572
        AX1=250.0
        AX2=280.0
        AX3=REAL(N)
        SI=LININ3(AX1,AY1,AX2,AY2,AX3,IBUGA3,ISUBRO,IERROR)
      ELSEIF(N.EQ.280)THEN
        SI=-2.85572
      ELSEIF(N.GT.280 .AND. N.LT.300)THEN
        AY1=-2.85572
        AY2=-2.87777
        AX1=280.0
        AX2=300.0
        AX3=REAL(N)
        SI=LININ3(AX1,AY1,AX2,AY2,AX3,IBUGA3,ISUBRO,IERROR)
      ELSEIF(N.EQ.300)THEN
        SI=-2.87777
      ELSEIF(N.GT.300 .AND. N.LT.315)THEN
        AY1=-2.87777
        AY2=-2.89327
        AX1=300.0
        AX2=315.0
        AX3=REAL(N)
        SI=LININ3(AX1,AY1,AX2,AY2,AX3,IBUGA3,ISUBRO,IERROR)
      ELSEIF(N.EQ.315)THEN
        SI=-2.89327
      ELSEIF(N.GT.315 .AND. N.LT.350)THEN
        AY1=-2.89327
        AY2=-2.92651
        AX1=315.0
        AX2=350.0
        AX3=REAL(N)
        SI=LININ3(AX1,AY1,AX2,AY2,AX3,IBUGA3,ISUBRO,IERROR)
      ELSEIF(N.EQ.350)THEN
        SI=-2.92651
      ELSEIF(N.GT.350 .AND. N.LT.375)THEN
        AY1=-2.92651
        AY2=-2.94810
        AX1=350.0
        AX2=375.0
        AX3=REAL(N)
        SI=LININ3(AX1,AY1,AX2,AY2,AX3,IBUGA3,ISUBRO,IERROR)
      ELSEIF(N.EQ.375)THEN
        SI=-2.94810
      ELSEIF(N.GT.375 .AND. N.LT.400)THEN
        AY1=-2.94810
        AY2=-2.96818
        AX1=375.0
        AX2=400.0
        AX3=REAL(N)
        SI=LININ3(AX1,AY1,AX2,AY2,AX3,IBUGA3,ISUBRO,IERROR)
      ELSEIF(N.EQ.400)THEN
        SI=-2.96818
      ELSEIF(N.GT.400)THEN
        AY1=-2.96818
        AY2=-3.09053
        AX1=400.0
        AX2=1000.0
        AX3=REAL(N)
        SI=LININ3(AX1,AY1,AX2,AY2,AX3,IBUGA3,ISUBRO,IERROR)
      ENDIF
!
      IERR=0
!
!     SET LOWER AND UPPER BOUNDS FOR DW AND CALCULATE FUNCTION AT
!     THESE VALUES
!
      DWL=1.00004D0
      FL=DWL*(DWL-1.0D0)-((DSQRT(DWL)-DEXP(DBLE(SI)*DSQRT(DLOG(DWL))))*   &
         AMOM(2)/(AMOM(1) - XMIN))**2
!
      DWU=1.0D0+(AMOM(2)/(AMOM(1)-XMIN))**2 - 0.1D-7
      FU=DWU*(DWU-1.0D0)-((DSQRT(DWU)-DEXP(DBLE(SI)*DSQRT(DLOG(DWU))))*   &
         AMOM(2)/(AMOM(1) - XMIN))**2
!
!     SET THE TOLERANCE LEVEL
!
      EPS=0.1D-10
      IF(FL*FU.GT.0.0)THEN
        IERR=1
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,222)
  222   FORMAT('      NO MODIFIED MOMENT ESTIMATOR FOUND.')
        CALL DPWRST('XXX','WRIT')
      ELSE
        DW=(DWL+DWU)/2.0D0
        F=FL
300     CONTINUE
        IF(DABS(DW-DWL).GT.EPS)THEN
          F=DW*(DW-1.0D0)-((DSQRT(DW)-DEXP(DBLE(SI)*DSQRT(DLOG(DW))))*   &
            AMOM(2)/(AMOM(1) - XMIN))**2
          IF(F*FL.LT.0.0D0)THEN
            DWU=DW
          ELSE
            DWL=DW
            FL=F
          ENDIF
          DW=(DWL+DWU)/2.0D0
          GO TO 300
        ELSE
          VMMOM(1)=AMOM(1) - AMOM(2)/DSQRT(DW-1.0D0)
          BETA=AMOM(2)/DSQRT(DW*(DW-1.0D0))
          VMMOM(2)=DLOG(BETA)
          VMMOM(3)=DSQRT(DLOG(DW))
          VMMOM(4)=DW
          VMMOM(5)=BETA
          VMMOM(6)=(DW+2.0D0)*DSQRT(DW-1.0D0)
          VMMOM(7)=VMMOM(1) + BETA*DSQRT(DW)
          VMMOM(8)=BETA*DSQRT(DW*(DW-1.0D0))
        ENDIF
      ENDIF
!
      ALOCMM=VMMOM(1)
      SCALMM=VMMOM(5)
      SHAPMM=VMMOM(3)
      UHATMM=VMMOM(2)
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'IMO1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF LGNMO1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9012)ALOCMO,SCALMO,SHAPMO,UHATMO
 9012   FORMAT('ALOCMO,SCALMO,SHAPMO,UHATMO = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)ALOCMM,SCALMM,SHAPMM,UHATMM
 9013   FORMAT('ALOCMM,SCALMM,SHAPMM,UHATMM = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE LGNMO1
      DOUBLE PRECISION FUNCTION LGNMO2(DW,AMOM)
!
!     PURPOSE--COMPUTE A FUNCTION NEEDED BY LGNMO1 (USED TO COMPUTE
!              MOMENT ESTIMATES FOR THE 3-PARAMETER WEIBULL
!              DISTRIBUTION).
!
!     REFERENCE--COHEN AND WHITTEN, "PARAMETER ESTIMATION IN RELIABILITY
!                AND LIFE SPAN MODELS", MARCEL DEKKER, INC., PP. 352-352.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2014/4
!     ORIGINAL VERSION--APRIL     2014
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION AMOM(*)
      DOUBLE PRECISION DW
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      LGNMO2=DW**3 + 3.0D0*DW**2 - 4.0D0 - DBLE(AMOM(3))**2
!
      RETURN
      END FUNCTION LGNMO2
      DOUBLE PRECISION FUNCTION LGNMO3(DW)
!
!     PURPOSE--COMPUTE A FUNCTION NEEDED BY LGNMO1 (USED TO COMPUTE
