      SUBROUTINE LGNPDF(X,SD,PDF)
!CCCC SUBROUTINE LGNPDF(X,PDF)
!CCCC APRIL 1995.  ADD SD PARAMETER (THIS IS SHAPE PARAMETER FOR
!CCCC LOGNORMAL).
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE LOGNORMAL
!              DISTRIBUTION.
!              THE LOGNORMAL DISTRIBUTION USED
!              HEREIN HAS MEAN = SQRT(E) = 1.64872127
!              AND STANDARD DEVIATION = SQRT(E*(E-1)) = 2.16119742.
!              THIS DISTRIBUTION IS DEFINED FOR ALL POSITIVE X
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              F(X) = (1/(X*SQRT(2*PI))) * EXP(-LOG(X)*LOG(X)/2)
!              THE LOGNORMAL DISTRIBUTION USED HEREIN
!              IS THE DISTRIBUTION OF THE VARIATE X = EXP(Z) WHERE
!              THE VARIATE Z IS NORMALLY DISTRIBUTED
!              WITH MEAN = 0 AND STANDARD DEVIATION = 1.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE LOGNORMAL
!             DISTRIBUTION WITH MEAN = SQRT(E) = 1.64872127
!             AND STANDARD DEVIATION = SQRT(E*(E-1)) = 2.16119742.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NORPDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES 112-136.
!               --CRAMER, MATHEMATICAL METHODS OF STATISTICS,
!                 1946, PAGES 219-220.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--APRIL     1994.
!     UPDATED         --JANUARY   1995. X=0 CASE EXPLICITLY 0
!     UPDATED         --APRIL     1995. SUPPORT SHAPE PARAMETER
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PDF=0.0
      IF(X.LT.0.0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    4 FORMAT('***** ERROR--THE FIRST ARGUMENT TO LGNPDF IS NEGATIVE.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!-----START POINT-----------------------------------------------------
!
      IF(X.GT.0.0)THEN
        IF(SD.EQ.1.0)THEN
          ARG=LOG(X)
          CALL NORPDF(ARG,PDF)
          PDF=(1.0/X)*PDF
        ELSE
          ARG=LOG(X)/SD
          CALL NORPDF(ARG,ARG2)
          PDF=(1.0/(SD*X))*ARG2
        ENDIF
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE LGNPDF
      SUBROUTINE LGNPPF(P,SD,PPF)
!CCCC SUBROUTINE LGNPPF(P,PPF)
!CCCC APRIL 1995.  SUPPORT SCALE PARAMETER
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE LOGNORMAL
!              DISTRIBUTION.
!              THE LOGNORMAL DISTRIBUTION USED
!              HEREIN HAS MEAN = SQRT(E) = 1.64872127
!              AND STANDARD DEVIATION = SQRT(E*(E-1)) = 2.16119742.
!              THIS DISTRIBUTION IS DEFINED FOR ALL POSITIVE X
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              F(X) = (1/(X*SQRT(2*PI))) * EXP(-LOG(X)*LOG(X)/2)
!              THE LOGNORMAL DISTRIBUTION USED HEREIN
!              IS THE DISTRIBUTION OF THE VARIATE X = EXP(Z) WHERE
!              THE VARIATE Z IS NORMALLY DISTRIBUTED
!              WITH MEAN = 0 AND STANDARD DEVIATION = 1.
!              NOTE THAT THE PERCENT POINT FUNCTION OF A DISTRIBUTION
!              IS IDENTICALLY THE SAME AS THE INVERSE CUMULATIVE
!              DISTRIBUTION FUNCTION OF THE DISTRIBUTION.
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE
!                                (BETWEEN 0.0 (EXCLUSIVELY)
!                                AND 1.0 (EXCLUSIVELY))
!                                AT WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION PERCENT
!                                POINT FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT FUNCTION .
!             VALUE PPF FOR THE LOGNORMAL DISTRIBUTION
!             WITH MEAN = SQRT(E) = 1.64872127
!             AND STANDARD DEVIATION = SQRT(E*(E-1)) = 2.16119742.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--P SHOULD BE BETWEEN 0.0 (EXCLUSIVELY)
!                   AND 1.0 (EXCLUSIVELY).
!     OTHER DATAPAC   SUBROUTINES NEEDED--NORPPF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES 112-136.
!               --CRAMER, MATHEMATICAL METHODS OF STATISTICS,
!                 1946, PAGES 219-220.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-921-2315
!     ORIGINAL VERSION--APRIL     1994.
!     UPDATED         --JANUARY   1995.
!     UPDATED         --APRIL     1995. SUPPORT SCALE PARAMETER
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PPF=0.0
      IF(P.LT.0.0.OR.P.GE.1.0)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    1 FORMAT('***** ERROR--THE FIRST ARGUMENT TO LGNPPF IS OUTSIDE ',   &
             'THE ALLOWABLE (0,1) INTERVAL.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!-----START POINT-----------------------------------------------------
!
      IF(P.GT.0.0)THEN
        IF(SD.EQ.1.0)THEN
          CALL NORPPF(P,PPF)
          PPF=EXP(PPF)
        ELSE
          CALL NORPPF(P,PPF)
          PPF=EXP(PPF*SD)
        ENDIF
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE LGNPPF
      SUBROUTINE LGNRAN(N,SIGMA,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE LOGNORMAL DISTRIBUTION.
!              THE PROTOTYPE LOGNORMAL DISTRIBUTION USED
!              HEREIN HAS MEAN = SQRT(E) = 1.64872127
!              AND STANDARD DEVIATION = SQRT(E*(E-1)) = 2.16119742.
!              THIS DISTRIBUTION IS DEFINED FOR ALL POSITIVE X
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              F(X) = (1/(X*SQRT(2*PI))) * EXP(-LOG(X)*LOG(X)/2)
!              THE PROTOTYPE LOGNORMAL DISTRIBUTION USED HEREIN
!              IS THE DISTRIBUTION OF THE VARIATE X = EXP(Z) WHERE
!              THE VARIATE Z IS NORMALLY DISTRIBUTED
!              WITH MEAN = 0 AND STANDARD DEVIATION = 1.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE LOGNORMAL DISTRIBUTION
!             WITH MEAN = SQRT(E) = 1.64872127
!             AND STANDARD DEVIATION = SQRT(E*(E-1)) = 2.16119742.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG, SQRT, SIN, COS, EXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--TOCHER, THE ART OF SIMULATION,
!                 1963, PAGES 14-15.
!               --HAMMERSLEY AND HANDSCOMB, MONTE CARLO METHODS,
!                 1964, PAGE 36.
!               --CRAMER, MATHEMATICAL METHODS OF STATISTICS,
!                 1946, PAGES 219-220.
!               --JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES 112-136.
!               --HASTINGS AND PEACOCK, STATISTICAL
!                 DISTRIBUTIONS--A HANDBOOK FOR
!                 STUDENTS AND PRACTITIONERS, 1975,
!                 PAGE 88.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--82.6
!     ORIGINAL VERSION--NOVEMBER  1975.
!     UPDATED         --JULY      1976.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --APRIL     2003. ADD SHAPE PARAMETER SIGMA
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION Y(2)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
      DATA PI/3.14159265359/
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    5 FORMAT('***** ERROR--THE FIRST ARGUMENT TO LGNRAN IS ',   &
             'NON-POSITIVE.')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!     THEN GENERATE 2 ADDITIONAL UNIFORM (0,1) RANDOM NUMBERS
!     (TO BE USED BELOW IN FORMING THE N-TH NORMAL
!     RANDOM NUMBER WHEN THE DESIRED SAMPLE SIZE N
!     HAPPENS TO BE ODD).
!
      CALL UNIRAN(N,ISEED,X)
      CALL UNIRAN(2,ISEED,Y)
!
!     GENERATE N NORMAL RANDOM NUMBERS
!     USING THE BOX-MULLER METHOD.
!
      DO 200 I=1,N,2
        IP1=I+1
        U1=X(I)
        IF(I.EQ.N)THEN
          U2=Y(2)
        ELSE
          U2=X(IP1)
        ENDIF
        ARG1=-2.0*LOG(U1)
        ARG2=2.0*PI*U2
        SQRT1=SQRT(ARG1)
        Z1=SQRT1*COS(ARG2)
        Z2=SQRT1*SIN(ARG2)
        X(I)=Z1
        IF(I.EQ.N)GO TO 200
        X(IP1)=Z2
  200 CONTINUE
!
!     GENERATE N LOGNORMAL RANDOM NUMBERS USING THE DEFINITION THAT
!     A LOGNORMAL VARIATE EQUALS AN EXPONETIATED NORMAL VARIATE.
!
      DO 400 I=1,N
        X(I)=EXP(SIGMA*X(I))
  400 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE LGNRAN
      SUBROUTINE LIBFD1(IHLF1,IHLF2,I1,I2,ITYPE,   &
      IFUNZ1,IFUNZ2,IDERZ1,IDERZ2)
!
!     PURPOSE--COMPUTE DERIVATIVES FOR
!              SQUARE ROOT, EXPONENTIAL, AND LOGS.
!
!     ORIGINAL VERSION--JANUARY   1979.
!     UPDATED         --FEBRUARY  1979.
!     UPDATED         --JANUARY   1981.
!
!---------------------------------------------------------------------
!
      CHARACTER*4 IHLF1
      CHARACTER*4 IHLF2
      CHARACTER*4 ITYPE
      CHARACTER*4 IFUNZ1
      CHARACTER*4 IFUNZ2
      CHARACTER*4 IDERZ1
      CHARACTER*4 IDERZ2
!
      DIMENSION IFUNZ1(*)
      DIMENSION IFUNZ2(*)
      DIMENSION IDERZ1(*)
      DIMENSION IDERZ2(*)
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      I1P1=I1+1
      I1P2=I1+2
!
      IF(IHLF1.EQ.'SQRT'.AND.IHLF2.EQ.'    ')GO TO 510
      IF(IHLF1.EQ.'EXP '.AND.IHLF2.EQ.'    ')GO TO 520
      IF(IHLF1.EQ.'ALOG'.AND.IHLF2.EQ.'    ')GO TO 530
      IF(IHLF1.EQ.'ALOG'.AND.IHLF2.EQ.'E   ')GO TO 530
      IF(IHLF1.EQ.'ALOG'.AND.IHLF2.EQ.'10  ')GO TO 540
      IF(IHLF1.EQ.'LOG '.AND.IHLF2.EQ.'    ')GO TO 530
      IF(IHLF1.EQ.'LOGE'.AND.IHLF2.EQ.'    ')GO TO 530
      IF(IHLF1.EQ.'LOG1'.AND.IHLF2.EQ.'0   ')GO TO 540
!
!     TREAT THE SQUARE ROOT CASE
!
  510 CONTINUE
      I2=I2+1
      IDERZ1(I2)='0   '
      IDERZ2(I2)='    '
      I2=I2+1
      IDERZ1(I2)='.   '
      IDERZ2(I2)='    '
      I2=I2+1
      IDERZ1(I2)='5   '
      IDERZ2(I2)='    '
      I2=I2+1
      IDERZ1(I2)='*   '
      IDERZ2(I2)='    '
      I2=I2+1
      IDERZ1(I2)=IFUNZ1(I1P1)
      IDERZ2(I2)=IFUNZ2(I1P1)
      IF(ITYPE.EQ.'EXP ')I2=I2+1
      IF(ITYPE.EQ.'EXP ')IDERZ1(I2)=IFUNZ1(I1P2)
      IF(ITYPE.EQ.'EXP ')IDERZ2(I2)=IFUNZ2(I1P2)
      I2=I2+1
      IDERZ1(I2)='**  '
      IDERZ2(I2)='    '
      I2=I2+1
      IDERZ1(I2)='(   '
      IDERZ2(I2)='    '
      I2=I2+1
      IDERZ1(I2)='-   '
      IDERZ2(I2)='    '
      I2=I2+1
      IDERZ1(I2)='0   '
      IDERZ2(I2)='    '
      I2=I2+1
      IDERZ1(I2)='.   '
      IDERZ2(I2)='    '
      I2=I2+1
      IDERZ1(I2)='5   '
      IDERZ2(I2)='    '
      I2=I2+1
      IDERZ1(I2)=')   '
      IDERZ2(I2)='    '
      IF(ITYPE.EQ.'EXP ')GO TO 980
      GO TO 985
!
!     TREAT THE EXPONENTIAL CASE
!
  520 CONTINUE
      I2=I2+1
      IDERZ1(I2)='EXP '
      IDERZ2(I2)='    '
      I2=I2+1
      IDERZ1(I2)='(   '
      IDERZ2(I2)='    '
      I2=I2+1
      IDERZ1(I2)=IFUNZ1(I1P1)
      IDERZ2(I2)=IFUNZ2(I1P1)
      IF(ITYPE.EQ.'EXP ')I2=I2+1
      IF(ITYPE.EQ.'EXP ')IDERZ1(I2)=IFUNZ1(I1P2)
      IF(ITYPE.EQ.'EXP ')IDERZ2(I2)=IFUNZ2(I1P2)
      I2=I2+1
      IDERZ1(I2)=')   '
      IDERZ2(I2)='    '
      IF(ITYPE.EQ.'EXP ')GO TO 980
      GO TO 985
!
!     TREAT THE NATURAL LOGARITHM CASE
!
  530 CONTINUE
      I2=I2+1
      IDERZ1(I2)='(   '
      IDERZ2(I2)='    '
      I2=I2+1
      IDERZ1(I2)='1   '
      IDERZ2(I2)='    '
      I2=I2+1
      IDERZ1(I2)='/   '
      IDERZ2(I2)='    '
      I2=I2+1
      IDERZ1(I2)='(   '
      IDERZ2(I2)='    '
      I2=I2+1
      IDERZ1(I2)=IFUNZ1(I1P1)
      IDERZ2(I2)=IFUNZ2(I1P1)
      IF(ITYPE.EQ.'EXP ')I2=I2+1
      IF(ITYPE.EQ.'EXP ')IDERZ1(I2)=IFUNZ1(I1P2)
      IF(ITYPE.EQ.'EXP ')IDERZ2(I2)=IFUNZ2(I1P2)
      I2=I2+1
      IDERZ1(I2)=')   '
      IDERZ2(I2)='    '
      I2=I2+1
      IDERZ1(I2)=')   '
      IDERZ2(I2)='    '
      IF(ITYPE.EQ.'EXP ')GO TO 980
      GO TO 985
!
!     TREAT THE LOGARITHM (TO THE BASE 10) CASE
!
  540 CONTINUE
      I2=I2+1
      IDERZ1(I2)='(   '
      IDERZ2(I2)='    '
      I2=I2+1
      IDERZ1(I2)='1   '
      IDERZ2(I2)='    '
      I2=I2+1
      IDERZ1(I2)='/   '
      IDERZ2(I2)='    '
      I2=I2+1
      IDERZ1(I2)='(   '
      IDERZ2(I2)='    '
      I2=I2+1
      IDERZ1(I2)=IFUNZ1(I1P1)
      IDERZ2(I2)=IFUNZ2(I1P1)
      IF(ITYPE.EQ.'EXP ')I2=I2+1
      IF(ITYPE.EQ.'EXP ')IDERZ1(I2)=IFUNZ1(I1P2)
      IF(ITYPE.EQ.'EXP ')IDERZ2(I2)=IFUNZ2(I1P2)
      I2=I2+1
      IDERZ1(I2)=')   '
      IDERZ2(I2)='    '
      I2=I2+1
      IDERZ1(I2)=')   '
      IDERZ2(I2)='    '
      I2=I2+1
      IDERZ1(I2)='*   '
      IDERZ2(I2)='    '
      I2=I2+1
      IDERZ1(I2)='0   '
      IDERZ2(I2)='    '
      I2=I2+1
      IDERZ1(I2)='.   '
      IDERZ2(I2)='    '
      I2=I2+1
      IDERZ1(I2)='4   '
      IDERZ2(I2)='    '
      I2=I2+1
      IDERZ1(I2)='3   '
      IDERZ2(I2)='    '
      I2=I2+1
      IDERZ1(I2)='4   '
      IDERZ2(I2)='    '
      I2=I2+1
      IDERZ1(I2)='2   '
      IDERZ2(I2)='    '
      I2=I2+1
      IDERZ1(I2)='9   '
      IDERZ2(I2)='    '
      I2=I2+1
      IDERZ1(I2)='4   '
      IDERZ2(I2)='    '
      I2=I2+1
      IDERZ1(I2)='4   '
      IDERZ2(I2)='    '
      I2=I2+1
      IDERZ1(I2)='8   '
      IDERZ2(I2)='    '
      I2=I2+1
      IDERZ1(I2)='1   '
      IDERZ2(I2)='    '
      I2=I2+1
      IDERZ1(I2)='9   '
      IDERZ2(I2)='    '
      IF(ITYPE.EQ.'EXP ')GO TO 980
      GO TO 985
!
  980 CONTINUE
  985 CONTINUE
!
      RETURN
      END SUBROUTINE LIBFD1
      SUBROUTINE LIBPTR(ICTEXT,NCTEXT,ICTEX2,NCTEX2,ICASE,   &
                        ISUBRO,IBUGG3)
!
!     PURPOSE--FOR LIBPLOT OUTPUT, TRANSLATE BETWEEN DATAPLOT'S
!              SPECIAL CHARACTERS AND LIBPLOT SPECIAL CHARACTERS.
!              NOTE THAT THIS MAPPING MAY NOT BE 1-TO-1.  SPECIFICALLY,
!              WE ARE LOOKING THE TRANSLATE THE DATAPLOT SPECIAL
!              SYMBOLS.  LIBPLOT MAY SUPPORT ADDITIONAL SYMBOLS
!              BEYOND WHAT DATAPLOT SUPPORTS.  THE USER CAN ENTER
!              THESE ADDITIONAL LIBPLOT SPECIAL SYMBOLS, BUT THEY
!              THEY WILL BE PLOTTED "AS IS" ON NON-LIBPLOT DEVICES.
!
!              NOTE THAT THIS ROUTINE IS SIMPLER THAN THE POSTSCRIPT
!              ROUTINE IN THAT WE DO NOT NEED TO SPLIT THE STRING
!              INTO MULTIPLE STRINGS.  RATHER WE ARE JUST DOING A
!              STRAIGHT TRANSLATION FROM ONE SYMBOL CODE TO THE OTHER.
!
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2009.5
!     ORIGINAL VERSION--MAY       2009.
!
!-----NON-COMMON VARIABLES (GRAPHICS)-------------------------------------
!
      CHARACTER*4 ICASE
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGG3
!
      CHARACTER*4 ICTEXT(*)
      CHARACTER*4 ICTEX2(*)
!
      CHARACTER*1 IC1
      CHARACTER*1 IC2
      CHARACTER*1 IC3
      CHARACTER*1 IC4
      CHARACTER*1 IC5
      CHARACTER*1 IC6
      CHARACTER*1 IBASLC
!
!-----COMMON----------------------------------------------------------
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'STTR')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF LIBPTR--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,55)NCTEXT,MAXSYM
   55   FORMAT('NCTEXT,MAXSYM = ',2I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,56)(ICTEXT(I),I=1,MIN(NCTEXT,25))
   56   FORMAT('(ICTEXT(I),I=1,NCTEXT) = ',25A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,61)ICASE
   61   FORMAT('ICASE = ',A4)
