        ELSEIF(IC1.EQ.'T' .AND. IC2.EQ.'H' .AND. IC3.EQ.'F' .AND.   &
               IC4.EQ.'O' .AND. IC5.EQ.'(' .AND. IC6.EQ.')'   &
          )THEN
!
          NCTEX2=NCTEX2+1
          ICTEX2(NCTEX2)=IBASLC
          NCTEX2=NCTEX2+1
          ICTEX2(NCTEX2)='t'
          NCTEX2=NCTEX2+1
          ICTEX2(NCTEX2)='f'
!
          ILASTT=I+5
          NSKIP=5
          GO TO 1000
!
        ELSEIF(IC1.EQ.'L' .AND. IC2.EQ.'B' .AND. IC3.EQ.'R' .AND.   &
               IC4.EQ.'A' .AND. IC5.EQ.'(' .AND. IC6.EQ.')'   &
          )THEN
!
          NCTEX2=NCTEX2+1
          ICTEX2(NCTEX2)=IBASLC
          NCTEX2=NCTEX2+1
          ICTEX2(NCTEX2)='l'
          NCTEX2=NCTEX2+1
          ICTEX2(NCTEX2)='c'
!
          ILASTT=I+5
          NSKIP=5
          GO TO 1000
!
        ELSEIF(IC1.EQ.'R' .AND. IC2.EQ.'B' .AND. IC3.EQ.'R' .AND.   &
               IC4.EQ.'A' .AND. IC5.EQ.'(' .AND. IC6.EQ.')'   &
          )THEN
!
          NCTEX2=NCTEX2+1
          ICTEX2(NCTEX2)=IBASLC
          NCTEX2=NCTEX2+1
          ICTEX2(NCTEX2)='r'
          NCTEX2=NCTEX2+1
          ICTEX2(NCTEX2)='c'
!
          ILASTT=I+5
          NSKIP=5
          GO TO 1000
!
        ELSEIF(IC1.EQ.'L' .AND. IC2.EQ.'C' .AND. IC3.EQ.'B' .AND.   &
               IC4.EQ.'R' .AND. IC5.EQ.'(' .AND. IC6.EQ.')'   &
          )THEN
!
          NCTEX2=NCTEX2+1
          ICTEX2(NCTEX2)=IBASLC
          NCTEX2=NCTEX2+1
          ICTEX2(NCTEX2)='l'
          NCTEX2=NCTEX2+1
          ICTEX2(NCTEX2)='t'
!
          ILASTT=I+5
          NSKIP=5
          GO TO 1000
!
        ELSEIF(IC1.EQ.'R' .AND. IC2.EQ.'C' .AND. IC3.EQ.'B' .AND.   &
               IC4.EQ.'R' .AND. IC5.EQ.'(' .AND. IC6.EQ.')'   &
          )THEN
!
          NCTEX2=NCTEX2+1
          ICTEX2(NCTEX2)=IBASLC
          NCTEX2=NCTEX2+1
          ICTEX2(NCTEX2)='R'
          NCTEX2=NCTEX2+1
          ICTEX2(NCTEX2)='T'
          ICTEXT(I)=CHAR(125)
!
          ILASTT=I+5
          NSKIP=5
          GO TO 1000
!
        ELSEIF(IC1.EQ.'R' .AND. IC2.EQ.'A' .AND. IC3.EQ.'R' .AND.   &
               IC4.EQ.'R' .AND. IC5.EQ.'(' .AND. IC6.EQ.')'   &
          )THEN
!
          NCTEX2=NCTEX2+1
          ICTEX2(NCTEX2)=IBASLC
          NCTEX2=NCTEX2+1
          ICTEX2(NCTEX2)='-'
          NCTEX2=NCTEX2+1
          ICTEX2(NCTEX2)='>'
!
          ILASTT=I+5
          NSKIP=5
          GO TO 1000
!
        ELSEIF(IC1.EQ.'U' .AND. IC2.EQ.'A' .AND. IC3.EQ.'R' .AND.   &
               IC4.EQ.'R' .AND. IC5.EQ.'(' .AND. IC6.EQ.')'   &
          )THEN
!
          NCTEX2=NCTEX2+1
          ICTEX2(NCTEX2)=IBASLC
          NCTEX2=NCTEX2+1
          ICTEX2(NCTEX2)='u'
          NCTEX2=NCTEX2+1
          ICTEX2(NCTEX2)='a'
!
          ILASTT=I+5
          NSKIP=5
          GO TO 1000
!
        ELSEIF(IC1.EQ.'D' .AND. IC2.EQ.'A' .AND. IC3.EQ.'R' .AND.   &
               IC4.EQ.'R' .AND. IC5.EQ.'(' .AND. IC6.EQ.')'   &
          )THEN
!
          NCTEX2=NCTEX2+1
          ICTEX2(NCTEX2)=IBASLC
          NCTEX2=NCTEX2+1
          ICTEX2(NCTEX2)='d'
          NCTEX2=NCTEX2+1
          ICTEX2(NCTEX2)='a'
!
          ILASTT=I+5
          NSKIP=5
          GO TO 1000
!
        ELSEIF(IC1.EQ.'H' .AND. IC2.EQ.'B' .AND. IC3.EQ.'A' .AND.   &
               IC4.EQ.'R' .AND. IC5.EQ.'(' .AND. IC6.EQ.')'   &
          )THEN
!
          NCTEX2=NCTEX2+1
          ICTEX2(NCTEX2)=IBASLC
          NCTEX2=NCTEX2+1
          ICTEX2(NCTEX2)='h'
          NCTEX2=NCTEX2+1
          ICTEX2(NCTEX2)='b'
!
          ILASTT=I+5
          NSKIP=5
          GO TO 1000
!
        ELSEIF(IC1.EQ.'D' .AND. IC2.EQ.'E' .AND. IC3.EQ.'G' .AND.   &
               IC4.EQ.'R' .AND. IC5.EQ.'(' .AND. IC6.EQ.')'   &
          )THEN
!
          NCTEX2=NCTEX2+1
          ICTEX2(NCTEX2)=IBASLC
          NCTEX2=NCTEX2+1
          ICTEX2(NCTEX2)='d'
          NCTEX2=NCTEX2+1
          ICTEX2(NCTEX2)='e'
!
          ILASTT=I+5
          NSKIP=5
          GO TO 1000
!
        ENDIF
        NCTEX2=NCTEX2+1
        ICTEX2(NCTEX2)=ICTEXT(I)
!
 1000 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'STTR')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF LIBPTR--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)NCTEX2
 9013   FORMAT('NCTEX2 = ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)(ICTEX2(I)(1:1),I=1,MIN(80,NCTEX2))
 9015   FORMAT('ICTEX2 = ',80A1)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE LIBPTR
      SUBROUTINE LIMITS( A, B, INFIN, LOWER, UPPER )
      DOUBLE PRECISION A, B, LOWER, UPPER, PHI
      INTEGER INFIN
      LOWER = 0.0D0
      UPPER = 1.0D0
      IF ( INFIN .GE. 0 ) THEN
         IF ( INFIN .NE. 0 ) LOWER = PHI(A)
         IF ( INFIN .NE. 1 ) UPPER = PHI(B)
      ENDIF
!
      RETURN
      END SUBROUTINE LIMITS
      SUBROUTINE LINEAR(IT,I1,I2,XS,YS,WH,WV,N,XMAXHF,I3,I4,   &
      ALPHA,BETA,PRED,RES,ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--CARRY OUT A LEAST SQUARES WEIGHTED LINEAR FIT
!              OF THE DATA IN LOCATIONS I1 TO I2
!              OF THE HORIZONTALLY SORTED DATA
!              IN VARIABLES XS(.) AND YS(.).
!              AFTER THE FIT IS DONE, COMPUTE PREDICTED VALUES
!              AND RESIDUALS FOR ELEMENTS I3 TO I4 OF XS(.).
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--88/2
!     ORIGINAL VERSION--FEBRUARY   1988
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION XS(*)
      DIMENSION YS(*)
      DIMENSION WH(*)
      DIMENSION WV(*)
      DIMENSION PRED(*)
      DIMENSION RES(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='LINE'
      ISUBN2='AR  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'OFF'.AND.ISUBRO.NE.'NEAR')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF LINEAR--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)ISUBRO,IBUGA3,IERROR
   52 FORMAT('ISUBRO,IBUGA3,IERROR = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)IT,I1,I2,N,I3,I4
   53 FORMAT('IT,I1,I2,N,I3,I4 = ',6I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,54)XMAXHF
   54 FORMAT('XMAXHF = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      IF(N.LE.0)GO TO 63
      DO 61 I=1,N
      WRITE(ICOUT,62)I,XS(I),YS(I),WH(I),WV(I)
   62 FORMAT('I,XS(I),YS(I),WH(I),WV(I) = ',I8,4E15.7)
      CALL DPWRST('XXX','BUG ')
   61 CONTINUE
   63 CONTINUE
   90 CONTINUE
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(N.GE.1)GO TO 119
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,111)
  111 FORMAT('***** ERROR IN LINEAR--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,112)
  112 FORMAT('      THE INPUT FULL SAMPLE SIZE,')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,113)
  113 FORMAT('      FOR WHICH LOWESS HORIZONTAL WEIGHTS')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,114)
  114 FORMAT('      ARE TO BE COMPUTED, MUST BE 1 OR LARGER.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,115)
  115 FORMAT('      SUCH WAS NOT THE CASE HERE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,116)N
  116 FORMAT('      THE FULL SAMPLE SIZE N = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
  119 CONTINUE
!
      IF(IT.GE.1)GO TO 129
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,121)
  121 FORMAT('***** ERROR IN LINEAR--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,122)
  122 FORMAT('      THE INPUT TARGET OBSERVATION INDEX')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,123)
  123 FORMAT('      FOR WHICH A LOWESS IS TO BE CARRIED OUT')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,124)N
  124 FORMAT('      MUST BE BETWEEN 1 AND ',I8,' (INCLUSIVE).')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,125)
  125 FORMAT('      SUCH WAS NOT THE CASE HERE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,126)IT
  126 FORMAT('      THE TARGET OBSERVATION INDEX IT = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
  129 CONTINUE
!
      IF(I1.LE.I2)GO TO 139
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,131)
  131 FORMAT('***** ERROR IN LINEAR--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,132)
  132 FORMAT('      THE  NEIGHBORHOOD LOWER INDEX')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,133)
  133 FORMAT('      FOR WHICH A LOWESS IS TO BE CARRIED OUT')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,134)
  134 FORMAT('      MUST NOT EXCEED THE NEIGHBORHOOD UPPER INDEX.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,135)
  135 FORMAT('      SUCH WAS NOT THE CASE HERE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,136)IT
  136 FORMAT('      THE NEIGHBORHOOD INDICES I1 AND I2 = ',2I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
  139 CONTINUE
!
      IF(I3.LE.I4)GO TO 149
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,141)
  141 FORMAT('***** ERROR IN LINEAR--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,142)
  142 FORMAT('      THE  DESIRED LOWER INDEX FOR WHICH')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,143)
  143 FORMAT('      LOWESS PREDICTED VALUES ARE TO BE COMPUTED')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,144)
  144 FORMAT('      MUST NOT EXCEED THE DESIRED UPPER INDEX.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,145)
  145 FORMAT('      SUCH WAS NOT THE CASE HERE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,146)I3,I4
  146 FORMAT('      THE DESIRED INDICES I3 AND I4 = ',2I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
  149 CONTINUE
!
!               ***********************************************
!               **  STEP 11--                                **
!               **  CARRY OUT A LEAST SQUARES WEIGHTED       **
!               **  LINEAR FIT                               **
!               ***********************************************
!
      IF(XMAXHF.LE.0.0)GO TO 1200
      GO TO 1300
!
!               ***********************************************
!               **  STEP 12--                                **
!               **  TREAT THE CASE WHEN ALL HORIXONTAL AXIS  **
!               **  VALUES ARE IDENTICAL                     **
!               ***********************************************
!
 1200 CONTINUE
      NN=I2-I1+1
      ANN=NN
!
      SUMY=0.0
      SUMW=0.0
      DO 1210 I=I1,I2
      W=WH(I)*WV(I)
      SUMY=SUMY+W*YS(I)
      SUMW=SUMW+W
 1210 CONTINUE
      YBAR=SUMY/SUMW
!
      ALPHA=YBAR
      BETA=0.0
!
      DO 1220 I=I3,I4
      PRED(I)=ALPHA
      RES(I)=YS(I)-PRED(I)
 1220 CONTINUE
!
      GO TO 9000
!               *********************************************
!               **  STEP 13--                              **
!               **  TREAT THE CASE WHEN AT LEAST 1         **
!               **  HORIZONTAL AXIS VALUE IS DIFFERENT     **
!               *********************************************
!
 1300 CONTINUE
      NN=I2-I1+1
      ANN=NN
!
      SUMW=0.0
      DO 1310 I=I1,I2
      W=WH(I)*WV(I)
      SUMW=SUMW+W
 1310 CONTINUE
!
      IF(SUMW.GT.0.0)GO TO 1319
      WRITE(ICOUT,1311)
 1311 FORMAT('***** ERROR IN LINEAR--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1312)
 1312 FORMAT('      SUM OF WEIGHTS = 0')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1313)IT,I1,I2,N
 1313 FORMAT('IT,I1,I2,N = ',4I8)
      CALL DPWRST('XXX','BUG ')
      DO 1314 I=I1,I2
      WPROD=WH(I)*WV(I)
      WRITE(ICOUT,1315)I,WH(I),WV(I),WPROD
 1315 FORMAT('I,WH(I),WV(I),WPROD = ',I8,3E15.7)
      CALL DPWRST('XXX','BUG ')
 1314 CONTINUE
      IERROR='YES'
      GO TO 9000
 1319 CONTINUE
!
      SUMX=0.0
      SUMY=0.0
      SUMW=0.0
      DO 1320 I=I1,I2
      W=WH(I)*WV(I)
      SUMX=SUMX+W*XS(I)
      SUMY=SUMY+W*YS(I)
      SUMW=SUMW+W
 1320 CONTINUE
      XBAR=SUMX/SUMW
      YBAR=SUMY/SUMW
!
      SUM1=0.0
      SUM2=0.0
      DO 1330 I=I1,I2
      W=WH(I)*WV(I)
      DELX=XS(I)-XBAR
      DELY=YS(I)-YBAR
      SUM1=SUM1+W*DELX*DELY
      SUM2=SUM2+W*DELX**2
 1330 CONTINUE
      BETA=0.0
      IF(SUM2.NE.0.0)BETA=SUM1/SUM2
      ALPHA=YBAR-BETA*XBAR
!
      DO 1340 I=I3,I4
      PRED(I)=ALPHA+BETA*XS(I)
      RES(I)=YS(I)-PRED(I)
 1340 CONTINUE
!
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'OFF'.AND.ISUBRO.NE.'NEAR')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF LINEAR--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)ISUBRO,IBUGA3,IERROR
 9012 FORMAT('ISUBRO,IBUGA3,IERROR = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)IT,I1,I2,N,I3,I4
 9013 FORMAT('IT,I1,I2,N,I3,I4 = ',6I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9014)XMAXHF
 9014 FORMAT('XMAXHF = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      IF(N.LE.0)GO TO 9033
      DO 9031 I=I1,I2
      WRITE(ICOUT,9032)I,XS(I),YS(I),WH(I),WV(I)
 9032 FORMAT('I,XS(I),YS(I),WH(I),WV(I) = ',I8,4E15.7)
      CALL DPWRST('XXX','BUG ')
 9031 CONTINUE
 9033 CONTINUE
      WRITE(ICOUT,9040)ALPHA,BETA
 9040 FORMAT('ALPHA,BETA = ',2E15.7)
      CALL DPWRST('XXX','BUG ')
      IF(N.LE.0)GO TO 9043
      DO 9041 I=I3,I4
      WRITE(ICOUT,9042)I,PRED(I),RES(I)
 9042 FORMAT('I,PRED(I),RES(I) = ',I8,2E15.7)
      CALL DPWRST('XXX','BUG ')
 9041 CONTINUE
 9043 CONTINUE
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE LINEAR
      SUBROUTINE LINFIT(Y,X,N,                                         &
                        ALPHA,BETA,XRESSD,XRESDF,CCXY,SDALPH,SDBETA,   &
                        CCALBE,                                        &
                        ISUBRO,IBUGA3,IERROR)
!CCCC THE ABOVE ARGUMENT LIST WAS AUGMENTED    DECEMBER 1993
!
!     PURPOSE--CARRY OUT A LEAST SQUARES LINEAR FIT
!              OF THE DATA IN Y(.) AND X(.).
!              AFTER THE FIT IS DONE, COMPUTE PREDICTED VALUES,
!              RESIDUALS, RESIDUAL STANDARD DEVIATION,
!              RESIDUAL DEGREES OF FREEDOM.
!              ALSO COMPUTE THE CORRELATION COEFFICIENT.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--88/3
!     ORIGINAL VERSION--MARCH      1988
!     UPDATED         --DECEMBER   1993  SDA0, SDA1, CORR01
!     UPDATED         --DECEMBER   1993  PROTECT RESSD/DF
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION X(*)
!CCCC DIMENSION PRED(*)  DUE TO COMPLEXITIES WITH DP'S PRED & RES
!CCCC                    AND TEMP STORAGE
!CCCC DIMENSION RES(*)   DUE TO COMPLEXITIES WITH DP'S PRED & RES
!CCCC                    AND TEMP STORAGE
!CCCC DIMENSION SDPRED(*)
!CCCC DIMENSION SDRESV(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='LINF'
      ISUBN2='IT  '
      IERROR='NO'
!
      AN=N
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'NFIT')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF LINFIT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)ISUBRO,IBUGA3,IERROR,N
   52   FORMAT('ISUBRO,IBUGA3,IERROR,N = ',3(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        IF(N.GE.1)THEN
          DO 61 I=1,N
            WRITE(ICOUT,62)I,Y(I),X(I)
   62       FORMAT('I,Y(I),X(I) = ',I8,2G15.7)
            CALL DPWRST('XXX','BUG ')
   61     CONTINUE
        ENDIF
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN LINFIT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE INPUT SAMPLE SIZE MUST BE AT LEAST 1.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,116)N
  116   FORMAT('      THE SAMPLE SIZE = ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ***********************************************
!               **  STEP 11--                                **
!               **  CARRY OUT A LEAST SQUARES                **
!               **  LINEAR FIT                               **
!               ***********************************************
!
      SUMX=0.0
      SUMY=0.0
      DO 1120 I=1,N
         SUMX=SUMX+X(I)
         SUMY=SUMY+Y(I)
 1120 CONTINUE
      XBAR=SUMX/AN
      YBAR=SUMY/AN
!
      SUMXX=0.0
      SUMYY=0.0
      SUMXY=0.0
      DO 1130 I=1,N
         DELX=X(I)-XBAR
         DELY=Y(I)-YBAR
         SUMXX=SUMXX+DELX**2
         SUMYY=SUMYY+DELY**2
         SUMXY=SUMXY+DELX*DELY
 1130 CONTINUE
      BETA=0.0
      IF(SUMXX.NE.0.0)BETA=SUMXY/SUMXX
      ALPHA=YBAR-BETA*XBAR
!
!CCCC DO1140I=1,N
!CCCC    PRED(I)=ALPHA+BETA*X(I)
!CCCC    RES(I)=Y(I)-PRED(I)
!1140 CONTINUE
!
      XRESDF=N-2
      SUM=0.0
      DO 1150 I=1,N
         SUM=SUM+(Y(I)-(ALPHA+BETA*X(I)))**2
 1150 CONTINUE
      RESVAR=0.0
      IF(XRESDF.GT.0.0)RESVAR=SUM/XRESDF
      XRESSD=0.0
      IF(RESVAR.GT.0.0)XRESSD=SQRT(RESVAR)
!
!               ***********************************************
!               **  STEP 12--                                **
!               **  COMPUTE CORRELATION COEFFICIENT (X,Y)    **
!               ***********************************************
!
      ADENOM=0.0
      IF(SUMXX.GT.0.0.AND.SUMYY.GT.0.0)ADENOM=SQRT(SUMXX)*SQRT(SUMYY)
      CCXY=0.0
      IF(ADENOM.GT.0.0)CCXY=SUMXY/ADENOM
!
!               ************************************
!               **  STEP 13--                     **
!               **  COMPUTE SD OF ESTIMATES       **
!               **  AND CORR(ESTIMATES)           **
!               ************************************
!
      SDALPH=0.0
      SDBETA=0.0
      CCALBE=0.0
      SUM=0.0
      DO 1200 I=1,N
         SUM=SUM+X(I)*X(I)
 1200 CONTINUE
      IF(SUMXX.GT.0.0)THEN
         SDALPH=XRESSD*SQRT(SUM/(AN*SUMXX))
         SDBETA=XRESSD*SQRT(1.0/SUMXX)
      ENDIF
      IF(SUM.GT.0.0)THEN
         ANUM=(-XBAR)
         ADENOM=SQRT(SUM/AN)
         CCALBE=ANUM/ADENOM
      ENDIF
!
!               *******************************
!               **  STEP 14--                **
!               **  COMPUTE SD(PRED VALUES)  **
!               *******************************
!
!CCCC DO1300I=1,N
!CCCC    TERM1=1.0/AN
!CCCC    TERM2=0.0
!CCCC    IF(SUMXX.GT.0.0)TERM2=((X(I)-XBAR)**2)/SUMXX
!CCCC    SDPRED(I)=SDRES*SQRT(TERM1+TERM2)
!CCCC    SDRESV(I)=SDRES*SQRT(1.0-TERM1-TERM2)
!1300 CONTINUE
!
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'NFIT')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF LINFIT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9031)IERROR,YBAR,XBAR
 9031   FORMAT('IERROR,YBAR,XBAR = ',A4,2X,2G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9032)SUMXX,SUMYY,SUMXY
 9032   FORMAT('SUMXX,SUMYY,SUMXY = ',3G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9036)ALPHA,BETA,XRESSD,XRESDF
 9036   FORMAT('ALPHA,BETA,XRESSD,XRESDF = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9038)ADENOM,CCXY
 9038   FORMAT('ADENOM,CCXY = ',2E15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9039)ADENOM,CCXY,SDALPH,SDBETA,CCALBE
 9039   FORMAT('ADENOM,CCXY,SDALPH,SDBETA,CCALBE = ',5G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE LINFIT
      SUBROUTINE LINFI2(Y,X,N,ALPHA,BETA,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--CARRY OUT A LEAST SQUARES LINEAR FIT
!              OF THE DATA IN Y(.) AND X(.).
!              THIS IS A MODIFIED VERSION OF LINFIT.  THE
!              DISTINCTION IS THAT THIS VERSION HAS BEEN PRUNED
!              DOWN TO ONLY GENERATE THE PARAMETER ESTIMATES
!              (USED BY PPCC PLOT FOR ESTIMATES OF LOCATION AND
!              SCALE).
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004/5
!     ORIGINAL VERSION--MAY        2004
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='LINF'
      ISUBN2='I2  '
      IERROR='NO'
!
      AN=N
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'NFI2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF LINFI2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)ISUBRO,IBUGA3,IERROR,N
   52   FORMAT('ISUBRO,IBUGA3,IERROR,N = ',3(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        IF(N.GE.1)THEN
          DO 61 I=1,N
            WRITE(ICOUT,62)I,Y(I),X(I)
   62       FORMAT('I,Y(I),X(I) = ',I8,2G15.7)
            CALL DPWRST('XXX','BUG ')
   61     CONTINUE
        ENDIF
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(N.LT.1)THEN
        ALPHA=0.0
        BETA=1.0
        GO TO 9000
      ENDIF
!
!               ***********************************************
!               **  STEP 11--                                **
!               **  CARRY OUT A LEAST SQUARES                **
!               **  LINEAR FIT                               **
!               ***********************************************
!
      SUMX=0.0
      SUMY=0.0
      DO 1120 I=1,N
         SUMX=SUMX+X(I)
         SUMY=SUMY+Y(I)
 1120 CONTINUE
      XBAR=SUMX/AN
      YBAR=SUMY/AN
!
      SUMXX=0.0
      SUMYY=0.0
      SUMXY=0.0
      DO 1130 I=1,N
         DELX=X(I)-XBAR
         DELY=Y(I)-YBAR
         SUMXX=SUMXX+DELX**2
         SUMYY=SUMYY+DELY**2
         SUMXY=SUMXY+DELX*DELY
 1130 CONTINUE
      BETA=0.0
      IF(SUMXX.NE.0.0)BETA=SUMXY/SUMXX
      ALPHA=YBAR-BETA*XBAR
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'NFI2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF LINFI2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9031)YBAR,XBAR,ALPHA,BETA
 9031   FORMAT('YBAR,XBAR,ALPHA,BETA = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9032)SUMXX,SUMYY,SUMXY
 9032   FORMAT('SUMXX,SUMYY,SUMXY = ',3G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE LINFI2
      SUBROUTINE LINFI3(Y,X,N,   &
                        ALPHA,BETA,XRESSD,XRESDF,CCXY,SDALPH,SDBETA,   &
                        CCALBE,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--CARRY OUT A LEAST SQUARES LINEAR FIT OF THE DATA IN Y(.)
!              AND X(.).  AFTER THE FIT IS DONE, COMPUTE PREDICTED
!              VALUES, RESIDUALS, RESIDUAL STANDARD DEVIATION, RESIDUAL
!              DEGREES OF FREEDOM, AND THE CORRELATION COEFFICIENT.
!
!              THIS IS A COPY OF LINFIT THAT IMPLEMENTS THE FIT WITH
!              NO INTERCEPT TERM.
!
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2016/11
!     ORIGINAL VERSION--NOVEMBER   2016
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='LINF'
      ISUBN2='IT  '
      IERROR='NO'
!
      AN=N
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'NFI3')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF LINFI3--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)ISUBRO,IBUGA3,IERROR,N
   52   FORMAT('ISUBRO,IBUGA3,IERROR,N = ',3(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        IF(N.GE.1)THEN
          DO 61 I=1,N
            WRITE(ICOUT,62)I,Y(I),X(I)
   62       FORMAT('I,Y(I),X(I) = ',I8,2G15.7)
            CALL DPWRST('XXX','BUG ')
   61     CONTINUE
        ENDIF
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN LINFI3--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE INPUT SAMPLE SIZE MUST BE AT LEAST 1.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,116)N
  116   FORMAT('      THE SAMPLE SIZE = ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ***********************************************
!               **  STEP 11--                                **
!               **  CARRY OUT A LEAST SQUARES                **
!               **  LINEAR FIT                               **
!               ***********************************************
!
      SUMX=0.0
      SUMY=0.0
      DO 1120 I=1,N
         SUMX=SUMX+X(I)
         SUMY=SUMY+Y(I)
 1120 CONTINUE
      XBAR=SUMX/AN
      YBAR=SUMY/AN
!
      SUMXX=0.0
      SUMYY=0.0
      SUMXY=0.0
      DO 1130 I=1,N
         DELX=X(I)-XBAR
         DELY=Y(I)-YBAR
         SUMXX=SUMXX+DELX**2
         SUMYY=SUMYY+DELY**2
         SUMXY=SUMXY+DELX*DELY
 1130 CONTINUE
      BETA=0.0
      IF(SUMXX.NE.0.0)BETA=SUMXY/SUMXX
      ALPHA=0.0
!
      XRESDF=N-1
      SUM=0.0
      DO 1150 I=1,N
         SUM=SUM+(Y(I)-(ALPHA+BETA*X(I)))**2
 1150 CONTINUE
      RESVAR=0.0
      IF(XRESDF.GT.0.0)RESVAR=SUM/XRESDF
      XRESSD=0.0
      IF(RESVAR.GT.0.0)XRESSD=SQRT(RESVAR)
!
!               ***********************************************
!               **  STEP 12--                                **
!               **  COMPUTE CORRELATION COEFFICIENT (X,Y)    **
!               ***********************************************
!
      ADENOM=0.0
      IF(SUMXX.GT.0.0.AND.SUMYY.GT.0.0)ADENOM=SQRT(SUMXX)*SQRT(SUMYY)
      CCXY=0.0
      IF(ADENOM.GT.0.0)CCXY=SUMXY/ADENOM
!
!               ************************************
!               **  STEP 13--                     **
!               **  COMPUTE SD OF ESTIMATES       **
!               **  AND CORR(ESTIMATES)           **
!               ************************************
!
      SDALPH=0.0
      SDBETA=0.0
      CCALBE=0.0
      SUM=0.0
      DO 1200 I=1,N
         SUM=SUM+X(I)*X(I)
 1200 CONTINUE
      IF(SUMXX.GT.0.0)THEN
         SDBETA=XRESSD*SQRT(1.0/SUMXX)
      ENDIF
      IF(SUM.GT.0.0)THEN
         ANUM=(-XBAR)
         ADENOM=SQRT(SUM/AN)
         CCALBE=ANUM/ADENOM
      ENDIF
!
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'NFI3')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF LINFI3--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9031)IERROR,YBAR,XBAR
 9031   FORMAT('IERROR,YBAR,XBAR = ',A4,2X,2G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9032)SUMXX,SUMYY,SUMXY
 9032   FORMAT('SUMXX,SUMYY,SUMXY = ',3G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9036)ALPHA,BETA,XRESSD,XRESDF
 9036   FORMAT('ALPHA,BETA,XRESSD,XRESDF = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9038)ADENOM,CCXY
 9038 FORMAT('ADENOM,CCXY = ',2G15.7)
      CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9039)ADENOM,CCXY,SDALPH,SDBETA,CCALBE
 9039   FORMAT('ADENOM,CCXY,SDALPH,SDBETA,CCALBE = ',5G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE LINFI3
      SUBROUTINE LININT(Y,X,N,X2,N2,IWRITE,Y2,   &
                        YTEMP,YDIST,XDIST,   &
                        IBUGG3,ISUBRO,IERROR)
!
!     PURPOSE--COMPUTE LINEAR INTERPOLATION OF A VARIABLE
!              (GENERATE INTERPOLATED POINTS).
!     INPUT  ARGUMENTS--Y      = SINGLE PRECISION VARIABLE
!                                CONTAINING THE ORIGINAL
!                                VERTICAL AXIS DATA POINTS.
!                     --X      = SINGLE PRECISION VARIABLE
!                                CONTAINING THE ORIGINAL
!                                HORIZONTAL AXIS DATA POINTS.
!                     --X2     = SINGLE PRECISION VARIABLE
!                                CONTAINING THE DESIRED
!                                HORIZONTAL AXIS INTERPOLATION
!                                POINTS.
!     OUTPUT ARGUMENTS--Y2     = SINGLE PRECISION VARIABLE
!                                CONTAINING THE COMPUTED
!                                VERTICAL AXIS INTERPOLATION
!                                POINTS.
!     NOTE--IT IS PROBABLY NOT PERMISSIBLE TO HAVE THE OUTPUT VECTOR Y2(.)
!           BEING IDENTICAL TO THE INPUT VECTOR Y(.)
!     NOTE--THIS SUBROUTINE DOES NOT ASSUME THAT THE INPUT
!           DATA IS ALREADY SORTED ACCORDING TO THE
!           HORIZONTAL AXIS VARIABLE.
!           SUCH SORTING IS DOEN HEREIN.
!     CAUTION--THE INPUT VECTORS Y AND X ARE SORTED HEREIN
!              AND SO MAY BE DIFFERENT UPON LEAVING THIS SUBROUTINE
!              THAN UPON ENTERING THIS SUBROUTINE.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--94/5
!     ORIGINAL VERSION--MAY       1994.
!     UPDATED         --JULY      2019. MOVE CREATION OF SCRATCH
!                                       STORAGE TO CALLING ROUTINE
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGG3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
!
      DIMENSION Y(*)
      DIMENSION X(*)
      DIMENSION X2(*)
      DIMENSION Y2(*)
      DIMENSION YTEMP(*)
      DIMENSION YDIST(*)
      DIMENSION XDIST(*)
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='LINI'
      ISUBN2='NT  '
      IERROR='NO'
!
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'NINT')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF LININT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)N,N2
   52   FORMAT('N,N2 = ',2I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,Y(I),X(I)
   56     FORMAT('I,Y(I),X(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
        DO 65 I=1,N2
          WRITE(ICOUT,66)I,X2(I)
   66     FORMAT('I,X2(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   65   CONTINUE
      ENDIF
!
!               ****************************************
!               **  STEP 11--                         **
!               **  SORT THE INPUT DATA ACCORDING     **
!               **  TO THE HORIZONTAL AXIS VARIABLE   **
!               ****************************************
!
      CALL SORTC(X,Y,N,X,Y)
!
!               *******************************************************
!               **  STEP 12--                                        **
!               **  DETERMINE THE NUMBER OF DISTINCT X VALUES        **
!               *******************************************************
!
      ISTEPN='12'
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'NINT')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NDIST=0
      DO 1210 I=1,N
        IF(NDIST.EQ.0)GO TO 1220
        DO 1215 I2=1,NDIST
          IF(X(I).EQ.XDIST(I2))GO TO 1210
 1215   CONTINUE
 1220   CONTINUE
        NDIST=NDIST+1
        XDIST(NDIST)=X(I)
 1210 CONTINUE
!
      CALL SORT(XDIST,NDIST,XDIST)
!
!               *****************************************************
!               **  STEP 13--                                      **
!               **  IF ALL DISTINCT (THAT IS, NO REPLICATION),     **
!               **  (THAT IS, HAVE NO REPLICATION),                **
!               **  THEN COPY OVER Y VALUES.                       **
!               **  IF NOT ALL DISTINCT                            **
!               **  (THAT IS, HAVE SOME REPLICATION),              **
!               **  THEN COMPUTE A MEAN VALUE OVER THE REPLICATES  **
!               **  AND TREAT THAT AS THE COMMON VALUE.            **
!               **  THE CORE OF THE INTERPOLATION CODE             **
!               **  IS EXPECTING SORTED, DISTINCT X VALUES.        **
!               *****************************************************
!
      IF(NDIST.EQ.N)THEN
        DO 1311 K=1,NDIST
          YDIST(K)=Y(K)
 1311   CONTINUE
      ELSE
        DO 1321 K=1,NDIST
          TAG=XDIST(K)
          J=0
          DO 1322 I=1,N
            IF(X(I).EQ.TAG)THEN
              J=J+1
              YTEMP(J)=Y(I)
            ENDIF
 1322     CONTINUE
          NI=J
          CALL MEAN(YTEMP,NI,IWRITE,YMEAN,IBUGG3,IERROR)
          YDIST(K)=YMEAN
 1321   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 14--                             **
!               **  COMPUTE INTERPOLATED VALUES           **
!               ********************************************
!
      CALL LININ2(YDIST,XDIST,NDIST,X2,N2,Y2,IBUGG3,ISUBRO,IERROR)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'NINT')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF LININT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9051)NDIST
 9051   FORMAT('NDIST = ',I8)
        CALL DPWRST('XXX','BUG ')
        DO 9052 I=1,NDIST
          WRITE(ICOUT,9053)I,XDIST(I),YDIST(I)
 9053     FORMAT('I,XDIST(I),YDIST(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
 9052   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE LININT
      SUBROUTINE LININ2(Y,X,N,X2,N2,Y2,IBUGG3,ISUBRO,IERROR)
!
!     PURPOSE--COMPUTE LINEAR INTERPOLATION OF A VARIABLE
!              (GENERATE INTERPOLATED POINTS).
!     INPUT  ARGUMENTS--Y      = SINGLE PRECISION VARIABLE
!                                CONTAINING THE ORIGINAL
!                                VERTICAL AXIS DATA POINTS.
!                     --X      = SINGLE PRECISION VARIABLE
!                                CONTAINING THE ORIGINAL
!                                HORIZONTAL AXIS DATA POINTS.
!                     --X2     = SINGLE PRECISION VARIABLE
!                                CONTAINING THE DESIRED
!                                HORIZONTAL AXIS INTERPOLATION
!                                POINTS.
!     OUTPUT ARGUMENTS--Y2     = SINGLE PRECISION VARIABLE
!                                CONTAINING THE COMPUTED
!                                VERTICAL AXIS INTERPOLATION
!                                POINTS.
!     NOTE--IT IS PROBABLY NOT PERMISSIBLE TO HAVE THE OUTPUT VECTOR Y2(.)
!           BEING IDENTICAL TO THE INPUT VECTOR Y(.)
!     NOTE--THIS SUBROUTINE DOES NOT ASSUME THAT THE INPUT
!           DATA IS ALREADY SORTED ACCORDING TO THE
!           HORIZONTAL AXIS VARIABLE.
!           SUCH SORTING IS DOEN HEREIN.
!     CAUTION--THE INPUT VECTORS Y AND X ARE SORTED HEREIN
!              AND SO MAY BE DIFFERENT UPON LEAVING THIS SUBROUTINE
!              THAN UPON ENTERING THIS SUBROUTINE.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--94/5
!     ORIGINAL VERSION--MAY L     1994.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IBUGG3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
!
      DIMENSION Y(*)
      DIMENSION X(*)
      DIMENSION X2(*)
      DIMENSION Y2(*)
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='LINI'
      ISUBN2='N2  '
      IERROR='NO'
!
      I2=0
!
      IF(IBUGG3.EQ.'OFF'.AND.ISUBRO.NE.'NIN2')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF LININ2--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)N
   52 FORMAT('N = ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 55 I=1,N
      WRITE(ICOUT,56)I,Y(I),X(I)
   56 FORMAT('I,Y(I),X(I) = ',I8,2E15.7)
      CALL DPWRST('XXX','BUG ')
   55 CONTINUE
      WRITE(ICOUT,62)N2
   62 FORMAT('N2 = ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 65 I=1,N2
      WRITE(ICOUT,66)I,X2(I)
   66 FORMAT('I,X2(I) = ',I8,E15.7)
      CALL DPWRST('XXX','BUG ')
   65 CONTINUE
   90 CONTINUE
!
      NM1=N-1
      NM2=N-2
!
!               ****************************************
!               **  STEP 31--
!               **  COMPUTE INTERPOLATION VALUES
!               ****************************************
!
      DO 3100 J=1,N2
      XT=X2(J)
      IF(X(1).GT.XT.OR.XT.GT.X(N))GO TO 3110
      GO TO 3119
!
 3110 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3111)
 3111 FORMAT('***** ERROR IN LININ2--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3112)
 3112 FORMAT('      AN ATTEMPT WAS MADE TO COMPUTE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3113)
 3113 FORMAT('      A SMOOTHED VALUE BEYOND THE RANGE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3114)
 3114 FORMAT('      OF THE DATA--SUCH EXTRAPOLATION')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3115)
 3115 FORMAT('      IS UNRELIABLE AND NOT PERMITTED.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3116)X(1)
 3116 FORMAT('         SMALLEST DATA POINT X(1)      = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3117)X(N)
 3117 FORMAT('         LARGEST DATA POINT  X(N)      = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3118)XT
 3118 FORMAT('         ATTEMPTED EXTRAPOLATION POINT = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
 3119 CONTINUE
!
      DO 3200 I=1,N
      I2=I
      IF(X(I).EQ.XT)GO TO 3210
      IF(X(I).GT.XT)GO TO 3220
 3200 CONTINUE
!
 3210 CONTINUE
      Y2(J)=Y(I2)
      GO TO 3100
!
 3220 CONTINUE
      K1=I2-1
      DELX=X(I2)-X(K1)
      DELY=Y(I2)-Y(K1)
      SLOPE=DELY/DELX
      Y2(J)=SLOPE*(XT-X(K1))+Y(K1)
!
 3100 CONTINUE
!
!               ****************************************
!               **  STEP 41--
!               **  IF CALLED FOR,
!               **  WRITE OUT INTERPOLATION VALUES
!               ****************************************
!
      IF(IBUGG3.EQ.'OFF'.AND.ISUBRO.NE.'NIN2')GO TO 4190
      DO 4100 J=1,N2
      WRITE(ICOUT,4110)X2(J),Y2(J)
      CALL DPWRST('XXX','BUG ')
 4110 FORMAT('X2(J),Y2(J) = ',2E15.7)
 4100 CONTINUE
 4190 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG3.EQ.'OFF'.AND.ISUBRO.NE.'NIN2')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF LININ2--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)N,N2
 9012 FORMAT('N,N2 = ',2I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9041)N2
 9041 FORMAT('N2 = ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 9042 I=1,N2
      WRITE(ICOUT,9043)I,X2(I),Y2(I)
 9043 FORMAT('I,X2(I),Y2(I) = ',I8,2E15.7)
      CALL DPWRST('XXX','BUG ')
 9042 CONTINUE
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE LININ2
      REAL FUNCTION LININ3(X1,Y1,X2,Y2,X3,IBUGG3,ISUBRO,IERROR)
!
!     PURPOSE--COMPUTE LINEAR INTERPOLATION FOR PARAMETERS
!              (GENERATE INTERPOLATED POINTS).
!     INPUT  ARGUMENTS--Y1     = SINGLE PRECISION PARAMETER
!                                CONTAINING THE FIRST ORIGINAL
!                                VERTICAL AXIS DATA POINT.
!                     --X1     = SINGLE PRECISION PARAMETER
!                                CONTAINING THE FIRST ORIGINAL
!                                HORIZONTAL AXIS DATA POINT.
!                     --Y2     = SINGLE PRECISION PARAMETER
!                                CONTAINING THE SECOND ORIGINAL
!                                VERTICAL AXIS DATA POINT.
!                     --X2     = SINGLE PRECISION PARAMETER
!                                CONTAINING THE SECOND ORIGINAL
!                                HORIZONTAL AXIS DATA POINT.
!                     --X3     = SINGLE PRECISION PARAMETER
!                                CONTAINING THE DESIRED
!                                HORIZONTAL AXIS INTERPOLATION
!                                POINT.
!     OUTPUT ARGUMENTS--LININ3   CONTAINING THE COMPUTED
!                                VERTICAL AXIS INTERPOLATION
!                                POINTS.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2013/8
!     ORIGINAL VERSION--AUGUST    2013.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IBUGG3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='LINI'
      ISUBN2='N3  '
      IERROR='NO'
      LININ3=0.0
!
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'NIN3')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF LININ3--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,56)Y1,X1,X2
   56   FORMAT('Y1,X1,X2 = ',3G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ********************************************
!               **  STEP 14--                             **
!               **  COMPUTE INTERPOLATED VALUES           **
!               ********************************************
!
      IF(X2.LT.X1)THEN
        ATEMP=X2
        X2=X1
        X1=ATEMP
        ATEMP=Y2
        Y2=Y1
        Y1=ATEMP
      ENDIF
!
      IF(X3.LT.X1 .OR. X3.GT.X2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,101)
  101   FORMAT('***** ERROR IN LINEAR INTERPOLATION--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,103)
  103   FORMAT('      THE POINT TO BE INTERPOLATED IS OUT OF RANGE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,105)X1
  105   FORMAT('      MINIMUM POINT:       ',G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,107)X2
  107   FORMAT('      MAXIMUM POINT:       ',G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,109)X3
  109   FORMAT('      INTERPOLATION POINT: ',G15.7)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      Y3=Y1 + (Y2-Y1)*(X3-X1)/(X2-X1)
      LININ3=Y3
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'NIN3')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF LININ3--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IERROR,Y3
 9012   FORMAT('IERROR,Y3 = ',A4,2X,G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END FUNCTION LININ3
      SUBROUTINE LKCDF(X,A,B,BETA,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE LAGRANGE KATZ
!              DISTRIBUTION WITH SHAPE PARAMETERS A, B, AND BETA.
!              THIS DISTRIBUTION IS DEFINED FOR ALL NON-NEGATIVE
!              INTEGERS  X >= 0.
!
!              THE PROBABILITY MASS FUNCTION IS:
!              p(X;A,B,BETA)=
!                  (A/BETA)/((A/BETA) + (X*B/BETA) + X)*
!                  ((A/BETA)+X*b/BETA+X  X)*
!                  BETA**X*(1-BETA)**((A/BETA)+X*B/BETA)
!                  X = 0, 1, 2, 3, ,...
!                  A > 0, B > -BETA, BETA < 1
!
!              THE CUMULATIVE DISTRIBUTION FUNCTION IS COMPUTED
!              FROM THE FOLLOWING RECURRENCE RELATION:
!
!              P(X+1) = {(A+B*(X+1)+BETA*X)/(X+1)}*(1-BETA)**(b/BETA)*
!                       PROD[i=1 to X-1][(1 + b/(a+B*X+BETA*i)]*P(X)
!              WHERE P(0) = (1-BETA)**(A/BETA) AND
!                    P(1) = A*(1-BETA)**(b/BETA)*P(0)
!
!     INPUT  ARGUMENTS--X      = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE A NON-NEGATIVE INTEGER.
!                     --A      = THE FIRST SHAPE PARAMETER
!                     --B      = THE SECOND SHAPE PARAMETER
!                     --BETA   = THE THIRD SHAPE PARAMETER
!     OUTPUT ARGUMENTS--CDF    = THE DOUBLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION CUMULATIVE DISTRIBUTION FUNCTION
!             VALUE CDF FOR THE LAGRANGE KATZ DISTRIBUTION WITH
!             SHAPE PARAMETERS A, B, AND BETA
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE A NON-NEGATIVE INTEGER
!                 --A > 0, B > -BETA, BETA < 1
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--CONSUL AND FAMOYE (2006), "LAGRANGIAN PROBABILITY
!                 DISTRIBUTIONS", BIRKHAUSER, CHAPTER 12.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007/2
!     ORIGINAL VERSION--FEBRUARY  2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      IMPLICIT DOUBLE PRECISION (A-H, O-Z)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IX=INT(X+0.5D0)
      CDF=0.0D0
!
      IF(IX.LT.0)THEN
        WRITE(ICOUT,4)
    4   FORMAT('***** ERROR--THE FIRST ARGUMENT TO LKCDF IS LESS ',   &
               'THAN 0.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
        GO TO 9000
      ELSEIF(A.LE.0.0D0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO LKCDF IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)A
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(BETA.GE.1.0D0)THEN
        WRITE(ICOUT,25)
   25   FORMAT('***** ERROR--THE FOURTH ARGUMENT TO LKCDF IS GREATER ',   &
               'THAN OR EQUAL TO 1.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(B.LE.-BETA)THEN
        WRITE(ICOUT,35)
   35   FORMAT('***** ERROR--THE THIRD ARGUMENT TO LKCDF IS LESS ',   &
               'THAN OR EQUAL TO -(FOURTH ARGUMENT).')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)B
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!
!     USE THE RECURRENCE RELATION (PAGE 243 OF CONSUL AND FAMOYE):
!
      CDF=(1.0D0 - BETA)**(A/BETA)
      IF(IX.EQ.0)GO TO 9000
!
      DPDF=A*(1.0D0 - BETA)**(B/BETA)*CDF
      CDF=CDF + DPDF
      IF(IX.EQ.1)GO TO 9000
!
!     FOR X = 2, USE RELATION:
!
!         p(x+1;a,b,beta)=p(x;a+b,b,beta)*(a+c*x)/(1+x)
!
!     NOTE THAT WE NEED TO REPLACE A WITH A + B IN COMPUTATION
!     OF p(1).
!
      DP0=(1.0D0 - BETA)**((A+B)/BETA)
      DP1=(A+B)*(1.0D0 - BETA)**(B/BETA)*DP0
      DX=1.0D0
      C=A*(B+BETA)/(A+B)
      DPDF=DP1*(A + C*DX)/(1.0 + DX)
      CDF=CDF + DPDF
      IF(IX.EQ.2)GO TO 9000
      DPDFSV=DPDF
!
      DTERM1=(B/BETA)*DLOG(1.0D0 - BETA)
      DO 100 I=3,IX
        DX=DBLE(I)
        DTERM2=DLOG(A + B*DX + BETA*(DX-1.0D0))
        DTERM3=DLOG(DX)
        IF(DPDFSV.LE.0.0D0)THEN
          GO TO 9000
        ELSE
          DTERM4=DLOG(DPDFSV)
        ENDIF
!
        DSUM=0.0D0
        DO 200 J=1,I-2
          DSUM=DSUM + DLOG(1.0D0 + B/   &
               (A + B*(DX-1.0D0) + BETA*DBLE(J)))
  200   CONTINUE
!
        DPDF=DEXP(DTERM1 + DTERM2 - DTERM3 + DTERM4 + DSUM)
        CDF=CDF + DPDF
        DPDFSV=DPDF
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE LKCDF
      SUBROUTINE LKPDF(X,A,B,BETA,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE LAGRANGE KATZ
!              DISTRIBUTION WITH SHAPE PARAMETERS A, B, AND BETA.
!              THIS DISTRIBUTION IS DEFINED FOR ALL NON-NEGATIVE
!              INTEGERS  X >= 0.
!
!              THE PROBABILITY MASS FUNCTION IS:
!              p(X;A,B,BETA)=
!                  (A/BETA)/((A/BETA) + (X*B/BETA) + X)*
!                  ((A/BETA)+X*b/BETA+X  X)*
!                  BETA**X*(1-BETA)**((A/BETA)+X*B/BETA)
!                  X = 0, 1, 2, 3, ,...
!                  A > 0, B > -BETA, BETA < 1
!
!              THE PROBABILITIES ARE COMPUTED
!              FROM THE FOLLOWING RECURRENCE RELATION:
!
!              P(X+1) = {(A+B*(X+1)+BETA*X)/(X+1)}*(1-BETA)**(b/BETA)*
!                       PROD[i=1 to X-1][(1 + b/(a+B*X+BETA*i)]*P(X)
!              WHERE P(0) = (1-BETA)**(A/BETA) AND
!                    P(1) = A*(1-BETA)**(b/BETA)*P(0)
!
!     INPUT  ARGUMENTS--X      = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE A NON-NEGATIVE INTEGER.
!                     --A      = THE FIRST SHAPE PARAMETER
!                     --B      = THE SECOND SHAPE PARAMETER
!                     --BETA   = THE THIRD SHAPE PARAMETER
!     OUTPUT ARGUMENTS--PDF    = THE DOUBLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PROBABILITY DENSITY FUNCTION
!             VALUE PDF FOR THE LAGRANGE KATZ DISTRIBUTION WITH
!             SHAPE PARAMETERS A, B, AND BETA
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE A NON-NEGATIVE INTEGER
!                 --A > 0, B > -BETA, BETA < 1
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--CONSUL AND FAMOYE (2006), "LAGRANGIAN PROBABILITY
!                 DISTRIBUTIONS", BIRKHAUSER, CHAPTER 12.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007/2
!     ORIGINAL VERSION--FEBRUARY  2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      IMPLICIT DOUBLE PRECISION (A-H, O-Z)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IX=INT(X+0.5D0)
      PDF=0.0D0
!
      IF(IX.LT.0)THEN
        WRITE(ICOUT,4)
    4   FORMAT('***** ERROR--THE FIRST ARGUMENT TO LKPDF IS LESS ',   &
               'THAN 0')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(A.LE.0.0D0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO LKPDF IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)A
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(BETA.GE.1.0D0)THEN
        WRITE(ICOUT,25)
   25   FORMAT('***** ERROR--THE FOURTH ARGUMENT TO LKPDF IS GREATER ',   &
               'THAN OR EQUAL TO 1.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(B.LE.-BETA)THEN
        WRITE(ICOUT,35)
   35   FORMAT('***** ERROR--THE THIRD ARGUMENT TO LKPDF IS LESS ',   &
               'THAN OR EQUAL TO -(FOURTH ARGUMENT).')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)B
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!     ALTHOUGH THE DIRECT COMPUTATION OF THE PDF MIGHT BE
!     MORE EFFICIENT IN SOME CASES, IT IS NOT CLEAR HOW TO
!     HANDLE NEGATIVE VALUES OF BETA (THE DLNGAM FUNCTION IS
!     ONLY IMPLEMENTED FOR POSITIVE ARGUMENTS).  SO IN THE
!     MEANTIME, USE THE RECURRENCE RELATION (PAGE 243 OF CONSUL
!     AND FAMOYE).
!
!CCCC  DX=DBLE(IX)
!CCCC  DTERM1=A/BETA
!CCCC  DTERM2=DX*B/BETA
!
!CCCC  DTERM3=DLOG(DTERM1) - DLOG(DTERM1 + DTERM2 + DX)
!CCCC  DTERM4=DX*DLOG(BETA)
!CCCC  DTERM5=(DTERM1+DTERM2)*DLOG(1.0D0 - BETA)
!CCCC  DTERM6=DLNGAM(DTERM1 + DTERM2 + DX + 1.0D0)
!CCCC  DTERM7=DLNGAM(DTERM1 + DTERM2 + 1.0D0)
!CCCC  DTERM8=DLNGAM(DX + 1.0D0)
!CCCC  DPDF=DTERM3 + DTERM4 + DTERM5 + DTERM6 - DTERM7 - DTERM8
!CCCC  PDF=DEXP(DPDF)
!
      CDF=(1.0D0 - BETA)**(A/BETA)
      IF(IX.EQ.0)THEN
        PDF=CDF
        GO TO 9000
      ENDIF
!
      DPDF=A*(1.0D0 - BETA)**(B/BETA)*CDF
      IF(IX.EQ.1)THEN
        PDF=DPDF
        GO TO 9000
      ENDIF
      CDF=CDF + DPDF
!
      DPDFSV=DPDF
      DTERM1=(B/BETA)*DLOG(1.0D0 - BETA)
!
      DO 100 I=2,IX
        DX=DBLE(I)
        DTERM2=DLOG(A + B*DX + BETA*(DX-1.0D0))
        DTERM3=DLOG(DX)
        IF(DPDFSV.LE.0.0D0)THEN
          GO TO 9000
        ELSE
          DTERM4=DLOG(DPDFSV)
        ENDIF
!
        IF(I-2.GE.1)THEN
          DSUM=0.0D0
          DO 200 J=1,I-2
            DSUM=DSUM + DLOG(1.0D0 + B/   &
                 (A + B*(DX-1.0D0) + BETA*DBLE(J)))
  200     CONTINUE
        ELSE
!CCCC     DSUM=DLOG(1.0D0 + B/(A + B))
          DSUM=DLOG(1.0D0)
        ENDIF
!
        DPDF=DEXP(DTERM1 + DTERM2 - DTERM3 + DTERM4 + DSUM)
        CDF=CDF + DPDF
        DPDFSV=DPDF
  100 CONTINUE
!
      PDF=DPDF
!
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE LKPDF
      SUBROUTINE LKPPF(P,A,B,BETA,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE LAGRANGE KATZ
!              DISTRIBUTION WITH SHAPE PARAMETERS A, B, AND BETA.
!              THIS DISTRIBUTION IS DEFINED FOR ALL NON-NEGATIVE
!              INTEGERS  X >= 0.
!
!              THE PROBABILITY MASS FUNCTION IS:
!              p(X;A,B,BETA)=
!                  (A/BETA)/((A/BETA) + (X*B/BETA) + X)*
!                  ((A/BETA)+X*b/BETA+X  X)*
!                  BETA**X*(1-BETA)**((A/BETA)+X*B/BETA)
!                  X = 0, 1, 2, 3, ,...
!                  A > 0, B > -BETA, BETA < 1
!
!              THE CUMULATIVE DISTRIBUTION FUNCTION IS COMPUTED
!              FROM THE FOLLOWING RECURRENCE RELATION:
!
!              P(X+1) = {(A+B*(X+1)+BETA*X)/(X+1)}*(1-BETA)**(b/BETA)*
!                       PROD[i=1 to X-1][(1 + b/(a+B*X+BETA*i)]*P(X)
!              WHERE P(0) = (1-BETA)**(A/BETA) AND
!                    P(1) = A*(1-BETA)**(b/BETA)*P(0)
!
!              THE PERCENT POINT FUNCTION IS COMPUTED BY SUMMING
!              THE CUMULATIVE DISTRIBUTION FUNCTION UNTIL THE
!              APPROPRIATE PROBABILITY IS REACHED.
!
!     INPUT  ARGUMENTS--P      = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --A      = THE FIRST SHAPE PARAMETER
!                     --B      = THE SECOND SHAPE PARAMETER
!                     --BETA   = THE THIRD SHAPE PARAMETER
!     OUTPUT ARGUMENTS--PPF    = THE DOUBLE PRECISION PERCENT POINT
!                                FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION PERCENT POINT FUNCTION
!             VALUE PPF FOR THE LAGRANGE KATZ DISTRIBUTION WITH
!             SHAPE PARAMETERS A, B, AND BETA
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--0 <= P < 1
!                 --A > 0, B > -BETA, BETA < 1
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--CONSUL AND FAMOYE (2006), "LAGRANGIAN PROBABILITY
!                 DISTRIBUTIONS", BIRKHAUSER, CHAPTER 12.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007/2
!     ORIGINAL VERSION--FEBRUARY  2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      IMPLICIT DOUBLE PRECISION (A-H, O-Z)
!
!-----COMMON----------------------------------------------------------
!
      REAL R1MACH
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PPF=0.0D0
!
      IF(P.LT.0.0 .OR. P.GE.1.0)THEN
        WRITE(ICOUT,4)
    4   FORMAT('***** ERROR--THE FIRST ARGUMENT TO LKPPF IS OUTSIDE ',   &
               'THE (0,1] INTERVAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(A.LE.0.0D0)THEN
        WRITE(ICOUT,15)
   15   FORMAT('***** ERROR--THE SECOND ARGUMENT TO LKPPF IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)A
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(BETA.GE.1.0D0)THEN
        WRITE(ICOUT,25)
   25   FORMAT('***** ERROR--THE FOURTH ARGUMENT TO LKPPF IS GREATER ',   &
               'THAN OR EQUAL TO 1.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(B.LE.-BETA)THEN
        WRITE(ICOUT,35)
   35   FORMAT('***** ERROR--THE THIRD ARGUMENT TO LKPPF IS LESS ',   &
               'THAN OR EQUAL TO -(FOURTH ARGUMENT).')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)B
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)BETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!     USE THE RECURRENCE RELATION (PAGE 243 OF CONSUL AND FAMOYE):
!
      DEPS=1.0D-7
      DCDF=(1.0D0 - BETA)**(A/BETA)
      IF(DCDF.GE.P-DEPS)THEN
        PPF=0.0D0
        GO TO 9000
      ENDIF
!
      DPDF=A*(1.0D0 - BETA)**(B/BETA)*DCDF
      DCDF=DCDF + DPDF
      IF(DCDF.GE.P-DEPS)THEN
        PPF=1.0D0
        GO TO 9000
      ENDIF
!
      DPDFSV=DPDF
      DTERM1=(B/BETA)*DLOG(1.0D0 - BETA)
!
      I=1
!
  100 CONTINUE
        I=I+1
        IF(DBLE(I).GE.DBLE(I1MACH(9)))THEN
          WRITE(ICOUT,55)
   55     FORMAT('***** ERROR--THE COMPUTED PERCENT POINT VALUE ',   &
                 'EXCEEDS THE LARGEST MACHINE INTEGER.')
          CALL DPWRST('XXX','BUG ')
          PPF=0.0D0
          GO TO 9000
        ENDIF
        DX=DBLE(I)
!
        DTERM2=DLOG(A + B*DX + BETA*(DX-1.0D0))
        DTERM3=DLOG(DX)
        IF(DPDFSV.LE.0.0D0)THEN
          PPF=DBLE(I)
          GO TO 9000
        ELSE
          DTERM4=DLOG(DPDFSV)
        ENDIF
!
        IF(I-2.GE.1)THEN
          DSUM=0.0D0
          DO 200 J=1,I-2
            DSUM=DSUM + DLOG(1.0D0 + B/   &
                 (A + B*(DX-1.0D0) + BETA*DBLE(J)))
  200     CONTINUE
        ELSE
!CCCC     DSUM=DLOG(1.0D0 + B/(A + B))
          DSUM=DLOG(1.0D0)
        ENDIF
!
        DPDF=DEXP(DTERM1 + DTERM2 - DTERM3 + DTERM4 + DSUM)
        DCDF=DCDF + DPDF
        DPDFSV=DPDF
!
        IF(DCDF.GE.P-DEPS)THEN
          PPF=DBLE(I)
          GO TO 9000
        ENDIF
      GO TO 100
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE LKPPF
      SUBROUTINE LKRAN(N,A,B,BETA,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE LAGRANGE KATZ DISTRIBUTION
!              WITH SHAPE PARAMETERS A, B, AND BETA.
!              THE PROBABILITY MASS FUNCTION IS:
!
!              THE PROBABILITY MASS FUNCTION IS:
!              p(X;A,B,BETA)=
!                  (A/BETA)/((A/BETA) + (X*B/BETA) + X)*
!                  ((A/BETA)+X*b/BETA+X  X)*
!                  BETA**X*(1-BETA)**((A/BETA)+X*B/BETA)
!                  X = 0, 1, 2, 3, ,...
!                  A > 0, B > -BETA, BETA < 1
!
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --A      = THE SINGLE PRECISION VALUE
!                                OF THE FIRST SHAPE PARAMETER.
!                     --B      = THE SINGLE PRECISION VALUE
!                                OF THE SECOND SHAPE PARAMETER.
!                     --BETA   = THE SINGLE PRECISION VALUE
!                                OF THE THIRD SHAPE PARAMETER.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE LAGRANGE KATZ DISTRIBUTION
!             WITH SHAPE PARAMETERS A, B, AND BETA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --A > 0, BETA < 1, B > -BETA
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN, LKPPF
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--CONSUL AND FAMOYE (2006), "LAGRANGIAN PROBABILITY
!                 DISTRIBUTIONS", BIRKHAUSER, CHAPTER 12.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007/2
!     ORIGINAL VERSION--FEBRUARY  2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      REAL A
      REAL B
      REAL BETA
!
      DIMENSION X(*)
!
      DOUBLE PRECISION DPPF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,5)
    5   FORMAT('***** ERROR--THE REQUESTED NUMBER OF LAGRANGE KATZ ',   &
               'RANDOM NUMBERS IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
   47   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(A.LE.0.0)THEN
        WRITE(ICOUT,11)
   11   FORMAT('***** ERROR--THE A PARAMETER FOR THE LAGRANGE KATZ')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,12)
   12   FORMAT('      RANDOM NUMBERS IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)A
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(BETA.GE.1.0)THEN
        WRITE(ICOUT,21)
   21   FORMAT('***** ERROR--THE BETA PARAMETER FOR THE LAGRANGE KATZ')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,22)
   22   FORMAT('      RANDOM NUMBERS IS GREATER THAN OR EQUAL TO 1.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)BETA
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(B.LE.-BETA)THEN
        WRITE(ICOUT,31)
   31   FORMAT('***** ERROR--THE B PARAMETER FOR THE LAGRANGE KATZ')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,32)
   32   FORMAT('      RANDOM NUMBERS IS LESS THAN OR EQUAL TO -BETA.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,48)B
   48   FORMAT('***** THE VALUE OF THE B ARGUMENT IS ',G15.7,'.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,49)BETA
   49   FORMAT('***** THE VALUE OF THE BETA ARGUMENT IS ',G15.7,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
!
!     GENERATE N LAGRANGE KATZ DISTRIBUTION RANDOM NUMBERS USING
!     THE INVERSION METHOD.
!
      CALL UNIRAN(N,ISEED,X)
      DO 100 I=1,N
        ZTEMP=X(I)
        CALL LKPPF(DBLE(ZTEMP),DBLE(A),DBLE(B),DBLE(BETA),DPPF)
        X(I)=REAL(DPPF)
  100 CONTINUE
!
 9999 CONTINUE
!
      RETURN
      END SUBROUTINE LKRAN
      SUBROUTINE LLGCDF(X,DELTA,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE LOG-LOGISTIC DISTRIBUTION.
!              THIS DISTRIBUTION IS DEFINED FOR ALL POSITIVE X
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!                 F(X,DELTA) = DELTA*X**(DELTA-1)/[1+X**DELTA)**2]
!              THE CUMULATIVE DISTRIBUTION FUNCTION IS
!                 F(X,DELTA) = 1/(1+X**(-DELTA))
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE POSITIVE.
!                     --DELTA  = THE POSITIVE SHAPE PARAMETER
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE LOG-LOGISTIC DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE POSITIVE.
!                 --DELTA SHOULD BE POSITIVE.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--"MEASURING SKEWNESS WITH RESPECT TO THE MODE",
!                 ARNOLD AND GROENEVELD, AMERICAN STATISTICIAN,
!                 FEBRUARY, 1995.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--APRIL     1995.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX, DDELTA
      DOUBLE PRECISION DTERM1, DTERM2, DTERM3
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(X.LT.0.0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9999
      ENDIF
      IF(DELTA.LE.0.0)THEN
        WRITE(ICOUT,14)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DELTA
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9999
      ENDIF
    4 FORMAT('***** NON-FATAL DIAGNOSTIC--THE FIRST INPUT ARGUMENT')
   14 FORMAT('***** NON-FATAL DIAGNOSTIC--THE SECOND INPUT ARGUMENT')
    5 FORMAT('      TO THE LLGCDF SUBROUTINE IS NEGATIVE *****')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
!
!-----START POINT-----------------------------------------------------
!
      CDF=0.0
      IF(X.EQ.0.0)GO TO 9999
      DX=DBLE(X)
      DDELTA=DBLE(DELTA)
!
      DTERM1=DLOG(1.0D0)
      DTERM2=DLOG(1.0D0 + DX**(-DDELTA))
      DTERM3=DTERM1-DTERM2
      DCDF=DEXP(DTERM3)
      CDF=REAL(DCDF)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE LLGCDF
      SUBROUTINE LLGPDF(X,DELTA,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE LOG-LOGISTIC DISTRIBUTION.
!              THIS DISTRIBUTION IS DEFINED FOR ALL POSITIVE X
!              AND HAS THE PROBABILITY DENSITY FUNCTION
!              F(X,DELTA) = DELTA*X**(DELTA-1)/[1+X**DELTA)**2]
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE POSITIVE.
!                     --DELTA  = THE POSITIVE SHAPE PARAMETER
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE LOG-LOGISTIC DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE POSITIVE.
!                 --DELTA SHOULD BE POSITIVE.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--"MEASURING SKEWNESS WITH RESPECT TO THE MODE",
!                 ARNOLD AND GROENEVELD, AMERICAN STATISTICIAN,
!                 FEBRUARY, 1995.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--APRIL     1995.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX, DDELTA
      DOUBLE PRECISION DUL, DZ, DPDF
      DOUBLE PRECISION DTERM1, DTERM2, DTERM3, DTERM4
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(X.LT.0.0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ENDIF
      IF(DELTA.LE.0.0)THEN
        WRITE(ICOUT,14)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DELTA
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ENDIF
    4 FORMAT('***** NON-FATAL DIAGNOSTIC--THE FIRST INPUT ARGUMENT')
   14 FORMAT('***** NON-FATAL DIAGNOSTIC--THE SECOND INPUT ARGUMENT')
    5 FORMAT('      TO THE LLGPDF SUBROUTINE IS NEGATIVE *****')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
!
!-----START POINT-----------------------------------------------------
!
      PDF=0.0
      IF(X.EQ.0.0)GO TO 9999
      DX=DBLE(X)
      DDELTA=DBLE(DELTA)
!
! CHECK FOR VALUE OF X**DELTA THAT IS TO LARGE (SET PDF TO 0)
!
      DUL=DLOG(DSQRT(D1MACH(2)))
      DZ=DDELTA*DLOG(DX)
      IF(DZ.GE.DUL)GO TO 9999
!
      DTERM1=DLOG(DDELTA)
      DTERM2=(DDELTA-1.0D0)*DLOG(DX)
      DTERM3=2.0D0*DLOG(1.0D0+DX**DDELTA)
      DTERM4=DTERM1+DTERM2-DTERM3
      IF(DTERM4.GE.-80.0D0)THEN
        DPDF=DEXP(DTERM4)
      ELSE
        DPDF=0.0D0
      ENDIF
      PDF=REAL(DPDF)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE LLGPDF
      SUBROUTINE LLGPPF(P,DELTA,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE LOG-LOGISTIC
!              DISTRIBUTION.
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE
!                                (BETWEEN 0.0 (EXCLUSIVELY)
!                                AND 1.0 (EXCLUSIVELY))
!                                AT WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION PERCENT
!                                POINT FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT FUNCTION .
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--P SHOULD BE BETWEEN 0.0 (EXCLUSIVELY)
!                   AND 1.0 (EXCLUSIVELY).
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--"MEASURING SKEWNESS WITH RESPECT TO THE MODE",
!                 ARNOLD AND GROENEVELD, AMERICAN STATISTICIAN,
!                 FEBRUARY, 1995.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-921-2315
!     ORIGINAL VERSION--APRIL     1995.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DTERM1, DTERM2, DTERM3
      DOUBLE PRECISION DPPF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(DELTA.LE.0.0)THEN
        WRITE(ICOUT,14)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DELTA
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ENDIF
   14 FORMAT('***** NON-FATAL DIAGNOSTIC--THE SECOND INPUT ARGUMENT')
    5 FORMAT('      TO THE LLGPDF SUBROUTINE IS NEGATIVE *****')
      IF(P.LT.0.0.OR.P.GE.1.0)GO TO 50
      GO TO 90
   50 CONTINUE
      WRITE(ICOUT,1)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,2)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,46)P
      CALL DPWRST('XXX','BUG ')
      PPF=0.0
      RETURN
   90 CONTINUE
    1 FORMAT(   &
      '***** FATAL ERROR--THE FIRST  INPUT ARGUMENT TO THE LLGPPF')
    2 FORMAT(   &
      '      SUBROUTINE IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL *****')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
!
!-----START POINT-----------------------------------------------------
!
      PPF=0.0
      IF(P.EQ.0.0)GO TO 9999
!
      DTERM1=(-1.0D0/DBLE(DELTA))
      DTERM2=DLOG((1.0D0-DBLE(P))/DBLE(P))
      DTERM3=DTERM1*DTERM2
      DPPF=DEXP(DTERM3)
      PPF=DPPF
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE LLGPPF
      SUBROUTINE LLGRAN(N,DELTA,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE LOG-LOGISTIC DISTRIBUTION
!              WITH SHAPE PARAMETER VALUE = DELTA.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --DELTA  = THE SINGLE PRECISION VALUE OF THE
!                                SHAPE PARAMETER.
!                                DELTA SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE LOG-LOGISTIC DISTRIBUTION
!             WITH SHAPE PARAMETER VALUE = DELTA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --DELTA SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--XX
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2001.10
!     ORIGINAL VERSION--OCTOBER   2001.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
      IF(DELTA.LE.0.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DELTA
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    5 FORMAT('***** FATAL ERROR--THE 1ST INPUT ARGUMENT TO THE ',   &
      'LLGRAN SUBROUTINE IS NON-POSITIVE *****')
   15 FORMAT('***** FATAL ERROR--THE 2ND INPUT ARGUMENT TO THE ',   &
      'LLGRAN SUBROUTINE IS NON-POSITIVE *****')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,' *****')
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N LOG-LOGISTIC DISTRIBUTION RANDOM NUMBERS
!     USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD.
!
      DO 100 I=1,N
        CALL LLGPPF(X(I),DELTA,XTEMP)
        X(I)=XTEMP
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE LLGRAN
      SUBROUTINE LLTSLV(NR,N,A,X,B)
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
! PURPOSE
! -------
! SOLVE AX=B WHERE A HAS THE FORM L(L-TRANSPOSE)
! BUT ONLY THE LOWER TRIANGULAR PART, L, IS STORED.
!
! PARAMETERS
! ----------
! NR           --> ROW DIMENSION OF MATRIX
! N            --> DIMENSION OF PROBLEM
! A(N,N)       --> MATRIX OF FORM L(L-TRANSPOSE).
!                  ON RETURN A IS UNCHANGED.
! X(N)        <--  SOLUTION VECTOR
! B(N)         --> RIGHT-HAND SIDE VECTOR
!
! NOTE
! ----
! IF B IS NOT REQUIRED BY CALLING PROGRAM, THEN
! B AND X MAY SHARE THE SAME STORAGE.
!
      DIMENSION A(NR,1),X(N),B(N)
!
! FORWARD SOLVE, RESULT IN X
!
      CALL FORSLV(NR,N,A,X,B)
!
! BACK SOLVE, RESULT IN X
!
      CALL BAKSLV(NR,N,A,X,X)
      RETURN
      END SUBROUTINE LLTSLV
      SUBROUTINE LMRGLO(PARA,XMOM,NMOM)
!===================================================== LMRGLO.FOR
!***********************************************************************
!*                                                                     *
!*  FORTRAN CODE WRITTEN FOR INCLUSION IN IBM RESEARCH REPORT RC20525, *
!*  'FORTRAN ROUTINES FOR USE WITH THE METHOD OF L-MOMENTS, VERSION 3' *
!*                                                                     *
!*  J. R. M. HOSKING                                                   *
!*  IBM RESEARCH DIVISION                                              *
!*  T. J. WATSON RESEARCH CENTER                                       *
!*  YORKTOWN HEIGHTS                                                   *
!*  NEW YORK 10598, U.S.A.                                             *
!*                                                                     *
!*  VERSION 3     AUGUST 1996                                          *
!*                                                                     *
!***********************************************************************
!
!  L-MOMENT RATIOS FOR THE GENERALIZED LOGISTIC DISTRIBUTION
!
!  PARAMETERS OF ROUTINE:
!  PARA   * INPUT* ARRAY OF LENGTH 3. CONTAINS THE PARAMETERS OF THE
!                  DISTRIBUTION, IN THE ORDER XI, ALPHA, K (LOCATION,
!                  SCALE, SHAPE).
!  XMOM   *OUTPUT* ARRAY OF LENGTH NMOM. ON EXIT, CONTAINS THE L-MOMENTS
!                  LAMBDA-1, LAMBDA-2, TAU-3, TAU-4, ... .
!  NMOM   * INPUT* NUMBER OF L-MOMENTS TO BE FOUND. AT MOST 20.
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
      DOUBLE PRECISION PARA(3),XMOM(NMOM),Z(10,20)
!
      INCLUDE 'DPCOP2.INC'
!
      DATA ZERO/0D0/,ONE/1D0/
      DATA PI/3.141592653589793238D0/
!
!         SMALL IS USED TO DECIDE WHETHER TO APPROXIMATE THE FIRST 2
!         L-MOMENTS BY A POWER-SERIES EXPANSION WHEN G IS NEAR ZERO.
!         C1,C2 ARE COEFFICIENTS OF THIS POWER-SERIES EXPANSION.
!         C1 IS PI**2/6, C2 IS 7*PI**4/360.
!
      DATA SMALL/1D-4/
      DATA C1,C2/   &
        0.164493406684822644D1,  0.189406565899449184D1/
!
!         Z-ARRAY CONTAINS COEFFICIENTS OF THE REPRESENTATIONS OF
!         L-MOMENT RATIOS AS POLYNOMIALS IN THE SHAPE PARAMETER K
!
      DATA Z(1,3)/1D0/
      DATA (Z(I, 4),I=1, 2)/   &
        0.166666666666666667D0,  0.833333333333333333D0/
      DATA (Z(I, 5),I=1, 2)/   &
        0.416666666666666667D0,  0.583333333333333333D0/
      DATA (Z(I, 6),I=1, 3)/   &
        0.666666666666666667D-1,  0.583333333333333333D0,   &
        0.350000000000000000D0/
      DATA (Z(I, 7),I=1, 3)/   &
        0.233333333333333333D0,  0.583333333333333333D0,   &
        0.183333333333333333D0/
      DATA (Z(I, 8),I=1, 4)/   &
        0.357142857142857143D-1,  0.420833333333333333D0,   &
        0.458333333333333333D0,  0.851190476190476190D-1/
      DATA (Z(I, 9),I=1, 4)/   &
        0.150992063492063492D0,  0.515625000000000000D0,   &
        0.297916666666666667D0,  0.354662698412698413D-1/
      DATA (Z(I,10),I=1, 5)/   &
        0.222222222222222222D-1,  0.318893298059964727D0,   &
        0.479976851851851852D0,  0.165509259259259259D0,   &
        0.133983686067019400D-1/
      DATA (Z(I,11),I=1, 5)/   &
        0.106507936507936508D0,  0.447663139329805996D0,   &
        0.360810185185185185D0,  0.803902116402116402D-1,   &
        0.462852733686067019D-2/
      DATA (Z(I,12),I=1, 6)/   &
        0.151515151515151515D-1,  0.251316137566137566D0,   &
        0.469695216049382716D0,  0.227650462962962963D0,   &
        0.347139550264550265D-1,  0.147271324354657688D-2/
      DATA (Z(I,13),I=1, 6)/   &
        0.795695045695045695D-1,  0.389765946502057613D0,   &
        0.392917309670781893D0,  0.123813106261022928D0,   &
        0.134998713991769547D-1,  0.434261597456041900D-3/
      DATA (Z(I,14),I=1, 7)/   &
        0.109890109890109890D-1,  0.204132996632996633D0,   &
        0.447736625514403292D0,  0.273053442827748383D0,   &
        0.591917438271604938D-1,  0.477687757201646091D-2,   &
        0.119302636663747775D-3/
      DATA (Z(I,15),I=1, 7)/   &
        0.619345205059490774D-1,  0.342031759392870504D0,   &
        0.407013705173427396D0,   0.162189192806752331D0,   &
        0.252492100235155791D-1,  0.155093427662872107D-2,   &
        0.306778208563922850D-4/
      DATA (Z(I,16),I=1, 8)/   &
        0.833333333333333333D-2,  0.169768364902293474D0,   &
        0.422191282868366202D0,   0.305427172894620811D0,   &
        0.840827939972285210D-1,  0.972435791446208113D-2,   &
        0.465280282988616322D-3,  0.741380670696146887D-5/
      DATA (Z(I,17),I=1, 8)/   &
        0.497166028416028416D-1,  0.302765838589871328D0,   &
        0.410473300089185506D0,   0.194839026503251764D0,   &
        0.386598063704648526D-1,  0.341399407642897226D-2,   &
        0.129741617371825705D-3,  0.168991182291033482D-5/
      DATA (Z(I,18),I=1, 9)/   &
        0.653594771241830065D-2,  0.143874847595085690D0,   &
        0.396432853710259464D0,   0.328084180720899471D0,   &
        0.107971393165194318D0,   0.159653369932077769D-1,   &
        0.110127737569143819D-2,  0.337982364582066963D-4,   &
        0.364490785333601627D-6/
      DATA (Z(I,19),I=1, 9)/   &
        0.408784570549276431D-1,  0.270244290725441519D0,   &
        0.407599524514551521D0,   0.222111426489320008D0,   &
        0.528463884629533398D-1,  0.598298239272872761D-2,   &
        0.328593965565898436D-3,  0.826179113422830354D-5,   &
        0.746033771150646605D-7/
      DATA (Z(I,20),I=1,10)/   &
        0.526315789473684211D-2,  0.123817655753054913D0,   &
        0.371859291444794917D0,   0.343568747670189607D0,   &
        0.130198662812524058D0,   0.231474364899477023D-1,   &
        0.205192519479869981D-2,  0.912058258107571930D-4,   &
        0.190238611643414884D-5,  0.145280260697757497D-7/
!
      U=PARA(1)
      A=PARA(2)
      G=PARA(3)
      IF(A.LE.ZERO.OR.DABS(G).GE.ONE)THEN
        WRITE(ICOUT,7000)
 7000   FORMAT('***** ERROR IN GENERALIZED LOGISTIC L-MOMENTS--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,7005)
 7005   FORMAT('      PARAMETERS INVALID')
        CALL DPWRST('XXX','WRIT')
        GO TO 9000
      ELSEIF(NMOM.GT.20)THEN
        WRITE(ICOUT,7000)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,7010)
 7010   FORMAT('      PARAMETER NMOM TOO LARGE')
        CALL DPWRST('XXX','WRIT')
        GO TO 9000
      ENDIF
!
!         FIRST 2 MOMENTS
!
      GG=G*G
      ALAM1=-G*(C1+GG*C2)
      ALAM2=ONE+GG*(C1+GG*C2)
      IF(DABS(G).GT.SMALL)ALAM2=G*PI/DSIN(G*PI)
      IF(DABS(G).GT.SMALL)ALAM1=(ONE-ALAM2)/G
      XMOM(1)=U+A*ALAM1
      IF(NMOM.EQ.1)GO TO 9000
      XMOM(2)=A*ALAM2
      IF(NMOM.EQ.2)GO TO 9000
!
!         HIGHER MOMENTS
!
      DO 20 M=3,NMOM
         KMAX=M/2
         SUM=Z(KMAX,M)
         DO 10 K=KMAX-1,1,-1
            SUM=SUM*GG+Z(K,M)
   10    CONTINUE
         IF(M.NE.M/2*2)SUM=-G*SUM
         XMOM(M)=SUM
   20 CONTINUE
!
 9000 CONTINUE
      RETURN
!
      END SUBROUTINE LMRGLO
      SUBROUTINE LNHERM(X,AN,HN,ISIGN)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE LOGARITHM OF THE HERMITE
!              POLYNOMIAL OF ORDER N.  THIS IS USEFUL FOR LARGER
!              ORDERS WHERE OVERFLOW MAY OCCUR WITH THE STANDARD
!              HERMITE POLYNOMIAL.
!
!              THE HERMITE POLYNOMIAL CAN BE NEGATIVE OR POSITIVE,
!              SO TAKE LOG OF ABSOLUTE VALUE, SAVE SIGN IN ISIGN.
!              IF HERMITE POLYNOMIAL IS ZERO, THEN SET THIS FUNCTION
!              TO ZERO.
!
!              THIS FUNCTION IS INTENDED FOR INTERMEDIATE PRIMARILY
!              FOR WHEN HIGH ORDER HERMITE POLYNOMIALS ARE USED IN
!              INTERMEDIATE CALCULATIONS AND LOGS CAN BE USED TO
!              HANDLE LARGE VALUES.
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION INPUT ARGUMENT
!                       AN     = THE SINGLE PRECISION VALUE FOR THE
!                                ORDER OF THE FUNCTION (SHOULD BE
!                                NON-NEGATIVE ORDER)
!     OUTPUT ARGUMENTS--HN     = THE SINGLE PRECISION VALUE OF THE
!                                LOG HERMITE POLYNOMIAL.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE
!     MODE OF INTERNAL OPERATIONS--SOME DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--"HANDBOOK OF MATHEMATICAL FUNCTIONS, AMS 55",
!                 ABRAMOWITZ AND STEGUM.
!                 USE FOLLOWING RECURRENCE FORMULA:
!                    H(N+1) = 2.0*X*H(N)-2.0*N*H(N-1)
!                 FIRST FEW TERMS ARE FROM TABLE 22.12 OF ABRAMOWITZ
!                 AND STEGUM.
!                 COMPUTE THE HERMITE POLYNOMIAL IN THE STANDARD WAY
!                 (IN DOUBLE PRECISION), BUT TAKE LOG BEFORE CONVERTING
!                 TO SINGLE PRECISION.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--JULY       1995.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DN, DN2
      DOUBLE PRECISION DHN, DHN1, DHN2
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      N=INT(AN+0.5)
      IF(N.LT.0)THEN
        WRITE(ICOUT,6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
    6 FORMAT('***** NON-FATAL DIAGNOSTIC--THE 2ND INPUT ARGUMENT ',   &
      'TO THE LNHERM SUBROUTINE IS NEGATIVE *****')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,' *****')
!
      DX=DBLE(X)
      DN=DBLE(N)
!
      IF(N.LE.0)THEN
        DHN=1.0D0
      ELSEIF(N.EQ.1)THEN
        DHN=2.0D0*DX
      ELSEIF(N.EQ.2)THEN
        DHN=4.0D0*DX**2 - 2.0D0
      ELSEIF(N.EQ.3)THEN
        DHN=8.0D0*DX**3 - 12.0D0*DX
      ELSEIF(N.EQ.4)THEN
        DHN=16.0D0*DX**4 - 48.0D0*X**2 + 12.0D0
      ELSEIF(N.EQ.5)THEN
        DHN=32.0D0*DX**5 - 160.0D0*DX**3 + 120.0D0*DX
      ELSE
        DHN1=32.0D0*DX**5 - 160.0D0*DX**3 + 120.0D0*DX
        DHN2=16.0D0*DX**4 - 48.0D0*X**2 + 12.0D0
        DO 1000 I=6,N
          DN2=DBLE(I)-1.0D0
          DHN=2.0D0*DX*DHN1 - 2.0D0*DN2*DHN2
          DHN2=DHN1
          DHN1=DHN
 1000   CONTINUE
      ENDIF
!
      IF(DHN.GT.0.0)THEN
        DHN=DLOG(DHN)
        ISIGN=1
      ELSEIF(DHN.LT.0.D0)THEN
        DHN=DLOG(DABS(DHN))
        ISIGN=-1
      ELSE
        DHN=0.0D0
        ISIGN=0
      ENDIF
!
      HN=REAL(DHN)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE LNHERM
      SUBROUTINE LNSRCH(N,X,F,G,P,XPLS,FPLS,MXTAKE,   &
                        IRETCD,STEPMX,STEPTL,SX,IPR)
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
! PURPOSE
! -------
! FIND A NEXT NEWTON ITERATE BY LINE SEARCH.
!
! PARAMETERS
! ----------
! N            --> DIMENSION OF PROBLEM
! X(N)         --> OLD ITERATE:   X[K-1]
! F            --> FUNCTION VALUE AT OLD ITERATE, F(X)
! G(N)         --> GRADIENT AT OLD ITERATE, G(X), OR APPROXIMATE
! P(N)         --> NON-ZERO NEWTON STEP
! XPLS(N)     <--  NEW ITERATE X[K]
! FPLS        <--  FUNCTION VALUE AT NEW ITERATE, F(XPLS)
! OPTFCN       --> NAME OF SUBROUTINE TO EVALUATE FUNCTION
! IRETCD      <--  RETURN CODE
! MXTAKE      <--  BOOLEAN FLAG INDICATING STEP OF MAXIMUM LENGTH USED
! STEPMX       --> MAXIMUM ALLOWABLE STEP SIZE
! STEPTL       --> RELATIVE STEP SIZE AT WHICH SUCCESSIVE ITERATES
!                  CONSIDERED CLOSE ENOUGH TO TERMINATE ALGORITHM
! SX(N)        --> DIAGONAL SCALING MATRIX FOR X
! IPR          --> DEVICE TO WHICH TO SEND OUTPUT
!
! INTERNAL VARIABLES
! ------------------
! SLN              NEWTON LENGTH
! RLN              RELATIVE LENGTH OF NEWTON STEP
!
      INTEGER N,IRETCD
      DIMENSION SX(N)
      DIMENSION X(N),G(N),P(N)
      DIMENSION XPLS(N)
      DIMENSION FHAT(1)
      LOGICAL MXTAKE
!
      PLMBDA=0.0
      PFPLS=0.0
!
      IPR=IPR
      MXTAKE=.FALSE.
      IRETCD=2
!$    WRITE(IPR,954)
!$    WRITE(IPR,955) (P(I),I=1,N)
      TMP=0.0D0
      DO 5 I=1,N
        TMP=TMP+SX(I)*SX(I)*P(I)*P(I)
    5 CONTINUE
      SLN=SQRT(TMP)
      IF(SLN.LE.STEPMX) GO TO 10
!
! NEWTON STEP LONGER THAN MAXIMUM ALLOWED
        SCL=STEPMX/SLN
        CALL SCLMUL(N,SCL,P,P)
        SLN=STEPMX
!$      WRITE(IPR,954)
!$      WRITE(IPR,955) (P(I),I=1,N)
   10 CONTINUE
      SLP=DDOT(N,G,1,P,1)
      RLN=0.D0
      DO 15 I=1,N
        RLN=MAX(RLN,ABS(P(I))/MAX(ABS(X(I)),1.D0/SX(I)))
   15 CONTINUE
      RMNLMB=STEPTL/RLN
      ALMBDA=1.0D0
!$    WRITE(IPR,952) SLN,SLP,RMNLMB,STEPMX,STEPTL
!
! LOOP
! CHECK IF NEW ITERATE SATISFACTORY.  GENERATE NEW LAMBDA IF NECESSARY.
!
  100 CONTINUE
      IF(IRETCD.LT.2) RETURN
      DO 105 I=1,N
        XPLS(I)=X(I) + ALMBDA*P(I)
  105 CONTINUE
      CALL OPTFCN(N,XPLS,FHAT)
      FPLS=FHAT(1)
!$    WRITE(IPR,950) ALMBDA
!$    WRITE(IPR,951)
!$    WRITE(IPR,955) (XPLS(I),I=1,N)
!$    WRITE(IPR,953) FPLS
      IF(FPLS.GT. F+SLP*1.D-4*ALMBDA) GO TO 130
!     IF(FPLS.LE. F+SLP*1.D-4*ALMBDA)
!     THEN
!
! SOLUTION FOUND
!
        IRETCD=0
        IF(ALMBDA.EQ.1.0 .AND. SLN.GT. .99D0*STEPMX) MXTAKE=.TRUE.
        GO TO 100
!
! SOLUTION NOT (YET) FOUND
!
!     ELSE
  130   CONTINUE
        IF(ALMBDA .GE. RMNLMB) GO TO 140
!       IF(ALMBDA .LT. RMNLMB)
!       THEN
!
! NO SATISFACTORY XPLS FOUND SUFFICIENTLY DISTINCT FROM X
!
          IRETCD=1
          GO TO 100
!       ELSE
!
! CALCULATE NEW LAMBDA
!
  140     IF(ALMBDA.NE.1.0D0) GO TO 150
!         IF(ALMBDA.EQ.1.0D0)
!         THEN
!
! FIRST BACKTRACK: QUADRATIC FIT
!
            TLMBDA=-SLP/(2.D0*(FPLS-F-SLP))
            GO TO 170
!         ELSE
!
! ALL SUBSEQUENT BACKTRACKS: CUBIC FIT
!
  150       CONTINUE
            T1=FPLS-F-ALMBDA*SLP
            T2=PFPLS-F-PLMBDA*SLP
            T3=1.0D0/(ALMBDA-PLMBDA)
            A=T3*(T1/(ALMBDA*ALMBDA) - T2/(PLMBDA*PLMBDA))
            B=T3*(T2*ALMBDA/(PLMBDA*PLMBDA)   &
                 - T1*PLMBDA/(ALMBDA*ALMBDA) )
            DISC=B*B-3.0D0*A*SLP
            IF(DISC.LE. B*B) GO TO 160
!           IF(DISC.GT. B*B)
!           THEN
!
! ONLY ONE POSITIVE CRITICAL POINT, MUST BE MINIMUM
!
              TLMBDA=(-B+SIGN(1.0D0,A)*SQRT(DISC))/(3.0D0*A)
              GO TO 165
!           ELSE
!
! BOTH CRITICAL POINTS POSITIVE, FIRST IS MINIMUM
!
  160         TLMBDA=(-B-SIGN(1.0D0,A)*SQRT(DISC))/(3.0D0*A)
!           ENDIF
  165       IF(TLMBDA.GT. .5D0*ALMBDA) TLMBDA=.5D0*ALMBDA
!         ENDIF
  170     CONTINUE
          PLMBDA=ALMBDA
          PFPLS=FPLS
          IF(TLMBDA.GE. ALMBDA*.1D0) GO TO 180
!         IF(TLMBDA.LT.ALMBDA/10.D0)
!         THEN
            ALMBDA=ALMBDA*.1D0
            GO TO 190
!         ELSE
  180       ALMBDA=TLMBDA
!         ENDIF
!       ENDIF
!     ENDIF
  190 GO TO 100
!C950 FORMAT(18H LNSRCH    ALMBDA=,E20.13)
!C951 FORMAT(29H LNSRCH    NEW ITERATE (XPLS))
!C952 FORMAT(18H LNSRCH    SLN   =,E20.13/
!C   +       18H LNSRCH    SLP   =,E20.13/
!C   +       18H LNSRCH    RMNLMB=,E20.13/
!C   +       18H LNSRCH    STEPMX=,E20.13/
!C   +       18H LNSRCH    STEPTL=,E20.13)
!C953 FORMAT(19H LNSRCH    F(XPLS)=,E20.13)
!C954 FORMAT(26H0LNSRCH    NEWTON STEP (P))
!C955 FORMAT(14H LNSRCH       ,5(E20.13,3X))
      END SUBROUTINE LNSRCH
      DOUBLE PRECISION FUNCTION LOBACH(XVALUE)
!
!   DESCRIPTION:
!
!      This function calculates the Lobachewsky function L(x), defined as
!
!         LOBACH(x) = {integral 0 to x} ( -ln ( | cos t | ) dt
!
!      The code uses Chebyshev expansions whose coefficients are given
!      to 20 decimal places.
!
!
!   ERROR RETURNS:
!
!      If |x| too large, it is impossible to accurately reduce the
!      argument to the range [0,pi]. An error message is printed
!      and the program returns the value 0.0
!
!
!   MACHINE-DEPENDENT CONSTANTS:
!
!      NTERM1 - INTEGER - The no. of terms to be used of the array ARLOB1.
!                          The recommended value is such that
!                          ABS(ARLOB1(NTERM1)) < EPS/100
!
!      NTERM2 - INTEGER - The no. of terms to be used of the array ARLOB2.
!                          The recommended value is such that
!                          ABS(ARLOB2(NTERM2)) < EPS/100
!
!      XLOW1 - DOUBLE PRECISION - The value below which L(x) = 0.0 to machine-precision.
!                     The recommended value is
!                              cube-root ( 6*XMIN )
!
!      XLOW2 - DOUBLE PRECISION - The value below which L(x) = x**3/6 to
!                     machine-precision. The recommended value is
!                              sqrt ( 10*EPS )
!
!      XLOW3 - DOUBLE PRECISION - The value below which
!                         L(pi/2) - L(pi/2-x) = x ( 1 - log(x) )
!                     to machine-precision. The recommended value is
!                               sqrt ( 18*EPS )
!
!      XHIGH - DOUBLE PRECISION - The value of |x| above which it is impossible
!                     to accurately reduce the argument. The
!                     recommended value is   1 / EPS.
!
!      For values of EPS, and XMIN, refer to the file MACHCON.TXT
!
!      The machine-dependent constants are computed internally by
!      using the D1MACH subroutine.
!
!
!   INTRINSIC FUNCTIONS USED:
!
!      INT , LOG , SQRT
!
!
!   OTHER MISCFUN SUBROUTINES USED:
!
!          CHEVAL , ERRPRN, D1MACH
!
!
!   AUTHOR:
!
!      Dr. Allan J. MacLeod,
!      Dept. of Mathematics and Statistics,
!      University of Paisley,
!      High St.,
!      Paisley,
!      SCOTLAND
!
!      ( e-mail: macl_ms0@paisley.ac.uk )
!
!
!   LATEST UPDATE:
!                  23 January, 1996
!
      INTEGER INDPI2,INDSGN,NPI,NTERM1,NTERM2
      DOUBLE PRECISION ARLOB1(0:15),ARLOB2(0:10),   &
           CHEVAL,FVAL,FVAL1,HALF,LBPB21,LBPB22,LOBPIA,LOBPIB,   &
           LOBPI1,LOBPI2,ONE,ONEHUN,PI,PIBY2,PIBY21,PIBY22,PIBY4,PI1,   &
           PI11,PI12,PI2,SIX,T,TCON,TEN,TWO,X,XCUB,XHIGH,XLOW1,   &
           XLOW2,XLOW3,XR,XVALUE,ZERO
!CCCC CHARACTER FNNAME*6,ERRMSG*26
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
!CCCC DATA FNNAME/'LOBACH'/
!CCCC DATA ERRMSG/'ARGUMENT TOO LARGE IN SIZE'/
      DATA ZERO,HALF/ 0.0D0 , 0.5D0 /
      DATA ONE,TWO,SIX/ 1.0D0 , 2.0D0 , 6.0D0 /
      DATA TEN,ONEHUN/ 10.0D0 , 100.0D0 /
      DATA LOBPIA,LOBPIB/ 1115.0D0 , 512.0D0 /
      DATA LOBPI2/-1.48284696397869499311D-4/
      DATA LBPB22/-7.41423481989347496556D-5/
      DATA PI11,PI12/ 201.0D0 , 64.0D0 /
      DATA PI2/9.67653589793238462643D-4/
      DATA PIBY22/4.83826794896619231322D-4/
      DATA TCON/3.24227787655480868620D0/
      DATA ARLOB1/0.34464884953481300507D0,   &
                  0.584198357190277669D-2,   &
                  0.19175029694600330D-3,   &
                  0.787251606456769D-5,   &
                  0.36507477415804D-6,   &
                  0.1830287272680D-7,   &
                  0.96890333005D-9,   &
                  0.5339055444D-10,   &
                  0.303408025D-11,   &
                  0.17667875D-12,   &
                  0.1049393D-13,   &
                  0.63359D-15,   &
                  0.3878D-16,   &
                  0.240D-17,   &
                  0.15D-18,   &
                  0.1D-19/
      DATA ARLOB2/2.03459418036132851087D0,   &
                  0.1735185882027407681D-1,   &
                  0.5516280426090521D-4,   &
                  0.39781646276598D-6,   &
                  0.369018028918D-8,   &
                  0.3880409214D-10,   &
                  0.44069698D-12,   &
                  0.527674D-14,   &
                  0.6568D-16,   &
                  0.84D-18,   &
                  0.1D-19/
!
!   Start computation
!
      X = ABS ( XVALUE )
      INDSGN = 1
      IF ( XVALUE .LT. ZERO ) THEN
         INDSGN = -1
      ENDIF
!
!   Compute the machine-dependent constants.
!
      XR = D1MACH(3)
      XHIGH = ONE / XR
!
!   Error test
!
      IF ( X .GT. XHIGH ) THEN
!CCCC    CALL ERRPRN(FNNAME,ERRMSG)
         WRITE(ICOUT,999)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,101)X
         CALL DPWRST('XXX','BUG ')
         LOBACH = ZERO
         RETURN
      ENDIF
  999 FORMAT(1X)
  101 FORMAT('***** ERROR FROM LOBACH--ARGUMENT TOO LARGE.   ',   &
             'ARGUMENT = ',G15.7)
!
!   continue with constants
!
      T = XR / ONEHUN
      DO 10 NTERM1 = 15 , 0 , -1
         IF ( ABS(ARLOB1(NTERM1)) .GT. T ) GO TO  19
 10   CONTINUE
 19   DO 20 NTERM2 = 10 , 0 , -1
         IF ( ABS(ARLOB2(NTERM2)) .GT. T ) GO TO  29
 20   CONTINUE
 29   XLOW1 = ( SIX * D1MACH(1) ) ** (TWO/SIX)
      XLOW2 = SQRT ( TEN * XR )
      T = TWO * TEN - TWO
      XLOW3 = SQRT ( T * XR )
!
!   Reduce argument to [0,pi]
!
      PI1 = PI11/PI12
      PI = PI1 + PI2
      PIBY2 = PI/TWO
      PIBY21 = PI1/TWO
      PIBY4 = PIBY2/TWO
      NPI = INT ( X / PI )
      XR = ( X - NPI * PI1 ) - NPI * PI2
!
!   Reduce argument to [0,pi/2]
!
      INDPI2 = 0
      IF ( XR .GT. PIBY2 ) THEN
         INDPI2 = 1
         XR = ( PI1 - XR ) + PI2
      ENDIF
!
!   Code for argument in [0,pi/4]
!
      IF ( XR .LE. PIBY4 ) THEN
         IF ( XR .LT. XLOW1 ) THEN
            FVAL = ZERO
         ELSE
            XCUB = XR * XR * XR
            IF ( XR .LT. XLOW2 ) THEN
               FVAL = XCUB / SIX
            ELSE
               T = ( TCON * XR * XR - HALF ) - HALF
               FVAL = XCUB * CHEVAL(NTERM1,ARLOB1,T)
            ENDIF
         ENDIF
      ELSE
!
!   Code for argument in [pi/4,pi/2]
!
         XR = ( PIBY21 - XR ) + PIBY22
         IF ( XR .EQ. ZERO ) THEN
            FVAL1 = ZERO
         ELSE
            IF ( XR .LT. XLOW3 ) THEN
               FVAL1 = XR * ( ONE - LOG( XR ) )
            ELSE
               T = ( TCON * XR * XR - HALF ) - HALF
               FVAL1 = XR * ( CHEVAL(NTERM2,ARLOB2,T) - LOG( XR ) )
            ENDIF
         ENDIF
         LBPB21 = LOBPIA / ( LOBPIB + LOBPIB )
         FVAL = ( LBPB21 - FVAL1 ) + LBPB22
      ENDIF
      LOBPI1 = LOBPIA / LOBPIB
!
!   Compute value for argument in [pi/2,pi]
!
      IF ( INDPI2 .EQ. 1 ) THEN
         FVAL = ( LOBPI1 - FVAL ) + LOBPI2
      ENDIF
      LOBACH = FVAL
!
!   Scale up for arguments > pi
!
      IF ( NPI .GT. 0 ) THEN
         LOBACH = ( FVAL + NPI * LOBPI2 ) + NPI * LOBPI1
      ENDIF
      IF ( INDSGN .EQ. -1 ) THEN
         LOBACH = - LOBACH
      ENDIF
      RETURN
      END FUNCTION LOBACH
      SUBROUTINE LOCAL (XI,YI,FI,NXG,XG,NYG,YG,NP,MP,AL,AB,C,IP,IER)
!
!     THIS SUBROUTINE CONSTRUCTS THE LOCAL APPROXIMANTS FOR THE GRID
!     VERSION OF FRANKE'S METHOD.  THE LOCAL APPROXIMATIONS ARE TAKEN
!     TO BE THE THIN PLATE SPLINES DESCRIBED BY DUCHON AND OTHERS.
!
!     THE ARGUMENTS ARE AS FOLLOWS.
!
!        XI   - \
!        YI   - INPUT.  THE DATA POINTS (XI,YI,FI),I=1,NPI.
!        FI   - /
!        NXG  - INPUT.  THE NUMBER OF VERTICAL GRID LINES.
!        XG   - INPUT.  THE COORDINATES OF THE VERTICAL GRID LINES, IN
!                       INCREASING ORDER.
!        NYG  - INPUT.  THE NUMBER OF HORIZONTAL GRID LINES.
!        YG   - INPUT.  THE COORDINATES OF THE HORIZONTAL GRID LINES, IN
!                       INCREASING ORDER.
!        NP   - INPUT.  AN ARRAY WHICH GIVES THE INITIAL SUBSCRIPT IN
!                       THE ARRAY MP AT WHICH THE SUBSCRIPTS FOR THE
!                       LOCAL INTERPOLATION POINTS ARE STORED.
!        MP   - INPUT.  AN ARRAY WHICH GIVES THE SUBSCRIPTS FOR THE
!                       LOCAL INTERPOLATION POINTS.
!        AL   - OUTPUT.  THE COEFFICIENTS FOR THE LINEAR PART OF THE
!                       LOCAL THIN PLATE SPLINE FIT.
!        AB   - OUTPUT.  THE COEFFICIENTS FOR THE THIN PLATE SPLINES
!        C    - OUTPUT.  NOT MEANINGFUL.  THIS IS A SCRATCH ARRAY USED
!                       DURING CALCULATION OF THE LOCAL APPROXIMATIONS.
!        IP   - OUTPUT.  NOT MEANINGFUL.  THIS IS A SCRATCH ARRAY USED
!                       TO STORE PIVOT ORDER IN EQUATION SOLUTION.
!        IER  - OUTPUT.  RETURN INDICATOR.
!                 = 0,  NORMAL RETURN.
!                 = 1,  SINGULAR MATRIX HAS BEEN DETECTED IN THE
!                       THIN PLATE SPLINE FIT.
!
!     SUBROUTINES USED
!        LINPACK:  SGECO,SGESL
!        SLATEC:  XERROR
!
      DIMENSION XI(*), YI(*), FI(*), NP(*), MP(*), AL(*), AB(*), XG(*),   &
       YG(*),C(*),IP(*)
!
!     ARITHMETIC STATEMENT FUNCTION FOR THE THIN PLATE SPLINE BASIS
!     FUNCTIONS.
!
      PHI(X,Y,XP,YP) = ((X-XP)**2+(Y-YP)**2)*LOG(((X-XP)**2+(Y-YP)**2)   &
       + 1.E-20)
      IER = 0
      IJ = 0
      DO 160 J=1,NYG
      DO 140 I=1,NXG
      IJ = IJ + 1
  140 CONTINUE
  160 CONTINUE
      IJ = 0
!
      DO 260 J=1,NYG
      DY = YG(J+2)-YG(J)
!
      DO 240 I=1,NXG
      DX = XG(I+2)-XG(I)
      IJ = IJ+1
      LEND = NP(IJ+1)-NP(IJ)
      LEND3 = LEND + 3
      IALS = (IJ-1)*3
!
      DO 200 LI=1,LEND
      MPI = NP(IJ)+LI-1
      KI = MP(MPI)
      XKI = (XI(KI)-XG(I))/DX
      YKI = (YI(KI)-YG(J))/DY
      LIJ = LEND*LEND3 + LI
      C(LIJ) = 1.
      C(LIJ+LEND3) = XKI
      C(LIJ+2*LEND3) = YKI
      LIJ = LEND3*(LI - 1) + LEND + 1
      C(LIJ) = 1.
      C(LIJ+1) = XKI
      C(LIJ+2) = YKI
      LIJL = LI
      LIJU = LEND3*(LI-1)+1
!
      DO 180 LJ=1,LI
      MPJ = NP(IJ)+LJ-1
      KJ = MP(MPJ)
      XKJ = (XI(KJ)-XG(I))/DX
      YKJ = (YI(KJ)-YG(J))/DY
      C(LIJL) = PHI(XKI,YKI,XKJ,YKJ)
      C(LIJU) = C(LIJL)
      LIJL = LIJL + LEND3
      LIJU = LIJU + 1
  180 CONTINUE
!
      LIJ = LEND3*LEND3 + LI
      C(LIJ) = FI(KI)
  200 CONTINUE
      DO 215 LLI=1,3
      LIJU = (LEND + LLI - 1)*LEND3 + LEND + 1
      LIJL = LEND*LEND3 + LEND + LLI
      DO 210 LLJ = 1,LLI
      C(LIJL) = 0.
      C(LIJU) = 0.
      LIJL = LIJL + LEND3
      LIJU = LIJU + 1
  210 CONTINUE
      LIJ = LEND3*LEND3 + LEND + LLI
      C(LIJ) = 0.
  215 CONTINUE
!
      LR = LEND3*LEND3 + 1
      LRR = LR + LEND3
!
      CALL SGECO(C,LEND3,LEND3,IP,RCOND,C(LRR))
      IF((.1*RCOND+1.).EQ.1.)GO TO 300
      CALL SGESL(C,LEND3,LEND3,IP,C(LR),0)
!
      DO 220 LI=1,LEND
      IAB = NP(IJ)+LI-1
      AB(IAB) = C(LR)
      LR = LR + 1
  220 CONTINUE
!
      AL(IALS+1) = C(LR)
      AL(IALS+2) = C(LR+1)
      AL(IALS+3) = C(LR+2)
  240 CONTINUE
!
  260 CONTINUE
!
      RETURN
!
!     ERROR RETURN
!
  300 IER = 1
      RETURN
      END SUBROUTINE LOCAL 
      SUBROUTINE LOEVL (XI,YI,NXG,XG,NYG,YG,NP,MP,AL,AB,NXO,XO,NYO   &
      ,YO,FO)
!
!     THIS SUBROUTINE EVALUATES THE INTERPOLANT FOR THE GRID VERSION OF
!     FRANKE'S METHOD.  THE FUNCTION IS EVALUATED AT THE GRID OF POINTS
!     INDICATED BY NXO, XO, NYO, YO, AND THESE VALUES ARE RETURNED
!     IN THE ARRAY FO, WHICH IS ASSUMED TO BE DIMENSIONED (NXO,NYO).
!
!     THE ARGUMENTS ARE AS FOLLOWS.
!
!        XI   - \
!        YI   - INPUT.  THE DATA POINTS (XI,YI,FI),I=1,...,NPI.
!        FI   - /
!        NXG  - INPUT.  THE NUMBER OF VERTICAL GRID LINES.
!        XG   - INPUT.  THE COORDINATES OF THE VERTICAL GRID LINES, IN
!                       INCREASING ORDER.
!        NYG  - INPUT.  THE NUMBER OF HORIZONTAL GRID LINES.
!        YG   - INPUT.  THE COORDINATES OF THE HORIZONTAL GRID LINES,
!                       IN INCREASING ORDER.
!        NP   - INPUT.  AN ARRAY WHICH GIVES THE INITIAL SUBSCRIPT IN
!                       THE ARRAY MP AT WHICH THE SUBSCRIPTS FOR THE
!                       LOCAL INTERPOLATION POINTS ARE STORED.
!        MP   - INPUT.  AN ARRAY WHICH GIVES THE SUBSCRIPTS FOR THE
!                       LOCAL INTERPOLATION POINTS.
!        AL   - INPUT.  THE COEFFICIENTS FOR THE LINEAR PART OF THE
!                       THIN PLATE SPLINE APPROXIMATIONS.
!        AB   - INPUT.  THE COEFFICIENTS FOR THE LOCAL THIN PLATE
!                       SPLINE APPROXIMATIONS.
!        NXO  - INPUT.  THE NUMBER OF XO VALUES AT WHICH THE INTERPO-
!                       LATION FUNCTION IS TO BE CALCULATED.
!        XO   - INPUT.  THE VALUES OF X AT WHICH THE INTERPOLATION
!                       FUNCTION IS TO BE CALCULATED.
!        NYO  - INPUT.  THE NUMBER OF YO VALUES AT WHICH THE INTERPO-
!                       LATION FUNCTION IS TO BE CALCULATED.
!        YO   - INPUT.  THE VALUES OF Y AT WHICH THE INTERPOLATION
!                       FUNCTION IS TO BE CALCULATED.
!        FO   - OUTPUT.  VALUES OF THE INTERPOLATION FUNCTION AT THE
!                       GRID POINTS INDICATED BY NXO, XO, NYO, YO.
!                       FO IS ASSUMED TO BE DIMENSIONED (NXO,NYO) IN THE
!                       CALLING PROGRAM.
!
      DIMENSION XG(*), YG(*), XI(*), YI(*), NP(*), MP(*), FC(4), AL(*),   &
      AB(*), XO(*), YO(*), FO(NXO,1)
!
!     ARITHMETIC STATEMENT FUNCTION FOR THE HERMITE CUBIC.
!
      H3(S) = 1. - S**2*(3. - 2.*S)
!
!     ARITHMETIC STATEMENT FUNCTION FOR THE THIN PLATE SPLINE BASIS
!     FUNCTIONS.
!
      PHI(X,Y,XP,YP) = ((X-XP)**2+(Y-YP)**2)*LOG(((X-XP)**2+(Y-YP)**2)   &
       + 1.E-20)
!
      J = 1
!
      DO 640 JO=1,NYO
!
!       DETERMINE THE LOCATION OF THE POINT YO IN TERMS OF THE SMALLEST
!       VALUE OF J SUCH THAT YO(JO) IS IN SOME RECTANGLE (I,J).
!
        YV = YO(JO)
        JJS = J+1
        IF (YV.LT.YG(JJS)) JJS=1
!
        DO 100 JJ=JJS,NYG
          IF (YV.LT.YG(JJ+1)) GO TO 120
  100   CONTINUE
!
        J = NYG
        GO TO 140
  120   CONTINUE
        J = JJ-1
  140   CONTINUE
        JD = 3
        IF (J.GE.1) GO TO 160
        JD = 0
        J = 1
        GO TO 180
  160   CONTINUE
        IF (J.LT.NYG) GO TO 180
        JD = 6
  180   CONTINUE
        DY = YG(J+2)-YG(J+1)
        I = 1
!
        DO 620 IO=1,NXO
!
!         DETERMINE THE LOCATION OF THE POINT XO IN TERMS OF THE
!         SMALLEST VALUE OF I SUCH THAT XO(IO) IS IN THE
!         RECTANGLE (I,J).
!
          IIS = I+1
          XV = XO(IO)
          IF (XV.LT.XG(IIS)) IIS=1
!
          DO 200 II=IIS,NXG
            IF (XV.LT.XG(II+1)) GO TO 220
  200     CONTINUE
!
          I = NXG
          GO TO 240
  220     CONTINUE
          I = II-1
  240     CONTINUE
          ID = 2
          IF (I.GE.1) GO TO 260
          ID = 1
          I = 1
          GO TO 280
  260     CONTINUE
          IF (I.LT.NXG) GO TO 280
          ID = 3
  280     CONTINUE
          DX = XG(I+2)-XG(I+1)
          KD = ID+JD
          GO TO (300,360,300,440,520,440,300,360,300), KD
!
!         THIS IS FOR (XO(IO),YO(JO)) POINTS IN A SINGLE
!         RECTANGLE (I,J)
!
  300     CONTINUE
          FV = 0.
          IJ = (J-1)*NXG+I
          IAL = 3*IJ-2
          LMAX = NP(IJ+1)-NP(IJ)
          DXA = XG(I+2)-XG(I)
          DYA = YG(J+2)-YG(J)
          XVD = (XV-XG(I))/DXA
          YVD = (YV-YG(J))/DYA
!
          DO 320 L=1,LMAX
            MPS = NP(IJ)+L-1
            KI = MP(MPS)
            XKI = (XI(KI)-XG(I))/DXA
            YKI = (YI(KI)-YG(J))/DYA
            FV = FV+AB(MPS)*PHI(XKI,YKI,XVD,YVD)
  320     CONTINUE
!
          FV = FV + AL(IAL) + AL(IAL+1)*XVD + AL(IAL+2)*YVD
          GO TO 620
!
!         THIS IS FOR XO(IO),YO(JO)) POINTS WHICH ARE IN TWO
!         RECTANGLES, (I,J) AND (I+1,J).
!
  360     CONTINUE
          DYA = YG(J+2)-YG(J)
          YVD = (YV-YG(J))/DYA
!
          DO 420 IP=1,2
            FC(IP) = 0.
            IS = I+IP-1
            IJ = (J-1)*NXG+IS
            IAL = 3*IJ-2
            DXA = XG(IS+2)-XG(IS)
            XVD = (XV-XG(IS))/DXA
            LMAX = NP(IJ+1)-NP(IJ)
!
            DO 380 L=1,LMAX
              MPS = NP(IJ)+L-1
              KI = MP(MPS)
              XKI = (XI(KI)-XG(IS))/DXA
              YKI = (YI(KI)-YG(J))/DYA
              FC(IP) = FC(IP)+AB(MPS)*PHI(XKI,YKI,XVD,YVD)
  380       CONTINUE
!
            FC(IP)=FC(IP)+AL(IAL)+AL(IAL+1)*XVD+AL(IAL+2)*YVD
  420     CONTINUE
!
          WI = H3((XV-XG(I+1))/DX)
          FV = FC(1)*WI+(1.-WI)*FC(2)
          GO TO 620
!
!         THIS IS FOR (XO(IO),YO(JO)) POINTS WHICH ARE IN TWO
!         RECTANGLES, (I,J) AND (I,J+1).
!
  440     CONTINUE
          DXA = XG(I+2)-XG(I)
          XVD = (XV-XG(I))/DXA
!
          DO 500 JP=1,2
            FC(JP) = 0.
            JS = J+JP-1
            IJ = (JS-1)*NXG+I
            IAL = 3*IJ-2
            DYA = YG(JS+2)-YG(JS)
            YVD = (YV-YG(JS))/DYA
            LMAX = NP(IJ+1)-NP(IJ)
!
            DO 460 L=1,LMAX
              MPS = NP(IJ)+L-1
              KJ = MP(MPS)
              XKJ = (XI(KJ)-XG(I))/DXA
              YKJ = (YI(KJ)-YG(JS))/DYA
              FC(JP) = FC(JP)+AB(MPS)*PHI(XKJ,YKJ,XVD,YVD)
  460       CONTINUE
!
            FC(JP)=FC(JP)+AL(IAL)+AL(IAL+1)*XVD+AL(IAL+2)*YVD
  500     CONTINUE
!
          UJ = H3((YV-YG(J+1))/DY)
          FV = FC(1)*UJ+(1.-UJ)*FC(2)
          GO TO 620
!
!         THIS IS FOR (XO(IO),YO(JO)) POINTS WHICH ARE IN FOUR
!         RECTANGLES, (I,J), (I+1,J), (I,J+1), AND (I+1,J+1).
!
  520     CONTINUE
          KFC = 0
!
          DO 600 JP=1,2
            JS = J+JP-1
            DYA = YG(JS+2)-YG(JS)
            YVD = (YV-YG(JS))/DYA
!
            DO 580 IP=1,2
              IS = I+IP-1
              IJ = (JS-1)*NXG+IS
              IAL = 3*IJ-2
              KFC = KFC+1
              FC(KFC) = 0.
              DXA = XG(IS+2)-XG(IS)
              XVD = (XV-XG(IS))/DXA
              LMAX = NP(IJ+1)-NP(IJ)
!
              DO 540 L=1,LMAX
                MPS = NP(IJ)+L-1
                KI = MP(MPS)
                XKI = (XI(KI)-XG(IS))/DXA
                YKI = (YI(KI)-YG(JS))/DYA
                FC(KFC) = FC(KFC)+AB(MPS)*PHI(XKI,YKI,XVD,YVD)
  540         CONTINUE
!
              FC(KFC)=FC(KFC)+AL(IAL)+AL(IAL+1)*XVD+AL(IAL+2)*YVD
  580       CONTINUE
!
  600     CONTINUE
!
          WI = H3((XV-XG(I+1))/DX)
          UJ = H3((YV-YG(J+1))/DY)
          FV = WI*(UJ*FC(1)+(1.-UJ)*FC(3))+   &
               (1.-WI)*(UJ*FC(2)+(1.-UJ)*FC(4))
          FO(IO,JO) = FV
  620   CONTINUE
  640 CONTINUE
!
      RETURN
      END SUBROUTINE LOEVL 
      SUBROUTINE LOGARI(Y1,Y2,N1,IACASE,IWRITE,   &
      Y3,N3,SCAL3,ITYP3,IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--CARRY OUT LOGICAL    ARITHMETIC OPERATIONS
!              OF THE REAL DATA IN Y1 AND Y2.
!
!     OPERATIONS--AND (OR CONJUNCTION OR MULTIPLICATION)
!                 OR (OR DISJUNCTION OR ADDITION)
!                 NAND
!                 NOR (OR EXCLUSIVE DISJUNCTION)
!                 IFTHEN (OR IMPLICATION)
!                 IFF (OR EQUIVALENCE)
!                 NOT (OR NEGATION OR NOT OR COMPLEMENT)
!                 XOR (OR EXCLUSIVE OR   OR EXCL. DISJUNCTION)
!
!     INPUT  ARGUMENTS--Y1 (REAL)
!                     --Y2 (REAL)
!     OUTPUT ARGUMENTS--Y3 (REAL)
!                       SCAL3
!                       ITYP3
!
!     NOTE--IT IS NOT PERMISSIBLE TO HAVE THE OUTPUT LOGICALY3(.)
!           BEING IDENTICAL TO THE INPUT LOGICALY1(.) OR Y2(.).
!     REFERENCE--HANDBOOK OF MATHEMATICAL TABLES AND FORMULAS,
!                BURINGTON, EDITION 5, PAGES 130-135.
!              --INTRODUCTION TO COMPUTER SCIENCE,
!                SCHEID, SCHAUM OUTLINE SERIES, PP. 3, 4, 6, 7, 43, 224.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--87/9
!     ORIGINAL VERSION--AUGUST   1987.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IACASE
      CHARACTER*4 IWRITE
      CHARACTER*4 ITYP3
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
!
      DIMENSION Y1(*)
      DIMENSION Y2(*)
      DIMENSION Y3(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='LOGA'
      ISUBN2='RI  '
      IERROR='NO'
!
      SCAL3=(-999.0)
      ITYP3='VECT'
!
      TOL=0.00001
      ONE=1.0
      ONEMIN=ONE-TOL
      ONEMAX=ONE+TOL
      ZERO=0.0
      ZERMIN=ZERO-TOL
      ZERMAX=ZERO+TOL
!
      IF(IBUGA3.EQ.'OFF'.AND.ISUBRO.NE.'GARI')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF LOGARI--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IBUGA3,ISUBRO,IACASE,IWRITE
   52 FORMAT('IBUGA3,ISUBRO,IACASE,IWRITE = ',A4,2X,A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)N1
   53 FORMAT('N1 = ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 55 I=1,N1
      WRITE(ICOUT,56)I,Y1(I),Y2(I)
   56 FORMAT('I,Y1(I),Y2(I) = ',I8,2E13.5)
      CALL DPWRST('XXX','BUG ')
   55 CONTINUE
   90 CONTINUE
!
!               **************************************************
!               **  CARRY OUT LOGICAL    ARITHMETIC OPERATIONS  **
!               **************************************************
!
!               ********************************************
!               **  STEP 11--                             **
!               **  CHECK NUMBER OF INPUT OBSERVATIONS.   **
!               ********************************************
!
      IF(N1.LT.1)GO TO 1100
      GO TO 1190
!
 1100 CONTINUE
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1151)
 1151 FORMAT('***** ERROR IN LOGARI--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1152)
 1152 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1153)
 1153 FORMAT('      IN THE VARIABLE FOR WHICH')
      CALL DPWRST('XXX','BUG ')
      IF(IACASE.EQ.'LOAN')WRITE(ICOUT,1161)
 1161 FORMAT('      THE LOGICAL    AND    IS TO BE ',   &
      'COMPUTED')
      IF(IACASE.EQ.'LOAN')CALL DPWRST('XXX','BUG ')
      IF(IACASE.EQ.'LOOR')WRITE(ICOUT,1162)
 1162 FORMAT('      THE LOGICAL    OR     IS TO BE ',   &
      'COMPUTED')
      IF(IACASE.EQ.'LOOR')CALL DPWRST('XXX','BUG ')
      IF(IACASE.EQ.'LONA')WRITE(ICOUT,1163)
 1163 FORMAT('      THE LOGICAL    NAND   IS TO BE ',   &
      'COMPUTED')
      IF(IACASE.EQ.'LONA')CALL DPWRST('XXX','BUG ')
      IF(IACASE.EQ.'LONO')WRITE(ICOUT,1164)
 1164 FORMAT('      THE LOGICAL    NOR    IS TO BE ',   &
      'COMPUTED')
      IF(IACASE.EQ.'LONO')CALL DPWRST('XXX','BUG ')
      IF(IACASE.EQ.'LOIM')WRITE(ICOUT,1165)
 1165 FORMAT('      THE LOGICAL    IMPLICATION   IS TO BE ',   &
      'COMPUTED')
      IF(IACASE.EQ.'LOIM')CALL DPWRST('XXX','BUG ')
      IF(IACASE.EQ.'LOEQ')WRITE(ICOUT,1166)
 1166 FORMAT('      THE LOGICAL    EQUIVALENCE   IS TO BE ',   &
      'COMPUTED')
      IF(IACASE.EQ.'LOEQ')CALL DPWRST('XXX','BUG ')
      IF(IACASE.EQ.'LONT')WRITE(ICOUT,1167)
 1167 FORMAT('      THE LOGICAL    NOT    IS TO BE ',   &
      'COMPUTED')
      IF(IACASE.EQ.'LONT')CALL DPWRST('XXX','BUG ')
      IF(IACASE.EQ.'LOXO')WRITE(ICOUT,1168)
 1168 FORMAT('      THE LOGICAL    XOR    IS TO BE ',   &
      'COMPUTED')
      IF(IACASE.EQ.'LOXO')CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1181)
 1181 FORMAT('      MUST BE 1 OR LARGER.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1182)
 1182 FORMAT('      SUCH WAS NOT THE CASE HERE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1183)N1
 1183 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS HERE = ',I8,   &
      '.')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
!
 1190 CONTINUE
!
!               *********************************
!               **  STEP 12--                  **
!               **  BRANCH TO THE PROPER CASE  **
!               *********************************
!
      IF(IACASE.EQ.'LOAN')GO TO 2100
      IF(IACASE.EQ.'LOOR')GO TO 2200
      IF(IACASE.EQ.'LONA')GO TO 2300
      IF(IACASE.EQ.'LONO')GO TO 2400
      IF(IACASE.EQ.'LOIM')GO TO 2500
      IF(IACASE.EQ.'LOEQ')GO TO 2600
      IF(IACASE.EQ.'LONT')GO TO 2700
      IF(IACASE.EQ.'LOXO')GO TO 2800
!
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1211)
 1211 FORMAT('***** INTERNAL ERROR IN LOGARI--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1212)
 1212 FORMAT('      IACASE NOT EQUAL TO')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1213)
 1213 FORMAT('      LOAN, LOOR, LONA, LONO, ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1214)
 1214 FORMAT('      LOIM, LOEQ, LONT, OR LOXO')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1215)
 1215 FORMAT('      IACASE = ',A4)
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
!
!               *********************************************
!               **  STEP 21--                              **
!               **  TREAT THE LOGICAL    AND         CASE  **
!               **  0 0 1 1   &   0 1 0 1  YIELDS  0 0 0 1 **
!               *********************************************
!
 2100 CONTINUE
      DO 2110 I=1,N1
      Y3(I)=ZERO
      IF(ONEMIN.LE.Y1(I).AND.Y1(I).LE.ONEMAX.AND.   &
         ONEMIN.LE.Y2(I).AND.Y2(I).LE.ONEMAX)Y3(I)=ONE
 2110 CONTINUE
!
      ITYP3='VECT'
      N3=N1
      GO TO 9000
!
!               *********************************************
!               **  STEP 22--                              **
!               **  TREAT THE LOGICAL    OR          CASE  **
!               **  0 0 1 1   &   0 1 0 1  YIELDS  0 1 1 1 **
!               *********************************************
!
 2200 CONTINUE
      DO 2210 I=1,N1
      Y3(I)=ONE
      IF(ZERMIN.LE.Y1(I).AND.Y1(I).LE.ZERMAX.AND.   &
         ZERMIN.LE.Y2(I).AND.Y2(I).LE.ZERMAX)Y3(I)=ZERO
 2210 CONTINUE
!
      ITYP3='VECT'
      N3=N1
      GO TO 9000
!
!               ************************************************
!               **  STEP 23--                                 **
!               **  TREAT THE LOGICAL    NAND           CASE  **
!               **  0 0 1 1   &   0 1 0 1  YIELDS  1 1 1 0    **
!               ************************************************
!
 2300 CONTINUE
      DO 2310 I=1,N1
      Y3(I)=ONE
      IF(ONEMIN.LE.Y1(I).AND.Y1(I).LE.ONEMAX.AND.   &
         ONEMIN.LE.Y2(I).AND.Y2(I).LE.ONEMAX)Y3(I)=ZERO
 2310 CONTINUE
!
      ITYP3='VECT'
      N3=N1
      GO TO 9000
!
!               ************************************************
!               **  STEP 24--                                 **
!               **  TREAT THE LOGICAL    NOR            CASE  **
!               **  0 0 1 1   &   0 1 0 1  YIELDS  1 0 0 0    **
!               ************************************************
!
 2400 CONTINUE
      DO 2410 I=1,N1
      Y3(I)=ZERO
      IF(ZERMIN.LE.Y1(I).AND.Y1(I).LE.ZERMAX.AND.   &
         ZERMIN.LE.Y2(I).AND.Y2(I).LE.ZERMAX)Y3(I)=ONE
 2410 CONTINUE
!
      ITYP3='VECT'
      N3=N1
      GO TO 9000
!
!               ***************************************************
!               **  STEP 25--                                    **
!               **  TREAT THE LOGICAL    IMPLICATION       CASE  **
!               **  0 0 1 1   &   0 1 0 1  YIELDS  1 1 0 1       **
!               ***************************************************
!
 2500 CONTINUE
      DO 2510 I=1,N1
      Y3(I)=ONE
      IF(ONEMIN.LE.Y1(I).AND.Y1(I).LE.ONEMAX.AND.   &
         ZERMIN.LE.Y2(I).AND.Y2(I).LE.ZERMAX)Y3(I)=ZERO
 2510 CONTINUE
!
      ITYP3='VECT'
      N3=N1
      GO TO 9000
!
!               ************************************************
!               **  STEP 26--                                 **
!               **  TREAT THE LOGICAL    EQUIVALENCE    CASE  **
!               **  0 0 1 1   &   0 1 0 1  YIELDS  1 0 0 1    **
!               ************************************************
!
 2600 CONTINUE
      DO 2610 I=1,N1
      Y3(I)=ZERO
      IF(ONEMIN.LE.Y1(I).AND.Y1(I).LE.ONEMAX.AND.   &
         ONEMIN.LE.Y2(I).AND.Y2(I).LE.ONEMAX)Y3(I)=ONE
      IF(ZERMIN.LE.Y1(I).AND.Y1(I).LE.ZERMAX.AND.   &
         ZERMIN.LE.Y2(I).AND.Y2(I).LE.ZERMAX)Y3(I)=ONE
 2610 CONTINUE
!
      ITYP3='VECT'
      N3=N1
      GO TO 9000
!
!               *********************************************
!               **  STEP 27--                              **
!               **  TREAT THE LOGICAL    NOT         CASE  **
!               **  0 1      YIELDS  1 0                   **
!               *********************************************
!
 2700 CONTINUE
      DO 2710 I=1,N1
      Y3(I)=ZERO
      IF(ZERMIN.LE.Y1(I).AND.Y1(I).LE.ZERMAX)Y3(I)=ONE
 2710 CONTINUE
!
      ITYP3='VECT'
      N3=N1
      GO TO 9000
!
!               ************************************************
!               **  STEP 28--                                 **
!               **  TREAT THE LOGICAL    XOR            CASE  **
!               **  0 0 1 1   &   0 1 0 1  YIELDS  0 1 1 0    **
!               ************************************************
!
 2800 CONTINUE
      DO 2810 I=1,N1
      Y3(I)=ONE
      IF(ONEMIN.LE.Y1(I).AND.Y1(I).LE.ONEMAX.AND.   &
         ONEMIN.LE.Y2(I).AND.Y2(I).LE.ONEMAX)Y3(I)=ZERO
      IF(ZERMIN.LE.Y1(I).AND.Y1(I).LE.ZERMAX.AND.   &
         ZERMIN.LE.Y2(I).AND.Y2(I).LE.ZERMAX)Y3(I)=ZERO
 2810 CONTINUE
!
      ITYP3='VECT'
      N3=N1
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGA3.EQ.'OFF'.AND.ISUBRO.NE.'GARI')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF LOGARI--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGA3,ISUBRO,IACASE,IWRITE
 9012 FORMAT('IBUGA3,ISUBRO,IACASE,IWRITE = ',A4,2X,A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)IERROR
 9013 FORMAT('IERROR = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9017)N1,N3
 9017 FORMAT('N1,N3 = ',2I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9018)SCAL3,ITYP3
 9018 FORMAT('SCAL3,ITYP3 = ',E15.7,2X,A4)
      CALL DPWRST('XXX','BUG ')
      IF(ITYP3.EQ.'SCAL')GO TO 9090
      DO 9021 I=1,N1
      WRITE(ICOUT,9022)I,Y1(I),Y2(I)
 9022 FORMAT('I,Y1(I),Y2(I) = ',I8,2E13.5)
      CALL DPWRST('XXX','BUG ')
 9021 CONTINUE
      DO 9031 I=1,N3
      WRITE(ICOUT,9032)I,Y3(I)
 9032 FORMAT('I,Y3(I) = ',I8,E13.5)
      CALL DPWRST('XXX','BUG ')
 9031 CONTINUE
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE LOGARI
      SUBROUTINE LOGGAM(X,ALG)
!
!     THIS PROGRAM CALCULATES THE LOG(TO BASE E) OF THE GAMMA FUNCTION
!     THE INPUT IS SINGLE PRECISION X
!     THE OUTPUT IS SINGLE PRECISION ALG
!     ALL INTERNAL OPERATIONS ARE DONE IN SINGLE PRECISION
!     THE ALGORITHM IS TO USE THE RECURSION FORMULA G(X)=G(X+1)/X
!     UNTIL X IS LARGE ENOUGH TO USE AN ASYMPTOTIC FORMULA FOR G(X)--THE CUT-OFF
!     POINT USED WAS X = 10
!     THE ASYMPTOTIC FORMULA USED IS IN AMS 55, PAGE 257, 6.1.41 (THE FIRST 9
!     TERMS OF THE SERIES WERE USED--I.E., OUT TO X**-17)
!     ALTHOUGH THE DATA STATEMENT DEFINES 10 COEFFICIENTS, THE PROGRAM MAKES USE
!     OF ONLY 9 COEFFICIENTS (THE ERROR BEING BOUNDED BY THE TENTH COEFFICIENT
!     DIVIDED BY X**19
!     SUBROUTINES NEEDED--NONE
!     PRINTING--NONE UNLESS AN ERROR CONDITION EXISTS
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82.6
!     ORIGINAL VERSION--JUNE      1972.
!     UPDATED         --FEBRUARY  1981.
!     UPDATED         --FEBRUARY  1982.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION Y,Y2,Y3,Y4,Y5,DEN,A,B,C,D
!
      DIMENSION D(10)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
      DATA C/ .918938533204672741D0/
      DATA D(1),D(2),D(3),D(4),D(5)   &
         /.833333333333333333D-1,-.277777777777777778D-2,   &
          .793650793650793651D-3,-.595238095238095238D-3,.841750841750841751D-3/
      DATA D(6),D(7),D(8),D(9),D(10)   &
         /-.191752691752691753D-2,.641025641025641025D-2,-.295506535947712418D-1,   &
          .179644372368830573D0,-.139243221690590111D1/
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(X.LE.0.0D0)GO TO 50
      GO TO 90
   50 WRITE(ICOUT,5)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,45)X
      CALL DPWRST('XXX','BUG ')
      RETURN
   90 CONTINUE
    5 FORMAT('***** FATAL ERROR--THE 1ST INPUT ARGUMENT TO THE ',   &
      'LOGGAM SUBROUTINE IS NON-POSITIVE *****')
   45 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',D22.15,' *****')
!
      Y=X
      DEN=1.0D0
  100 IF(Y.GE.10.0D0)GO TO 200
      DEN=DEN*Y
      Y=Y+1
      GO TO 100
  200 Y2=Y*Y
      Y3=Y*Y2
      Y4=Y2*Y2
      Y5=Y2*Y3
      A=(Y-0.5D0)*DLOG(Y)-Y+C
      B=D(1)/Y+D(2)/Y3+D(3)/Y5+D(4)/(Y2*Y5)+D(5)/(Y4*Y5)+   &
      D(6)/(Y*Y5*Y5)+D(7)/(Y3*Y5*Y5)+D(8)/(Y5*Y5*Y5)+D(9)/(Y2*Y5*Y5*Y5)
      ALG=(A+B)-DLOG(DEN)
!
      RETURN
      END SUBROUTINE LOGGAM
      SUBROUTINE LOGIST(N,X,X0,AK,IERROR)
!
!     PURPOSE--THIS SUBROUTINE GENERATES N LOGISTIC NUMBERS
!              (A CLASSIC CHAOS THEORY SEQUENCE)
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF LOGISTIC NUMBERS
!                                TO BE GENERATED.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                LOGISTIC NUMBERS
!                                WILL BE PLACED.
!                     --X0     = THE STARTING VALUE
!                                (THIS WILL BE THE FIRST VALUE
!                                OF THE OUTPUT SEQUENCE)
!                     --AK    = THE INDEX FOR THE SYSTEM
!     OUTPUT--N LOGISTIC-SEQUENCE NUMBERS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--89.6
!     ORIGINAL VERSION--APRIL 1989.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IERROR
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      CPUMA3=CPUMAX/3.0
!
!               ******************************************
!               **  TREAT THE LOGISTIC SEQUENCE CASE    **
!               ******************************************
!
!               *******************************************
!               **  STEP 1--                             **
!               **  TEST THE INPUT ARGUMENTS FOR ERRORS  **
!               *******************************************
!
      IF(N.GE.1)GO TO 190
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,101)
  101 FORMAT('***** ERROR IN LOGIST--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,102)
  102 FORMAT('      THE LENGTH OF THE DESIRED SEQUENCE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,103)
  103 FORMAT('      OF LOGISTIC NUMBERS MUST BE 1 OR LARGER;')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,104)
  104 FORMAT('      SUCH WAS NOT THE CASE HERE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,105)N
  105 FORMAT('      N = ',I8)
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
  190 CONTINUE
!
!               ******************************
!               **  STEP 2--                **
!               **  GENERATE THE SEQUENCE   **
!               ******************************
!
      X(1)=X0
      IF(N.LT.2)GO TO 1190
      DO 1100 I=2,N
      I2=I
      IM1=I-1
      X(I)=AK*X(IM1)*(1.0-X(IM1))
      IF(X(I).GE.CPUMA3)GO TO 1150
 1100 CONTINUE
      GO TO 1190
!
 1150 CONTINUE
      I2P1=I2+1
      WRITE(ICOUT,1151)
 1151 FORMAT('***** ERROR IN LOGIST--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1152)
 1152 FORMAT('      A NUMBER IN THE LOGISTIC SEQUENCE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1153)
 1153 FORMAT('      HAS JUST EXCEEDED THE ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1154)
 1154 FORMAT('      LARGEST FLOATING POINT NUMBER')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1155)
 1155 FORMAT('      ALLOWABLE FOR THIS COMPUTER (',E15.7,').')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1156)
 1156 FORMAT('      THE VALUE CAUSING THE OVERFLOW WAS')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1157)I2P1
 1157 FORMAT('      THE ',I8,'-TH NUMBER IN THE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1158)
 1158 FORMAT('      LOGISTIC SEQUENCE.')
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
!
 1190 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE LOGIST
      SUBROUTINE LOGIT(X,N1,Y,N2,PSTAMV,IWRITE,XIDTEM,STAT,   &
                        IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE BIAS CORRECTED
!             LOGARITHM OF THE ODDS RATIO.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED) OBSERVATIONS
!                                WHICH CONSTITUTE THE FIRST SET
!                                OF DATA.
!                     --N1     = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!                     --Y      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED) OBSERVATIONS
!                                WHICH CONSTITUTE THE SECOND SET
!                                OF DATA.
!                     --N2     = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR Y.
!                     --PSTAMV = THE MISSING VALUE CODE
!     OUTPUT ARGUMENTS--STAT   = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED LOG ODDS RATIO
!                                BETWEEN THE 2 SETS OF DATA
!                                IN THE INPUT VECTORS X AND Y.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE LOG ODDS RATIO BETWEEN THE 2 SETS
!             OF DATA IN THE INPUT VECTORS X AND Y.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--ODDDIS.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTIUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007/4
!     ORIGINAL VERSION--APRIL     2007.
!     UPDATED         --AUGUST    2007. IF 2X2 CASE, CHECK IF SUM
!                                       OF ENTRIES IS <= 4.  IN THIS
!                                       CASE, ASSUME WE HAVE RAW DATA
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISTEPN
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION Y(*)
      DIMENSION XIDTEM(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='LOGI'
      ISUBN2='T   '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF LOGIT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3
   52   FORMAT('IBUGA3 = ',A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)N1,N2
   53   FORMAT('N1,N2 = ',2I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,MAX(N1,N2)
          WRITE(ICOUT,56)I,X(I),Y(I)
   56     FORMAT('I,X(I),Y(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 21--                             **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='21'
      IF(IBUGA3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(N1.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1201)
 1201   FORMAT('***** ERROR IN THE BIAS CORRECTED ',   &
               'LOG ODDS RATIO')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1203)
 1203   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE FIRST ',   &
               'RESPONSE VARIABLES IS LESS THAN TWO')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1205)N1
 1205   FORMAT('SAMPLE SIZE = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(N2.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1201)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1213)
 1213   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE SECOND ',   &
               'RESPONSE VARIABLES IS LESS THAN TWO')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1205)N2
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ********************************************
!               **  STEP 22--                             **
!               **  CHECK THAT THE VARIABLES HAVE AT MOST **
!               **  TWO DISTINCT VALUES (1 INDICATES A    **
!               **  SUCCESS, 0 INDICATES A FAILURE).      **
!               ********************************************
!
      ISTEPN='22'
      IF(IBUGA3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     NOTE: CHECK FOR SPECIAL CASE N = 2.  IN THIS CASE,
!           ASSUME WE HAVE A 2X2 TABLE OF COUNTS INSTEAD
!           OF RAW DATA.
!
      IF(N1.EQ.2 .AND. N2.EQ.2)THEN
        N11=INT(X(1)+0.5)
        N21=INT(X(2)+0.5)
        N12=INT(Y(1)+0.5)
        N22=INT(Y(2)+0.5)
!
!       CHECK IF ALL ENTRIES 0 OR 1. IF SO, ASSUME
!       RAW DATA CASE.
!
        IF((N11.EQ.0 .OR. N11.EQ.1) .AND.   &
           (N12.EQ.0 .OR. N12.EQ.1) .AND.   &
           (N21.EQ.0 .OR. N21.EQ.1) .AND.   &
           (N22.EQ.0 .OR. N22.EQ.1)) GO TO 1349
!
        IF(N11.LT.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1201)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1311)
 1311     FORMAT('      ROW 1 COLUMN 1 OF THE COUNTS TABLE IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(N21.LT.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1201)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1321)
 1321     FORMAT('      ROW 2 COLUMN 1 OF THE COUNTS TABLE IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(N12.LT.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1201)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1331)
 1331     FORMAT('      ROW 1 COLUMN 2 OF THE COUNTS TABLE IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(N22.LT.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1201)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1341)
 1341     FORMAT('      ROW 2 COLUMN 2 OF THE COUNTS TABLE IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        AN11=REAL(N11)
        AN21=REAL(N21)
        AN12=REAL(N12)
        AN22=REAL(N22)
        GO TO 3000
      ENDIF
!
 1349 CONTINUE
!
      CALL ODDDIS(X,N1,PSTAMV,IWRITE,XIDTEM,N11,N21,NOUT,   &
                  IBUGA3,IERROR)
      IF(IERROR.EQ.'YES' .OR. IERROR.EQ.'ON')GO TO 9000
      CALL ODDDIS(Y,N2,PSTAMV,IWRITE,XIDTEM,N12,N22,NOUT,   &
                  IBUGA3,IERROR)
      IF(IERROR.EQ.'YES' .OR. IERROR.EQ.'ON')GO TO 9000
      AN11=REAL(N11)
      AN21=REAL(N21)
      AN12=REAL(N12)
      AN22=REAL(N22)
      GO TO 3000
!
!     COMPUTE THE BIAS CORRECTED LOG OF THE ODDS RATIO.
!
 3000 CONTINUE
      AN1=AN11+AN21
      AN2=AN12+AN22
      AN=AN1 + AN2
!
      P11=AN11/AN1
      P21=AN21/AN1
      P12=AN12/AN2
      P22=AN22/AN2
!
      STAT=LOG((AN11+0.5)*(AN22+0.5)/((AN12+0.5)*(AN21+0.5)))
!
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'OFF')GO TO 890
      IF(IWRITE.EQ.'OFF' .OR. IWRITE.EQ.'NO')GO TO 890
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,811)STAT
  811 FORMAT('THE BIAS CORRECTED LOG ODDS RATIO = ',G15.7)
      CALL DPWRST('XXX','BUG ')
  890 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END OF LOGIT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGA3,IERROR
 9012   FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)N,N11,N12,N21,N22
 9013   FORMAT('N,N11,N12,N21,N22 = ',5I10)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)P11,P12,P21,P22
 9014   FORMAT('P11,P12,P21,P22 = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)STAT
 9015   FORMAT('STAT = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE LOGIT
      SUBROUTINE LOGISE(X,N1,Y,N2,PSTAMV,IWRITE,XIDTEM,STAT,   &
                        IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE STANDARD ERROR OF THE
!              BIAS CORRECTED LOGARITHM OF THE ODDS RATIO.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED) OBSERVATIONS
!                                WHICH CONSTITUTE THE FIRST SET
!                                OF DATA.
!                     --N1     = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!                     --Y      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED) OBSERVATIONS
!                                WHICH CONSTITUTE THE SECOND SET
!                                OF DATA.
!                     --N2     = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR Y.
!     OUTPUT ARGUMENTS--STAT   = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED STANDARD ERROR OF THE
!                                LOG ODDS RATIO (BIAS CORRECTED)
!                                BETWEEN THE 2 SETS OF DATA
!                                IN THE INPUT VECTORS X AND Y.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE STANDARD ERROR OF THE LOG ODDS RATIO BETWEEN
!             THE 2 SETS OF DATA IN THE INPUT VECTORS X AND Y.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--ODDDIS.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTIUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007/4
!     ORIGINAL VERSION--APRIL     2007.
!     UPDATED         --AUGUST    2007. IF 2X2 CASE, CHECK IF SUM
!                                       OF ENTRIES IS <= 4.  IN THIS
!                                       CASE, ASSUME WE HAVE RAW DATA
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISTEPN
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION Y(*)
      DIMENSION XIDTEM(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='LOGI'
      ISUBN2='SE  '
      IERROR='NO'
!
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF LOGISE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3
   52   FORMAT('IBUGA3 = ',A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)N1,N2
   53   FORMAT('N1,N2 = ',2I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,MAX(N1,N2)
          WRITE(ICOUT,56)I,X(I),Y(I)
   56     FORMAT('I,X(I),Y(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 21--                             **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='21'
      IF(IBUGA3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(N1.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1201)
 1201   FORMAT('***** ERROR IN STANDARD ERROR OF BIAS CORRECTED ',   &
               'LOG ODDS RATIO')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1203)
 1203   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE FIRST ',   &
               'RESPONSE VARIABLES IS LESS THAN TWO')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1205)N1
 1205   FORMAT('SAMPLE SIZE = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(N2.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1201)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1213)
 1213   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE SECOND ',   &
               'RESPONSE VARIABLES IS LESS THAN TWO')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1205)N2
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!     NOTE: CHECK FOR SPECIAL CASE N = 2.  IN THIS CASE,
!           ASSUME WE HAVE A 2X2 TABLE OF COUNTS INSTEAD
!           OF RAW DATA.
!
      IF(N1.EQ.2 .AND. N2.EQ.2)THEN
        N11=INT(X(1)+0.5)
        N21=INT(X(2)+0.5)
        N12=INT(Y(1)+0.5)
        N22=INT(Y(2)+0.5)
!
!       CHECK IF ALL ENTRIES 0 OR 1. IF SO, ASSUME
!       RAW DATA CASE.
!
        IF((N11.EQ.0 .OR. N11.EQ.1) .AND.   &
           (N12.EQ.0 .OR. N12.EQ.1) .AND.   &
           (N21.EQ.0 .OR. N21.EQ.1) .AND.   &
           (N22.EQ.0 .OR. N22.EQ.1)) GO TO 1349
!
        IF(N11.LT.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1201)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1311)
 1311     FORMAT('      ROW 1 COLUMN 1 OF THE COUNTS TABLE IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(N21.LT.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1201)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1321)
 1321     FORMAT('      ROW 2 COLUMN 1 OF THE COUNTS TABLE IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(N12.LT.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1201)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1331)
 1331     FORMAT('      ROW 1 COLUMN 2 OF THE COUNTS TABLE IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
        ELSEIF(N22.LT.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1201)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1341)
 1341     FORMAT('      ROW 2 COLUMN 2 OF THE COUNTS TABLE IS ',   &
                 'NEGATIVE.')
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        AN11=REAL(N11)
        AN21=REAL(N21)
        AN12=REAL(N12)
        AN22=REAL(N22)
        GO TO 3000
      ENDIF
!
!
!               ********************************************
!               **  STEP 22--                             **
!               **  CHECK THAT THE VARIABLES HAVE AT MOST **
!               **  TWO DISTINCT VALUES (1 INDICATES A    **
!               **  SUCCESS, 0 INDICATES A FAILURE).      **
!               ********************************************
!
 1349 CONTINUE
!
      ISTEPN='22'
      IF(IBUGA3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL ODDDIS(X,N1,PSTAMV,IWRITE,XIDTEM,N11,N21,NOUT,   &
                  IBUGA3,IERROR)
      IF(IERROR.EQ.'YES' .OR. IERROR.EQ.'ON')GO TO 9000
      CALL ODDDIS(Y,N2,PSTAMV,IWRITE,XIDTEM,N12,N22,NOUT,   &
                  IBUGA3,IERROR)
      IF(IERROR.EQ.'YES' .OR. IERROR.EQ.'ON')GO TO 9000
      AN11=REAL(N11)
      AN21=REAL(N21)
      AN12=REAL(N12)
      AN22=REAL(N22)
      GO TO 3000
!
!     COMPUTE THE BIAS CORRECTED LOG OF THE ODDS RATIO.
!
 3000 CONTINUE
      AN1=AN11+AN21
      AN2=AN12+AN22
      AN=AN1 + AN2
!
      P11=AN11/AN1
      P21=AN21/AN1
      P12=AN12/AN2
      P22=AN22/AN2
!
      STAT=SQRT((1.0/(AN11+0.5)) + (1.0/(AN21+0.5)) +   &
               (1.0/(AN12+0.5)) + (1.0/(AN22+0.5)))
!
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'OFF')GO TO 890
      IF(IWRITE.EQ.'OFF' .OR. IWRITE.EQ.'NO')GO TO 890
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,811)STAT
  811 FORMAT('THE STANDARD ERROR OF BIAS CORRECTED LOG ODDS ',   &
             'RATIO = ',G15.7)
      CALL DPWRST('XXX','BUG ')
  890 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END OF LOGISE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGA3,IERROR
 9012   FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)N,N11,N12,N21,N22
 9013   FORMAT('N,N11,N12,N21,N22 = ',5I10)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)P11,P12,P21,P22
 9014   FORMAT('P11,P12,P21,P22 = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)STAT
 9015   FORMAT('STAT = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE LOGISE
      SUBROUTINE LOGCDF(X,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE LOGISTIC DISTRIBUTION
!              WITH MEAN = 0 AND STANDARD DEVIATION = PI/SQRT(3).
!              THIS DISTRIBUTION IS DEFINED FOR ALL X AND HAS
!              THE PROBABILITY DENSITY FUNCTION
!              F(X) = EXP(X)/(1+EXP(X)).
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 1970, PAGES 1-21.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-921-2315
!     ORIGINAL VERSION--APRIL     1994.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS.
!     NO INPUT ARGUMENT ERRORS POSSIBLE
!     FOR THIS DISTRIBUTION.
!
!-----START POINT-----------------------------------------------------
!
      IF(X.GE.0.0)GO TO 150
      CDF=EXP(X)/(1.0+EXP(X))
      RETURN
  150 CDF=1.0/(1.0+EXP(-X))
      RETURN
!
      END SUBROUTINE LOGCDF
      SUBROUTINE LOGCHA(X,CHAZ)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE HAZARD
!              FUNCTION VALUE FOR THE LOGISTIC DISTRIBUTION
!              WITH MEAN = 0 AND STANDARD DEVIATION = PI/SQRT(3).
!              THIS DISTRIBUTION IS DEFINED FOR ALL X AND HAS
!              THE CUMULATIVE HAZARD FUNCTION
!              F(X) = 1/(1+EXP(-X)).
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE HAZARD
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--HAZ    = THE SINGLE PRECISION CUMULATIVE
!                                HAZARD FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE HAZARD
!             FUNCTION VALUE HAZ.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG, EXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--EVANS, HASTINGS, AND PEACOCK, "STATISITCAL
!                 DISTRIBUTIONS", THIRD EDITION, 2000, PAGES 124-128.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2899
!     ORIGINAL VERSION--OCTOBER   2003.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS.
!     NO INPUT ARGUMENT ERRORS POSSIBLE
!     FOR THIS DISTRIBUTION.
!
!-----START POINT-----------------------------------------------------
!
      CHAZ=LOG(1.0+EXP(-X))
!
      RETURN
      END SUBROUTINE LOGCHA
      SUBROUTINE LOGFUN (N, X, FVEC, IFLAG, XDATA, NOBS)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE FUNCTIONS FOR THE
!              LOGISTIC MAXIMUM LIKELIHOOD EQUATIONS.
!
!              SUM[i=1 to n][1+EXP{-(X(i)-ahat)/bhat}]**(-1)-N/2 = 0
!
!              (X(i)-ahat)/bhat)/SUM[i=1 to n][1+EXP{-(X(i)-ahat)}]**(-1)
!              - 0.5*SUM[i=1 to n][(X(i)-ahat)/bhat] - 0.5*N = 0
!
!              CALLED BY SNSQE ROUTINE FOR SOLVING SIMULTANEOUS
!              NONLINEAR EQUATIONS.  NOTE THAT THE CALLING SEQUENCE
!              DID NOT ACCOMODATE A DATA ARRAY (AND ASSCIATED NUMBER OF
!              OBSERVATIONS), SO THESE WERE ADDED TO THE CALL LIST.
!     EXAMPLE--PARETO MAXIMUM LIKELIHOOD Y
!     REFERENCE--CHARLES ANTLE, LAWRENCE KLIMKO, AND WILLIAM
!                HARKNESS, (1970), "CONFIDENCE INTERVALS FOR THE
!                PARAMETERS OF THE LOGISTIC DISTRIBUTION", BIOMETRIKA,
!                PP. 397-402.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 CENTER FOR APPLIED MATHEMATICS
!                 NATIONAL BUREAU OF STANDARDS
!                 WASHINGTON, D. C. 20234
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2003/10
!     ORIGINAL VERSION--OCTOBER   2003.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION X(*)
      DOUBLE PRECISION FVEC(*)
      REAL XDATA(*)
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DA
      DOUBLE PRECISION DB
      DOUBLE PRECISION DX
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DSUM3
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  COMPUTE SOME SUMS
!
      N=2
      IFLAG=0
!
      DN=DBLE(NOBS)
      DSUM1=0.0D0
      DSUM2=0.0D0
      DSUM3=0.0D0
      DA=X(1)
      DB=X(2)
      DO 100 I=1,NOBS
        DX=DBLE(XDATA(I))
        DTERM1=(DX - DA)/DB
        DTERM2=1.0D0 + DEXP(-DTERM1)
        DSUM1=DSUM1 + 1.0D0/DTERM2
        DSUM2=DSUM2 + DTERM1/DTERM2
        DSUM3=DSUM3 + DTERM1
  100 CONTINUE
!
      DTERM1=DSUM1 - 0.5D0*DN
      DTERM2=DSUM2 - 0.5D0*DSUM3 - 0.5D0*DN
!
! COMPUTE NONLINEAR FUNCTIONS
!
      FVEC(1) = DTERM1
      FVEC(2) = DTERM2
!
      RETURN
      END SUBROUTINE LOGFUN 
      SUBROUTINE LOGHAZ(X,HAZ)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE HAZARD
!              FUNCTION VALUE FOR THE LOGISTIC DISTRIBUTION
!              WITH MEAN = 0 AND STANDARD DEVIATION = PI/SQRT(3).
!              THIS DISTRIBUTION IS DEFINED FOR ALL X AND HAS
!              THE HAZARD FUNCTION
!              F(X) = 1/(1+EXP(-X)).
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE HAZARD
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--HAZ    = THE SINGLE PRECISION HAZARD
!                                FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION HAZARD
!             FUNCTION VALUE HAZ.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--EVANS, HASTINGS, AND PEACOCK, "STATISITCAL
!                 DISTRIBUTIONS", THIRD EDITION, 2000, PAGES 124-128.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2899
!     ORIGINAL VERSION--OCTOBER   2003.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS.
!     NO INPUT ARGUMENT ERRORS POSSIBLE
!     FOR THIS DISTRIBUTION.
!
!-----START POINT-----------------------------------------------------
!
      HAZ=1.0/(1.0+EXP(-X))
!
      RETURN
      END SUBROUTINE LOGHAZ
      SUBROUTINE LOGLI1(Y,N,ALOC,SCALE,ALIK,AIC,AICC,BIC,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE LIKELIHOOD FUNCTION FOR
!              THE LOGISTIC DISTRIBUTION.  THIS IS FOR THE RAW DATA
!              CASE (I.E., NO GROUPING AND NO CENSORING).
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2009/10
!     ORIGINAL VERSION--OCTOBER   2009.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DS
      DOUBLE PRECISION DU
      DOUBLE PRECISION DN
      DOUBLE PRECISION DNP
      DOUBLE PRECISION DLIK
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM3
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='LOGL'
      ISUBN2='I1  '
      IERROR='NO'
!
      ALIK=-99.0
      AIC=-99.0
      AICC=-99.0
      BIC=-99.0
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'GLI1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF LOGLI1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO
   52   FORMAT('IBUGA3,ISUBRO = ',A4,2X,A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,55)N,ALOC,SCALE
   55   FORMAT('N,ALOC,SCALE = ',I8,2G15.7)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  COMPUTE LIKELIHOOD FUNCTION         **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'GLI1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IERFLG=0
      IERROR='NO'
      IWRITE='OFF'
!
!     THE LOGISTIC LOG-LIKELIHOOD FUNCTION CAN BE GIVEN AS:
!
!     SUM[i=1 to N][(X(I)-LOC)/SCALE)]  - 2*N*LOG(SCALE) -
!     2*SUM[i=1 to N][LOG(1 + EXP((X(I)-LOC)/SCALE)]
!
      DN=DBLE(N)
      DS=DBLE(SCALE)
      DU=DBLE(ALOC)
      DTERM1=-2.0D0*DN*DLOG(DS)
      DSUM1=0.0D0
      DSUM2=0.0D0
      DO 1000 I=1,N
        DX=DBLE(Y(I))
        DSUM1=DSUM1 + (DX-DU)/DS
        DSUM2=DSUM2 + DLOG(1.0D0 + DEXP((DX-DU)/DS))
 1000 CONTINUE
!
      DLIK=DSUM1 + DTERM1 - 2.0D0*DSUM2
      ALIK=REAL(DLIK)
      DNP=2.0D0
      AIC=REAL(-2.0D0*DLIK + 2.0D0*DNP)
      DTERM3=(2.0D0*DNP*(DNP+1.0D0))/(DN-DNP-1.0D0)
      AICC=REAL(-2.0D0*DLIK + 2.0D0*DNP + DTERM3)
      BIC=REAL(-2.0D0*DLIK + DNP*LOG(DN))
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'GLI1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF LOGLI1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)DSUM1,DSUM2,DTERM1,DTERM3
 9013   FORMAT('DSUM1,DSUM2,DTERM1,DTERM3 = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9014)ALIK,AIC,AICC,BIC
 9014   FORMAT('ALIK,AIC,AICC,BIC = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE LOGLI1
      SUBROUTINE LOGML1(Y,N,MAXNXT,   &
                        DTEMP1,   &
                        XMEAN,XSD,XMIN,XMAX,   &
                        ALOC,ASCALE,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE MAXIMUM LIKELIHOOD ESTIMATES
!              FOR THE LOGISTIC DISTRIBUTION FOR THE RAW DATA CASE
!              (I.E., NO CENSORING AND NO GROUPING).
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!              PUT THIS IN A SEPARATE ROUTINE AS IT MAY BE CALLED
!              FROM MULTIPLE PLACES (DPMLLO WILL GENERATE THE OUTPUT
!              FOR THE LOGISTIC MLE COMMAND).
!
!     REFERENCE--CHARLES ANTLE, LAWRENCE KLIMKO, AND WILLIAM
!                HARKNESS, (1970), "CONFIDENCE INTERVALS FOR THE
!                PARAMETERS OF THE LOGISTIC DISTRIBUTION", BIOMETRIKA,
!                PP. 397-402.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2009/9
!     ORIGINAL VERSION--OCTOBER   2009. EXTRACTED AS A SEPARATE
!                                       SUBROUTINE (FROM DPMLLO)
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*40 IDIST
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      INTEGER IFLAG
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DOUBLE PRECISION DTEMP1(*)
!
      DOUBLE PRECISION TOL
      DOUBLE PRECISION XPAR(2)
      DOUBLE PRECISION FVEC(2)
!
      EXTERNAL LOGFUN
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      DATA PI/3.14159265358979/
!
      ISUBN1='LOGM'
      ISUBN2='L1  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'GML1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF LOGML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N,MAXNXT
   52   FORMAT('IBUGA3,ISUBRO,N,MAXNXT = ',A4,2X,A4,2X,2I8)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  CARRY OUT CALCULATIONS              **
!               **  FOR LOGISTIC MLE ESTIMATE           **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'GML1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IDIST='LOGISTIC'
      IFLAG=0
      CALL SUMRAW(Y,N,IDIST,IFLAG,   &
                  XMEAN,XVAR,XSD,XMIN,XMAX,   &
                  ISUBRO,IBUGA3,IERROR)
!
      XPAR(1)=DBLE(XMEAN)
      XPAR(2)=DBLE((SQRT(3.0)/PI)*XSD)
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'GML1')THEN
        WRITE(ICOUT,101)XPAR(1),XPAR(2)
  101   FORMAT('XPAR(1),XPAR(2) = ',2G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      IOPT=2
      TOL=1.0D-6
      NVAR=2
      NPRINT=-1
      INFO=0
      JAC=0
      LWA=MAXNXT
      CALL DNSQE(LOGFUN,JAC,IOPT,NVAR,XPAR,FVEC,TOL,NPRINT,INFO,   &
                 DTEMP1,MAXNXT,Y,N)
!
      ALOC=REAL(XPAR(1))
      ASCALE=REAL(XPAR(2))
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'GML1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF LOGML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9055)N,XMEAN,XSD,XMIN,XMAX
 9055   FORMAT('N,XMEAN,XSD,XMIN,XMAX = ',I8,4G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9056)ALOC,ASCALE
 9056   FORMAT('ALOC,ASCALE = ',2G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE LOGML1
      SUBROUTINE LOGPDF(X,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE LOGISTIC DISTRIBUTION
!              WITH MEAN = 0 AND STANDARD DEVIATION = PI/SQRT(3).
!              THIS DISTRIBUTION IS DEFINED FOR ALL X AND HAS
!              THE PROBABILITY DENSITY FUNCTION
!              F(X) = EXP(X)/(1+EXP(X)).
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 1970, PAGES 1-21.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-921-2315
!     ORIGINAL VERSION--APRIL     1994.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS.
!     NO INPUT ARGUMENT ERRORS POSSIBLE
!     FOR THIS DISTRIBUTION.
!
!-----START POINT-----------------------------------------------------
!
      PDF=EXP(X)/((1.0+EXP(X))**2)
!
      RETURN
      END SUBROUTINE LOGPDF
      SUBROUTINE LOGPPF(P,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE LOGISTIC DISTRIBUTION
!              WITH MEAN = 0 AND STANDARD DEVIATION = PI/SQRT(3).
!              THIS DISTRIBUTION IS DEFINED FOR ALL X AND HAS
!              THE PROBABILITY DENSITY FUNCTION
!              F(X) = EXP(X)/(1+EXP(X)).
!              NOTE THAT THE PERCENT POINT FUNCTION OF A DISTRIBUTION
!              IS IDENTICALLY THE SAME AS THE INVERSE CUMULATIVE
!              DISTRIBUTION FUNCTION OF THE DISTRIBUTION.
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE
!                                (BETWEEN 0.0 AND 1.0)
!                                AT WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION PERCENT
!                                POINT FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT
!             FUNCTION VALUE PPF.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--P SHOULD BE BETWEEN 0.0 AND 1.0, EXCLUSIVELY.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--EXP.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--FILLIBEN, SIMPLE AND ROBUST LINEAR ESTIMATION
!                 OF THE LOCATION PARAMETER OF A SYMMETRIC
!                 DISTRIBUTION (UNPUBLISHED PH.D. DISSERTATION,
!                 PRINCETON UNIVERSITY), 1969, PAGES 21-44, 229-231.
!               --FILLIBEN, 'THE PERCENT POINT FUNCTION',
!                 (UNPUBLISHED MANUSCRIPT), 1970, PAGES 28-31.
!               --JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 1970, PAGES 1-21.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--82.6
!     ORIGINAL VERSION--JUNE      1972.
!     UPDATED         --SEPTEMBER 1975.
!     UPDATED         --NOVEMBER  1975.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(P.LE.0.0.OR.P.GE.1.0)GO TO 50
      GO TO 90
   50 WRITE(ICOUT,1)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,46)P
      CALL DPWRST('XXX','BUG ')
      RETURN
   90 CONTINUE
    1 FORMAT('***** FATAL ERROR--THE 1ST INPUT ARGUMENT TO THE ',   &
      'LOGPPF SUBROUTINE IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
!
!CCCC CALL QCORR(P,Q)
!CCCC PPF=LOG(P/Q)
      PPF=LOG(P/(1.0-P))
!
      RETURN
      END SUBROUTINE LOGPPF
      SUBROUTINE LOGRAN(N,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE LOGISTIC DISTRIBUTION
!              WITH MEAN = 0 AND STANDARD DEVIATION = PI/SQRT(3).
!              THIS DISTRIBUTION IS DEFINED FOR ALL X AND HAS
!              THE PROBABILITY DENSITY FUNCTION
!              F(X) = EXP(X)/(1+EXP(X)).
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE LOGISTIC DISTRIBUTION
!             WITH MEAN = 0 AND STANDARD DEVIATION = PI/SQRT(3).
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--TOCHER, THE ART OF SIMULATION,
!                 1963, PAGES 14-15.
!               --HAMMERSLEY AND HANDSCOMB, MONTE CARLO METHODS,
!                 1964, PAGE 36.
!               --FILLIBEN, SIMPLE AND ROBUST LINEAR ESTIMATION
!                 OF THE LOCATION PARAMETER OF A SYMMETRIC
!                 DISTRIBUTION (UNPUBLISHED PH.D. DISSERTATION,
!                 PRINCETON UNIVERSITY), 1969, PAGE 230.
!               --FILLIBEN, 'THE PERCENT POINT FUNCTION',
!                 (UNPUBLISHED MANUSCRIPT), 1970, PAGES 28-31.
!               --JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 1970, PAGES 1-21.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--82.6
!     ORIGINAL VERSION--JUNE      1972.
!     UPDATED         --SEPTEMBER 1975.
!     UPDATED         --NOVEMBER  1975.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)GO TO 50
      GO TO 90
   50 WRITE(ICOUT, 5)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,47)N
      CALL DPWRST('XXX','BUG ')
      RETURN
   90 CONTINUE
    5 FORMAT('***** FATAL ERROR--THE 1ST INPUT ARGUMENT TO THE ',   &
      'LOGRAN SUBROUTINE IS NON-POSITIVE *****')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,' *****')
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N LOGISTIC RANDOM NUMBERS
!     USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD.
!
      DO 100 I=1,N
      X(I)=LOG(X(I)/(1.0-X(I)))
  100 CONTINUE
!
      RETURN
      END SUBROUTINE LOGRAN
      SUBROUTINE LOGRD(X,N,NX,XG,T)
!     THIS SUBROUTINE PLACES A SET OF INTERVALS OVER THE SET OF POINTS
!     (X(I), I=1,...,N).  THIS IS DONE BY PLACING APPROXIMATELY EQUAL
!     NUMBERS OF THEM WITHIN EACH INTERVAL.
!
!     THE ARGUMENTS ARE AS FOLLOWS.
!
!        N   - INPUT.  THE NUMBER OF POINTS IN THE ARRAY X.
!        X   - INPUT.  THE ARRAY OF X POINTS.
!        NX  - INPUT.  THE DESIRED NUMBER OF INTERVALS.
!        XG  - OUTPUT.  THE COORDINATES OF THE INTERVAL ENDPOINTS.
!        T   - WORK ARRAY OF DIMENSION AT LEAST N.
!
!     SUBROUTINES USED
!        SLATEC:  SSORT
!
      DIMENSION X(*),XG(*),T(*)
!
      DO 100 I=1,N
        T(I) = X(I)
  100 CONTINUE
!
!CCCC CALL SSORT(T,T,N,1)
      CALL SORT(T,N,T)
!
      FINC = REAL(N-1)/REAL(NX+1)
      DO 140 J=1,NX
        FK = J*FINC + 1.
        K = INT(FK)
        WK1 = FK - K
        XG(J+1) = (1. - WK1)*T(K) + WK1*T(K+1)
  140 CONTINUE
!
      XG(1) = T(1)
      XG(NX+2) = T(N)
!
      RETURN
      END SUBROUTINE LOGRD
      SUBROUTINE LOGSF(P,SF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE SPARSITY
!              FUNCTION VALUE FOR THE LOGISTIC DISTRIBUTION
!              WITH MEAN = 0 AND STANDARD DEVIATION = PI/SQRT(3).
!              THIS DISTRIBUTION IS DEFINED FOR ALL X AND HAS
!              THE PROBABILITY DENSITY FUNCTION
!              F(X) = EXP(X)/(1+EXP(X)).
!              NOTE THAT THE SPARSITY FUNCTION OF A DISTRIBUTION
!              IS THE DERIVATIVE OF THE PERCENT POINT FUNCTION,
!              AND ALSO IS THE RECIPROCAL OF THE PROBABILITY
!              DENSITY FUNCTION (BUT IN UNITS OF P RATHER THAN X).
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE
!                                (BETWEEN 0.0 AND 1.0)
!                                AT WHICH THE SPARSITY
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--SF     = THE SINGLE PRECISION
!                                SPARSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION SPARSITY
!             FUNCTION VALUE SF.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--P SHOULD BE BETWEEN 0.0 AND 1.0, EXCLUSIVELY.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--FILLIBEN, SIMPLE AND ROBUST LINEAR ESTIMATION
!                 OF THE LOCATION PARAMETER OF A SYMMETRIC
!                 DISTRIBUTION (UNPUBLISHED PH.D. DISSERTATION,
!                 PRINCETON UNIVERSITY), 1969, PAGES 21-44, 229-231.
!               --FILLIBEN, 'THE PERCENT POINT FUNCTION',
!                 (UNPUBLISHED MANUSCRIPT), 1970, PAGES 28-31.
!               --JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 1970, PAGES 1-21.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-921-2315
!     ORIGINAL VERSION--APRIL     1994.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(P.LE.0.0.OR.P.GE.1.0)GO TO 50
      GO TO 90
   50 CONTINUE
      WRITE(ICOUT,1)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,2)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,46)P
      CALL DPWRST('XXX','BUG ')
      RETURN
   90 CONTINUE
    1 FORMAT(   &
      '***** FATAL ERROR--THE FIRST  INPUT ARGUMENT TO THE LOGSF')
    2 FORMAT(   &
      'SUBROUTINE IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL *****')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
!
!-----START POINT-----------------------------------------------------
!
      SF=1.0/(P-P*P)
!
      RETURN
      END SUBROUTINE LOGSF
      SUBROUTINE LOSCDF(X,P,IR,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE AT THE SINGLE PRECISION VALUE X
!              FOR THE LOST GAMES DISTRIBUTION
!              WITH SINGLE PRECISION SHAPE PARAMETERS P AND
!              IR.  THIS DISTRIBUTION IS DEFINED FOR ALL
!              NON-NEGATIVE INTEGER X >= IR.
!              THIS DISTRIBUTION HAS THE PROBABILITY MASS FUNCTION
!              p(X;P,IR) = (2*X-IR  X)*(1-P)**(X-IR)*(P)**X
!                          *(IR/(2*X-IR))   X = IR, IR+ 1, ...
!                                  (X*(X-K)!)
!              THIS DISTRIBUTION IS USED TO MODEL THE "GAMBLER'S
!              RUIN" PROBLEM.  IT CAN ALSO BE USED TO MODEL A
!              QUEUE WHERE THE QUEUE FOLLOWS A HOMOGENEOUS POISSON
!              PROCESS WITH PARAMETER LAMBDA, THE SERVICE TIME IS
!              EXPONENTIAL WITH PARAMETER MU < LAMBDA, AND THERE
!              ARE R INITIAL CUSTOMERS.  THE LOST GAMES DISTRIBUTION
!              IS THEN THE DISTRIBUTION OF THE NUMBER OF CUSTOMERS
!              SERVED UNTIL THE QUEUE FIRST VANISHES WITH
!              P = LAMBDA/(LAMBDA+MU).
!
!              NOTE THAT WE ARE USING DEVROYE'S FORMULATION OF
!              THE PDF.  HOWEVER, WE USE P > 0.5 (I.E., THE
!              PROBABILITY THAT THE GAMBLER LOSES ON A GIVEN
!              HAND) WHEREAS DEVROYE USES P < 0.5 = PROBABILITY
!              GAMBLER WINS ON A GIVEN HAND.
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE AN INTEGR >= IR.
!                     --P      = THE SINGLE PRECISION VALUE
!                                OF THE FIRST SHAPE PARAMETER.
!                     --IR     = THE SINGLE PRECISION VALUE
!                                OF THE SECOND SHAPE PARAMETER.
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE LOST GAMES DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE AN INTEGER >= IR
!                 --0.5 < P < 1,  AND IR >= 1
!     OTHER DATAPAC   SUBROUTINES NEEDED--DLNGAM.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DEXP, DLOG
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND KEMP (1992).  "UNIVARIATE
!                 DISCRETE DISTRIBUTIONS", SECOND EDITION,
!                 WILEY, PP. 445-447.
!               --LUC DEVROYE (1986), "NON-UNIFORM RANDOM VARIATE
!                 GENERATION", SPRINGER-VERLANG, PP. 758-759.
!               --KEMP AND KEMP (1968), "ON A DISTRIBUTION ASSOCIATED
!                 WITH CERTAIN STOCHASTIC PROCESSES", JOURNAL OF
!                 THE ROYAL STATISTICAL SOCIETY, SERIES B, 30,
!                 PP. 401-410.
!               --HAIGHT (1961), "A DISTRIBUTION ANALOGOUS TO THE
!                 BOREL-TANNER", BIOMETRIKA, 48, PP. 167-173.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/6
!     ORIGINAL VERSION--JUNE      2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DP
      DOUBLE PRECISION DR
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DPDFSV
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DC1
      DOUBLE PRECISION DC2
      DOUBLE PRECISION DC3
!CCCC DOUBLE PRECISION DTERM1
!CCCC DOUBLE PRECISION DTERM2
!CCCC DOUBLE PRECISION DTERM3
!CCCC DOUBLE PRECISION DLNGAM
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      CDF=0.0
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(P.LE.0.5 .OR. P.GE.1.0)THEN
        WRITE(ICOUT,11)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9999
      ENDIF
   11 FORMAT('***** ERROR--THE SECOND ARGUMENT TO LOSCDF ',   &
      ' IS OUTSIDE THE ALLOWABLE (0.5,1) INTERVAL')
!
      IF(IR.LT.0)THEN
        WRITE(ICOUT,12)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)IR
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9999
      ENDIF
   12 FORMAT('***** ERROR--THE THIRD ARGUMENT TO LOSCDF IS ',   &
      ' NEGATIVE')
      INTX=INT(X+0.5)
      IF(INTX.LT.IR)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)INTX
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,48)INTX
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9999
      ENDIF
    5 FORMAT('***** ERROR--THE FIRST ARGUMENT TO LOSCDF IS LESS ',   &
      'THAN THE THIRD ARUGMENT')
!
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
   48 FORMAT('***** THE VALUE OF THE THIRD ARGUMENT IS ',I8)
!
      DP=DBLE(P)
      DR=DBLE(IR)
      DCDF=0.0D0
!
!CCCC DO100I=INTX,IR,-1
!CCCC   DX=DBLE(I)
!CCCC   DTERM1=DLNGAM(2.0D0*DX-DR+1) - DLNGAM(DX+1.0D0) -
!CCCC1         DLNGAM(DX-DR+1.0D0)
!CCCC   DTERM2=(DX-DR)*DLOG(1.0D0-DP) + DX*DLOG(DP)
!CCCC   DTERM3=DLOG(DR) - DLOG(2.0D0*DX - DR)
!CCCC   DPDF=DEXP(DTERM1 + DTERM2 + DTERM3)
!CCCC   DCDF=DCDF+DPDF
!C100 CONTINUE
!
!CCCC CDF=REAL(DCDF)
!
!     USE THE RECURRENCE RELATION (FROM KEMP AND KEMP):
!
!     P(X;P,R) = C*P(X-1;P,R)
!
!     WHERE
!
!        C = (2*X-R-1)*(2*X-R-2)*P*(1-P)/[X*(X-R)]
!
      DC1=DLOG(DP) + DLOG(1.0D0 - DP)
      DPDF=DR*DLOG(DP)
      DPDFSV=DPDF
      DCDF=DEXP(DPDF)
!
      IF(INTX.GT.IR)THEN
        DO 200 I=IR+1,INTX
          DX=DBLE(I)
          DC2=DLOG(2.0D0*DX-DR-1.0D0) + DLOG(2.0D0*DX-DR-2.0D0)
          DC3=DLOG(DX) + DLOG(DX-DR)
          DPDF=DC2 - DC3 + DC1 + DPDFSV
          DCDF=DCDF + DEXP(DPDF)
          DPDFSV=DPDF
  200   CONTINUE
      ENDIF
!
      CDF=REAL(DCDF)
!
 9999 CONTINUE
                                                                                                                                  
      RETURN
      END SUBROUTINE LOSCDF
      SUBROUTINE LOSPDF(X,P,IR,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY MASS
!              FUNCTION VALUE AT THE SINGLE PRECISION VALUE X
!              FOR THE LOST GAMES DISTRIBUTION
!              WITH SINGLE PRECISION SHAPE PARAMETERS P AND
!              IR.  THIS DISTRIBUTION IS DEFINED FOR ALL
!              NON-NEGATIVE INTEGER X >= IR.
!              THIS DISTRIBUTION HAS THE PROBABILITY FUNCTION
!              p(X;P,IR) = (2*X-IR  X)*(1-P)**(X-IR)*(P)**X
!                          *(IR/(2*X-IR))   X = IR, IR+ 1, ...
!                                  (X*(X-K)!)
!              THIS DISTRIBUTION IS USED TO MODEL THE "GAMBLER'S
!              RUIN" PROBLEM.  IT CAN ALSO BE USED TO MODEL A
!              QUEUE WHERE THE QUEUE FOLLOWS A HOMOGENEOUS POISSON
!              PROCESS WITH PARAMETER LAMBDA, THE SERVICE TIME IS
!              EXPONENTIAL WITH PARAMETER MU < LAMBDA, AND THERE
!              ARE R INITIAL CUSTOMERS.  THE LOST GAMES DISTRIBUTION
!              IS THEN THE DISTRIBUTION OF THE NUMBER OF CUSTOMERS
!              SERVED UNTIL THE QUEUE FIRST VANISHES WITH
!              P = LAMBDA/(LAMBDA+MU).
!
!              NOTE THAT WE ARE USING DEVROYE'S FORMULATION OF
!              THE PDF.  HOWEVER, WE USE P > 0.5 (I.E., THE
!              PROBABILITY THAT THE GAMBLER LOSES ON A GIVEN
!              HAND) WHEREAS DEVROYE USES P < 0.5 = PROBABILITY
!              GAMBLER WINS ON A GIVEN HAND.
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE PROBABILITY MASS
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE AN INTEGR >= IR.
!                     --P      = THE SINGLE PRECISION VALUE
!                                OF THE FIRST SHAPE PARAMETER.
!                     --IR     = THE SINGLE PRECISION VALUE
!                                OF THE SECOND SHAPE PARAMETER.
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                MASS FUNCTION VALUE
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF
!             FOR THE LOST GAMES DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE A POSITIVE INTEGER
!                 --0.5 < P < 1,  AND IR >= 1
!     OTHER DATAPAC   SUBROUTINES NEEDED--DLNGAM.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DEXP, DLOG
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND KEMP (1992).  "UNIVARIATE
!                 DISCRETE DISTRIBUTIONS", SECOND EDITION,
!                 WILEY, PP. 445-447.
!               --LUC DEVROYE (1986), "NON-UNIFORM RANDOM VARIATE
!                 GENERATION", SPRINGER-VERLANG, PP. 758-759.
!               --KEMP AND KEMP (1968), "ON A DISTRIBUTION ASSOCIATED
!                 WITH CERTAIN STOCHASTIC PROCESSES", JOURNAL OF
!                 THE ROYAL STATISTICAL SOCIETY, SERIES B, 30,
!                 PP. 401-410.
!               --HAIGHT (1961), "A DISTRIBUTION ANALOGOUS TO THE
!                 BOREL-TANNER", BIOMETRIKA, 48, PP. 167-173.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/6
!     ORIGINAL VERSION--JUNE      2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DP
      DOUBLE PRECISION DR
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DLNGAM
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      PDF=0.0
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(P.LE.0.5 .OR. P.GE.1.0)THEN
        WRITE(ICOUT,11)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ENDIF
   11 FORMAT('***** ERROR--THE SECOND ARGUMENT TO LOSPDF ',   &
      ' IS OUTSIDE THE ALLOWABLE (0.5,1) INTERVAL')
!
      IF(IR.LT.0)THEN
        WRITE(ICOUT,12)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)IR
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ENDIF
   12 FORMAT('***** ERROR--THE THIRD ARGUMENT TO LOSPDF IS ',   &
      ' NON-POSITIVE')
      INTX=INT(X+0.5)
      IF(INTX.LT.IR)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)INTX
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,48)INTX
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ENDIF
    5 FORMAT('***** ERROR--THE FIRST ARGUMENT TO LOSPDF IS LESS ',   &
      'THAN THE THIRD ARUGMENT')
!
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
   48 FORMAT('***** THE VALUE OF THE THIRD ARGUMENT IS ',I8)
!
      DX=DBLE(INTX)
      DP=DBLE(P)
      DR=DBLE(IR)
!
      DTERM1=DLNGAM(2.0D0*DX-DR+1) - DLNGAM(DX+1.0D0) -   &
             DLNGAM(DX-DR+1.0D0)
      DTERM2=(DX-DR)*DLOG(1.0D0-DP) + DX*DLOG(DP)
      DTERM3=DLOG(DR) - DLOG(2.0D0*DX - DR)
      DPDF=DEXP(DTERM1 + DTERM2 + DTERM3)
!
      PDF=REAL(DPDF)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE LOSPDF
      SUBROUTINE LOSPPF(P,PPAR,IR,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE AT THE SINGLE PRECISION VALUE P
!              FOR THE LOST GAMES DISTRIBUTION
!              WITH SINGLE PRECISION SHAPE PARAMETERS PPAR AND
!              IR.  THIS DISTRIBUTION IS DEFINED FOR ALL
!              NON-NEGATIVE INTEGER X >= IR.
!              THIS DISTRIBUTION HAS THE PROBABILITY MASS FUNCTION
!              p(X;P,IR) = (2*X-IR  X)*(1-P)**(X-IR)*(P)**X
!                          *(IR/(2*X-IR))   X = IR, IR+ 1, ...
!                                  (X*(X-K)!)
!              THIS DISTRIBUTION IS USED TO MODEL THE "GAMBLER'S
!              RUIN" PROBLEM.  IT CAN ALSO BE USED TO MODEL A
!              QUEUE WHERE THE QUEUE FOLLOWS A HOMOGENEOUS POISSON
!              PROCESS WITH PARAMETER LAMBDA, THE SERVICE TIME IS
!              EXPONENTIAL WITH PARAMETER MU < LAMBDA, AND THERE
!              ARE R INITIAL CUSTOMERS.  THE LOST GAMES DISTRIBUTION
!              IS THEN THE DISTRIBUTION OF THE NUMBER OF CUSTOMERS
!              SERVED UNTIL THE QUEUE FIRST VANISHES WITH
!              P = LAMBDA/(LAMBDA+MU).
!
!              NOTE THAT WE ARE USING DEVROYE'S FORMULATION OF
!              THE PDF.  HOWEVER, WE USE P > 0.5 (I.E., THE
!              PROBABILITY THAT THE GAMBLER LOSES ON A GIVEN
!              HAND) WHEREAS DEVROYE USES P < 0.5 = PROBABILITY
!              GAMBLER WINS ON A GIVEN HAND.
!
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                                0 <= P <= 1.
!                     --PPAR   = THE SINGLE PRECISION VALUE
!                                OF THE FIRST SHAPE PARAMETER.
!                     --IR     = THE SINGLE PRECISION VALUE
!                                OF THE SECOND SHAPE PARAMETER.
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION PERCENT POINT
!                                FUNCTION VALUE
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT
!             FUNCTION VALUE PPF FOR THE LOST GAMES DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--0 <= P <= 1
!                 --0.5 < P < 1,  AND IR >= 0
!     OTHER DATAPAC   SUBROUTINES NEEDED--DLNGAM.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DEXP, DLOG
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND KEMP (1992).  "UNIVARIATE
!                 DISCRETE DISTRIBUTIONS", SECOND EDITION,
!                 WILEY, PP. 445-447.
!               --LUC DEVROYE (1986), "NON-UNIFORM RANDOM VARIATE
!                 GENERATION", SPRINGER-VERLANG, PP. 758-759.
!               --KEMP AND KEMP (1968), "ON A DISTRIBUTION ASSOCIATED
!                 WITH CERTAIN STOCHASTIC PROCESSES", JOURNAL OF
!                 THE ROYAL STATISTICAL SOCIETY, SERIES B, 30,
!                 PP. 401-410.
!               --HAIGHT (1961), "A DISTRIBUTION ANALOGOUS TO THE
!                 BOREL-TANNER", BIOMETRIKA, 48, PP. 167-173.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/6
!     ORIGINAL VERSION--JUNE      2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DP
      DOUBLE PRECISION DPPAR
      DOUBLE PRECISION DR
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DPDFSV
      DOUBLE PRECISION DCDF
!CCCC DOUBLE PRECISION DTERM1
!CCCC DOUBLE PRECISION DTERM2
!CCCC DOUBLE PRECISION DTERM3
!CCCC DOUBLE PRECISION DLNGAM
      DOUBLE PRECISION DC1
      DOUBLE PRECISION DC2
      DOUBLE PRECISION DC3
      DOUBLE PRECISION DEPS
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      PPF=0.0
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(PPAR.LE.0.5 .OR. PPAR.GE.1.0)THEN
        WRITE(ICOUT,11)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9999
      ENDIF
   11 FORMAT('***** ERROR--THE SECOND ARGUMENT TO LOSPPF ',   &
      ' IS OUTSIDE THE ALLOWABLE (0.5,1) INTERVAL')
!
      IF(IR.LT.0)THEN
        WRITE(ICOUT,12)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)IR
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9999
      ENDIF
   12 FORMAT('***** ERROR--THE THIRD ARGUMENT TO LOSPPF IS ',   &
      ' NEGATIVE')
!
      IF(P.LT.0.0 .OR. P.GE.1.0)THEN
        WRITE(ICOUT,13)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9999
      ENDIF
   13 FORMAT('***** ERROR--THE FIRST ARGUMENT TO LOSPPF ',   &
      ' IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL')
!
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
!
!     USE THE RECURRENCE RELATION (FROM KEMP AND KEMP):
!
!     P(X;P,R) = C*P(X-1;P,R)
!
!     WHERE
!
!        C = (2*X-R-1)*(2*X-R-2)*P*(1-P)/[X*(X-R)]
!
      DEPS=1.0D-7
      DPPAR=DBLE(PPAR)
      DP=DBLE(P)
      DR=DBLE(IR)
      I=IR
      DPDFSV=DR*DLOG(DPPAR)
      DCDF=DEXP(DPDFSV)
      IF(DCDF.GE.DP-DEPS)THEN
        PPF=REAL(IR)
        GO TO 9999
      ENDIF
!
      DC1=DLOG(DPPAR) + DLOG(1.0D0 - DPPAR)
  100 CONTINUE
        I=I+1
        IF(DBLE(I).GE.DBLE(I1MACH(9)))THEN
          WRITE(ICOUT,55)
   55     FORMAT('***** ERROR--THE COMPUTED PERCENT POINT VALUE ',   &
                 'EXCEEDS THE LARGEST MACHINE INTEGER.')
          CALL DPWRST('XXX','BUG ')
          PPF=REAL(I)
          GO TO 9999
        ENDIF
        DX=DBLE(I)
!CCCC   DTERM1=DLNGAM(2.0D0*DX-DR+1) - DLNGAM(DX+1.0D0) -
!CCCC1         DLNGAM(DX-DR+1.0D0)
!CCCC   DTERM2=(DX-DR)*DLOG(1.0D0-DPPAR) + DX*DLOG(DPPAR)
!CCCC   DTERM3=DLOG(DR) - DLOG(2.0D0*DX - DR)
!CCCC   DPDF=DEXP(DTERM1 + DTERM2 + DTERM3)
!CCCC   DCDF=DCDF+DPDF
        DC2=DLOG(2.0D0*DX-DR-1.0D0) + DLOG(2.0D0*DX-DR-2.0D0)
        DC3=DLOG(DX) + DLOG(DX-DR)
        DPDF=DC2 - DC3 + DC1 + DPDFSV
        DCDF=DCDF + DEXP(DPDF)
        DPDFSV=DPDF
        IF(DCDF.GE.DP-DEPS)THEN
          PPF=REAL(I)
          GO TO 9999
        ENDIF
      GO TO 100
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE LOSPPF
      SUBROUTINE LOSRAN(N,P,IR,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE LOST GAMES DISTRIBUTION
!              WITH SHAPE PARAMETERS P AND IR.
!              IR.  THIS DISTRIBUTION IS DEFINED FOR ALL
!              NON-NEGATIVE INTEGER X >= IR.
!              THIS DISTRIBUTION HAS THE PROBABILITY FUNCTION
!              p(X;P,IR) = (2*X-IR  X)*(1-P)**(X-IR)*(P)**X
!                          *(IR/(2*X-IR))   X = IR, IR+ 1, ...
!                                  (X*(X-K)!)
!              THIS DISTRIBUTION IS USED TO MODEL THE "GAMBLER'S
!              RUIN" PROBLEM.  IT CAN ALSO BE USED TO MODEL A
!              QUEUE WHERE THE QUEUE FOLLOWS A HOMOGENEOUS POISSON
!              PROCESS WITH PARAMETER LAMBDA, THE SERVICE TIME IS
!              EXPONENTIAL WITH PARAMETER MU < LAMBDA, AND THERE
!              ARE R INITIAL CUSTOMERS.  THE LOST GAMES DISTRIBUTION
!              IS THEN THE DISTRIBUTION OF THE NUMBER OF CUSTOMERS
!              SERVED UNTIL THE QUEUE FIRST VANISHES WITH
!              P = LAMBDA/(LAMBDA+MU).
!
!              NOTE THAT WE ARE USING DEVROYE'S FORMULATION OF
!              THE PDF.  HOWEVER, WE USE P > 0.5 (I.E., THE
!              PROBABILITY THAT THE GAMBLER LOSES ON A GIVEN
!              HAND) WHEREAS DEVROYE USES P < 0.5 = PROBABILITY
!              GAMBLER WINS ON A GIVEN HAND.
!
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --P      = THE SINGLE PRECISION VALUE
!                                OF THE FIRST SHAPE PARAMETER.
!                     --IR     = THE SINGLE PRECISION VALUE
!                                OF THE SECOND SHAPE PARAMETER.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N FROM THE LOST GAMES
!             DISTRIBUTION WITH SHAPE PARAMETERS P AND IR.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --0 < P < 1, IR A NON-NEGATIVE INTEGER
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN, LOSPPF
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND KEMP (1992).  "UNIVARIATE
!                 DISCRETE DISTRIBUTIONS", SECOND EDITION,
!                 WILEY, PP. 445-447.
!               --LUC DEVROYE (1986), "NON-UNIFORM RANDOM VARIATE
!                 GENERATION", SPRINGER-VERLANG, PP. 758-759.
!               --KEMP AND KEMP (1968), "ON A DISTRIBUTION ASSOCIATED
!                 WITH CERTAIN STOCHASTIC PROCESSES", JOURNAL OF
!                 THE ROYAL STATISTICAL SOCIETY, SERIES B, 30,
!                 PP. 401-410.
!               --HAIGHT (1961), "A DISTRIBUTION ANALOGOUS TO THE
!                 BOREL-TANNER", BIOMETRIKA, 48, PP. 167-173.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/6
!     ORIGINAL VERSION--JUNE      2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      INTEGER N
      INTEGER IR
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
    5 FORMAT('***** ERROR--THE REQUESTED NUMBER OF ',   &
      'LOST GAMES RANDOM NUMBERS IS NON-POSITIVE')
!
      IF(P.LE.0.5 .OR. P.GE.1.0)THEN
        WRITE(ICOUT,11)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,12)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ENDIF
   11 FORMAT('***** ERROR--THE P PARAMETER FOR THE LOST GAMES')
   12 FORMAT('      RANDOM NUMBERS IS OUTSIDE THE ALLOWABLE (0.5,1) ',   &
             'INTERVAL')
!
      IF(IR.LT.0)THEN
        WRITE(ICOUT,21)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)IR
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ENDIF
   21 FORMAT('***** ERROR--THE R PARAMETER FOR THE LOST GAMES ',   &
             'RANDOM NUMBERS IS NON-POSITIVE')
!
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
!
      CALL UNIRAN(N,ISEED,X)
      DO 100 I=1,N
        XTEMP=X(I)
        CALL LOSPPF(XTEMP,P,IR,PPF)
        X(I)=PPF
  100 CONTINUE
!
 9999 CONTINUE
!
      RETURN
      END SUBROUTINE LOSRAN
      SUBROUTINE LOLIP (NXG,XG,NYG,YG,NPI,XI,YI,NP,MP,MPM,NMAX,D)
!
!     THIS SUBROUTINE DETERMINES THE LOCAL INTERPOLATION POINTS FOR THE
!     GRID VERSION OF FRANKE'S METHOD OF SURFACE INTERPOLATION.
!     MINPTS POINTS ARE REQUIRED FOR EACH REGION.
!     IF FEWER THAN MINPTS POINTS ARE FOUND IN THE REGION, THE NEXT
!     CLOSEST POINTS (IN THE SUP NORM AFTER THE CURRENT RECTANGLE IS
!     TRANSFORMED ONTO (0,1)) ARE USED.  MINPTS IS SET TO 3, WHICH IS
!     THE RECOMMENDED VALUE, ALTHOUGH IT MAY BE ALTERED.
!
!     THE ARGUMENTS ARE AS FOLLOWS.
!
!        NXG  - INPUT.  NUMBER OF VERTICAL GRID LINES.
!        XG   - INPUT.  THE COORDINATES OF THE VERTICAL GRID LINES, IN
!                       INCREASING ORDER
!        NYG  - INPUT.  NUMBER OF HORIZONTAL GRID LINES.
!        YG   - INPUT.  THE COORDINATES OF THE HORIZONTAL GRID LINES,
!                       IN INCREASING ORDER.
!        NPI  - INPUT.  THE NUMBER OF DATA POINTS.
!        XI   - \
!        YI   - INPUT.  THE DATA POINTS (XI,YI), I=1,...,NPI.
!        FI   - /
!        NP   - OUTPUT.  AN ARRAY WHICH GIVES THE INITIAL SUBSCRIPT IN
!                       THE ARRAY MP AT WHICH THE SUBSCRIPTS FOR THE
!                       LOCAL INTERPOLATION POINTS ARE STORED.
!        MP   - OUTPUT.  AN ARRAY WHICH GIVES THE SUBSCRIPTS FOR THE
!                       LOCAL INTERPOLATION POINTS.
!        MPM  - INPUT.  DIMENSION OF THE ARRAY MP IN THE CALLING PROGRAM
!        NMAX - OUTPUT.  THE MAXIMUM NUMBER OF INTERPOLATION POINTS
!                        OVER ALL THE REGIONS.
!        D    - A WORK ARRAY OF DIMENSION AT LEAST NPI.
!
      DIMENSION XG(*), YG(*), XI(*), YI(*), NP(*), MP(*), D(*)
      DATA MINPTS/3/
      IJ = 1
      NP(1) = 1
      NMAX = 0
      L = 0
!
      DO 200 J=1,NYG
        YGA = (YG(J+2)+YG(J))/2.
        DYG = YG(J+2)-YG(J)
!
        DO 180 I=1,NXG
          XGA = (XG(I+2)+XG(I))/2.
          DXG = XG(I+2)-XG(I)
          IJ = IJ+1
!
!         DETERMINE THE POINTS IN THE (I,J)TH RECTANGLE.
!
          DO 120 NK=1,NPI
            D(NK) = AMAX1(ABS(XI(NK) - XGA)/DXG,ABS(YI(NK) - YGA)/DYG)
            IF(D(NK).GT..6125)GO TO 120
            D(NK) = 1.E10
            L = L + 1
            LL = MIN0(L,MPM)
            MP(LL) = NK
  120     CONTINUE
!
          NP(IJ) = L+1
          IF (NP(IJ)-NP(IJ-1).GE.MINPTS) GO TO 180
!
!         ADD THE CLOSEST POINTS IF THERE ARE LESS THAN MINPTS IN THE
!         RECTANGLE.
!
          LM = MINPTS-(NP(IJ)-NP(IJ-1))
!
          DO 160 II=1,LM
            L = L+1
            LL = MIN0(L,MPM)
            MP(LL) = 1
            DM = D(1)
!
            DO 140 NK=2,NPI
              IF (D(NK).GE.DM) GO TO 140
              DM = D(NK)
              MP(LL) = NK
  140       CONTINUE
!
            NK = MP(LL)
            D(NK) = 1.E10
  160     CONTINUE
!
          NP(IJ) = L+1
          NMAX = MAX0(NMAX,NP(IJ)-NP(IJ-1))
!
  180   CONTINUE
  200 CONTINUE
!
      RETURN
      END SUBROUTINE LOLIP 
      SUBROUTINE LOTPS (MODE,NPPR,NPI,XI,YI,FI,NXO,XO,NYO,YO,IWK,NIWK,   &
                        NIWKU,WK,NWK,NWKU,FO,KER)
!***START PROLOGUE LOTPS
!
!     THIS VERSION IS DATED 03/04/82.
!
!                RICHARD FRANKE
!                DEPARTMENT OF MATHEMATICS
!                NAVAL POSTGRADUATE SCHOOL
!                MONTEREY, CALIFORNIA  93940
!                     (408)646-2758 / 2206
!
!
!
!     REFERENCE
!        SMOOTH INTERPOLATION OF SCATTERED DATA BY LOCAL THIN
!        PLATE SPLINES, COMPUTERS AND MATHEMATICS WITH
!        APPLICATIONS 8(1982)???-???+8
!                    OR
!        NAVAL POSTGRADUATE SCHOOL TR#NPS-53-81-002, 1981
!        (AVAILABLE FROM NTIS, AD-A098 232/2)
!
!     ABSTRACT
!        SUBROUTINE LOTPS SERVES AS THE USER INTERFACE FOR A SET OF
!        SUBROUTINES WHICH SOLVE THE SCATTERED DATA INTERPOLATION
!        PROBLEM.  A SMOOTH FUNCTION PASSING THROUGH THE GIVEN POINTS
!        (XI(K),YI(K),FI(K)),K=1,...,NPI IS CONSTRUCTED.
!        THE RESULT RETURNED IS AN ARRAY OF VALUES, FO(I,J), OF THE INT-
!        ERPOLATION FUNCTION AT GRID POINTS, (XO(I),YO(J)),I=1,...,NXO,
!        J=1,...,NYO.
!        THE METHOD USED INVOLVES CONSTRUCTION OF LOCALLY DEFINED 'THIN
!        PLATE SPLINES', WHICH ARE THEN BLENDED TOGETHER SMOOTHLY
!        THROUGH THE USE OF A PARTITION OF UNITY DEFINED ON A
!        RECTANGULAR GRID ON THE PLANE.  THE FUNCTIONS IN THE PARTITION
!        OF UNITY ARE UNIVARIATE PIECEWISE HERMITE CUBIC POLYNOMIALS.
!
!     CAUTIONS
!        THE USER SHOULD BE AWARE THAT FOR SOME DATA THE INTERPOLATION
!        FUNCTION MAY BE ILL-BEHAVED.  SOME INVESTIGATION OF ITS
!        BEHAVIOR FOR THE TYPE OF DATA TO BE INPUT SHOULD BE UNDERTAKEN
!        BEFORE IMBEDDING ANY SCHEME FOR SCATTERED DATA INTERPOLATION
!        INTO ANOTHER PROGRAM.
!
!     DESCRIPTION OF ARGUMENTS
!
!        MODE - INPUT.  INDICATES THE STATUS OF THE CALCULATION.
!                 = 1,  SET UP THE PROBLEM.  COMPUTE THE COEFFICIENTS
!                       FOR THE LOCAL APPROXIMATIONS BY THIN PLATE
!                       SPLINES, AND RETURN THE GRID OF INTERPOLATED
!                       FUNCTION VALUES INDICATED BY NXO, XO, NYO, YO
!                       IN THE ARRAY FO.
!                 = 2,  THIS MODE VALUE IS A CONVENIENCE FOR USERS WHO
!                       WISH TO CALL THE ROUTINE TO EVALUATE THE
!                       SURFACE REPEATEDLY ON DIFFERENT GRIDS OF
!                       POINTS.  A CALL TO LOTPS WITH MODE = 1 HAS
!                       BEEN MADE PREVIOUSLY, NOW CALCULATE
!                       THE GRID OF INTERPOLATED POINTS INDICATED
!                       BY NXO, XO, NYO, YO IN IN THE ARRAY FO.  THE
!                       PROGRAM ASSUMES THAT THE ARRAYS XI, YI, IWK,
!                       AND WK ARE UNCHANGED FROM THE PREVIOUS CALL.
!        NPPR - INPUT.  DESIRED AVERAGE NUMBER OF POINTS PER REGION.
!                       THE SUGGESTED VALUE FOR THE NOVICE USER IS TEN,
!                       WHICH USUALLY GIVES GOOD RESULTS.  THIS PAR-
!                       AMETER HAS TO DO WITH THE LOCAL PROPERTY OF THE
!                       SURFACE.  THE INFLUENCE REGION OF A POINT HAS
!                       AREA WHICH IS ROUGHLY PROPORTIONAL TO NPPR.
!                       UNDER CERTAIN CONDITIONS, SUCH AS TO PRESERVE
!                       ROTATIONAL INVARIANCE, OR TO FORCE CERTAIN
!                       SETS OF POINTS TO BELONG TO THE SAME REGION,
!                       THE USER MAY SPECIFY HIS OWN GRID LINES.
!                       IF THE USER WISHES TO SPECIFY HIS OWN GRID LINES
!                       X TILDA AND Y TILDA, HE MAY DO SO BY SETTING
!                       NPPR = 0 AND SETTING NECESSARY VALUES IN THE
!                       ARRAYS IWK AND WK, AS NOTED BELOW.  DATA WHICH
!                       HAS A POOR DISTRIBUTION OVER THE REGION OF INT-
!                       EREST SHOULD PROBABLY HAVE THE GRID SPECIFIED.
!                       THIS IS ALSO ADVISABLE IF THE X-Y POINTS OCCUR
!                       ALONG LINES.  SEE THE REFERENCE FOR ADDITIONAL
!                       DETAILS.
!        NPI  - INPUT.  NUMBER OF INPUT DATA POINTS.
!        XI   - \
!        YI   - INPUT ARRAYS.  THE DATA POINTS (XI,YI,FI), I=1,...,NPI.
!        FI   - /
!        NXO  - INPUT.  THE NUMBER OF XO VALUES AT WHICH THE INTERP-
!                       OLATION FUNCTION IS TO BE CALCULATED.
!        XO   - INPUT ARRAY.  THE VALUES OF X AT WHICH THE INTERPOLATION
!                       FUNCTION IS TO BE CALCULATED.  THESE SHOULD
!                       BE IN INCREASING ORDER FOR MOST EFFICIENT
!                       EVALUATION, HOWEVER, THEY ONLY NEED TO BE
!                       MONOTONIC.
!        NYO  - INPUT.  THE NUMBER OF YO VALUES AT WHICH THE INTERP-
!                       OLATION FUNCTION IS TO BE CALCULATED.
!        YO   - INPUT ARRAY.  THE VALUES OF Y AT WHICH THE INTERPOLATION
!                       FUNCTION IS TO BE CALCULATED.  THESE SHOULD
!                       BE IN INCREASING ORDER FOR MOST EFFICIENT
!                       EVALUATION, HOWEVER, THEY ONLY NEED TO BE
!                       MONOTONIC.
!        IWK  - INPUT/OUTPUT ARRAY.  THIS ARRAY IS OUTPUT WHEN MODE = 1
!                       AND IS INPUT WHEN MODE = 2.  THIS MUST BE
!                       AN ARRAY DIMENSIONED APPROXIMATELY 7*NPI.  THE
!                       EXACT DIMENSION IS NOT KNOWN A PRIORI, BUT
!                       WILL BE RETURNED AS THE VALUE OF NIWKU.
!                       WHEN NPPR IS INPUT AS ZERO THE USER MUST
!                       SPECIFY THE NUMBER OF VERTICAL GRID LINES (THE
!                       NUMBER OF X TILDA VALUES) IN IWK(1) AND THE
!                       NUMBER OF HORIZONTAL GRID LINES (THE NUMBER OF
!                       Y TILDA VALUES) IN IWK(2).
!        NIWK - INPUT.  ON ENTRY WITH MODE = 1 THIS MUST BE SET TO THE
!                       DIMENSION OF THE ARRAY IWK IN THE CALLING
!                       PROGRAM.
!        NIWKU- OUTPUT.  THE ACTUAL NUMBER OF LOCATIONS NEEDED IN THE
!                       ARRAY IWK.
!        WK   - INPUT/OUTPUT ARRAY.  THIS ARRAY IS OUTPUT WHEN MODE = 1
!                       AND IS INPUT WHEN MODE = 2.  THIS MUST BE AN
!                       ARRAY DIMENSIONED APPROXIMATELY 7*NPI PLUS
!                       THE NUMBER NEEDED TO SET UP AND SOLVE THE SYSTEM
!                       OF EQUATIONS FOR THE LOCAL APPROXIMATIONS.  FOR
!                       NPPR NONZERO THIS WILL BE ABOUT 2.5*NPPR*NPPR
!                       PLUS 11*NPPR.  THE EXACT DIMENSION IS NOT KNOWN
!                       A PRIORI, BUT WILL BE RETURNED AS THE VALUE OF
!                       NWKU.
!                       WHEN NPPR IS INPUT AS ZERO THE USER MUST SPECIFY
!                       THE VALUES OF X TILDA AND Y TILDA AS FOLLOWS.
!                       WK(2), ... , WK(NXG+1) ARE THE NXG (= IWK(1))
!                       X GRID VALUES, X(I) TILDA, IN INCREASING ORDER.
!                       TYPICALLY WK(1) = MIN X(I), ALTHOUGH IT NEED
!                       NOT BE.  WK(1) MUST BE LESS THAN OR EQUAL TO
!                       WK(2), AND SHOULD BE LESS THAN OR EQUAL TO
!                       MIN X(I).  WK(NXG+2) IS USUALLY MAX X(I), AL-
!                       THOUGH IT NEED NOT BE.  WK(NXG+2) MUST BE
!                       GREATER THAN WK(NXG+1), AND SHOULD BE GREATER
!                       THAN OR EQUAL TO MAX X(I).
!                       THE VALUES OF WK(NXG+3), ... , WK(NXG+NYG+4)
!                       ARE THE Y GRID VALUES, Y(I) TILDA, AND MUST
!                       SATISFY DUAL CONDITIONS.
!        NWK  - INPUT.  ON ENTRY WITH MODE = 1 THIS MUST BE SET TO THE
!                       DIMENSION OF THE ARRAY WK IN THE CALLING
!                       PROGRAM.
!        NWKU - OUTPUT.  THE ACTUAL NUMBER OF LOCATIONS NEEDED IN THE
!                       ARRAY WK.
!        FO   - OUTPUT ARRAY.  VALUES OF THE INTERPOLATION FUNCTION AT
!                       THE GRID OF POINTS INDICATED BY NXO, XO, NYO, YO
!                       FO IS ASSUMED TO BE DIMENSIONED (NXO,NYO) IN THE
!                       CALLING PROGRAM.
!        KER  - OUTPUT.  RETURN INDICATOR.
!                 = 0,  NORMAL RETURN.
!                 = NONZERO, ERROR CONDITION ENCOUNTERED.
!
!     ERROR MESSAGES
!        NO. 1   FATAL         SINGULAR MATRIX IN THE CALCULATION OF
!                              LOCAL THIN PLATE SPLINES.  TRY LARGER
!                              VALUE FOR NPPR AND/OR MINPTS.  (MINPTS
!                              IS IN SUBROUTINE LOLIP.)
!        NO. 2   RECOVERABLE   FIRST CALL TO LOTPS MUST BE WITH MODE=1
!        NO. 3   FATAL         PREVIOUS ERROR RETURN FROM SUBROUTINE
!                              LOCAL NOT CORRECTED.
!        NO. 4   FATAL         ARRAY IWK AND/OR WK NOT DIMENSIONED LARGE
!                              ENOUGH.  REDIMENSION AS GIVEN BY NIWKU
!                              AND NWKU.
!        NO. 5   RECOVERABLE   MODE IS OUT OF RANGE.
!
!     SUBROUTINES USED
!
!        THIS PACKAGE:  LOGRD, LOLIP, LOCAL, LOEVL.
!        LINPACK: SGECO, SGESL
!        SLATEC:  SSORT, XERROR
!
!***END PROLOGUE
      DIMENSION XI(NPI), YI(NPI), FI(NPI), IWK(NIWK), WK(NWK),   &
       XO(NXO), YO(NYO), FO(NXO,NYO)
      DATA KERO/-1/
!
      IABWK=0
      IALWK=0
      MPWK=0
      NYGWK=0
!
      IF (MODE.LT.1.OR.MODE.GT.2) GO TO 220
      KER = 0
!
!     ON INITIAL ENTRY MODE = 1, THE GRID LINES ARE SET UP,
!     LOCAL INTERPOLATION POINTS ARE DETERMINED AND LOCAL APPROXIMATIONS
!     ARE COMPUTED.
!
      IF (MODE.EQ.2) GO TO 140
      NXGWK = 1
      NPWK = 3
      IF (NPPR.LE.0) GO TO 100
      NXG = INT(SQRT(4.*REAL(NPI)/REAL(NPPR))-.5)
      NXG = MAX0(NXG,1)
      NYG = NXG
      IWK(1) = NXG
      IWK(2) = NYG
      GO TO 120
  100 NXG = IWK(1)
      NYG = IWK(2)
  120 IALWK = NXG+NYG+5
      IABWK = IALWK + 3*NXG*NYG
      NYGWK = NXG+3
      MPWK = NXG*NYG+4
!
      IF(NPPR.LE.0)GO TO 130
      CALL LOGRD(XI,NPI,NXG,WK(NXGWK),WK(IALWK))
      CALL LOGRD(YI,NPI,NYG,WK(NYGWK),WK(IALWK))
  130 CONTINUE
!
!     DETERMINE THE LOCAL INTERPOLATION POINTS FOR THE REGIONS.
      MWK = NWK - MPWK + 1
      CALL LOLIP (NXG,WK(NXGWK),NYG,WK(NYGWK),NPI,XI,YI,IWK(NPWK),   &
      IWK(MPWK),MWK,NMAX,WK(IALWK))
      NCFM = IABWK +IWK(MPWK - 1)-1
      NWKU = NCFM + (NMAX+3)*(NMAX+5) - 1
      NIPVT = NXG*NYG+3+IWK(MPWK-1)
      NIWKU = NIPVT + NMAX + 2
      IF (NIWKU.GT.NIWK) GO TO 200
      IF (NWKU.GT.NWK) GO TO 200
!
!     COMPUTE THE LOCAL APPROXIMATIONS.
      CALL LOCAL (XI,YI,FI,NXG,WK(NXGWK),NYG,WK(NYGWK),IWK(NPWK),   &
       IWK(MPWK),WK(IALWK),WK(IABWK),WK(NCFM),IWK(NIPVT),IER)
      KERO = IER
      IF (IER.NE.0) GO TO 160
  140 IF (KERO.NE.0) GO TO 180
!
!     COMPUTE THE FUNCTION VALUES ON THE DESIRED GRID OF POINTS.
!
      CALL LOEVL (XI,YI,IWK(1),WK(NXGWK),IWK(2),WK(NYGWK),IWK(NPWK),   &
       IWK(MPWK),WK(IALWK),WK(IABWK),NXO,XO,NYO,YO,FO)
      RETURN
!
!     ERROR RETURNS
!
  160 KER = IER
!CCCC IF(IER.NE.0)CALL XERROR('LOTPS-SINGULAR MATRIX IN LOCAL; INCREAS
!CCCC1E NPPR OR SPECIFY OWN GRID LINES',71,1,2)
      RETURN
  180 KER = 3
      IF (KERO.LT.0) GO TO 190
!CCCC  CALL XERROR('LOTPS-PREVIOUS ERROR FROM SUBROUTINE LOCAL HAS NOT
!CCCC1BEEN CORRECTED.',65,3,2)
      RETURN
  190 KER = 2
!CCCC CALL XERROR('LOTPS-FIRST CALL TO LOTPS MUST BE WITH MODE = 1',
!CCCC1 47,2,1)
      RETURN
  200 KER = 4
!CCCC CALL XERROR('LOTPS-WORK ARRAYS IWK AND/OR WK NOT DIMENSIONED LAR
!CCCC1GE ENOUGH',60,4,2)
      RETURN
  220 KER = 5
!CCCC CALL XERROR('LOTPS-MODE IS OUT OF RANGE.  MUST BE 1 OR 2',43,5,
!CCCC1 1)
      RETURN
      END SUBROUTINE LOTPS 
      SUBROUTINE LOWESS(Y,X,N,ALOWFR,ALOWDG,   &
      XTEMP1,XTEMP2,YS,XS,WH,WV,XTEMP7,MAXNXT,   &
      PRED2,RES2,ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE PERFORMS A LOWESS FIT/SMOOTH
!              OF THE DATA IN Y AND X
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--88/2
!     ORIGINAL VERSION--FEBRUARY  1988.
!     UPDATED         --MAY       1989.  ERROR BRANCHES AFTER CALLS
!     UPDATED         --MARCH     1994.  SUPPORT QUADRATIC LOWESS FITS
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION X(*)
      DIMENSION XTEMP1(*)
      DIMENSION XTEMP2(*)
      DIMENSION YS(*)
      DIMENSION XS(*)
      DIMENSION WH(*)
      DIMENSION WV(*)
      DIMENSION XTEMP7(*)
      DIMENSION PRED2(*)
      DIMENSION RES2(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='LOWE'
      ISUBN2='SS  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'OFF'.AND.ISUBRO.NE.'WESS')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('**** AT THE BEGINNING OF LOWESS--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)ISUBRO,IBUGA3,IERROR
   52 FORMAT('ISUBRO,IBUGA3,IERROR = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,61)N,ALOWFR
   61 FORMAT('N,ALOWFR = ',I8,E15.7)
      CALL DPWRST('XXX','BUG ')
      IF(N.LE.0)GO TO 64
      DO 62 I=1,N
      WRITE(ICOUT,63)I,Y(I),X(I)
   63 FORMAT('I,Y(I),X(I) = ',I8,2E15.7)
      CALL DPWRST('XXX','BUG ')
   62 CONTINUE
   64 CONTINUE
   90 CONTINUE
!
!               ***********************************
!               **  STEP 11--                    **
!               **  SORT THE DATA                **
!               **  ACCORDING TO THE HORIZONTAL  **
!               **  AXIS VARIABLE.               **
!               **  RECORD THE ORDER OF THE      **
!               **  INCOMING DATA.               **
!               ***********************************
!
      ISTEPN='11'
      IF(IBUGA3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL SORTC(X,Y,N,XS,YS)
!
      DO 1100 I=1,N
      XTEMP1(I)=I
 1100 CONTINUE
      CALL SORTC(X,XTEMP1,N,XS,XTEMP7)
!
      AN=N
!
!               ***********************************************
!               **  STEP 12--                                **
!               **  COMPUTE THE TOTAL                        **
!               **  NUMBER OF NEIGHBORS IN  A NEIGHBORHOOD   **
!               ***********************************************
!
      ISTEPN='12'
      IF(IBUGA3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NN=INT(ALOWFR*AN+0.5)
      ANN=NN
!
!               ***********************************************
!               **  STEP 21--                                **
!               **  SET THE VERTICAL (ROBUSTNESS) WEIGHTS    **
!               **  EQUAL TO UNITY PRIOR TO COMPUTING        **
!               **  INITIAL PREDICTED VALUES                 **
!               ***********************************************
!
      ISTEPN='21'
      IF(IBUGA3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      DO 2100 I=1,N
      WV(I)=1.0
 2100 CONTINUE
!
!               ************************************************
!               **  STEP 22--                                 **
!               **  LOOP THROUGH EACH OF THE                  **
!               **  N HORIZONTAL DATA POINTS                  **
!               **  FROM SMALLEST TO LARGEST.                 **
!               **  FOR EACH DATA POINT--                     **
!               **     1) COMPUTE NEIGHBORHOOD LIMITS         **
!               **     2) COMPUTE HORIZONTAL WEIGHTS          **
!               **        FOR EACH NEIGHBORHOOD POINT         **
!               **     3) COMPUTE A INITIAL PREDICTED VALUE   **
!               **        FOR THAT POINT VIA A                **
!               **        WEIGHTED LINEAR FIT                 **
!               **        USING HORIZONTAL WEIGHTS ONLY.      **
!               ************************************************
!
      ISTEPN='22'
      IF(IBUGA3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      DO 2200 IT=1,N
!
      CALL NEIGH(IT,NN,XS,N,I1,I2,ISUBRO,IBUGA3,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      DEL1=XS(IT)-XS(I1)
      DEL2=XS(I2)-XS(IT)
      XMAXHF=DEL1
      IF(DEL2.GT.DEL1)XMAXHF=DEL2
      CALL WEIGHH(IT,I1,I2,XS,N,XMAXHF,   &
      WH,ISUBRO,IBUGA3,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      I3=IT
      I4=IT
!CCCC MARCH 1994.  ADD CHECK FOR QUADRATIC DEGREE.
      IF(ALOWDG.GT.1.5)THEN
      CALL QUAFIT(IT,I1,I2,XS,YS,WH,WV,N,XMAXHF,I3,I4,   &
      ALPHA,BETA1,BETA2,PRED2,RES2,ISUBRO,IBUGA3,IERROR)
      ELSE
      CALL LINEAR(IT,I1,I2,XS,YS,WH,WV,N,XMAXHF,I3,I4,   &
      ALPHA,BETA,PRED2,RES2,ISUBRO,IBUGA3,IERROR)
      ENDIF
      IF(IERROR.EQ.'YES')GO TO 9000
!
 2200 CONTINUE
!
!               *************************************************
!               **  STEP 31--                                  **
!               **  BASED ON THE INITIAL PREDICTED VALUES      **
!               **  AND THE CONSEQUENTIAL RESIDUALS,           **
!               **  COMPUTE VERTICAL (ROBUSTNESS) WEIGHTS      **
!               **  FOR ALL N DATA POINTS                      **
!               *************************************************
!
      ISTEPN='31'
      IF(IBUGA3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL WEIGHV(RES2,N,XTEMP1,XTEMP2,MAXNXT,   &
      WV,ISUBRO,IBUGA3,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
!               ************************************************
!               **  STEP 32--                                 **
!               **  AGAIN LOOP THROUGH EACH OF THE            **
!               **  N HORIZONTAL DATA POINTS                  **
!               **  FROM SMALLEST TO LARGEST.                 **
!               **  FOR EACH DATA POINT--                     **
!               **     1) COMPUTE NEIGHBORHOOD LIMITS         **
!               **     2) COMPUTE HORIZONTAL WEIGHTS          **
!               **        FOR EACH NEIGHBORHOOD POINT         **
!               **     3) COMPUTE A FINAL PREDICTED VALUE     **
!               **        FOR THAT POINT VIA A                **
!               **        WEIGHTED LINEAR FIT                 **
!               **        USING BOTH THE HORIZONTAL WEIGHTS   **
!               **        AND THE VERTICAL WEIGHTS            **
!               ************************************************
!
      ISTEPN='32'
      IF(IBUGA3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      DO 3200 IT=1,N
!
      CALL NEIGH(IT,NN,XS,N,I1,I2,ISUBRO,IBUGA3,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      DEL1=XS(IT)-XS(I1)
      DEL2=XS(I2)-XS(IT)
      XMAXHF=DEL1
      IF(DEL2.GT.DEL1)XMAXHF=DEL2
      CALL WEIGHH(IT,I1,I2,XS,N,XMAXHF,   &
      WH,ISUBRO,IBUGA3,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      I3=IT
      I4=IT
!CCCC MARCH 1994.  ADD CHECK FOR QUADRATIC DEGREE.
      IF(ALOWDG.GT.1.5)THEN
      CALL QUAFIT(IT,I1,I2,XS,YS,WH,WV,N,XMAXHF,I3,I4,   &
      ALPHA,BETA1,BETA2,PRED2,RES2,ISUBRO,IBUGA3,IERROR)
      ELSE
      CALL LINEAR(IT,I1,I2,XS,YS,WH,WV,N,XMAXHF,I3,I4,   &
      ALPHA,BETA,PRED2,RES2,ISUBRO,IBUGA3,IERROR)
      ENDIF
      IF(IERROR.EQ.'YES')GO TO 9000
!
 3200 CONTINUE
!
      DO 3300 I=1,N
      XTEMP1(I)=PRED2(I)
      XTEMP2(I)=RES2(I)
 3300 CONTINUE
!
      DO 3400 I=1,N
      J=INT(XTEMP7(I)+0.5)
      PRED2(J)=XTEMP1(I)
      RES2(J)=XTEMP2(I)
 3400 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'OFF'.AND.ISUBRO.NE.'WESS')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('**** AT THE END       OF LOWESS--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)ISUBRO,IBUGA3,IERROR
 9012 FORMAT('ISUBRO,IBUGA3,IERROR = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9021)N,ALOWFR,NN
 9021 FORMAT('N,ALOWFR,NN = ',I8,E15.7,I8)
      CALL DPWRST('XXX','BUG ')
      IF(N.LE.0)GO TO 9024
      DO 9022 I=1,N
      WRITE(ICOUT,9023)I,Y(I),X(I),PRED2(I),RES2(I)
 9023 FORMAT('I,Y(I),X(I),PRED2(I),RES2(I) = ',I8,4E11.3)
      CALL DPWRST('XXX','BUG ')
 9022 CONTINUE
 9024 CONTINUE
      IF(N.LE.0)GO TO 9034
      DO 9032 I=1,N
      WRITE(ICOUT,9033)I,YS(I),XS(I),WH(I),WV(I),PRED2(I),RES2(I)
 9033 FORMAT('I,YS(I),XS(I),WH(I),WV(I),PRED2(I),RES2(I) = ',   &
      I8,6E11.3)
      CALL DPWRST('XXX','BUG ')
 9032 CONTINUE
 9034 CONTINUE
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE LOWESS
      SUBROUTINE LOWHIN(X,N,IWRITE,XTEMP,MAXNXT,XLOWHI,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE
!              SAMPLE LOWER HINGE
!              OF THE DATA IN THE INPUT VECTOR X.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--XLOWHI = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SAMPLE LOWER HINGE.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE LOWER HINGE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--SORT.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82.6
!     ORIGINAL VERSION--JUNE      1981.
!     UPDATED         --AUGUST    1981.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION XTEMP(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='LOWH'
      ISUBN2='IN  '
      IERROR='NO'
!
      IARG1=0
      IARG2=0
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF LOWHIN--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,N
   52   FORMAT('IBUGA3,N = ',A4,2X,I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I)
   56     FORMAT('I,X(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ***************************
!               **  COMPUTE LOWER HINGE  **
!               ***************************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.LT.1 .OR. N.GT.MAXNXT)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN LOWER HINGE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE RESPONSE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)MAXNXT
  113   FORMAT('      VARIABLE IS LESS THAN 1 OR GREATER THAN ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE NUMBER OF OBSERVATIONS = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(N.EQ.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,121)
  121   FORMAT('***** WARNING IN LOWER HINGE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,123)
  123   FORMAT('      THERE IS ONLY A SINGLE RESPONSE VALUE.')
        CALL DPWRST('XXX','BUG ')
        XLOWHI=X(1)
        GO TO 9000
      ENDIF
!
      HOLD=X(1)
      DO 135 I=2,N
        IF(X(I).NE.HOLD)GO TO 139
  135 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,121)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,136)HOLD
  136 FORMAT('      THE RESPONSE VALUES ARE EQUAL TO ',G15.7)
      CALL DPWRST('XXX','BUG ')
      XLOWHI=HOLD
      GO TO 9000
  139 CONTINUE
!
!               ********************************
!               **  STEP 2--                  **
!               **  COMPUTE THE LOWER HINGE.  **
!               ********************************
!
      CALL SORT(X,N,XTEMP)
!
      N2=(N+1)/2
      IARG1=(N2+1)/2
      IARG2=(N2+1)-IARG1
      XLOWHI=(XTEMP(IARG1)+XTEMP(IARG2))/2.0
!
!               j******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,811)N,XLOWHI
  811   FORMAT('THE LOWER HINGE OF THE ',I8,' OBSERVATIONS = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF LOWHIN--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IERROR,IARG1,IARG2,XLOWHI
 9012   FORMAT('IERROR,IARG1,IARG2,XLOWHI = ',A4,2X,2I8,G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE LOWHIN
      SUBROUTINE LOWQUA(X,N,IWRITE,XTEMP,MAXNXT,XLOWQU,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE SAMPLE LOWER QUARTILE
!              OF THE DATA IN THE INPUT VECTOR X.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--XLOWQU = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SAMPLE LOWER QUARTILE.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE LOWER QUARTILE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--SORT.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!               EXCEPTION--HOLLERITH STRINGS IN FORMAT STATEMENTS
!                          DENOTED BY QUOTES RATHER THAN NH.
!     VERSION NUMBER--82.6
!     ORIGINAL VERSION--JUNE      1981.
!     UPDATED         --AUGUST    1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --OCTOBER   2008. WEIGHTING OF NEAREST TWO
!                                       POINTS WAS REVERSED
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION XTEMP(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='LOWQ'
      ISUBN2='UA  '
      IERROR='NO'
!
      NI=0
      NIP1=0
!
      ANI=0.0
      A2NI=0.0
      REM=0.0
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF LOWQUA--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)N,IBUGA3
   53   FORMAT('N,IBUGA3 = ',I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I)
   56     FORMAT('I,X(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ******************************
!               **  COMPUTE LOWER QUARTILE  **
!               ******************************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.LT.1 .OR. N.GT.MAXNXT)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN LOWER QUARTILE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE RESPONSE ',   &
               'VARIABLE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,115)MAXNXT
  115   FORMAT('      MUST BE BETWEEN 1 AND ',I8,' (INCLUSIVELY).')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE NUMBER OF OBSERVATIONS = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(N.EQ.1)THEN
!CCCC   WRITE(ICOUT,999)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,121)
!C121   FORMAT('***** WARNING IN LOWER QUARTILE--',
!CCCC1         'THERE IS ONLY ONE RESPONSE VALUE.')
!CCCC   CALL DPWRST('XXX','BUG ')
        XLOWQU=X(1)
        GO TO 9000
      ENDIF
!
      HOLD=X(1)
      DO 135 I=2,N
        IF(X(I).NE.HOLD)GO TO 139
  135 CONTINUE
!CCCC WRITE(ICOUT,999)
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,136)HOLD
!C136 FORMAT('***** WARNING IN LOWER QUARTILE--',
!CCCC1       'THE RESPONSE VARIABLE HAS ALL ELEMENTS = ',G15.7)
!CCCC CALL DPWRST('XXX','BUG ')
      XLOWQU=HOLD
      GO TO 9000
  139 CONTINUE
!
!               ***********************************
!               **  STEP 2--                     **
!               **  COMPUTE THE LOWER QUARTILE.  **
!               ***********************************
!
      CALL SORT(X,N,XTEMP)
!
      P=0.25
!
      ANI=P*(AN+1.0)
      NI=INT(ANI)
      A2NI=NI
      REM=ANI-A2NI
      NIP1=NI+1
      IF(NI.LE.1)NI=1
      IF(NI.GE.N)NI=N
      IF(NIP1.LE.1)NIP1=1
      IF(NIP1.GE.N)NIP1=N
!CCCC 10/20/2008: WEIGHTING IS BACKWARDS
!CCCC XLOWQU=REM*XTEMP(NI)+(1.0-REM)*XTEMP(NIP1)
      XLOWQU=(1.0-REM)*XTEMP(NI)+REM*XTEMP(NIP1)
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'ON' .AND.IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,811)N,XLOWQU
  811   FORMAT('THE LOWER QUARTILE OF THE ',I8,' OBSERVATIONS = ',   &
               G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF LOWQUA--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)ANI,NI,A2NI,REM,NIP1
 9014   FORMAT('ANI,NI,A2NI,REM,NIP1 = ',G15.7,I8,2G15.7,I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)IERROR,XLOWQU
 9015   FORMAT('IERROR,XLOWQU = ',A4,2X,G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE LOWQUA
      DOUBLE PRECISION FUNCTION LPLFUN (ALPHA,X)
!
!     PURPOSE--THIS ROUTINE IS USED IN FINDING THE Lp LOCATION
!              ESTIMATE.  THIS FUNCTION FINDS THE ROOT OF
!
!              SUM[i=1 to n][|X(i)-alpha|**(p-1)*SIGN(x(i)-ALPHA) = 0
!
!              CALLED BY DFZER2 ROUTINE FOR FINDING THE ROOT OF A
!              FUNCTION.
!     EXAMPLE--LET A = LP LOCATION Y
!     REFERENCES--FRANCESCA PENNECCHI AND LUCA CALLEGARO, "BETWEEN
!                 THE MEAN AND THE MEDIAN: THE Lp ESTIMATOR",
!                 METROLOGIA, 43, 2006, PP. 213-219.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2007/11
!     ORIGINAL VERSION--NOVEMBER   2007.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION ALPHA
      DOUBLE PRECISION X(*)
!
      INTEGER N
      DOUBLE PRECISION DP
      COMMON/LPLCOM/DP,N
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DSUM
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DX
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  COMPUTE SOME SUMS
!
      DSUM=0.0D0
      DO 100 I=1,N
        DX=X(I)
        DTERM1=DX-ALPHA
        IF(DTERM1.GE.0.0D0)THEN
          DFACT=1.0D0
        ELSE
          DFACT=-1.0D0
        ENDIF
        DSUM=DSUM + DFACT*DABS(DTERM1)**(DP-1.0D0)
  100 CONTINUE
!
      LPLFUN=DSUM
!
      RETURN
      END FUNCTION LPLFUN 
      SUBROUTINE LPLOC(X,N,P,IWRITE,XTEMP,DTEMP,MAXNXT,XLP,   &
                       IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE SAMPLE LP LOCATION
!              ESTIMATE OF THE DATA IN THE INPUT VECTOR X.
!
!              GIVEN THE MODEL
!
!                 X(i) = ALPHA + E(i)
!
!              THE L(p) ESTIMATOR OF ALPHA IS
!
!                 L(p)(X(i)) = Arg(alpha)
!                     MIN{(SUM[i=1 to n][|X(i) - ALPHA|**p)**(1/p)}
!
!              OR EQUIVALENTLY
!
!                 L(p)(X(i)) = Arg(alpha)
!                     MIN{SUM[i=1 to n][|X(i) - ALPHA|**p}
!
!              THIS ESTIMATE IS THE SOLUTION OF THE EQUATION
!
!              SUM[i=1 to n][|X(i)-alpha|**(p-1)*SIGN(x(i)-ALPHA) = 0
!
!              THERE ARE 3 SPECIAL CASES:
!
!               P = 1   - SAMPLE MEDIAN
!               P = 2   - SAMPLE MEAN
!               P = INF - SAMPLE MID-RANGE
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!                     --P      = THE SINGLE PRECISION VALUE OF THE
!                                "p" PARAMETER.
!     OUTPUT ARGUMENTS--XLP    = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SAMPLE LP LOCATION ESTIMATE.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE LP LOCATION ESTIMATE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--SORT.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--FRANCESCA PENNECCHI AND LUCA CALLEGARO, "BETWEEN
!                 THE MEAN AND THE MEDIAN: THE Lp ESTIMATOR",
!                 METROLOGIA, 43, 2006, PP. 213-219.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     ORIGINAL VERSION--NOVEMBER  2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION XTEMP(*)
      DOUBLE PRECISION DTEMP(*)
!
      DOUBLE PRECISION LPLFUN
      EXTERNAL LPLFUN
      DOUBLE PRECISION DP
      COMMON/LPLCOM/DP,IN
!
      DOUBLE PRECISION DXLOW
      DOUBLE PRECISION DXUP
      DOUBLE PRECISION DXSTRT
      DOUBLE PRECISION DAE
      DOUBLE PRECISION DRE
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='LPLO'
      ISUBN2='C   '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF LPLOC--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,N,P
   52   FORMAT('IBUGA3,N,P = ',A4,2X,I10,2X,G15.7)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,MIN(N,100)
          WRITE(ICOUT,56)I,X(I)
   56     FORMAT('I,X(I) = ',I8,E15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               **********************
!               **  COMPUTE LPLOC   **
!               **********************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.LT.1 .OR.N.GT.MAXNXT)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN LP LOCATION--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS IN THE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)
  113   FORMAT('      RESPONSE VARIABLE IS LESS THAN 1 OR GREATER')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,115)MAXNXT
  115   FORMAT('      THAN ',I10)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS = ',I10,'.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(P.LT.1.0)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,122)
  122   FORMAT('      THE P PARAMETER IS LESS THAN 1.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,127)P
  127   FORMAT('      THE VALUE OF P = ',G15.7)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(N.EQ.1)THEN
        XLP=X(1)
        GO TO 8000
      ENDIF
!
      HOLD=X(1)
      DO 135 I=2,N
        IF(X(I).NE.HOLD)GO TO 139
  135 CONTINUE
      XLP=HOLD
      GO TO 8000
  139 CONTINUE
!
      EPS=1.0E-6
      ATEMP=ABS(P-1.0)
      IF(ATEMP.LE.EPS)THEN
        CALL MEDIAN(X,N,IWRITE,XTEMP,MAXNXT,XLP,IBUGA3,IERROR)
        GO TO 8000
      ENDIF
      ATEMP=ABS(P-2.0)
      IF(ATEMP.LE.EPS)THEN
        CALL MEAN(X,N,IWRITE,XLP,IBUGA3,IERROR)
        GO TO 8000
      ENDIF
      IF(P.GT.10.0)THEN
        CALL MIDRAN(X,N,IWRITE,XLP,IBUGA3,IERROR)
        GO TO 8000
      ENDIF
!
!               ***************************
!               **  STEP 2--             **
!               **  COMPUTE THE LPLOC.   **
!               ***************************
!
!     STEP 1: USE MEDIAN AS STARTING VALUE.
!
      CALL SORT(X,N,XTEMP)
!
      IEVODD=N-(N/2)*2
      NMID=N/2
      NMIDP1=NMID+1
      XMED=0.0
      IF(IEVODD.EQ.0)XMED=(XTEMP(NMID)+XTEMP(NMIDP1))/2.0
      IF(IEVODD.EQ.1)XMED=XTEMP(NMIDP1)
!
!     STEP 2: USE DFZER2 TO FIND ROOT OF EQUATION.
!
      IN=N
      DP=DBLE(P)
      DO 200 I=1,N
        DTEMP(I)=DBLE(XTEMP(I))
  200 CONTINUE
!
      DXSTRT=DBLE(XMED)
      DAE=0.000001D0
      DRE=DAE
      IFLAG=0
      DXLOW=DBLE(XTEMP(1))
      DXUP=DBLE(XTEMP(N))
      CALL DFZER2(LPLFUN,DXLOW,DXUP,DXSTRT,DRE,DAE,IFLAG,DTEMP)
!
      XLP=REAL(DXLOW)
!
      IF(IFLAG.EQ.2)THEN
!
!  NOTE: SUPPRESS THIS MESSAGE FOR NOW.
!CCCC   WRITE(ICOUT,999)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,111)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,1113)
!1113   FORMAT('      ESTIMATE OF LPLOC MAY NOT BE COMPUTED TO ',
!CCCC1         'DESIRED TOLERANCE.')
!CCCC   CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.3)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1121)
 1121   FORMAT('***** WARNING FROM LP LOCATION ESTIMATE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1123)
 1123   FORMAT('      ESTIMATE MAY BE NEAR A SINGULAR POINT.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.4)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1133)
 1133   FORMAT('      APPROPRIATE BRACKETING INTERVAL NOT FOUND.')
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IFLAG.EQ.5)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1121)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1143)
 1143   FORMAT('      MAXIMUM ITERATIONS EXCEEDED.')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
 8000 CONTINUE
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,811)N,XLP,P
  811   FORMAT('THE Lp LOCATION ESTIMATE OF THE ',I8,   &
               ' OBSERVATIONS = ',G15.7,'(P = ',F5.2,')')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF LPLOC--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGA3,IERROR
 9012 FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)N
 9013 FORMAT('N = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9015)XMED
 9015 FORMAT('XMED = ',E15.7)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE LPLOC
      SUBROUTINE LPOCDF(X,LAMBDA,THETA,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE AT THE SINGLE PRECISION VALUE X
!              FOR THE LAGRANGE-POISSON DISTRIBUTION
!              WITH SINGLE PRECISION SHAPE PARAMETERS LAMBDA AND
!              THETA.  THIS DISTRIBUTION IS DEFINED FOR ALL
!              NON-NEGATIVE INTEGER X >= 0.
!              THIS DISTRIBUTION HAS THE PROBABILITY FUNCTION
!              p(X;LAMBDA,THETA) = THETA*EXP(-THETA-LAMBDA*X)*
!                                  (THETA+LAMBDA*X)**(X-1)/
!                                  (X*(X-K)!)
!                                  X >= 0; 0 < LAMBDA < 1; THETA > 0.
!              NOTE THAT THIS DISTRIBUTION IS A SHIFTED AND
!              RE-PARAMETERIZED VERSION OF THE BOREL-TANNER
!              DISTRIBUTION.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE A NON-NEGATIVE INTEGR
!                     --LAMBDA = THE SINGLE PRECISION VALUE
!                                OF THE FIRST SHAPE PARAMETER.
!                     --THETA  = THE SINGLE PRECISION VALUE
!                                OF THE SECOND SHAPE PARAMETER.
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE CDF
!             FOR THE LAGRANGE-POISSON DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE A POSITIVE INTEGER
!                 --0 < LAMBDA < 1,  AND THETA > 0
!     OTHER DATAPAC   SUBROUTINES NEEDED--LNGAMM.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DEXP, DLOG
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND KEMP (1992).  "UNIVARIATE
!                 DISCRETE DISTRIBUTIONS", SECOND EDITION,
!                 WILEY, PP. 394-400.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/5
!     ORIGINAL VERSION--MAY       2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      REAL THETA
      REAL LAMBDA
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DLAMB
      DOUBLE PRECISION DTHETA
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DLNGAM
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      CDF=0.0
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(LAMBDA.LE.0.0 .OR. LAMBDA.GE.1.0)THEN
        WRITE(ICOUT,11)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)LAMBDA
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(THETA.LE.0.0)THEN
        WRITE(ICOUT,12)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)THETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
      INTX=INT(X+0.5)
      IF(INTX.LT.0)THEN
        CDF=0.0
        GO TO 9999
      ENDIF
!
   11 FORMAT('***** ERROR--THE SECOND ARGUMENT TO LPOCDF ',   &
             'IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL.')
   12 FORMAT('***** ERROR--THE THIRD ARGUMENT TO LPOCDF ',   &
             'IS NON-POSITIVE.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
      DLAMB=DBLE(LAMBDA)
      DTHETA=DBLE(THETA)
      DCDF=0.0D0
!
      IF(INTX.EQ.0)THEN
        DCDF=DEXP(-DTHETA)
      ELSEIF(INTX.EQ.1)THEN
        DCDF=DEXP(-DTHETA) + DTHETA*DEXP(-DTHETA-DLAMB)
      ELSE
        DO 100 I=INTX,0,-1
          DX=DBLE(I)
          DTERM1=DLOG(DTHETA) + (-DTHETA-DLAMB*DX) +   &
                 (DX-1.0D0)*DLOG(DTHETA+DLAMB*DX)
          DTERM2=DLNGAM(DX+1.0D0)
          DPDF=DEXP(DTERM1 - DTERM2)
          DCDF=DCDF + DPDF
  100   CONTINUE
      ENDIF
!
      CDF=REAL(DCDF)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE LPOCDF
      SUBROUTINE LPOFUN(N,XPAR,FVEC,IFLAG,Y,K)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE FUNCTIONS FOR THE
!              LAGRANGE-POISSON WEIGHTED DISCREPENCIES (A
!              MODIFICATION OF MAXIMUM LIKELIHOOD) EQUATIONS.
!
!              SUM[i=1 to k][Y(i) - LPOPDF(X)]*
!                 [(X*(THETA+LAMBDA)/(THETA*(THETA+LAMBDA*X)) - 1] = 0
!
!              SUM[i=1 to k][Y(i) - LPOPDF(X)]*
!                 [(X*(X-1)/(THETA+LAMBDA*X)) - X] = 0
!
!              WITH THETA AND LAMBDA DENOTING THE SHAPE PARAMETERS.
!              THIS ROUTINE ASSUMES THE DATA IS IN THE FORM
!
!                   X(I)  FREQ(I)
!
!              CALLED BY DNSQE ROUTINE FOR SOLVING SIMULTANEOUS
!              NONLINEAR EQUATIONS.  NOTE THAT THE CALLING SEQUENCE
!              DID NOT ACCOMODATE A DATA ARRAY (AND ASSCIATED NUMBER OF
!              OBSERVATIONS), SO THESE WERE ADDED TO THE CALL LIST.
!              SINCE DNSQE ONLY PASSES ONE ARRAY, WE SPLIT INTO
!              TWO PARTS: 1 - MAXNXT/2 ARE THE FREQUENCIES WHILE
!              (MAXNXT/2 + 1) - MAXNXT ARE THE CLASS VALUES (I.E.,
!              THE X).
!     EXAMPLE--LAGRANGE-POISSON MAXIMUM LIKELIHOOD Y
!     REFERENCE --FELIX FAMOYE AND CARL M. -S. LEE (1992),
!                 "ESTIMATION OF GENERALIZED POISSON DISTRIBUTION",
!                 COMMUNICATIONS IN STATISTICS -- SIMULATION,
!                 21(1), PP. 173-188.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/6
!     ORIGINAL VERSION--JUNE      2006.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION XPAR(*)
      DOUBLE PRECISION FVEC(*)
      REAL Y(*)
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DTHETA
      DOUBLE PRECISION DLAMB
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
!
      DOUBLE PRECISION XBAR
      COMMON/LPOCOM/XBAR,MAXNXT,NTOT
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  COMPUTE SOME SUMS
!
      IFLAG=0
      N=2
!
      DLAMB=XPAR(1)
      DTHETA=XPAR(2)
!
      IINDX=MAXNXT/2
!
      DSUM1=0.0D0
      DSUM2=0.0D0
!
      DO 200 I=1,K
!
        DX=DBLE(Y(IINDX+I))
        DFREQ=Y(I)
!
        CALL LPOPDF(REAL(DX),REAL(DLAMB),REAL(DTHETA),PDF)
        DTERM1=(DFREQ-DBLE(PDF))
!
        DTERM2=DX*(DTHETA+DLAMB)/(DTHETA*(DTHETA+DLAMB*DX))
        DSUM1=DSUM1 + DTERM1*(DTERM2 - 1.0D0)
        DTERM3=DX*(DX-1.0D0)/(DTHETA+DLAMB*DX) - DX
        DSUM2=DSUM2 + DTERM1*DTERM3
!
  200 CONTINUE
!
      FVEC(1)=DSUM1
      FVEC(2)=DSUM2
!
      RETURN
      END SUBROUTINE LPOFUN
      SUBROUTINE LPOFU2(N,XPAR,FVEC,IFLAG,Y,K)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE FUNCTIONS FOR THE
!              LAGRANGE POISSON MAXIMUM LIKELIHOOD EQUATION.
!
!              THE MAXIMUM LIKELIHOOD ESTIMATE OF LAMBDA IS
!              THE SOLUTION OF THE EQUATION:
!
!                 SUM[X=0 to K][X*(X-1)*N(X)/(XBAR+(X-XBAR)*LAMBDA)] -
!                 N*XBAR = 0
!
!              THIS ROUTINE ASSUMES THE DATA IS IN THE FORM
!
!                   X(I)  FREQ(I)
!
!              CALLED BY DNSQE ROUTINE FOR SOLVING SIMULTANEOUS
!              NONLINEAR EQUATIONS.  NOTE THAT THE CALLING SEQUENCE
!              DID NOT ACCOMODATE A DATA ARRAY (AND ASSCIATED NUMBER OF
!              OBSERVATIONS), SO THESE WERE ADDED TO THE CALL LIST.
!              SINCE DNSQE ONLY PASSES ONE ARRAY, WE SPLIT INTO
!              TWO PARTS: 1 - MAXNXT/2 ARE THE FREQUENCIES WHILE
!              (MAXNXT/2 + 1) - MAXNXT ARE THE CLASS VALUES (I.E.,
!              THE X).
!     EXAMPLE--LAGRANGE POISSON MAXIMUM LIKELIHOOD Y
!     REFERENCES--CONSUL AND FAMOYE (2006), "LAGRANGIAN PROBABILITY
!                 DISTRIBUTIONS", BIRKHAUSER, CHAPTER 9.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/7
!     ORIGINAL VERSION--JULY      2006.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION XPAR(*)
      DOUBLE PRECISION FVEC(*)
      REAL Y(*)
!
      DOUBLE PRECISION DLAMBD
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DN
      DOUBLE PRECISION DX
      DOUBLE PRECISION DFREQ
!
      DOUBLE PRECISION XBAR
      COMMON/LPOCOM/XBAR,MAXROW,NTOT
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFLAG=0
      N=2
!
      DLAMBD=XPAR(1)
      DN=DBLE(NTOT)
      IINDX=MAXROW/2
!
      DTERM1=DN*XBAR
!
      DSUM1=0.0D0
      DO 100 I=0,K
        DX=DBLE(Y(IINDX+I))
        DFREQ=Y(I+1)
        DSUM1=DSUM1 + DX*(DX-1.0D0)*DFREQ/(XBAR+(DX-XBAR)*DLAMBD)
  100 CONTINUE
!
      FVEC(1)=DSUM1 - DTERM1
!
      RETURN
      END SUBROUTINE LPOFU2
      SUBROUTINE LPOFU3(N,XPAR,FVEC,IFLAG,Y,K)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE FUNCTIONS FOR THE
!              LAGRANGE-POISSON EWRC METHOD.  EWRC IS A
!              COMBINATION OF THE WEIGHTED DISCREPENCIES AND
!              MAXIMUM LIKELIHOOD METHODS.  THE EWRC ESTIMATES
!              ARE THE SOLUTIONS OF THE FOLLOWING EQUATIONS:
!
!              SUM[i=1 to k][Y(i)*(Y(i) - LPOPDF(X))]*
!                 [(X*(THETA+LAMBDA)/(THETA*(THETA+LAMBDA*X)) - 1] = 0
!
!              SUM[i=1 to k][Y(i)*(Y(i) - LPOPDF(X))]*
!                 [(X*(X-1)/(THETA+LAMBDA*X)) - X] = 0
!
!              WITH THETA AND LAMBDA DENOTING THE SHAPE PARAMETERS.
!              THIS ROUTINE ASSUMES THE DATA IS IN THE FORM
!
!                   X(I)  FREQ(I)
!
!              CALLED BY DNSQE ROUTINE FOR SOLVING SIMULTANEOUS
!              NONLINEAR EQUATIONS.  NOTE THAT THE CALLING SEQUENCE
!              DID NOT ACCOMODATE A DATA ARRAY (AND ASSCIATED NUMBER OF
!              OBSERVATIONS), SO THESE WERE ADDED TO THE CALL LIST.
!              SINCE DNSQE ONLY PASSES ONE ARRAY, WE SPLIT INTO
!              TWO PARTS: 1 - MAXNXT/2 ARE THE FREQUENCIES WHILE
!              (MAXNXT/2 + 1) - MAXNXT ARE THE CLASS VALUES (I.E.,
!              THE X).
!     EXAMPLE--LAGRANGE-POISSON MAXIMUM LIKELIHOOD Y
!     REFERENCE --FELIX FAMOYE AND CARL M. -S. LEE (1992),
!                 "ESTIMATION OF GENERALIZED POISSON DISTRIBUTION",
!                 COMMUNICATIONS IN STATISTICS -- SIMULATION,
!                 21(1), PP. 173-188.
!               --CONSUL AND FAMOYE (2006), "LAGRANGIAN PROBABILITY
!                 DISTRIBUTIONS", BIRKHAUSER, CHAPTER 9.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBUG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/8
!     ORIGINAL VERSION--AUGUST    2006.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION XPAR(*)
      DOUBLE PRECISION FVEC(*)
      REAL Y(*)
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DTHETA
      DOUBLE PRECISION DLAMB
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
!
      DOUBLE PRECISION XBAR
      COMMON/LPOCOM/XBAR,MAXNXT,NTOT
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  COMPUTE SOME SUMS
!
      IFLAG=0
      N=2
!
      DLAMB=XPAR(1)
      DTHETA=XPAR(2)
!
      IINDX=MAXNXT/2
!
      DSUM1=0.0D0
      DSUM2=0.0D0
!
      DO 200 I=1,K
!
        DX=DBLE(Y(IINDX+I))
        DFREQ=Y(I)
!
        CALL LPOPDF(REAL(DX),REAL(DLAMB),REAL(DTHETA),PDF)
        DTERM1=DFREQ*(DFREQ-DBLE(PDF))
!
        DTERM2=DX*(DTHETA+DLAMB)/(DTHETA*(DTHETA+DLAMB*DX))
        DSUM1=DSUM1 + DTERM1*(DTERM2 - 1.0D0)
        DTERM3=DX*(DX-1.0D0)/(DTHETA+DLAMB*DX) - DX
        DSUM2=DSUM2 + DTERM1*DTERM3
!
  200 CONTINUE
!
      FVEC(1)=DSUM1
      FVEC(2)=DSUM2
!
      RETURN
      END SUBROUTINE LPOFU3
      SUBROUTINE LPOPDF(X,LAMBDA,THETA,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE AT THE SINGLE PRECISION VALUE X
!              FOR THE LAGRANGE-POISSON DISTRIBUTION
!              WITH SINGLE PRECISION SHAPE PARAMETERS LAMBDA AND
!              THETA.  THIS DISTRIBUTION IS DEFINED FOR ALL
!              NON-NEGATIVE INTEGER X >= 0.
!              THIS DISTRIBUTION HAS THE PROBABILITY FUNCTION
!              p(X;LAMBDA,THETA) = THETA*EXP(-THETA-LAMBDA*X)*
!                                  (THETA+LAMBDA*X)**(X-1)/
!                                  (X*(X-K)!)
!                                  X >= 0; 0 < LAMBDA < 1; THETA > 0.
!              NOTE THAT THIS DISTRIBUTION IS A SHIFTED AND
!              RE-PARAMETERIZED VERSION OF THE BOREL-TANNER
!              DISTRIBUTION.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE A NON-NEGATIVE INTEGR
!                     --LAMBDA = THE SINGLE PRECISION VALUE
!                                OF THE FIRST SHAPE PARAMETER.
!                     --THETA  = THE SINGLE PRECISION VALUE
!                                OF THE SECOND SHAPE PARAMETER.
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                MASS FUNCTION VALUE
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF
!             FOR THE LAGRANGE-POISSON DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE A POSITIVE INTEGER
!                 --0 < LAMBDA < 1,  AND THETA > 0
!     OTHER DATAPAC   SUBROUTINES NEEDED--LNGAMM.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DEXP, DLOG
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND KEMP (1992).  "UNIVARIATE
!                 DISCRETE DISTRIBUTIONS", SECOND EDITION,
!                 WILEY, PP. 394-400.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/5
!     ORIGINAL VERSION--MAY       2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      REAL THETA
      REAL LAMBDA
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DLAMB
      DOUBLE PRECISION DTHETA
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DLNGAM
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      PDF=0.0
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(LAMBDA.LE.0.0 .OR. LAMBDA.GE.1.0)THEN
        WRITE(ICOUT,11)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)LAMBDA
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ENDIF
!
      IF(THETA.LE.0.0)THEN
        WRITE(ICOUT,12)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)THETA
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ENDIF
      INTX=INT(X+0.5)
      IF(INTX.LT.0)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)INTX
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ENDIF
!
    5 FORMAT('***** ERROR--THE FIRST INPUT ARGUMENT TO THE LPOPDF ',   &
      'SUBROUTINE IS NON-POSITIVE')
   11 FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO THE ',   &
      ' LPOPDF SUBROUTINE IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL')
   12 FORMAT('***** ERROR--THE THIRD INPUT ARGUMENT TO THE ',   &
      ' LPOPDF SUBROUTINE IS NON-POSITIVE')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
!
      DX=DBLE(INTX)
      DLAMB=DBLE(LAMBDA)
      DTHETA=DBLE(THETA)
!
      IF(INTX.EQ.0)THEN
        DPDF=DEXP(-DTHETA)
      ELSEIF(INTX.EQ.1)THEN
        DPDF=DTHETA*DEXP(-DTHETA-DLAMB)
      ELSE
        DTERM1=DLOG(DTHETA) + (-DTHETA-DLAMB*DX) +   &
               (DX-1.0D0)*DLOG(DTHETA+DLAMB*DX)
        DTERM2=DLNGAM(DX+1.0D0)
        DPDF=DEXP(DTERM1 - DTERM2)
      ENDIF
      PDF=REAL(DPDF)
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE LPOPDF
      SUBROUTINE LPOPPF(P,LAMBDA,THETA,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE AT THE SINGLE PRECISION VALUE P
!              FOR THE LAGRANGE-POISSON DISTRIBUTION
!              WITH SINGLE PRECISION SHAPE PARAMETERS LAMBDA AND
!              THETA.  THIS DISTRIBUTION IS DEFINED FOR ALL
!              NON-NEGATIVE INTEGER X >= 0.
!              THIS DISTRIBUTION HAS THE PROBABILITY FUNCTION
!              p(X;LAMBDA,THETA) = THETA*EXP(-THETA-LAMBDA*X)*
!                                  (THETA+LAMBDA*X)**(X-1)/
!                                  (X*(X-K)!)
!                                  X >= 0; 0 < LAMBDA < 1; THETA > 0.
!              NOTE THAT THIS DISTRIBUTION IS A SHIFTED AND
!              RE-PARAMETERIZED VERSION OF THE BOREL-TANNER
!              DISTRIBUTION.
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE
!                                AT WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE A NON-NEGATIVE INTEGR
!                     --LAMBDA = THE SINGLE PRECISION VALUE
!                                OF THE FIRST SHAPE PARAMETER.
!                     --THETA  = THE SINGLE PRECISION VALUE
!                                OF THE SECOND SHAPE PARAMETER.
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION PERCENT POINT
!                                FUNCTION VALUE
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT
!             FUNCTION VALUE PPF
!             FOR THE LAGRANGE-POISSON DISTRIBUTION
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--0 <= P < 1
!                 --0 < LAMBDA < 1,  AND THETA > 0
!     OTHER DATAPAC   SUBROUTINES NEEDED--LNGAMM.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DEXP, DLOG
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND KEMP (1992).  "UNIVARIATE
!                 DISCRETE DISTRIBUTIONS", SECOND EDITION,
!                 WILEY, PP. 394-400.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/5
!     ORIGINAL VERSION--MAY       2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      REAL P
      REAL THETA
      REAL LAMBDA
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DP
      DOUBLE PRECISION DLAMB
      DOUBLE PRECISION DTHETA
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DEPS
      DOUBLE PRECISION DLNGAM
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      PPF=0.0
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PPF=0.0
      IF(P.LT.0.0.OR.P.GE.1.0)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(LAMBDA.LE.0.0 .OR. LAMBDA.GE.1.0)THEN
        WRITE(ICOUT,11)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)LAMBDA
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(THETA.LE.0.0)THEN
        WRITE(ICOUT,12)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)THETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
!
    1 FORMAT('***** ERROR--THE FIRST ARGUMENT TO LPOPPF ',   &
             'IS OUTSIDE THE ALLOWABLE (0,1] INTERVAL.')
   11 FORMAT('***** ERROR--THE SECOND ARGUMENT TO LPOPPF ',   &
             'IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL')
   12 FORMAT('***** ERROR--THE THIRD ARGUMENT TO LPOPPF ',   &
             'IS NON-POSITIVE')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
      DP=DBLE(P)
      DLAMB=DBLE(LAMBDA)
      DTHETA=DBLE(THETA)
!
      IF(P.LE.0.0)THEN
        PPF=0.0
        GO TO 9999
      ENDIF
!
!     COMPUTE PDF FOR X = 0
!
      DEPS=1.0D-7
      DCDF=DEXP(-DTHETA)
!
      IF(DCDF.GE.DP-DEPS)THEN
        PPF=0.0
        GO TO 9999
      ENDIF
      I=0
!
      DCDF=DCDF + DTHETA*DEXP(-DTHETA-DLAMB)
      IF(DCDF.GE.DP-DEPS)THEN
        PPF=1.0
        GO TO 9999
      ENDIF
      I=1
!
  100 CONTINUE
        I=I+1
        IF(DBLE(I).GE.DBLE(I1MACH(9)))THEN
          WRITE(ICOUT,55)
   55     FORMAT('***** ERROR--THE COMPUTED PERCENT POINT VALUE ',   &
                 'EXCEEDS THE LARGEST MACHINE INTEGER.')
          CALL DPWRST('XXX','BUG ')
          PPF=0.0
          GO TO 9999
        ENDIF
        DX=DBLE(I)
        DTERM1=DLOG(DTHETA) + (-DTHETA-DLAMB*DX) +   &
               (DX-1.0D0)*DLOG(DTHETA+DLAMB*DX)
        DTERM2=DLNGAM(DX+1.0D0)
        DPDF=DEXP(DTERM1 - DTERM2)
        DCDF=DCDF + DPDF
        IF(DCDF.GE.DP-DEPS)THEN
          PPF=REAL(I)
          GO TO 9999
        ENDIF
      GO TO 100
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE LPOPPF
      SUBROUTINE LPORAN(N,LAMBDA,THETA,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE LAGRANGE-POISSON DISTRIBUTION
!              WITH SHAPE PARAMETERS LAMBDA AND THETA.
!              THIS DISTRIBUTION IS DEFINED FOR ALL
!              NON-NEGATIVE INTEGER X >= 0.
!              THIS DISTRIBUTION HAS THE PROBABILITY FUNCTION
!              p(X;LAMBDA,THETA) = THETA*EXP(-THETA-LAMBDA*X)*
!                                  (THETA+LAMBDA*X)**(X-1)/
!                                  (X*(X-K)!)
!                                  X >= 0; 0 < LAMBDA < 1; THETA > 0.
!              NOTE THAT THIS DISTRIBUTION IS A SHIFTED AND
!              RE-PARAMETERIZED VERSION OF THE BOREL-TANNER
!              DISTRIBUTION.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --LAMBDA = THE SINGLE PRECISION VALUE
!                                OF THE FIRST SHAPE PARAMETER.
!                     --THETA  = THE SINGLE PRECISION VALUE
!                                OF THE SECOND SHAPE PARAMETER.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE LAGRANGE-POISSON DISTRIBUTION
!             WITH SHAPE PARAMETERS LAMBDA AND THETA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --0 < LAMBDA < 1, THETA > 0
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN, LPOPPF
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND KEMP (1992).  "UNIVARIATE
!                 DISCRETE DISTRIBUTIONS", SECOND EDITION,
!                 WILEY, PP. 394-400.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/6
!     ORIGINAL VERSION--JUNE      2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      REAL LAMBDA
      REAL THETA
      DIMENSION X(*)
!
!CCCC DIMENSION U(2)
!
!CCCC DOUBLE PRECISION PI
!CCCC DOUBLE PRECISION C
!CCCC DOUBLE PRECISION V
!CCCC DOUBLE PRECISION Y
!CCCC DOUBLE PRECISION DK
!CCCC DOUBLE PRECISION DLAMB
!CCCC DOUBLE PRECISION U1
!CCCC DOUBLE PRECISION W
!CCCC DOUBLE PRECISION WT
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
    5   FORMAT('***** ERROR--THE REQUESTED NUMBER OF ',   &
               'LAGRANGE-POISSON RANDOM NUMBERS IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
   47   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(LAMBDA.LE.0.0 .OR. LAMBDA.GE.1.0)THEN
        WRITE(ICOUT,11)
   11   FORMAT('***** ERROR--THE LAMBDA PARAMETER FOR THE ',   &
               'LAGRANGE-POISSON RANDOM NUMBERS IS OUTSIDE THE ',   &
               '(0,1) INTERVAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)LAMBDA
   46   FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(THETA.LE.0.0)THEN
        WRITE(ICOUT,12)
   12   FORMAT('***** ERROR--THE THETA PARAMETER FOR THE ',   &
               'LAGRANGE-POISSON RANDOM NUMBERS IS NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)THETA
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
!
!     GENERATE N LAGRANGE-POISSON DISTRIBUTION RANDOM NUMBERS
!     USING THE ALGORITHM GIVEN IN THE DEVROYE PAPER.
!
!     I DON'T THINK I HAVE THIS QUITE RIGHT, SO JUST USE
!     INVERSE PPF METHOD FOR NOW.
!
!CCCC NTEMP=2
!CCCC C=1.0D0/DSQRT(2.0D0*PI)
!CCCC DK=DBLE(IK)
!CCCC DLAMB=DBLE(LAMBDA)
!
!CCCC DO100I=1,N
!
!110    CONTINUE
!CCCC   CALL UNIRAN(NTEMP,ISEED,U)
!CCCC   U1=DBLE(U(1))
!
!CCCC   V=(1.0D0 + 4.0D0*C*DSQRT(DK))*U1
!
!CCCC   IF(V.LE.1.0D0)THEN
!CCCC     X(I)=REAL(IK)
!CCCC     GO TO 100
!CCCC   ELSEIF(V.GT.1.0D0 .AND. V.LE.1.0D0+2.0D0*C*DSQRT(DK))THEN
!CCCC     Y=DK + 1.0D0 + (V - 1.0D0)**2/(4.0D0*C*C)
!CCCC     T=C/DSQRT(Y-1.0D0-DK)
!CCCC   ELSE
!CCCC     Y=DK + 1.0D0 + (2.0D0*DK*C/(1.0D0+4.0D0*C*DSQRT(DK)-V))**2
!CCCC     T=DK*C/(Y-1.0D0-DK)**1.5
!CCCC   ENDIF
!
!CCCC   W=DBLE(U(2))
!CCCC   WT=W*T
!CCCC   CALL LPOCDF(REAL(Y),LAMBDA,K,CDF)
!CCCC   CALL LPOPDF(REAL(Y),LAMBDA,K,PDF)
!CCCC   CALL LPOPDF(REAL(Y),LAMBDA,K,PPF)
!CCCC   IF(WT.LT.DBLE(PPF))THEN
!CCCC     IY=INT(Y+0.5)
!CCCC     X(I)=REAL(IY)
!CCCC     GO TO 100
!CCCC   ELSE
!CCCC     GO TO 110
!CCCC   ENDIF
!
! 100 CONTINUE
!
      CALL UNIRAN(N,ISEED,X)
      DO 100 I=1,N
        XTEMP=X(I)
        CALL LPOPPF(XTEMP,LAMBDA,THETA,PPF)
        X(I)=PPF
  100 CONTINUE
!
 9999 CONTINUE
!
      RETURN
      END SUBROUTINE LPORAN
      SUBROUTINE LPVARI(X,N,P,IWRITE,XTEMP,DTEMP,MAXNXT,XLPVAR,   &
                       IQUASE,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE APPROXIMATE VARIANCE
!              OF THE SAMPLE LP LOCATION ESTIMATE OF THE DATA IN THE
!              INPUT VECTOR X.
!
!              GIVEN THE MODEL
!
!                 X(i) = ALPHA + E(i)
!
!              THE L(p) ESTIMATOR OF ALPHA IS
!
!                 L(p)(X(i)) = Arg(alpha)
!                     MIN{(SUM[i=1 to n][|X(i) - ALPHA|**p)**(1/p)}
!
!              OR EQUIVALENTLY
!
!                 L(p)(X(i)) = Arg(alpha)
!                     MIN{SUM[i=1 to n][|X(i) - ALPHA|**p}
!
!              THIS ESTIMATE IS THE SOLUTION OF THE EQUATION
!
!              SUM[i=1 to n][|X(i)-alpha|**(p-1)*SIGN(x(i)-ALPHA) = 0
!
!              THERE ARE 3 SPECIAL CASES:
!
!               P = 1   - SAMPLE MEDIAN
!               P = 2   - SAMPLE MEAN
!               P = INF - SAMPLE MID-RANGE
!
!               THE ESTIMATE OF THE ASYMPTOTIC VARIANCE IS THEN:
!
!               w(p)^2 = m(2*p-2)/[(p-1)*m(p-2)]**2
!
!               WHERE
!
!               m(r) = (1/n)*SUM[i=1 to n][|X(i)-Lp(X(i))|**r]
!
!               THE VARIANCE OF THE LP ESTIMATE IS THEN OBTAINED
!               BY DIVIDING w(p)^2 BY N.
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!                     --P      = THE SINGLE PRECISION VALUE OF THE
!                                "p" PARAMETER.
!     OUTPUT ARGUMENTS--XLPVAR = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED VARIANCE OF THE SAMPLE
!                                LP LOCATION ESTIMATE.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE VARIANCE OF
!             THE SAMPLE LP LOCATION ESTIMATE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--SORT, LPLOC.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DABS.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--FRANCESCA PENNECCHI AND LUCA CALLEGARO, "BETWEEN
!                 THE MEAN AND THE MEDIAN: THE Lp ESTIMATOR",
!                 METROLOGIA, 43, 2006, PP. 213-219.
!
!     NOTE--SEEMS TO BE DISCREPANCY WITH FRANCESCA RESULTS IN
!           PAPER AND RESULT RETURNED HERE.  BOOTSTRAP ESTIMATE
!           IS CLOSE TO REPORTED RESULT, SUGGESTING THAT THE
!           PUBLISHED FORMULA MAY BE IN ERROR.  FRANCESCA WILL
!           INVESTIGATE, CODE BELOW WILL BE ADJUSTED WHEN I
!           HEAR BACK FROM HER.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     ORIGINAL VERSION--NOVEMBER  2007.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IQUASE
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION XTEMP(*)
      DOUBLE PRECISION DTEMP(*)
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DP
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DR1
      DOUBLE PRECISION DR2
      DOUBLE PRECISION DLP
      DOUBLE PRECISION DLPVAR
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='LPVA'
      ISUBN2='RI  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF LPVARI--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,N,P
   52   FORMAT('IBUGA3,N,P = ',A4,2X,I10,2X,G15.7)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,MIN(N,100)
          WRITE(ICOUT,56)I,X(I)
   56     FORMAT('I,X(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               **********************
!               **  COMPUTE LPLOC   **
!               **********************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.LT.1 .OR.N.GT.MAXNXT)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN VARIANCE OF LP LOCATION--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS IN THE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)
  113   FORMAT('      RESPONSE VARIABLE IS LESS THAN 1 OR GREATER')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,115)MAXNXT
  115   FORMAT('      THAN ',I10)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS = ',I10,'.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(P.LT.1.0)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,122)
  122   FORMAT('      THE P PARAMETER IS LESS THAN 1.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,127)P
  127   FORMAT('      THE VALUE OF P = ',G15.7)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(N.EQ.1)THEN
        XLPVAR=0.0
        GO TO 8000
      ENDIF
!
      HOLD=X(1)
      DO 135 I=2,N
        IF(X(I).NE.HOLD)GO TO 139
  135 CONTINUE
      XLPVAR=0.0
      GO TO 8000
  139 CONTINUE
!
      CALL LPLOC(X,N,P,IWRITE,XTEMP,DTEMP,MAXNXT,XLP,   &
                 IBUGA3,IERROR)
!
!               ************************************
!               **  STEP 2--                      **
!               **  COMPUTE THE VARIANCE OF THE   **
!               **  Lp ESTIMATE.                  **
!               ************************************
!
       EPS=1.0E-06
       IF(ABS(P-1.0).LE.EPS)THEN
         P100=0.5
         CALL QUANSE(P100,X,N,IWRITE,XTEMP,MAXNXT,IQUASE,XLPVAR,   &
                     IBUGA3,IERROR)
       ELSE
         DLP=DBLE(XLP)
         DP=DBLE(P)
         DSUM1=0.0D0
         DSUM2=0.0D0
         DR1=2.0D0*DP - 2.0D0
         DR2=DP - 2.0D0
!
         DO 1000 I=1,N
           DX=DBLE(X(I))
           DTERM1=DABS(DX-DLP)**DR1
           DTERM2=DABS(DX-DLP)**DR2
           DSUM1=DSUM1 + DTERM1
           DSUM2=DSUM2 + DTERM2
 1000   CONTINUE
!
        DTERM1=DSUM1/(DSUM2**2)
        DTERM2=DBLE(N)/((DP-1.0D0)**2)
        DLPVAR=DTERM1*DTERM2/DBLE(N)
        XLPVAR=REAL(DLPVAR)
      ENDIF
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
 8000 CONTINUE
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,811)N
  811   FORMAT('THE VARIANCE OF THE Lp LOCATION ESTIMATE OF THE ',I8,   &
               ' OBSERVATIONS')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,813)XLPVAR,P
  813   FORMAT('= ',G15.7,'(P = ',F5.2,')')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF LPVARI--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGA3,IERROR
 9012   FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)N
 9013   FORMAT('N = ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)XLP,XLPVAR
 9015   FORMAT('XLP,XLPVAR = ',2G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9017)DR1,DR2,DSUM1,DSUM2
 9017   FORMAT('DR1,DR2,DSUM1,DSUM2 = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE LPVARI
      LOGICAL FUNCTION LSAME( CA, CB )
!
!  -- LAPACK auxiliary routine (version 1.1) --
!     Univ. of Tennessee, Univ. of California Berkeley, NAG Ltd.,
!     Courant Institute, Argonne National Lab, and Rice University
!     February 29, 1992
!
!     .. Scalar Arguments ..
      CHARACTER          CA, CB
!     ..
!
!  Purpose
!  =======
!
!  LSAME returns .TRUE. if CA is the same letter as CB regardless of
!  case.
!
!  Arguments
!  =========
!
!  CA      (input) CHARACTER*1
!  CB      (input) CHARACTER*1
!          CA and CB specify the single characters to be compared.
!
!     .. Intrinsic Functions ..
      INTRINSIC          ICHAR
!     ..
!     .. Local Scalars ..
      INTEGER            INTA, INTB, ZCODE
!     ..
!     .. Executable Statements ..
!
!     Test if the characters are equal
!
      LSAME = CA.EQ.CB
      IF( LSAME )   &
         RETURN
!
!     Now test for equivalence if both characters are alphabetic.
!
      ZCODE = ICHAR( 'Z' )
!
!     Use 'Z' rather than 'A' so that ASCII can be detected on Prime
!     machines, on which ICHAR returns a value with bit 8 set.
!     ICHAR('A') on Prime machines returns 193 which is the same as
!     ICHAR('A') on an EBCDIC machine.
!
      INTA = ICHAR( CA )
      INTB = ICHAR( CB )
!
      IF( ZCODE.EQ.90 .OR. ZCODE.EQ.122 ) THEN
!
!        ASCII is assumed - ZCODE is the ASCII code of either lower or
!        upper case 'Z'.
!
         IF( INTA.GE.97 .AND. INTA.LE.122 ) INTA = INTA - 32
         IF( INTB.GE.97 .AND. INTB.LE.122 ) INTB = INTB - 32
!
      ELSE IF( ZCODE.EQ.233 .OR. ZCODE.EQ.169 ) THEN
!
!        EBCDIC is assumed - ZCODE is the EBCDIC code of either lower or
!        upper case 'Z'.
!
         IF( INTA.GE.129 .AND. INTA.LE.137 .OR.   &
             INTA.GE.145 .AND. INTA.LE.153 .OR.   &
             INTA.GE.162 .AND. INTA.LE.169 ) INTA = INTA + 64
         IF( INTB.GE.129 .AND. INTB.LE.137 .OR.   &
             INTB.GE.145 .AND. INTB.LE.153 .OR.   &
             INTB.GE.162 .AND. INTB.LE.169 ) INTB = INTB + 64
!
      ELSE IF( ZCODE.EQ.218 .OR. ZCODE.EQ.250 ) THEN
!
!        ASCII is assumed, on Prime machines - ZCODE is the ASCII code
!        plus 128 of either lower or upper case 'Z'.
!
         IF( INTA.GE.225 .AND. INTA.LE.250 ) INTA = INTA - 32
         IF( INTB.GE.225 .AND. INTB.LE.250 ) INTB = INTB - 32
      END IF
      LSAME = INTA.EQ.INTB
!
!     RETURN
!
!     End of LSAME
!
      END FUNCTION LSAME
      SUBROUTINE LSNCDF(X,ALMBDA,SD,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE LOG-SKEW-NORMAL DISTRIBUTION
!              WITH SHAPE PARAMETERS = LAMBDA AND SD (SD IS THE
!              SCALE PARAMETER OF THE CORRESPONDING NORMAL
!              DISTRIBUTION).
!              THIS DISTRIBUTION IS DEFINED FOR POSITIVE X AND HAS
!              THE CUMULATIVE DISTRIBUTION FUNCTION
!                 LSNCDF(X,LAMBDA,SD) = SNCDF(LOG(X)/SD,LAMBDA)
!              WITH SNPDF DENOTING THE SKEW-NORMAL PROBABILITY
!              DENSITY FUNCTION.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE NON-NEGATIVE.
!                     --ALMBDA = THE FIRST SHAPE PARAMETER
!                     --SD     = THE SECOND SHAPE PARAMETER
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE PDF FOR THE LOG-SKEWED-NORMAL DISTRIBUTION
!             WITH SHAPE PARAMETERS = LAMBDA AND SD.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--SNCDF
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 JOHN WILEY, 1994, PAGE 454.
!               --"Log-Skew-Normal and Log-Skew-t Distributions as
!                 Models for Family Income Data", Azzalini, Cappello,
!                 and Kotz, paper downloaded from Azzalini's web
!                 site.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.3
!     ORIGINAL VERSION--MARCH     2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ISKNDF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!               ***************************************
!               **  STEP 1--                         **
!               **  CHECK INPUT ARGUMENTS FOR ERRORS **
!               ***************************************
!
      IF(X.LE.0.0)THEN
        CDF=0.0
        GO TO 9000
      ENDIF
      IF(SD.LE.0.0)THEN
        WRITE(ICOUT,6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,45)SD
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9000
      ENDIF
    6 FORMAT('**** ERROR: ARGUMENT FOR THE SECOND SHAPE PARAMETER OF ',   &
             'THE LOG-SKEW-NORMAL CDF IS NON-POSITIVE.')
   45 FORMAT('     VALUE OF THE ARGUMENT IS ',G15.7)
!
!               ************************************
!               **  STEP 2--                      **
!               **  COMPUTE THE DENSITY FUNCTION  **
!               ************************************
!
      ISKNDF='DEFA'
      CALL SNCDF(LOG(X)/SD,ALMBDA,ISKNDF,CDF)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE LSNCDF
      SUBROUTINE LSNPDF(X,ALMBDA,SD,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE LOG-SKEW-NORMAL DISTRIBUTION
!              WITH SHAPE PARAMETERS = LAMBDA AND SD (SD IS THE
!              SCALE PARAMETER OF THE CORRESPONDING NORMAL
!              DISTRIBUTION).
!              THIS DISTRIBUTION IS DEFINED FOR POSITIVE X AND HAS
!              THE PROBABILITY DENSITY FUNCTION
!                 LSNPDF(X,LAMBDA,SD) = (1/(SD*X))*
!                                       SNPDF(LOG(X)/SD,LAMBDA)
!              WITH SNPDF DENOTING THE SKEW-NORMAL PROBABILITY
!              DENSITY FUNCTION.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE NON-NEGATIVE.
!                     --ALMBDA = THE FIRST SHAPE PARAMETER
!                     --SD     = THE SECOND SHAPE PARAMETER
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE LOG-SKEWED-NORMAL DISTRIBUTION
!             WITH SHAPE PARAMETER = LAMBDA.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NODPDF, NODCDF..
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 JOHN WILEY, 1994, PAGE 454.
!               --"Log-Skew-Normal and Log-Skew-t Distributions as
!                 Models for Family Income Data", Azzalini, Cappello,
!                 and Kotz, paper downloaded from Azzalini's web
!                 site.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.3
!     ORIGINAL VERSION--MARCH     2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DLMBDA
      DOUBLE PRECISION DSD
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DPDF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!               ***************************************
!               **  STEP 1--                         **
!               **  CHECK INPUT ARGUMENTS FOR ERRORS **
!               ***************************************
!
      IF(X.EQ.0.0)THEN
        PDF=0.0
        GO TO 9000
      ELSEIF(X.LT.0.0)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,45)X
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9000
      ENDIF
      IF(SD.LE.0.0)THEN
        WRITE(ICOUT,6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,45)SD
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9000
      ENDIF
    5 FORMAT('**** ERROR: ARGUMENT FOR LOG-SKEW-NORMAL DISTRIBUTION ',   &
             'IS NON-POSITIVE.')
    6 FORMAT('**** ERROR: ARGUMENT FOR THE SECOND SHAPE PARAMETER OF ',   &
             'THE LOG-SKEW-NORMAL DISTRIBUTION IS NON-POSITIVE.')
   45 FORMAT('     VALUE OF THE ARGUMENT IS ',G15.7)
!
!               ************************************
!               **  STEP 2--                      **
!               **  COMPUTE THE DENSITY FUNCTION  **
!               ************************************
!
      DX=DBLE(X)
      DLMBDA=DBLE(ALMBDA)
      DSD=DBLE(SD)
!
      CALL NODCDF(DLOG(DX)*DLMBDA/DSD,DTERM1)
      CALL NODPDF(DLOG(DX)/DSD,DTERM2)
      DPDF=2.0D0*DTERM1*DTERM2
      DPDF=(1.0D0/(DSD*DX))*DPDF
      PDF=REAL(DPDF)
      GO TO 9000
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE LSNPDF
      SUBROUTINE LSNPPF(P,ALMBDA,SD,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE LOG-SKEW-NORMAL DISTRIBUTION
!              WITH SHAPE PARAMETERS = LAMBDA AND SD.
!              THIS DISTRIBUTION IS DEFINED FOR ALL X AND THE
!              PERCENT POINT FUNCTION IS COMPUTED BY
!              TAKING THE EXPONENT OF THE SKEW-NORMAL PPF FUNCTION.
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --ALMBDA = THE FIRST SHAPE PARAMETER
!                     --SD     = THE SECOND SHAPE PARAMETER
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
