         PPF=0.0
         GO TO 9000
      ENDIF
!
      IF(SD.LE.0.0)THEN
        WRITE(ICOUT,6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,45)SD
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9000
      ENDIF
    6 FORMAT('**** ERROR: ARGUMENT FOR THE SECOND SHAPE PARAMETER OF ',   &
             'THE LOG-SKEW-NORMAL PPF IS NON-POSITIVE.')
   45 FORMAT('     VALUE OF THE ARGUMENT IS ',G15.7)
!
      ISKNDF='DEFA'
      CALL SNPPF(P,ALMBDA,ISKNDF,PPF2)
      PPF=EXP(PPF2*SD)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE LSNPPF
      SUBROUTINE LSNRAN(N,ALMBDA,SD,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE LOG-SKEWED-NORMAL DISTRIBUTION
!              WITH SHAPE PARAMETERS = ALMBDA AND SD.
!              THIS DISTRIBUTION IS DEFINED FOR POSITIVE X.
!              LOG-SKEWED-NORMAL RANDOM NUMBERS ARE FOUND BY
!              EXPONENTIATING SKEW-NORMAL RANDOM NUMBERS.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --ALMBDA = THE FIRST SHAPE (PARAMETER) FOR THE
!                                LOG-SKEWED-NORMAL DISTRIBUTION.
!                     --SD     = THE SECOND SHAPE (PARAMETER) FOR THE
!                                LOG-SKEWED-NORMAL DISTRIBUTION.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE LOG-SKEWED-NORMAL DISTRIBUTION
!             WITH SHAPE PARAMETERS = ALMBDA AND SD.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --ALMBDA CAN BE ANY REAL NUMBER.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NORRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 JOHN WILEY, 1994, PAGE 454.
!               --AZZALINI HAS AUTHORED A NUMBER OF PAPERS ON THIS
!                 DISTRIBUTION.  ALGORITHM FOR RANDOM NUMBERS
!                 ADAPTED FROM AZZALINI'S R FUNCTIONS FOR SKEW
!                 NORMAL.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.3
!     ORIGINAL VERSION--MARCH     2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION Y(2)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
    5 FORMAT('***** ERROR--FOR THE LOG-SKEWED-NORMAL DISTRIBUTION,')
    6 FORMAT('       THE REQUESTED NUMBER OF RANDOM NUMBERS WAS ',   &
            'NON-POSITIVE.')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,' *****')
!
!     ALGORITM ADAPTED FROM AZZALINI'S R FUNCTION LIBRARY.
!
      DO 100 I=1,N
!
        CALL NORRAN(2,ISEED,Y)
        U1=Y(1)
        U2=Y(2)
        ATEMP=ALMBDA*U1
        IF(U2.GT.ATEMP)U1=-U1
        X(I)=EXP(SD*U1)
!
  100 CONTINUE
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE LSNRAN
      SUBROUTINE LSTCDF(X,NU,ALMBDA,SD,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE LOG-SKEW-T DISTRIBUTION
!              WITH SHAPE PARAMETERS = NU, LAMBDA AND SD (SD IS THE
!              SCALE PARAMETER OF THE CORRESPONDING T DISTRIBUTION).
!              THIS DISTRIBUTION IS DEFINED FOR POSITIVE X AND HAS
!              THE CUMULATIVE DISTRIBUTION FUNCTION
!                 LSTCDF(X,NU,LAMBDA,SD) = STCDF(LOG(X)/SD,NU,LAMBDA)
!              WITH SNPDF DENOTING THE SKEW-T PROBABILITY
!              DENSITY FUNCTION.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE NON-NEGATIVE.
!                     --NU     = THE FIRST SHAPE PARAMETER
!                     --ALMBDA = THE SECOND SHAPE PARAMETER
!                     --SD     = THE THIRD SHAPE PARAMETER
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE LOG-SKEWED-T DISTRIBUTION
!             WITH SHAPE PARAMETERS = NU, LAMBDA, AND SD.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--STCDF
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 JOHN WILEY, 1994, PAGE 454.
!               --"Log-Skew-Normal and Log-Skew-t Distributions as
!                 Models for Family Income Data", Azzalini, Cappello,
!                 and Kotz, paper downloaded from Azzalini's web
!                 site.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.3
!     ORIGINAL VERSION--MARCH     2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!               ***************************************
!               **  STEP 1--                         **
!               **  CHECK INPUT ARGUMENTS FOR ERRORS **
!               ***************************************
!
      IF(X.LE.0.0)THEN
        CDF=0.0
        GO TO 9000
      ENDIF
      IF(NU.LE.0)THEN
        WRITE(ICOUT,7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)NU
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9000
      ENDIF
      IF(SD.LE.0.0)THEN
        WRITE(ICOUT,6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,45)SD
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9000
      ENDIF
    6 FORMAT('**** ERROR: ARGUMENT FOR THE THIRD SHAPE PARAMETER OF ',   &
             'THE LOG-SKEW-T CDF IS NON-POSITIVE.')
    7 FORMAT('**** ERROR: ARGUMENT FOR THE FIRST (DEGREES OF ',   &
             'FREEDOM) SHAPE PARAMETER OF')
    8 FORMAT('     THE LOG-SKEW-T CDF IS NON-POSITIVE.')
   45 FORMAT('     VALUE OF THE ARGUMENT IS ',G15.7)
   46 FORMAT('     VALUE OF THE ARGUMENT IS ',I8)
!
!               ************************************
!               **  STEP 2--                      **
!               **  COMPUTE THE DENSITY FUNCTION  **
!               ************************************
!
      CALL STCDF(LOG(X)/SD,NU,ALMBDA,CDF)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE LSTCDF
      SUBROUTINE LSTPDF(X,NU,ALMBDA,SD,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE LOG-SKEW-T DISTRIBUTION
!              WITH SHAPE PARAMETERS = NU, LAMBDA AND SD (SD IS THE
!              SCALE PARAMETER OF THE CORRESPONDING T DISTRIBUTION).
!              THIS DISTRIBUTION IS DEFINED FOR POSITIVE X AND HAS
!              THE PROBABILITY DENSITY FUNCTION
!                 LSTPDF(X,NU,LAMBDA,SD) = (1/(SD*X))*
!                             STPDF(LOG(X)/SD,NU,LAMBDA,SD)
!              WITH SNPDF DENOTING THE SKEW-T PROBABILITY
!              DENSITY FUNCTION.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE NON-NEGATIVE.
!                     --NU     = THE FIRST SHAPE PARAMETER
!                     --ALMBDA = THE SECOND SHAPE PARAMETER
!                     --SD     = THE THIRD SHAPE PARAMETER
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE LOG-SKEWED-T DISTRIBUTION
!             WITH SHAPE PARAMETERS = NU, LAMBDA, AND SD.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--STPDF
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 JOHN WILEY, 1994, PAGE 454.
!               --"Log-Skew-Normal and Log-Skew-t Distributions as
!                 Models for Family Income Data", Azzalini, Cappello,
!                 and Kotz, paper downloaded from Azzalini's web
!                 site.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.3
!     ORIGINAL VERSION--MARCH     2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!               ***************************************
!               **  STEP 1--                         **
!               **  CHECK INPUT ARGUMENTS FOR ERRORS **
!               ***************************************
!
      IF(X.LE.0.0)THEN
        PDF=0.0
        GO TO 9000
      ENDIF
      IF(NU.LE.0)THEN
        WRITE(ICOUT,7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)NU
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9000
      ENDIF
      IF(SD.LE.0.0)THEN
        WRITE(ICOUT,6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,45)SD
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9000
      ENDIF
    6 FORMAT('**** ERROR: ARGUMENT FOR THE THIRD SHAPE PARAMETER OF ',   &
             'THE LOG-SKEW-T PDF IS NON-POSITIVE.')
    7 FORMAT('**** ERROR: ARGUMENT FOR THE FIRST (DEGREES OF ',   &
             'FREEDOM) SHAPE PARAMETER OF')
    8 FORMAT('     THE LOG-SKEW-T PDF IS NON-POSITIVE.')
   45 FORMAT('     VALUE OF THE ARGUMENT IS ',G15.7)
   46 FORMAT('     VALUE OF THE ARGUMENT IS ',I8)
!
!               ************************************
!               **  STEP 2--                      **
!               **  COMPUTE THE DENSITY FUNCTION  **
!               ************************************
!
      CALL STPDF(LOG(X)/SD,NU,ALMBDA,PDF)
      PDF=(1.0/(SD*X))*PDF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE LSTPDF
      SUBROUTINE LSTPPF(P,NU,ALMBDA,SD,PPF)
