        WRITE(ICOUT,46)NU
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9000
      ENDIF
      IF(SD.LE.0.0)THEN
        WRITE(ICOUT,6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,45)SD
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9000
      ENDIF
    6 FORMAT('**** ERROR: ARGUMENT FOR THE THIRD SHAPE PARAMETER OF ',   &
             'THE LOG-SKEW-T PPF IS NON-POSITIVE.')
    7 FORMAT('**** ERROR: ARGUMENT FOR THE FIRST (DEGREES OF ',   &
             'FREEDOM) SHAPE PARAMETER OF')
    8 FORMAT('     THE LOG-SKEW-T PPF IS NON-POSITIVE.')
   45 FORMAT('     VALUE OF THE ARGUMENT IS ',G15.7)
   46 FORMAT('     VALUE OF THE ARGUMENT IS ',I8)
!
      CALL STPPF(P,NU,ALMBDA,PPF2)
      PPF=EXP(PPF2*SD)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE LSTPPF
      SUBROUTINE LSTRAN(N,NU,ALMBDA,SD,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE LOG-SKEWED-T DISTRIBUTION
!              WITH SHAPE PARAMETERS = NU, ALMBDA AND SD.
!              THIS DISTRIBUTION IS DEFINED FOR POSITIVE X.
!              LOG-SKEWED-T RANDOM NUMBERS ARE FOUND BY
!              EXPONENTIATING SKEW-NORMAL RANDOM NUMBERS.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --NU     = THE FIRST SHAPE (PARAMETER) FOR THE
!                                LOG-SKEWED-T DISTRIBUTION.
!                     --ALMBDA = THE SECOND SHAPE (PARAMETER) FOR THE
!                                LOG-SKEWED-T DISTRIBUTION.
!                     --SD     = THE THIRD SHAPE (PARAMETER) FOR THE
!                                LOG-SKEWED-T DISTRIBUTION.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE LOG-SKEWED-T DISTRIBUTION
!             WITH SHAPE PARAMETERS = NU, ALMBDA, AND SD.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --ALMBDA CAN BE ANY REAL NUMBER.
!     OTHER DATAPAC   SUBROUTINES NEEDED--STRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON, KOTZ, AND BALAKRISHNAN, "CONTINUOUS
!                 UNIVARIATE DISTRIBUTIONS--VOLUME I", SECOND EDITION,
!                 JOHN WILEY, 1994, PAGE 454.
!               --"Log-Skew-Normal and Log-Skew-t Distributions as
!                 Models for Family Income Data", Azzalini, Cappello,
!                 and Kotz, paper downloaded from Azzalini's web
!                 site.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATION INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATION INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004.3
!     ORIGINAL VERSION--MARCH     2004.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
      IF(NU.LE.0)THEN
        WRITE(ICOUT,7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)NU
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
      IF(SD.LE.0.0)THEN
        WRITE(ICOUT,9)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,45)SD
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    5 FORMAT('***** ERROR--FOR THE LOG-SKEWED-T DISTRIBUTION,')
    6 FORMAT('       THE REQUESTED NUMBER OF RANDOM NUMBERS WAS ',   &
            'NON-POSITIVE.')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,' *****')
    7 FORMAT('**** ERROR: ARGUMENT FOR THE FIRST (DEGREES OF ',   &
             'FREEDOM) SHAPE PARAMETER OF')
    8 FORMAT('     THE LOG-SKEW-T CDF IS NON-POSITIVE.')
    9 FORMAT('**** ERROR: ARGUMENT FOR THE THIRD SHAPE PARAMETER OF ',   &
             'THE LOG-SKEW-T CDF IS NON-POSITIVE.')
   45 FORMAT('     VALUE OF THE ARGUMENT IS ',G15.7)
!
!     TRANSFORM SKEWED T RANDOM NUMBERS
!
      CALL STRAN(N,NU,ALMBDA,ISEED,X)
!
      DO 100 I=1,N
        X(I)=EXP(SD*X(I))
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE LSTRAN
      subroutine ma(x, n, len, ave)
!
!  This routine is part of the Bill Cleveland seasonal loess
!  program.
!
      integer n, len, i, j, k, m, newn
      real x(n), ave(n), flen, v
      newn = n-len+1
      flen = real(len)
      v = 0.0
      do 23083 i = 1,len
      v = v+x(i)
23083 continue
      ave(1) = v/flen
      if(.not.(newn .gt. 1))go to 23085
      k = len
      m = 0
      do 23087 j = 2, newn
      k = k+1
      m = m+1
      v = v-x(m)+x(k)
      ave(j) = v/flen
23087 continue
23085 continue
      return
      end
      SUBROUTINE MAD(X,N,IWRITE,XTEMP,XTEMP2,MAXNXT,XMAD,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE
!              SAMPLE MEDIAN ABSOLUTE DEVIATION (WITH DENOMINATOR N)
!              OF THE DATA IN THE INPUT VECTOR X.
!              THE SAMPLE MEDIAN ABSOLUTE DEVIATION = (THE MEDIAN OF
!              THE ABSOLUTE DEVIATIONS ABOUT THE SAMPLE MEDIAN) / N).
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!     OUTPUT ARGUMENTS--XMAD    = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SAMPLE MEDIAN ABSOLUTE DEVIATION.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE MEDIAN ABSOLUTE DEVIATION (WITH DENOMINATOR N-1).
!     OTHER DATAPAC   SUBROUTINES NEEDED--MEDIAN AND SORT.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--MOSTELLER AND TUKEY, 'DATA ANALYSIS AND REGRESSION'
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--95/3
!     ORIGINAL VERSION--MARCH     1995.
!     UPDATED         --JULY      2010. ADD EXTRA DUMMY ARRAY SO
!                                       DON'T HAVE TO MODIFY ORIGINAL
!                                       X ARRAY
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRIT2
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION XTEMP(*)
      DIMENSION XTEMP2(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='MAD '
      ISUBN2='    '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF MAD--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,N
   52   FORMAT('IBUGA3,N = ',A4,2X,I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I)
   56     FORMAT('I,X(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ******************************************
!               **  COMPUTE MEDIAN ABSOLUTE DEVIATION  **
!               ******************************************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN MEDIAN ABSOLUTE DEVIATION--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE RESPONSE VARIABLE HAS LESS THAN ONE ',   &
               'OBSERVATION.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        XMAD=CPUMIN
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(N.EQ.1)THEN
        XMAD=0.0
        GO TO 9000
      ENDIF
!
      HOLD=X(1)
      DO 135 I=2,N
        IF(X(I).NE.HOLD)GO TO 139
  135 CONTINUE
      XMAD=0.0
      GO TO 9000
  139 CONTINUE
!
!               ***********************************************
!               **  STEP 2--                                 **
!               **  COMPUTE THE MEDIAN ABSOLUTE DEVIATION.   **
!               ***********************************************
!
      IWRIT2='OFF'
      CALL MEDIAN(X,N,IWRIT2,XTEMP,MAXNXT,XMED,IBUGA3,IERROR)
!
      DO 300 I=1,N
        XTEMP2(I)=ABS(X(I)-XMED)
  300 CONTINUE
      CALL MEDIAN(XTEMP2,N,IWRIT2,XTEMP,MAXNXT,XMAD,IBUGA3,IERROR)
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,811)N,XMAD
  811   FORMAT('THE MEDIAN ABSOLUTE DEVIATION OF THE ',I8,   &
               ' OBSERVATIONS = ',E15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF MAD--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGA3,IERROR,N,XMED,XMAD
 9012   FORMAT('IBUGA3,IERROR,N,XMED,XMAD = ',A4,2X,A4,2X,I8,2G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE MAD
      SUBROUTINE MAHDIS(AMAT1,AMAT2,AMAT3,MAXROM,MAXCOM,NR1,NC1,   &
      Y1,Y2,INDEX,DMEAN,   &
      ICASE,IWRITE,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE
!              MAHALONBIS DISTANCE OF A MATRIX.
!     INPUT  ARGUMENTS--AMAT1  = THE SINGLE PRECISION MATRIX
!                     --MAXROM = THE INTEGER ROW DIMENSION OF AMAT
!                     --MAXCOM = THE INTEGER COUMN DIMENSION OF AMAT
!                     --NR1    = THE INTEGER NUMBER OF ROWS OF AMAT
!                     --NC1    = THE INTEGER NUMBER OF COLUMNS OF AMAT
!     OUTPUT ARGUMENTS--AMAT3    = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED MAHALANOBIS DISTANCE MATRIX.
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             MAHALANOBIS DISTANCE MATRIX.
!     NOTE--THIS ROUTINE ASSUMES THE ERROR CHECKING (FOR EQUAL
!           ROWS AND COLUMNS, MATCHING DIMENSIONS FOR X AND AMAT)
!           IS DONE BT THE CALLING SUBROUTINE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--98.7
!     ORIGINAL VERSION--JULY      1998.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASE
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION AMAT1(MAXROM,MAXCOM)
      DIMENSION AMAT2(MAXROM,MAXCOM)
      DIMENSION AMAT3(MAXROM,MAXCOM)
      DIMENSION Y1(*)
      DIMENSION Y2(*)
      DIMENSION INDEX(*)
      DOUBLE PRECISION DMEAN(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='MAHD'
      ISUBN2='IS  '
      IWRITE='NO'
      IERROR='NO'
!
      IF(IBUGA3.EQ.'OFF')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF MAHDIS--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IBUGA3,ICASE
   52 FORMAT('IBUGA3,ICASE = ',2A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)NR1,NC1
   53 FORMAT('NR1, NC1 = ',2I8)
      CALL DPWRST('XXX','BUG ')
   90 CONTINUE
!
!               **********************************
!               **  COMPUTE MAHALNOBIS DISTANCE **
!               **********************************
!
      IF(ICASE.EQ.'COLU')THEN
        CALL VARCOV(AMAT1,AMAT2,MAXROM,MAXCOM,NR1,NC1,DMEAN,   &
                  ICASE,IBUGA3,IERROR)
         CALL SGECO(AMAT2,MAXROM,NC1,INDEX,RCOND,Y1)
!
         IF(1.0+RCOND.EQ.1.0)THEN
           WRITE(ICOUT,999)
           CALL DPWRST('XXX','BUG ')
           WRITE(ICOUT,5171)
           CALL DPWRST('XXX','ERRO ')
           WRITE(ICOUT,5172)
           CALL DPWRST('XXX','ERRO ')
           WRITE(ICOUT,5173)
           CALL DPWRST('XXX','ERRO ')
           IERROR='YES'
           GO TO 9000
         ENDIF
 5171 FORMAT('*** ERROR FROM MAHDIS: UNABLE TO COMPUTE THE INVERSE OF ',   &
             'THE COVARIANCE MATRIX.')
 5172 FORMAT('    PROBLEM: SOME ROWS ARE LINEARLY DEPDENDENT ON OTHER',   &
             ' ROWS.')
 5173 FORMAT('    SUGGESTED SOLUTION: WORK WITH A SUBSET OF THE ',   &
             'ORIGINAL ROWS.')
!
         IJOB=1
         CALL SGEDI(AMAT2,MAXROM,NR1,INDEX,Y1,Y2,IJOB)
         DO 5111 I=1,NC1
           DO 5113 J=1,I
             IF(I.EQ.J)THEN
               AMAT3(I,I)=0.0
             ELSE
               DO 5117 K=1,NR1
                 Y1(K)=AMAT1(K,I)-AMAT1(K,J)
 5117          CONTINUE
               CALL QUAFRM(AMAT2,MAXROM,MAXCOM,NR1,NR1,Y1,IWRITE,   &
                           XQUAD,IBUGA3,IERROR)
               AMAT3(I,J)=XQUAD
               AMAT3(J,I)=XQUAD
             ENDIF
 5113      CONTINUE
 5111    CONTINUE
      ELSE
        CALL VARCOV(AMAT1,AMAT2,MAXROM,MAXCOM,NR1,NC1,DMEAN,   &
                  ICASE,IBUGA3,IERROR)
         CALL SGECO(AMAT2,MAXROM,NR1,INDEX,RCOND,Y1)
!
         IF(1.0+RCOND.EQ.1.0)THEN
           WRITE(ICOUT,999)
           CALL DPWRST('XXX','BUG ')
           WRITE(ICOUT,6171)
           CALL DPWRST('XXX','ERRO ')
           WRITE(ICOUT,6172)
           CALL DPWRST('XXX','ERRO ')
           WRITE(ICOUT,6173)
           CALL DPWRST('XXX','ERRO ')
           IERROR='YES'
           GO TO 9000
         ENDIF
 6171 FORMAT('*** ERROR FROM MAHDIS: UNABLE TO COMPUTE THE INVERSE OF ',   &
             'THE COVARIANCE MATRIX.')
 6172 FORMAT('    PROBLEM: SOME ROWS ARE LINEARLY DEPDENDENT ON OTHER',   &
             ' ROWS.')
 6173 FORMAT('    SUGGESTED SOLUTION: WORK WITH A SUBSET OF THE ',   &
             'ORIGINAL ROWS.')
!
         IJOB=1
         CALL SGEDI(AMAT2,MAXROM,NR1,INDEX,Y1,Y2,IJOB)
         DO 6111 I=1,NR1
           DO 6113 J=1,I
             IF(I.EQ.J)THEN
               AMAT3(I,I)=0.0
             ELSE
               DO 6117 K=1,NC1
                 Y1(K)=AMAT1(I,K)-AMAT1(J,K)
 6117          CONTINUE
               CALL QUAFRM(AMAT2,MAXROM,MAXCOM,NC1,NC1,Y1,IWRITE,   &
                           XQUAD,IBUGA3,IERROR)
               AMAT3(I,J)=XQUAD
               AMAT3(J,I)=XQUAD
             ENDIF
 6113      CONTINUE
 6111    CONTINUE
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF MAHDIS--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGA3,IERROR
 9012 FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)NR1,NC1
 9013 FORMAT('NR1,NC1 = ',2I8)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE MAHDIS
