!
!CCCC THE FOLLOWING SECTION WAS MOVED HERE TO BE FIRST   MAY 1992 (JJF)
!CCCC TO AVOID MISPROCESSING OF   LET FUNCTION A = FIT   MAY 1992 (JJF)
!               ***********************************
!               **  TREAT THE LET FUNCTION CASE  **
!               ***********************************
!
!CCCC APRIL 1996.  IF ENTERED AS LET STRING, PRESERVE CASE.  IF
!CCCC ENTERED AS LET FUNCTION, CONVERT TO UPPER CASE
      IF(NUMARG.GE.1.AND.ICOM.EQ.'LET'.AND.   &
      IHARG(1).EQ.'FUNC'.AND.IHARG2(1).EQ.'TION')THEN
        ISFLAG='FUNCTION'
        GO TO 1800
      ELSEIF(NUMARG.GE.1.AND.ICOM.EQ.'LET'.AND.   &
      IHARG(1).EQ.'STRI'.AND.IHARG2(1).EQ.'NG')THEN
        ISFLAG='STRING'
        GO TO 1800
      ELSE
        GO TO 1899
      ENDIF
!
 1800 CONTINUE
