!
!              ONE WAY ANOVA Y X
!              ONE WAY RANDOM EFFECTS ANOVA Y X
!              ONE WAY SUMMARY ANOVA Y X
!              ONE WAY SUMMARY RANDOM EFFECTS ANOVA Y X
!              TWO WAY ANOVA Y X
!              TWO WAY RANDOM EFFECTS ANOVA Y X
!              TWO WAY SUMMARY ANOVA Y X
!              TWO WAY SUMMARY RANDOM EFFECTS ANOVA Y X
!
      IF((ICOM.EQ.'ANAL' .OR. ICOM.EQ.'ANOV') .OR.   &
         (IHARG(1).EQ.'ANOV' .OR. IHARG(1).EQ.'ANAL') .OR.   &
         (IHARG(2).EQ.'ANOV' .OR. IHARG(2).EQ.'ANAL') .OR.   &
         (IHARG(3).EQ.'ANOV' .OR. IHARG(3).EQ.'ANAL') .OR.   &
         (IHARG(4).EQ.'ANOV' .OR. IHARG(4).EQ.'ANAL') .OR.   &
         (IHARG(5).EQ.'ANOV' .OR. IHARG(5).EQ.'ANAL'))THEN
