!
      IF(ICOM.EQ.'LOWE')THEN
        IF(IHARG(1).EQ.'TAIL')GO TO 1199
        IF(IHARG(1).EQ.'PRED')GO TO 1199
        IF(IHARG(1).EQ.'COEF' .AND. IHARG(2).EQ.'OF  '.AND.   &
           IHARG(3).EQ.'VARI')GO TO 1199
        IF(IHARG(1).EQ.'COEF' .AND. IHARG(2).EQ.'OF  '.AND.   &
           IHARG(3).EQ.'DISP')GO TO 1199
        IF(IHARG(1).EQ.'ONE ' .AND. IHARG(2).EQ.'SIDE')GO TO 1199
        GO TO 1100
      ENDIF
      IF(ICOM.EQ.'LOES')GO TO 1100
      IF(ICOM.EQ.'SEAS')GO TO 1100
      GO TO 1199
!
 1100 CONTINUE
      ICASAN='LOWF'
!CCCC MARCH 1994.  ADD ARGUMENT.
!CCCC CALL DPLOW(ALOWFR,
      CALL DPLOW(ALOWFR,ALOWDG,ICAPSW,IFORSW,   &
                 TEMP,TEMP2,XTEMP1,XTEMP2,MAXNXT,   &
                 IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
      IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      GO TO 9000
!
 1199 CONTINUE
!
!               ************************************************
!               **  TREAT THE ORTHOGONAL DISTANCE FIT   CASE  **
!               ************************************************
!
      IF(ICOM.EQ.'ORTH'.AND.NUMARG.GE.2.AND.IHARG(1).EQ.'DIST')THEN
        IF(IHARG(2).EQ.'FIT' .OR. IHARG(2).EQ.'REGR')THEN
          ICASAN='ORTF'
          CALL DPORTH(IBUGA2,IBUGA3,IBUGCO,IBUGEV,IBUGQ,ISUBRO,   &
                      IFOUND,IERROR)
          IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
        ENDIF
      ENDIF
!
!               ******************************
!               **  TREAT THE ... FIT CASE  **
!               ******************************
!
!CCCC THE FOLLOWING 8 LINES WERE ADDED JUNE 1989
      IF(ICOM.EQ.'BOOT')GO TO 1799
      IF(ICOM.EQ.'DEMI')GO TO 1799
      IF(ICOM.EQ.'2**K'.AND.NUMARG.GE.1.AND.IHARG(1).EQ.'FIT')GO TO 1799
      IF(ICOM.EQ.'2**K'.AND.NUMARG.GE.2.AND.IHARG(2).EQ.'FIT')GO TO 1799
      IF(ICOM.EQ.'DEX'.AND.NUMARG.GE.1.AND.IHARG(1).EQ.'FIT')GO TO 1799
      IF(ICOM.EQ.'DEX'.AND.NUMARG.GE.2.AND.IHARG(2).EQ.'FIT')GO TO 1799
      IF(ICOM.EQ.'BEST'.AND.NUMARG.GE.2.AND.   &
         IHARG(1).EQ.'DIST'.AND.IHARG(2).EQ.'FIT')GO TO 1799
      IF(IHARG(1).EQ.'BEST'.AND.   &
         IHARG(2).EQ.'DIST'.AND.IHARG(3).EQ.'FIT')GO TO 1799
!
      IF(ICOM.EQ.'FIT ')GO TO 1700
!CCCC CHECK FOR "RECIPE FIT" AND "SIMCOV FIT" CASES.  SEPTEMBER 1997
      IF(NUMARG.GE.1.AND.ICOM.NE.'SPLI'.AND.ICOM.NE.'PRE '.AND.      &
         ICOM.NE.'LOWE'.AND.ICOM.NE.'RECI'.AND.ICOM.NE.'SIMC'.AND.   &
         IHARG(1).EQ.'FIT ')GO TO 1700
      DO 1710 I=2,5
        IM1=I-1
        IF(NUMARG.GE.I.AND.IHARG(IM1).NE.'SPLI'.AND.                 &
           IHARG(1).NE.'PRE '.AND.IHARG(IM1).NE.'OF'.AND.            &
           IHARG(IM1).NE.'DEMI'.AND.IHARG(I).EQ.'FIT ')GO TO 1700
 1710 CONTINUE
      GO TO 1799
!
 1700 CONTINUE
      ICASAN='FIT'
      CALL DPFIT(ICAPSW,IFORSW,   &
                 IBUGA2,IBUGA3,IBUGCO,IBUGEV,IBUGQ,ISUBRO,   &
                 IFOUND,IERROR)
      IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
!     GO TO 9000
!
 1799 CONTINUE
!
!               ******************************
!               **  TREAT THE BEST CP CASE  **
!               ******************************
!
      IF(ICOM.EQ.'BEST'.AND.NUMARG.GE.1.AND.   &
      IHARG(1).EQ.'CP  ')THEN
        ICASAN='CP'
        CALL DPBECP(ICAPSW,IFORSW,   &
                    IBUGA2,IBUGA3,IBUGCO,IBUGEV,IBUGQ,ISUBRO,   &
                    IFOUND,IERROR)
        IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!               ******************************
!               **  TREAT THE BOOTSTRAP FIT **
!               ******************************
!
      IF(ICOM.EQ.'BOOT'.AND.NUMARG.GE.1.AND.IHARG(1).EQ.'FIT ')THEN
        ICASAN='BFIT'
        CALL DPBOFI(ICAPSW,IFORSW,ISEED,IBOOSS,                 &
                    IBUGA2,IBUGA3,IBUGCO,IBUGEV,IBUGQ,ISUBRO,   &
                    IFOUND,IERROR)
        IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ELSEIF(ICOM.EQ.'BOOT'.AND.NUMARG.GE.2.AND.                &
             IHARG(1).EQ.'REPL'.AND.IHARG(2).EQ.'FIT ')THEN
        ICASAN='BFIT'
        CALL DPBOFI(ICAPSW,IFORSW,ISEED,IBOOSS,                 &
                    IBUGA2,IBUGA3,IBUGCO,IBUGEV,IBUGQ,ISUBRO,   &
                    IFOUND,IERROR)
        IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!               ******************************
!               **  TREAT THE DEMING    FIT **
!               ******************************
!
      IF(ICOM.EQ.'DEMI'.AND.NUMARG.GE.1.AND.                            &
         (IHARG(1).EQ.'FIT ' .OR. IHARG(1).EQ.'REGR'))THEN
        ICASAN='DFIT'
        CALL DPDFIT(ICAPSW,IFORSW,                                      &
                    IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
        IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ELSEIF(ICOM.EQ.'REPL'.AND.NUMARG.GE.2.AND.IHARG(1).EQ.'DEMI'.AND. &
         (IHARG(2).EQ.'FIT ' .OR. IHARG(2).EQ.'REGR'))THEN
        ICASAN='DFIT'
        CALL DPDFIT(ICAPSW,IFORSW,                                      &
                    IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
        IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ELSEIF(ICOM.EQ.'WEIG'.AND.NUMARG.GE.2.AND.IHARG(1).EQ.'DEMI'.AND. &
         (IHARG(2).EQ.'FIT '.OR.IHARG(2).EQ.'REGR'))THEN
        ICASAN='DFIT'
        CALL DPDFIT(ICAPSW,IFORSW,                                      &
                    IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
        IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ELSEIF(ICOM.EQ.'WEIG'.AND.NUMARG.GE.3.AND.IHARG(1).EQ.'REPL'.AND. &
        IHARG(2).EQ.'DEMI'.AND.                                         &
        (IHARG(3).EQ.'FIT ' .OR. IHARG(3).EQ.'REGR'))THEN
        ICASAN='DFIT'
        CALL DPDFIT(ICAPSW,IFORSW,                                      &
                    IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
        IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ELSEIF(ICOM.EQ.'REPL'.AND.NUMARG.GE.3.AND.IHARG(1).EQ.'WEIG'.AND. &
        IHARG(2).EQ.'DEMI'.AND.                                         &
        (IHARG(3).EQ.'FIT ' .OR. IHARG(3).EQ.'REGR'))THEN
        ICASAN='DFIT'
        CALL DPDFIT(ICAPSW,IFORSW,                                      &
                    IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
        IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!               *********************************************
!               **  TREAT THE ORDINARY LEAST PRODUCTS  FIT **
!               *********************************************
!
      IF(ICOM.EQ.'ORDI'.AND.NUMARG.GE.3.AND.                         &
         IHARG(1).EQ.'LEAS' .AND. IHARG(2).EQ.'PROD' .AND.           &
         (IHARG(3).EQ.'FIT ' .OR. IHARG(3).EQ.'REGR'))THEN
        ICASAN='OLPF'
        CALL DPOLPF(ICAPSW,IFORSW,ISEED,IBOOSS,                      &
                    IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
        IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS COMMENTED OUT HERE    MAY 1992 (JJF)
!CCCC AND MOVED UP TO THE TOP OF THIS SUBROUTINE      MAY 1992 (JJF)
!CCCC TO FIX MISPROCESSING OF    LET STRING A = FIT   MAY 1992 (JJF)
!CCCC           ***********************************
!CCCC           **  TREAT THE LET FUNCTION CASE  **
!CCCC           ***********************************
!CCCC
!CCCC IF(NUMARG.GE.1.AND.ICOM.EQ.'LET'.AND.
!CCCC1IHARG(1).EQ.'FUNC'.AND.IHARG2(1).EQ.'TION')GO TO 1800
!CCCC IF(NUMARG.GE.1.AND.ICOM.EQ.'LET'.AND.
!CCCC1IHARG(1).EQ.'STRI'.AND.IHARG2(1).EQ.'NG')GO TO 1800
!CCCC GO TO 1899
!CCCC
!1800 CONTINUE
!CCCC ICASAN='LETF'
!CCCC CALL DPLETF(IANGLU,IBUGA2,IBUGA3,IBUGCO,IBUGEV,IBUGQ,ISUBRO,
!CCCC1IFOUND,IERROR)
!CCCC IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
!CCCC
!1899 CONTINUE
!
!               **************************
!               **  TREAT THE LET CASE  **
!               **************************
!
      IF(NUMARG.GE.1.AND.ICOM.EQ.'LET')THEN
        ICASAN='LET'
        CALL DPLET(IANGLU,ISEED,IBUGA2,IBUGA3,IBUGCO,IBUGEV,IBUGQ,   &
                   TEMP,TEMP2,XTEMP1,XTEMP2,MAXNXT,   &
                   IFTEXP,IFTORD,IFORSW,IOSMET,   &
                   ROOTAC,OPTACC,IOPTME,IOPTHE,   &
                   ISUBRO,IFOUND,IERROR)
        IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS REWRITTEN      JULY 1995
!               ************************************
!               **  TREAT THE MEDIAN POLISH CASE  **
!               ************************************
!
      IF(ICOM.EQ.'MEDI'.AND.   &
         NUMARG.GE.1.AND.IHARG(1).EQ.'POLI'.AND.   &
         IHARG2(1).EQ.'SH  ')THEN
         ICASAN='MEPO'
         CALL DPMEPO(ICAPSW,IFORSW,   &
                     IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED      JULY 1995
!               **********************************************
!               **  TREAT THE MANDEL (2-WAY) ANALYSIS CASE  **
!               **********************************************
!
!CCCC APRIL 1996.  FOLLOWING CODE IS NOT WORKING YET
!CCCC OCTOBER 2000.  UPDATE (CALL IT CONCENSUS MEANS OR
!CCCC MANDEL-PAULE, IT IMPLEMENTS BOTH MANDEL-PAULE AND
!CCCC MARK VANGEL'S MAXIMUM LIKELIHOOD APPROACH).
!
      IF(ICOM.EQ.'MAND'.AND.NUMARG.GE.1.AND.IHARG(1).EQ.'PAUL')THEN
         ICASAN='MAND'
         CALL DPMAND(ICAPSW,IFORSW,ISEED,IBOOSS,   &
                     ISUBRO,IBUGA2,IBUGA3,IBUGQ,IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
      IF(ICOM.EQ.'CONS'.AND.NUMARG.GE.1.AND.IHARG(1).EQ.'MEAN')THEN
         ICASAN='MAND'
         CALL DPMAND(ICAPSW,IFORSW,ISEED,IBOOSS,   &
                     ISUBRO,IBUGA2,IBUGA3,IBUGQ,IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED      NOVEMBER 2024
!               **********************************************
!               **  TREAT THE POSITION EFFECT TEST    CASE  **
!               **********************************************
!
      IF(ICOM.EQ.'POSI'.AND.NUMARG.GE.1.AND.IHARG(1).EQ.'EFFE')THEN
         ICASAN='POEF'
         CALL DPPETE(ICAPSW,IFORSW,ISUBRO,   &
                     IBUGA2,IBUGA3,IBUGQ,IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED      FEBRUARY 2005
!               **********************************************
!               **  TREAT THE E691 INTERLAB           CASE  **
!               **********************************************
!
      IF(ICOM.EQ.'E691'.AND.NUMARG.GE.2.AND.IHARG(1).EQ.'INTE'.AND.   &
         IHARG(2).EQ.'ANAL')THEN
         ICASAN='E691'
         CALL DPEINL(ICAPSW,IFORSW,ISUBRO,   &
                     IBUGA2,IBUGA3,IBUGQ,IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ELSEIF(ICOM.EQ.'E691'.AND.NUMARG.GE.1.AND.IHARG(1).EQ.'INTE')THEN
         ICASAN='E691'
         CALL DPEINL(ICAPSW,IFORSW,ISUBRO,   &
                     IBUGA2,IBUGA3,IBUGQ,IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED      OCTOBER 2008
!               **************************************************
!               **  TREAT THE ONE SAMPLE PROFICIENCY TEST CASE  **
!               **************************************************
!
      IF(ICOM.EQ.'ONE '.AND.NUMARG.GE.3.AND.IHARG(1).EQ.'SAMP'.AND.   &
         IHARG(2).EQ.'PROF'.AND.IHARG(3).EQ.'TEST')THEN
         ICASAN='1SPT'
         ISHIFT=3
         CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                       IBUGA2,IERROR)
         CALL DP1IPT(ICAPSW,IFORSW,ISUBRO,   &
                     IBUGA2,IBUGA3,IBUGQ,IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ELSEIF(ICOM.EQ.'ONE '.AND.NUMARG.GE.2.AND.IHARG(1).EQ.'SAMP'.AND.   &
             IHARG(2).EQ.'PROF')THEN
         ICASAN='1SPT'
         ISHIFT=2
         CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                       IBUGA2,IERROR)
         CALL DP1IPT(ICAPSW,IFORSW,ISUBRO,   &
                     IBUGA2,IBUGA3,IBUGQ,IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED      OCTOBER 2008
!               **************************************************
!               **  TREAT THE TWO SAMPLE PROFICIENCY TEST CASE  **
!               **************************************************
!
      IF(ICOM.EQ.'TWO '.AND.NUMARG.GE.3.AND.IHARG(1).EQ.'SAMP'.AND.   &
         IHARG(2).EQ.'PROF'.AND.IHARG(3).EQ.'TEST')THEN
         ICASAN='2SPT'
         ISHIFT=3
         CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                       IBUGA2,IERROR)
         CALL DP2IPT(ICAPSW,IFORSW,ISUBRO,   &
                     IBUGA2,IBUGA3,IBUGQ,IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ELSEIF(ICOM.EQ.'TWO '.AND.NUMARG.GE.2.AND.IHARG(1).EQ.'SAMP'.AND.   &
             IHARG(2).EQ.'PROF')THEN
         ICASAN='2SPT'
         ISHIFT=2
         CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                       IBUGA2,IERROR)
         CALL DP2IPT(ICAPSW,IFORSW,ISUBRO,   &
                     IBUGA2,IBUGA3,IBUGQ,IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED      JANUARY 2009
!               **************************************************
!               **  TREAT THE LIMIT OF DETECTION          CASE  **
!               **************************************************
!
      IMULT='OFF'
      IREPL='OFF'
      IF(ICOM.EQ.'DIRT'.AND.NUMARG.GE.3.AND.IHARG(1).EQ.'LIMI'.AND.   &
         IHARG(2).EQ.'OF  '.AND.IHARG(3).EQ.'DETE')THEN
         ICASAN='LODD'
         ISHIFT=3
         CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                       IBUGA2,IERROR)
         CALL DPLODE(ICASAN,ICAPSW,IFORSW,IMULT,IREPL,   &
                     ISUBRO,IBUGA2,IBUGA3,IBUGQ,IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ELSEIF(ICOM.EQ.'CLEA'.AND.NUMARG.GE.3.AND.IHARG(1).EQ.'LIMI'.AND.   &
         IHARG(2).EQ.'OF  '.AND.IHARG(3).EQ.'DETE')THEN
         ICASAN='LODC'
         ISHIFT=3
         CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                       IBUGA2,IERROR)
         CALL DPLODE(ICASAN,ICAPSW,IFORSW,IMULT,IREPL,   &
                     ISUBRO,IBUGA2,IBUGA3,IBUGQ,IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ELSEIF(ICOM.EQ.'REPL'.AND.NUMARG.GE.3.AND.IHARG(1).EQ.'LIMI'.AND.   &
         IHARG(2).EQ.'OF  '.AND.IHARG(3).EQ.'DETE')THEN
         IREPL='ON'
         ICASAN='LODD'
         ISHIFT=3
         CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                       IBUGA2,IERROR)
         CALL DPLODE(ICASAN,ICAPSW,IFORSW,IMULT,IREPL,   &
                     ISUBRO,IBUGA2,IBUGA3,IBUGQ,IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ELSEIF(ICOM.EQ.'MULT'.AND.NUMARG.GE.3.AND.IHARG(1).EQ.'LIMI'.AND.   &
         IHARG(2).EQ.'OF  '.AND.IHARG(3).EQ.'DETE')THEN
         IMULT='ON'
         ICASAN='LODD'
         ISHIFT=3
         CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                       IBUGA2,IERROR)
         CALL DPLODE(ICASAN,ICAPSW,IFORSW,IMULT,IREPL,   &
                     ISUBRO,IBUGA2,IBUGA3,IBUGQ,IFOUND,IERROR)
      ELSEIF(ICOM.EQ.'LIMI'.AND.NUMARG.GE.2.AND.IHARG(1).EQ.'OF  '.AND.   &
             IHARG(2).EQ.'DETE')THEN
         ICASAN='LODD'
         ISHIFT=2
         CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                       IBUGA2,IERROR)
         CALL DPLODE(ICASAN,ICAPSW,IFORSW,IMULT,IREPL,   &
                     ISUBRO,IBUGA2,IBUGA3,IBUGQ,IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED      JULY 2003
!               **********************************************
!               **  TREAT THE LINEAR CALIBRATION      CASE  **
!               **********************************************
!
      IF(ICOM.EQ.'LINE'.AND.NUMARG.GE.1.AND.IHARG(1).EQ.'CALI')THEN
         ICASAN='LICA'
         CALL DPLICA(ICAPSW,IFORSW,ISEED,ISUBRO,IBUGA2,IBUGA3,IBUGQ,   &
                     IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED      JULY 2003
!               **********************************************
!               **  TREAT THE QUADRATIC CALIBRATION   CASE  **
!               **********************************************
!
      IF(ICOM.EQ.'QUAD'.AND.NUMARG.GE.1.AND.IHARG(1).EQ.'CALI')THEN
         ICASAN='QUCA'
         CALL DPLICA(ICAPSW,IFORSW,ISEED,ISUBRO,IBUGA2,IBUGA3,IBUGQ,   &
                     IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED      MARCH 2017
!               *****************************************************
!               **  TREAT THE K-MEANS        CLUSTER         CASE  **
!               **  TREAT THE NORMAL MIXTURE CLUSTER         CASE  **
!               *****************************************************
!
      IF(ICOM.EQ.'K   '.AND.NUMARG.GE.1.AND.IHARG(1).EQ.'MEAN')THEN
         ICASAN='KMEA'
         CALL DPKMEA(ICAPSW,IFORSW,ISEED,   &
                     IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ELSEIF(ICOM.EQ.'NORM'.AND.NUMARG.GE.1.AND.IHARG(1).EQ.'MIXT')THEN
         ICASAN='NMIX'
         CALL DPKMEA(ICAPSW,IFORSW,ISEED,   &
                     IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ELSEIF(ICOM.EQ.'K   '.AND.NUMARG.GE.1.AND.IHARG(1).EQ.'MEDO')THEN
         ICASAN='KMED'
         CALL DPKMEA(ICAPSW,IFORSW,ISEED,   &
                     IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ELSEIF(ICOM.EQ.'K   '.AND.NUMARG.GE.1.AND.IHARG(1).EQ.'MEDI')THEN
         ICASAN='KMED'
         CALL DPKMEA(ICAPSW,IFORSW,ISEED,   &
                     IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ELSEIF(ICOM.EQ.'SING'.AND.NUMARG.GE.1.AND.IHARG(1).EQ.'LINK')THEN
         ICASAN='SLIN'
         CALL DPKMEA(ICAPSW,IFORSW,ISEED,   &
                     IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ELSEIF(ICOM.EQ.'AGNE')THEN
         ICASAN='AGNE'
         CALL DPKMEA(ICAPSW,IFORSW,ISEED,   &
                     IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ELSEIF(ICOM.EQ.'DIAN')THEN
         ICASAN='DIAN'
         CALL DPKMEA(ICAPSW,IFORSW,ISEED,   &
                     IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ELSEIF(ICOM.EQ.'FANN' .OR. ICOM.EQ.'FUZZ')THEN
         ICASAN='FANN'
         CALL DPKMEA(ICAPSW,IFORSW,ISEED,   &
                     IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!
!               **********************************
!               **  TREAT THE ... PRE-FIT CASE  **
!               **********************************
!
      IF(NUMARG.GE.1.AND.ICOM.EQ.'PRE '.AND.IHARG(1).EQ.'FIT ')   &
      GO TO 2200
      DO 2210 I=2,5
      IM1=I-1
      IF(NUMARG.GE.I.AND.IHARG(IM1).EQ.'PRE '.AND.IHARG(I).EQ.'FIT ')   &
      GO TO 2200
 2210 CONTINUE
      IF(ICOM.EQ.'PREF')GO TO 2200
      DO 2220 I=1,4
      IF(NUMARG.GE.I.AND.IHARG(I).EQ.'PREF'.AND.   &
      IHARG2(I).EQ.'IT  ')GO TO 2200
 2220 CONTINUE
      GO TO 2299
!
 2200 CONTINUE
      ICASAN='PREF'
      CALL DPPREF(IBUGA2,IBUGA3,IBUGCO,IBUGEV,IBUGQ,ISUBRO,   &
                  IFOUND,IERROR)
      IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
!
 2299 CONTINUE
!
!               *********************************
!               **  TREAT THE ... SMOOTH CASE  **
!               *********************************
!
      IF(ICOM.EQ.'SMOO')GO TO 2300
      IF(ICOM.EQ.'LOW'.AND.NUMARG.GE.1.AND.IHARG(1).EQ.'PASS')GO TO 2300
      IF(ICOM.EQ.'HIGH'.AND.NUMARG.GE.1.AND.IHARG(1).EQ.'PASS')GO TO 2300
      DO 2310 I=1,3
      IF(NUMARG.GE.I.AND.IHARG(I).EQ.'SMOO'.AND.   &
      IHARG2(I).EQ.'TH  ')GO TO 2300
      IF(NUMARG.GE.I.AND.IHARG(I).EQ.'SMOO'.AND.   &
      IHARG2(I).EQ.'THIN')GO TO 2300
 2310 CONTINUE
      GO TO 2399
!
 2300 CONTINUE
      ICASAN='SMOO'
      CALL DPSMOO(IBUGA2,IBUGA3,IBUGQ,IFOUND,IERROR)
      IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
!
 2399 CONTINUE
!
!               *************************************
!               **  TREAT THE ... SPLINE FIT CASE  **
!               *************************************
!
      IF(NUMARG.GE.1.AND.ICOM.EQ.'SPLI'.AND.IHARG(1).EQ.'FIT ')   &
      GO TO 2400
      DO 2410 I=2,5
      IM1=I-1
      IF(NUMARG.GE.I.AND.IHARG(IM1).EQ.'SPLI'.AND.IHARG(I).EQ.'FIT ')   &
      GO TO 2400
 2410 CONTINUE
      GO TO 2499
!
 2400 CONTINUE
      ICASAN='SPLI'
      CALL DPSPL(IBUGA2,IBUGA3,IBUGQ,ISUBRO,   &
                 ICASAN,ICAPSW,IFORSW,   &
                 IFOUND,IERROR)
      IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      GO TO 9000
!
 2499 CONTINUE
!
!               ******************************
!               **  TREAT THE SUMMARY CASE  **
!               ******************************
!
      IF(ICOM.EQ.'SUMM' .OR. IHARG(1).EQ.'SUMM')THEN
        IF(IHARG(1).EQ.'HOMO'.AND.IHARG(2).EQ.'PLOT')GO TO 2599
        IF(IHARG(1).EQ.'SUBS'.AND.IHARG(2).EQ.'HOMO'.AND.   &
           IHARG(3).EQ.'PLOT')GO TO 2599
        IF(IHARG(1).EQ.'HIGH'.AND.IHARG(2).EQ.'HOMO'.AND.   &
           IHARG(3).EQ.'PLOT')GO TO 2599
        ICASAN='SUMM'
        CALL DPSUMM(XTEMP1,XTEMP2,MAXNXT,   &
                    ICASAN,ICAPSW,IFORSW,   &
                    IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
        IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
 2599 CONTINUE
!
!               ****************************************
!               **  TREAT THE FOLLOWING CASES:        **
!               **    1) PREDICTION LIMITS            **
!               **    2) PREDICTION BOUNDS            **
!               **    3) SD PREDICTION LIMITS         **
!               ****************************************
!
      IMULT='OFF'
      IREPL='OFF'
      IF(ICOM.EQ.'PRED' .OR. IHARG(1).EQ.'PRED' .OR.   &
         IHARG(2).EQ.'PRED' .OR. IHARG(3).EQ.'PRED' .OR.   &
         IHARG(4).EQ.'PRED' .OR. IHARG(5).EQ.'PRED' .OR.   &
         IHARG(6).EQ.'PRED' .OR. IHARG(7).EQ.'PRED')THEN
        CALL DPPRLI(XTEMP1,XTEMP2,MAXNXT,ICASAN,   &
                    ICAPSW,IFORSW,IMULT,IREPL,   &
                    ISUBRO,IBUGA2,IBUGA3,IBUGQ,IFOUND,IERROR)
        IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!               *****************************************
!               **  TREAT THE SD CONFIDENCE LIMIT CASE **
!               *****************************************
!
      IMULT='OFF'
      IREPL='OFF'
      IF(ICOM.EQ.'CONF' .OR. IHARG(1).EQ.'CONF' .OR.   &
         IHARG(2).EQ.'CONF' .OR. IHARG(3).EQ.'CONF' .OR.   &
         IHARG(4).EQ.'CONF' .OR. IHARG(5).EQ.'CONF')THEN
        CALL DPSDCI(XTEMP1,XTEMP2,MAXNXT,ICASAN,   &
                    ICAPSW,IFORSW,IMULT,IREPL,   &
                    ISUBRO,IBUGA2,IBUGA3,IBUGQ,IFOUND,IERROR)
        IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!               ***************************************************
!               **  TREAT THE COEF OF VARI CONFIDENCE LIMIT CASE **
!               **  TREAT THE COEF OF DISP CONFIDENCE LIMIT CASE **
!               ***************************************************
!
      IMULT='OFF'
      IREPL='OFF'
      IF(ICOM.EQ.'CONF' .OR. IHARG(1).EQ.'CONF' .OR.   &
         IHARG(2).EQ.'CONF' .OR. IHARG(3).EQ.'CONF' .OR.   &
         IHARG(4).EQ.'CONF' .OR. IHARG(5).EQ.'CONF' .OR.   &
         IHARG(6).EQ.'CONF' .OR. IHARG(7).EQ.'CONF')THEN
        CALL DPCVCI(XTEMP1,XTEMP2,MAXNXT,ICASAN,   &
                    ICAPSW,IFORSW,IMULT,IREPL,ISEED,   &
                    ISUBRO,IBUGA2,IBUGA3,IBUGQ,IFOUND,IERROR)
        IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!               *************************************************
!               **  TREAT THE BIWEIGHT CONFIDENCE LIMITS CASE  **
!               *************************************************
!
!     MARCH 2010: SUPPORT FOR "MULTIPLE" AND "REPLICATED" OPTIONS
!
      IMULT='OFF'
      IREPL='OFF'
      ISHIFT=0
      IF(ICOM.EQ.'BIWE')THEN
        IF(NUMARG.GE.2.AND.IHARG(1).EQ.'CONF' .AND.   &
          (IHARG(2).EQ.'LIMI'.OR.IHARG(2).EQ.'INTE'))THEN
          ISHIFT=2
        ENDIF
      ELSEIF(ICOM.EQ.'MULT' .AND. IHARG(1).EQ.'BIWE' .AND.   &
             IHARG(2).EQ.'CONF')THEN
        IMULT='ON'
        IF(NUMARG.GE.3.AND.   &
          (IHARG(3).EQ.'LIMI'.OR.IHARG(3).EQ.'INTE'))THEN
          ISHIFT=3
        ENDIF
      ELSEIF(ICOM.EQ.'REPL' .AND. IHARG(1).EQ.'BIWE' .AND.   &
             IHARG(2).EQ.'CONF')THEN
        IREPL='ON'
        IF(NUMARG.GE.3.AND.   &
          (IHARG(3).EQ.'LIMI'.OR.IHARG(3).EQ.'INTE'))THEN
          ISHIFT=3
        ENDIF
      ENDIF
!
      IF(ISHIFT.GT.0)THEN
        CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                    IBUGA2,IERROR)
        ICASAN='ONEV'
        CALL DPBWCO(XTEMP1,XTEMP2,MAXNXT,ICASAN,   &
                    ICAPSW,IFORSW,IMULT,IREPL,   &
                    ISUBRO,IBUGA2,IBUGA3,IBUGQ,IFOUND,IERROR)
        IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!               *****************************************************
!               **  TREAT THE TRIMMED MEAN CONFIDENCE LIMITS CASE  **
!               *****************************************************
!
!     MARCH 2010: SUPPORT FOR "MULTIPLE" AND "REPLICATED" OPTIONS
!
      IMULT='OFF'
      IREPL='OFF'
      ISHIFT=0
      IF(ICOM.EQ.'TRIM' .AND. IHARG(1).EQ.'MEAN')THEN
        IF(NUMARG.GE.3.AND.IHARG(2).EQ.'CONF' .AND.   &
          (IHARG(3).EQ.'LIMI'.OR.IHARG(3).EQ.'INTE'))THEN
          ISHIFT=3
        ENDIF
      ELSEIF(ICOM.EQ.'MULT' .AND. IHARG(1).EQ.'TRIM' .AND.   &
             IHARG(2).EQ.'MEAN' .AND. IHARG(3).EQ.'CONF')THEN
        IMULT='ON'
        IF(NUMARG.GE.4.AND.   &
          (IHARG(4).EQ.'LIMI'.OR.IHARG(4).EQ.'INTE'))THEN
          ISHIFT=4
        ENDIF
      ELSEIF(ICOM.EQ.'REPL' .AND. IHARG(1).EQ.'TRIM' .AND.   &
             IHARG(2).EQ.'MEAN' .AND. IHARG(3).EQ.'CONF')THEN
        IREPL='ON'
        IF(NUMARG.GE.4.AND.   &
          (IHARG(4).EQ.'LIMI'.OR.IHARG(4).EQ.'INTE'))THEN
          ISHIFT=4
        ENDIF
      ENDIF
!
      IF(ISHIFT.GT.0)THEN
        CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                    IBUGA2,IERROR)
        ICASAN='TMCI'
        CALL DPTMCO(XTEMP1,XTEMP2,MAXNXT,ICASAN,   &
                    ICAPSW,IFORSW,IMULT,IREPL,   &
                    ISUBRO,IBUGA2,IBUGA3,IBUGQ,IFOUND,IERROR)
        IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!               *****************************************************
!               **  TREAT THE MEDIAN       CONFIDENCE LIMITS CASE  **
!               **  TREAT THE QUANTILE     CONFIDENCE LIMITS CASE  **
!               *****************************************************
!
!     MARCH 2010: SUPPORT FOR "MULTIPLE" AND "REPLICATED" OPTIONS
!
      IMULT='OFF'
      IREPL='OFF'
      ISHIFT=0
!
      IF(ICOM.EQ.'MEDI')THEN
        IF(NUMARG.GE.2.AND.IHARG(1).EQ.'CONF' .AND.   &
          (IHARG(2).EQ.'LIMI'.OR.IHARG(2).EQ.'INTE'))THEN
          ISHIFT=2
        ENDIF
      ELSEIF(ICOM.EQ.'MULT' .AND. IHARG(1).EQ.'MEDI' .AND.   &
             IHARG(2).EQ.'CONF')THEN
        IMULT='ON'
        IF(NUMARG.GE.3.AND.   &
          (IHARG(3).EQ.'LIMI'.OR.IHARG(3).EQ.'INTE'))THEN
          ISHIFT=3
        ENDIF
      ELSEIF(ICOM.EQ.'REPL' .AND. IHARG(1).EQ.'MEDI' .AND.   &
             IHARG(2).EQ.'CONF')THEN
        IREPL='ON'
        IF(NUMARG.GE.3.AND.   &
          (IHARG(3).EQ.'LIMI'.OR.IHARG(3).EQ.'INTE'))THEN
          ISHIFT=3
        ENDIF
      ENDIF
!
      IF(ISHIFT.GT.0)THEN
        CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                    IBUGA2,IERROR)
        ICASAN='MECI'
        CALL DPQUCO(XTEMP1,XTEMP2,MAXNXT,ICASAN,   &
                    ICAPSW,IFORSW,IMULT,IREPL,   &
                    ISUBRO,IBUGA2,IBUGA3,IBUGQ,IFOUND,IERROR)
        IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
      IF(ICOM.EQ.'QUAN')THEN
        IF(NUMARG.GE.2.AND.IHARG(1).EQ.'CONF' .AND.   &
          (IHARG(2).EQ.'LIMI'.OR.IHARG(2).EQ.'INTE'))THEN
          ISHIFT=2
        ENDIF
      ELSEIF(ICOM.EQ.'MULT' .AND. IHARG(1).EQ.'QUAN' .AND.   &
             IHARG(2).EQ.'CONF')THEN
        IMULT='ON'
        IF(NUMARG.GE.3.AND.   &
          (IHARG(3).EQ.'LIMI'.OR.IHARG(3).EQ.'INTE'))THEN
          ISHIFT=3
        ENDIF
      ELSEIF(ICOM.EQ.'REPL' .AND. IHARG(1).EQ.'QUAN' .AND.   &
             IHARG(2).EQ.'CONF')THEN
        IREPL='ON'
        IF(NUMARG.GE.3.AND.   &
          (IHARG(3).EQ.'LIMI'.OR.IHARG(3).EQ.'INTE'))THEN
          ISHIFT=3
        ENDIF
      ENDIF
!
      IF(ISHIFT.GT.0)THEN
        CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                    IBUGA2,IERROR)
        ICASAN='QUCI'
        CALL DPQUCO(XTEMP1,XTEMP2,MAXNXT,ICASAN,   &
                    ICAPSW,IFORSW,IMULT,IREPL,   &
                    ISUBRO,IBUGA2,IBUGA3,IBUGQ,IFOUND,IERROR)
        IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!               ***************************************************
!               **  TREAT THE PROPORTION CONFIDENCE LIMITS CASE  **
!               **  AND DIFFERENCE OF PROPORTION CONFIDENCE      **
!               **  LIMITS CASE                                  **
!               ***************************************************
!
      IF(ICOM.EQ.'PROP')THEN
        IF(NUMARG.GE.2.AND.IHARG(1).EQ.'CONF'.AND.   &
          (IHARG(2).EQ.'LIMI'.OR.IHARG(2).EQ.'INTE'))THEN
          ISHIFT=2
          CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                      IBUGA2,IERROR)
          ICASAN='PROP'
          CALL DPPRCL(MAXNXT,ICASAN,ANOPL1,ANOPL2,ICAPSW,IFORSW,   &
                      ISUBRO,IBUGA2,IBUGA3,IBUGQ,IFOUND,IERROR)
          IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
        ENDIF
      ENDIF
!
      IF(ICOM.EQ.'DIFF')THEN
        IF(NUMARG.GE.4.AND.IHARG(1).EQ.'OF  '.AND.   &
          IHARG(2).EQ.'PROP'.AND.IHARG(3).EQ.'CONF'.AND.   &
          (IHARG(4).EQ.'LIMI'.OR.IHARG(4).EQ.'INTE'))THEN
          ISHIFT=4
          CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                      IBUGA2,IERROR)
          ICASAN='DPRO'
          CALL DPPRCL(MAXNXT,ICASAN,ANOPL1,ANOPL2,ICAPSW,IFORSW,   &
                      ISUBRO,IBUGA2,IBUGA3,IBUGQ,IFOUND,IERROR)
          IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
        ENDIF
        IF(NUMARG.GE.3.AND.IHARG(1).EQ.'PROP'.AND.   &
           IHARG(2).EQ.'CONF'.AND.   &
           (IHARG(3).EQ.'LIMI'.OR.IHARG(3).EQ.'INTE'))THEN
          ISHIFT=3
          CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                      IBUGA2,IERROR)
          ICASAN='DPRO'
          CALL DPPRCL(MAXNXT,ICASAN,ANOPL1,ANOPL2,ICAPSW,IFORSW,   &
                      ISUBRO,IBUGA2,IBUGA3,IBUGQ,IFOUND,IERROR)
          IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
        ENDIF
      ENDIF
!
!               ****************************************
!               **  TREAT THE TOLERANCE  LIMITS CASE  **
!               ****************************************
!
      IF(ICOM.EQ.'TOLE' .OR. IHARG(1).EQ.'TOLE' .OR.   &
         IHARG(2).EQ.'TOLE' .OR. IHARG(3).EQ.'TOLE')THEN
         CALL DPTOLI(XTEMP1,XTEMP2,TEMP2,MAXNXT,   &
                    ICASAN,ICAPSW,IFORSW,   &
                    IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
        IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
!
      ENDIF
!
!               ******************************
!               **  TREAT THE RUNS    CASE  **
!               ******************************
!
      IF(ICOM.EQ.'RUNS' .OR. IHARG(1).EQ.'RUNS' .OR.   &
         IHARG(2).EQ.'RUNS')THEN
        ICASAN='RUNS'
        CALL DPRUN(XTEMP1,MAXNXT,ICASAN,ICAPSW,IFORSW,   &
                   IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
        IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!               *********************************************
!               **  TREAT THE RELIABILTY TREND TESTS CASE  **
!               *********************************************
!
      IF(ICOM.EQ.'RELI')THEN
        IF(NUMARG.GE.2.AND.IHARG(1).EQ.'TREN'.AND.   &
           IHARG(2).EQ.'TEST')THEN
             ICASAN='TREN'
             ISHIFT=2
             CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                         IBUGA2,IERROR)
             CALL DPTREN(XTEMP2,MAXNXT,ICAPSW,IFORSW,   &
                         IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
             IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
        ENDIF
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS REWRITTEN     FEBRUARY 1994
!               ******************************
!               **  TREAT THE T TEST  CASE  **
!               ******************************
!
      IF((ICOM.EQ.'T   ' .AND. IHARG(1).EQ.'TEST') .OR.   &
          (IHARG(1).EQ.'T   ' .AND. IHARG(2).EQ.'TEST') .OR.   &
          (IHARG(2).EQ.'T   ' .AND. IHARG(3).EQ.'TEST') .OR.   &
          (IHARG(3).EQ.'T   ' .AND. IHARG(4).EQ.'TEST') .OR.   &
          (IHARG(4).EQ.'T   ' .AND. IHARG(5).EQ.'TEST') .OR.   &
          (IHARG(5).EQ.'T   ' .AND. IHARG(6).EQ.'TEST')   &
         )THEN
        CALL DPTTES(XTEMP1,MAXNXT,ICAPSW,IFORSW,   &
                    IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
            IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED         JUNE 2017
!               *****************************************************
!               **  TREAT THE COEFFICIENT OF VARIATION TEST  CASE  **
!               *****************************************************
!
      IF((ICOM.EQ.'ONE ' .AND. IHARG(1).EQ.'SAMP') .OR.   &
         (ICOM.EQ.'1   ' .AND. IHARG(1).EQ.'SAMP') .OR.   &
         (ICOM.EQ.'TWO ' .AND. IHARG(1).EQ.'SAMP') .OR.   &
         (ICOM.EQ.'2   ' .AND. IHARG(1).EQ.'SAMP'))THEN
        CALL DPCVTE(XTEMP1,XTEMP2,MAXNXT,   &
                    ICAPSW,IFORSW,   &
                    IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
            IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED     JUNE 1999
!               *********************************
!               **  TREAT THE SIGN TEST  CASE  **
!               *********************************
!
      IF(ICOM.EQ.'SIGN' .OR. IHARG(1).EQ.'SIGN' .OR.   &
         IHARG(2).EQ.'SIGN')THEN
         CALL DPSIGN(XTEMP1,XTEMP2,MAXNXT,   &
                    ICAPSW,IFORSW,   &
                    IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED     JUNE 1999
!CCCC THE FOLLOWING SECTION WAS REWRITTEN     MAY      2011
!               *************************************************
!               **  TREAT THE WILCOXON SIGNED RANK TEST  CASE  **
!               *************************************************
!
      IF((ICOM.EQ.'SIGN' .AND. IHARG(1).EQ.'RANK') .OR.   &
          (IHARG(1).EQ.'SIGN' .AND. IHARG(2).EQ.'RANK') .OR.   &
          (IHARG(2).EQ.'SIGN' .AND. IHARG(3).EQ.'RANK') .OR.   &
          (IHARG(3).EQ.'SIGN' .AND. IHARG(4).EQ.'RANK') .OR.   &
          (IHARG(4).EQ.'SIGN' .AND. IHARG(5).EQ.'RANK') .OR.   &
          (IHARG(5).EQ.'SIGN' .AND. IHARG(6).EQ.'RANK')   &
         )THEN
        CALL DPWILC(XTEMP1,XTEMP2,MAXNXT,   &
                    ICAPSW,IFORSW,   &
                    IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
            IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED     JULY 1999
!               *************************************************
!               **  TREAT THE MANN-WHITNEY RANK SUM TEST  CASE **
!               *************************************************
!
      IF( (ICOM.EQ.'MANN'     .AND. IHARG(1).EQ.'WHIT') .OR.   &
          (IHARG(1).EQ.'MANN' .AND. IHARG(2).EQ.'WHIT') .OR.   &
          (IHARG(2).EQ.'MANN' .AND. IHARG(3).EQ.'WHIT') .OR.   &
          (IHARG(3).EQ.'MANN' .AND. IHARG(4).EQ.'WHIT') .OR.   &
          (ICOM.EQ.'RANK'     .AND. IHARG(1).EQ.'SUM ') .OR.   &
          (IHARG(1).EQ.'RANK' .AND. IHARG(2).EQ.'SUM ') .OR.   &
          (IHARG(2).EQ.'SIGN' .AND. IHARG(3).EQ.'RANK') .OR.   &
          (IHARG(3).EQ.'SIGN' .AND. IHARG(4).EQ.'RANK')   &
         )THEN
         CALL DPMANN(MAXNXT,ICAPSW,IFORSW,   &
                     IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED     JUNE 2023
!               *************************************************
!               **  TREAT THE SIEGEL POLIY          TEST  CASE **
!               *************************************************
!
      IF( (ICOM.EQ.'SIEG'     .AND. IHARG(1).EQ.'POLI') .OR.   &
          (IHARG(1).EQ.'SIEG' .AND. IHARG(2).EQ.'POLI') .OR.   &
          (IHARG(2).EQ.'SIEG' .AND. IHARG(3).EQ.'POLI') .OR.   &
          (IHARG(3).EQ.'SIEG' .AND. IHARG(4).EQ.'POLI')   &
         )THEN
         CALL DPSGTU(MAXNXT,ICAPSW,IFORSW,   &
                     IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED     AUGUST 2023
!               *************************************************
!               **  TREAT THE FLIGNER POLICELLO     TEST  CASE **
!               *************************************************
!
      IF( (ICOM.EQ.'FLIG'     .AND. IHARG(1).EQ.'POLI') .OR.   &
          (IHARG(1).EQ.'FLIG' .AND. IHARG(2).EQ.'POLI') .OR.   &
          (IHARG(2).EQ.'FLIG' .AND. IHARG(3).EQ.'POLI') .OR.   &
          (IHARG(3).EQ.'FLIG' .AND. IHARG(4).EQ.'POLI')   &
         )THEN
         CALL DPFPTE(MAXNXT,ICAPSW,IFORSW,   &
                     IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED     JULY 2023
!               ******************************************************
!               **  TREAT THE TWO SAMPLE LINEAR RANK SUM TEST  CASE **
!               ******************************************************
!
      IF( (ICOM.EQ.'TWO '     .AND. IHARG(1).EQ.'SAMP') .OR.   &
          (IHARG(1).EQ.'TWO ' .AND. IHARG(2).EQ.'SAMP') .OR.   &
          (IHARG(2).EQ.'TWO ' .AND. IHARG(3).EQ.'SAMP') .OR.   &
          (IHARG(3).EQ.'TWO ' .AND. IHARG(4).EQ.'SAMP')   &
         )THEN
         CALL DPLRST(MAXNXT,ICAPSW,IFORSW,   &
                     IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ELSEIF( (ICOM.EQ.'2   '     .AND. IHARG(1).EQ.'SAMP') .OR.   &
          (IHARG(1).EQ.'2   ' .AND. IHARG(2).EQ.'SAMP') .OR.   &
          (IHARG(2).EQ.'2   ' .AND. IHARG(3).EQ.'SAMP') .OR.   &
          (IHARG(3).EQ.'2   ' .AND. IHARG(4).EQ.'SAMP')   &
         )THEN
         CALL DPLRST(MAXNXT,ICAPSW,IFORSW,   &
                     IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
