      IF(ICOM.EQ.'ANDE' .AND. IHARG(1).EQ.'DARL')GO TO 2019
!
      IF( (ICOM.EQ.'TWO '     .AND. IHARG(1).EQ.'SAMP') .OR.   &
          (IHARG(1).EQ.'TWO ' .AND. IHARG(2).EQ.'SAMP') .OR.   &
          (IHARG(2).EQ.'TWO ' .AND. IHARG(3).EQ.'SAMP') .OR.   &
          (IHARG(3).EQ.'TWO ' .AND. IHARG(4).EQ.'SAMP')   &
         )THEN
         CALL DPPTES(MAXNXT,ICAPSW,IFORSW,ISEED,   &
                     IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ELSEIF( (ICOM.EQ.'2   '     .AND. IHARG(1).EQ.'SAMP') .OR.   &
          (IHARG(1).EQ.'2   ' .AND. IHARG(2).EQ.'SAMP') .OR.   &
          (IHARG(2).EQ.'2   ' .AND. IHARG(3).EQ.'SAMP') .OR.   &
          (IHARG(3).EQ.'2   ' .AND. IHARG(4).EQ.'SAMP')   &
         )THEN
         CALL DPPTES(MAXNXT,ICAPSW,IFORSW,ISEED,   &
                     IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ELSEIF( (ICOM.EQ.'K   '     .AND. IHARG(1).EQ.'SAMP') .OR.   &
          (IHARG(1).EQ.'K   ' .AND. IHARG(2).EQ.'SAMP') .OR.   &
          (IHARG(2).EQ.'K   ' .AND. IHARG(3).EQ.'SAMP') .OR.   &
          (IHARG(3).EQ.'K   ' .AND. IHARG(4).EQ.'SAMP')   &
         )THEN
         CALL DPPTES(MAXNXT,ICAPSW,IFORSW,ISEED,   &
                     IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
 2019 CONTINUE
!
!CCCC THE FOLLOWING SECTION WAS ADDED     MARCH 2024
!               ******************************************************
!               **  TREAT THE JONCKHEERE-TERPSTRA TEST         CASE **
!               ******************************************************
      IF(ICOM.EQ.'JONC')THEN
         CALL DPJTTE(MAXNXT,ICAPSW,IFORSW,ISEED,   &
                     IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED     MAY 2024
