!               ******************************************************
      IF(ICOM.EQ.'RAND' .AND. IHARG(1).EQ.'COMP' .AND.   &
         IHARG(2).EQ.'BLOC')THEN
         CALL DPRCBD(MAXNXT,ICAPSW,IFORSW,ISEED,   &
                     IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!
!CCCC THE FOLLOWING SECTION WAS ADDED     JUNE 2011
!               **************************************************
!               **  TREAT THE FISHER TWO SAMPLE RAND TEST  CASE **
!               **************************************************
!
      IF( (ICOM.EQ.'FISH'     .AND. IHARG(1).EQ.'TWO ') .OR.   &
          (IHARG(1).EQ.'FISH' .AND. IHARG(2).EQ.'TWO ') .OR.   &
          (IHARG(2).EQ.'FISH' .AND. IHARG(3).EQ.'TWO ') .OR.   &
          (IHARG(3).EQ.'FISH' .AND. IHARG(4).EQ.'TWO ')   &
         )THEN
         CALL DPFIRT(MAXNXT,ICAPSW,IFORSW,   &
                     IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED     MAY 2011
!               ************************************
!               **  TREAT THE KLOTZ TEST     CASE **
!               ************************************
!
      IF(ICOM.EQ.'KLOT' .OR. IHARG(1).EQ.'KLOT' .OR.   &
         IHARG(2).EQ.'KLOT')THEN
         CALL DPKLOT(MAXNXT,ICAPSW,IFORSW,   &
                     IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED     JUNE 2011
!               ********************************************
!               **  TREAT THE SQUARED RANKS TEST     CASE **
!               ********************************************
!
      IF((ICOM.EQ.'SQUA' .AND. IHARG(1).EQ.'RANK') .OR.   &
         (IHARG(1).EQ.'SQUA' .AND. IHARG(2).EQ.'RANK') .OR.   &
         (IHARG(2).EQ.'SQUA' .AND. IHARG(3).EQ.'RANK'))THEN
         CALL DPSQRA(MAXNXT,ICAPSW,IFORSW,   &
                     IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED     JUNE 2011
!               ********************************************
!               **  TREAT THE MEDIAN        TEST     CASE **
!               ********************************************
!
      IF((ICOM.EQ.'MEDI' .AND. IHARG(1).EQ.'TEST') .OR.   &
         (IHARG(1).EQ.'MEDI' .AND. IHARG(2).EQ.'TEST') .OR.   &
         (IHARG(2).EQ.'MEDI' .AND. IHARG(3).EQ.'TEST'))THEN
         CALL DPMETE(MAXNXT,ICAPSW,IFORSW,   &
                     IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED     JUNE 2011
!               ********************************************
!               **  TREAT THE COX STUART    TEST     CASE **
!               ********************************************
!
      IF((ICOM.EQ.'COX ' .AND. IHARG(1).EQ.'STUA') .OR.   &
         (IHARG(1).EQ.'COX ' .AND. IHARG(2).EQ.'STUA') .OR.   &
         (IHARG(2).EQ.'COX ' .AND. IHARG(3).EQ.'STUA'))THEN
         CALL DPCXTE(XTEMP1,XTEMP2,MAXNXT,   &
                     ICAPSW,IFORSW,   &
                     IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED     FEBRUARY 1994
!               ***********************************************
!               **  TREAT THE CHI-SQUARED TEST  CASE  OR THE **
!               **  TREAT THE CHI-SQUARED INDEPENDENCE TEST  **
!               ***********************************************
!
      IF(ICOM.EQ.'CHI ')THEN
         IF(NUMARG.GE.1.AND.IHARG(1).EQ.'SQUA')THEN
            IF(NUMARG.GE.3.AND.IHARG(2).EQ.'INDE'.AND.   &
               IHARG(3).EQ.'TEST')THEN
               ISHIFT=3
               CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
               IBUGA2,IERROR)
               ICASAN='CHIS'
               CALL DPCHIS(MAXNXT,ICASAN,ICAPSW,IFORSW,   &
                           IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
               IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
            ELSEIF(NUMARG.GE.2.AND.IHARG(2).EQ.'INDE')THEN
               ISHIFT=2
               CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
               IBUGA2,IERROR)
               ICASAN='CHIS'
               CALL DPCHIS(MAXNXT,ICASAN,ICAPSW,IFORSW,   &
                           IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
               IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
            ELSEIF(NUMARG.GE.2.AND.IHARG(2).EQ.'TEST')THEN
               ISHIFT=2
               CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
               IBUGA2,IERROR)
               ICASAN='CSTE'
               CALL DPCSTE(MAXNXT,ICAPSW,IFORSW,ICASAN,   &
                           IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
               IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
            ELSEIF(NUMARG.GE.4.AND.IHARG(2).EQ.'LOWE' .AND.   &
                   IHARG(3).EQ.'TAIL' .AND. IHARG(4).EQ.'TEST')THEN
               ISHIFT=4
               CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
               IBUGA2,IERROR)
               ICASAN='CSLT'
               CALL DPCSTE(MAXNXT,ICAPSW,IFORSW,ICASAN,   &
                           IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
               IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
            ELSEIF(NUMARG.GE.4.AND.IHARG(2).EQ.'UPPE' .AND.   &
                   IHARG(3).EQ.'TAIL' .AND. IHARG(4).EQ.'TEST')THEN
               ISHIFT=4
               CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
               IBUGA2,IERROR)
               ICASAN='CSUT'
               CALL DPCSTE(MAXNXT,ICAPSW,IFORSW,ICASAN,   &
                           IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
               IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
            ELSEIF(NUMARG.GE.4.AND.IHARG(2).EQ.'TWO ' .AND.   &
                   IHARG(3).EQ.'TAIL' .AND. IHARG(4).EQ.'TEST')THEN
               ISHIFT=4
               CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
               IBUGA2,IERROR)
               ICASAN='CS2T'
               CALL DPCSTE(MAXNXT,ICAPSW,IFORSW,ICASAN,   &
                           IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
               IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
            ENDIF
         ENDIF
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED     MARCH 2007
!               ***********************************************
!               **  TREAT THE FISHER EXACT             TEST  **
!               ***********************************************
!
      IF(ICOM.EQ.'FISH')THEN
        IF(NUMARG.GE.2.AND.IHARG(1).EQ.'EXAC'.AND.   &
          IHARG(2).EQ.'TEST')THEN
          ISHIFT=2
          CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
          IBUGA2,IERROR)
          ICASAN='FISH'
          CALL DPFISH(MAXNXT,ICASAN,ICAPSW,IFORSW,   &
                      IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
        ELSEIF(NUMARG.GE.1.AND.IHARG(1).EQ.'EXAC')THEN
          ISHIFT=1
          CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
          IBUGA2,IERROR)
          ICASAN='FISH'
          CALL DPFISH(MAXNXT,ICASAN,ICAPSW,IFORSW,   &
                      IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
        ELSEIF(NUMARG.GE.1.AND.IHARG(1).EQ.'TEST')THEN
          ISHIFT=1
          CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
          IBUGA2,IERROR)
          ICASAN='FISH'
          CALL DPFISH(MAXNXT,ICASAN,ICAPSW,IFORSW,   &
                      IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
         ENDIF
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED     DECEMBER 1998
!               *************************************************
!               **  TREAT THE CHI-SQUARED 2 SAMPLE TEST  CASE  **
!               *************************************************
!
!CCCC 2011/3: SUPPORT "GROUPED" KEYWORD
!
      IF(ICOM.EQ.'CHI '.OR.ICOM.EQ.'CHIS'.OR.ICOM.EQ.'2'.OR.   &
         ICOM.EQ.'TWO')THEN
         CALL DP2CHS(TEMP,TEMP2,XTEMP1,MAXNXT,   &
                     ICAPSW,IFORSW,   &
                     IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
               IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ELSEIF(ICOM.EQ.'GROU' .OR. IHARG(1).EQ.'CHI '.OR.   &
             IHARG(1).EQ.'CHIS'.OR.IHARG(1).EQ.'2'.OR.   &
             IHARG(1).EQ.'TWO')THEN
         CALL DP2CHS(TEMP,TEMP2,XTEMP1,MAXNXT,   &
                     ICAPSW,IFORSW,   &
                     IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
               IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED     DECEMBER 1998
!               *******************************************************
!               **  TREAT THE KOLMOGOROV-SMIRNOV 2 SAMPLE TEST  CASE **
!               *******************************************************
!
      IF(ICOM.EQ.'KOLM'.OR.ICOM.EQ.'2'.OR.   &
         ICOM.EQ.'TWO' .OR. ICOM.EQ.'KS')THEN
         CALL DP2KST(TEMP,TEMP2,MAXNXT,   &
                     ICAPSW,IFORSW,   &
                     IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED     MAY  2014
!               *******************************************************
!               **  TREAT THE DISTRIBUTIONAL LIKELIHOOD RATIO   CASE **
!               *******************************************************
!
      IF(NUMARG.GE.4)THEN
        DO 7390 I=1,NUMARG-1
          IF(IHARG(I).EQ.'DIST'.AND.IHARG(I+1).EQ.'LIKE'.AND.   &
             IHARG(I+2).EQ.'RATI')THEN
               CALL DPLRDI(MAXNXT,ICAPSW,IFORSW,ISEED,   &
                          IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
               IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
          ENDIF
 7390   CONTINUE
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED     MARCH  2011
!               *******************************************************
!               **  TREAT THE BEST DISTRIBUTIONAL FIT           CASE **
!               *******************************************************
!
      IF(ICOM.EQ.'BEST' .AND. IHARG(1).EQ.'DIST' .AND.   &
         IHARG(2).EQ.'FIT')THEN
         CALL DPBEFI(MAXNXT,ICAPSW,IFORSW,ISEED,   &
                     IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ELSEIF(IHARG(1).EQ.'BEST' .AND. IHARG(2).EQ.'DIST' .AND.   &
             IHARG(3).EQ.'FIT')THEN
         CALL DPBEFI(MAXNXT,ICAPSW,IFORSW,ISEED,   &
                     IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED     NOVEMBER 1998
!               ***************************************************
!               **  TREAT THE CHI-SQUARED GOODNESS OF FIT  CASE  **
!               ***************************************************
!
!CCCC NOTE 12/2009: FOLDED INTO THE "GOODNESS OF FIT" COMMAND (DPGOFI)
      IF(ICOM.EQ.'ODDS')GO TO 7039
!
!CCCC IF(NUMARG.GE.3)THEN
!CCCC   DO7010I=1,NUMARG-2
!CCCC     IF(IHARG(I).EQ.'GOOD'.AND.IHARG(I+1).EQ.'OF'.AND.
!CCCC1       IHARG(I+2).EQ.'FIT')THEN
!CCCC          CALL DPCHSQ(XTEMP1,XTEMP2,TEMP,MAXNXT,
!CCCC1         ICAPSW,
!CCCC1         IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
!CCCC          IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
!CCCC     ENDIF
!7010   CONTINUE
!CCCC ENDIF
!CCCC IF(NUMARG.GE.2)THEN
!CCCC   DO7020I=1,NUMARG-1
!CCCC     IF(IHARG(I).EQ.'CHI '.AND.IHARG(I+1).EQ.'SQUA')THEN
!CCCC          CALL DPCHSQ(XTEMP1,XTEMP2,TEMP,MAXNXT,
!CCCC1         ICAPSW,
!CCCC1         IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
!CCCC          IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
!CCCC     ENDIF
!7020   CONTINUE
!CCCC ENDIF
!CCCC IF(NUMARG.GE.1)THEN
!CCCC   DO7030I=1,NUMARG
!CCCC     IF(IHARG(I).EQ.'CHIS')THEN
!CCCC          CALL DPCHSQ(XTEMP1,XTEMP2,TEMP,MAXNXT,
!CCCC1         ICAPSW,
!CCCC1         IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
!CCCC          IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
!CCCC     ENDIF
!7030   CONTINUE
!CCCC ENDIF
!
 7039 CONTINUE
!
!CCCC THE FOLLOWING SECTION WAS ADDED     NOVEMBER 1998
!               ***************************************************
!               **  TREAT THE KOLMOGOROV-SMIRNOV GOODNESS OF FIT  CASE
!               ***************************************************
!
!CCCC SEPTEMBER 2009: USE DPGOFI ROUTINE INSTEAD OF DP1KST
!
      IF(NUMARG.GE.2)THEN
        DO 7070 I=1,NUMARG-1
          IF(IHARG(I).EQ.'KOLM'.AND.IHARG(I+1).EQ.'SMIR')THEN
               CALL DPGOFI(MAXNXT,ICAPSW,IFORSW,ISEED,   &
               IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
               IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
          ELSEIF(IHARG(I).EQ.'K   '.AND.IHARG(I+1).EQ.'S   ')THEN
               CALL DPGOFI(MAXNXT,ICAPSW,IFORSW,ISEED,   &
               IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
               IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
          ELSEIF(IHARG(I).EQ.'KS  ')THEN
               CALL DPGOFI(MAXNXT,ICAPSW,IFORSW,ISEED,   &
               IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
               IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
          ELSEIF(IHARG(I).EQ.'ANDE'.AND.IHARG(I+1).EQ.'DARL'.AND.   &
                (IHARG(I+2).NE.'K' .OR. IHARG(I+2).NE.'KSAM'))THEN
               CALL DPGOFI(MAXNXT,ICAPSW,IFORSW,ISEED,   &
               IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
               IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
          ELSEIF(IHARG(I).EQ.'A   '.AND.IHARG(I+1).EQ.'D   ')THEN
               CALL DPGOFI(MAXNXT,ICAPSW,IFORSW,ISEED,   &
               IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
               IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
          ELSEIF(IHARG(I).EQ.'AD  ')THEN
               CALL DPGOFI(MAXNXT,ICAPSW,IFORSW,ISEED,   &
               IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
               IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
          ELSEIF(IHARG(I).EQ.'PPCC')THEN
               CALL DPGOFI(MAXNXT,ICAPSW,IFORSW,ISEED,   &
               IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
               IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
          ELSEIF(IHARG(I).EQ.'CHI '.AND.IHARG(I+1).EQ.'SQUA')THEN
               CALL DPGOFI(MAXNXT,ICAPSW,IFORSW,ISEED,   &
               IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
               IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
          ELSEIF(IHARG(I).EQ.'C   '.AND.IHARG(I+1).EQ.'S   ')THEN
               CALL DPGOFI(MAXNXT,ICAPSW,IFORSW,ISEED,   &
               IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
               IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
          ELSEIF(IHARG(I).EQ.'CHIS')THEN
               CALL DPGOFI(MAXNXT,ICAPSW,IFORSW,ISEED,   &
               IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
               IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
          ELSEIF(IHARG(I).EQ.'CS  ')THEN
               CALL DPGOFI(MAXNXT,ICAPSW,IFORSW,ISEED,   &
               IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
               IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
          ENDIF
 7070   CONTINUE
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED     SEPTEMBER 1997
!               ***************************************
!               **  TREAT THE F LOCATION TEST  CASE  **
!               ***************************************
!
      IF(ICOM.EQ.'F   '.AND.NUMARG.GE.1.AND.IHARG(1).EQ.'LOCA')THEN
         ISHIFT=1
         CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                     IBUGA2,IERROR)
         ICASAN='FLTE'
         IF(IERROR.EQ.'YES')GO TO 9000
         IF(NUMARG.GE.1.AND.IHARG(1).EQ.'TEST')THEN
            ISHIFT=1
            CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
            IBUGA2,IERROR)
            IF(IERROR.EQ.'YES')GO TO 9000
         ENDIF
         IMULT='OFF'
         CALL DPFLTE(XTEMP1,MAXNXT,   &
                     ICAPSW,IFORSW,IMULT,   &
                     IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ELSEIF(ICOM.EQ.'MULT'.AND.NUMARG.GE.2.AND.IHARG(1).EQ.'F   '.AND.   &
             IHARG(2).EQ.'LOCA')THEN
         ISHIFT=1
         CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                     IBUGA2,IERROR)
         ICASAN='FLTE'
         IF(IERROR.EQ.'YES')GO TO 9000
         IF(NUMARG.GE.1.AND.IHARG(1).EQ.'TEST')THEN
            ISHIFT=1
            CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
            IBUGA2,IERROR)
         ENDIF
         IF(IERROR.EQ.'YES')GO TO 9000
         IMULT='ON'
         CALL DPFLTE(XTEMP1,MAXNXT,   &
                     ICAPSW,IFORSW,IMULT,   &
                     IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED     FEBRUARY 1994
!               ******************************
!               **  TREAT THE F TEST  CASE  **
!               ******************************
!
      IF(ICOM.EQ.'F   ')THEN
         IF(NUMARG.GE.1.AND.IHARG(1).EQ.'TEST')THEN
            ISHIFT=1
            CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
