         IF(ICASDI.EQ.'K-SA')THEN
           ICASAN='ADKS'
           CALL DPADKS(XTEMP1,XTEMP2,MAXNXT,   &
                       ICAPSW,IFORSW,IMULT,   &
                       IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
           IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
         ENDIF
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED     MARCH 1999
!               *********************************************
!               **  TREAT THE WILKS-SHAPIRO    TEST  CASE  **
!               *********************************************
!
      IF((ICOM.EQ.'WILK' .AND. IHARG(1).EQ.'SHAP') .OR.   &
         (ICOM.EQ.'SHAP' .AND. IHARG(1).EQ.'WILK'))THEN
         ICASAN='WSTE'
         CALL DPWSHA(XTEMP1,MAXNXT,ICASDI,   &
                     ICAPSW,ICASAN,IFORSW,ISEED,   &
                     IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
      ELSE
        DO 17120 I=1,NUMARG-1
          IF(IHARG(I).EQ.'WILK' .AND. IHARG(I+1).EQ.'SHAP')THEN
            ICASAN='WSTE'
            CALL DPWSHA(XTEMP1,MAXNXT,ICASDI,   &
                        ICAPSW,ICASAN,IFORSW,ISEED,   &
                        IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
            GO TO 17129
          ELSEIF(IHARG(I).EQ.'SHAP' .AND. IHARG(I+1).EQ.'WILK')THEN
            ICASAN='WSTE'
            CALL DPWSHA(XTEMP1,MAXNXT,ICASDI,   &
                        ICAPSW,ICASAN,IFORSW,ISEED,   &
                        IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
            GO TO 17129
          ENDIF
17120   CONTINUE
17129   CONTINUE
      ENDIF
      IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
!
!CCCC THE FOLLOWING SECTION WAS ADDED     JUNE 2012
!               *********************************************
!               **  TREAT THE JARQUE BERA      TEST  CASE  **
!               *********************************************
!
      IF(ICOM.EQ.'JARQ' .AND. IHARG(1).EQ.'BERA')THEN
         ICASAN='JABE'
         CALL DPWSHA(XTEMP1,MAXNXT,ICASDI,   &
                     ICAPSW,ICASAN,IFORSW,ISEED,   &
                     IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
      ELSE
        DO 17130 I=1,NUMARG-1
          IF(IHARG(I).EQ.'JARQ' .AND. IHARG(I+1).EQ.'BERA')THEN
            ICASAN='JABE'
            CALL DPWSHA(XTEMP1,MAXNXT,ICASDI,   &
                        ICAPSW,ICASAN,IFORSW,ISEED,   &
                        IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
            GO TO 17139
          ENDIF
17130   CONTINUE
17139   CONTINUE
      ENDIF
      IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
!
!CCCC THE FOLLOWING SECTION WAS ADDED     NOVEMBER 2013
!               ***********************************************
!               **  TREAT THE POISSON DISPERSION TEST  CASE  **
!               ***********************************************
!
      IF(ICOM.EQ.'POIS' .AND. IHARG(1).EQ.'DISP')THEN
         ICASAN='PDIS'
         CALL DPPDTE(XTEMP1,XTEMP2,MAXNXT,   &
                     ICAPSW,ICASAN,IFORSW,   &
                     IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
      ELSE
        DO 17140 I=1,NUMARG-1
          IF(IHARG(I).EQ.'POIS' .AND. IHARG(I+1).EQ.'DISP')THEN
            ICASAN='PDIS'
            CALL DPPDTE(XTEMP1,XTEMP2,MAXNXT,   &
                        ICAPSW,ICASAN,IFORSW,   &
                        IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
            GO TO 17149
          ENDIF
17140   CONTINUE
17149   CONTINUE
      ENDIF
      IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
!
!               ****************************************************
!               **  TREAT THE MCCOOL WEIBULL LOCATION TEST  CASE  **
!               ****************************************************
!
      IF(ICOM.EQ.'MCCO' .AND. IHARG(1).EQ.'WEIB' .AND.   &
         IHARG(2).EQ.'LOCA' .AND. IHARG(3).EQ.'TEST')THEN
        ISHIFT=3
        CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                    IBUGA2,IERROR)
        ICASAN='MCCO'
        CALL DPMCWE(MAXNXT,ICAPSW,IFORSW,   &
                    IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
        GO TO 9000
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED     SEPTEMBER 1997
!               *********************************************
!               **  TREAT THE GRUBB            TEST  CASE  **
!               *********************************************
!
      IF(ICOM.EQ.'GRUB')THEN
        CALL DPGRUB(XTEMP1,MAXNXT,   &
                    ICAPSW,ICASAN,IFORSW,   &
                    IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
      ELSE
        DO 7110 I=1,NUMARG
          IF(IHARG(I).EQ.'GRUB')THEN
            CALL DPGRUB(XTEMP1,MAXNXT,   &
                        ICAPSW,ICASAN,IFORSW,   &
                        IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
            GO TO 7119
          ENDIF
 7110   CONTINUE
 7119   CONTINUE
      ENDIF
      IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
!
!CCCC THE FOLLOWING SECTION WAS ADDED     NOVEMBER 2009
!               *********************************************
!               **  TREAT THE TIETJEN-MOORE    TEST  CASE  **
!               *********************************************
!
      IF(ICOM.EQ.'TIET')THEN
        CALL DPTIET(XTEMP1,MAXNXT,   &
                    ICAPSW,ICASAN,IFORSW,ISEED,   &
                    IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
      ELSE
        DO 7120 I=1,NUMARG
          IF(IHARG(I).EQ.'TIET')THEN
            CALL DPTIET(XTEMP1,MAXNXT,   &
                        ICAPSW,ICASAN,IFORSW,ISEED,   &
                        IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
            GO TO 7129
          ENDIF
 7120   CONTINUE
 7129   CONTINUE
      ENDIF
      IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
!
!CCCC THE FOLLOWING SECTION WAS ADDED     NOVEMBER 2009
!               ******************************************************
!               **  TREAT THE EXTREME STUDENTIZED DEVIATE TEST CASE **
!               ******************************************************
!
      IF(ICOM.EQ.'ESD ' .OR.   &
         (ICOM.EQ.'EXTR' .AND. IHARG(1).EQ.'STUD' .AND.   &
          IHARG(2).EQ.'DEVI'))THEN
        CALL DPGESD(XTEMP1,MAXNXT,   &
                    ICAPSW,ICASAN,IFORSW,ISEED,   &
                    IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
      ELSE
        DO 7130 I=1,NUMARG
          IF(IHARG(I).EQ.'ESD ')THEN
            CALL DPGESD(XTEMP1,MAXNXT,   &
                        ICAPSW,ICASAN,IFORSW,ISEED,   &
                        IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
            GO TO 7139
          ENDIF
 7130   CONTINUE
 7139   CONTINUE
        DO 7140 I=1,NUMARG-2
          IF(IHARG(I).EQ.'EXTR' .AND. IHARG(I+1).EQ.'STUD' .AND.   &
             IHARG(I+2).EQ.'DEVI')THEN
            CALL DPGESD(XTEMP1,MAXNXT,   &
                        ICAPSW,ICASAN,IFORSW,ISEED,   &
                        IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
            GO TO 7149
          ENDIF
 7140   CONTINUE
 7149   CONTINUE
      ENDIF
      IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
!
!CCCC THE FOLLOWING SECTION WAS ADDED     NOVEMBER 2009
!               *********************************************
!               **  TREAT THE DIXON            TEST  CASE  **
!               *********************************************
!
      IF(ICOM.EQ.'DIXO')THEN
        CALL DPDIXO(XTEMP1,MAXNXT,   &
                    ICAPSW,ICASAN,IFORSW,ISEED,   &
                    IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
      ELSE
        DO 7150 I=1,NUMARG
          IF(IHARG(I).EQ.'DIXO')THEN
            CALL DPDIXO(XTEMP1,MAXNXT,   &
                        ICAPSW,ICASAN,IFORSW,ISEED,   &
                        IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
            GO TO 7159
          ENDIF
 7150   CONTINUE
 7159   CONTINUE
      ENDIF
      IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
!
!CCCC THE FOLLOWING SECTION WAS ADDED     OCTOBER 2019
!               *********************************************
!               **  TREAT THE DAVID            TEST  CASE  **
!               *********************************************
!
      IF(ICOM.EQ.'DAVI')THEN
        CALL DPDAVI(XTEMP1,MAXNXT,   &
                    ICAPSW,ICASAN,IFORSW,   &
                    IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
      ELSE
        DO 7160 I=1,NUMARG
          IF(IHARG(I).EQ.'DAVI')THEN
            CALL DPDAVI(XTEMP1,MAXNXT,   &
                        ICAPSW,ICASAN,IFORSW,   &
                        IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
            GO TO 7169
          ENDIF
 7160   CONTINUE
 7169   CONTINUE
      ENDIF
      IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
!
!CCCC THE FOLLOWING SECTION WAS ADDED     OCTOBER 2019
!               *********************************************
!               **  TREAT THE SKEWNESS OUTLIER TEST  CASE  **
!               **  TREAT THE KURTOSIS OUTLIER TEST  CASE  **
!               *********************************************
!
      IF(ICOM.EQ.'SKEW' .OR. ICOM.EQ.'KURT')THEN
        CALL DPSKOU(MAXNXT,ICAPSW,ICASAN,IFORSW,   &
                    IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
      ELSE
        DO 7170 I=1,NUMARG
          IF(IHARG(I).EQ.'SKEW' .OR. IHARG(I).EQ.'KURT')THEN
            CALL DPSKOU(MAXNXT,ICAPSW,ICASAN,IFORSW,   &
                        IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
            GO TO 7179
          ENDIF
 7170   CONTINUE
 7179   CONTINUE
      ENDIF
      IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
!
!CCCC THE FOLLOWING SECTION WAS ADDED     FEBRUARY 2003
!               *********************************************
!               **  TREAT THE LJUNG-BOX        TEST  CASE  **
!               *********************************************
!
      IF(ICOM.EQ.'LJUN' .OR. IHARG(1).EQ.'LJUN' .OR.   &
         IHARG(2).EQ.'LJUN')THEN
         CALL DPLUJA(XTEMP1,MAXNXT,   &
                     ICASAN,ICAPSW,IFORSW,   &
                     IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED     JANUARY 2013
!               ********************************************************
!               **  TREAT THE MEAN SUCCESSIVE DIFFERENCES TEST  CASE  **
!               ********************************************************
!
!     THIS TEST ALSO KNOWN AS DURBIN-WATSON TEST OR ADJACENCY TEST
!
      IF(ICOM.EQ.'MEAN' .OR. IHARG(1).EQ.'MEAN' .OR.   &
         IHARG(2).EQ.'MEAN')THEN
         CALL DPMSDT(XTEMP1,MAXNXT,   &
                     ICASAN,ICAPSW,IFORSW,   &
                     IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
      IF(ICOM.EQ.'DURB' .OR. IHARG(1).EQ.'DURB' .OR.   &
         IHARG(2).EQ.'DURB')THEN
         CALL DPMSDT(XTEMP1,MAXNXT,   &
                     ICASAN,ICAPSW,IFORSW,   &
                     IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
      IF(ICOM.EQ.'ADJA' .OR. IHARG(1).EQ.'ADJA' .OR.   &
         IHARG(2).EQ.'ADJA')THEN
         CALL DPMSDT(XTEMP1,MAXNXT,   &
                     ICASAN,ICAPSW,IFORSW,   &
                     IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED     NOVEMBER 2003
!               ******************************************************
!               **  TREAT THE FREQUENCY        TEST  CASE           **
!               **  TREAT THE FREQUENCY WITHIN A BLOCK  TEST  CASE  **
!               ******************************************************
!
      IF(ICOM.EQ.'FREQ' .OR. IHARG(1).EQ.'FREQ' .OR.   &
         IHARG(2).EQ.'FREQ' .OR. IHARG(3).EQ.'FREQ')THEN
         CALL DPFRTE(XTEMP1,MAXNXT,   &
                     ICASAN,ICAPSW,IFORSW,   &
                     IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
           IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED     DECEMBER 2003
!               ******************************************************
!               **  TREAT THE CUMULATIVE SUM   TEST  CASE           **
!               ******************************************************
!
      IF((ICOM.EQ.'CUMU' .AND. IHARG(1).EQ.'SUM ') .OR.   &
         (IHARG(1).EQ.'CUMU' .OR. IHARG(2).EQ.'SUM') .OR.   &
         (IHARG(2).EQ.'CUMU' .OR. IHARG(3).EQ.'SUM'))THEN
         CALL DPCUSU(XTEMP1,MAXNXT,   &
                     ICASAN,ICAPSW,IFORSW,   &
                     IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!               ************************************************
!               **  TREAT THE <DIST>  MAXIMUM LIKELIHOOD CASE **
!               ************************************************
!
      IMAX=NUMARG-1
      IF(IMAX.GE.1)THEN
        DO 1410 I=1,IMAX
          IF(IHARG(I).EQ.'MLE ' .OR.   &
            (IHARG(I).EQ.'MAXI' .AND. IHARG(I+1).EQ.'LIKE'))THEN
            CALL DPMLWE(XTEMP1,MAXNXT,   &
                        ICAPSW,IFORSW,   &
                        MINMAX,ISEED,   &
                        ICASAN,IBUGA2,IBUGA3,IBUGQ,ISUBRO,   &
                        IFOUND,IERROR)
            IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
          ENDIF
 1410   CONTINUE
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED     APRIL 1998
!               ********************************************************
!               **  TREAT THE A BASIS/B BASIS TOLERANCE LIMIT    CASE **
!               ********************************************************
!
      IF(   &
         (ICOM.EQ.'A   ' .AND. IHARG(1).EQ.'BASI').OR.   &
         (IHARG(1).EQ.'A   ' .AND. IHARG(2).EQ.'BASI').OR.   &
         (IHARG(2).EQ.'A   ' .AND. IHARG(3).EQ.'BASI').OR.   &
         (IHARG(3).EQ.'A   ' .AND. IHARG(4).EQ.'BASI').OR.   &
         ICOM.EQ.'ABAS' .OR.   &
         IHARG(1).EQ.'ABAS' .OR. IHARG(2).EQ.'ABAS' .OR.   &
         IHARG(3).EQ.'ABAS' .OR. IHARG(4).EQ.'ABAS'   &
         )THEN
         ICASAN='ABAS'
         CALL DPABAS(XTEMP1,XTEMP2,MAXNXT,   &
                     ICASAN,ICASDI,ICAPSW,IFORSW,   &
                     IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ELSEIF(   &
         (ICOM.EQ.'B   ' .AND. IHARG(1).EQ.'BASI').OR.   &
         (IHARG(1).EQ.'B   ' .AND. IHARG(2).EQ.'BASI').OR.   &
         (IHARG(2).EQ.'B   ' .AND. IHARG(3).EQ.'BASI').OR.   &
         (IHARG(3).EQ.'B   ' .AND. IHARG(4).EQ.'BASI').OR.   &
         ICOM.EQ.'BBAS' .OR.   &
         IHARG(1).EQ.'BBAS' .OR. IHARG(2).EQ.'BBAS' .OR.   &
         IHARG(3).EQ.'BBAS' .OR. IHARG(4).EQ.'BBAS'   &
         )THEN
         ICASAN='BBAS'
         CALL DPABAS(XTEMP1,XTEMP2,MAXNXT,   &
                     ICASAN,ICASDI,ICAPSW,IFORSW,   &
                     IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!               *******************************************
!               **  TREAT THE (2**K) DEX FIT CASE        **
!               **  TREAT THE    YATES ANALYSIS    CASE  **
!               *******************************************
!
      IF(ICOM.EQ.'2**K' .OR. ICOM.EQ.'YATE' .OR.   &
         ICOM.EQ.'PHD ' .OR.   &
        (ICOM.EQ.'DEX'.AND.NUMARG.GE.1.AND.   &
         IHARG(1).EQ.'PHD ') .OR.   &
        (ICOM.EQ.'DEX'.AND.NUMARG.GE.1.AND.   &
         IHARG(1).EQ.'FIT'))THEN
!CCCC   THE FOLLOWING 4 LINES WERE INSERTED NOVEMBER 1989
        IF(NUMARG.GE.2.AND.IHARG(2).EQ.'CUTO'.AND.   &
           IHARG2(2).EQ.'FF')GO TO 3499
        IF(NUMARG.GE.1.AND.IHARG(1).EQ.'OUTP'.AND.   &
           IHARG2(1).EQ.'UT')GO TO 3499
        ICASAN='DEXF'
        CALL DPYATE(ICASAN,   &
                    ICAPSW,IFORSW,   &
                    IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
        IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
 3499 CONTINUE
!
!               *******************************
!               **  TREAT THE TABULATE CASE  **
!               *******************************
!
      IF(ICOM.EQ.'TABU' .OR. ICOM.EQ.'TAB')THEN
        ICASAN='TABU'
        CALL DPCRTA(TEMP,ISEED,ICAPSW,IFORSW,   &
                    IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
        IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED NOVEMBER 1989
!               *************************************
!               **  TREAT THE CROSS-TABULATE CASE  **
!               *************************************
!
      IF(ICOM.EQ.'CROS' .AND. NUMARG.GE.1 .AND.   &
        (IHARG(1).EQ.'TABU' .OR. IHARG(1).EQ.'TAB'))THEN
        ICASAN='CRTA'
        CALL DPCRTA(TEMP,ISEED,ICAPSW,IFORSW,   &
                    IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
        IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!               ********************************************
!               **  TREAT THE POSITIONAL TABULATION CASE  **
!               ********************************************
!
      IF(ICOM.EQ.'POSI' .AND. IHARG(1).EQ.'TABU')THEN
        ICASAN='POTA'
        CALL DPPOTA(TEMP,XTEMP1,XTEMP2,MAXNXT,   &
                    ISEED,   &
                    ICAPSW,IFORSW,   &
                    IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
        IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED MAY 1988
!               **********************************************
!               **  TREAT THE EXPERIMENTAL SIMULATION CASE  **
!               **  (SYNONYM = RUN)                         **
!               **********************************************
!
      IF(ICOM.EQ.'EXPE' .OR. ICOM.EQ.'RUN')THEN
        ICASAN='EXSI'
        CALL DPEXSI(ISEED,MAXNXT,ICASAN,   &
                    IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
        IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED SEPTEMBER 1990
!               ******************************************
!               **  TREAT THE CAPABILITY ANALYSIS CASE  **
!               ******************************************
!
      IF(ICOM.EQ.'CAPA' .OR. IHARG(1).EQ.'CAPA')GO TO 4500
      IF(ICOM.EQ.'CP  ' .OR. IHARG(1).EQ.'CP  ')GO TO 4500
      IF(ICOM.EQ.'CPK ' .OR. IHARG(1).EQ.'CPK ')GO TO 4500
      GO TO 4599
!
 4500 CONTINUE
      ICASAN='CAPA'
      CALL DPCAAN(XTEMP1,MAXNXT,   &
                  ICASAN,ICAPSW,IFORSW,   &
                  IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
      IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
!
 4599 CONTINUE
!
!               *******************************************
!               **  TREAT THE (YATES) PHD ANALYSIS CASE  **
!               *******************************************
!
!CCCC FEBRUARY 1995.  RENAME PHD TO DEX PHD IN ORDER TO ALLOW
!CCCC FUTURE ADDITION OF A MORE GENERAL PHD COMMAND.
!CCCC IF(ICOM.EQ.'PHD ')GO TO 4600
!CCCC SEPTEMBER 2012.  FOLD DEX PHD INTO STANDARD YATES ANALYSIS
!CCCC COMMAND.
!
!CCCC IF(ICOM.EQ.'DEX ')THEN
!CCCC   IF(NUMARG.GE.1.AND.IHARG(1).EQ.'PHD ')GO TO 4600
!CCCC   GO TO 4699
!CCCC ENDIF
!CCCC IF(ICOM.EQ.'PHD ')THEN
!CCCC   IF(NUMARG.GE.1.AND.IHARG(1).EQ.'DEX ')GO TO 4600
!CCCC   GO TO 4699
!CCCC ENDIF
!CCCC GO TO 4699
!
!4600 CONTINUE
!CCCC ICASAN='PHD '
!CCCC CALL DPPHD(ICASAN,
!CCCC1IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
!CCCC IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
!
!4699 CONTINUE
!
!CCCC THE FOLLOWING SECTION WAS ADDED     MARCH 1994
!               ******************************
!               **  TREAT THE DDS     CASE  **
!               ******************************
!
      IF(ICOM.EQ.'DDS ')THEN
         ICASAN='DDS '
         CALL DPDDS(XTEMP1,MAXNXT,   &
                    ICAPSW,IFORSW,   &
                    IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED     MAY 1999
!               ******************************
!               **  TREAT THE ARMA    CASE  **
!               ******************************
!
      IF(ICOM.EQ.'ARMA'.OR.ICOM.EQ.'ARIM')THEN
         ICASAN='ARMA'
         IF(NUMARG.GE.1.AND.IHARG(1).EQ.'FIT ')THEN
           ISHIFT=1
           CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                       IBUGA2,IERROR)
         ENDIF
         IF(NUMARG.GE.1.AND.IHARG(1).EQ.'MODE')THEN
           ISHIFT=1
           CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                       IBUGA2,IERROR)
         ENDIF
         IF(NUMARG.GE.1.AND.IHARG(1).EQ.'FORE')THEN
           ISHIFT=1
           CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                       IBUGA2,IERROR)
           ICASAN='ARFC'
         ENDIF
         CALL DPARMA(MAXNXT,   &
                     ISUBRO,IBUGA2,IBUGA3,IBUGQ,IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED     JULY 1995
!CCCC THE FOLLOWING SECTION WAS ACTIVATED SEPTEMBER 1997
!               ************************************************
!               **  TREAT THE ... RECIPE ANALYSIS CASE        **
!               **  RECIPE = REGRESSION CONFIDENCE INTERVALS  **
!               **           ON PERCENTILES                   **
!               ************************************************
!
!CCCC ACTIVATE COMMAND   AUGUST 1997
      IF(NUMARG.GE.1.AND.ICOM.EQ.'RECI'.AND.IHARG(1).NE.'SIMC')THEN
         IF(NUMARG.GE.2.AND.IHARG(1).EQ.'PROB'.AND.IHARG(2).EQ.'PLOT')   &
           GO TO 4799
         IF(NUMARG.GE.2.AND.IHARG(1).EQ.'PPCC'.AND.IHARG(2).EQ.'PLOT')   &
           GO TO 4799
         IF(NUMARG.GE.2.AND.IHARG(1).EQ.'KOLM'.AND.IHARG(2).EQ.'SMIR')   &
           GO TO 4799
         IF(NUMARG.GE.2.AND.IHARG(1).EQ.'CHI '.AND.IHARG(2).EQ.'SQUA')   &
           GO TO 4799
         IF(NUMARG.GE.1.AND.IHARG(1).EQ.'CHI ')   &
           GO TO 4799
         ICASAN='RECI'
         CALL DPRECI(ISEED,IBUGA2,IBUGA3,IBUGCO,IBUGEV,IBUGQ,ISUBRO,   &
                     IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
 4799 CONTINUE
!
!CCCC THE FOLLOWING SECTION WAS ADDED     SEPTEMBER 1997
!               ************************************************
!               **  TREAT THE ... SIMCOV ANALYSIS CASE        **
!               **  USED PRIOR TO A RECIPE ANALYIS TO         **
!               **  DETERMINE IF SATTERTHWAITE APPROXIMATION  **
!               **  WILL BE ADEQUATE                          **
!               ************************************************
!
      IF(NUMARG.GE.1.AND.ICOM.EQ.'RECI'.AND.IHARG(1).EQ.'SIMC')THEN
        ICOM='SIMC'
        ISHIFT=1
        CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
        IBUGA2,IERROR)
        ICASAN='SIMC'
        CALL SIMCOV(ISEED,IBUGA2,IBUGA3,IBUGCO,IBUGEV,IBUGQ,ISUBRO,   &
                    IFOUND,IERROR)
        IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ELSEIF(NUMARG.GE.1.AND.ICOM.EQ.'SIMC')THEN
         ICASAN='SIMC'
         CALL SIMCOV(ISEED,IBUGA2,IBUGA3,IBUGCO,IBUGEV,IBUGQ,ISUBRO,   &
                     IFOUND,IERROR)
         IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED     MARCH 1999
!               ***************************************************
!               **  TREAT THE SINGLE SAMPLE ACCEPTANCE PLAN CASE **
!               ***************************************************
!
      IF(ICOM.EQ.'SING')THEN
         IF(NUMARG.GE.3.AND.IHARG(1).EQ.'SAMP'.AND.   &
            IHARG(2).EQ.'ACCE'.AND.IHARG(3).EQ.'PLAN')THEN
            ISHIFT=3
            CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
            IBUGA2,IERROR)
            IFOUND='YES'
         ENDIF
         IF(NUMARG.GE.2.AND.IHARG(1).EQ.'SAMP'.AND.   &
            IHARG(2).EQ.'ACCE')THEN
            ISHIFT=2
            CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
            IBUGA2,IERROR)
            IFOUND='YES'
         ENDIF
         IF(NUMARG.GE.2.AND.IHARG(1).EQ.'SAMP'.AND.   &
            IHARG(2).EQ.'PLAN')THEN
            ISHIFT=2
            CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
            IBUGA2,IERROR)
            IFOUND='YES'
         ENDIF
         IF(NUMARG.GE.1.AND.IHARG(1).EQ.'SAMP')THEN
            ISHIFT=1
            CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
            IBUGA2,IERROR)
            IFOUND='YES'
         ENDIF
!
         ICASAN='SSNC'
         IF(IFOUND.EQ.'YES')THEN
           CALL DPACSA(MAXNXT,ICASAN,   &
                       IBUGA2,IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
           IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
         ENDIF
      ENDIF
!
!
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
!
      IERRST=IERROR
!
!     APRIL 2007.  CHECK FOR FATAL ERROR
!
      IF(IERROR.EQ.'YES' .OR. IERROR.EQ.'WARN')THEN
        CALL DPERRO(IERRFA,IANSLC,IWIDTH,IGUIFL,   &
                    ISUBN1,ISUBN2,ICASAN,   &
                    IBUGA2,ISUBRO,IERROR)
      ENDIF
!
      IF(IBUGAN.EQ.'ON' .OR. ISUBRO.EQ.'INAN')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF MAINAN--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)IBUGAN,IBUGA2,IBUGA3
 9013   FORMAT('IBUGAN,IBUGA2,IBUGA3 = ',A4,2X,A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)IBUGCO,IBUGEV,IBUGQ
 9015   FORMAT('IBUGCO,IBUGEV,IBUGQ = ',A4,2X,A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9016)IFTEXP,IANGLU,ALOWFR
 9016   FORMAT('IFTEXP,IANGLU,ALOWFR = ',A4,2X,A4,2X,G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9018)ICASAN,ISEED,ANOPL1,ANOPL2
 9018   FORMAT('ICASAN,ISEED,ANOPL1,ANOPL2 = ',A4,I8,E15.7,E15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9020)IFOUND,IERROR
 9020   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9027)ICOM,ICOM2,NUMARG
 9027   FORMAT('ICOM,ICOM2,NUMARG = ',A4,2X,A4,2X,I8)
        CALL DPWRST('XXX','BUG ')
        DO 9030 I=1,NUMARG
          WRITE(ICOUT,9031)I,IHARG(I),IHARG2(I),IARGT(I),IARG(I),ARG(I)
 9031     FORMAT('I,IHARG(I),IHARG2(I),IARGT(I),IARG(I),ARG(I) = ',   &
                 I8,2X,A4,2X,A4,2X,A4,2X,I8,E15.7)
            CALL DPWRST('XXX','BUG ')
 9030   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE MAINAN
      SUBROUTINE MAINDG(IBUGDG,IBUGD2,IBUGU2,ISUBRO,   &
                        DEFANG,ANGLE,IDEANU,IANGLU,IREPCH,   &
                        IMPSW,ICAPSW,   &
                        IFOUND,IERROR)
!
!     PURPOSE--THIS IS SUBROUTING MAINDG.
!              (THE   TD    AT THE END OF    MAINDG   STANDS FOR DIAGRAMMATIC
!              THIS SUBROUTINE SEARCHES FOR AND EXECUTES DIAGRAMMATIC GRAPHICS C
!              THE DIAGRAMMATIC GRAPHICS COMMANDS SEARCHED FOR BY MAINDG ARE AS
!
!                      COPY                              A NUMBER
!                      ERASE                             NO ENTRY
!                      RING BELL                         A NUMBER
!
!                      TEXT                              A STRING OF TEXT
!                      FONT                              A FONT NAME
!                      CASE                              UPPER OR LOWER
!                      HEIGHT                            A NUMBER
!                      WIDTH                             A NUMBER
!                      HW                                2 NUMBERS
!                      JUSTIFICATION                     LEFT, CENTER, OR RIGHT
!                      ANGLE                             A NUMBER
!                      ANGLE UNITS                       RADIANS, DEGREES, OR GR
!                      CRLF (CARRIAGE RETURN/LINE FEED)  ON OR OFF
!                      ... MARGIN                        A NUMBER
!                      CROSS-HAIR                        0 OR 2 PARAMTER NAMES
!
!                      MOVE                              2, 4, 6, 8, ... NUMBERS
!                      MOVEDATA                          2, 4, 6, 8, ... NUMBERS
!                      DRAW                              2, 4, 6, 8, ... NUMBERS
!                      DRAWDATA                          2, 4, 6, 8, ... NUMBERS
!
!                      POINT                             0, 2, 4, 6, ... NUMBERS
!                      ARROW                             2, 4, 6, 8, ... NUMBERS
!                      BOX                               2, 4, 6, 8, ... NUMBERS
!                      TRIANGLE                          4, 6, 8, ...    NUMBERS
!                      HEXAGON                           2, 4, 6, 8, ... NUMBERS
!                      CIRCLE                            2, 4, 6, 8, ... NUMBERS
!                      SEMI-CIRCLE                       2, 4, 6, 8, ... NUMBERS
!                      ELLIPSE                           4, 6, 8, ... NUMBERS
!                      AMPLIFIER                           2, 4, 6, 8, ... NUMBE
!                      DIAMOND                           4, 6, 8, ... NUMBERS
!                      OVAL                              4, 6, 8, ... NUMBERS
!                      ARC                               4, 6, 8, ... NUMBERS
!
!                      RESISTOR                       2, 4, ... NUMBERS
!                      CAPACITOR                         2, 4, 6, 8, ... NUMBERS
!                      GROUND                            2, 4, 6, 8, ... NUMBERS
!                      INDUCTOR                          2, 4, 6, 8, ... NUMBERS
!
!                      AND                               2, 4, 6, 8, ... NUMBERS
!                      OR                                2, 4, 6, 8, ... NUMBERS
!                      NAND                              2, 4, 6, 8, ... NUMBERS
!                      NOR                               2, 4, 6, 8, ... NUMBERS
!
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82.6
!     ORIGINAL VERSION--APRIL     1981.
!     UPDATED         --MAY       1981.
!     UPDATED         --AUGUST    1981.
!     UPDATED         --SEPTEMBER 1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --NOVEMBER  1982.
!     UPDATED         --DECEMBER  1988. AVOID POINT & POINCARE PLOT CONFLICT
!     UPDATED         --AUGUST    1992. AVOID SYMBOL & SYMBOL PLOT CONFLICT
!     UPDATED         --AUGUST    1992. AVOID NAME CONFLICTS WITH BOX
!     UPDATED         --OCTOBER   1992. BOX BORDER SETTINGS
!     UPDATED         --NOVEMBER  1992. MOVEDATA COMMAND
!     UPDATED         --MARCH     1993. ARGUMENTS TO DPBX
!     UPDATED         --SEPTEMBER 1993. ALLOW LOWER CASE TEXT
!     UPDATED         --FEBRUARY  1994. FIX CAPABILITY CONFLICT
!     UPDATED         --MAY       1994. DISCONNECT (TEKT. HARD-) COPY
!                                       COMMAND
!     UPDATED         --SEPTEMBER 1994. DRAWDATA COMMAND
!     UPDATED         --OCTOBER   1995. NAME CONFLICT WITH ANGLIT PROB
!                                       PLOT AND ANGLE COMMANDS
!     UPDATED         --MARCH     1997. SUPPORT FOR DEVICE FONT (ALAN)
!                                       AUGMENT ARGUMENT LIST FOR
!                                       MOST COMMANDS
!     UPDATED         --JULY      1997. ELLIPSE DATA COMMAND (ALAN)
!     UPDATED         --JULY      1997. <COMM> DATA COMMAND (ALAN)
!                                       FOR DIAGRAMMATIC GRAPHICS
!                                       COMMANDS THAT DRAW FIGURES
!     UPDATED         --JULY      1997. POLGON COMMAND (ALAN)
!     UPDATED         --JANUARY   1998. NAME CONFLICT WITH SEMI-
!                                       CIRCLE AND SEMICIRCULAR
!                                       PROB PLOT AND PPCC PLOT
!     UPDATED         --AUGUST    1998. DRAW<D/S><D/S><D/S><D/S>
!     UPDATED         --AUGUST    1998. MOVE<D/S><D/S>
!     UPDATED         --SEPTEMBER 1998. ADD IMPSW TO ARGUMENT LIST
!                                       (USED TO SET IMPSW2)
!     UPDATED         --SEPTEMBER 1999. ARGUMENT LIST TO DPTEXT
!     UPDATED         --SEPTEMBER 2002. ICAPSW
!     UPDATED         --APRIL     2007. CHECK "CENSORED" FOR
!                                       TRIANGLE COMMAND
!     UPDATED         --SEPTEMBER 2007. IERRST
!     UPDATED         --JULY      2010. CHECK FOR FATAL ERROR
!     UPDATED         --DECEMBER  2018. CALL LIST TO DPTEXT
!     UPDATED         --DECEMBER  2018. CALL LIST TO DPTRIA
!     UPDATED         --DECEMBER  2018. CALL LIST TO DPAMPL
!     UPDATED         --DECEMBER  2018. CALL LIST TO DPAND
!     UPDATED         --DECEMBER  2018. CALL LIST TO DPARC
!     UPDATED         --DECEMBER  2018. CALL LIST TO DPARRO
!     UPDATED         --DECEMBER  2018. CALL LIST TO DPBX
!     UPDATED         --DECEMBER  2018. CALL LIST TO DPSCIR
!     UPDATED         --DECEMBER  2018. CALL LIST TO DPRESI
!     UPDATED         --DECEMBER  2018. CALL LIST TO DPPYRA
!     UPDATED         --DECEMBER  2018. CALL LIST TO DPPOIN
!     UPDATED         --DECEMBER  2018. CALL LIST TO DPPOLY
!     UPDATED         --DECEMBER  2018. CALL LIST TO DPMOVE
!     UPDATED         --DECEMBER  2018. CALL LIST TO DPNAND
!     UPDATED         --DECEMBER  2018. CALL LIST TO DPNOR
!     UPDATED         --DECEMBER  2018. CALL LIST TO DPOR
!     UPDATED         --DECEMBER  2018. CALL LIST TO DPOVAL
!     UPDATED         --DECEMBER  2018. CALL LIST TO DPCAPA
!     UPDATED         --DECEMBER  2018. CALL LIST TO DPCIRC
!     UPDATED         --DECEMBER  2018. CALL LIST TO DPCUBE
!     UPDATED         --DECEMBER  2018. CALL LIST TO DPDIAM
!     UPDATED         --DECEMBER  2018. CALL LIST TO DPELLI
!     UPDATED         --DECEMBER  2018. CALL LIST TO DPERAS
!     UPDATED         --DECEMBER  2018. CALL LIST TO DPEXIT
!     UPDATED         --DECEMBER  2018. CALL LIST TO DPGROU
!     UPDATED         --DECEMBER  2018. CALL LIST TO DPHEXA
!     UPDATED         --DECEMBER  2018. CALL LIST TO DPINDU
!     UPDATED         --DECEMBER  2018. CALL LIST TO DPLATT
!     UPDATED         --OCTOBER   2020. CALL LIST TO VARIOUS ROUTINES
!                                       TO SUPPORT RGB COLOR
!     UPDATED         --MAY       2022. SUPPORT FOR DEVICE HARDWARE
!                                       CHARACTER OFFSET
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IMPSW
      CHARACTER*4 ICAPSW
      CHARACTER*4 IDEANU
      CHARACTER*4 IANGLU
!
      CHARACTER*1 IREPCH
!
      CHARACTER*4 IBUGDG
      CHARACTER*4 IBUGD2
      CHARACTER*4 IBUGU2
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 IHOLD
      CHARACTER*4 ITEXCV
      CHARACTER*4 ICASE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!CCCC THE FOLLOWING LINE WAS ADDED NOVEMBER 1992
!CCCC AND THEN MODIFIED AUGUST 1998.
      CHARACTER*4 UNITSW
      CHARACTER*4 X1UNIT
      CHARACTER*4 X2UNIT
      CHARACTER*4 Y1UNIT
      CHARACTER*4 Y2UNIT
!
      DIMENSION PRV(6)
      DIMENSION PDIARV(4)
      DIMENSION ITEXCV(10)
      DIMENSION PTEXRV(5)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCOPC.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOBE.INC'
      INCLUDE 'DPCOST.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IBUGG4=IBUGU2
      ISUBG4=ISUBRO
!
      PXSTAR=PXEND
      PYSTAR=PYEND
!
!CCCC ADD FOLLOWING LINE SEPTEMBER 1998.
      IMPSW2=IMPSW
!
      IF(IBUGDG.EQ.'ON' .OR. ISUBRO.EQ.'INDG')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('AT THE BEGINNING OF MAINDG--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)IBUGDG,IBUGD2,ISUBRO,IDEFAU,ITEXAU
   53   FORMAT('IBUGDG,IBUGD2,ISUBRO,IDEFAU,ITEXAU = ',4(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,59)PXSTAR,PYSTAR,PXEND,PYEND
   59   FORMAT('PXSTAR,PYSTAR,PXEND,PYEND = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,60)DEFANG,ANGLE,IDEANU,IANGLU,IDMANU(1)
   60   FORMAT('DEFANG,ANGLE,IDEANU,IANGLU,IDMANU(1) = ',   &
               2G15.7,2(2X,A4),2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,65)IREPCH,IFOUND,IERROR,ICOM,ICOM2,NUMARG
   65   FORMAT('IREPCH,IFOUND,IERROR,ICOM,ICOM2,NUMARG = ',5(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        DO 70 I=1,NUMARG
          WRITE(ICOUT,71)I,IHARG(I),IHARG2(I),IARGT(I),IARG(I),ARG(I)
   71     FORMAT('I,IHARG(I),IHARG2(I),IARGT(I),IARG(I),ARG(I) = ',   &
                 I8,3(2X,A4),2X,I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   70   CONTINUE
      ENDIF
!
      IFOUND='NO'
      IERROR='NO'
!
!               ***************************
!               **  TREAT THE COPY CASE  **
!               ***************************
!
!CCCC THE FOLLOWING SECTION WAS COMMENTED OUT      MAY 1994.
!CCCC IN DEFERENCE TO THE COPY FILE COMMAND        MAY 1994
!CCCC IF(ICOM.EQ.'COPY')GO TO 100
!CCCC IF(ICOM.EQ.'MAKE')GO TO 100
!CCCC GO TO 199
!
!C100 CONTINUE
!CCCC CALL DPCOPY(IHARG,IARGT,IARG,NUMARG,
!CCCC1NUMDEV,
!CCCC1IDMANU,IDMODE,IDMOD2,IDMOD3,
!CCCC1IDPOWE,IDCONT,IDCOLO,IDNVPP,IDNHPP,IDUNIT,
!CCCC ADD FOLLOWING LINE MARCH 1997.
!CCCC1IDFONT,
!CCCC1IBUGD2,ISUBRO,IFOUND,IERROR)
!CCCC IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
!
!C199 CONTINUE
!
!               *******************************
!               **  TREAT THE ERASE CASE     **
!               **  TREAT THE PAGE CASE      **
!               **  TREAT THE NEW PAGE CASE  **
!               *******************************
!
      IF(ICOM.EQ.'ERAS')GO TO 200
      IF(ICOM.EQ.'PAGE' .AND. IHARG(1).NE.'TEST')GO TO 200
      IF(ICOM.EQ.'NEW')GO TO 200
      GO TO 299
!
  200 CONTINUE
      ICASE='ERAS'
      CALL DPERAS(IHARG,IARGT,IARG,NUMARG,   &
                  IBACCO,IBACC2,IGRASW,IDIASW,   &
                  PGRAXF,PGRAYF,PDIAXC,PDIAYC,PDIAX2,PDIAY2,   &
                  PDIAHE,PDIAWI,PDIAVG,PDIAHG,   &
                  NUMDEV,IDMANU,IDMODE,IDMOD2,IDMOD3,   &
                  IDPOWE,IDCONT,IDCOLO,IDNVPP,IDNHPP,IDUNIT,   &
                  IDNVOF,IDNHOF,IDFONT,PDSCAL,   &
                  ICAPSW,IBUGD2,ISUBRO,IFOUND,IERROR)
      IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
!
  299 CONTINUE
!
!               ********************************
!               **  TREAT THE RING BELL CASE  **
!               ********************************
!
      IF(ICOM.EQ.'RING')THEN
        ICASE='BELL'
        CALL DPRING(IHARG,IARGT,IARG,NUMARG,   &
                    NUMDEV,   &
                    IDMANU,IDMODE,IDMOD2,IDMOD3,   &
                    IDPOWE,IDCONT,IDCOLO,IDNVPP,IDNHPP,IDUNIT,   &
                    IDFONT,   &
                    IBUGD2,ISUBRO,IFOUND,IERROR)
        IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!               ***************************
!               **  TREAT THE TEXT CASE  **
!               ***************************
!
!CCCC MODIFIED TO SUPPORT "ELLIPSE DATA" OPTION.  JULY 1997.
      IF(ICOM.EQ.'TEXT')GO TO 1100
      GO TO 1199
!
 1100 CONTINUE
      ICASE='TEXT'
      PRV(1)=PGRAXF
      PRV(2)=PGRAYF
      PRV(3)=PDIAXC
      PRV(4)=PDIAYC
      PRV(5)=PDIAX2
      PRV(6)=PDIAY2
!
      PDIARV(1)=PDIAHE
      PDIARV(2)=PDIAWI
      PDIARV(3)=PDIAVG
      PDIARV(4)=PDIAHG
!
      ITEXCV(1)=ITEXFO
      ITEXCV(2)=ITEXCA
      ITEXCV(3)=ITEXJU
      ITEXCV(4)=ITEXDI
      ITEXCV(5)=ITEXCR
      ITEXCV(6)=ITEXLF
      ITEXCV(7)=ITEXSY
      ITEXCV(8)=ITEXSP
      ITEXCV(9)=ITEXFI
      ITEXCV(10)=ITEXCO
!
      PTEXRV(1)=PTEXHE
      PTEXRV(2)=PTEXWI
      PTEXRV(3)=PTEXVG
      PTEXRV(4)=PTEXHG
      PTEXRV(5)=PTEXTH
!
      CALL DPTEXT(IANS,IANSLC,IWIDTH,   &
                  ITEXTE,NCTEX,   &
                  PXSTAR,PYSTAR,PXEND,PYEND,   &
                  IGRASW,IDIASW,PRV,PDIARV,   &
                  ILINPA,ILINCO,ILINC2,MAXLN,PLINTH,   &
                  ATEXBA,ITEBLI,ITEBCO,ITEBC2,MAXTX,PTEBTH,   &
                  ITEFSW,ITEFCO,ITEFC2,   &
                  ITEPTY,ITEPLI,ITEPCO,ITEPC2,PTEPTH,PTEPSP,   &
                  PTEXMR,ITEXCV,ATEXAN,PTEXRV,   &
                  IHNAME,IHNAM2,IUSE,IVALUE,VALUE,NUMNAM,   &
                  IVSTAR,IVSTOP,IFUNC,NUMCHF,IREPCH,   &
                  NUMDEV,IDMANU,IDMODE,IDMOD2,IDMOD3,   &
                  IDPOWE,IDCONT,IDCOLO,IDNVPP,IDNHPP,IDUNIT,   &
                  IDNVOF,IDNHOF,IDFONT,PDSCAL,   &
                  IMPSW2,AMPSCH,AMPSCW,   &
                  IBACCO,IBACC2,   &
                  IBUGD2,IFOUND,IERROR)
      IF(ITEXCR.EQ.'ON')PXSTOP=PTEXMR
      IF(ITEXLF.EQ.'ON')PYSTOP=PYSTAR-PTEXHE-PTEXVG
      IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
!
 1199 CONTINUE
!
!               ***************************
!               **  TREAT THE FONT CASE  **
!               ***************************
!
      IF(ICOM.EQ.'FONT')GO TO 1200
      GO TO 1299
!
 1200 CONTINUE
      ICASE='FONT'
      CALL DPFONT(IHARG,NUMARG,   &
      IDEFFO,   &
      ITEXFO,   &
      IBUGD2,ISUBRO,IFOUND,IERROR)
      IF(IFOUND.EQ.'YES'.AND.IERROR.EQ.'NO')GO TO 1250
      GO TO 1259
 1250 CONTINUE
      IX1ZFO=ITEXFO
      IX2ZFO=ITEXFO
      IY1ZFO=ITEXFO
      IY2ZFO=ITEXFO
      ITITFO=ITEXFO
      IX1LFO=ITEXFO
      IX2LFO=ITEXFO
      IX3LFO=ITEXFO
      IY1LFO=ITEXFO
      IY2LFO=ITEXFO
      DO 1251 I=1,MAXLEG
      ILEGFO(I)=ITEXFO
 1251 CONTINUE
      DO 1252 I=1,MAXCHA
      ICHAFO(I)=ITEXFO
 1252 CONTINUE
 1259 CONTINUE
      IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
!
 1299 CONTINUE
!
!               ************************************************
!               **  TREAT THE CASE (UPPER VERSUS LOWER) CASE  **
!               ************************************************
!
      IF(ICOM.EQ.'CASE')THEN
        ICASE='CASE'
        CALL DPCASE(ICOM,IHARG,NUMARG,   &
                    IDEFCA,              &
                    ITEXCA,              &
                    IBUGD2,ISUBRO,IFOUND,IERROR)
