!               ************************************
!
      IF(ICOM.EQ.'ANGL' .OR. ICOM.EQ.'RADI' .OR.   &
         ICOM.EQ.'DEGR' .OR. ICOM.EQ.'GRAD')THEN
        IF(IHARG(1).NE.'FIT ' .AND. IHARG(2).NE.'FIT' .AND.   &
           IHARG(3).NE.'FIT ')THEN
          ICASE='ANGU'
          IF(ICOM.NE.'ANGL')THEN
            ISHIFT=2
            CALL SHIFTR(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                        IBUGD2,IERROR)
            IHARG(1)='UNIT'
            IHOLD=ICOM
            IF(NUMARG.GE.3.AND.IHARG(3).EQ.'OFF')IHOLD=IDEFAU
            IF(NUMARG.GE.3.AND.IHARG(3).EQ.'OFF'.AND.ICOM.EQ.IDEFAU)   &
               IHOLD='DEGR'
            IHARG(2)=IHOLD
            NUMARG=2
          ENDIF
          CALL DPANGU(IHARG,NUMARG,IDEFAU,ITEXAU,   &
                      IBUGD2,ISUBRO,IFOUND,IERROR)
          IANGLU=ITEXAU
          IDEANU=IDEFAU
          IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
        ENDIF
      ENDIF
!
!               ************************************
!               **  TREAT THE PATTERN CASE        **
!               ************************************
!
      IF(ICOM.EQ.'PATT')THEN
        ICASE='PATT'
        CALL DPPATT(IHARG,NUMARG,   &
                    IDEFPA,   &
                    ITEXPA,   &
                    IBUGD2,ISUBRO,IFOUND,IERROR)
        IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!               ************************************
!               **  TREAT THE COLOR CASE  **
!               ************************************
!
      IF(ICOM.EQ.'COLO' .OR. ICOM.EQ.'PEN')THEN
        ICASE='COLO'
        CALL DPCOLO(IHARG,NUMARG,   &
                    IDEFCO,   &
                    ITEXCO,   &
                    IBUGD2,ISUBRO,IFOUND,IERROR)
        IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!               ***************************************
!               **  TREAT THE VERTICAL SPACING CASE  **
!               ***************************************
!
      IF(ICOM.EQ.'VERT')THEN
        ICASE='VESP'
        CALL DPVERT(IHARG,IARGT,ARG,NUMARG,   &
                    PDEFVG,   &
                    PTEXVG,   &
                    IBUGD2,ISUBRO,IFOUND,IERROR)
        IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!               *****************************************
!               **  TREAT THE HORIZONTAL SPACING CASE  **
!               *****************************************
!
      IF(ICOM.EQ.'HORI'.AND.IHARG(1).NE.'SWIT')GO TO 7700
      GO TO 7799
!
 7700 CONTINUE
      ICASE='HOSP'
      CALL DPHORI(IHARG,IARGT,ARG,NUMARG,   &
      PDEFHG,   &
      PTEXHG,   &
      IBUGD2,ISUBRO,IFOUND,IERROR)
      IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
!
 7799 CONTINUE
!
!               ***************************************
!               **  TREAT THE CARRAIAGE RETURN CASE  **
!               ***************************************
!
      IF(ICOM.EQ.'CARR' .OR. ICOM.EQ.'CR')THEN
        ICASE='CR'
        CALL DPCR(IHARG,NUMARG,   &
                  IDEFCR,   &
                  ITEXCR,   &
                  IBUGD2,ISUBRO,IFOUND,IERROR)
        IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!               ********************************
!               **  TREAT THE LINE FEED CASE  **
!               ********************************
!
      IF(ICOM.EQ.'LINE'.AND.NUMARG.GE.1.AND.IHARG(1).EQ.'FEED')GO TO 7900
      IF(ICOM.EQ.'LF')GO TO 7900
      GO TO 7999
!
 7900 CONTINUE
      ICASE='LIFE'
      CALL DPLF(IHARG,NUMARG,   &
      IDEFLF,   &
      ITEXLF,   &
      IBUGD2,ISUBRO,IFOUND,IERROR)
      IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
!
 7999 CONTINUE
!
!               ***************************************
!               **  TREAT THE SYMBOL CHARACTER CASE  **
!               ***************************************
!
!CCCC AUGUST 1992.  CHECK FOR CONFLICT WITH "SYMBOL PLOT" COMMAND.
!CCCC IF(ICOM.EQ.'SYMB')GO TO 8000
      IF(ICOM.EQ.'SYMB'.AND.IHARG(1).NE.'PLOT')THEN
        ICASE='SYMB'
        CALL DPSYMB(IHARG,NUMARG,   &
                    IDEFSY,   &
                    ITEXSY,   &
                    IBUGD2,ISUBRO,IFOUND,IERROR)
        IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!               *******************************************************
!               **  TREAT THE SPACING (EQUAL VS. PROPORTIONAL) CASE  **
!               *******************************************************
!
      IF(ICOM.EQ.'SPAC')THEN
        ICASE='SPAC'
        CALL DPSPAC(IHARG,NUMARG,   &
                    IDEFSP,   &
                    ITEXSP,   &
                    IBUGD2,ISUBRO,IFOUND,IERROR)
        IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!               *****************************
!               **  TREAT THE THICKNESS CASE  **
!               *****************************
!
      IF(ICOM.EQ.'THIC')THEN
        ICASE='THIC'
        CALL DPTHIC(IHARG,IARGT,ARG,NUMARG,   &
                    PDEFTH,   &
                    PTEXTH,   &
                    PFRATH,PTICTH,PTIZTH,PVGRTH,PHGRTH,PTITTH,PX1LTH,   &
                    PX2LTH,PY1LTH,   &
                    PY2LTH,PLEGTH,MAXLG,PBOPTH,PBOFTH,MAXBX,PARRTH,   &
                    MAXAR,   &
                    PSEGTH,MAXSG,PLINTH,MAXLN,PCHATH,MAXCH2,PFILTH,   &
                    MAXFL,   &
                    PPATTH,MAXPT,PSPITH,MAXSP,PBABTH,PBAPTH,MAXBA,   &
                    PREPTH,MAXRG,   &
                    PMABTH,PMAPTH,MAXMR,PTEBTH,PTEPTH,MAXTX,   &
                    IBUGD2,ISUBRO,IFOUND,IERROR)
        IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!               *******************************
!               **  TREAT THE DIALOGUE CASE  **
!               *******************************
!
!CCCC IF(ICOM.EQ.'DIAL')GO TO 8300
!CCCC IF(ICOM.EQ.'D')GO TO 8300
!CCCC GO TO 8399
!CCCC
!8300 CONTINUE
!CCCC CALL DPDIAL(IHARG,IARGT,IARG,NUMARG,
!CCCC1IGRASW,PDIAXC,PDIAYC,
!CCCC1NUMDEV,
!CCCC1IDMANU,IDMODE,IDMOD2,IDMOD3,
!CCCC1IDPOWE,IDCONT,IDCOLO,IDNVPP,IDNHPP,IDUNIT,
!CCCC1IDNVOF,IDNHOF,
!CCCC ADD FOLLOWING LINE MARCH 1997.
!CCCC1IDFONT,
!CCCC1IBUGD2,ISUBRO,IFOUND,IERROR)
!CCCC IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
!CCCC
!8399 CONTINUE
!
!               **************************
!               **  TREAT THE CUBE CASE **
!               **************************
!
!CCCC MODIFIED TO SUPPORT "CUBE DATA" OPTION.  JULY 1997.
      IF(ICOM.EQ.'CUBE')THEN
        ICASE='CUBE'
        UNITSW='SCRE'
        IF(IHARG(1).EQ.'DATA')THEN
          UNITSW='DATA'
          ISHIFT=1
          CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                      IBUGD2,IERROR)
        ENDIF
        CALL DPCUBE(IHARG,IARGT,ARG,NUMARG,   &
                    PXSTAR,PYSTAR,PXEND,PYEND,   &
                    ILINPA,ILINCO,ILINC2,MAXLN,PLINTH,   &
                    AREGBA,IREBLI,IREBCO,IREBC2,MAXRG,PREBTH,   &
                    IREFSW,IREFCO,IREFC2,   &
                    IREPTY,IREPLI,IREPCO,IREPC2,PREPTH,PREPSP,   &
                    PTEXHE,PTEXWI,PTEXVG,PTEXHG,   &
                    IGRASW,IDIASW,   &
                    PGRAXF,PGRAYF,PDIAXC,PDIAYC,PDIAX2,PDIAY2,   &
                    PDIAHE,PDIAWI,PDIAVG,PDIAHG,   &
                    NUMDEV,IDMANU,IDMODE,IDMOD2,IDMOD3,   &
                    IDPOWE,IDCONT,IDCOLO,IDNVPP,IDNHPP,IDUNIT,   &
                    IDNVOF,IDNHOF,IDFONT,UNITSW,PDSCAL,   &
                    IBACCO,IBACC2,   &
                    IBUGD2,IFOUND,IERROR)
        IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!               ******************************
!               **  TREAT THE PYRAMID CASE  **
!               ******************************
!
!CCCC MODIFIED TO SUPPORT "PYRAMID DATA" OPTION.  JULY 1997.
      IF(ICOM.EQ.'PYRA')THEN
        ICASE='PYRA'
        UNITSW='SCRE'
        IF(IHARG(1).EQ.'DATA')THEN
          UNITSW='DATA'
          ISHIFT=1
          CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                      IBUGD2,IERROR)
        ENDIF
      CALL DPPYRA(IHARG,IARGT,ARG,NUMARG,   &
                  PXSTAR,PYSTAR,PXEND,PYEND,   &
                  ILINPA,ILINCO,ILINC2,MAXLN,PLINTH,   &
                  AREGBA,IREBLI,IREBCO,IREBC2,MAXRG,PREBTH,   &
                  IREFSW,IREFCO,IREFC2,   &
                  IREPTY,IREPLI,IREPCO,IREPC2,PREPTH,PREPSP,   &
                  PTEXHE,PTEXWI,PTEXVG,PTEXHG,   &
                  IGRASW,IDIASW,   &
                  PGRAXF,PGRAYF,PDIAXC,PDIAYC,PDIAX2,PDIAY2,   &
                  PDIAHE,PDIAWI,PDIAVG,PDIAHG,   &
                  NUMDEV,IDMANU,IDMODE,IDMOD2,IDMOD3,   &
                  IDPOWE,IDCONT,IDCOLO,IDNVPP,IDNHPP,IDUNIT,   &
                  IDNVOF,IDNHOF,IDFONT,UNITSW,PDSCAL,   &
                  IBACCO,IBACC2,   &
                  IBUGD2,IFOUND,IERROR)
        IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!               ******************************
!               **  TREAT THE LATTICE  CASE **
!               ******************************
!
!CCCC MODIFIED TO SUPPORT "LATTICE DATA" OPTION.  JULY 1997.
      IF(ICOM.EQ.'LATT')THEN
        ICASE='LATT'
        UNITSW='SCRE'
        IF(IHARG(1).EQ.'DATA')THEN
          UNITSW='DATA'
          ISHIFT=1
          CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                      IBUGD2,IERROR)
        ENDIF
        CALL DPLATT(IHARG,IARGT,ARG,NUMARG,   &
                    PXSTAR,PYSTAR,PXEND,PYEND,   &
                    ILINPA,ILINCO,ILINC2,MAXLN,PLINTH,   &
                    AREGBA,IREBLI,IREBCO,IREBC2,MAXRG,PREBTH,   &
                    IREFSW,IREFCO,IREFC2,   &
                    IREPTY,IREPLI,IREPCO,IREPC2,PREPTH,PREPSP,   &
                    PTEXHE,PTEXWI,PTEXVG,PTEXHG,   &
                    IGRASW,IDIASW,   &
                    PGRAXF,PGRAYF,PDIAXC,PDIAYC,PDIAX2,PDIAY2,   &
                    PDIAHE,PDIAWI,PDIAVG,PDIAHG,   &
                    NUMDEV,   &
                    IDMANU,IDMODE,IDMOD2,IDMOD3,   &
                    IDPOWE,IDCONT,IDCOLO,IDNVPP,IDNHPP,IDUNIT,   &
                    IDNVOF,IDNHOF,IDFONT,UNITSW,PDSCAL,   &
                    IBACCO,IBACC2,   &
                    IBUGD2,IFOUND,IERROR)
        IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!               ******************************
!               **  TREAT THE POLYGON CASE  **
!               ******************************
!
      IF(ICOM.EQ.'POLY'.AND.ICOM2.EQ.'GON ')THEN
        ICASE='POLY'
        UNITSW='SCRE'
        IF(IHARG(1).EQ.'DATA')THEN
          UNITSW='DATA'
          ISHIFT=1
          CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                      IBUGD2,IERROR)
        ENDIF
        CALL DPPOLY(PXSTAR,PYSTAR,PXEND,PYEND,   &
                    ILINPA,ILINCO,ILINC2,MAXLN,PLINTH,   &
                    AREGBA,IREBLI,IREBCO,IREBC2,MAXRG,PREBTH,   &
                    IREFSW,IREFCO,IREFC2,   &
                    IREPTY,IREPLI,IREPCO,IREPC2,PREPTH,PREPSP,   &
                    PTEXHE,PTEXWI,PTEXVG,PTEXHG,   &
                    IGRASW,IDIASW,   &
                    PGRAXF,PGRAYF,PDIAXC,PDIAYC,PDIAX2,PDIAY2,   &
                    PDIAHE,PDIAWI,PDIAVG,PDIAHG,   &
                    NUMDEV,IDMANU,IDMODE,IDMOD2,IDMOD3,   &
                    IDPOWE,IDCONT,IDCOLO,IDNVPP,IDNHPP,IDUNIT,   &
                    IDNVOF,IDNHOF,IDFONT,UNITSW,PDSCAL,   &
                    IBACCO,IBACC2,   &
                    IBUGD2,IFOUND,IERROR)
        IF(IFOUND.EQ.'YES'.OR.IERROR.EQ.'YES')GO TO 9000
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
!
      IERRST=IERROR
!
!     APRIL 2007.  CHECK FOR FATAL ERROR
!
      IF(IERROR.EQ.'YES')THEN
        ISUBN1='MAIN'
        ISUBN2='DG  '
        ICASE='INDG'
        CALL DPERRO(IERRFA,IANSLC,IWIDTH,IGUIFL,   &
                    ISUBN1,ISUBN2,ICASE,   &
                    IBUGD2,ISUBRO,IERROR)
      ENDIF
!
      IF(IBUGDG.EQ.'ON' .OR. ISUBRO.EQ.'INDG')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('AT THE END       OF MAINDG--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)IFOUND,IERROR
 9014   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9019)PXSTAR,PYSTAR,PXEND,PYEND
 9019   FORMAT('PXSTAR,PYSTAR,PXEND,PYEND = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE MAINDG
